# todavía es ~2x más rápido que el modelo 7b full. Override via env.
_LOOKUP_NUM_CTX = int(os.environ.get("RAG_LOOKUP_NUM_CTX", "4096"))

# Per-intent rerank pool override. Synthesis/comparison necesitan más pool
