def _map_eval_row(entry: dict) -> dict:
    out: dict = {"ts": entry.get("ts") or datetime.now().isoformat(timespec="seconds")}
    sg = entry.get("singles") or {}
    ch = entry.get("chains") or {}
    for src_key, dst in (("hit5", "singles_hit5"), ("mrr", "singles_mrr"),
                          ("n", "singles_n")):
        if src_key in sg:
            out[dst] = sg[src_key]
    for src_key, dst in (("hit5", "chains_hit5"), ("mrr", "chains_mrr"),
                          ("chain_success", "chains_chain_success"),
                          ("turns", "chains_turns"), ("chains", "chains_n")):
        if src_key in ch:
            out[dst] = ch[src_key]
    # Preserve the full nested singles/chains dicts in extra_json so richer
    # fields (bootstrap CI bounds, p50/p95 latency) aren't lost to the flat
    # column projection.
    extra: dict = {}
    if sg:
        extra["singles"] = sg
    if ch:
        extra["chains"] = ch
    for k, v in entry.items():
        if k in {"ts", "singles", "chains"}:
            continue
        extra[k] = v
    if extra:
        out["extra_json"] = extra
    return out


def _map_surface_row(ev: dict) -> dict:
    out: dict = {}
    for k in ("ts", "cmd", "n_pairs", "sim_threshold", "min_hops", "top",
              "skip_young_days", "llm", "duration_ms"):
        if k in ev and ev[k] is not None:
            out[k] = ev[k]
    if "ts" not in out:
        out["ts"] = datetime.now().isoformat(timespec="seconds")
    if "llm" in out and isinstance(out["llm"], bool):
        out["llm"] = int(out["llm"])
    known = {"ts", "cmd", "n_pairs", "sim_threshold", "min_hops", "top",
             "skip_young_days", "llm", "duration_ms"}
    extra = {k: v for k, v in ev.items() if k not in known}
    if extra:
        out["extra_json"] = extra
    return out


def _map_proactive_row(ev: dict) -> dict:
    out: dict = {}
    for k in ("ts", "kind", "sent", "reason"):
        if k in ev and ev[k] is not None:
            out[k] = ev[k]
    if "ts" not in out:
        out["ts"] = datetime.now().isoformat(timespec="seconds")
    if "sent" in out and isinstance(out["sent"], bool):
        out["sent"] = int(out["sent"])
    known = {"ts", "kind", "sent", "reason"}
    extra = {k: v for k, v in ev.items() if k not in known}
    if extra:
        out["extra_json"] = extra
    return out


def _map_anticipate_row(ev: dict) -> dict:
    """Mapper para rag_anticipate_candidates. Los flags 0/1 se normalizan
    desde bool si vienen así."""
    out: dict = {}
    for k in ("ts", "kind", "score", "dedup_key", "reason", "message_preview"):
        if k in ev and ev[k] is not None:
            out[k] = ev[k]
    if "ts" not in out:
        out["ts"] = datetime.now().isoformat(timespec="seconds")
    for flag in ("selected", "sent"):
        v = ev.get(flag, 0)
        out[flag] = int(bool(v))
    return out


# Decisión válida del user en RagNet: aprueba el draft tal cual ('si'),
# aprueba con edits ('editar'), lo descarta ('rejected'), o el draft
# venció sin respuesta del user ('expired'). El CHECK constraint de la
# tabla rag_draft_decisions enforcea el mismo set; lo replicamos en
# Python para fallar temprano sin tocar SQL.
_VALID_DRAFT_DECISIONS: frozenset[str] = frozenset({
    "approved_si", "approved_editar", "rejected", "expired",
})


def _map_draft_decision_row(ev: dict) -> dict:
    """Mapper para rag_draft_decisions. Las cols `*_json` aceptan dict/list
    y se serializan automáticamente en `_sql_append_event`."""
    out: dict = {}
    for k in ("ts", "draft_id", "contact_jid", "contact_name",
              "bot_draft", "decision", "sent_text"):
        if k in ev and ev[k] is not None:
            out[k] = ev[k]
    if "ts" not in out:
        out["ts"] = datetime.now().isoformat(timespec="seconds")
    if "original_msgs" in ev and ev["original_msgs"] is not None:
        out["original_msgs_json"] = ev["original_msgs"]
    if "extra" in ev and ev["extra"] is not None:
        out["extra_json"] = ev["extra"]
    return out


def _record_draft_decision(
    *,
    draft_id: str,
    contact_jid: str,
    contact_name: str | None,
    original_msgs: list[dict],
    bot_draft: str,
    decision: str,
    sent_text: str | None = None,
    extra: dict | None = None,
) -> int | None:
    """Persiste una decisión de draft a `rag_draft_decisions`.

    Cierra el loop de auto-aprendizaje del bot WhatsApp: cuando el user
    puntúa un draft via `/si`, `/no`, o `/editar` en el RagNet group, el
    listener postea acá la decisión + lo que se mandó al contacto. Pares
    (bot_draft, sent_text) cuando `decision='approved_editar'` son gold
    humano para futuro fine-tune del modelo de drafts.

    Args:
        draft_id: short hex del listener TS, estable across updates del
            mismo draft (si el bot regenera el draft N veces antes de la
            decisión final, todas las rows comparten draft_id).
        contact_jid: jid de WhatsApp del contacto que escribió.
        contact_name: display name (opcional).
        original_msgs: list de `{id, text, ts}` con los mensajes que
            dispararon el draft.
        bot_draft: texto que el LLM generó.
        decision: uno de `approved_si`, `approved_editar`, `rejected`,
            `expired`. Cualquier otro valor → return None.
        sent_text: lo que finalmente se mandó al contacto. NULL si
            rejected/expired.
        extra: dict libre para metadatos future (ej. score del LLM,
            latency, model tag).

    Returns:
        rowid del INSERT, o None si la decisión es inválida o el write
        falló (silent-fail para no romper el listener si el DB está
        inaccesible — la UX del user nunca depende de telemetría).
    """
    if decision not in _VALID_DRAFT_DECISIONS:
        return None
    row = {
        "ts": datetime.now().isoformat(timespec="seconds"),
        "draft_id": draft_id,
        "contact_jid": contact_jid,
        "contact_name": contact_name,
        "original_msgs": original_msgs or [],
        "bot_draft": bot_draft or "",
        "decision": decision,
        "sent_text": sent_text,
        "extra": extra,
    }
    # `_sql_write_with_retry` traga errors via _silent_log; usamos un
    # holder mutable para devolver el rowid al caller (las write_fn no
    # aceptan return value en su contract).
    holder: dict = {"id": None}

    def _do() -> None:
        with _ragvec_state_conn() as conn:
            holder["id"] = _sql_append_event(
                conn, "rag_draft_decisions", _map_draft_decision_row(row),
            )
    try:
        _sql_write_with_retry(_do, "draft_decision_sql_write_failed")
    except Exception as exc:  # pragma: no cover - retry helper ya silencia
        _silent_log("draft_decision_helper", exc)
        return None
    return holder["id"]


# Set válido de ratings para `rag_brief_feedback`. Mismo dominio que el
# `rag_anticipate_feedback` (mute > negative > positive de precedencia
# en el parser TS); replicamos la frozenset acá para validación rápida
# sin tocar SQL. El CHECK de la tabla enforcea lo mismo a nivel DB.
_VALID_BRIEF_FEEDBACK_RATINGS: frozenset[str] = frozenset({
    "positive", "negative", "mute",
})


def _map_brief_feedback_row(ev: dict) -> dict:
    """Mapper para rag_brief_feedback. Shape simple: ts/dedup_key/rating/
    reason/source. NO hay extra_json — si en el futuro queremos meter
    más metadata por feedback (chat origin, latency entre push y
    reply, etc.), agregamos columna nueva via migration."""
    out: dict = {}
    for k in ("ts", "dedup_key", "rating", "reason", "source"):
        if k in ev and ev[k] is not None:
            out[k] = ev[k]
    if "ts" not in out:
        out["ts"] = datetime.now().isoformat(timespec="seconds")
    return out


def _record_brief_feedback(
    *,
    dedup_key: str,
    rating: str,
    reason: str = "",
    source: str = "wa",
) -> int | None:
    """Persiste un feedback del user sobre un brief (morning/evening/digest)
    a `rag_brief_feedback`. Cierra el loop de los briefs:

    - El daemon de briefs escribe el archivo + lo pushea a WhatsApp
      con un footer `_brief:<vault_relpath>_` (ver
      `_brief_push_to_whatsapp`).
    - El listener TS detecta la reacción del user (👍/👎/🔇 o tokens
      "ok"/"no"/"basta") dentro de los 30min siguientes y postea acá
      via `POST /api/brief/feedback`.
    - Esta función inserta la row.

    Args:
        dedup_key: vault_relpath del brief al que apunta el feedback.
            Único por brief (cada brief lleva la fecha en el nombre).
        rating: uno de `positive | negative | mute`. Cualquier otro
            valor → return None.
        reason: texto libre opcional (ej. el body completo del reply
            para debug).
        source: origen del feedback (default 'wa' — WhatsApp). Forward-
            compatible con otros canales (PWA, CLI, etc.).

    Returns:
        rowid del INSERT, o None si la rating es inválida o el write
        falla (silent-fail — la UX del listener no debe romperse por
        un fallo de telemetría). Mismo contract que
        `_record_draft_decision` y `record_feedback` del anticipatory
        agent.
    """
    if not dedup_key:
        return None
    if rating not in _VALID_BRIEF_FEEDBACK_RATINGS:
        return None
    row = {
        "ts": datetime.now().isoformat(timespec="seconds"),
        "dedup_key": dedup_key,
        "rating": rating,
        "reason": reason or "",
        "source": source or "wa",
    }
    holder: dict = {"id": None}

    def _do() -> None:
        with _ragvec_state_conn() as conn:
            holder["id"] = _sql_append_event(
                conn, "rag_brief_feedback", _map_brief_feedback_row(row),
            )
    try:
        _sql_write_with_retry(_do, "brief_feedback_sql_write_failed")
    except Exception as exc:  # pragma: no cover - retry helper ya silencia
        _silent_log("brief_feedback_helper", exc)
        return None
    return holder["id"]


def _map_cpu_row(ev: dict) -> dict:
    out: dict = {}
    for k in ("ts", "total_pct", "ncores", "interval_s"):
        if k in ev and ev[k] is not None:
            out[k] = ev[k]
    if "by_category" in ev:
        out["by_category_json"] = ev["by_category"]
    if "top" in ev:
        out["top_json"] = ev["top"]
    if "ts" not in out:
        out["ts"] = datetime.now().isoformat(timespec="seconds")
    known = {"ts", "total_pct", "ncores", "interval_s", "by_category", "top"}
    extra = {k: v for k, v in ev.items() if k not in known}
    if extra:
        out["extra_json"] = extra
    return out


def _map_memory_row(ev: dict) -> dict:
    out: dict = {"ts": ev.get("ts") or datetime.now().isoformat(timespec="seconds")}
    if "total_mb" in ev and ev["total_mb"] is not None:
        out["total_mb"] = ev["total_mb"]
    if "by_category" in ev:
        out["by_category_json"] = ev["by_category"]
    if "top" in ev:
        out["top_json"] = ev["top"]
    if "vm" in ev:
        out["vm_json"] = ev["vm"]
    known = {"ts", "total_mb", "by_category", "top", "vm"}
    extra = {k: v for k, v in ev.items() if k not in known}
    if extra:
        out["extra_json"] = extra
    return out


# ── DB ────────────────────────────────────────────────────────────────────────
# sqlite-vec backend. Schema per "collection" (namespaced per-vault):
#   vec_{name}  — virtual table: rowid INTEGER PRIMARY KEY, embedding float[dim]
#   meta_{name} — regular table: rowid → chunk_id + document + metadata fields
# Extra metadata (frontmatter fields not in KNOWN_META_COLS) goes into
# meta_{name}.extra_json as a JSON blob — still SELECT-able via json_extract()
# if needed, but the hot-path `where` filters use proper columns.
#
# Concurrency model: single `ragvec.db` file, WAL mode. Writers serialize
# at _collection_write_lock() level (fcntl.flock). Readers run in parallel.


_KNOWN_META_COLS = (
    # Note-collection metadata
    "file", "folder", "note", "tags", "hash", "outlinks",
    "created_ts", "parent", "title", "area", "type", "archived_at",
    "archived_from", "archived_reason", "contradicts", "ambient",
    # URL sub-index metadata
    "url", "anchor", "line", "source", "profile", "bookmark_folder",
)


def _sanitize_table_suffix(name: str) -> str:
    """Collection name → SQL-safe table suffix. obsidian_notes_v9_abc123 is
    already alphanumeric+underscore; this is defensive."""
    return "".join(c if c.isalnum() or c == "_" else "_" for c in name)


class SqliteVecCollection:
    """sqlite-vec-backed collection.

    Exposes the subset of the API used by rag.py:
      count(), get(), add(), delete(), query(), .id, .name
    """

    __slots__ = ("_db", "name", "_dim", "_vec", "_meta")

    def __init__(self, db: "sqlite3.Connection", name: str, dim: int = 1024):
        self._db = db
        self.name = name
        self._dim = dim
        suffix = _sanitize_table_suffix(name)
        self._vec = f"vec_{suffix}"
        self._meta = f"meta_{suffix}"
        self._ensure_tables()

    def _ensure_tables(self):
        # Meta table is dim-independent → always create.
        # vec0 table requires a known dim; defer to _ensure_vec_table(dim)
        # called from the first add() — allows tests with 4-dim mocks and
        # production with 1024-dim bge-m3 to coexist without hardcoding.
        int_cols = {"line"}
        real_cols = {"created_ts"}
        cols_sql = ", ".join(
            f"{c} INTEGER" if c in int_cols
            else f"{c} REAL" if c in real_cols
            else f"{c} TEXT"
            for c in _KNOWN_META_COLS if c != "created_ts"
        )
        self._db.execute(
            f"CREATE TABLE IF NOT EXISTS {self._meta} ("
            " rowid INTEGER PRIMARY KEY, "
            " chunk_id TEXT UNIQUE NOT NULL, "
            " document TEXT, "
            f"{cols_sql}, "
            " created_ts REAL, "
            " extra_json TEXT"
            ")"
        )
        self._db.execute(
            f"CREATE INDEX IF NOT EXISTS idx_{self._meta}_file "
            f"ON {self._meta}(file)"
        )
        self._db.execute(
            f"CREATE INDEX IF NOT EXISTS idx_{self._meta}_folder "
            f"ON {self._meta}(folder)"
        )
        self._db.execute(
            "CREATE TABLE IF NOT EXISTS rag_schema_version ("
            " table_name TEXT PRIMARY KEY, "
            " version INTEGER NOT NULL DEFAULT 0"
            ")"
        )
        self._db.commit()

    def _ensure_vec_table(self, dim: int):
        """Create vec0 table lazily on first insert with the actual dim.
        If the table already exists with a different dim, drop+recreate
        (destructive — caller must own the decision, e.g. `index --reset`
        or switching between test/prod)."""
        existing = self._db.execute(
            "SELECT sql FROM sqlite_master WHERE type='table' AND name = ?",
            (self._vec,),
        ).fetchone()
        if existing:
            sql = existing[0]
            if f"float[{dim}]" in sql:
                return
            # Dim mismatch → recreate. Only safe when no rows yet.
            row_ct = self._db.execute(
                f"SELECT COUNT(*) FROM {self._meta}"
            ).fetchone()[0]
            if row_ct > 0:
                raise RuntimeError(
                    f"vec0 dim mismatch in '{self._vec}': existing != {dim} "
                    f"and {row_ct} meta rows exist. Drop/recreate needed."
                )
            self._db.execute(f"DROP TABLE {self._vec}")
        self._db.execute(
            f"CREATE VIRTUAL TABLE {self._vec} "
            f"USING vec0(embedding float[{dim}])"
        )
        self._dim = dim

    @property
    def id(self) -> str:
        """Monotonic schema version bumped on every destructive write.
        Used by _load_corpus() to detect stale BM25 cache — a new `id`
        signals the collection was destructively rewritten."""
        row = self._db.execute(
            "SELECT version FROM rag_schema_version WHERE table_name = ?",
            (self.name,),
        ).fetchone()
        return f"{self.name}:{row[0] if row else 0}"

    def _bump_version(self):
        self._db.execute(
            "INSERT INTO rag_schema_version(table_name, version) VALUES(?, 1) "
            "ON CONFLICT(table_name) DO UPDATE SET version = version + 1",
            (self.name,),
        )

    def count(self) -> int:
        return self._db.execute(
            f"SELECT COUNT(*) FROM {self._meta}"
        ).fetchone()[0]

    @staticmethod
    def _build_where(where: dict | None) -> tuple[str, list]:
        """Translate a dict-based `where` filter to a SQL WHERE clause.

        Supported:
          {field: value}              → `field = ?`
          {field: {"$in": [...]}}     → `field IN (?, ?, …)`
          {field: {"$contains": "x"}} → `field LIKE '%x%'`
          {field: {"$gte": n}}        → `field >= ?`  (also $gt/$lte/$lt/$ne)
          {"$and": [cond1, cond2]}    → `(cond1) AND (cond2)`
          {"$or": [cond1, cond2]}     → `(cond1) OR (cond2)`
        """
        def _expand(cond: dict) -> tuple[str, list]:
            if not cond:
                return "1 = 1", []
            parts: list[str] = []
            params: list = []
            for k, v in cond.items():
                if k == "$and":
                    subs = [_expand(c) for c in v]
                    parts.append(" AND ".join(f"({s[0]})" for s in subs))
                    for s in subs:
                        params.extend(s[1])
                elif k == "$or":
                    subs = [_expand(c) for c in v]
                    parts.append(" OR ".join(f"({s[0]})" for s in subs))
                    for s in subs:
                        params.extend(s[1])
                elif isinstance(v, dict):
                    # Field-level operator dict
                    field_parts = []
                    for op, val in v.items():
                        if op == "$in":
                            vals = list(val)
                            if not vals:
                                field_parts.append("0 = 1")
                            else:
                                ph = ",".join("?" * len(vals))
                                field_parts.append(f"{k} IN ({ph})")
                                params.extend(vals)
                        elif op == "$nin":
                            vals = list(val)
                            if not vals:
                                field_parts.append("1 = 1")
                            else:
                                ph = ",".join("?" * len(vals))
                                field_parts.append(f"({k} NOT IN ({ph}) OR {k} IS NULL)")
                                params.extend(vals)
                        elif op == "$contains":
                            field_parts.append(f"{k} LIKE ?")
                            params.append(f"%{val}%")
                        elif op == "$gte":
                            field_parts.append(f"{k} >= ?")
                            params.append(val)
                        elif op == "$lte":
                            field_parts.append(f"{k} <= ?")
                            params.append(val)
                        elif op == "$gt":
                            field_parts.append(f"{k} > ?")
                            params.append(val)
                        elif op == "$lt":
                            field_parts.append(f"{k} < ?")
                            params.append(val)
                        elif op == "$ne":
                            field_parts.append(f"({k} != ? OR {k} IS NULL)")
                            params.append(val)
                        elif op == "$eq":
                            field_parts.append(f"{k} = ?")
                            params.append(val)
                        else:
                            # Unknown operator — fall through to equality of dict
                            # serialised as JSON. Defensive; shouldn't happen.
                            field_parts.append(f"{k} = ?")
                            params.append(json.dumps(v))
                    if field_parts:
                        parts.append(" AND ".join(field_parts))
                else:
                    parts.append(f"{k} = ?")
                    params.append(v)
            return " AND ".join(parts), params

        if not where:
            return "", []
        sql, params = _expand(where)
        return " WHERE " + sql, params

    def _row_to_meta(self, row, meta_col_names):
        """Reconstruct metadata dict from meta_* row."""
        out = {}
        for i, col in enumerate(meta_col_names):
            v = row[i]
            if v is None:
                continue
            out[col] = v
        # Merge extra_json if present
        extra = out.pop("extra_json", None)
        if extra:
            try:
                out.update(json.loads(extra))
            except Exception:
                pass
        return out

    def get(self, ids=None, where=None, include=None) -> dict:
        include = include or []
        want_docs = "documents" in include
        want_metas = "metadatas" in include
        want_embs = "embeddings" in include

        meta_cols = list(_KNOWN_META_COLS) + ["extra_json"]
        select_cols = ["rowid", "chunk_id"]
        if want_docs:
            select_cols.append("document")
        if want_metas:
            select_cols.extend(meta_cols)

        sql = f"SELECT {', '.join(select_cols)} FROM {self._meta}"
        params: list = []
        if ids is not None:
            ids_list = list(ids)
            if not ids_list:
                base = {"ids": []}
                if want_docs:
                    base["documents"] = []
                if want_metas:
                    base["metadatas"] = []
                if want_embs:
                    base["embeddings"] = []
                return base
            placeholders = ",".join("?" * len(ids_list))
            sql += f" WHERE chunk_id IN ({placeholders})"
            params = ids_list
        elif where:
            w_sql, w_params = self._build_where(where)
            sql += w_sql
            params = w_params

        rows = self._db.execute(sql, params).fetchall()
        result_ids = [r[1] for r in rows]
        out: dict = {"ids": result_ids}

        if want_docs:
            doc_idx = 2
            out["documents"] = [r[doc_idx] for r in rows]
        if want_metas:
            meta_start = 2 + (1 if want_docs else 0)
            out["metadatas"] = [self._row_to_meta(r[meta_start:], meta_cols) for r in rows]
        if want_embs:
            import numpy as _np
            rowids = [r[0] for r in rows]
            embed_map: dict[int, list[float]] = {}
            vec_exists = self._db.execute(
                "SELECT 1 FROM sqlite_master WHERE type='table' AND name = ?",
                (self._vec,),
            ).fetchone() is not None
            if rowids and vec_exists:
                placeholders = ",".join("?" * len(rowids))
                for rid, raw in self._db.execute(
                    f"SELECT rowid, embedding FROM {self._vec} WHERE rowid IN ({placeholders})",
                    rowids,
                ).fetchall():
                    arr = _np.frombuffer(raw, dtype="float32")
                    embed_map[rid] = arr.tolist()
            out["embeddings"] = [embed_map.get(r[0]) for r in rows]

        return out

    def add(self, ids, embeddings, documents, metadatas):
        known = _KNOWN_META_COLS
        # Lazily create the vec0 table with the actual embedding dim.
        embeddings = [list(e) for e in embeddings]
        if embeddings:
            self._ensure_vec_table(len(embeddings[0]))
        with self._db:
            for cid, emb, doc, meta in zip(ids, embeddings, documents, metadatas):
                extra = {k: v for k, v in meta.items() if k not in known}
                extra_json = json.dumps(extra, ensure_ascii=False) if extra else None
                # Normalize created_ts to float or None
                created_ts = meta.get("created_ts")
                try:
                    created_ts = float(created_ts) if created_ts is not None else None
                except (TypeError, ValueError):
                    created_ts = None
                values = [cid, doc]
                for col in known:
                    if col == "created_ts":
                        values.append(created_ts)
                    else:
                        v = meta.get(col)
                        # Preserve primitive types (int/float/bool/str/None);
                        # only stringify complex values like lists/dicts.
                        if v is None or isinstance(v, (int, float, bool, str)):
                            values.append(v)
                        else:
                            values.append(str(v))
                values.append(extra_json)
                cols_list = ["chunk_id", "document"] + list(known) + ["extra_json"]
                placeholders = ",".join("?" * len(values))
                updates = ", ".join(f"{c}=excluded.{c}" for c in cols_list if c != "chunk_id")
                self._db.execute(
                    f"INSERT INTO {self._meta}({','.join(cols_list)}) VALUES({placeholders}) "
                    f"ON CONFLICT(chunk_id) DO UPDATE SET {updates}",
                    values,
                )
                rowid = self._db.execute(
                    f"SELECT rowid FROM {self._meta} WHERE chunk_id = ?", (cid,)
                ).fetchone()[0]
                # Replace vec entry (vec0 doesn't support upsert directly)
                self._db.execute(f"DELETE FROM {self._vec} WHERE rowid = ?", (rowid,))
                self._db.execute(
                    f"INSERT INTO {self._vec}(rowid, embedding) VALUES(?, ?)",
                    (rowid, sqlite_vec.serialize_float32(list(emb))),
                )
            self._bump_version()

    def update(self, ids, metadatas):
        """Metadata-only update — keeps the embedding + document untouched.

        Chromadb-era callers (`_maybe_backfill_created_ts` en rag.py:18434)
        esperan `col.update(ids=..., metadatas=...)`. Sin este método el
        backfill lazy fallaba con
        `AttributeError: 'SqliteVecCollection' object has no attribute 'update'`
        y cada query con `date_range` omitía silenciosamente los chunks
        pre-temporal (verificado en `web.log` 2026-04-20).

        Updates only the columns present in each meta dict. Missing columns
        stay at their current value (no NULL clobbering). `extra_json` is
        fully rewritten from the non-known-cols present in the incoming
        meta — callers should pass the FULL merged metadata dict (same
        convention as `add`), not a partial patch.
        """
        if not ids:
            return
        known = _KNOWN_META_COLS
        with self._db:
            for cid, meta in zip(ids, metadatas):
                if meta is None:
                    continue
                # Split into first-class cols vs the extra bag.
                set_clauses: list[str] = []
                params: list = []
                for col in known:
                    if col not in meta:
                        continue
                    v = meta.get(col)
                    if col == "created_ts":
                        try:
                            v = float(v) if v is not None else None
                        except (TypeError, ValueError):
                            v = None
                    elif v is not None and not isinstance(v, (int, float, bool, str)):
                        v = str(v)
                    set_clauses.append(f"{col}=?")
                    params.append(v)
                # Rewrite `extra_json` from every non-known key present in
                # the payload — mirrors `add()`'s normalization so a roundtrip
                # add→update stays shape-stable.
                extra_keys = [k for k in meta.keys() if k not in known]
                if extra_keys:
                    extra = {k: meta[k] for k in extra_keys}
                    set_clauses.append("extra_json=?")
                    params.append(json.dumps(extra, ensure_ascii=False) if extra else None)
                if not set_clauses:
                    continue
                params.append(cid)
                self._db.execute(
                    f"UPDATE {self._meta} SET {', '.join(set_clauses)} WHERE chunk_id=?",
                    params,
                )
            self._bump_version()

    def delete(self, ids=None, where=None):
        rowids: list[int] = []
        if ids is not None:
            if not ids:
                return
            placeholders = ",".join("?" * len(ids))
            rowids = [r[0] for r in self._db.execute(
                f"SELECT rowid FROM {self._meta} WHERE chunk_id IN ({placeholders})",
                list(ids),
            ).fetchall()]
        elif where:
            w_sql, w_params = self._build_where(where)
            rowids = [r[0] for r in self._db.execute(
                f"SELECT rowid FROM {self._meta}" + w_sql, w_params,
            ).fetchall()]
        if not rowids:
            return
        with self._db:
            placeholders = ",".join("?" * len(rowids))
            self._db.execute(
                f"DELETE FROM {self._vec} WHERE rowid IN ({placeholders})", rowids,
            )
            self._db.execute(
                f"DELETE FROM {self._meta} WHERE rowid IN ({placeholders})", rowids,
            )
            self._bump_version()

    def query(self, query_embeddings, n_results: int = 10,
              where=None, include=None) -> dict:
        """Semantic search. Returns batched results: {ids, documents,
        metadatas, distances} each as list[list[...]] — one sublist per
        query embedding."""
        include = include or ["documents", "metadatas", "distances"]
        want_docs = "documents" in include
        want_metas = "metadatas" in include
        want_dist = "distances" in include

        meta_cols = list(_KNOWN_META_COLS) + ["extra_json"]
        select_cols = ["m.chunk_id"]
        if want_docs:
            select_cols.append("m.document")
        if want_metas:
            select_cols.extend(f"m.{c}" for c in meta_cols)
        select_cols.append("v.distance")
        # Trailing v.rowid → used only for Python-side stable tie-breaking.
        select_cols.append("v.rowid")

        where_sql, where_params = self._build_where(where)
        # vec0's MATCH is restrictive — can't chain arbitrary predicates in
        # the same SELECT. Split the knn into a CTE and apply metadata
        # filters on the outer SELECT. Over-fetch by 4× to compensate for
        # post-filtering losing top candidates.
        fetch_n = int(n_results)
        post_filter = bool(where_sql)
        if post_filter:
            fetch_n = int(n_results) * 4 + 20

        out: dict[str, list] = {"ids": []}
        if want_docs:
            out["documents"] = []
        if want_metas:
            out["metadatas"] = []
        if want_dist:
            out["distances"] = []

        vec_exists = self._db.execute(
            "SELECT 1 FROM sqlite_master WHERE type='table' AND name = ?",
            (self._vec,),
        ).fetchone() is not None
        if not vec_exists:
            for _ in query_embeddings:
                out["ids"].append([])
                if want_docs:
                    out["documents"].append([])
                if want_metas:
                    out["metadatas"].append([])
                if want_dist:
                    out["distances"].append([])
            return out

        for qemb in query_embeddings:
            # Step 1: vec0 knn into a subquery (no extra predicates allowed).
            # Step 2: outer SELECT joins meta, applies user `where`, limits to n_results.
            outer_where = where_sql  # already starts with " WHERE " if non-empty
            # Secondary sort by rowid keeps tied distances in insertion order
            # — without it, vec0 may return ties non-deterministically.
            sql = (
                f"SELECT {', '.join(select_cols)} FROM ("
                f"  SELECT rowid, distance FROM {self._vec} "
                f"  WHERE embedding MATCH ? AND k = ? ORDER BY distance"
                f") v JOIN {self._meta} m ON v.rowid = m.rowid"
                f"{outer_where} "
                f"LIMIT ?"
            )
            params = (
                [sqlite_vec.serialize_float32(list(qemb)), fetch_n]
                + where_params
                + [int(n_results)]
            )
            rows = self._db.execute(sql, params).fetchall()
            # Python-side stable sort by (distance, rowid) — sqlite-vec ties
            # resolve arbitrarily inside vec0, so we enforce insertion-order
            # for ties here. Columns layout: chunk_id [doc] [meta*] distance rowid.
            rows = sorted(rows, key=lambda r: (r[-2], r[-1]))
            ids = [r[0] for r in rows]
            out["ids"].append(ids)
            if want_docs:
                out["documents"].append([r[1] for r in rows])
            if want_metas:
                ms_start = 2 if want_docs else 1
                out["metadatas"].append(
                    [self._row_to_meta(r[ms_start:ms_start + len(meta_cols)], meta_cols)
                     for r in rows]
                )
            if want_dist:
                out["distances"].append([r[-2] for r in rows])

        return out


class SqliteVecClient:
    """sqlite-vec client. All collections share one SQLite file
    (ragvec.db inside path).

    Concurrency contract — READ THIS BEFORE ADDING PARALLELISM:

    - The connection uses `check_same_thread=False` + `isolation_level=None`
      (autocommit) + WAL + NORMAL synchronous. Multiple threads can issue
      statements on the same connection; SQLite serialises them internally.
    - Readers are **eventually consistent**, not snapshot-isolated. A query
      that runs mid-write may see the post-write state for some rows and the
      pre-write state for others (WAL gives durability, not MVCC snapshots
      at the Python API level since we autocommit). Good enough for the
      retrieval pipeline, which tolerates a chunk appearing/disappearing
      between calls.
    - Writes are serialised **at the application layer** by
      `_collection_write_lock()` — the module-wide file lock under
      `~/.local/share/obsidian-rag/.collection-ops.lock`. DO NOT rely on
      SQLite's busy_timeout alone for correctness; the write lock also
      guards the JSONL audit trail + schema-version bump.
    - Telemetry writes inside `RAG_STATE_SQL` tables use explicit
      `BEGIN IMMEDIATE` + `COMMIT` wrappers (see `_sql_upsert`) because
      they batch multiple rows. Vec writes (`col.add`) are single-row and
      run under autocommit.

    If you add snapshot reads (e.g. "give me a consistent view during a
    long analytical scan"), wrap the read in `BEGIN DEFERRED` / `COMMIT`
    explicitly — autocommit + WAL is not enough.
    """

    def __init__(self, path):
        import sqlite3 as _sqlite3
        self.path = Path(path)
        self.path.mkdir(parents=True, exist_ok=True)
        self._file = self.path / "ragvec.db"
        self._db = _sqlite3.connect(str(self._file), check_same_thread=False,
                                    isolation_level=None)
        self._db.enable_load_extension(True)
        sqlite_vec.load(self._db)
        self._db.execute("PRAGMA journal_mode=WAL")
        self._db.execute("PRAGMA synchronous=NORMAL")
        self._db.execute("PRAGMA busy_timeout=10000")
        self._db.execute(
            "CREATE TABLE IF NOT EXISTS rag_schema_version ("
            " table_name TEXT PRIMARY KEY, "
            " version INTEGER NOT NULL DEFAULT 0"
            ")"
        )
        self._db.commit()
        self._collections: dict[str, SqliteVecCollection] = {}
        # Post 2026-04-21 split: telemetry tables live in telemetry.db (see
        # _TELEMETRY_DB_FILENAME + _ragvec_state_conn). SqliteVecClient no
        # longer creates rag_* tables on ragvec.db — that was a safety net
        # for a pre-T10 code path that's gone. RAG_STATE_SQL env is still
        # respected by plist trail-config but now a no-op here.

    def get_or_create_collection(self, name: str, metadata=None):
        # metadata arg ignored (was `{"hnsw:space": "cosine"}`); sqlite-vec
        # uses cosine distance natively via vec0 MATCH.
        if name not in self._collections:
            self._collections[name] = SqliteVecCollection(self._db, name)
        return self._collections[name]

    def list_collections(self):
        rows = self._db.execute(
            "SELECT name FROM sqlite_master WHERE type='table' AND name LIKE 'meta_%' "
            "ORDER BY name"
        ).fetchall()
        # Strip "meta_" prefix → collection name
        names = [r[0][5:] for r in rows]
        # Return lightweight objects with .name (callers only use .name)
        class _ColRef:
            def __init__(self, n): self.name = n
        return [_ColRef(n) for n in names]

    def delete_collection(self, name: str):
        suffix = _sanitize_table_suffix(name)
        with self._db:
            self._db.execute(f"DROP TABLE IF EXISTS vec_{suffix}")
            self._db.execute(f"DROP TABLE IF EXISTS meta_{suffix}")
            self._db.execute(
                "DELETE FROM rag_schema_version WHERE table_name = ?", (name,)
            )
        self._collections.pop(name, None)


_db_singleton: tuple[str, "SqliteVecCollection"] | None = None
_db_singleton_created_at: float = 0.0
_db_singleton_lock = threading.Lock()


def get_db() -> SqliteVecCollection:
    global _db_singleton, _db_singleton_created_at
    db_key = str(DB_PATH)
    with _db_singleton_lock:
        if _db_singleton is not None and _db_singleton[0] == db_key:
            # Cheap sentinel mtime check: if another process ran `index --reset`
            # after we cached the handle, the sentinel file will be newer.
            try:
                sentinel_mtime = os.stat(COLLECTION_RESET_SENTINEL).st_mtime
                if sentinel_mtime > _db_singleton_created_at:
                    _db_singleton = None
            except FileNotFoundError:
                pass
        if _db_singleton is None or _db_singleton[0] != db_key:
            DB_PATH.mkdir(parents=True, exist_ok=True)
            client = SqliteVecClient(path=db_key)
            col = client.get_or_create_collection(
                name=COLLECTION_NAME,
                metadata={"hnsw:space": "cosine"},
            )
            _db_singleton = (db_key, col)
            _db_singleton_created_at = time.time()
        return _db_singleton[1]


def _collection_name_for_vault(vault_path: Path) -> str:
    """Mismo schema que COLLECTION_NAME: sha256[:8] sufijo salvo default.
    Factorizado para que podamos abrir colecciones de vaults *distintos* al
    activo sin tocar VAULT_PATH ni forzar reimport.
    """
    resolved = vault_path.resolve()
    if str(resolved) == str(_DEFAULT_VAULT.resolve()):
        return _COLLECTION_BASE
    slug = hashlib.sha256(str(resolved).encode()).hexdigest()[:8]
    return f"{_COLLECTION_BASE}_{slug}"


def get_db_for(vault_path: Path) -> SqliteVecCollection:
    """Abre la colección sqlite-vec correspondiente a un vault arbitrario.
    Todos los vaults viven en la misma DB (DB_PATH) — la separación es por
    nombre de colección, namespaced por hash del path del vault.
    No hay singleton aquí: cada llamada abre un cliente fresco, así que el
    sentinel de reset no aplica — `index --reset` invalida el singleton de
    get_db() y siempre llama a get_or_create_collection que devuelve el UUID
    vigente.
    """
    DB_PATH.mkdir(parents=True, exist_ok=True)
    client = SqliteVecClient(path=str(DB_PATH))
    return client.get_or_create_collection(
        name=_collection_name_for_vault(vault_path),
        metadata={"hnsw:space": "cosine"},
    )


def _urls_collection_name_for_vault(vault_path: Path) -> str:
    """Mismo schema que URLS_COLLECTION_NAME pero para un vault arbitrario."""
    resolved = vault_path.resolve()
    if str(resolved) == str(_DEFAULT_VAULT.resolve()):
        return _URLS_COLLECTION_BASE
    slug = hashlib.sha256(str(resolved).encode()).hexdigest()[:8]
    return f"{_URLS_COLLECTION_BASE}_{slug}"


# ── Auto-index ────────────────────────────────────────────────────────────────
# Detectar y absorber cambios del vault sin que el usuario tenga que correr
# `rag index` explícito. Dos casos:
#   1. Vault vacío en scope → first-time full index (silent excepto progreso).
#   2. Vault con contenido + archivos modificados desde último check → reindex
#      incremental SOLO de esos archivos. mtime es el filtro barato; hash
#      gate dentro de _index_single_file evita reembedding si nada cambió.
# Persistimos last_check_at por vault para no leer todos los archivos cada
# vez que arranca el chat.

AUTO_INDEX_STATE_PATH = Path.home() / ".local/share/obsidian-rag/auto_index_state.json"


def _auto_index_state_load() -> dict:
    """Lee el state de auto-index. Estructura: {vault_hash: last_check_ts}.
    Tolerante a archivo faltante o corrupto — devuelve {} en cualquier error.
    """
    if not AUTO_INDEX_STATE_PATH.is_file():
        return {}
    try:
        return json.loads(AUTO_INDEX_STATE_PATH.read_text(encoding="utf-8"))
    except Exception:
        return {}


def _auto_index_state_save(state: dict) -> None:
    try:
        AUTO_INDEX_STATE_PATH.parent.mkdir(parents=True, exist_ok=True)
        AUTO_INDEX_STATE_PATH.write_text(
            json.dumps(state, indent=2), encoding="utf-8",
        )
    except Exception as exc:
        _silent_log("auto_index_state_save", exc)


def _vault_state_key(vault_path: Path) -> str:
    """Clave estable para el state — sha256[:16] del path absoluto."""
    return hashlib.sha256(str(vault_path.resolve()).encode()).hexdigest()[:16]


@contextlib.contextmanager
def _with_vault(vault_path: Path):
    """Context manager que swappea los globals VAULT_PATH /
    COLLECTION_NAME / URLS_COLLECTION_NAME para apuntar a otro vault.

    Usado por _auto_index_vault para reusar _index_single_file (que asume
    que VAULT_PATH es el vault target). Single-threaded — NO usar entre
    threads. Restaura los valores en finally + invalida cache de corpus.
    """
    g = globals()
    saved = {
        "VAULT_PATH": g["VAULT_PATH"],
        "COLLECTION_NAME": g["COLLECTION_NAME"],
        "URLS_COLLECTION_NAME": g["URLS_COLLECTION_NAME"],
    }
    try:
        g["VAULT_PATH"] = vault_path
        g["COLLECTION_NAME"] = _collection_name_for_vault(vault_path)
        g["URLS_COLLECTION_NAME"] = _urls_collection_name_for_vault(vault_path)
        _invalidate_corpus_cache()
        yield
    finally:
        g["VAULT_PATH"] = saved["VAULT_PATH"]
        g["COLLECTION_NAME"] = saved["COLLECTION_NAME"]
        g["URLS_COLLECTION_NAME"] = saved["URLS_COLLECTION_NAME"]
        _invalidate_corpus_cache()


def auto_index_vault(vault_path: Path) -> dict:
    """Detecta cambios en `vault_path` y reindexa lo necesario. Retorna
    {scanned, indexed, removed, kind, took_ms} donde kind ∈
    {"first_time", "incremental", "no_changes", "skipped_lock_held"}.

    Estrategia:
      - Vault vacío → first_time, escanea todo + indexa.
      - Vault con contenido → mtime-based incremental: solo lee archivos
        cuyo mtime > last_check_at. Para cada uno, _index_single_file
        ya hace su propio hash gate (skip si content no cambió de verdad).
      - Limpia orphans (archivos en el índice que ya no están en disco).
      - Actualiza last_check_at al final.

    If the collection write lock is held by another process (e.g. rag index
    --reset), skips this cycle immediately and returns kind="skipped_lock_held".
    Watch will trigger again on the next file change; chat has already started.
    """
    import time as _t
    t0 = _t.perf_counter()

    # Non-blocking lock probe: if a reset or another heavy writer holds the
    # lock, skip this entire auto-index cycle rather than racing or waiting.
    # Individual _index_single_file calls acquire the lock themselves (10s
    # timeout), so watch-triggered single-file writes still serialize correctly.
    try:
        with _collection_write_lock(blocking=False):
            pass  # just probe; real acquire happens inside _index_single_file
    except LockHeldError:
        _log_collection_op("auto_index_skipped", str(vault_path), {"reason": "write_lock_held"})
        return {
            "scanned": 0,
            "indexed": 0,
            "removed": 0,
            "kind": "skipped_lock_held",
            "took_ms": int((_t.perf_counter() - t0) * 1000),
        }
    state = _auto_index_state_load()
    key = _vault_state_key(vault_path)
    last_check = float(state.get(key, 0.0))

    with _with_vault(vault_path):
        # Usar get_db_for(vault_path) en vez de get_db() — el singleton de
        # get_db() cachea por DB_PATH e ignora COLLECTION_NAME del swap,
        # entonces auto_index de un vault secundario terminaba operando
        # sobre la colección del vault default. La orphan-cleanup veía
        # on_disk del vault X contra indexed_files del vault default y
        # borraba todo lo que no matcheara (bug: drenaba home al autoindexar
        # work).
        col = get_db_for(vault_path)
        first_time = col.count() == 0

        # Listar md files (rglob es rápido en APFS, ~50ms para 500 archivos).
        # Audit 2026-04-26: skip symlinks para evitar ciclos (a→b→a).
        # Python 3.13+ rglob soporta `recurse_symlinks=False`. En 3.13 o
        # menor caemos al manual `is_symlink()` check.
        md_files: list[Path] = []
        try:
            _md_iter = vault_path.rglob("*.md", recurse_symlinks=False)
        except TypeError:
            _md_iter = vault_path.rglob("*.md")
        for p in _md_iter:
            try:
                if p.is_symlink():
                    continue
                rel = p.relative_to(vault_path)
            except ValueError:
                continue
            except OSError:
                continue
            if is_excluded(str(rel)):
                continue
            md_files.append(p)

        # Bootstrap: si la colección ya tiene chunks pero last_check es 0
        # (estado no existía o fue borrado), asumimos que el index está al
        # día y solo persistimos el timestamp actual. Sin esto, la primera
        # corrida de auto_index escanea TODOS los archivos via
        # _index_single_file (col.get por archivo = ~25s en 500 notas) —
        # dispara un hang aparente al arrancar chat.
        if not first_time and last_check == 0.0:
            state[key] = _t.time()
            _auto_index_state_save(state)
            return {
                "scanned": len(md_files),
                "indexed": 0,
                "removed": 0,
                "kind": "no_changes",
                "took_ms": int((_t.perf_counter() - t0) * 1000),
            }

        # mtime-filter SOLO si no es first_time (ahí hay que indexar todo).
        if first_time:
            candidates = md_files
        else:
            candidates = [p for p in md_files if p.stat().st_mtime > last_check]

        indexed = 0
        indexed_paths: list[Path] = []
        for p in candidates:
            try:
                status = _index_single_file(col, p, skip_contradict=True)
            except Exception:
                continue
            if status == "indexed":
                indexed += 1
                indexed_paths.append(p)

        # Orphans: archivos en el índice que ya no están en disco. Solo
        # vale chequear cuando el vault ya estaba indexado (skip first_time).
        # SAFETY GATE (2026-04-18): iCloud sync puede hacer que rglob devuelva
        # 0 archivos temporariamente — sin este guard, TODOS los chunks se
        # marcan como orphans y se borra la colección entera. Bailout si
        # on_disk está vacío (no hay archivos visibles) o si on_disk cubre
        # <10% del set indexado (sync parcial). Logeamos y dejamos que la
        # próxima corrida limpie cuando sync haya terminado.
        removed = 0
        if not first_time:
            on_disk = {str(p.relative_to(vault_path)) for p in md_files}
            existing = col.get(include=["metadatas"])
            indexed_files = {m.get("file", "") for m in existing["metadatas"]}
            indexed_files.discard("")
            if not on_disk:
                print(
                    f"[auto_index] {vault_path.name}: rglob 0 files — "
                    f"skip orphan cleanup (iCloud sync in progress?)",
                    flush=True,
                )
                orphans = set()
            elif indexed_files and len(on_disk) < 0.1 * len(indexed_files):
                print(
                    f"[auto_index] {vault_path.name}: on_disk={len(on_disk)} "
                    f"vs indexed={len(indexed_files)} — too many orphans, "
                    f"skip cleanup (likely sync glitch)",
                    flush=True,
                )
                orphans = set()
            else:
                orphans = indexed_files - on_disk
            # Double-check per-orphan via is_file() inside the write lock.
            # rglob on iCloud can return a partial listing during sync (file
            # exists but momentarily invisible) — without this guard that
            # single missing path gets deleted from the index. is_file() on
            # the exact path hits macOS's fileProvider and reliably reflects
            # the real on-disk state.
            if orphans:
                with _collection_write_lock():
                    for orphan in orphans:
                        if (vault_path / orphan).is_file():
                            continue  # false positive from stale rglob
                        stale = col.get(where={"file": orphan}, include=[])
                        if stale["ids"]:
                            col.delete(ids=stale["ids"])
                            removed += 1

    state[key] = _t.time()
    _auto_index_state_save(state)

    # ── LLM Wiki layer hook ──────────────────────────────────────────────────
    # After the sqlite-vec indexing settles, compile a wiki page per newly
    # indexed source and refresh Wiki/index.md. Silent-fail end-to-end — the
    # indexing above already succeeded; if the helper model is wedged or
    # something else blows up, we log to silent_errors.jsonl and return the
    # usual stats untouched. Kill-switch: OBSIDIAN_RAG_WIKI_ENABLED=0.
    if indexed_paths:
        try:
            _wiki_ingest_indexed_files(vault_path, indexed_paths)
        except Exception as exc:
            _silent_log("auto_index_wiki_hook", exc)

    if first_time and indexed > 0:
        kind = "first_time"
    elif indexed == 0 and removed == 0:
        kind = "no_changes"
    else:
        kind = "incremental"

    return {
        "scanned": len(md_files),
        "indexed": indexed,
        "removed": removed,
        "kind": kind,
        "took_ms": int((_t.perf_counter() - t0) * 1000),
    }


def get_urls_db() -> SqliteVecCollection:
    """Companion collection storing one row per URL found in the vault, with
    its surrounding prose embedded for semantic-by-context lookup.
    """
    DB_PATH.mkdir(parents=True, exist_ok=True)
    client = SqliteVecClient(path=str(DB_PATH))
    return client.get_or_create_collection(
        name=URLS_COLLECTION_NAME,
        metadata={"hnsw:space": "cosine"},
    )


# ── URL EXTRACTION ────────────────────────────────────────────────────────────
# URLs in markdown notes show up two ways: as `[anchor](https://...)` (preferred,
# carries human description) and as bare `https://...`. We extract both, dedup
# by URL within a file, and capture ±URL_CONTEXT_CHARS of surrounding prose so
# the URL-finder can match queries like "donde está el link a la doc de X" by
# semantic similarity to that context, not to the URL itself.

URL_BARE_RE = re.compile(r'https?://[^\s\)\]"\'<>`]+', re.IGNORECASE)
URL_MD_RE = re.compile(r'\[([^\]]+)\]\((https?://[^\)\s]+)\)', re.IGNORECASE)
# Trailing punctuation that's almost never part of a real URL.
_URL_TRAILING_PUNCT = ".,;:!?)>\"'`"
URL_CONTEXT_CHARS = 240
# Images and media — almost always noise when the user asks for "links" or
# "documentación de X". Filtered at extraction time. Embedded image references
# in markdown also use `![alt](url)` which never goes through URL_MD_RE
# (notice the leading `!` is not consumed by `[`); but bare image URLs in prose
# are common (CDN links inside copy-pasted docs), so we filter on the path tail.
_IMAGE_EXT_RE = re.compile(
    r"\.(?:png|jpe?g|gif|svg|webp|bmp|ico|tiff?|avif|heic|mp4|webm|mov|mp3|wav|ogg|pdf)"
    r"(?:[?#].*)?$",
    re.IGNORECASE,
)


def _is_media_url(url: str) -> bool:
    return bool(_IMAGE_EXT_RE.search(url))


def _grab_url_context(text: str, start: int, end: int, window: int = URL_CONTEXT_CHARS) -> str:
    """Return up to `window` chars on each side of [start, end), single-line."""
    a = max(0, start - window)
    b = min(len(text), end + window)
    snippet = text[a:b]
    snippet = re.sub(r'\s+', ' ', snippet).strip()
    return snippet[:window * 2 + 100]


def extract_urls(text: str) -> list[dict]:
    """Pull every URL out of a note body. Returns deduped list of
    {url, anchor, line, context}.

    Markdown-style links are scanned first and consumed so a bare-URL pass
    doesn't double-flag the same address inside a `[label](url)`.
    """
    out: list[dict] = []
    seen: set[str] = set()
    consumed: list[tuple[int, int]] = []
    for m in URL_MD_RE.finditer(text):
        anchor, url = m.group(1).strip(), m.group(2).strip()
        consumed.append(m.span())
        if url in seen or _is_media_url(url):
            continue
        seen.add(url)
        out.append({
            "url": url,
            "anchor": anchor[:120],
            "line": text[:m.start()].count("\n") + 1,
            "context": _grab_url_context(text, m.start(), m.end()),
        })
    for m in URL_BARE_RE.finditer(text):
        if any(s <= m.start() < e for s, e in consumed):
            continue
        url = m.group(0).rstrip(_URL_TRAILING_PUNCT)
        if url in seen or _is_media_url(url):
            continue
        seen.add(url)
        out.append({
            "url": url,
            "anchor": "",
            "line": text[:m.start()].count("\n") + 1,
            "context": _grab_url_context(text, m.start(), m.end()),
        })
    return out


# MOZE (Money app) → monthly vault notes. User re-exports `MOZE_*.csv` to
# iCloud `/Finances` (mismo dir donde caen los `.xlsx` de resúmenes de
# tarjeta); transformamos cada mes en una nota markdown para que el
# pipeline normal de indexado la absorba. No hay retrieval path especial —
# chunks, graph y reranker la tratan como cualquier otra nota.
#
# Migración 2026-04-26: el dir antes era `/Backup`. Override por env via
# `OBSIDIAN_RAG_FINANCE_DIR` (compartido con `web/server.py:_fetch_finance`
# para que un solo override mueva ambos consumidores en sync).
MOZE_BACKUP_DIR = Path(
    os.environ.get("OBSIDIAN_RAG_FINANCE_DIR", "")
    or (Path.home() / "Library/Mobile Documents/com~apple~CloudDocs/Finances")
)
MOZE_VAULT_SUBPATH = os.environ.get(
    "OBSIDIAN_RAG_MOZE_FOLDER", "02-Areas/Personal/Finanzas/MOZE"
)
MOZE_MONTH_ES = [
    "", "enero", "febrero", "marzo", "abril", "mayo", "junio",
    "julio", "agosto", "septiembre", "octubre", "noviembre", "diciembre",
]


def _moze_pnum(s: str) -> float:
    """Parse MOZE numeric column: ES decimals, optional thousand dots."""
    s = (s or "").strip().replace(".", "").replace(",", ".")
    try:
        return float(s)
    except Exception:
        return 0.0


def _moze_fmt_ars(n: float) -> str:
    """$3.470.209 — ES-AR thousands, no decimals."""
    v = int(round(abs(n)))
    s = f"{v:,}".replace(",", ".")
    return f"${s}"


def _moze_parse_latest() -> tuple[Path, list[tuple[datetime, dict]]] | None:
    """Find newest MOZE_*.csv and parse into (date, row) tuples. Dates are
    MM/DD/YYYY; rows with unparseable dates are skipped.
    """
    try:
        csvs = sorted(
            MOZE_BACKUP_DIR.glob("MOZE_*.csv"),
            key=lambda p: p.stat().st_mtime,
            reverse=True,
        )
    except Exception:
        return None
    if not csvs:
        return None
    src = csvs[0]
    rows: list[tuple[datetime, dict]] = []
    try:
        with src.open(newline="", encoding="utf-8") as fh:
            for r in csv.DictReader(fh):
                raw = (r.get("Date") or "").strip()
                if not raw:
                    continue
                try:
                    d = datetime.strptime(raw, "%m/%d/%Y")
                except ValueError:
                    continue
                rows.append((d, r))
    except Exception:
        return None
    return (src, rows) if rows else None


def _moze_render_month(year: int, month: int, rows: list[tuple[datetime, dict]],
                       prev_rows: list[tuple[datetime, dict]],
                       source_name: str, source_mtime: float) -> str:
    """Render one monthly note. `rows`/`prev_rows` are pre-filtered to month.
    Deterministic — same inputs → same output — so the file hash is stable
    and the indexer skips unchanged months.
    """
    from collections import Counter

    def _sum_by(rs, cur_only="ARS"):
        tot = 0.0
        for _, r in rs:
            if (r.get("Currency") or "").strip() != cur_only:
                continue
            if (r.get("Type") or "").strip() != "Expense":
                continue
            tot += abs(_moze_pnum(r.get("Price")))
        return tot

    ars_this = _sum_by(rows, "ARS")
    ars_prev = _sum_by(prev_rows, "ARS")
    usd_this = sum(
        abs(_moze_pnum(r.get("Price")))
        for _, r in rows
        if (r.get("Type") or "").strip() == "Expense"
        and (r.get("Currency") or "").strip() in ("USD", "USDB")
    )
    income_ars = sum(
        abs(_moze_pnum(r.get("Price")))
        for _, r in rows
        if (r.get("Type") or "").strip() == "Income"
        and (r.get("Currency") or "").strip() == "ARS"
    )

    cat_tot: Counter = Counter()
    for _, r in rows:
        if (r.get("Currency") or "").strip() != "ARS":
            continue
        if (r.get("Type") or "").strip() != "Expense":
            continue
        cat = (r.get("Main Category") or "—").strip() or "—"
        cat_tot[cat] += abs(_moze_pnum(r.get("Price")))

    delta_pct = ((ars_this - ars_prev) / ars_prev * 100.0) if ars_prev else None
    month_label_es = f"{MOZE_MONTH_ES[month]} {year}"

    lines: list[str] = []
    lines.append("---")
    lines.append("type: finanzas")
    lines.append("source: MOZE")
    lines.append(f"month: {year:04d}-{month:02d}")
    lines.append(f"gasto_ars: {int(round(ars_this))}")
    if usd_this:
        lines.append(f"gasto_usd: {int(round(usd_this))}")
    if income_ars:
        lines.append(f"ingreso_ars: {int(round(income_ars))}")
    lines.append("tags: [finanzas, moze, gastos]")
    lines.append("ambient: skip")
    lines.append(f"source_file: {source_name}")
    lines.append("---")
    lines.append("")
    lines.append(f"# Finanzas — {month_label_es}")
    lines.append("")

    lines.append("## Resumen")
    lines.append("")
    lines.append(f"- Gasto ARS: **{_moze_fmt_ars(ars_this)}**")
    if ars_prev:
        delta_txt = f"{delta_pct:+.1f}%" if delta_pct is not None else "—"
        lines.append(f"- Mes anterior: {_moze_fmt_ars(ars_prev)} ({delta_txt})")
    if usd_this:
        lines.append(f"- Gasto USD: ${usd_this:,.2f}")
    if income_ars:
        lines.append(f"- Ingreso ARS: {_moze_fmt_ars(income_ars)}")
    lines.append(f"- Transacciones: {sum(1 for _, r in rows if (r.get('Type') or '') in ('Expense','Income'))}")
    lines.append("")

    if cat_tot:
        lines.append("## Top categorías (ARS)")
        lines.append("")
        for name, amt in cat_tot.most_common(10):
            share = (amt / ars_this * 100.0) if ars_this else 0.0
            lines.append(f"- {name}: {_moze_fmt_ars(amt)} ({share:.0f}%)")
        lines.append("")

    lines.append("## Transacciones")
    lines.append("")
    ordered = sorted(rows, key=lambda t: (t[0], t[1].get("Time") or ""))
    for d, r in ordered:
        typ = (r.get("Type") or "").strip()
        if typ not in ("Expense", "Income", "Receivable"):
            continue
        cur = (r.get("Currency") or "").strip()
        cat = (r.get("Main Category") or "").strip()
        sub = (r.get("Subcategory") or "").strip()
        name = (r.get("Name") or "").strip()
        store = (r.get("Store") or "").strip()
        amt = _moze_pnum(r.get("Price"))
        sign = "+" if typ == "Income" else "-"
        amt_str = _moze_fmt_ars(amt) if cur == "ARS" else f"${abs(amt):,.2f}"
        parts = [
            d.strftime("%Y-%m-%d"),
            typ,
            cat,
        ]
        if sub and sub != cat:
            parts.append(sub)
        if name:
            parts.append(name)
        if store:
            parts.append(store)
        parts.append(f"{sign}{amt_str} {cur}")
        lines.append(f"- {' · '.join(parts)}")
    lines.append("")

    return "\n".join(lines)


def _sync_moze_notes(vault_root: Path) -> dict:
    """Regenerate monthly MOZE notes under `{vault_root}/{MOZE_VAULT_SUBPATH}/`.

    Per-month note: `YYYY-MM.md`. Rewrite only if content changed (compare by
    file text) so the indexer's hash-based skip still works. Also writes an
    `_index.md` at the folder root with a summary table of recent months.

    Returns stats for logging. Silent-fail if no CSV is found.
    """
    from collections import defaultdict

    parsed = _moze_parse_latest()
    if not parsed:
        return {"ok": False, "reason": "no_csv"}
    src, rows = parsed

    by_month: dict[tuple[int, int], list[tuple[datetime, dict]]] = defaultdict(list)
    for d, r in rows:
        by_month[(d.year, d.month)].append((d, r))

    target_dir = vault_root / MOZE_VAULT_SUBPATH
    try:
        target_dir.mkdir(parents=True, exist_ok=True)
    except Exception as exc:
        return {"ok": False, "reason": f"mkdir: {exc}"}

    months_sorted = sorted(by_month.keys())
    src_mtime = src.stat().st_mtime
    written = 0
    skipped = 0
    current_set = set()

    for i, (year, month) in enumerate(months_sorted):
        fname = f"{year:04d}-{month:02d}.md"
        current_set.add(fname)
        month_rows = by_month[(year, month)]
        prev_rows: list[tuple[datetime, dict]] = []
        if i > 0:
            prev_rows = by_month[months_sorted[i - 1]]
        body = _moze_render_month(year, month, month_rows, prev_rows, src.name, src_mtime)
        path = target_dir / fname
        existing = path.read_text(encoding="utf-8") if path.is_file() else ""
        # Strip `generated_at`-style volatile fields — we don't emit any, so
        # a direct compare is enough; hash-based index skip follows naturally.
        if existing == body:
            skipped += 1
            continue
        path.write_text(body, encoding="utf-8")
        written += 1

    # Prune stale month files (e.g., a month that got fully deleted in MOZE).
    for p in target_dir.glob("*.md"):
        if p.name == "_index.md":
            continue
        if p.name not in current_set:
            try:
                p.unlink()
            except Exception:
                pass

    # Roll-up index note — gives chat queries like "cuánto gasté este año"
    # a single surface to land on instead of 12 per-month notes.
    idx_lines = [
        "---",
        "type: finanzas",
        "source: MOZE",
        "tags: [finanzas, moze, indice]",
        "ambient: skip",
        f"source_file: {src.name}",
        "---",
        "",
        "# Finanzas — índice mensual (MOZE)",
        "",
        f"Fuente: `{src.name}` (export Money app).",
        "",
        "| Mes | Gasto ARS | Δ vs mes ant |",
        "|---|---:|---:|",
    ]
    prev_tot = 0.0
    for (year, month) in months_sorted:
        mrows = by_month[(year, month)]
        tot = sum(
            abs(_moze_pnum(r.get("Price")))
            for _, r in mrows
            if (r.get("Type") or "").strip() == "Expense"
            and (r.get("Currency") or "").strip() == "ARS"
        )
        delta = ""
        if prev_tot:
            delta_pct = (tot - prev_tot) / prev_tot * 100.0
            delta = f"{delta_pct:+.1f}%"
        idx_lines.append(
            f"| [[{year:04d}-{month:02d}]] | {_moze_fmt_ars(tot)} | {delta} |"
        )
        prev_tot = tot
    idx_body = "\n".join(idx_lines) + "\n"
    idx_path = target_dir / "_index.md"
    if not idx_path.is_file() or idx_path.read_text(encoding="utf-8") != idx_body:
        idx_path.write_text(idx_body, encoding="utf-8")
        written += 1
    else:
        skipped += 1

    return {
        "ok": True,
        "source": src.name,
        "months_total": len(months_sorted),
        "months_written": written,
        "months_skipped": skipped,
        "target": str(target_dir.relative_to(vault_root)),
    }


# ── Resúmenes de tarjeta de crédito → notas mensuales ────────────────────
# El banco emite un `.xlsx` por ciclo (Santander Río exporta `Último resumen
# - <Marca> <Últimos4>.xlsx`) y el user lo deja caer en el mismo dir iCloud
# `/Finances` que los CSV de MOZE. Naming esperado: empieza con "Último
# resumen" (con o sin acento) — globs case-insensitive para tolerar
# variaciones del banco.
#
# Pre 2026-04-26 el data flow era unidireccional: web/server.py:_fetch_credit_
# cards leía el xlsx live (cache en RAM por (path, mtime)) y lo servía al
# tool `credit_cards_summary`. NO había notas markdown ni indexación en
# sqlite-vec — el chat solo veía las tarjetas vía pre-router que detectaba
# "tarjeta/visa/master/amex" y forzaba el tool. Cualquier query que NO
# matcheara el regex (ej. "listame los gastos en pesos" después de
# "Cuanto debo a la visa?") terminaba en MOZE chunks o en respuestas
# huecas porque el retriever no tenía nada de tarjetas que recuperar.
#
# Post-fix: `_sync_credit_cards_notes` genera 1 nota .md por (tarjeta,
# ciclo) bajo `02-Areas/Personal/Finanzas/Tarjetas/`. La nota incluye
# frontmatter estructurado (brand, last4, totales, fechas) + body con los
# top movimientos. `rag index` la absorbe vía rglob como cualquier nota
# del vault → embedding + reranker la levantan en `retrieve("gastos visa
# marzo")` aunque el pre-router no fire. El tool `credit_cards_summary`
# se mantiene en paralelo para datos transaccionales 100% frescos
# (REGLA 1.b del web system prompt: cita literal de tool fresca, no
# parafraseo de chunks).
#
# DUPLICACIÓN CONOCIDA: `_parse_credit_card_xlsx` (+ helpers `_parse_ars_or_
# usd`, `_parse_card_date`, `_CARD_BRAND_RE`, `_CARD_LAST4_RE`) existe
# byte-idéntico en `web/server.py` líneas ~5901-6192. La intención era
# hacer un único source-of-truth acá y que web importe desde rag, pero
# el refactor cross-file fue revertido por una sesión paralela mientras
# se shipia este commit. La duplicación es funcional (ambos parsers
# producen el mismo dict) pero hay riesgo de drift si alguien edita uno
# y olvida el otro. TODO: deduplicar movimiento posterior — flag
# `from rag import _parse_credit_card_xlsx` en web/server.py + delete
# de la copia. Tests de parser (`tests/test_credit_cards_parser.py`)
# importan desde `web.server` y siguen verdes; tests del sync
# (`tests/test_credit_cards_sync.py`) importan desde `rag`. Si los dos
# tests salen de sincro entre sí en el futuro, ese es el síntoma.
TARJETAS_VAULT_SUBPATH = os.environ.get(
    "OBSIDIAN_RAG_TARJETAS_FOLDER", "02-Areas/Personal/Finanzas/Tarjetas"
)

# Regex para extraer marca + últimos 4 del nombre de archivo o sheet name.
# Tolera "Visa Crédito terminada en 1059", "Visa 1059", "Mastercard 5234",
# "Amex 3456". Case-insensitive.
_CARD_BRAND_RE = re.compile(
    r"\b(Visa|Master(?:card)?|Amex|American\s*Express|Cabal|Maestro|Naranja)\b",
    re.IGNORECASE,
)
_CARD_LAST4_RE = re.compile(r"(\d{4})(?!\d)")


def _parse_ars_or_usd(raw: object) -> tuple[float | None, str | None]:
    """Parsea celdas tipo `$549.438,75`, `U$S98,93`, `-$926,15`, o numérico
    crudo (openpyxl puede devolver float si la celda tiene formato número).
    Retorna `(amount, currency)` donde currency ∈ {"ARS", "USD", None}.

    Heurística decimal: si el string tiene `,` lo asumimos formato ES
    (decimal coma, miles punto) y normalizamos. Si solo tiene `.` puede ser
    formato US (`24.99`) — solo strippeamos puntos como miles si hay 3
    dígitos exactos después, sino el punto es decimal.
    """
    if raw is None:
        return (None, None)
    if isinstance(raw, (int, float)):
        return (float(raw), None)
    s = str(raw).strip()
    if not s:
        return (None, None)
    cur: str | None = None
    if s.upper().startswith("U$S") or "U$S" in s.upper() or s.upper().startswith("USD"):
        cur = "USD"
    elif s.startswith("$") or "ARS" in s.upper():
        cur = "ARS"
    # Strippeamos símbolos no-numéricos.
    cleaned = re.sub(r"[^\d,.\-]", "", s)
    if "," in cleaned:
        # Formato ES: punto = miles, coma = decimal.
        cleaned = cleaned.replace(".", "").replace(",", ".")
    elif cleaned.count(".") > 1:
        # Múltiples puntos → todos son miles ES sin decimal explícito.
        cleaned = cleaned.replace(".", "")
    # Else: un solo punto → decimal US (`24.99`), dejarlo como está.
    try:
        return (float(cleaned), cur)
    except ValueError:
        return (None, cur)


def _parse_card_date(raw: object) -> str | None:
    """DD/MM/YYYY → ISO `YYYY-MM-DD`. None si no parsea. Acepta
    `datetime.date|datetime` (openpyxl normaliza fechas si la celda tiene
    formato fecha) y strings con prefijo (`"Cierre: 26/03/2026"`).
    """
    if raw is None:
        return None
    if hasattr(raw, "strftime"):
        try:
            return raw.strftime("%Y-%m-%d")
        except Exception:
            return None
    s = str(raw).strip()
    m = re.search(r"(\d{1,2})/(\d{1,2})/(\d{4})", s)
    if not m:
        return None
    try:
        d = datetime(int(m.group(3)), int(m.group(2)), int(m.group(1)))
        return d.strftime("%Y-%m-%d")
    except ValueError:
        return None


def _parse_credit_card_xlsx(path: Path) -> dict | None:
    """Parsea un `Último resumen - <Marca> <Últimos4>.xlsx` del banco a un
    dict normalizado. None si openpyxl no está disponible o el xlsx no
    tiene la estructura esperada (sin Total a pagar reconocible).
    """
    try:
        from openpyxl import load_workbook
    except ImportError:
        return None
    try:
        wb = load_workbook(path, data_only=True, read_only=True)
    except Exception:
        return None

    rows: list[tuple] = []
    sheet_name = ""
    try:
        ws = wb.active
        sheet_name = ws.title or ""
        # Lectura completa: el archivo es <100 filas — read_only modo
        # streaming, sin riesgo de memoria.
        for row in ws.iter_rows(values_only=True):
            rows.append(row)
    except Exception:
        return None
    finally:
        try:
            wb.close()
        except Exception:
            pass

    if not rows:
        return None

    # Identificar marca + últimos 4 — primero del sheet name, sino del
    # nombre de archivo, sino del primer row con "terminada en".
    brand = None
    last4 = None
    for source in (sheet_name, path.stem):
        m_brand = _CARD_BRAND_RE.search(source)
        m_last4 = _CARD_LAST4_RE.search(source)
        if m_brand and not brand:
            brand = m_brand.group(1).title()
            if brand.lower() in ("master", "mastercard"):
                brand = "Mastercard"
            elif brand.lower() in ("amex", "american express"):
                brand = "Amex"
        if m_last4 and not last4:
            last4 = m_last4.group(1)
        if brand and last4:
            break

    # Pasada por filas: extraer secciones por anchor text.
    holder = None
    closing_date = None
    due_date = None
    next_closing_date = None
    next_due_date = None
    total_ars = None
    total_usd = None
    minimum_ars = None
    minimum_usd = None
    top_purchases: list[dict] = []

    def _row_text(r: tuple) -> str:
        return " ".join(str(c) for c in r if c is not None).strip()

    n = len(rows)
    i = 0
    in_purchases_block = False
    in_payments_block = False
    while i < n:
        row = rows[i]
        text = _row_text(row).lower()

        # Header: "Tarjeta <Marca> ... terminada en NNNN"
        if not last4 and "terminada en" in text:
            m = _CARD_LAST4_RE.search(text)
            if m:
                last4 = m.group(1)
            m_brand = _CARD_BRAND_RE.search(text)
            if m_brand and not brand:
                brand = m_brand.group(1).title()

        # "Fecha de cierre" / "Fecha de vencimiento" — fila siguiente las trae
        if "fecha de cierre" in text and "fecha de vencimiento" in text and i + 1 < n:
            nxt = rows[i + 1]
            closing_date = _parse_card_date(nxt[0] if len(nxt) > 0 else None)
            due_date = _parse_card_date(nxt[1] if len(nxt) > 1 else None)
            i += 2
            continue

        # "Total a pagar" — fila siguiente: ARS | USD
        if "total a pagar" in text and i + 1 < n:
            nxt = rows[i + 1]
            v0, c0 = _parse_ars_or_usd(nxt[0] if len(nxt) > 0 else None)
            v1, c1 = _parse_ars_or_usd(nxt[1] if len(nxt) > 1 else None)
            for v, c in ((v0, c0), (v1, c1)):
                if v is None:
                    continue
                if c == "USD":
                    total_usd = v
                else:
                    total_ars = v if total_ars is None else total_ars
            i += 2
            continue

        # "Mínimo a pagar"
        if "mínimo a pagar" in text or "minimo a pagar" in text:
            if i + 1 < n:
                nxt = rows[i + 1]
                v0, c0 = _parse_ars_or_usd(nxt[0] if len(nxt) > 0 else None)
                v1, c1 = _parse_ars_or_usd(nxt[1] if len(nxt) > 1 else None)
                for v, c in ((v0, c0), (v1, c1)):
                    if v is None:
                        continue
                    if c == "USD":
                        minimum_usd = v
                    else:
                        minimum_ars = v if minimum_ars is None else minimum_ars
                i += 2
                continue

        # "Próximo resumen" — la fila tiene "Cierre: DD/MM/YYYY" en col 2
        if "próximo resumen" in text or "proximo resumen" in text:
            # Las dos siguientes filas tienen "Cierre: ..." y "Vencimiento: ..."
            for j in range(i + 1, min(i + 4, n)):
                trow = _row_text(rows[j]).lower()
                if "cierre" in trow:
                    cell = rows[j][1] if len(rows[j]) > 1 else None
                    next_closing_date = _parse_card_date(cell)
                if "vencimiento" in trow:
                    cell = rows[j][1] if len(rows[j]) > 1 else None
                    next_due_date = _parse_card_date(cell)
            i += 1
            continue

        # Holder: "<Marca> Crédito terminada en NNNN" + col 2 con "(Titular)"
        if holder is None and len(row) > 1 and row[1] and "titular" in str(row[1]).lower():
            holder = re.sub(r"\s*\(Titular\)\s*$", "", str(row[1])).strip() or None

        # Bloques de movimientos: "Pago de tarjeta y devoluciones" (skipear) /
        # "Tarjeta de <holder>" (capturar movimientos hasta "Total de ...")
        if "pago de tarjeta y devoluciones" in text:
            in_payments_block = True
            in_purchases_block = False
        elif text.startswith("tarjeta de ") and "terminada en" in text:
            in_purchases_block = True
            in_payments_block = False
            if holder is None:
                m = re.search(r"tarjeta de (.+?)\s*-", text, re.IGNORECASE)
                if m:
                    holder = m.group(1).strip().title()
        elif text.startswith("total de ") and ("terminada en" in text or "tarjeta" in text):
            in_purchases_block = False
            in_payments_block = False
        elif text.startswith("otros conceptos"):
            in_purchases_block = False
            in_payments_block = False
        elif in_purchases_block and len(row) >= 5:
            # Fila de movimiento: (fecha, descripción, cuotas, comprobante, ARS, USD)
            desc = (str(row[1]).strip() if row[1] else "").strip()
            if desc and desc.lower() not in ("descripción", "descripcion"):
                amt_ars, _ = _parse_ars_or_usd(row[4] if len(row) > 4 else None)
                amt_usd, _ = _parse_ars_or_usd(row[5] if len(row) > 5 else None)
                amount = None
                currency = None
                if amt_ars is not None:
                    amount = abs(amt_ars)
                    currency = "ARS"
                elif amt_usd is not None:
                    amount = abs(amt_usd)
                    currency = "USD"
                if amount is not None and amount > 0:
                    top_purchases.append({
                        "date": _parse_card_date(row[0] if len(row) > 0 else None),
                        "description": desc,
                        "amount": amount,
                        "currency": currency,
                    })

        i += 1

    # Sin total ni fechas reconocibles → xlsx no es un resumen válido.
    if total_ars is None and total_usd is None and not closing_date and not due_date:
        return None

    # Top 5 movimientos por monto absoluto, separando ARS/USD.
    ars_purchases = sorted(
        (p for p in top_purchases if p["currency"] == "ARS"),
        key=lambda p: p["amount"],
        reverse=True,
    )[:5]
    usd_purchases = sorted(
        (p for p in top_purchases if p["currency"] == "USD"),
        key=lambda p: p["amount"],
        reverse=True,
    )[:3]

    try:
        mtime = path.stat().st_mtime
    except Exception:
        mtime = 0.0

    return {
        "brand": brand,
        "last4": last4,
        "holder": holder,
        "closing_date": closing_date,
        "due_date": due_date,
        "next_closing_date": next_closing_date,
        "next_due_date": next_due_date,
        "total_ars": total_ars,
        "total_usd": total_usd,
        "minimum_ars": minimum_ars,
        "minimum_usd": minimum_usd,
        "top_purchases_ars": ars_purchases,
        "top_purchases_usd": usd_purchases,
        "source_file": path.name,
        "source_mtime": datetime.fromtimestamp(mtime).isoformat(timespec="seconds") if mtime else None,
        "all_purchases": top_purchases,  # extra para el render de nota
    }


def _card_note_filename(card: dict) -> str | None:
    """Construye el filename de la nota .md para una tarjeta parseada.

    Convención: `Tarjeta-<Marca>-<Últimos4>-YYYY-MM.md`, donde YYYY-MM es
    el `closing_date.year-month`. Si no hay `closing_date` ni
    `due_date` reconocible, devuelve None — sin ancla temporal no
    podemos diferenciar ciclos. Garantiza que re-exportar el mismo
    ciclo SOBREESCRIBE la nota (mismo filename), pero un ciclo nuevo
    crea una nota nueva.

    Marca + last4 son obligatorios. Si falta alguno, devuelve None
    (xlsx mal formado / parser falló parcialmente).
    """
    brand = (card.get("brand") or "").strip()
    last4 = (card.get("last4") or "").strip()
    if not brand or not last4:
        return None
    cycle = card.get("closing_date") or card.get("due_date")
    if not cycle:
        return None
    yyyy_mm = cycle[:7]  # "2026-03-26" → "2026-03"
    return f"Tarjeta-{brand}-{last4}-{yyyy_mm}.md"


def _card_render_note(card: dict) -> str:
    """Renderiza una nota markdown para un resumen de tarjeta parseado.

    Frontmatter estructurado para que el chat tool format y el retriever
    tengan los mismos campos visibles. Body con un párrafo TL;DR (cuánto
    debo, cuándo cierra/vence) y los top movimientos en tablas separadas
    ARS/USD para que las dos monedas tengan visibilidad cuando el user
    pregunta "qué gasté en marzo en la Visa".

    Determinístico: dado el mismo `card` dict siempre devuelve el mismo
    string. Eso habilita el hash-skip del indexador (no escribir si el
    contenido es idéntico al .md previo).
    """
    brand = card.get("brand") or "?"
    last4 = card.get("last4") or "????"
    holder = card.get("holder") or ""
    closing = card.get("closing_date") or ""
    due = card.get("due_date") or ""
    next_closing = card.get("next_closing_date") or ""
    next_due = card.get("next_due_date") or ""
    total_ars = card.get("total_ars")
    total_usd = card.get("total_usd")
    minimum_ars = card.get("minimum_ars")
    minimum_usd = card.get("minimum_usd")
    src_file = card.get("source_file") or ""
    cycle_yyyy_mm = (closing or due or "")[:7]

    def _fmt_ars(v: float | None) -> str:
        if v is None:
            return "—"
        # ES locale: punto miles, coma decimal.
        s = f"{v:,.2f}"  # `1,234,567.89` → en-US
        # Swap: `,` ↔ `.`
        return s.replace(",", "_TMP_").replace(".", ",").replace("_TMP_", ".")

    def _fmt_usd(v: float | None) -> str:
        if v is None:
            return "—"
        return f"{v:,.2f}".replace(",", "_TMP_").replace(".", ",").replace("_TMP_", ".")

    # Frontmatter — claves estables, valores YAML-safe (sin chars
    # especiales que requieran quoting). `tags` ayuda a filtros del retriever.
    fm: list[str] = ["---"]
    fm.append("type: finanzas")
    fm.append("source: tarjeta")
    fm.append(f"brand: {brand}")
    fm.append(f"last4: \"{last4}\"")  # quote: empieza con dígito, evitar coerción a int
    if holder:
        fm.append(f"holder: {holder}")
    if cycle_yyyy_mm:
        fm.append(f"cycle: {cycle_yyyy_mm}")
    if closing:
        fm.append(f"closing_date: {closing}")
    if due:
        fm.append(f"due_date: {due}")
    if next_closing:
        fm.append(f"next_closing_date: {next_closing}")
    if next_due:
        fm.append(f"next_due_date: {next_due}")
    if total_ars is not None:
        fm.append(f"total_ars: {total_ars:.2f}")
    if total_usd is not None:
        fm.append(f"total_usd: {total_usd:.2f}")
    if minimum_ars is not None:
        fm.append(f"minimum_ars: {minimum_ars:.2f}")
    if minimum_usd is not None:
        fm.append(f"minimum_usd: {minimum_usd:.2f}")
    tags = ["finanzas", "tarjeta", brand.lower()]
    fm.append(f"tags: [{', '.join(tags)}]")
    fm.append("ambient: skip")
    if src_file:
        fm.append(f"source_file: {src_file}")
    fm.append("---")
    fm.append("")

    # Body — TL;DR primero, después tablas.
    title = f"# Tarjeta {brand} ·{last4} — ciclo {cycle_yyyy_mm or 'sin fecha'}"
    body: list[str] = [title, ""]
    if holder:
        body.append(f"Titular: **{holder}**.")
        body.append("")

    # Resumen del ciclo — el LLM lo cita literal por REGLA 1.b.
    parts: list[str] = []
    if total_ars is not None:
        parts.append(f"total ARS **${_fmt_ars(total_ars)}**")
    if total_usd is not None:
        parts.append(f"total USD **U$S{_fmt_usd(total_usd)}**")
    if parts:
        body.append("Total a pagar este ciclo: " + " · ".join(parts) + ".")
    if closing or due:
        body.append(f"Fecha de cierre: **{closing or '—'}** · Fecha de vencimiento: **{due or '—'}**.")
    if minimum_ars is not None or minimum_usd is not None:
        mins: list[str] = []
        if minimum_ars is not None:
            mins.append(f"ARS **${_fmt_ars(minimum_ars)}**")
        if minimum_usd is not None:
            mins.append(f"USD **U$S{_fmt_usd(minimum_usd)}**")
        body.append("Mínimo a pagar: " + " · ".join(mins) + ".")
    if next_closing or next_due:
        body.append(f"Próximo ciclo — cierre: {next_closing or '—'} · vencimiento: {next_due or '—'}.")
    body.append("")

    # Tabla de top movimientos ARS.
    ars = card.get("top_purchases_ars") or []
    if ars:
        body.append("## Top movimientos ARS")
        body.append("")
        body.append("| Fecha | Descripción | Monto |")
        body.append("|---|---|---:|")
        for p in ars:
            d = p.get("date") or ""
            desc = (p.get("description") or "").replace("|", "\\|")
            amt = p.get("amount")
            body.append(f"| {d} | {desc} | ${_fmt_ars(amt)} |")
        body.append("")

    usd = card.get("top_purchases_usd") or []
    if usd:
        body.append("## Top movimientos USD")
        body.append("")
        body.append("| Fecha | Descripción | Monto |")
        body.append("|---|---|---:|")
        for p in usd:
            d = p.get("date") or ""
            desc = (p.get("description") or "").replace("|", "\\|")
            amt = p.get("amount")
            body.append(f"| {d} | {desc} | U$S{_fmt_usd(amt)} |")
        body.append("")

    # Lista plana de TODOS los movimientos para que retrieval por descripción
    # funcione (ej. "claro deb aut" o "merpago idilica" disparan match
    # exacto). No queremos solo top-5 acá — el reranker puede traer la nota
    # entera si la query menciona una merchant específica.
    all_p = card.get("all_purchases") or []
    if all_p:
        body.append("## Todos los movimientos")
        body.append("")
        for p in all_p:
            d = p.get("date") or ""
            desc = (p.get("description") or "").replace("|", "\\|")
            cur = p.get("currency") or ""
            amt = p.get("amount")
            if cur == "USD":
                body.append(f"- {d} — {desc} — U$S{_fmt_usd(amt)}")
            else:
                body.append(f"- {d} — {desc} — ${_fmt_ars(amt)}")
        body.append("")

    body.append(f"_Fuente: `{src_file}` (export del banco)._")
    body.append("")

    return "\n".join(fm + body)


def _sync_credit_cards_notes(vault_root: Path) -> dict:
    """Regenerate per-cycle credit-card notes from the xlsx exports in
    `MOZE_BACKUP_DIR` (same `/Finances` folder). Mirrors the MOZE pattern:
    one note per (card, cycle), hash-skip if content is unchanged, prune
    notes whose source xlsx no longer exists.

    Returns stats for logging:
      {ok, files_total, files_written, files_skipped, target}
    or {ok=False, reason} on no-source / unparseable.

    Silent-fail patterns:
      - No xlsx in `/Finances` → `{ok: False, reason: "no_xlsx"}`
      - Some xlsx fail to parse → continue with the rest, count failures
      - openpyxl missing → first xlsx returns None, all do, "no_parsed"
    """
    try:
        seen: set[Path] = set()
        for pattern in ("Último resumen*.xlsx", "Ultimo resumen*.xlsx"):
            for p in MOZE_BACKUP_DIR.glob(pattern):
                seen.add(p)
        files = sorted(seen, key=lambda p: p.name)
    except Exception as exc:
        return {"ok": False, "reason": f"glob: {exc}"}
    if not files:
        return {"ok": False, "reason": "no_xlsx"}

    target_dir = vault_root / TARJETAS_VAULT_SUBPATH
    # Audit 2026-04-26: enforce que el target queda DENTRO del vault.
    # Sin esto, `OBSIDIAN_RAG_TARJETAS_FOLDER=../../../tmp` permitiría
    # escribir notas fuera del vault. Vault es user-controlled así que
    # el riesgo es bajo, pero el guard es trivial. resolve() colapsa
    # `..` y symlinks; relative_to() raises si el target escapa.
    try:
        _vr = vault_root.resolve()
        _td = target_dir.resolve()
        _td.relative_to(_vr)
    except Exception:
        return {"ok": False, "reason": f"target escapa vault: {target_dir}"}
    try:
        target_dir.mkdir(parents=True, exist_ok=True)
    except Exception as exc:
        return {"ok": False, "reason": f"mkdir: {exc}"}

    written = 0
    skipped = 0
    parse_failed = 0
    current_set: set[str] = set()

    for xlsx in files:
        card = _parse_credit_card_xlsx(xlsx)
        if not card:
            parse_failed += 1
            continue
        fname = _card_note_filename(card)
        if not fname:
            # brand/last4/cycle missing — can't name deterministically.
            parse_failed += 1
            continue
        current_set.add(fname)
        body = _card_render_note(card)
        path = target_dir / fname
        existing = path.read_text(encoding="utf-8") if path.is_file() else ""
        if existing == body:
            skipped += 1
            continue
        path.write_text(body, encoding="utf-8")
        written += 1

    # Prune .md whose source no longer exists. Conservative: only delete
    # files matching our `Tarjeta-*.md` naming scheme so we don't nuke
    # user-authored notes the same folder might contain.
    for p in target_dir.glob("Tarjeta-*.md"):
        if p.name not in current_set:
            try:
                p.unlink()
            except Exception:
                pass

    if not current_set and parse_failed:
        return {"ok": False, "reason": "no_parsed"}

    return {
        "ok": True,
        "files_total": len(files),
        "files_written": written,
        "files_skipped": skipped,
        "files_parse_failed": parse_failed,
        "target": str(target_dir.relative_to(vault_root)),
    }


_WHATSAPP_ETL_SCRIPT = Path.home() / ".local/bin/whatsapp-to-vault"
_WHATSAPP_ETL_RE = re.compile(
    r"wrote\s+(\d+)\s+files,\s+(\d+)\s+unchanged,\s+(\d+)\s+\(chat, month\)\s+buckets,\s+(\d+)\s+chats"
)


def _sync_whatsapp_notes(vault_root: Path) -> dict:
    """Trigger the WhatsApp → vault ETL script and parse its summary line.

    Mirrors the MOZE pre-index pattern: produces `.md` files in
    `<vault>/03-Resources/WhatsApp/<chat>/YYYY-MM.md` so the regular rglob
    picks them up. Subprocess to keep it as a single source of truth — the
    same script that the `com.fer.whatsapp-vault-sync` launchd plist runs
    every 15 min. Silent-fail when the script is missing (other machines).
    """
    if not _WHATSAPP_ETL_SCRIPT.is_file():
        return {"ok": False, "reason": "script_missing"}
    try:
        proc = subprocess.run(
            [str(_WHATSAPP_ETL_SCRIPT)],
            capture_output=True, timeout=60, text=True,
        )
    except (subprocess.TimeoutExpired, FileNotFoundError, OSError) as exc:
        return {"ok": False, "reason": str(exc)[:120]}
    out = (proc.stdout or "").strip()
    err = (proc.stderr or "").strip()
    if proc.returncode != 0:
        return {"ok": False, "reason": err[:160] or f"rc={proc.returncode}"}
    m = _WHATSAPP_ETL_RE.search(out)
    if not m:
        return {"ok": True, "raw": out[:160]}
    return {
        "ok": True,
        "files_written": int(m.group(1)),
        "files_unchanged": int(m.group(2)),
        "buckets": int(m.group(3)),
        "chats": int(m.group(4)),
        "target": "03-Resources/WhatsApp",
    }


# ── External-source ETLs ─────────────────────────────────────────────────────
# Same pattern as MOZE / WhatsApp: produce `.md` files inside the vault so the
# regular `_run_index` rglob absorbs them. Each helper is silent-fail and
# returns a stats dict for logging. Triggered from `_run_index` after the
# WhatsApp sync, before the vault scan.

