# ── rag brief schedule — auto-tuning del horario de los briefs ─────────────
# Si el user mutea consistentemente el morning brief en la primera hora
# (07:00–07:59), este sub-grupo ofrece (a) ver la recomendación, (b)
# aplicarla escribiendo en `rag_brief_schedule_prefs`, (c) volver al
# default. El daemon `com.fer.obsidian-rag-brief-auto-tune` corre el
# `auto-tune --apply` cada Domingo 03:00. Lógica en
# `rag/brief_schedule.py` (analyze_brief_feedback + safe-bands).
#
# Nombre del callable Python = `brief_schedule_grp` (NO `brief_schedule`)
# para no sombrear el submódulo `rag.brief_schedule` cuando alguien hace
# `from rag import brief_schedule`. El nombre del subcomando de Click
# ("schedule") es independiente y no cambia.
@brief.group("schedule", invoke_without_command=True)
@click.pass_context
def brief_schedule_grp(ctx: click.Context):
    """Ver/ajustar el horario de los briefs morning/today/digest.

    Sin subcomando muestra el current schedule + recommendations
    (equivalente a `rag brief schedule status`).
    """
    if ctx.invoked_subcommand is None:
        ctx.invoke(brief_schedule_status, plain=False)


def _format_recommendation_line(kind: str, analysis: dict, plain: bool) -> str:
    cur = f"{analysis['current_hour']:02d}:{analysis['current_minute']:02d}"
    rec = analysis["recommendation"]
    if rec["should_shift"]:
        sh, sm = rec["suggested_hour"], rec["suggested_minute"]
        new = f"{sh:02d}:{sm:02d}"
        body = (
            f"{kind:>7}: {cur} → {new}  "
            f"[mute={analysis['mute_count']} pos={analysis['positive_count']} "
            f"neg={analysis['negative_count']}]  {rec['reason']}"
        )
        return body if plain else f"[yellow]{body}[/yellow]"
    body = (
        f"{kind:>7}: {cur} (no shift)  "
        f"[mute={analysis['mute_count']} pos={analysis['positive_count']} "
        f"neg={analysis['negative_count']}]  {rec['reason']}"
    )
    return body if plain else f"[dim]{body}[/dim]"


@brief_schedule_grp.command("status")
@click.option("--plain", is_flag=True,
              help="Output plano sin colores (para piping/scripts).")
@click.option("--lookback-days", type=int, default=30, show_default=True,
              help="Ventana en días para `rag_brief_feedback`.")
def brief_schedule_status(plain: bool, lookback_days: int):
    """Muestra current schedule + recommendation por cada brief_kind.

    Lee `rag_brief_schedule_prefs` (current overrides) + `rag_brief_feedback`
    (últimos N días) y corre `analyze_brief_feedback` para cada kind. Output:

        morning: 07:00 → 08:00  [mute=4 pos=1 neg=0]  shift +30min: ...
        today:   22:00 (no shift)  [mute=0 pos=0 neg=0]  sin feedback ...
        digest:  22:00 (no shift)  [...]

    Pensado para ojo manual y para el daemon de auto-tune (que parsea
    el JSON via `analyze_all` directamente, no este CLI).
    """
    try:
        from rag.brief_schedule import VALID_BRIEF_KINDS, analyze_brief_feedback
    except Exception as exc:
        msg = f"error importando rag.brief_schedule: {exc}"
        click.echo(msg) if plain else console.print(f"[red]{msg}[/red]")
        return

    if plain:
        click.echo(f"brief schedule (lookback {lookback_days}d):")
    else:
        console.print(
            f"[bold]brief schedule[/bold] [dim](lookback {lookback_days}d)[/dim]"
        )
    for kind in VALID_BRIEF_KINDS:
        try:
            analysis = analyze_brief_feedback(kind, lookback_days=lookback_days)
        except Exception as exc:
            line = f"  {kind}: ERROR {exc}"
            click.echo(line) if plain else console.print(f"[red]{line}[/red]")
            continue
        line = _format_recommendation_line(kind, analysis, plain)
        click.echo("  " + line) if plain else console.print("  " + line)


@brief_schedule_grp.command("reset")
@click.option("--kind", "kind", type=click.Choice(["morning", "today", "digest", "all"]),
              required=True, help="Cuál override borrar.")
@click.option("--plain", is_flag=True)
def brief_schedule_reset(kind: str, plain: bool):
    """Borra el override de `rag_brief_schedule_prefs` (vuelve al default).

    Útil si el auto-tune metió un horario que no te gusta o si querés
    resetear todo después de un experimento. El próximo `rag setup`
    regenerará los plists con el default hardcoded.

    `--kind all` borra los tres overrides en una sola llamada.
    """
    try:
        from rag.brief_schedule import (
            VALID_BRIEF_KINDS, reset_brief_schedule_pref,
        )
    except Exception as exc:
        msg = f"error importando rag.brief_schedule: {exc}"
        click.echo(msg) if plain else console.print(f"[red]{msg}[/red]")
        return

    targets = list(VALID_BRIEF_KINDS) if kind == "all" else [kind]
    for k in targets:
        ok = reset_brief_schedule_pref(k)
        if ok:
            line = f"✓ {k}: override borrado (vuelve al default)"
            click.echo(line) if plain else console.print(f"[green]{line}[/green]")
        else:
            line = f"✗ {k}: error borrando override"
            click.echo(line) if plain else console.print(f"[red]{line}[/red]")


def _bootstrap_brief_plist(kind: str) -> tuple[bool, str]:
    """Re-bootstrap the launchd plist for `kind` only. Used by
    `auto-tune --apply` after writing the override so launchd picks up
    the new StartCalendarInterval without waiting for `rag setup`.

    Returns (ok, message). Silent-fail-friendly: returns False + message
    if launchctl isn't available (Linux CI, sandboxed env). The override
    row is still in the DB, so the next `rag setup` will regenerate the
    plist correctly.
    """
    import shutil
    import subprocess

    if shutil.which("launchctl") is None:
        return (False, "launchctl no disponible (skip bootstrap)")
    label = f"com.fer.obsidian-rag-{kind}"
    fname = f"{label}.plist"
    plist_path = _LAUNCH_AGENTS_DIR / fname
    if not plist_path.is_file():
        return (False, f"{fname} no instalado (correr `rag setup`)")
    try:
        rag_bin = _rag_binary()
        # Regenerate the plist XML using the now-current pref.
        if kind == "morning":
            xml = _morning_plist(rag_bin, *current_schedule_for_bootstrap("morning"))
        elif kind == "today":
            xml = _today_plist(rag_bin, *current_schedule_for_bootstrap("today"))
        elif kind == "digest":
            xml = _digest_plist(rag_bin, *current_schedule_for_bootstrap("digest"))
        else:
            return (False, f"kind desconocido: {kind}")
        plist_path.write_text(xml, encoding="utf-8")
        # `bootout` then `bootstrap` swaps the running plist atomically.
        subprocess.run(
            ["launchctl", "bootout", f"gui/{__import__('os').getuid()}", str(plist_path)],
            check=False, capture_output=True,
        )
        subprocess.run(
            ["launchctl", "bootstrap", f"gui/{__import__('os').getuid()}", str(plist_path)],
            check=False, capture_output=True,
        )
        return (True, f"{label} re-bootstrapped")
    except Exception as exc:
        return (False, f"error: {exc}")


def current_schedule_for_bootstrap(kind: str) -> tuple[int, int]:
    """Helper: read the currently-effective schedule (override or default)
    for `kind`. Mirrors `rag.brief_schedule.current_schedule` but lives
    here so the bootstrap path doesn't depend on the analyzer module
    reloading on each launchctl invocation."""
    try:
        from rag.brief_schedule import current_schedule
        return current_schedule(kind)
    except Exception:
        # Defensive fallback to defaults from DEFAULT_SCHEDULES.
        return {"morning": (7, 0), "today": (22, 0), "digest": (22, 0)}.get(kind, (0, 0))


@brief_schedule_grp.command("auto-tune")
@click.option("--dry-run", is_flag=True,
              help="Forzar dry-run aunque venga --apply (CI / sanity check).")
@click.option("--apply", "apply_flag", is_flag=True,
              help="Escribir overrides + re-bootstrap del plist afectado.")
@click.option("--lookback-days", type=int, default=30, show_default=True,
              help="Ventana en días para `rag_brief_feedback`.")
@click.option("--plain", is_flag=True)
def brief_schedule_auto_tune(dry_run: bool, apply_flag: bool, lookback_days: int, plain: bool):
    """Aplicar el shift sugerido por `analyze_brief_feedback` para cada kind.

    Sin `--apply` corre en dry-run: muestra qué shifts haría sin tocar la
    DB. Con `--apply`, escribe en `rag_brief_schedule_prefs` y re-bootstrappea
    sólo el plist afectado (no toca los otros) via `launchctl bootout` +
    `bootstrap`. `--dry-run` siempre gana sobre `--apply` (útil para
    pre-flight check antes del cron del Domingo).

    Modo de uso:

      rag brief schedule auto-tune              # dry-run, ver qué haría
      rag brief schedule auto-tune --apply      # aplicar (escribe + bootstrap)

    El daemon `com.fer.obsidian-rag-brief-auto-tune.plist` corre con
    `--apply` cada Domingo 03:00.
    """
    # Default = dry-run unless --apply is set. --dry-run forces dry-run.
    is_dry = dry_run or not apply_flag
    try:
        from rag.brief_schedule import (
            VALID_BRIEF_KINDS, analyze_brief_feedback, set_brief_schedule_pref,
        )
    except Exception as exc:
        msg = f"error importando rag.brief_schedule: {exc}"
        click.echo(msg) if plain else console.print(f"[red]{msg}[/red]")
        return

    header = f"brief auto-tune {'(dry-run)' if is_dry else '(apply)'}"
    if plain:
        click.echo(header)
    else:
        console.print(f"[bold]{header}[/bold]")

    any_shift = False
    for kind in VALID_BRIEF_KINDS:
        try:
            analysis = analyze_brief_feedback(kind, lookback_days=lookback_days)
        except Exception as exc:
            line = f"  {kind}: ERROR {exc}"
            click.echo(line) if plain else console.print(f"[red]{line}[/red]")
            continue
        rec = analysis["recommendation"]
        if not rec["should_shift"]:
            line = (
                f"  {kind}: no shift "
                f"({rec['reason']})"
            )
            click.echo(line) if plain else console.print(f"[dim]{line}[/dim]")
            continue
        any_shift = True
        sh, sm = rec["suggested_hour"], rec["suggested_minute"]
        cur_h, cur_m = analysis["current_hour"], analysis["current_minute"]
        line = (
            f"  {kind}: {cur_h:02d}:{cur_m:02d} → {sh:02d}:{sm:02d}  "
            f"({rec['reason']})"
        )
        click.echo(line) if plain else console.print(f"[yellow]{line}[/yellow]")
        if is_dry:
            continue
        ok = set_brief_schedule_pref(kind, sh, sm, reason=rec["reason"])
        if not ok:
            err = f"    ✗ falló escribir pref para {kind}"
            click.echo(err) if plain else console.print(f"[red]{err}[/red]")
            continue
        bok, bmsg = _bootstrap_brief_plist(kind)
        prefix = "    ✓" if bok else "    ·"
        line2 = f"{prefix} {bmsg}"
        if plain:
            click.echo(line2)
        else:
            console.print(line2 if bok else f"[dim]{line2}[/dim]")

    if not any_shift:
        msg = "nada para aplicar — todos los kinds en zona buena"
        click.echo(msg) if plain else console.print(f"[green]{msg}[/green]")


# ── `rag migrations` — schema migrations explícitas ─────────────────────
#
# CLI thin wrapper sobre `rag.migrations`. Operaciones:
#   - `rag migrations status`  → version actual + pending count
#   - `rag migrations list`    → todas las conocidas (applied | pending)
#   - `rag migrations apply`   → aplica pending hasta --target N (--dry-run)
#   - `rag migrations bootstrap` → registra todas como aplicadas sin correrlas
#
# Todas operan contra `telemetry.db` (DB_PATH / telemetry.db). Las commands
# abren su propia conn raw — NO pasan por `_ragvec_state_conn` para evitar
# que `_ensure_telemetry_tables` corra `apply_pending_migrations` antes de
# que el user pueda inspeccionar el estado.


def _migrations_open_conn():
    """Abre una conn directa a telemetry.db sin disparar el wiring de
    `_ensure_telemetry_tables`. Solo crea la tabla `rag_schema_migrations`
    si no existe — el resto del DDL queda intacto para no enmascarar
    estados de DBs viejas."""
    import sqlite3 as _sqlite3
    DB_PATH.mkdir(parents=True, exist_ok=True)
    db_file = DB_PATH / _TELEMETRY_DB_FILENAME
    conn = _sqlite3.connect(str(db_file), isolation_level=None,
                            check_same_thread=False, timeout=30.0)
    conn.execute("PRAGMA busy_timeout=30000")
    return conn


@cli.group("migrations")
def migrations_group() -> None:
    """Schema migrations versionadas para telemetry.db.

    Mata la clase de bugs `CREATE TABLE IF NOT EXISTS no aplica ALTER en
    DBs viejas`. Cada migration vive como `migrate_NNN_*` en
    `rag/migrations.py` y se aplica explícitamente bajo SAVEPOINT.
    """


@migrations_group.command("status")
@click.option("--plain", is_flag=True, help="Output mínimo, sin Rich")
def migrations_status_cmd(plain: bool) -> None:
    """Muestra version actual + count de pending."""
    from rag import migrations as _m  # noqa: PLC0415
    conn = _migrations_open_conn()
    try:
        cur = _m.current_version(conn)
        all_known = _m.known_migrations()
        pending = [v for v, _, _ in all_known if v > cur]
        max_known = max((v for v, _, _ in all_known), default=0)
    finally:
        conn.close()
    if plain:
        click.echo(f"current_version={cur} max_known={max_known} pending={len(pending)}")
        return
    console.print(f"[cyan]current version:[/cyan] [bold]{cur}[/bold]")
    console.print(f"[cyan]max known:[/cyan]       [bold]{max_known}[/bold]")
    if pending:
        console.print(f"[yellow]pending:[/yellow]         {len(pending)} ({pending})")
    else:
        console.print("[green]up to date — no pending migrations[/green]")


@migrations_group.command("list")
@click.option("--applied", "filter_applied", is_flag=True, help="Solo migrations aplicadas")
@click.option("--pending", "filter_pending", is_flag=True, help="Solo migrations pending")
@click.option("--plain", is_flag=True)
def migrations_list_cmd(filter_applied: bool, filter_pending: bool, plain: bool) -> None:
    """Lista todas las migrations conocidas + estado."""
    from rag import migrations as _m  # noqa: PLC0415
    conn = _migrations_open_conn()
    try:
        applied = _m.applied_versions(conn)
        rows = _m.known_migrations()
    finally:
        conn.close()
    for v, name, _fn in rows:
        is_applied = v in applied
        if filter_applied and not is_applied:
            continue
        if filter_pending and is_applied:
            continue
        status = "applied" if is_applied else "pending"
        if plain:
            click.echo(f"{v}\t{status}\t{name}")
        else:
            color = "green" if is_applied else "yellow"
            console.print(f"[{color}]{v:>3} {status:<8}[/] {name}")


@migrations_group.command("apply")
@click.option("--target", type=int, default=None,
              help="Aplica solo hasta esta version (default: todas las pending)")
@click.option("--dry-run", is_flag=True, help="Lista qué se aplicaría sin tocar la DB")
@click.option("--plain", is_flag=True)
def migrations_apply_cmd(target: int | None, dry_run: bool, plain: bool) -> None:
    """Aplica pending migrations. `--target N` limita; `--dry-run` no escribe."""
    from rag import migrations as _m  # noqa: PLC0415
    conn = _migrations_open_conn()
    try:
        cur = _m.current_version(conn)
        pending = [(v, name) for v, name, _ in _m.known_migrations() if v > cur]
        if target is not None:
            pending = [(v, name) for v, name in pending if v <= target]
        if not pending:
            msg = "no pending migrations"
            click.echo(msg) if plain else console.print(f"[green]{msg}[/green]")
            return
        if dry_run:
            for v, name in pending:
                if plain:
                    click.echo(f"would apply {v} {name}")
                else:
                    console.print(f"[yellow]would apply[/yellow] [bold]{v}[/bold] {name}")
            return
        # Filter the pending list down to target before calling apply_pending_migrations.
        # apply_pending_migrations doesn't take a target; emulate by registering
        # the higher-version skips temporarily — simpler: aplicar en loop manual.
        applied_now: list[int] = []
        for v, name, fn in _m.known_migrations():
            if v <= cur:
                continue
            if target is not None and v > target:
                break
            sp = f"migration_{v}"
            try:
                conn.execute(f"SAVEPOINT {sp}")
                fn(conn)
                conn.execute(
                    "INSERT OR REPLACE INTO rag_schema_migrations(version, name, applied_at, hash)"
                    " VALUES(?, ?, ?, ?)",
                    (v, name, _m._now_iso(), _m._migration_hash(fn)),
                )
                conn.execute(f"RELEASE SAVEPOINT {sp}")
                applied_now.append(v)
            except Exception as exc:
                try:
                    conn.execute(f"ROLLBACK TO SAVEPOINT {sp}")
                    conn.execute(f"RELEASE SAVEPOINT {sp}")
                except Exception:
                    pass
                if plain:
                    click.echo(f"FAILED at {v} {name}: {exc!r}")
                else:
                    console.print(f"[red]FAILED at {v} {name}:[/red] {exc!r}")
                raise click.exceptions.Exit(1)
        if plain:
            click.echo(f"applied {applied_now}")
        else:
            console.print(f"[green]applied:[/green] {applied_now}")
    finally:
        conn.close()


@migrations_group.command("bootstrap")
@click.option("--plain", is_flag=True)
def migrations_bootstrap_cmd(plain: bool) -> None:
    """Registra todas las migrations conocidas como aplicadas SIN correrlas.

    Pensado para DBs preexistentes que ya tienen las columnas/índices que
    las migrations harían (porque los `_migrate_*` legacy corrieron en
    boots previos). Solo bootstrappea si la tabla está vacía.
    """
    from rag import migrations as _m  # noqa: PLC0415
    conn = _migrations_open_conn()
    try:
        cur = _m.current_version(conn)
        if cur > 0:
            msg = f"history no vacía (version={cur}) — no bootstrap"
            click.echo(msg) if plain else console.print(f"[yellow]{msg}[/yellow]")
            return
        # Forzamos aún si la heurística falla — el user pidió explícitamente.
        # Pero si el DB no tiene rag_queries.trace_id, la app va a fallar
        # en cuanto intente escribir; lo correcto sería primero `apply`.
        # Acá simplemente registramos las versions sin correr el body.
        from datetime import datetime as _dt, timezone as _tz
        now = _dt.now(_tz.utc).isoformat(timespec="seconds")
        registered: list[int] = []
        for v, name, fn in _m.known_migrations():
            try:
                conn.execute(
                    "INSERT OR IGNORE INTO rag_schema_migrations(version, name, applied_at, hash)"
                    " VALUES(?, ?, ?, ?)",
                    (v, name, now, _m._migration_hash(fn)),
                )
                registered.append(v)
            except Exception:
                continue
        if plain:
            click.echo(f"bootstrapped {registered}")
        else:
            console.print(f"[green]bootstrapped:[/green] {registered}")
    finally:
        conn.close()


@cli.command("state")
@click.argument("text", required=False)
@click.option("--clear", is_flag=True, help="Borra el estado actual")
@click.option("--plain", is_flag=True)
def state_cmd(text: str | None, clear: bool, plain: bool):
    """Lee/escribe el estado del usuario (cansado, inspirado, focus-code…).

    TTL 24h — señal mutable. Se inyecta al system prompt de query/chat
    automáticamente para calibrar tono sin que lo declares cada vez.

      rag state                # muestra estado actual (si no expiró)
      rag state cansado         # set
      rag state --clear         # borra
    """
    if clear:
        clear_user_state()
        msg = "estado limpiado"
        click.echo(msg) if plain else console.print(f"[dim]{msg}[/dim]")
        return
    if not text:
        st = read_user_state()
        if st:
            msg = f"{st['state']} (hace {st['age_hours']:.1f}h)"
            click.echo(msg) if plain else console.print(f"[cyan]{msg}[/cyan]")
        else:
            msg = "sin estado activo"
            click.echo(msg) if plain else console.print(f"[dim]{msg}[/dim]")
        return
    write_user_state(text.strip())
    msg = f"estado: {text.strip()}"
    click.echo(msg) if plain else console.print(f"[cyan]{msg}[/cyan]")


@cli.command()
@click.option("--file", "queries_file", default="queries.yaml",
              help="YAML con queries golden (default: queries.yaml)")
@click.option("-k", default=5, help="top-k para calcular hit/recall (default: 5)")
@click.option("--hyde", is_flag=True, help="Activa HyDE en la evaluación")
@click.option("--no-multi", is_flag=True, help="Sin multi-query expansion")
@click.option("--latency", is_flag=True,
              help="Mide + reporta P50/P95/P99 de retrieve() por query (ms)")
@click.option("--max-p95-ms", type=float, default=None,
              help="Gate: exit 1 si P95 retrieve > este umbral. Implica --latency")
def eval(queries_file: str, k: int, hyde: bool, no_multi: bool,
         latency: bool, max_p95_ms: float | None):
    """Evaluar el retriever contra un set de queries golden.

    Métricas: hit@k (% queries donde alguna nota esperada cae en top-k),
    MRR (mean reciprocal rank del mejor hit), recall@k (fracción de notas
    esperadas recuperadas por query, promediado).

    Con --latency cronometra cada llamada a retrieve() y reporta P50/P95/P99.
    Con --max-p95-ms gatea: exit(1) si P95 > umbral (útil para CI).
    """
    if max_p95_ms is not None:
        latency = True
    # Strip RAG_EXPLORE from env before running — a stale parent-shell export
    # must not corrupt deterministic eval metrics. The assert below is a cheap
    # defensive sanity check that fires if the pop somehow failed (dead code in
    # practice, but documents the invariant clearly).
    os.environ.pop("RAG_EXPLORE", None)
    assert os.environ.get("RAG_EXPLORE") != "1", (
        "RAG_EXPLORE must not be set during eval — it corrupts metrics"
    )
    # `RAG_SKIP_BEHAVIOR_LOG=1` (2026-04-28): silencia los writers de
    # telemetry user-signal (`log_query_event`, `log_behavior_event`,
    # `log_impressions`) durante eval. Sin esto, las queries del eval set
    # entraban a `rag_queries` (con cmd="eval") y a `rag_behavior` (con
    # source="eval" tras commit `16df67e`); el auto-harvest pipeline
    # podía pescarlas como "low-confidence user queries" para mandarlas
    # al LLM judge — gasto de ciclos LLM en queries sintéticas. El
    # caller-aware logging ya las marcaba; este flag las elimina del
    # todo. Belt-and-suspenders. Setteado vía os.environ in-process: el
    # plist `com.fer.obsidian-rag-online-tune` también lo setea como
    # variable de entorno para coherencia.
    os.environ["RAG_SKIP_BEHAVIOR_LOG"] = "1"

    import pathlib
    path = pathlib.Path(queries_file)
    if not path.is_absolute():
        path = pathlib.Path.cwd() / queries_file
    if not path.is_file():
        console.print(f"[red]No existe {path}[/red]")
        return

    data = yaml.safe_load(path.read_text(encoding="utf-8"))
    queries = data.get("queries") or []
    chains = data.get("chains") or []
    if not queries and not chains:
        console.print(f"[yellow]Sin queries ni chains en {path}[/yellow]")
        return

    col = get_db()
    if col.count() == 0:
        console.print("[red]Índice vacío. Ejecuta: rag index[/red]")
        return

    # Trend-log snapshot: captured below inside the singles/chains blocks, then
    # appended to eval.jsonl once at the end so /api/home can render a mini
    # trend line without re-running the evaluator.
    singles_snap: dict | None = None
    chains_snap: dict | None = None

    def _bootstrap_ci(values: list[float], iters: int = 1000,
                      conf: float = 0.95, seed: int = 42) -> tuple[float, float]:
        """Percentile bootstrap CI over per-case metric values (hit bool or RR).

        Returns (lo, hi) bounds. Used to surface whether eval-to-eval deltas
        are within noise: if two runs' CIs overlap, the change is not
        significant on the current golden set.
        """
        if not values:
            return (0.0, 0.0)
        import random as _rnd
        rng = _rnd.Random(seed)
        n = len(values)
        means: list[float] = []
        for _ in range(iters):
            s = 0.0
            for _ in range(n):
                s += values[rng.randrange(n)]
            means.append(s / n)
        means.sort()
        alpha = (1 - conf) / 2
        lo = means[int(alpha * iters)]
        hi = means[min(iters - 1, int((1 - alpha) * iters))]
        return (lo, hi)

    def _score(expected_set: set[str], seen_paths: list[str]) -> tuple[bool, float, float]:
        retrieved_set = set(seen_paths)
        hit = bool(expected_set & retrieved_set)
        rr = 0.0
        for rank, p in enumerate(seen_paths, start=1):
            if p in expected_set:
                rr = 1.0 / rank
                break
        recall = (
            len(expected_set & retrieved_set) / len(expected_set)
            if expected_set else 0.0
        )
        return hit, rr, recall

    def _dedup(paths: list[str]) -> list[str]:
        seen: list[str] = []
        for p in paths:
            if p not in seen:
                seen.append(p)
        return seen

    # ── Single queries ──────────────────────────────────────────────────
    per_query: list[tuple[str, bool, float, float, list[str]]] = []
    singles_latency_ms: list[float] = []
    if queries:
        for entry in track(queries, description="Evaluando queries…"):
            q = entry["question"]
            expected = set(entry.get("expected") or [])
            _t0 = time.perf_counter()
            # `caller="eval"` (2026-04-28): impressions del eval set NO
            # son user signal — el ranker training filtra esto out. Ver
            # commit `fd97829` y RAG_SKIP_BEHAVIOR_LOG (que también blokea
            # log_query_event para eval).
            result = retrieve(
                col, q, k, folder=None, tag=None,
                precise=hyde, multi_query=not no_multi, auto_filter=True,
                caller="eval",
            )
            singles_latency_ms.append((time.perf_counter() - _t0) * 1000)
            seen_paths = _dedup([m.get("file", "") for m in result["metas"]])
            hit, rr, recall = _score(expected, seen_paths)
            per_query.append((q, hit, rr, recall, seen_paths))

        tbl = Table(title=f"Queries sueltas (k={k})", show_lines=False)
        tbl.add_column("Query", style="cyan", overflow="fold", max_width=50)
        tbl.add_column("Hit", justify="center")
        tbl.add_column("RR", justify="right")
        tbl.add_column("Recall", justify="right")
        for q, hit, rr, rec, _ in per_query:
            tbl.add_row(
                q,
                "[green]✓[/green]" if hit else "[red]✗[/red]",
                f"{rr:.2f}",
                f"{rec:.2f}",
            )
        console.print(tbl)

        failed = [(q, paths) for q, hit, _, _, paths in per_query if not hit]
        if failed:
            console.print()
            console.print("[bold red]Queries sin hit — top-k recuperado:[/bold red]")
            for q, paths in failed:
                console.print(f"  [yellow]{q}[/yellow]")
                for p in paths[:k]:
                    console.print(f"    [dim]· {p}[/dim]")

        n = len(queries)
        hit_at_k = sum(1 for _, h, _, _, _ in per_query if h) / n
        mrr = sum(r for _, _, r, _, _ in per_query) / n
        recall_at_k = sum(r for _, _, _, r, _ in per_query) / n

        hit_vals = [1.0 if h else 0.0 for _, h, _, _, _ in per_query]
        rr_vals = [r for _, _, r, _, _ in per_query]
        hit_lo, hit_hi = _bootstrap_ci(hit_vals)
        mrr_lo, mrr_hi = _bootstrap_ci(rr_vals)

        console.print()
        console.print(
            f"[bold]Singles:[/bold] hit@{k} {hit_at_k:.2%} "
            f"[dim]\\[{hit_lo:.2%}, {hit_hi:.2%}][/dim]  ·  "
            f"MRR {mrr:.3f} [dim]\\[{mrr_lo:.3f}, {mrr_hi:.3f}][/dim]  ·  "
            f"recall@{k} {recall_at_k:.2%}  ·  "
            f"[dim]n={n}[/dim]"
        )
        singles_snap = {
            "hit5": round(hit_at_k, 4),
            "hit5_ci": [round(hit_lo, 4), round(hit_hi, 4)],
            "mrr": round(mrr, 4),
            "mrr_ci": [round(mrr_lo, 4), round(mrr_hi, 4)],
            "n": n,
        }

    # ── Multi-turn chains ───────────────────────────────────────────────
    # Turn 0 runs as-is. For later turns we explicitly call reformulate_query
    # against accumulated history and pass the rewrite as the search query to
    # retrieve(..., precise=False) — keeps history-aware search on while
    # avoiding HyDE (bundled with precise=True, known to hurt on qwen2.5:3b).
    if chains:
        console.print()
        chain_rows: list[tuple[str, str, str, bool, float, float, list[str]]] = []
        per_chain_success: list[tuple[str, bool]] = []

        chains_latency_ms: list[float] = []
        for chain in track(chains, description="Evaluando chains…"):
            chain_id = chain.get("id", "<sin id>")
            turns = chain.get("turns") or []
            history: list[dict] = []
            # Synthetic session — `session_summary` only fires past
            # SESSION_COMPRESSION_THRESHOLD turns. Current golden chains stay
            # under it, so the wiring is invariant on this set; longer chains
            # would benefit transparently.
            fake_sess: dict = {"turns": []}
            all_hit = True
            chain_seen_paths: list[str] = []  # accumulates across turns for diversity
            for i, turn in enumerate(turns):
                q = turn["question"]
                expected = set(turn.get("expected") or [])
                if i == 0 or not history:
                    search_q = q
                else:
                    chain_summary = session_summary(fake_sess)
                    search_q = reformulate_query(
                        q, history, summary=chain_summary,
                        seen_titles=_titles_from_paths(chain_seen_paths),
                    )
                _t0 = time.perf_counter()
                result = retrieve(
                    col, search_q, k, folder=None, tag=None,
                    precise=False, multi_query=not no_multi, auto_filter=True,
                    # Soft post-rerank penalty on titles seen in earlier
                    # chain turns — encourages diversity without forcing
                    # the LLM to drift off-topic (see retrieve() docstring
                    # for the earlier prompt-injection attempt that failed).
                    seen_titles=_titles_from_paths(chain_seen_paths),
                    caller="eval",
                )
                chains_latency_ms.append((time.perf_counter() - _t0) * 1000)
                seen_paths = _dedup([m.get("file", "") for m in result["metas"]])
                hit, rr, recall = _score(expected, seen_paths)
                if not hit:
                    all_hit = False
                chain_rows.append((chain_id, q, search_q, hit, rr, recall, seen_paths))
                # Track paths across turns so next reformulation can steer away
                # from already-covered notes (chain-diversity signal).
                for p in seen_paths[:3]:
                    if p and p not in chain_seen_paths:
                        chain_seen_paths.append(p)
                # Fake assistant turn: top retrieved path anchors the topic so
                # the next reformulation has concrete nouns to resolve pronouns
                # against without a real chat-model call.
                history.append({"role": "user", "content": q})
                top = seen_paths[0] if seen_paths else ""
                fake_a = f"(contexto recuperado: {top})"
                history.append({"role": "assistant", "content": fake_a})
                fake_sess["turns"].append({"q": q, "a": fake_a})
            per_chain_success.append((chain_id, all_hit))

        ctbl = Table(title=f"Chains multi-turno (k={k})", show_lines=False)
        ctbl.add_column("Chain", style="magenta", no_wrap=True)
        ctbl.add_column("Turno", style="cyan", overflow="fold", max_width=44)
        ctbl.add_column("Hit", justify="center")
        ctbl.add_column("RR", justify="right")
        ctbl.add_column("Recall", justify="right")
        for cid, q, _sq, hit, rr, rec, _ in chain_rows:
            ctbl.add_row(
                cid,
                q,
                "[green]✓[/green]" if hit else "[red]✗[/red]",
                f"{rr:.2f}",
                f"{rec:.2f}",
            )
        console.print(ctbl)

        failed_turns = [(cid, q, sq, paths) for cid, q, sq, hit, _, _, paths in chain_rows if not hit]
        if failed_turns:
            console.print()
            console.print("[bold red]Turns sin hit — top-k recuperado:[/bold red]")
            for cid, q, sq, paths in failed_turns:
                console.print(f"  [magenta]{cid}[/magenta] [yellow]{q}[/yellow]")
                if sq and sq != q:
                    console.print(f"    [dim italic]→ reformulada: {sq}[/dim italic]")
                for p in paths[:k]:
                    console.print(f"    [dim]· {p}[/dim]")

        nt = len(chain_rows)
        nc = len(per_chain_success)
        chain_hit = sum(1 for _, _, _, h, _, _, _ in chain_rows if h) / nt if nt else 0.0
        chain_mrr = sum(r for _, _, _, _, r, _, _ in chain_rows) / nt if nt else 0.0
        chain_recall = sum(r for _, _, _, _, _, r, _ in chain_rows) / nt if nt else 0.0
        chain_success = sum(1 for _, ok in per_chain_success if ok) / nc if nc else 0.0

        c_hit_vals = [1.0 if h else 0.0 for _, _, _, h, _, _, _ in chain_rows]
        c_rr_vals = [r for _, _, _, _, r, _, _ in chain_rows]
        c_success_vals = [1.0 if ok else 0.0 for _, ok in per_chain_success]
        c_hit_lo, c_hit_hi = _bootstrap_ci(c_hit_vals)
        c_mrr_lo, c_mrr_hi = _bootstrap_ci(c_rr_vals)
        c_succ_lo, c_succ_hi = _bootstrap_ci(c_success_vals)

        console.print()
        console.print(
            f"[bold]Chains:[/bold] hit@{k} {chain_hit:.2%} "
            f"[dim]\\[{c_hit_lo:.2%}, {c_hit_hi:.2%}][/dim]  ·  "
            f"MRR {chain_mrr:.3f} [dim]\\[{c_mrr_lo:.3f}, {c_mrr_hi:.3f}][/dim]  ·  "
            f"recall@{k} {chain_recall:.2%}  ·  "
            f"chain_success {chain_success:.2%} "
            f"[dim]\\[{c_succ_lo:.2%}, {c_succ_hi:.2%}][/dim]  ·  "
            f"[dim]turns={nt}, chains={nc}[/dim]"
        )
        chains_snap = {
            "hit5": round(chain_hit, 4),
            "hit5_ci": [round(c_hit_lo, 4), round(c_hit_hi, 4)],
            "mrr": round(chain_mrr, 4),
            "mrr_ci": [round(c_mrr_lo, 4), round(c_mrr_hi, 4)],
            "chain_success": round(chain_success, 4),
            "chain_success_ci": [round(c_succ_lo, 4), round(c_succ_hi, 4)],
            "turns": nt,
            "chains": nc,
        }

    # ── Latency report ──────────────────────────────────────────────────
    latency_snap: dict | None = None
    gate_failed = False
    if latency:
        def _pct(xs: list[float], p: float) -> float:
            if not xs:
                return 0.0
            s = sorted(xs)
            k = (len(s) - 1) * p
            lo = int(k)
            hi = min(lo + 1, len(s) - 1)
            return s[lo] + (s[hi] - s[lo]) * (k - lo)

        buckets = []
        if singles_latency_ms:
            buckets.append(("singles", singles_latency_ms))
        _chains_lat = locals().get("chains_latency_ms") or []
        if _chains_lat:
            buckets.append(("chains", _chains_lat))

        if buckets:
            console.print()
            ltbl = Table(title="Latencia retrieve() (ms)", show_lines=False)
            ltbl.add_column("Bucket", style="cyan", no_wrap=True)
            ltbl.add_column("n", justify="right")
            ltbl.add_column("p50", justify="right")
            ltbl.add_column("p95", justify="right")
            ltbl.add_column("p99", justify="right")
            ltbl.add_column("mean", justify="right")
            ltbl.add_column("max", justify="right")
            latency_snap = {}
            for label, xs in buckets:
                p50 = _pct(xs, 0.50)
                p95 = _pct(xs, 0.95)
                p99 = _pct(xs, 0.99)
                mean = sum(xs) / len(xs)
                mx = max(xs)
                ltbl.add_row(
                    label, str(len(xs)),
                    f"{p50:.0f}", f"{p95:.0f}", f"{p99:.0f}",
                    f"{mean:.0f}", f"{mx:.0f}",
                )
                latency_snap[label] = {
                    "n": len(xs),
                    "p50_ms": round(p50, 1),
                    "p95_ms": round(p95, 1),
                    "p99_ms": round(p99, 1),
                    "mean_ms": round(mean, 1),
                    "max_ms": round(mx, 1),
                }
                if max_p95_ms is not None and p95 > max_p95_ms:
                    gate_failed = True
                    console.print(
                        f"[bold red]GATE FAIL[/bold red] {label} p95 "
                        f"{p95:.0f}ms > {max_p95_ms:.0f}ms"
                    )
            console.print(ltbl)

    # Trend log — one line per `rag eval` run into rag_eval_runs. Silent-fail
    # so an unwritable DB never breaks the CLI. `/api/home._fetch_eval_trend`
    # tails the last N entries to surface drift against the CLAUDE.md baseline.
    # SQL-only since T10.
    if singles_snap or chains_snap:
        entry = {"ts": datetime.now().isoformat(timespec="seconds")}
        if singles_snap:
            entry["singles"] = singles_snap
        if chains_snap:
            entry["chains"] = chains_snap
        if latency_snap:
            entry["latency"] = latency_snap
        def _do() -> None:
            with _ragvec_state_conn() as conn:
                _sql_append_event(conn, "rag_eval_runs",
                                   _map_eval_row(entry))
        _sql_write_with_retry(_do, "eval_sql_write_failed")

    if gate_failed:
        raise SystemExit(1)


# ── RANKER AUTO-TUNING (rag tune) ────────────────────────────────────────────
# Weight optimization loop for RankerWeights. Collects per-case features via
# `collect_ranker_features()` once, then runs a random search over the 5 knobs
# that touch post-rerank scoring. Objective: hit@5 + 0.5 * MRR over the golden
# set (queries.yaml singles + chains + optional feedback.jsonl augmentation).
#
# Why random search over grid/Bayes: the feature vectors are fixed per case,
# so each trial is pure CPU (sort + metric). 500 trials finish in <1s after
# the ~1-2s-per-query feature gathering. No extra deps (no optuna). Seeded
# for reproducibility. Coordinate-descent refinement around the winner
# tightens the top region.

TUNE_LOG_PATH = Path.home() / ".local/share/obsidian-rag/tune.jsonl"

# Search spaces for random sampling. Keep defaults inside the box so the
# baseline is a representable sample (search includes the status quo).
_TUNE_SPACE = {
    "recency_cue":        (0.0, 0.35),   # default 0.10
    "recency_always":     (0.0, 0.10),   # default 0.00 (new signal)
    "tag_literal":        (0.0, 0.20),   # default 0.00 (new signal)
    "title_match":        (0.0, 0.40),   # default 0.15 — filename/title coverage boost
    "feedback_pos":       (0.0, 0.15),   # default 0.03
    "feedback_neg":       (0.0, 0.50),   # default 0.15
    "feedback_match_floor": (0.60, 0.95),  # default 0.80 — soft ramp floor; preserves pre-refactor hard-gate behavior at default
    "graph_pagerank":     (0.0, 0.30),   # default 0.00 — wikilink authority signal
    # Behavior priors — inert at 0.0 until behavior.jsonl accumulates signal
    "click_prior":        (0.0, 0.30),   # per-path CTR from open/save events
    "click_prior_folder": (0.0, 0.15),   # top-level folder CTR
    "click_prior_hour":   (0.0, 0.20),   # path × current-hour CTR
    "click_prior_dayofweek": (0.0, 0.15),  # path × weekday CTR (lun=0..dom=6)
    "dwell_score":        (0.0, 0.10),   # log1p(mean_dwell_s) per path
    # Contradiction penalty (default 0.0, opt-in). Range conservador 0-0.30:
    # log1p(count_distinct_ts) puede llegar a ~3 (e.g. 20 detecciones en
    # 90d) → contribución máxima ~0.9 al score, en el orden del feedback_neg.
    # Si tune encuentra que ayuda, debería convergir a un valor pequeño.
    "contradiction_penalty": (0.0, 0.30),
}


def _feedback_augmented_cases(min_len: int = 4) -> list[dict]:
    """Mine rag_feedback SQL for `corrective_path` events — each is a
    gold (query, [corrective_path]) tuple that `rag tune` consumes as
    positive training signal. Skips session-scope, deduplicates queries
    by normalised form (lowercase + collapsed whitespace), drops
    entries where the corrective path is empty or the query is shorter
    than `min_len`.

    Post-T10 (2026-04-19) reads from SQL — `corrective_path` lives
    inside `extra_json` since it isn't a first-class column. Pre-fix
    the pre-T10 JSONL parser returned [] against the stale file and
    `rag tune` silently lost all corrective signal.
    """
    sql = (
        "SELECT q, json_extract(extra_json, '$.corrective_path') AS cp"
        " FROM rag_feedback"
        " WHERE (scope IS NULL OR scope != 'session')"
        "   AND q IS NOT NULL AND q != ''"
        "   AND json_extract(extra_json, '$.corrective_path') IS NOT NULL"
        "   AND json_extract(extra_json, '$.corrective_path') != ''"
        " ORDER BY ts ASC"
    )
    try:
        with _ragvec_state_conn() as conn:
            rows = conn.execute(sql).fetchall()
    except Exception as exc:
        _silent_log("feedback_augmented_cases_sql_read", exc)
        return []
    seen_q: set[str] = set()
    out: list[dict] = []
    for q_raw, cp_raw in rows:
        q = (q_raw or "").strip()
        cp = (cp_raw or "").strip()
        if not q or not cp or len(q) < min_len:
            continue
        key = " ".join(q.lower().split())
        if key in seen_q:
            continue
        seen_q.add(key)
        out.append({"question": q, "expected": [cp], "source": "feedback"})
    return out


def _feedback_implicit_cases(
    days: int = 30,
    weight: float = 0.3,
) -> list[dict]:
    """Mine rag_feedback for IMPLICIT signals that `_feedback_augmented_cases`
    misses — feedbacks with `q` + `paths_json` but no `corrective_path`.

    Sources covered:
      - explicit ratings (+1/-1) without corrective: user reacted but
        didn't single out a path. Treat ALL top-K paths as weak signal.
      - session_outcome_loss / session_outcome_win: reward shaping daemon
        (rag feedback classify-sessions) flagged the session.
      - requery_detection: paraphrase within 30s → previous turn's paths
        are weak negatives.

    Why these are 'weak': we don't know which specific path drove the
    rating; the (q, path) pair is reconstructed from the top-K. Weight
    defaults to 0.3 — half of the strong signal (corrective_path = 1.0,
    direct behavior open = 0.5). Lower = lower influence on the tune
    objective relative to ground-truth golden cases.

    Returns dicts compatible with `_feedback_augmented_cases` /
    `_behavior_augmented_cases` output.
    """
    cutoff = (
        datetime.fromtimestamp(time.time() - days * 86400)
        .isoformat(timespec="seconds")
    )
    pos: dict[tuple[str, str], str] = {}
    neg: dict[tuple[str, str], str] = {}

    sql = (
        "SELECT rating, q, paths_json, "
        "       json_extract(extra_json, '$.implicit_loss_source')  AS loss_src, "
        "       json_extract(extra_json, '$.implicit_win_source')   AS win_src, "
        "       json_extract(extra_json, '$.corrective_path')       AS cp "
        "FROM rag_feedback "
        "WHERE (scope IS NULL OR scope != 'session') "
        "  AND q IS NOT NULL AND q != '' "
        "  AND paths_json IS NOT NULL AND paths_json != '' "
        "  AND ts >= ? "
        "ORDER BY ts ASC"
    )
    try:
        with _ragvec_state_conn() as conn:
            rows = conn.execute(sql, (cutoff,)).fetchall()
    except Exception as exc:
        _log_sql_state_error("feedback_implicit_cases_sql_read_failed",
                              err=repr(exc))
        return []

    for row in rows:
        rating = row["rating"] if hasattr(row, "keys") else row[0]
        q = (row["q"] if hasattr(row, "keys") else row[1]) or ""
        paths_json = row["paths_json"] if hasattr(row, "keys") else row[2]
        cp = row["cp"] if hasattr(row, "keys") else row[5]
        # Skip rows with explicit corrective_path — those are the strong
        # signal that `_feedback_augmented_cases` already consumes.
        if cp:
            continue
        try:
            paths = json.loads(paths_json) if isinstance(paths_json, str) else paths_json
        except (json.JSONDecodeError, TypeError):
            continue
        if not paths or not isinstance(paths, list):
            continue
        norm_q = " ".join(q.strip().lower().split())
        if not norm_q:
            continue
        # Determine sign from rating + implicit source.
        is_pos = rating == 1
        is_neg = rating == -1
        if not (is_pos or is_neg):
            continue
        for p in paths:
            if not isinstance(p, str) or not p:
                continue
            key = (norm_q, p)
            if is_pos:
                pos[key] = "feedback_implicit_pos"
            else:
                neg[key] = "feedback_implicit_neg"

    # Drop conflicting keys (same q+path appearing as both pos and neg).
    conflict = set(pos.keys()) & set(neg.keys())
    out: list[dict] = []
    for key, source in pos.items():
        if key in conflict:
            continue
        norm_q, path = key
        out.append({
            "question": norm_q,
            "expected": [path],
            "kind_hint": "behavior_pos",
            "source": source,
            "weight": weight,
        })
    for key, source in neg.items():
        if key in conflict:
            continue
        norm_q, path = key
        out.append({
            "question": norm_q,
            "anti_expected": [path],
            "kind_hint": "behavior_neg",
            "source": source,
            "weight": weight,
        })
    return out


def _behavior_augmented_cases(days: int = 14) -> list[dict]:
    """Mine behavior events for implicit feedback — forms gold (query, path) tuples.

    Positive events (open/positive_implicit/save/kept) with a query field
    become positive cases (weight=0.5). Negative events (negative_implicit/
    deleted) with a query field become hard-negative cases. Conflicting (q,path)
    pairs where both pos and neg are observed are dropped entirely. Events
    without a 'query' field (e.g. brief events) are skipped.

    Reads from rag_behavior with `ts >= since_ts` (ISO-8601 14-day cutoff).
    SQL-only since T10. On SQL error: empty list.
    """
    cutoff_ts = time.time() - days * 86400
    since_iso = datetime.fromtimestamp(cutoff_ts).isoformat(timespec="seconds")
    # Audit 2026-04-26 (BUG #4): pre-fix usaba un literal local desincronizado
    # del frozenset global. `_BEHAVIOR_POSITIVE` evolucionó agregando
    # `open_external` y `copy` pero esta función no se enteraba → tune nightly
    # descartaba esos eventos silenciosamente. Reusar el global garantiza
    # propagación automática a futuros adds.
    _POSITIVE = _BEHAVIOR_POSITIVE
    _NEGATIVE = _BEHAVIOR_NEGATIVE
    pos: dict[tuple[str, str], str] = {}   # (norm_q, path) → source
    neg: dict[tuple[str, str], str] = {}   # (norm_q, path) → source

    try:
        with _ragvec_state_conn() as conn:
            rows_iter = _sql_query_window(conn, "rag_behavior", since_iso)
    except Exception as exc:
        _log_sql_state_error("behavior_augmented_cases_sql_read_failed",
                              err=repr(exc))
        return []

    for ev in rows_iter:
        # Uniform accessor for sqlite3.Row.
        def _g(k):
            try:
                return ev[k]
            except (KeyError, IndexError):
                return None
        query = (_g("query") or "").strip()
        if not query:
            continue
        path = (_g("path") or "").strip()
        if not path:
            continue
        event = _g("event") or ""
        norm_q = " ".join(query.lower().split())
        key = (norm_q, path)
        if event in _POSITIVE:
            pos[key] = event
        elif event in _NEGATIVE:
            neg[key] = event
    # Drop conflicting (q, path) pairs
    conflict = set(pos.keys()) & set(neg.keys())
    out: list[dict] = []
    for key, source in pos.items():
        if key in conflict:
            continue
        norm_q, path = key
        out.append({
            "question": norm_q,
            "expected": [path],
            "kind_hint": "behavior_pos",
            "source": source,
            "weight": 0.5,
        })
    for key, source in neg.items():
        if key in conflict:
            continue
        norm_q, path = key
        out.append({
            "question": norm_q,
            "anti_expected": [path],
            "kind_hint": "behavior_neg",
            "source": source,
            "weight": 0.5,
        })
    return out


def _brief_synthetic_cases(
    days: int = 14,
    lookback_days: int = 7,
    max_queries_per_path: int = 5,
    weight: float = 0.3,
) -> list[dict]:
    """Recover brief kept/deleted events that lack a `query` field by attaching
    them to recent queries whose top-K returned the same path.

    Brief events arrive without a query because the brief is a curated stack
    of items presented to the user — the user kept/deleted each independently
    of the original retrieval call. But the path almost always surfaced via
    one or more recent queries (those queries' paths_json contains it). This
    function reconstructs (q, path) cases from that join:

      brief.kept    + path P + recent query Q where P ∈ Q.top_K  →  (Q, P) positive
      brief.deleted + path P + recent query Q where P ∈ Q.top_K  →  (Q, P) negative

    Args:
        days: window for brief events (matches `_behavior_augmented_cases`).
        lookback_days: how far back to search rag_queries for each event;
            limited to events PRIOR to the brief event ts (causal-only).
        max_queries_per_path: cap synthetic queries per (event, path) so a
            single popular path doesn't dominate the training signal.
        weight: lower than 0.5 (the direct behavior signal) because the
            (q, path) pair is reconstructed, not directly observed.

    Returns:
        list of dicts compatible with `_behavior_augmented_cases` output.
        Conflicting (q, path) keys (same pair as both pos and neg) are dropped.
        Cada caso emitido lleva ``synthetic_source="brief"`` (cerrado
        2026-04-28) para que downstream tuning pueda down-weight o filtrar
        este pool — son casos LLM-curated (el brief fue armado por el
        LLM a partir del corpus + reminders + calendar), no clicks
        directos del user. La distinción permite ablation experiments
        ("¿qué pasa si entreno SOLO con casos directos?") sin tener que
        re-derivar el origen post-hoc.
    """
    cutoff_ts = time.time() - days * 86400
    cutoff_iso = datetime.fromtimestamp(cutoff_ts).isoformat(timespec="seconds")
    pos: dict[tuple[str, str], str] = {}
    neg: dict[tuple[str, str], str] = {}

    try:
        with _ragvec_state_conn() as conn:
            brief_rows = conn.execute(
                "SELECT path, event, ts FROM rag_behavior "
                "WHERE source='brief' AND event IN ('kept','deleted') "
                "  AND path IS NOT NULL AND path != '' "
                "  AND (query IS NULL OR query = '') "
                "  AND ts >= ?",
                (cutoff_iso,),
            ).fetchall()

            for be in brief_rows:
                path = be["path"] if hasattr(be, "keys") else be[0]
                event = be["event"] if hasattr(be, "keys") else be[1]
                ev_ts = be["ts"] if hasattr(be, "keys") else be[2]
                # Lookback bound: don't attach queries posterior to the
                # brief event (would be leakage from future to past).
                lookback_ts = (
                    datetime.fromisoformat(ev_ts) - timedelta(days=lookback_days)
                ).isoformat(timespec="seconds")
                # JSON array LIKE: paths_json is `["a", "b"]`; match on
                # quoted path so we don't false-positive on substrings.
                # Path can't contain `"` in the vault (Obsidian disallows),
                # so simple LIKE is safe.
                pat = '%"' + path + '"%'
                qrows = conn.execute(
                    "SELECT q FROM rag_queries "
                    "WHERE ts >= ? AND ts <= ? "
                    "  AND paths_json LIKE ? "
                    "  AND q IS NOT NULL AND q != '' "
                    "ORDER BY ts DESC LIMIT ?",
                    (lookback_ts, ev_ts, pat, max_queries_per_path),
                ).fetchall()
                for r in qrows:
                    q = (r["q"] if hasattr(r, "keys") else r[0]) or ""
                    q = q.strip()
                    if not q:
                        continue
                    norm_q = " ".join(q.lower().split())
                    key = (norm_q, path)
                    if event == "kept":
                        pos[key] = "brief_kept_synthetic"
                    elif event == "deleted":
                        neg[key] = "brief_deleted_synthetic"
    except Exception as exc:
        _log_sql_state_error("brief_synthetic_cases_sql_read_failed",
                              err=repr(exc))
        return []

    # Drop conflicting (q, path) pairs (rare but possible if the user
    # kept then later deleted the same brief item).
    conflict = set(pos.keys()) & set(neg.keys())
    out: list[dict] = []
    for key, source in pos.items():
        if key in conflict:
            continue
        norm_q, path = key
        out.append({
            "question": norm_q,
            "expected": [path],
            "kind_hint": "behavior_pos",
            "source": source,
            "weight": weight,
            "synthetic_source": "brief",
        })
    for key, source in neg.items():
        if key in conflict:
            continue
        norm_q, path = key
        out.append({
            "question": norm_q,
            "anti_expected": [path],
            "kind_hint": "behavior_neg",
            "source": source,
            "weight": weight,
            "synthetic_source": "brief",
        })
    return out


def _score_case(feats: list[dict], expected: set[str],
                weights: "RankerWeights", k: int,
                anti_expected: set[str] | None = None) -> tuple[bool, float, float]:
    """Return (hit, reciprocal_rank, recall) for one case under `weights`.

    For positive cases (anti_expected=None): hit iff expected ∩ top-k ≠ ∅.
    For negative cases (anti_expected non-empty, expected empty): hit iff
    anti_expected ∩ top-k = ∅ (the ranker correctly pushes the bad result out).
    """
    top = apply_weighted_scores(feats, weights, k)
    paths = [t["path"] for t in top]
    retrieved = set(paths)
    # Negative case: hit = bad path NOT in top-k (ranker correctly avoids it)
    if anti_expected:
        hit = not bool(anti_expected & retrieved)
        # RR/recall not meaningful for negative cases — return 1.0 when hit
        rr = 1.0 if hit else 0.0
        recall = 1.0 if hit else 0.0
        return hit, rr, recall
    hit = bool(expected & retrieved)
    rr = 0.0
    for rank, p in enumerate(paths, start=1):
        if p in expected:
            rr = 1.0 / rank
            break
    recall = len(expected & retrieved) / len(expected) if expected else 0.0
    return hit, rr, recall


def _aggregate(cases_metrics: list[tuple[bool, float, float]]) -> dict:
    n = len(cases_metrics) or 1
    hit = sum(1 for h, _, _ in cases_metrics if h) / n
    mrr = sum(r for _, r, _ in cases_metrics) / n
    recall = sum(rc for _, _, rc in cases_metrics) / n
    return {"hit": hit, "mrr": mrr, "recall": recall, "n": n}


def _objective(agg: dict) -> float:
    """Composite objective favouring hit over rank quality."""
    return agg["hit"] + 0.5 * agg["mrr"]


def _sample_weights(rng) -> "RankerWeights":
    kw = {k: rng.uniform(lo, hi) for k, (lo, hi) in _TUNE_SPACE.items()}
    return RankerWeights(**kw)


def _coordinate_refine(
    best: "RankerWeights", cached_cases: list[dict], k: int,
    steps: int = 7,
) -> "RankerWeights":
    """Cheap local search: for each dim, scan `steps` equally-spaced values
    in a shrunken box around the current value, keeping each improvement.
    Deterministic. Cheap: O(5 * steps * len(cases_metrics)).
    """
    current = RankerWeights(**best.as_dict())
    best_score = _objective(_aggregate(
        [c["metrics"](current) for c in cached_cases]
    ))
    for dim, (lo, hi) in _TUNE_SPACE.items():
        cur = getattr(current, dim)
        span = (hi - lo) * 0.3
        low = max(lo, cur - span)
        high = min(hi, cur + span)
        if steps <= 1 or high <= low:
            continue
        for i in range(steps):
            trial_val = low + (high - low) * i / (steps - 1)
            kw = current.as_dict()
            kw[dim] = trial_val
            trial = RankerWeights(**kw)
            score = _objective(_aggregate(
                [c["metrics"](trial) for c in cached_cases]
            ))
            if score > best_score + 1e-9:
                best_score = score
                current = trial
    return current


def _log_tune_event(event: dict) -> None:
    ev = {"ts": datetime.now().isoformat(timespec="seconds"), **event}

    def _do() -> None:
        with _ragvec_state_conn() as conn:
            _sql_append_event(conn, "rag_tune", _map_tune_row(ev))
    _sql_write_with_retry(_do, "tune_sql_write_failed")


def _backup_ranker_config() -> Path | None:
    """Copy current ranker.json to a pid+timestamped backup, keeping only 3 newest.

    Returns the backup Path on success, None if ranker.json doesn't exist yet.
    Prunes backups older than the 3 most recent after writing.

    Filename format: `ranker.{unix_ts}.{pid}.json`. The pid suffix avoids
    collision when two `rag tune` processes run in the same wall-clock
    second (manual + cron) — without it the second copy silently overwrote
    the first. Pruning still uses mtime so the retention window is correct.

    Legacy `ranker.{ts}.json` files (pre-pid) are still matched by the
    glob + sort + prune flow, so the 7-day backfill is seamless.
    """
    if not RANKER_CONFIG_PATH.is_file():
        return None
    ts = int(time.time())
    backup = RANKER_CONFIG_PATH.parent / f"ranker.{ts}.{os.getpid()}.json"
    try:
        import shutil
        shutil.copy2(RANKER_CONFIG_PATH, backup)
        # Prune: keep only 3 most recent backups. glob matches both
        # `ranker.{ts}.json` (legacy) and `ranker.{ts}.{pid}.json` (new).
        backups = sorted(
            RANKER_CONFIG_PATH.parent.glob("ranker.*.json"),
            key=lambda p: p.stat().st_mtime,
            reverse=True,
        )
        for old in backups[3:]:
            try:
                old.unlink()
            except Exception:
                pass
        return backup
    except Exception:
        return None


def _restore_ranker_backup(backup: Path) -> bool:
    """Restore a backup file to ranker.json atomically. Returns True on success."""
    try:
        import shutil
        tmp = RANKER_CONFIG_PATH.with_suffix(".json.tmp")
        shutil.copy2(backup, tmp)
        tmp.replace(RANKER_CONFIG_PATH)
        return True
    except Exception:
        return False


# CI gate thresholds — recalibrados 2026-04-27 post golden remap (vault reorg).
#
# Timeline de los floors:
#
#   2026-04-17  n=42 singles / 33 turns  → singles 90.48% [76.19, 97.62]
#                                          chains  80.00% [63.64, 93.94]
#               → floors originales: 0.7619 / 0.6364 (CI lower bounds)
#
#   2026-04-21  queries.yaml expandido 42→60 singles (+6 synthesis/comparison,
#               +7 cross-source placeholders, +5 calendar goldens). Las queries
#               nuevas son INTENCIONALMENTE más difíciles — el retrieve pipeline
#               no regresionó.
#
#   2026-04-23  n=60 / 30 turns stable baseline (desde 2026-04-22):
#                 singles 71.67% [60.00, 83.33]
#                 chains  86.67% [73.33, 96.67]
#               → floors recalibrados: 0.60 / 0.73 (CI lower bounds)
#               Los floors viejos (0.7619 / 0.6364) ya no eran compatibles con
#               el golden set — singles 71.67% < 76.19% disparaba auto-rollback
#               en TODA corrida.
#
#   2026-04-27  Vault reorg commit 6f8994f: n=54 singles / 9 chains.
#               Golden remap borró 6 singles + 3 chains (paths muertos post-reorg
#               sin equivalente en el nuevo vault). El baseline estable post-remap
#               medido en 2 corridas reproducibles:
#                 singles 53.70% [40.74, 66.67]  (run 1 = run 2, bit-idéntico)
#                 chains  72.00% [52.00, 88.00]  (hit@5 bit-idéntico; MRR dentro CI)
#               → floors recalibrados: 0.4074 / 0.5200 (CI lower bounds del menor
#               de los 2 runs — criterio conservador "95% confianza de que una
#               corrida bajo esto es regresión real, no noise").
#               Nota: la caída de hit@5 (71.67% → 53.70% singles, 86.67% → 72.00%
#               chains) NO es regresión del pipeline — es reducción del n y
#               remoción de goldens fáciles que ya no existen en el vault.
#
# Overrides via env para fine-tune local sin tocar código:
#   RAG_EVAL_GATE_SINGLES_MIN="0.50"  → más estricto
#   RAG_EVAL_GATE_CHAINS_MIN="0.60"   → idem
#
# **Re-calibrar cuando**: expansión material de queries.yaml, cambio
# estructural en retrieve() (ej. nuevo modelo de embeddings), o si 5+
# corridas consecutivas bordean el floor sin regresión real.

GATE_SINGLES_HIT5_MIN = float(
    os.environ.get("RAG_EVAL_GATE_SINGLES_MIN", "0.4074")
)
GATE_CHAINS_HIT5_MIN = float(
    os.environ.get("RAG_EVAL_GATE_CHAINS_MIN", "0.52")
)


def _run_eval_gate() -> tuple[float | None, float | None, str]:
    """Run `rag eval` in a subprocess and parse hit@5 for singles + chains.

    Returns (singles_hit5, chains_hit5, raw_output). On timeout or parse error
    one or both values may be None (treat as regression). Scrubs RAG_EXPLORE
    from subprocess env so the eval run is production-equivalent.

    Timeout sized at 2400s (40 min): post 2026-04-27 vault reorg + golden
    remap + cross-source ingester expansion. Real cost measured 2026-04-27
    on M-chip mac with corpus 8k+ chunks: singles ~10:30 + chains ~13:45 +
    setup/teardown ~30s = **24 min total warm**.

    Timeline de timeouts:
      - originalmente 300s (5 min) — sized cuando n era más chico y chains
        usaban pipeline lighter
      - 2026-04-25: 1200s (20 min) — post-expansion del corpus, sized para
        "10-12 min warm typical" (medición optimista)
      - 2026-04-27: 2400s (40 min) — la medición optimista era WRONG, el
        eval real tarda 24 min y `rag tune --online` corre 5 trials de
        random search ANTES del eval (~3-5 min adicionales). Timeout 20
        min disparaba false-positive auto-rollback en TODAS las corridas
        nightly desde el 2026-04-25 (observado en online-tune.log:
        "✗ CI gate falló: No se pudo parsear singles hit@5 (timeout o
        error)"). 40 min deja margen cómodo para el cold-start de ollama
        + reload del qwen2.5:3b helper en chains + variación normal del
        random search.

    Override via RAG_EVAL_GATE_TIMEOUT_S env si tu hardware es faster o
    slower. El plist `com.fer.obsidian-rag-online-tune` lo setea
    explícitamente para no depender del default del código.
    """
    import subprocess
    _GATE_TIMEOUT_S = int(os.environ.get("RAG_EVAL_GATE_TIMEOUT_S", "2400"))
    env = {k: v for k, v in os.environ.items() if k != "RAG_EXPLORE"}
    assert "RAG_EXPLORE" not in env, "RAG_EXPLORE must not be set during gate eval"
    try:
        result = subprocess.run(
            ["rag", "eval"],
            capture_output=True,
            text=True,
            timeout=_GATE_TIMEOUT_S,
            env=env,
        )
    except subprocess.TimeoutExpired:
        return None, None, f"[timeout after {_GATE_TIMEOUT_S}s]"
    except Exception as exc:
        return None, None, f"[subprocess error: {exc}]"
    out = result.stdout + result.stderr
    singles_hit5 = None
    chains_hit5 = None
    m = re.search(r"Singles:\s*hit@\d+\s+(\d+(?:\.\d+)?)%", out)
    if m:
        singles_hit5 = float(m.group(1)) / 100.0
    m = re.search(r"Chains:\s*hit@\d+\s+(\d+(?:\.\d+)?)%", out)
    if m:
        chains_hit5 = float(m.group(1)) / 100.0
    return singles_hit5, chains_hit5, out


@cli.command()
@click.option("--file", "queries_file", default="queries.yaml",
              help="YAML golden (default: queries.yaml)")
@click.option("-k", default=5, help="top-k para métricas (default: 5)")
@click.option("--samples", default=500, show_default=True,
              help="Trials de random search")
@click.option("--seed", default=42, show_default=True,
              help="Seed para reproducibilidad")
@click.option("--no-chains", is_flag=True,
              help="Saltar chains (sólo singles + feedback)")
@click.option("--no-feedback", is_flag=True,
              help="Ignorar feedback.jsonl (usar sólo queries.yaml)")
@click.option("--apply", is_flag=True,
              help="Persistir winner a ~/.local/share/obsidian-rag/ranker.json")
@click.option("--yes", is_flag=True,
              help="Equivalente a --apply, sin prompt (para launchd)")
@click.option("--online", is_flag=True,
              help="Agregar behavior.jsonl como casos de tuning implícitos")
@click.option("--days", default=14, show_default=True,
              help="Ventana de días para eventos en behavior.jsonl (solo con --online)")
@click.option("--rollback", is_flag=True,
              help="Restaurar el backup más reciente de ranker.json sin tunear")
def tune(queries_file: str, k: int, samples: int, seed: int,
         no_chains: bool, no_feedback: bool, apply: bool, yes: bool,
         online: bool, days: int, rollback: bool):
    """Auto-calibrar pesos del ranker sobre un golden set.

    Toma queries.yaml + feedback.jsonl (corrective_path events), corre
    `collect_ranker_features()` una vez por caso (~1-2s cada uno), y luego
    barre `--samples` combinaciones de pesos in-memory contra hit@k + 0.5·MRR.
    Reporta top-5 y el baseline (weights actuales). Con --apply persiste
    el winner a RANKER_CONFIG_PATH. Log a tune.jsonl.

    Con --online incluye behavior.jsonl como casos de tuning implícitos (weight=0.5).
    Con --rollback restaura el backup más reciente sin tunear.

    Aproximación en chains: la reformulación entre turnos usa los pesos
    por defecto para anclar contexto — el barrido optimiza sólo la ordenación
    final por turno. Para obtener métricas end-to-end con el winner,
    re-correr `rag eval` después de --apply.
    """
    import pathlib
    import random
    # ── Rollback subcommand ──────────────────────────────────────────────────
    if rollback:
        backups = sorted(
            RANKER_CONFIG_PATH.parent.glob("ranker.*.json"),
            key=lambda p: p.stat().st_mtime,
            reverse=True,
        )
        if not backups:
            console.print("[yellow]No hay backups de ranker.json disponibles.[/yellow]")
            return
        # Show available backups
        console.print("[bold]Backups disponibles (más reciente primero):[/bold]")
        current_w = RankerWeights.load()
        for bp in backups:
            try:
                bdata = json.loads(bp.read_text(encoding="utf-8"))
                bw = RankerWeights.from_dict(bdata.get("weights", {}) if isinstance(bdata, dict) else {})
                delta_str = ", ".join(
                    f"{k}: {bw.as_dict()[k] - current_w.as_dict()[k]:+.4f}"
                    for k in sorted(bw.as_dict())
                    if abs(bw.as_dict()[k] - current_w.as_dict()[k]) > 1e-6
                ) or "(sin diferencia)"
            except Exception:
                delta_str = "(no se pudo parsear)"
            mtime_str = datetime.fromtimestamp(bp.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S")
            console.print(f"  [cyan]{bp.name}[/cyan]  {mtime_str}  Δ {delta_str}")
        # Restore most recent
        newest = backups[0]
        if _restore_ranker_backup(newest):
            _invalidate_ranker_weights()
            console.print(
                f"[green]✓[/green] restored ranker.json from [cyan]{newest.name}[/cyan]"
            )
        else:
            console.print(f"[red]Error al restaurar {newest.name}[/red]")
        return

    path = pathlib.Path(queries_file)
    if not path.is_absolute():
        path = pathlib.Path.cwd() / queries_file
    if not path.is_file():
        console.print(f"[red]No existe {path}[/red]")
        return
    data = yaml.safe_load(path.read_text(encoding="utf-8"))
    queries = data.get("queries") or []
    chains = [] if no_chains else (data.get("chains") or [])
    aug = [] if no_feedback else _feedback_augmented_cases()
    # Online mode: augment with implicit behavior signal
    behavior_cases: list[dict] = []
    if online:
        behavior_cases = _behavior_augmented_cases(days=days)
        # Synthetic attachment for brief kept/deleted events (which lack a
        # `query` field by design — the brief is a curated stack, not the
        # output of a single query). For each such event, we look up recent
        # rag_queries whose top-K returned the same path, and emit a
        # (q, path) case with reduced weight (0.3 vs 0.5 for direct signal).
        # See `_brief_synthetic_cases` for rationale.
        synthetic = _brief_synthetic_cases(days=days)
        behavior_cases.extend(synthetic)
        # Weak feedback signals: rag_feedback rows that have q + paths_json
        # but no corrective_path (i.e. implicit signals from
        # session_outcome / requery_detection / explicit ratings without
        # corrective). `_feedback_augmented_cases` only picks up rows with
        # corrective_path — this picks up the rest. weight=0.3 reflects
        # that the (q, path) pair is reconstructed from top-K, not directly
        # observed. See `_feedback_implicit_cases`.
        implicit_fb = _feedback_implicit_cases(days=max(days, 30))
        behavior_cases.extend(implicit_fb)
        console.print(
            f"[dim]Behavior cases: {len(behavior_cases)} "
            f"(pos={sum(1 for c in behavior_cases if 'expected' in c)}, "
            f"neg={sum(1 for c in behavior_cases if 'anti_expected' in c)}, "
            f"synthetic_brief={len(synthetic)}, "
            f"implicit_feedback={len(implicit_fb)}, "
            f"últimos {days}d)[/dim]"
        )

    col = get_db()
    if col.count() == 0:
        console.print("[red]Índice vacío. Ejecutá: rag index[/red]")
        return

    cases: list[dict] = []  # [{kind, id, q, expected, feats, anti_expected?}]
    total = len(queries) + len(aug) + len(behavior_cases) + sum(len(c.get("turns") or []) for c in chains)
    if total == 0:
        console.print("[yellow]Sin cases golden — queries.yaml vacío y sin feedback.[/yellow]")
        return

    # Singles + feedback augmentation + behavior — positive cases.
    single_items = list(queries) + aug
    # Behavior cases are handled separately since some are negative.
    with console.status(f"Extrayendo features ({len(single_items)} singles + "
                        f"{len(behavior_cases)} behavior + "
                        f"{sum(len(c.get('turns') or []) for c in chains)} turns)…"):
        for entry in single_items:
            q = entry["question"] if "question" in entry else entry.get("q", "")
            expected = set(entry.get("expected") or [])
            if not q or not expected:
                continue
            feats = collect_ranker_features(col, q, k_pool=RERANK_POOL_MAX)
            cases.append({
                "kind": "single",
                "id": entry.get("source", "golden"),
                "q": q,
                "expected": expected,
                "anti_expected": set(),
                "feats": feats,
            })

        # Behavior cases — positive and negative, weight=0.5.
        for entry in behavior_cases:
            q = entry.get("question", "")
            if not q:
                continue
            is_pos = "expected" in entry
            feats = collect_ranker_features(col, q, k_pool=RERANK_POOL_MAX)
            cases.append({
                "kind": "behavior_pos" if is_pos else "behavior_neg",
                "id": entry.get("source", "behavior"),
                "q": q,
                "expected": set(entry.get("expected") or []),
                "anti_expected": set(entry.get("anti_expected") or []),
                "weight": entry.get("weight", 0.5),
                "feats": feats,
            })

        # Chain turns — reformulated per eval's pattern, features captured once.
        defaults = RankerWeights.defaults()
        for chain in chains:
            chain_id = chain.get("id", "<sin id>")
            turns = chain.get("turns") or []
            history: list[dict] = []
            fake_sess: dict = {"turns": []}
            for i, turn in enumerate(turns):
                q = turn["question"]
                expected = set(turn.get("expected") or [])
                if i == 0 or not history:
                    search_q = q
                else:
                    chain_summary = session_summary(fake_sess)
                    search_q = reformulate_query(q, history, summary=chain_summary)
                feats = collect_ranker_features(col, search_q, k_pool=RERANK_POOL_MAX)
                if expected:
                    cases.append({
                        "kind": "chain",
                        "id": f"{chain_id}:{i}",
                        "chain_id": chain_id,
                        "turn_index": i,
                        "q": q,
                        "search_q": search_q,
                        "expected": expected,
                        "anti_expected": set(),
                        "feats": feats,
                    })
                # Anchor next turn with top-under-defaults.
                history.append({"role": "user", "content": q})
                top = apply_weighted_scores(feats, defaults, k)
                top_path = top[0]["path"] if top else ""
                fake_a = f"(contexto recuperado: {top_path})"
                history.append({"role": "assistant", "content": fake_a})
                fake_sess["turns"].append({"q": q, "a": fake_a})

    if not cases:
        console.print("[yellow]Sin cases evaluables.[/yellow]")
        return

    # Pre-compute per-case scoring closures — keeps the inner loop allocation-free.
    for c in cases:
        feats = c["feats"]; expected = c["expected"]
        anti = c.get("anti_expected") or set()
        c["metrics"] = lambda w, f=feats, e=expected, kk=k, a=anti: _score_case(f, e, w, kk, a)

    # Baseline: current persisted weights (or defaults if none saved).
    baseline_w = RankerWeights.load()
    baseline_metrics = [c["metrics"](baseline_w) for c in cases]
    baseline_agg = _aggregate(baseline_metrics)
    baseline_obj = _objective(baseline_agg)

    # Random search.
    rng = random.Random(seed)
    trials: list[tuple[float, RankerWeights, dict]] = []
    # Seed the trial list with the current baseline so a win must strictly beat it.
    trials.append((baseline_obj, baseline_w, baseline_agg))
    with console.status(f"Random search · {samples} trials…"):
        for _ in range(samples):
            w = _sample_weights(rng)
            metrics = [c["metrics"](w) for c in cases]
            agg = _aggregate(metrics)
            trials.append((_objective(agg), w, agg))

    trials.sort(key=lambda t: t[0], reverse=True)
    best_obj, best_w, best_agg = trials[0]

    # Coordinate descent refinement around the best random sample.
    refined = _coordinate_refine(best_w, cases, k)
    refined_agg = _aggregate([c["metrics"](refined) for c in cases])
    refined_obj = _objective(refined_agg)
    if refined_obj > best_obj:
        best_obj, best_w, best_agg = refined_obj, refined, refined_agg

    # Render results.
    console.print()
    console.print(Rule(title="[bold]rag tune[/bold]", style="cyan"))
    tbl = Table(show_header=True, header_style="bold", box=None, pad_edge=False)
    tbl.add_column("rank", justify="right", style="dim")
    tbl.add_column("objetivo", justify="right")
    tbl.add_column(f"hit@{k}", justify="right")
    tbl.add_column("MRR", justify="right")
    tbl.add_column("recall", justify="right")
    tbl.add_column("pesos", overflow="fold")
    tbl.add_row(
        "baseline",
        f"{baseline_obj:.4f}",
        f"{baseline_agg['hit']:.2%}",
        f"{baseline_agg['mrr']:.3f}",
        f"{baseline_agg['recall']:.2%}",
        json.dumps(baseline_w.as_dict(), separators=(",", ":")),
        style="yellow",
    )
    seen_objs: set[str] = set()
    rank = 1
    for obj, w, agg in trials:
        key = json.dumps(w.as_dict(), sort_keys=True)
        if key in seen_objs:
            continue
        seen_objs.add(key)
        if rank > 5:
            break
        delta = obj - baseline_obj
        tbl.add_row(
            str(rank),
            f"{obj:.4f} ({'+' if delta >= 0 else ''}{delta:.4f})",
            f"{agg['hit']:.2%}",
            f"{agg['mrr']:.3f}",
            f"{agg['recall']:.2%}",
            json.dumps(w.as_dict(), separators=(",", ":")),
            style="green" if delta > 0 else None,
        )
        rank += 1

    # Refined winner as its own row if different from top-1 random.
    if best_w.as_dict() != trials[0][1].as_dict():
        tbl.add_row(
            "refined",
            f"{best_obj:.4f} ({'+' if best_obj - baseline_obj >= 0 else ''}{best_obj - baseline_obj:.4f})",
            f"{best_agg['hit']:.2%}",
            f"{best_agg['mrr']:.3f}",
            f"{best_agg['recall']:.2%}",
            json.dumps(best_w.as_dict(), separators=(",", ":")),
            style="bold green" if best_obj > baseline_obj else None,
        )
    console.print(tbl)

    delta = best_obj - baseline_obj
    console.print()
    console.print(
        f"[dim]Cases: {len(cases)} "
        f"(singles={sum(1 for c in cases if c['kind']=='single')}, "
        f"chain_turns={sum(1 for c in cases if c['kind']=='chain')}, "
        f"behavior_pos={sum(1 for c in cases if c['kind']=='behavior_pos')}, "
        f"behavior_neg={sum(1 for c in cases if c['kind']=='behavior_neg')})[/dim]"
    )
    if delta > 1e-6:
        console.print(
            f"[green]✓[/green] Mejor config: [bold]+{delta:.4f}[/bold] sobre baseline "
            f"(hit {baseline_agg['hit']:.2%} → {best_agg['hit']:.2%}, "
            f"MRR {baseline_agg['mrr']:.3f} → {best_agg['mrr']:.3f})"
        )
    else:
        console.print(
            "[yellow]= Sin mejora sobre baseline.[/yellow] El config actual ya está cerca del óptimo "
            "en este golden — re-correr con --samples mayor o ampliar golden no hizo diferencia."
        )

    _log_tune_event({
        "cmd": "tune",
        "online": online,
        "samples": samples,
        "seed": seed,
        "n_cases": len(cases),
        "n_behavior": len(behavior_cases),
        "baseline": {"weights": baseline_w.as_dict(), **baseline_agg,
                     "objective": baseline_obj},
        "best": {"weights": best_w.as_dict(), **best_agg,
                 "objective": best_obj},
        "delta": delta,
    })

    if delta <= 1e-6:
        return
    do_apply = apply or yes
    if not do_apply:
        console.print()
        console.print(
            "[dim]Para persistir el winner:[/dim] "
            "[bold]rag tune --apply[/bold] "
            "[dim](o editar manualmente ranker.json)[/dim]"
        )
        return

    # ── Version backup before writing ────────────────────────────────────────
    backup_path = _backup_ranker_config()

    best_w.save(metadata={
        "source": "rag tune" + (" --online" if online else ""),
        "baseline": baseline_w.as_dict(),
        "metrics": best_agg,
        "delta": delta,
        "n_cases": len(cases),
        "n_behavior": len(behavior_cases),
        "samples": samples,
        "seed": seed,
    })
    _invalidate_ranker_weights()
    console.print(
        f"[green]✓[/green] Pesos persistidos en [cyan]{RANKER_CONFIG_PATH}[/cyan]."
    )
    if backup_path:
        console.print(f"[dim]Backup: {backup_path.name}[/dim]")

    # ── CI gate: only when --online --apply are both set ─────────────────────
    if online:
        console.print("[dim]Corriendo rag eval para validar CI gate…[/dim]")
        s_hit5, c_hit5, eval_out = _run_eval_gate()
        gate_ok = True
        reason = ""
        if s_hit5 is None:
            gate_ok = False
            reason = "No se pudo parsear singles hit@5 (timeout o error)"
        elif s_hit5 < GATE_SINGLES_HIT5_MIN:
            gate_ok = False
            reason = (
                f"Singles hit@5 {s_hit5:.2%} < floor {GATE_SINGLES_HIT5_MIN:.2%}"
            )
        if gate_ok and c_hit5 is None:
            gate_ok = False
            reason = "No se pudo parsear chains hit@5 (timeout o error)"
        elif gate_ok and c_hit5 is not None and c_hit5 < GATE_CHAINS_HIT5_MIN:
            gate_ok = False
            reason = (
                f"Chains hit@5 {c_hit5:.2%} < floor {GATE_CHAINS_HIT5_MIN:.2%}"
            )
        if not gate_ok:
            console.print(
                f"[red]✗ CI gate falló: {reason}. Auto-rollback…[/red]"
            )
            if backup_path and backup_path.is_file():
                if _restore_ranker_backup(backup_path):
                    _invalidate_ranker_weights()
                    console.print(
                        f"[yellow]Ranker restaurado desde {backup_path.name}[/yellow]"
                    )
                else:
                    console.print("[red]Error al restaurar backup[/red]")
            _log_tune_event({
                "cmd": "tune_gate_regression",
                "reason": reason,
                "singles_hit5": s_hit5,
                "chains_hit5": c_hit5,
                "gate_singles_min": GATE_SINGLES_HIT5_MIN,
                "gate_chains_min": GATE_CHAINS_HIT5_MIN,
                "auto_rolled_back": backup_path is not None,
            })
            import sys
            sys.exit(1)
        else:
            console.print(
                f"[green]✓[/green] CI gate pasado "
                f"(singles {s_hit5:.2%} ≥ {GATE_SINGLES_HIT5_MIN:.2%}, "
                f"chains {c_hit5:.2%} ≥ {GATE_CHAINS_HIT5_MIN:.2%})"
            )

    # ── Stratified eval (Sprint 3 hook, 2026-04-26) ────────────────────────
    # Defense-in-depth sobre el CI gate aggregate: cluster las queries de
    # singles por tipo (definition / procedural / temporal / etc.), y mide
    # hit@k per cluster baseline vs candidate. Si CUALQUIER cluster
    # regresiona >5pp, se considera regresión silenciosa que el aggregate
    # ocultó (mejora pareja de clusters fáciles, empeoró cluster crítico).
    #
    # Modo informativo siempre: imprime el delta per cluster post-tune.
    # Modo bloqueante con `RAG_TUNE_STRATIFIED_GATE=1`: si detecta
    # regresión, dispara rollback igual que el CI gate aggregate.
    #
    # Sin re-correr `rag eval` — reusa los `cases` ya computados (con
    # `feats` precomputados via collect_ranker_features) y solo re-scorea
    # con apply_weighted_scores. Costo: ~milisegundos, no segundos.
    try:
        from rag_implicit_learning import (
            cluster_query,
            should_rollback,
        )

        singles = [c for c in cases if c.get("kind") == "single"]

        def _hit5_for_cluster(cluster_cases, weights):
            hits = 0
            n_evaluable = 0
            for case in cluster_cases:
                feats = case.get("feats")
                expected = set(case.get("expected") or [])
                if not feats or not expected:
                    continue
                n_evaluable += 1
                ranked = apply_weighted_scores(feats, weights, k=k)
                paths_topk = [r["path"] for r in ranked[:k]]
                if any(p in expected for p in paths_topk):
                    hits += 1
            return {
                "hit5": hits / n_evaluable if n_evaluable > 0 else 0.0,
                "n_cases": n_evaluable,
                "included_in_gate": n_evaluable >= 3,
            }

        by_cluster: dict[str, list[dict]] = {}
        for case in singles:
            cluster = cluster_query(case.get("q") or "")
            by_cluster.setdefault(cluster, []).append(case)

        baseline_per_cluster: dict[str, dict] = {}
        candidate_per_cluster: dict[str, dict] = {}
        for cluster_name, cluster_cases in by_cluster.items():
            baseline_per_cluster[cluster_name] = _hit5_for_cluster(
                cluster_cases, baseline_w
            )
            candidate_per_cluster[cluster_name] = _hit5_for_cluster(
                cluster_cases, best_w
            )

        decision = should_rollback(baseline_per_cluster, candidate_per_cluster)

        console.print()
        console.print("[bold]Stratified eval per cluster:[/bold]")
        for cluster_name, delta_pp in sorted(decision["per_cluster_delta"].items()):
            n_cases_cluster = candidate_per_cluster[cluster_name]["n_cases"]
            style = (
                "green" if delta_pp > 0 else "red" if delta_pp < 0 else "dim"
            )
            console.print(
                f"  [{style}]{cluster_name:18}: {delta_pp:+.2f}pp"
                f" (n={n_cases_cluster})[/{style}]"
            )

        # Excluded clusters (n < 3) — listamos para visibility.
        excluded = [
            (name, info["n_cases"])
            for name, info in candidate_per_cluster.items()
            if not info["included_in_gate"]
        ]
        if excluded:
            console.print(
                f"  [dim]Clusters excluidos del gate (n<3): "
                + ", ".join(f"{n}={c}" for n, c in excluded)
                + "[/dim]"
            )

        stratified_gate_env = os.environ.get(
            "RAG_TUNE_STRATIFIED_GATE", "0"
        ).strip()
        stratified_gate_enabled = stratified_gate_env not in ("", "0", "false", "no")

        if decision["rollback"]:
            if stratified_gate_enabled:
                console.print(
                    f"[red]✗ Stratified gate falló: {decision['reason']}. "
                    "Auto-rollback…[/red]"
                )
                if backup_path and backup_path.is_file():
                    if _restore_ranker_backup(backup_path):
                        _invalidate_ranker_weights()
                        console.print(
                            f"[yellow]Ranker restaurado desde "
                            f"{backup_path.name}[/yellow]"
                        )
                _log_tune_event({
                    "cmd": "tune_stratified_regression",
                    "reason": decision["reason"],
                    "regressed_clusters": decision["regressed_clusters"],
                    "per_cluster_delta": decision["per_cluster_delta"],
                    "auto_rolled_back": backup_path is not None,
                })
                import sys as _sys
                _sys.exit(1)
            else:
                console.print(
                    f"[yellow]⚠ Stratified detectó regresión: "
                    f"{decision['reason']}[/yellow]"
                )
                console.print(
                    "[dim]   Set RAG_TUNE_STRATIFIED_GATE=1 en el plist "
                    "para que esto bloquee futuros deploys.[/dim]"
                )
                _log_tune_event({
                    "cmd": "tune_stratified_warn",
                    "reason": decision["reason"],
                    "regressed_clusters": decision["regressed_clusters"],
                    "per_cluster_delta": decision["per_cluster_delta"],
                })
        else:
            console.print(
                f"[green]✓[/green] Stratified eval OK: {decision['reason']}"
            )
    except Exception as exc:
        # Stratified eval es bonus — si rompe, NO afectamos el flow del tune.
        # Si esto pasa, el aggregate gate ya fue OK (sino habríamos exited
        # antes), así que el modelo igual queda persistido.
        console.print(
            f"[dim]Stratified eval skipped ({type(exc).__name__}: {exc})[/dim]"
        )


@cli.command()
@click.argument("path")
@click.option("--apply", is_flag=True, help="Escribir los tags al frontmatter (por defecto solo imprime)")
@click.option("--max-tags", default=6, help="Cantidad máxima de tags a sugerir")
def autotag(path: str, apply: bool, max_tags: int):
    """Sugerir tags para una nota usando el vocabulario existente del vault.

    El helper model (qwen2.5:3b) ve los tags ya usados en el índice + el
    contenido de la nota y elige los que encajen. No inventa tags nuevos —
    mantiene consistencia con la taxonomía del vault.
    """
    note_path = VAULT_PATH / path if not path.startswith("/") else Path(path)
    if not note_path.is_file():
        console.print(f"[red]Nota no encontrada:[/red] {note_path}")
        return

    col = get_db()
    c = _load_corpus(col)
    vocab = sorted(c["tags"])
    raw = note_path.read_text(encoding="utf-8", errors="ignore")
    fm = parse_frontmatter(raw)
    current_tags = _normalize_fm_tags(fm)
    body = clean_md(raw)[:3000]

    prompt = (
        "Sos un asistente que etiqueta notas personales. Elegí entre 3 y "
        f"{max_tags} tags DEL VOCABULARIO EXISTENTE que mejor describan esta nota. "
        "NO inventes tags nuevos. Devolvé SOLO una lista YAML de strings, "
        "sin explicación.\n\n"
        f"VOCABULARIO ({len(vocab)} tags): {', '.join(vocab)}\n\n"
        f"TÍTULO: {note_path.stem}\n\n"
        f"CONTENIDO:\n{body}\n\n"
        "TAGS:"
    )

    resp = _helper_client().chat(
        model=HELPER_MODEL,
        messages=[{"role": "user", "content": prompt}],
        options=HELPER_OPTIONS,
        keep_alive=OLLAMA_KEEP_ALIVE,
    )
    answer = resp.message.content.strip()

    # Parse: expect "- tag1\n- tag2" or "[tag1, tag2]" or plain list.
    vocab_set = {t.lower() for t in vocab}
    picked: list[str] = []
    for line in answer.splitlines():
        line = line.strip().strip("-*[]").strip().strip(",").strip("'\"")
        if not line:
            continue
        for tok in re.split(r"[,\s]+", line):
            tok = tok.strip("#'\"").lower()
            if tok in vocab_set and tok not in picked:
                picked.append(tok)
        if len(picked) >= max_tags:
            break

    if not picked:
        console.print("[yellow]El modelo no devolvió tags del vocabulario.[/yellow]")
        console.print(f"[dim]Respuesta raw: {answer[:200]}[/dim]")
        return

    merged = list(dict.fromkeys([*current_tags, *picked]))[:max_tags]
    new_tags = [t for t in picked if t not in current_tags]

    console.print(f"[bold cyan]Nota:[/bold cyan] {path}")
    console.print(f"[dim]Tags actuales:[/dim] {current_tags or '—'}")
    console.print(f"[bold green]Sugeridos:[/bold green] {picked}")
    console.print(f"[bold]Nuevos a añadir:[/bold] {new_tags or '—'}")

    if not apply or not new_tags:
        return

    # Rewrite frontmatter with merged tag list.
    if raw.startswith("---\n"):
        end = raw.find("\n---\n", 4)
        if end < 0:
            console.print("[red]Frontmatter mal formado, no se modifica.[/red]")
            return
        fm_text = raw[4:end]
        rest = raw[end + 5:]
        # Replace or insert tags: key — yaml.safe_dump-ish but we want to
        # preserve the rest of the frontmatter verbatim.
        new_fm_lines: list[str] = []
        in_tag_block = False
        for line in fm_text.splitlines():
            if in_tag_block and re.match(r"^\s*-\s+", line):
                continue  # drop old tag items
            in_tag_block = False
            if re.match(r"^tags\s*:", line):
                in_tag_block = True
                continue
            new_fm_lines.append(line)
        new_fm_lines.append("tags:")
        for t in merged:
            new_fm_lines.append(f"- {t}")
        new_raw = "---\n" + "\n".join(new_fm_lines) + "\n---\n" + rest
    else:
        # No frontmatter — prepend one.
        fm_block = "---\ntags:\n" + "\n".join(f"- {t}" for t in merged) + "\n---\n\n"
        new_raw = fm_block + raw

    note_path.write_text(new_raw, encoding="utf-8")
    console.print("[green]✓ Frontmatter actualizado.[/green]")
    _index_single_file(col, note_path)


@cli.command()
@click.option("--threshold", default=CONFIDENCE_RERANK_MIN,
              help=f"Queries con top_score ≤ este umbral se consideran 'gap' (default: {CONFIDENCE_RERANK_MIN})")
@click.option("--min-count", default=2, help="Queries mínimas por cluster para reportar")
@click.option("--days", default=60, help="Ventana de log a analizar (default: 60)")
def gaps(threshold: float, min_count: int, days: int):
    """Detectar temas consultados repetidamente sin respuesta en el vault.

    Agrupa queries low-confidence del log (confidence ≤ threshold) por
    similaridad de embedding. Cada cluster con ≥min-count apariciones es un
    candidato a nota nueva.
    """
    if not LOG_PATH.is_file():
        console.print("[yellow]No hay log todavía.[/yellow]")
        return
    from datetime import timedelta as _td
    cutoff = datetime.now() - _td(days=days)

    entries = []
    for line in LOG_PATH.read_text(encoding="utf-8").splitlines():
        if not line.strip():
            continue
        try:
            e = json.loads(line)
        except Exception:
            continue
        score = e.get("top_score")
        if score is None or score > threshold:
            continue
        try:
            ts = datetime.fromisoformat(e.get("ts", ""))
        except Exception:
            continue
        if ts < cutoff:
            continue
        q = e.get("q", "").strip()
        if q:
            entries.append({"q": q, "ts": ts, "score": score})

    if not entries:
        console.print("[green]No hay gaps persistentes en la ventana analizada.[/green]")
        return

    # Dedupe near-identical queries by lowercase stem, then cluster by
    # embedding similarity (cheap — N low-conf queries is small).
    queries_unique: list[str] = []
    query_counts: dict[str, int] = {}
    for e in entries:
        key = " ".join(_tokenize(e["q"]))
        if key not in query_counts:
            queries_unique.append(e["q"])
            query_counts[key] = 0
        query_counts[key] += 1

    if len(queries_unique) == 1:
        q = queries_unique[0]
        count = list(query_counts.values())[0]
        if count >= min_count:
            console.print(
                f"[yellow]Gap:[/yellow] [bold]{q}[/bold] "
                f"[dim](×{count})[/dim]"
            )
            console.print("[dim]Sugerencia: creá una nota sobre este tema.[/dim]")
        return

    # Cluster by cosine similarity on embeddings.
    embeddings = embed(queries_unique)
    clusters: list[list[int]] = []
    assigned = [False] * len(queries_unique)
    for i in range(len(queries_unique)):
        if assigned[i]:
            continue
        group = [i]
        assigned[i] = True
        for j in range(i + 1, len(queries_unique)):
            if assigned[j]:
                continue
            if cosine_sim(embeddings[i], embeddings[j]) >= 0.75:
                group.append(j)
                assigned[j] = True
        clusters.append(group)

    # Rank clusters by total query count.
    cluster_rows: list[tuple[int, list[str]]] = []
    for group in clusters:
        total = sum(
            query_counts.get(" ".join(_tokenize(queries_unique[idx])), 0)
            for idx in group
        )
        if total < min_count:
            continue
        sample = [queries_unique[idx] for idx in group]
        cluster_rows.append((total, sample))
    cluster_rows.sort(key=lambda x: -x[0])

    if not cluster_rows:
        console.print("[green]No hay gaps persistentes (todos los grupos < min-count).[/green]")
        return

    console.print(
        f"[bold yellow]Gaps detectados[/bold yellow] "
        f"[dim]({len(cluster_rows)} cluster(s), últimos {days} días)[/dim]"
    )
    console.print()
    for total, samples in cluster_rows:
        console.print(f"  [bold magenta]×{total}[/bold magenta]  {samples[0]}")
        for s in samples[1:4]:
            console.print(f"         [dim]· {s}[/dim]")
        if len(samples) > 4:
            console.print(f"         [dim]· … {len(samples) - 4} variantes más[/dim]")
        console.print()
    console.print(
        "[dim]Cada cluster es un tema que consultaste sin encontrar respuesta — "
        "candidato a una nota nueva.[/dim]"
    )


@cli.command()
@click.argument("query", required=False)
@click.option("--tag", default=None, help="Filtrar por tag")
@click.option("--folder", default=None, help="Filtrar por carpeta")
@click.option("--limit", default=30, help="Cantidad de notas a mostrar")
def timeline(query: str | None, tag: str | None, folder: str | None, limit: int):
    """Ver notas ordenadas por fecha de modificación (más recientes primero).

    Opcionalmente filtrable por tag, carpeta o query semántica. Usa
    frontmatter `modified` — si falta, cae a `created`.
    """
    col = get_db()
    c = _load_corpus(col)
    if query:
        # Rank by semantic similarity first, then show with dates.
        result = retrieve(
            col, query, limit, folder, tag=tag,
            precise=False, multi_query=True, auto_filter=False,
        )
        files = []
        seen = set()
        for m in result["metas"]:
            f = m.get("file", "")
            if f in seen or is_excluded(f):
                continue
            seen.add(f)
            files.append(m)
    else:
        files = _filter_files(c["metas"], tag, folder)

    files.sort(
        key=lambda m: m.get("modified") or m.get("created") or "",
        reverse=True,
    )
    files = files[:limit]

    if not files:
        console.print("[yellow]Sin resultados.[/yellow]")
        return

    tbl = Table(show_header=False, box=None, pad_edge=False, padding=(0, 1))
    tbl.add_column(style="dim")            # date
    tbl.add_column(style="bold magenta")   # title
    tbl.add_column(style="cyan dim")       # path
    for m in files:
        stamp = (m.get("modified") or m.get("created") or "")[:10]
        tbl.add_row(stamp or "—", m.get("note", ""), m.get("file", ""))
    console.print(tbl)


@cli.command()
@click.argument("note_title")
@click.option("--depth", default=1, help="Niveles de vecindad (1 = solo vecinos directos, 2 = vecinos de vecinos)")
@click.option("--output", default=None, help="Ruta .canvas de salida (default: 00-Inbox/graph-{note}.canvas)")
def graph(note_title: str, depth: int, output: str | None):
    """Exportar un Obsidian canvas con la vecindad de una nota por wikilinks.

    NOTE_TITLE: título exacto (file stem) de la nota semilla. Atravesa outlinks
    y backlinks hasta `--depth`. El canvas resultante puede abrirse en
    Obsidian para ver el clúster conceptual.
    """
    import json as _json
    col = get_db()
    c = _load_corpus(col)

    # Resolver título → primer path (Obsidian permite múltiples notas con mismo
    # stem; tomamos el primero no-excluido).
    paths = [p for p in c["title_to_paths"].get(note_title, set()) if not is_excluded(p)]
    if not paths:
        console.print(f"[red]Nota no encontrada en el índice:[/red] {note_title}")
        return
    seed_path = sorted(paths)[0]

    # BFS outlinks + backlinks
    visited: dict[str, int] = {seed_path: 0}
    edges: set[tuple[str, str]] = set()
    frontier = [seed_path]
    for hop in range(1, depth + 1):
        next_frontier: list[str] = []
        for p in frontier:
            # outlinks
            for target_title in c["outlinks"].get(p, []):
                for tp in c["title_to_paths"].get(target_title, set()):
                    if is_excluded(tp):
                        continue
                    edges.add((p, tp))
                    if tp not in visited:
                        visited[tp] = hop
                        next_frontier.append(tp)
            # backlinks — notes that link to the current node's TITLE
            title = _path_to_title(c, p)
            if title:
                for linker in c["backlinks"].get(title, set()):
                    if is_excluded(linker):
                        continue
                    edges.add((linker, p))
                    if linker not in visited:
                        visited[linker] = hop
                        next_frontier.append(linker)
        frontier = next_frontier
        if not frontier:
            break

    # Build Obsidian canvas JSON (file nodes + edges)
    nodes, canvas_edges = [], []
    path_to_id: dict[str, str] = {}
    for i, (p, hop) in enumerate(sorted(visited.items(), key=lambda kv: (kv[1], kv[0]))):
        node_id = f"n{i}"
        path_to_id[p] = node_id
        # Radial layout: seed at center, rings per hop
        import math
        if hop == 0:
            x, y = 0, 0
        else:
            ring_members = [q for q, h in visited.items() if h == hop]
            idx = ring_members.index(p)
            n = len(ring_members)
            r = hop * 600
            angle = 2 * math.pi * idx / max(1, n)
            x, y = int(r * math.cos(angle)), int(r * math.sin(angle))
        nodes.append({
            "id": node_id,
            "type": "file",
            "file": p,
            "x": x, "y": y,
            "width": 320, "height": 160,
        })
    for i, (a, b) in enumerate(sorted(edges)):
        if a in path_to_id and b in path_to_id:
            canvas_edges.append({
                "id": f"e{i}",
                "fromNode": path_to_id[a], "fromSide": "right",
                "toNode": path_to_id[b], "toSide": "left",
            })

    canvas = {"nodes": nodes, "edges": canvas_edges}

    if output:
        out_path = Path(output)
        if not out_path.is_absolute():
            out_path = VAULT_PATH / output
    else:
        safe = re.sub(r"[/\\:\n]", " ", note_title).strip()
        out_path = VAULT_PATH / INBOX_FOLDER / f"graph-{safe}.canvas"
    out_path.parent.mkdir(parents=True, exist_ok=True)
    out_path.write_text(_json.dumps(canvas, ensure_ascii=False, indent=2), encoding="utf-8")

    rel = out_path.relative_to(VAULT_PATH) if str(out_path).startswith(str(VAULT_PATH)) else out_path
    console.print(
        f"[green]✓ Canvas generado:[/green] [bold cyan]{rel}[/bold cyan] "
        f"[dim]({len(nodes)} nodos, {len(canvas_edges)} aristas, depth={depth})[/dim]"
    )


# ── Weekly narrative digest (Contradiction Radar phase 3) ─────────────────────

def _iso_week_label(dt: datetime) -> str:
    y, w, _ = dt.isocalendar()
    return f"{y}-W{w:02d}"


def _parse_iso_week(week: str) -> tuple[datetime, datetime]:
    """Parse 'YYYY-WNN' to [Monday 00:00, next Monday 00:00) local time."""
    from datetime import timedelta as _td
    m = re.match(r"^(\d{4})-W(\d{1,2})$", week.strip())
    if not m:
        raise click.BadParameter(
            f"Formato inválido: {week!r} (esperado YYYY-WNN, ej. 2026-W15)"
        )
    year, wk = int(m.group(1)), int(m.group(2))
    monday = datetime.strptime(f"{year}-W{wk:02d}-1", "%G-W%V-%u")
    return monday, monday + _td(days=7)


def _collect_week_evidence(
    start: datetime,
    end: datetime,
    vault: Path,
    query_log: Path,
    contradiction_log: Path,
) -> dict:
    """Gather evidence for the weekly digest from three sources.

    Returns dict with keys:
      - recent_notes: vault files modified in [start, end)
      - fm_contradictions: notes whose YAML has `contradicts: [paths]` (snapshot)
      - index_contradictions: sidecar log entries in [start, end) with ≥1 contradict
      - query_contradictions: queries.jsonl entries in window with contradictions
      - low_conf_queries: queries in window with top_score <= CONFIDENCE_RERANK_MIN
    """
    recent: list[dict] = []
    fm_contrad: list[dict] = []
    if vault.is_dir():
        for p in vault.rglob("*.md"):
            try:
                rel = str(p.relative_to(vault))
            except ValueError:
                continue
            if is_excluded(rel):
                continue
            try:
                mtime = datetime.fromtimestamp(p.stat().st_mtime)
            except OSError:
                continue
            try:
                raw = p.read_text(encoding="utf-8", errors="ignore")
            except OSError:
                continue
            fm = parse_frontmatter(raw)
            contradicts = fm.get("contradicts") or []
            if isinstance(contradicts, list) and contradicts:
                targets = [str(t) for t in contradicts if t]
                if targets:
                    fm_contrad.append({"path": rel, "targets": targets})
            if start <= mtime < end:
                snippet = clean_md(raw)[:300].strip()
                recent.append({
                    "path": rel,
                    "title": p.stem,
                    "modified": mtime.isoformat(timespec="seconds"),
                    "snippet": snippet,
                })
    recent.sort(key=lambda r: r["modified"], reverse=True)

    def _read_jsonl_in_window(path: Path) -> list[dict]:
        if not path.is_file():
            return []
        out: list[dict] = []
        try:
            lines = path.read_text(encoding="utf-8").splitlines()
        except OSError:
            return []
        for line in lines:
            line = line.strip()
            if not line:
                continue
            try:
                e = json.loads(line)
            except Exception:
                continue
            try:
                ts = datetime.fromisoformat(e.get("ts", ""))
            except Exception:
                continue
            if start <= ts < end:
                out.append(e)
        return out

    # Audit 2026-04-26 (BUG #12): pre-fix leía dos JSONLs stale post-T10:
    # `contradiction_log` ya no se escribe (Phase 2 → SQL `rag_contradictions`)
    # y `query_log` recibe `conversation_turn_written` events, no `cmd=query`.
    # Las 3 secciones del digest (index_contrad, query_contrad, low_conf)
    # quedaban siempre vacías. Fix: leer SQL directamente.
    start_iso = start.isoformat(timespec="seconds")
    end_iso = end.isoformat(timespec="seconds")
    index_contrad: list[dict] = []
    try:
        with _ragvec_state_conn() as _conn:
            for ts_str, subj, targets_json in _conn.execute(
                "SELECT ts, subject_path, contradicts_json FROM rag_contradictions "
                "WHERE ts >= ? AND ts < ?",
                (start_iso, end_iso),
            ):
                try:
                    targets = json.loads(targets_json) if targets_json else []
                except Exception:
                    continue
                if not isinstance(targets, list) or not targets:
                    continue
                index_contrad.append({
                    "ts": ts_str,
                    "subject_path": subj or "",
                    "targets": [
                        {"path": c.get("path", ""), "why": c.get("why", "")}
                        for c in targets if isinstance(c, dict)
                    ],
                })
    except Exception as _exc:
        try:
            _silent_log("week_evidence_contradictions_sql_failed", _exc)
        except Exception:
            pass

    query_contrad: list[dict] = []
    low_conf: list[dict] = []
    try:
        with _ragvec_state_conn() as _conn:
            for ts_str, q_text, top_score, extra_json in _conn.execute(
                "SELECT ts, q, top_score, extra_json FROM rag_queries "
                "WHERE ts >= ? AND ts < ? AND cmd = 'query'",
                (start_iso, end_iso),
            ):
                try:
                    extra = json.loads(extra_json) if extra_json else {}
                except Exception:
                    extra = {}
                contrad = extra.get("contradictions") if isinstance(extra, dict) else None
                if isinstance(contrad, list) and contrad:
                    for c in contrad:
                        if isinstance(c, dict) and c.get("path"):
                            query_contrad.append({
                                "ts": ts_str,
                                "q": q_text or "",
                                "path": c.get("path", ""),
                                "why": c.get("why", ""),
                            })
                if isinstance(top_score, (int, float)) and top_score <= CONFIDENCE_RERANK_MIN:
                    q_clean = (q_text or "").strip()
                    if q_clean:
                        low_conf.append({
                            "ts": ts_str,
                            "q": q_clean,
                            "top_score": float(top_score),
                        })
    except Exception as _exc:
        try:
            _silent_log("week_evidence_queries_sql_failed", _exc)
        except Exception:
            pass

    return {
        "recent_notes": recent,
        "fm_contradictions": fm_contrad,
        "index_contradictions": index_contrad,
        "query_contradictions": query_contrad,
        "low_conf_queries": low_conf,
    }


def _render_digest_prompt(week_label: str, ev: dict) -> str:
    parts: list[str] = [
        f"Contexto del vault para la semana {week_label}.",
        "",
    ]
    if ev["recent_notes"]:
        parts.append("Notas creadas/modificadas esta semana:")
        for n in ev["recent_notes"][:40]:
            snippet = n["snippet"].replace("\n", " ")
            parts.append(f"- [[{n['title']}]] ({n['path']}) — {snippet}")
        parts.append("")
    if ev["index_contradictions"]:
        parts.append("Contradicciones flaggeadas al indexar (fase 2):")
        for ic in ev["index_contradictions"][:40]:
            for t in ic["targets"]:
                parts.append(
                    f"- {ic['subject_path']} vs {t['path']} — {t['why']}"
                )
        parts.append("")
    if ev["fm_contradictions"]:
        parts.append(
            "Estado actual de `contradicts:` en frontmatter (snapshot del vault):"
        )
        for fc in ev["fm_contradictions"][:40]:
            parts.append(f"- {fc['path']} → {', '.join(fc['targets'])}")
        parts.append("")
    if ev["query_contradictions"]:
        parts.append("Contradicciones detectadas al responder queries (fase 1):")
        for qc in ev["query_contradictions"][:40]:
            parts.append(
                f"- pregunta {qc['q']!r} → {qc['path']}: {qc['why']}"
            )
        parts.append("")
    if ev["low_conf_queries"]:
        parts.append("Queries con baja confianza (posibles gaps persistentes):")
        for lq in ev["low_conf_queries"][:30]:
            parts.append(f"- {lq['q']!r} (top_score={lq['top_score']:.3f})")
        parts.append("")
    parts.append(
        "Tarea: armá un review en primera persona de qué pasó en mi vault "
        "esta semana: qué conceptos nuevos emergieron, qué posiciones se "
        "movieron vs posiciones previas, qué tensiones se revelaron, qué "
        "gaps persistentes aparecieron. Prosa narrativa, no bullets. "
        "400-600 palabras. Citá notas con [[wikilinks]] de Obsidian. Si "
        "alguno de los contextos está vacío, obvialo sin mencionarlo "
        "explícitamente."
    )
    return "\n".join(parts)


def _generate_digest_narrative(prompt: str) -> str:
    resp = _chat_capped_client().chat(
        model=resolve_chat_model(),
        messages=[{"role": "user", "content": prompt}],
        options=CHAT_OPTIONS,
        keep_alive=chat_keep_alive(),
    )
    # 2026-04-29: filter PT→ES post-gen — el digest semanal se guarda en
    # `04-Archive/99-obsidian-system/99-AI/reviews/` y se le pushea al
    # user. El prompt inline (línea 32400+) no incluye `language_es_AR.v1`
    # por ahora; el filter es safety net.
    from rag.iberian_leak_filter import replace_iberian_leaks
    return replace_iberian_leaks((resp.message.content or "").strip())


DIGEST_FOLDER = "04-Archive/99-obsidian-system/99-AI/reviews"


@cli.command()
@click.option("--week", "week_opt", default=None,
              help="Semana ISO YYYY-WNN (default: la semana que termina hoy)")
@click.option("--days", default=7, show_default=True,
              help="Ventana en días (ignorado si se pasa --week)")
@click.option("--dry-run", is_flag=True,
              help="No escribas ni indexes — mostrá el output")
def digest(week_opt: str | None, days: int, dry_run: bool):
    """Weekly narrative digest del vault (Contradiction Radar fase 3).

    Consume notas modificadas, frontmatter `contradicts:`, el sidecar log
    de contradicciones index-time, las contradicciones query-time y las
    queries low-confidence. Genera prosa narrativa con command-r y la
    guarda en `04-Archive/99-obsidian-system/99-AI/reviews/YYYY-WNN.md` (auto-indexado).
    """
    from datetime import timedelta as _td
    if week_opt:
        try:
            start, end = _parse_iso_week(week_opt)
        except click.BadParameter as e:
            console.print(f"[red]{e.message}[/red]")
            return
        week_label = week_opt
    else:
        end = datetime.now()
        start = end - _td(days=days)
        week_label = _iso_week_label(end)

    ev = _collect_week_evidence(
        start, end, VAULT_PATH, LOG_PATH, CONTRADICTION_LOG_PATH,
    )

    total_signals = (
        len(ev["recent_notes"]) + len(ev["fm_contradictions"])
        + len(ev["index_contradictions"])
        + len(ev["query_contradictions"]) + len(ev["low_conf_queries"])
    )
    if total_signals == 0:
        console.print(
            f"[yellow]Sin evidencia para {week_label}: "
            "0 notas modificadas, 0 contradicciones, 0 queries low-confidence."
            "[/yellow]"
        )
        return

    console.print(
        f"[dim]Evidencia {week_label}:[/dim] "
        f"{len(ev['recent_notes'])} notas · "
        f"{len(ev['index_contradictions'])} contradicciones index · "
        f"{len(ev['fm_contradictions'])} frontmatter · "
        f"{len(ev['query_contradictions'])} query · "
        f"{len(ev['low_conf_queries'])} low-conf"
    )

    prompt = _render_digest_prompt(week_label, ev)
    with console.status(
        "[dim]Generando narrativa con command-r…[/dim]", spinner="dots"
    ):
        narrative = _generate_digest_narrative(prompt)

    if not narrative:
        console.print("[red]El modelo devolvió respuesta vacía. Abortando.[/red]")
        return

    now = datetime.now().isoformat(timespec="seconds")
    fm_lines = [
        "---",
        f"created: '{now}'",
        f"modified: '{now}'",
        "tags:",
        "- review",
        "- weekly-digest",
        f"week: '{week_label}'",
        "---",
    ]
    body = (
        "\n".join(fm_lines)
        + f"\n\n# Review {week_label}\n\n{narrative.strip()}\n"
    )

    if dry_run:
        console.rule(f"[bold]Digest {week_label} (dry-run)[/bold]")
        console.print(body, markup=False, highlight=False)
        return

    path = VAULT_PATH / DIGEST_FOLDER / f"{week_label}.md"
    path.parent.mkdir(parents=True, exist_ok=True)
    if path.exists():
        path = path.with_name(
            f"{week_label} ({datetime.now().strftime('%H%M%S')}).md"
        )
    path.write_text(body, encoding="utf-8")

    try:
        col = get_db()
        _index_single_file(col, path)
    except Exception as e:
        console.print(
            f"[yellow]Nota escrita pero auto-index falló: {e}[/yellow]"
        )

    try:
        rel = path.relative_to(VAULT_PATH)
    except ValueError:
        rel = path
    console.print(
        f"[green]✓ Digest guardado:[/green] [bold cyan]{rel}[/bold cyan]"
    )
    if _brief_push_to_whatsapp(f"Digest {week_label}", str(rel), narrative):
        console.print("[dim]→ enviado a WhatsApp[/dim]")


def _path_to_title(corpus: dict, path: str) -> str | None:
    rev = corpus.get("_path_to_title_rev")
    if rev is None:
        rev = {}
        for title, paths in corpus["title_to_paths"].items():
            for p in paths:
                rev[p] = title
        corpus["_path_to_title_rev"] = rev
    return rev.get(path)


def _render_silent_errors_log(n: int, summary: bool) -> None:
    """Pretty-print the tail of silent_errors.jsonl.

    Lines are schema {ts, where, exc_type, exc}. Malformed lines are
    dropped silently — this is a diagnostic surface, not a parser.

    Two modes:
      - list (default): last N entries, newest at the bottom.
      - summary (--summary flag): aggregate by (where × exc_type), sort
        by count desc. Surfaces which subsystems fail most often without
        forcing the user to eyeball dozens of near-identical lines.
    """
    if not SILENT_ERRORS_LOG_PATH.is_file():
        console.print(
            f"[dim]No hay silent_errors.jsonl aún ({SILENT_ERRORS_LOG_PATH}).[/dim]\n"
            "[dim]Se escribe sólo cuando un `except Exception: pass` migrado falla; "
            "vacío = bueno.[/dim]"
        )
        return
    entries: list[dict] = []
    for line in SILENT_ERRORS_LOG_PATH.read_text(encoding="utf-8").splitlines():
        line = line.strip()
        if not line:
            continue
        try:
            entries.append(json.loads(line))
        except Exception:
            continue
    if not entries:
        console.print("[dim]silent_errors.jsonl está vacío — nada que reportar.[/dim]")
        return

    if summary:
        from collections import Counter
        counter: Counter[tuple[str, str]] = Counter()
        for e in entries:
            counter[(e.get("where", "?"), e.get("exc_type", "?"))] += 1
        tbl = Table(
            title=f"Silent errors · {len(entries)} total · top (where × exc_type)",
            show_lines=False,
        )
        tbl.add_column("count", justify="right", style="yellow")
        tbl.add_column("where", style="cyan", overflow="fold", max_width=50)
        tbl.add_column("exc_type", style="red")
        for (where, exc_type), cnt in counter.most_common(n):
            tbl.add_row(str(cnt), where, exc_type)
        console.print(tbl)
        return

    tail = entries[-n:]
    tbl = Table(
        title=f"Últimos {len(tail)} silent errors ({SILENT_ERRORS_LOG_PATH.name})",
        show_lines=False,
    )
    tbl.add_column("ts", style="dim", no_wrap=True)
    tbl.add_column("where", style="cyan", overflow="fold", max_width=32)
    tbl.add_column("exc_type", style="red", no_wrap=True)
    tbl.add_column("exc", style="yellow", overflow="fold", max_width=60)
    for e in tail:
        tbl.add_row(
            (e.get("ts") or "")[-8:],
            e.get("where") or "?",
            e.get("exc_type") or "?",
            (e.get("exc") or "").replace("\n", " ")[:200],
        )
    console.print(tbl)


@cli.command()
@click.option("-n", default=20, help="Cantidad de queries a mostrar (default: 20)")
@click.option("--low-confidence", is_flag=True, help="Solo queries con top_score < 0")
@click.option("--feedback", "with_feedback", is_flag=True,
              help="Solo turnos con rating (👍/👎), con una columna de feedback")
@click.option("--slow", is_flag=True,
              help="Feature #13: solo queries 'slow' — total latency > --slower-than ms "
                   "(default 5000). Ordenadas por total DESC.")
@click.option("--slower-than", "slower_than_ms", default=5000, show_default=True,
              help="Umbral en ms de total latency (retrieve+gen) para --slow.")
@click.option("--silent-errors", "silent_errors", is_flag=True,
              help="Listar silent_errors.jsonl (writes del _silent_log helper) en vez del queries log")
@click.option("--summary", is_flag=True,
              help="Con --silent-errors, agrupa por (where × exc_type) en vez de listar individualmente")
def log(n: int, low_confidence: bool, with_feedback: bool,
        slow: bool, slower_than_ms: int,
        silent_errors: bool, summary: bool):
    """Inspeccionar el log de queries (últimas N).

    Con --silent-errors, lee silent_errors.jsonl y muestra las últimas N
    excepciones que pasaron por `_silent_log(where, exc)`. Útil para
    detectar subsistemas que fallan calladamente (context_cache corrupto,
    feedback_golden_embed offline, contradict JSON parse). Agregar
    --summary agrupa por (where × exc_type) para ver patrones.

    --slow filtra queries cuyo total latency (retrieve+gen) supera
    --slower-than ms (default 5000) — útil para identificar outliers
    y detectar regresiones de perf. Ordena por total DESC para mostrar
    los peores casos primero.

    Post-T10 (2026-04-19) lee de `rag_queries` SQL — el archivo JSONL
    `queries.jsonl` ahora recibe eventos de otro stream (conversation
    writer observability) y los campos no coinciden, por lo que el
    renderer histórico dibujaba filas vacías.
    """
    if silent_errors:
        _render_silent_errors_log(n, summary)
        return

    # SQL read replaces the pre-T10 JSONL tail. Pulls enough rows to
    # satisfy an eventual `--feedback` post-filter without extra
    # round-trips: fetch N when feedback isn't active, 5*N otherwise
    # (heuristic — feedback rows are rare, so 5x overprovisioning covers
    # typical usage without dragging the whole table).
    # --slow needs a bigger pool to find outliers — fetch 20x N.
    fetch_n = n * 20 if slow else (n * 5 if with_feedback else n)
    entries = _read_queries_for_log(fetch_n, low_confidence=low_confidence)

    # Feedback annotations: always load so the renderer can paint the
    # thumb column when any feedback exists, even without --feedback.
    fb_by_turn = _read_feedback_map_for_log()

    if with_feedback:
        entries = [e for e in entries if e.get("turn_id") in fb_by_turn]
        # Trim to N now that the filter narrowed the set.
        entries = entries[-n:]

    if slow:
        # Compute total latency (retrieve + gen) and filter/sort.
        def _total_ms(e: dict) -> float:
            return float(e.get("t_retrieve") or 0) + float(e.get("t_gen") or 0)
        entries = [e for e in entries if _total_ms(e) > slower_than_ms]
        entries.sort(key=_total_ms, reverse=True)
        entries = entries[:n]
    title = (
        f"Queries más lentas ({len(entries)}, >{slower_than_ms}ms)"
        if slow
        else f"Últimas {len(entries)} queries"
    )
    tbl = Table(title=title, show_lines=False)
    tbl.add_column("ts", style="dim")
    tbl.add_column("query", style="cyan", overflow="fold", max_width=45)
    tbl.add_column("score", justify="right")
    if with_feedback or fb_by_turn:
        tbl.add_column("fb", justify="center")
    tbl.add_column("retr", justify="right")
    tbl.add_column("gen", justify="right")
    tbl.add_column("mode", style="dim")
    for e in entries:
        score = e.get("top_score")
        score_str = f"{score:+.1f}" if isinstance(score, (int, float)) else "-"
        score_style = "green" if (score or 0) >= 3 else ("yellow" if (score or 0) >= 0 else "red")
        row = [
            (e.get("ts") or "")[-8:],
            e.get("q") or "",
            f"[{score_style}]{score_str}[/{score_style}]",
        ]
        if with_feedback or fb_by_turn:
            rating = fb_by_turn.get(e.get("turn_id", "") or "_none_")
            if rating is None:
                row.append("[dim]·[/dim]")
            elif rating > 0:
                row.append("[green]👍[/green]")
            else:
                row.append("[red]👎[/red]")
        # NULL-safe: SQL rows return None for unset numeric fields (metachat
        # / create-intent turns never populate t_retrieve/t_gen). `.get(k, 0)`
        # returns None when the KEY IS PRESENT with a None value — the
        # default only fires on absent keys. Coerce explicitly.
        t_retrieve = e.get("t_retrieve") or 0.0
        t_gen = e.get("t_gen") or 0.0
        row.extend([
            f"{t_retrieve:.1f}",
            f"{t_gen:.1f}",
            e.get("mode") or "",
        ])
        tbl.add_row(*row)
    console.print(tbl)


# ── INSIGHTS ──────────────────────────────────────────────────────────────────
# Feedback loop desde queries.jsonl. Tres detectores output-only — el sistema
# se vuelve auto-observable sin tocar el vault. Invocá `rag insights` semanal o
# bajo demanda; la CLI surface los patrones, vos decidís qué acción tomar.
#
#   1. gaps     → queries low-confidence recurrentes ("escribí una nota")
#   2. hots     → queries repetidas con buena respuesta ("promové a nota estable")
#   3. orphans  → notas del vault nunca retrieved en la ventana ("archivá o relinká")
#
# Complementa `rag dead`: esa usa outlinks+backlinks (señal estructural),
# insights usa usage real (señal de demanda). Overlap esperado pero no total.

INSIGHTS_GAP_THRESHOLD = CONFIDENCE_RERANK_MIN
INSIGHTS_GAP_MIN_OCCURRENCES = 2
INSIGHTS_HOT_MIN_OCCURRENCES = 3
INSIGHTS_DEFAULT_WINDOW_DAYS = 30
INSIGHTS_ORPHAN_EXCLUDED_PREFIXES = ("00-Inbox/", "04-Archive/")


def _normalize_query_for_grouping(q: str) -> str:
    """Lowercase + strip accents + drop punctuation + collapse whitespace.

    Agrupa "¿Qué es RAG?" con "que es rag" — el user no tipea consistente,
    especialmente al dictar por voz. Accent-strip via NFKD + ASCII ignore.
    """
    s = unicodedata.normalize("NFKD", q or "").encode("ascii", "ignore").decode("ascii")
    s = re.sub(r"[^\w\s]", " ", s.lower())
    return re.sub(r"\s+", " ", s).strip()


def _load_query_entries(since: datetime, log_path: Path = LOG_PATH) -> list[dict]:
    """Entries with parseable ts ≥ since. Silently drops malformed lines — the
    log is append-only and a single bad line shouldn't poison the run."""
    if not log_path.is_file():
        return []
    out: list[dict] = []
    for line in log_path.read_text(encoding="utf-8").splitlines():
        line = line.strip()
        if not line:
            continue
        try:
            e = json.loads(line)
        except Exception:
            continue
        try:
            ts = datetime.fromisoformat(e.get("ts", ""))
        except Exception:
            continue
        if ts < since:
            continue
        out.append(e)
    return out


def detect_gap_queries(
    entries: list[dict],
    threshold: float = INSIGHTS_GAP_THRESHOLD,
    min_occurrences: int = INSIGHTS_GAP_MIN_OCCURRENCES,
) -> list[dict]:
    """Low-confidence queries asked min_occurrences+ times.

    A "gap" = el user repite una pregunta que el reranker no está resolviendo.
    Señal fuerte de que falta una nota. Agrupa por query normalizada y reporta
    count, max_score (lo más cerca que estuvimos), últimos timestamps.
    """
    groups: dict[str, dict] = {}
    for e in entries:
        if e.get("cmd") != "query":
            continue
        top = e.get("top_score")
        if not isinstance(top, (int, float)) or top > threshold:
            continue
        q = (e.get("q") or "").strip()
        key = _normalize_query_for_grouping(q)
        if not key:
            continue
        g = groups.setdefault(key, {
            "query": q, "count": 0, "max_score": top,
            "last_ts": e.get("ts", ""),
        })
        g["count"] += 1
        g["max_score"] = max(g["max_score"], top)
        if e.get("ts", "") > g["last_ts"]:
            g["last_ts"] = e.get("ts", "")
    return sorted(
        [g for g in groups.values() if g["count"] >= min_occurrences],
        key=lambda g: (-g["count"], -g["max_score"]),
    )


def detect_hot_queries(
    entries: list[dict],
    threshold: float = INSIGHTS_GAP_THRESHOLD,
    min_occurrences: int = INSIGHTS_HOT_MIN_OCCURRENCES,
) -> list[dict]:
    """Queries con top_score > threshold preguntadas min_occurrences+ veces.

    Distinto de gaps: acá el sistema responde bien pero el user sigue
    preguntando lo mismo. Señal de que la info existe pero no es fácil de
    recordar — candidata a promover (nota estable con título prominente,
    wikilinks desde un índice, etc.). Reporta top paths retrieved más veces
    para que vos sepas desde dónde promover.
    """
    groups: dict[str, dict] = {}
    for e in entries:
        if e.get("cmd") != "query":
            continue
        top = e.get("top_score")
        if not isinstance(top, (int, float)) or top <= threshold:
            continue
        q = (e.get("q") or "").strip()
        key = _normalize_query_for_grouping(q)
        if not key:
            continue
        g = groups.setdefault(key, {
            "query": q, "count": 0, "score_sum": 0.0,
            "last_ts": e.get("ts", ""), "_paths": {},
        })
        g["count"] += 1
        g["score_sum"] += top
        if e.get("ts", "") > g["last_ts"]:
            g["last_ts"] = e.get("ts", "")
        for p in (e.get("paths") or [])[:3]:
            if isinstance(p, str):
                g["_paths"][p] = g["_paths"].get(p, 0) + 1
    results: list[dict] = []
    for g in groups.values():
        if g["count"] < min_occurrences:
            continue
        top_paths = sorted(g["_paths"].items(), key=lambda kv: -kv[1])[:3]
        results.append({
            "query": g["query"], "count": g["count"],
            "avg_score": round(g["score_sum"] / g["count"], 3),
            "last_ts": g["last_ts"],
            "top_paths": [p for p, _ in top_paths],
        })
    return sorted(results, key=lambda g: -g["count"])


def detect_orphan_notes(
    entries: list[dict],
    vault_path: Path,
    excluded_prefixes: tuple[str, ...] = INSIGHTS_ORPHAN_EXCLUDED_PREFIXES,
) -> list[str]:
    """Vault .md files nunca mencionadas en `paths[]` de las entries dadas.

    Distinto de `rag dead` (señal estructural: 0 outlinks + 0 backlinks).
    Acá es señal de uso: la nota no apareció en ningún retrieve — podés
    haberle escrito links, pero nadie la encuentra en la práctica. Excluye
    Inbox (muy nueva), Reviews (auto-generada), Archive (cold intencional).
    """
    retrieved: set[str] = set()
    for e in entries:
        for p in e.get("paths") or []:
            if isinstance(p, str):
                retrieved.add(p)
    if not vault_path.is_dir():
        return []
    orphans: list[str] = []
    for md in vault_path.rglob("*.md"):
        try:
            rel = str(md.relative_to(vault_path))
        except ValueError:
            continue
        if is_excluded(rel):
            continue
        if any(rel.startswith(pre) for pre in excluded_prefixes):
            continue
        if rel in retrieved:
            continue
        orphans.append(rel)
    return sorted(orphans)


def telemetry_health(db_path: Path, days: int = 7, top_n: int = 10) -> dict:
    """Salud operativa de la telemetría en la ventana de N días.

    Devuelve:
      - intent_populated_pct: % de queries (filtradas por is_user_query) que
        exponen `intent` no-vacío en rag_queries.extra_json.
      - ctr_by_source: CTR Laplace-smoothed (clicks+1)/(impressions+10) por
        valor de rag_behavior.source. NULL/empty → bucket "unknown".
      - feedback_gaps: top-N queries con ≥2 repeticiones sin ningún rating
        en rag_feedback joineadas por turn_id (ambos lados limitados a la
        ventana). Ordenado por count desc.
      - corrective_paths_count: rows en rag_feedback con
        extra_json.corrective_path no-nulo y no-vacío (gatea GC#2.C
        re-training).
    Degradación graciosa: tablas faltantes o vacías → estructura con counts
    en 0 y listas vacías, sin excepciones.
    """
    import sqlite3 as _sqlite3
    cutoff = (datetime.now() - timedelta(days=days)).isoformat(timespec="seconds")
    intent_populated = 0
    intent_total = 0
    source_acc: dict[str, list[int]] = {}
    gaps: list[dict] = []
    corrective_paths_count = 0

    if not Path(db_path).exists():
        return {
            "window_days": days,
            "total_user_queries": 0,
            "intent_populated": 0,
            "intent_populated_pct": 0.0,
            "ctr_by_source": {},
            "feedback_gaps": [],
            "corrective_paths_count": 0,
        }

    conn = _sqlite3.connect(str(db_path))
    try:
        try:
            q_rows = conn.execute(
                "SELECT cmd, q, extra_json FROM rag_queries WHERE ts >= ?",
                (cutoff,),
            ).fetchall()
        except _sqlite3.Error:
            q_rows = []

        per_q: dict[str, dict] = {}
        for cmd, q, extra_json in q_rows:
            if not is_user_query(cmd, q):
                continue
            intent_total += 1
            intent_val: str | None = None
            turn_id: str | None = None
            if extra_json:
                try:
                    ej = json.loads(extra_json)
                except (ValueError, TypeError):
                    ej = None
                if isinstance(ej, dict):
                    raw = ej.get("intent")
                    if isinstance(raw, str) and raw.strip():
                        intent_val = raw.strip()
                    tid = ej.get("turn_id")
                    if isinstance(tid, str) and tid.strip():
                        turn_id = tid.strip()
            if intent_val:
                intent_populated += 1
            if q:
                norm = _normalize_query_for_grouping(q)
                if norm:
                    entry = per_q.setdefault(norm, {"q": q, "count": 0, "turn_ids": []})
                    entry["count"] += 1
                    if turn_id:
                        entry["turn_ids"].append(turn_id)

        try:
            b_rows = conn.execute(
                "SELECT source, event FROM rag_behavior WHERE ts >= ?",
                (cutoff,),
            ).fetchall()
        except _sqlite3.Error:
            b_rows = []
        for source, event in b_rows:
            key = source.strip() if isinstance(source, str) and source.strip() else "unknown"
            acc = source_acc.setdefault(key, [0, 0])
            acc[1] += 1
            if event in _BEHAVIOR_POSITIVE:
                acc[0] += 1

        try:
            rated_rows = conn.execute(
                "SELECT DISTINCT turn_id FROM rag_feedback "
                "WHERE ts >= ? AND turn_id IS NOT NULL AND turn_id != ''",
                (cutoff,),
            ).fetchall()
            rated_ids = {r[0] for r in rated_rows}
        except _sqlite3.Error:
            rated_ids = set()

        for entry in per_q.values():
            if entry["count"] < 2:
                continue
            if any(t in rated_ids for t in entry["turn_ids"]):
                continue
            gaps.append({"q": entry["q"], "count": entry["count"]})
        gaps.sort(key=lambda x: x["count"], reverse=True)
        gaps = gaps[:top_n]

        try:
            cp_row = conn.execute(
                "SELECT COUNT(*) FROM rag_feedback "
                "WHERE ts >= ? "
                "AND json_extract(extra_json, '$.corrective_path') IS NOT NULL "
                "AND json_extract(extra_json, '$.corrective_path') <> ''",
                (cutoff,),
            ).fetchone()
            corrective_paths_count = int(cp_row[0]) if cp_row else 0
        except _sqlite3.Error:
            corrective_paths_count = 0
    finally:
        conn.close()

    intent_pct = (intent_populated / intent_total * 100.0) if intent_total else 0.0
    ctr_by_source = {
        s: {
            "clicks": acc[0],
            "impressions": acc[1],
            "ctr": (acc[0] + 1) / (acc[1] + 10),
        }
        for s, acc in source_acc.items()
    }
    return {
        "window_days": days,
        "total_user_queries": intent_total,
        "intent_populated": intent_populated,
        "intent_populated_pct": round(intent_pct, 2),
        "ctr_by_source": ctr_by_source,
        "feedback_gaps": gaps,
        "corrective_paths_count": corrective_paths_count,
    }


@cli.group(invoke_without_command=True)
@click.option("--days", default=INSIGHTS_DEFAULT_WINDOW_DAYS, show_default=True,
              help="Ventana en días del log a analizar")
@click.option("--min-gap", default=INSIGHTS_GAP_MIN_OCCURRENCES, show_default=True,
              help="Mínimo de repeticiones para flaggear un gap")
@click.option("--min-hot", default=INSIGHTS_HOT_MIN_OCCURRENCES, show_default=True,
              help="Mínimo de repeticiones para flaggear una hot query")
@click.option("--json", "as_json", is_flag=True, help="Output JSON estructurado")
@click.option("--plain", is_flag=True, help="Output texto plano (bot-friendly)")
@click.pass_context
def insights(ctx: click.Context, days: int, min_gap: int, min_hot: int, as_json: bool, plain: bool):
    """Patrones en queries.jsonl: gaps, hot queries, notas huérfanas.

    Output-only — no escribe, no modifica vault, no llama al LLM. Surface los
    patrones y vos decidís qué acción tomar (escribir nota, archivar, etc.).
    """
    if ctx.invoked_subcommand is not None:
        return
    t0 = time.perf_counter()
    since = datetime.now() - timedelta(days=days)
    entries = _load_query_entries(since)
    gaps = detect_gap_queries(entries, min_occurrences=min_gap)
    hots = detect_hot_queries(entries, min_occurrences=min_hot)
    orphans = detect_orphan_notes(entries, VAULT_PATH)

    log_query_event({
        "cmd": "insights", "window_days": days,
        "n_entries": len(entries), "n_gaps": len(gaps),
        "n_hots": len(hots), "n_orphans": len(orphans),
        "timing": _round_timing_ms({"total_ms": (time.perf_counter() - t0) * 1000}),
    })

    if as_json:
        click.echo(json.dumps({
            "window_days": days,
            "entries_analyzed": len(entries),
            "gaps": gaps,
            "hot_queries": hots,
            "orphan_notes": orphans,
        }, ensure_ascii=False, indent=2))
        return

    if plain:
        lines = [f"Insights últimos {days}d · {len(entries)} queries analizadas"]
        if gaps:
            lines.append(f"\n🔴 {len(gaps)} gap(s) — escribí una nota:")
            for g in gaps[:10]:
                lines.append(f"  · ({g['count']}×) {g['query']}")
        if hots:
            lines.append(f"\n🟢 {len(hots)} hot(s) — promové a nota estable:")
            for h in hots[:10]:
                top = h["top_paths"][0] if h["top_paths"] else "-"
                lines.append(f"  · ({h['count']}×) {h['query']} → {top}")
        if orphans:
            lines.append(f"\n⚫ {len(orphans)} huérfana(s) — archivá o relinká:")
            for p in orphans[:10]:
                lines.append(f"  · {p}")
        if not (gaps or hots or orphans):
            lines.append("\nSin patrones detectados en la ventana.")
        click.echo("\n".join(lines))
        return

    console.print(Panel(
        f"Analizando últimos {days} día(s) · {len(entries)} queries",
        title="📊 Insights", style="cyan", border_style="cyan",
    ))
    console.print()

    if gaps:
        console.print(
            f"[bold red]🔴 {len(gaps)} gap(s)[/bold red] "
            "[dim]— queries sin respuesta en el vault, escribí una nota[/dim]"
        )
        tbl = Table(show_header=True, show_lines=False, box=None)
        tbl.add_column("×", justify="right", style="red")
        tbl.add_column("query", style="cyan", overflow="fold")
        tbl.add_column("max score", justify="right", style="dim")
        tbl.add_column("último", style="dim")
        for g in gaps[:20]:
            tbl.add_row(
                str(g["count"]), g["query"],
                f"{g['max_score']:.3f}", g["last_ts"][:10],
            )
        console.print(tbl)
        console.print()

    if hots:
        console.print(
            f"[bold green]🟢 {len(hots)} hot query(ies)[/bold green] "
            "[dim]— repetidas con buena respuesta, promové a nota estable[/dim]"
        )
        tbl = Table(show_header=True, show_lines=False, box=None)
        tbl.add_column("×", justify="right", style="green")
        tbl.add_column("query", style="cyan", overflow="fold")
        tbl.add_column("avg score", justify="right", style="dim")
        tbl.add_column("top path", style="dim", overflow="fold", max_width=44)
        for h in hots[:20]:
            top = h["top_paths"][0] if h["top_paths"] else "-"
            tbl.add_row(
                str(h["count"]), h["query"],
                f"{h['avg_score']:.3f}", top,
            )
        console.print(tbl)
        console.print()

    if orphans:
        console.print(
            f"[bold]⚫ {len(orphans)} nota(s) huérfana(s)[/bold] "
            "[dim]— nunca retrieved en la ventana, archivá o relinká[/dim]"
        )
        for p in orphans[:30]:
            console.print(f"  · [dim]{p}[/dim]")
        if len(orphans) > 30:
            console.print(f"  [dim]… {len(orphans) - 30} más[/dim]")
        console.print()

    if not (gaps or hots or orphans):
        console.print("[green]✓ sin patrones detectados en la ventana.[/green]")


@insights.command("telemetry-health")
@click.option("--days", default=7, show_default=True,
              help="Ventana en días sobre rag_queries/rag_behavior/rag_feedback")
@click.option("--json", "as_json", is_flag=True, help="Output JSON estructurado")
@click.option("--plain", is_flag=True, help="Output texto plano (bot-friendly)")
def insights_telemetry_health(days: int, as_json: bool, plain: bool):
    """Salud de la telemetría: intent coverage, CTR por source, feedback gaps."""
    report = telemetry_health(DB_PATH / _TELEMETRY_DB_FILENAME, days=days)

    if as_json:
        click.echo(json.dumps(report, ensure_ascii=False, indent=2))
        return

    if plain:
        lines = [
            f"Telemetry health · últimos {report['window_days']}d · "
            f"{report['total_user_queries']} user queries",
            f"intent populated: {report['intent_populated']}/"
            f"{report['total_user_queries']} ({report['intent_populated_pct']}%)",
        ]
        if report["ctr_by_source"]:
            lines.append("\nCTR por source (Laplace-smoothed):")
            for s, stats in sorted(report["ctr_by_source"].items()):
                lines.append(
                    f"  · {s}: {stats['clicks']}/{stats['impressions']} "
                    f"= {stats['ctr']:.3f}"
                )
        else:
            lines.append("\nCTR por source: sin eventos.")
        if report["feedback_gaps"]:
            lines.append("\nFeedback gaps (queries repetidas sin rating):")
            for g in report["feedback_gaps"]:
                lines.append(f"  · ({g['count']}×) {g['q']}")
        else:
            lines.append("\nFeedback gaps: ninguno.")
        lines.append(
            f"\nCorrective paths capturados: {report['corrective_paths_count']} "
            f"(último {report['window_days']}d)"
        )
        click.echo("\n".join(lines))
        return

    console.print(Panel(
        f"Telemetry health · últimos {report['window_days']}d · "
        f"{report['total_user_queries']} user queries",
        title="🩺 Telemetry", style="cyan", border_style="cyan",
    ))
    console.print(
        f"[bold]Intent coverage[/bold]: "
        f"{report['intent_populated']}/{report['total_user_queries']} "
        f"([green]{report['intent_populated_pct']}%[/green])"
    )
    console.print()

    if report["ctr_by_source"]:
        tbl = Table(title="CTR por source (Laplace)", show_header=True, box=None)
        tbl.add_column("source", style="cyan")
        tbl.add_column("clicks", justify="right", style="green")
        tbl.add_column("impressions", justify="right", style="dim")
        tbl.add_column("ctr", justify="right")
        for s, stats in sorted(report["ctr_by_source"].items()):
            tbl.add_row(s, str(stats["clicks"]), str(stats["impressions"]),
                        f"{stats['ctr']:.3f}")
        console.print(tbl)
        console.print()
    else:
        console.print("[dim]sin eventos en rag_behavior[/dim]")
        console.print()

    if report["feedback_gaps"]:
        tbl = Table(title="Feedback gaps (queries repetidas sin rating)",
                    show_header=True, box=None)
        tbl.add_column("×", justify="right", style="yellow")
        tbl.add_column("query", style="cyan", overflow="fold")
        for g in report["feedback_gaps"]:
            tbl.add_row(str(g["count"]), g["q"])
        console.print(tbl)
    else:
        console.print("[green]✓ sin feedback gaps en la ventana.[/green]")
    console.print()
    console.print(
        f"[bold]Corrective paths capturados[/bold]: "
        f"{report['corrective_paths_count']} "
        f"[dim](último {report['window_days']}d)[/dim]"
    )


# ── AGENT LOOP ────────────────────────────────────────────────────────────────

def _agent_tool_search(query: str, k: int = 5) -> str:
    """Buscar chunks relevantes en el vault de Obsidian.

    Args:
        query: Pregunta o tema a buscar, en lenguaje natural.
        k: Cantidad de chunks a devolver (default 5).

    Returns:
        JSON con lista de {note, path, score, content} de los chunks más
        relevantes, ordenados por score descendente.
    """
    col = get_db()
    result = retrieve(
        col, query, k, folder=None, tag=None,
        precise=False, multi_query=True, auto_filter=True,
    )
    out = [
        {
            "note": m.get("note", ""),
            "path": m.get("file", ""),
            "score": round(float(s), 3),
            "content": d[:1000],
        }
        for d, m, s in zip(result["docs"], result["metas"], result["scores"])
    ]
    return json.dumps(out, ensure_ascii=False)


def _agent_tool_read_note(path: str) -> str:
    """Leer contenido de una nota del vault, con fallback a project root
    para archivos especiales del proyecto (CLAUDE.md, AGENTS.md, README.md,
    docs/*.md). Bug 2026-04-28: el LLM hallucina cuando el path no existe
    en el vault. El fallback busca el archivo en el repo root antes de
    devolver error.

    Args:
        path: Ruta relativa al vault (ej. "02-Areas/Coaching/Ikigai.md") o
            archivo especial del project root (ej. "CLAUDE.md").

    Returns:
        Markdown completo de la nota, o mensaje de error si no existe en
        ningún lugar.
    """
    if not path or not isinstance(path, str):
        return "Error: path inválido"
    if not path.endswith(".md"):
        return "Error: el path debe terminar en .md"

    # Intento 1: vault path
    full = (VAULT_PATH / path).resolve()
    try:
        full.relative_to(VAULT_PATH.resolve())
    except ValueError:
        return "Error: path fuera del vault"

    basename = Path(path).name
    allowed_special = {"CLAUDE.md", "AGENTS.md", "README.md"}
    is_docs = path.startswith("docs/") and path.endswith(".md")

    if full.is_file():
        content = full.read_text(encoding="utf-8", errors="ignore")
        # Detección de placeholder: vault file pequeño (<200 bytes) que es
        # solo un redirect tipo `@04-Archive/.../CLAUDE.md` apunta al archivo
        # real. Si es uno de los archivos especiales whitelisted, fallback
        # a project root en vez de devolver el placeholder de 1 línea.
        is_placeholder = (
            len(content) < 200
            and content.lstrip().startswith("@")
            and (basename in allowed_special or is_docs)
        )
        if not is_placeholder:
            return content

    # Intento 2: project root fallback para archivos especiales.
    # Whitelist: CLAUDE.md, AGENTS.md, README.md (project root) +
    # cualquier archivo bajo docs/ (referencias técnicas).
    if basename in allowed_special or is_docs:
        repo_root = Path(__file__).resolve().parent.parent
        fallback = (repo_root / path).resolve()
        try:
            fallback.relative_to(repo_root)
        except ValueError:
            return f"Error: nota no encontrada: {path}"
        if fallback.is_file():
            return fallback.read_text(encoding="utf-8", errors="ignore")

    # Ni vault ni project root: devolver mensaje claro para que el LLM
    # NO hallucine. El mensaje incluye el path para que el LLM lo
    # reporte al user en vez de inventar contenido.
    return (
        f"Error: nota '{path}' no encontrada en el vault ni en el project "
        f"root. Sugerí al user que verifique el nombre o pase el path completo."
    )


def _agent_tool_list_notes(folder: str | None = None, tag: str | None = None, limit: int = 30) -> str:
    """Listar notas del vault, opcionalmente filtradas por carpeta o tag.

    Args:
        folder: Carpeta vault-relativa para filtrar (ej. "02-Areas/Coaching").
        tag: Tag sin '#' prefix (ej. "coaching").
        limit: Cantidad máxima a devolver.

    Returns:
        JSON con lista de {note, path, tags, modified}.
    """
    col = get_db()
    c = _load_corpus(col)
    files = _filter_files(c["metas"], tag, folder)
    files.sort(key=lambda m: m.get("modified") or "", reverse=True)
    out = [
        {
            "note": m.get("note", ""),
            "path": m.get("file", ""),
            "tags": m.get("tags", ""),
            "modified": m.get("modified", ""),
        }
        for m in files[:limit]
    ]
    return json.dumps(out, ensure_ascii=False)


def _agent_tool_weather(location: str | None = None) -> str:
    """Consultar el pronóstico del tiempo (hoy + 2 días).

    Args:
        location: Ciudad a consultar (ej. "Buenos Aires"). Default: ubicación configurada.

    Returns:
        JSON con condición actual y pronóstico de 3 días (temp, lluvia, descripción).
    """
    loc = location.replace(" ", "+") if location else WEATHER_LOCATION
    result = _fetch_weather_forecast(loc)
    if result is None:
        return "Error: no se pudo obtener el pronóstico. Verificá conectividad."
    return json.dumps(result, ensure_ascii=False)


def _agent_tool_record_contact_observation(
    contact_name: str,
    observation: str,
    category: str | None = None,
    source_excerpt: str | None = None,
    source_kind: str = "chat",
) -> str:
    """Anotar info relevante sobre un contacto en su nota del vault.

    Las notas de `04-Archive/99-obsidian-system/99-Contacts/` son contactos
    VIVOS: cada vez que el user menciona algo relevante sobre alguien (una
    preferencia, un update de trabajo, un cumpleaños que olvidó, un tema
    sensible), usá este tool para que la próxima vez que el LLM lea esa
    nota tenga el contexto. Es escritura persistente al vault.

    Doble escritura: (1) bullet timestamped en la sección `## Observaciones`
    al final de la nota (auditoría completa, incluye el excerpt crudo); y
    (2) si pasás `category` y matchea un bullet existente del frontmatter
    del contacto (ej. `- **Preferencias**: ...`), también appendea al
    value de ese bullet (vista consolidada para queries tipo "a Seba qué
    le gusta?"). Idempotente: texto ya presente → skip silencioso.

    Usalo cuando el user dice cosas como:
    - "Seba me llevó un vino" → observation="Le gusta el vino",
      category="Preferencias", source_excerpt="Seba me llevó un vino"
    - "Mi vieja ahora trabaja en San Pedro" → observation="Trabaja en San
      Pedro", category="Trabajo / contexto"
    - "Oscar anda de mal humor con el tema de la herencia" → observation=
      "Sensible con el tema de la herencia", category="Notas"

    NO usar para: queries/lookups ("qué le gusta a X"), eventos puntuales
    sin significado de contacto ("Seba vino a cenar" sin info nueva), o
    info que ya está en la nota.

    Args:
        contact_name: Nombre tal como el user lo dice ("Seba", "mi Mama",
            "Sebastian"). Se resuelve via el vault `99-Contacts/` (full_name,
            aliases, filename).
        observation: Texto procesado de la observación, corto y accionable
            ("Le gusta el vino"). Evitá la frase cruda — eso va en
            source_excerpt.
        category: Categoría del bullet del template del contacto
            (`Preferencias`, `Trabajo / contexto`, `Notas`, etc.). Opcional
            — si no se pasa, solo va a `## Observaciones` (auditoría).
        source_excerpt: Frase cruda que motivó la observación (se loguea
            en italic junto al bullet). Útil para auditoría.
        source_kind: Origen del insight. Default "chat" porque este tool
            lo llama el LLM del chat.

    Returns:
        JSON `{ok, file, observation_added, category_updated, reason?}`.
        Si el contacto no existe en el vault, devuelve `ok=false` con
        `reason="contact_not_in_vault"` — avisale al user que creé la nota
        primero (copiando `_template.md` de `99-Contacts/`).
    """
    from rag.integrations.whatsapp import _append_contact_observation
    try:
        result = _append_contact_observation(
            contact_name,
            observation,
            category=category,
            source_kind=source_kind,
            source_excerpt=source_excerpt,
        )
    except Exception as exc:
        return json.dumps(
            {"ok": False, "reason": f"exception: {str(exc)[:120]}"},
            ensure_ascii=False,
        )
    return json.dumps(result, ensure_ascii=False)


_AGENT_PENDING_WRITES: list[dict] = []
_AGENT_PENDING_WRITES_lock = threading.Lock()
# Guards `_AGENT_PENDING_WRITES` against concurrent append/clear/iterate.
# Hoy el único caller es `do()` en un solo thread, pero `_agent_tool_*` son
# importadas por `web/tools.py` y los read-tools ya se ejecutan en un thread
# pool. Si `propose_write` / `append_to_note` se exponen al web en el futuro,
# esta cobertura evita una race sigilosa en .append() bajo GIL.


# ── Scribe helpers (Fase A, 2026-04-23) ────────────────────────────────────
# Historia: el apply loop original tenía una línea nefasta —
#   if full.exists(): full = full.with_name(f"{full.stem} ({HHMMSS}).md")
# → cualquier overwrite se transformaba en un duplicado silencioso con
# sufijo temporal. El usuario pedía "agregá X a mi nota Y" y terminaba
# con `Y (183022).md`. El fix rompe el path en 3 primitivas:
#   - propose_write(overwrite=False) = create-only (default conservador)
#   - propose_write(overwrite=True)   = overwrite explícito + backup
#   - append_to_note(...)             = append al final o bajo heading
# Cada entry en _AGENT_PENDING_WRITES lleva `kind` ∈ {create,overwrite,append}
# para que el apply sepa qué operación hacer.


def _scribe_validate_path(path: str) -> str | None:
    """Shared path validation for propose_write + append_to_note.
    Returns an error string or None if the path is acceptable.
    Checks: endswith .md, not in dotfolder, resolved stays inside VAULT_PATH.
    Does NOT check existence — that's caller-specific."""
    if not path.endswith(".md"):
        return "Error: path debe terminar en .md"
    if is_excluded(path):
        return "Error: path en dotfolder rechazado"
    try:
        full = (VAULT_PATH / path).resolve()
        full.relative_to(VAULT_PATH.resolve())
    except (ValueError, OSError):
        return "Error: path fuera del vault"
    return None


def _scribe_backup_path(full: Path) -> Path:
    """Return a timestamped backup sibling for `full`. Shape:
    `<file>.bak.<unix_ts>`. Matches the `.bak.<ts>` convention used by
    the T10 state migration so `rag free --skip-baks` already knows
    how to prune them on the `rag maintenance` cycle."""
    return full.with_name(f"{full.name}.bak.{int(time.time())}")


def _scribe_insert_under_heading(body: str, section: str, content: str) -> str:
    """Insert `content` right after the line that matches `section`
    exactly (full-line match, anchored with ^ and $). Raises ValueError
    if the heading is not found — callers should have validated with
    `_scribe_heading_exists()` first.

    Insertion shape: newline + content + newline, keeping whatever
    followed the heading intact (blank lines, next heading, etc).
    """
    pattern = rf"^{re.escape(section)}\s*$"
    match = re.search(pattern, body, re.MULTILINE)
    if match is None:
        raise ValueError(f"section {section!r} no está en el body")
    insert_at = match.end()
    snippet = "\n" + content.rstrip("\n") + "\n"
    return body[:insert_at] + snippet + body[insert_at:]


def _scribe_heading_exists(body: str, section: str) -> bool:
    """True iff `section` appears as a standalone line in body. Used by
    the tool to validate BEFORE registering the pending entry — we'd
    rather fail early than discover the heading is missing at apply time."""
    pattern = rf"^{re.escape(section)}\s*$"
    return re.search(pattern, body, re.MULTILINE) is not None


def _scribe_append_to_body(body: str, content: str) -> str:
    """Append `content` to the end of `body` with a blank-line separator
    if needed. Guarantees a single trailing newline so subsequent appends
    keep the file clean."""
    if not body.endswith("\n"):
        body = body + "\n"
    if not body.endswith("\n\n"):
        body = body + "\n"
    return body + content.rstrip("\n") + "\n"


def _scribe_apply_entry(entry: dict, col) -> None:
    """Apply one pending scribe entry to the vault. Creates a backup
    `<path>.bak.<unix_ts>` for any operation that mutates an existing
    file (overwrite, append). Re-indexes the affected file via
    `_index_single_file` so subsequent retrieves see the update.

    Raises:
        RuntimeError: unknown kind, or kind="create" but path already
            exists (defensive — propose_write should have caught this).
    """
    kind = entry.get("kind", "create")
    rel_path = entry["path"]
    full = (VAULT_PATH / rel_path).resolve()
    full.parent.mkdir(parents=True, exist_ok=True)

    if kind == "create":
        if full.exists():
            raise RuntimeError(
                f"path ya existe: {rel_path} "
                "(use propose_write con overwrite=True si querés reemplazar)"
            )
        full.write_text(entry["content"], encoding="utf-8")
    elif kind == "overwrite":
        if full.exists():
            bak = _scribe_backup_path(full)
            bak.write_bytes(full.read_bytes())
        full.write_text(entry["content"], encoding="utf-8")
    elif kind == "append":
        if not full.is_file():
            raise RuntimeError(f"nota no encontrada: {rel_path}")
        bak = _scribe_backup_path(full)
        bak.write_bytes(full.read_bytes())
        old = full.read_text(encoding="utf-8", errors="ignore")
        section = entry.get("section")
        if section:
            new = _scribe_insert_under_heading(old, section, entry["content"])
        else:
            new = _scribe_append_to_body(old, entry["content"])
        full.write_text(new, encoding="utf-8")
    else:
        raise RuntimeError(f"kind desconocido: {kind!r}")

    try:
        _index_single_file(col, full)
    except Exception:
        pass


def _scribe_render_diff(entry: dict) -> str:
    """Build a unified-diff preview for a pending entry. For `create`
    returns a `+` prefixed preview of the first ~20 lines (there is no
    old body to diff against). For `overwrite` + `append` reads the
    current on-disk content and runs `difflib.unified_diff`.

    Output is capped at ~40 lines to keep the terminal readable; the
    tail is replaced with a `... (N líneas más)` marker.
    """
    kind = entry.get("kind", "create")
    if kind == "create":
        new_lines = entry["content"].splitlines()
        preview = "\n".join(f"+ {line}" for line in new_lines[:20])
        if len(new_lines) > 20:
            preview += f"\n+ ... ({len(new_lines) - 20} líneas más)"
        return preview

    full = (VAULT_PATH / entry["path"]).resolve()
    if not full.is_file():
        return "# (archivo no existe al momento del preview — modificado externamente?)"
    old = full.read_text(encoding="utf-8", errors="ignore")
    if kind == "overwrite":
        new = entry["content"]
    elif kind == "append":
        section = entry.get("section")
        if section:
            try:
                new = _scribe_insert_under_heading(old, section, entry["content"])
            except ValueError:
                return f"# (heading {section!r} desapareció entre propose y preview)"
        else:
            new = _scribe_append_to_body(old, entry["content"])
    else:
        return ""

    lines = list(difflib.unified_diff(
        old.splitlines(keepends=False),
        new.splitlines(keepends=False),
        fromfile=entry["path"],
        tofile=entry["path"],
        lineterm="",
        n=3,
    ))
    if len(lines) > 40:
        lines = lines[:40] + [f"... ({len(lines) - 40} líneas más)"]
    return "\n".join(lines)


def _agent_tool_propose_write(
    path: str, content: str, rationale: str = "", overwrite: bool = False,
) -> str:
    """Proponer crear o sobrescribir una nota del vault. NO escribe
    inmediatamente — registra la propuesta para que el usuario confirme.

    Usá esta tool para crear notas resumen, agregar notas derivadas, o
    guardar outputs. Siempre bajo rutas del vault (00-Inbox/, 01-Projects/,
    02-Areas/, 03-Resources/). Nunca en dotfolders.

    Por default NO sobrescribe si el path ya existe — devuelve error
    sugiriendo `append_to_note` (para agregar contenido preservando lo
    anterior) o `overwrite=True` (para reemplazar todo, con backup
    automático). Este default conservador reemplaza el comportamiento
    legacy (<2026-04-23) que creaba un duplicado con sufijo (HHMMSS).md
    silenciosamente cuando había colisión.

    Args:
        path: Ruta relativa al vault. Debe terminar en .md.
        content: Contenido markdown completo (incluye frontmatter si querés).
        rationale: Breve justificación (por qué esta nota).
        overwrite: Si True y el path existe, propone reemplazar el archivo
            entero. Se crea un backup `<path>.bak.<unix_ts>` antes del
            write efectivo. Ignorado si el path no existe.

    Returns:
        Mensaje de confirmación registrado o error explícito.
    """
    err = _scribe_validate_path(path)
    if err:
        return err
    full = (VAULT_PATH / path).resolve()
    path_exists = full.is_file()
    if path_exists and not overwrite:
        return (
            f"Error: '{path}' ya existe. Pasá overwrite=True para reemplazar "
            f"todo el archivo (con backup automático), o usá append_to_note "
            f"para agregar contenido al final o bajo un heading existente."
        )
    kind = "overwrite" if (path_exists and overwrite) else "create"
    with _AGENT_PENDING_WRITES_lock:
        _AGENT_PENDING_WRITES.append({
            "kind": kind, "path": path, "content": content, "rationale": rationale,
        })
    label = "Sobrescritura" if kind == "overwrite" else "Creación"
    return (
        f"{label} propuesta: {path} ({len(content)} chars). "
        f"El usuario verá el diff antes de ejecutar."
    )


def _agent_tool_append_to_note(
    path: str, content: str, section: str | None = None, rationale: str = "",
) -> str:
    """Agregar contenido a una nota existente SIN reescribirla entera.

    Dos modos:
      - section=None: append al final del body (después del último
        contenido, con blank-line separator automática).
      - section="## Heading exacto": insertar `content` justo después
        de esa línea. Match case-sensitive de línea completa (no
        substring). Si el heading no existe, devuelve error explícito.

    NO escribe inmediatamente — registra la propuesta con diff para
    confirmación. Crea backup `<path>.bak.<unix_ts>` al momento del apply.

    Preferida sobre `propose_write(overwrite=True)` cuando el usuario
    pide AGREGAR información a una nota existente; overwrite es
    destructivo (reemplaza todo), append es aditivo.

    Args:
        path: Ruta relativa al vault, terminando en .md. Debe existir.
        content: Texto markdown a insertar. No se valida estructura —
            el caller es responsable de pasar contenido bien-formado.
        section: Heading bajo el cual insertar (ej. "## Pendientes",
            "### Notas de hoy"). Debe empezar con "#" y coincidir
            exactamente con una línea de la nota. None = append al final.
        rationale: Justificación breve (aparece en el diff preview).

    Returns:
        Confirmación con ubicación exacta, o error explícito si el path
        no existe / heading no encontrado / validación de path falla.
    """
    err = _scribe_validate_path(path)
    if err:
        return err
    full = (VAULT_PATH / path).resolve()
    if not full.is_file():
        return f"Error: nota no encontrada: {path}"
    if section is not None:
        if not section.startswith("#"):
            return (
                "Error: section debe empezar con '#' y ser un heading "
                "markdown completo (ej. '## Pendientes')"
            )
        body = full.read_text(encoding="utf-8", errors="ignore")
        if not _scribe_heading_exists(body, section):
            return (
                f"Error: heading {section!r} no existe en {path}. "
                "Usá propose_write con overwrite=True para agregar el "
                "heading, o revisá el nombre exacto."
            )
    with _AGENT_PENDING_WRITES_lock:
        _AGENT_PENDING_WRITES.append({
            "kind": "append",
            "path": path,
            "content": content,
            "section": section,
            "rationale": rationale,
        })
    where = f"bajo {section!r}" if section else "al final del body"
    return (
        f"Append propuesto: {path} ({len(content)} chars) {where}. "
        "El usuario verá el diff antes de ejecutar."
    )


_AGENT_SYSTEM = (
    "Sos un asistente agéntico sobre un vault de Obsidian personal. "
    "Tenés tools para buscar, leer y listar notas del vault, y para PROPONER "
    "cambios — crear notas nuevas (`propose_write`), agregar contenido a "
    "notas existentes (`append_to_note`), o reemplazar una nota entera "
    "(`propose_write` con overwrite=True). No ejecutás writes vos — sólo "
    "los proponés; el usuario los confirma viendo el diff antes de ejecutar.\n\n"
    "PROCESO DE TRABAJO (Feature #4, 2026-04-23):\n"
    "En tu primer mensaje, ANTES de llamar tools, escribí un PLAN breve en "
    "prosa (3-5 oraciones, sin lista numerada larga): qué información necesitás "
    "buscar, qué orden de tools vas a usar, qué output esperás producir. Esto "
    "te ayuda a vos mismo a no divagar y al usuario a seguir lo que hacés.\n"
    "Después de cada tool call, si el resultado NO es lo que esperabas, hacelo "
    "explícito en 1 oración antes del siguiente tool call ('no encontré X, "
    "voy a probar Y'). Esto es self-reflection y evita loops inútiles.\n"
    "Si tres tool calls consecutivos no aportan información útil, pará y "
    "respondé honestamente que no pudiste completar la tarea. Preferimos un "
    "'no pude hacer X porque Z' corto a seis iteraciones improductivas.\n\n"
    "CÓMO ELEGIR LA TOOL DE WRITE CORRECTA (Fase A scribe, 2026-04-23):\n"
    "- Si el usuario pide AGREGAR algo a una nota existente ('agregá X a mi "
    "  nota Y', 'sumá un item a la lista de pendientes de Z'), usá "
    "  `append_to_note` — preserva todo el contenido previo y solo agrega "
    "  lo nuevo al final o bajo un heading específico.\n"
    "- Si el usuario pide CREAR una nota nueva ('creá una nota sobre X', "
    "  'armá un resumen de Y'), usá `propose_write` sin overwrite (default).\n"
    "- Si el usuario pide REEMPLAZAR completamente el contenido de una nota "
    "  ('reescribí esta nota desde cero', 'limpiá mi nota Y'), usá "
    "  `propose_write` con overwrite=True. El apply loop crea un backup "
    "  `.bak.<timestamp>` automáticamente antes de sobrescribir.\n"
    "- NO uses overwrite=True cuando el usuario solo quiere agregar algo — "
    "  append es siempre más seguro que overwrite.\n\n"
    "Reglas:\n"
    "1. Antes de proponer writes, usá search/read/list para juntar contexto "
    "   del vault real. No inventes paths ni contenidos.\n"
    "2. Las notas NUEVAS deben vivir bajo 00-Inbox/, 01-Projects/, "
    "   02-Areas/ o 03-Resources/. Default: 00-Inbox/ para capturas nuevas.\n"
    "3. Incluí frontmatter YAML válido con `created`, `tags` del vocabulario "
    "   existente cuando sea posible, y `related: [[wikilink]]` a notas "
    "   fuente cuando derivás de ellas.\n"
    "4. Cuando terminás, respondé con un resumen breve en lenguaje natural "
    "   de lo que hiciste y qué proponés.\n"
    "5. Si la instrucción es ambigua o no podés completarla con el vault, "
    "   decilo — no inventes.\n"
    "6. Tenés un tool `_agent_tool_weather` para consultar el pronóstico del "
    "   tiempo. Usalo cuando la pregunta sea sobre clima/lluvia/temperatura."
)


@cli.command()
@click.argument("instruction")
@click.option("--yes", is_flag=True, help="Ejecutar writes propuestos sin confirmar uno por uno")
@click.option("--max-iterations", default=8, help="Cap de iteraciones de tool calling (default 8)")
def do(instruction: str, yes: bool, max_iterations: int):
    """Ejecutar una instrucción agéntica sobre el vault.

    Ejemplos:
        rag do "armá un resumen de todas mis notas sobre ikigai en una nota nueva"
        rag do "listame qué referentes tengo en coaching y proponé una nota índice"
        rag do "buscá notas sin tags y sugerí tags basados en contenido"

    Los writes se proponen primero (`propose_write` tool) y se confirman al
    final uno por uno (o todos con --yes).
    """
    warmup_async()
    with _AGENT_PENDING_WRITES_lock:
        _AGENT_PENDING_WRITES.clear()

    tools = [
        _agent_tool_search,
        _agent_tool_read_note,
        _agent_tool_list_notes,
        _agent_tool_propose_write,
        _agent_tool_append_to_note,
        _agent_tool_weather,
        _agent_tool_record_contact_observation,
    ]
    tool_fns = {fn.__name__: fn for fn in tools}

    messages = [
        {"role": "system", "content": _AGENT_SYSTEM},
        {"role": "user", "content": instruction},
    ]

    console.print(Panel(f"[bold cyan]{instruction}[/bold cyan]", border_style="cyan"))

    model = resolve_chat_model()
    _keep_alive = chat_keep_alive(model)

    # Track consecutive "unproductive" tool results to detect loops.
    # A result is unproductive when:
    #   - Tool returned an error string starting with "Error:"
    #   - Tool returned "Sin resultados" / "no encontrado" (semantic search)
    # After 3 consecutive unproductive calls, we inject a synthetic message
    # telling the LLM to stop looping and answer honestly.
    _unproductive_streak = 0
    _UNPRODUCTIVE_CAP = int(os.environ.get("RAG_AGENT_UNPRODUCTIVE_CAP", "3"))

    def _is_unproductive(result_str: str) -> bool:
        if not isinstance(result_str, str):
            return False
        lowered = result_str.strip().lower()
        if not lowered:
            return True
        # Heuristics: tool errors + empty-search signals.
        if lowered.startswith("error"):
            return True
        if lowered.startswith("sin resultados") or lowered.startswith("sin candidatos"):
            return True
        if "no encontrado" in lowered[:80] or "not found" in lowered[:80]:
            return True
        return False

    for it in range(max_iterations):
        with console.status(f"[dim]pensando (iter {it + 1}/{max_iterations})…[/dim]", spinner="dots"):
            resp = _chat_capped_client().chat(
                model=model,
                messages=messages,
                tools=tools,
                options=CHAT_OPTIONS,
                keep_alive=_keep_alive,
            )

        msg = resp.message
        # Persist the assistant turn for the follow-up tool messages.
        messages.append({
            "role": "assistant",
            "content": msg.content or "",
            "tool_calls": [tc.model_dump() for tc in (msg.tool_calls or [])],
        })

        # Show the LLM's "thinking" / plan text between tool batches. This
        # is especially useful on the first iteration when the new agent
        # prompt asks for an upfront plan — the user can see the strategy
        # before any tool fires. Also surfaces self-reflection mid-loop.
        inline_text = (msg.content or "").strip()
        if inline_text and msg.tool_calls:
            console.print()
            console.print(f"[dim italic]{inline_text[:400]}[/dim italic]")

        if not msg.tool_calls:
            # Final answer.
            console.print()
            console.print(render_response(msg.content or ""))
            break

        # Execute each tool call.
        for tc in msg.tool_calls:
            name = tc.function.name
            args = tc.function.arguments or {}
            # Audit 2026-04-26 (BUG #10): algunos modelos ollama devuelven
            # args como JSON string raw — el dict comp de abajo crasheaba
            # con AttributeError sin capturar. Parse defensivo PRIMERO.
            if isinstance(args, str):
                try:
                    args = json.loads(args)
                except Exception:
                    args = {}
            if not isinstance(args, dict):
                args = {}
            # command-r wraps args as {"tool_name": "...", "parameters": {...}}.
            # Unwrap so we can call the Python function directly.
            if "parameters" in args and isinstance(args["parameters"], (dict, str)):
                params = args["parameters"]
                if isinstance(params, str):
                    try:
                        params = json.loads(params)
                    except Exception:
                        params = {}
                if not isinstance(params, dict):
                    params = {}
                args = params
            # Drop empty-string optional args so defaults kick in.
            args = {k: v for k, v in args.items() if v not in ("", None)}
            console.print(f"  [dim]→ {name}({', '.join(f'{k}={str(v)[:40]!r}' for k, v in args.items())})[/dim]")
            fn = tool_fns.get(name)
            if not fn:
                result = f"Error: tool '{name}' no existe"
            else:
                try:
                    result = fn(**args)
                except TypeError as e:
                    result = f"Error de argumentos en {name}: {e}"
                except Exception as e:
                    result = f"Error ejecutando {name}: {e}"
            result_str = result if isinstance(result, str) else json.dumps(result)
            # Unproductive streak tracking (Feature #4).
            if _is_unproductive(result_str):
                _unproductive_streak += 1
            else:
                _unproductive_streak = 0
            messages.append({
                "role": "tool",
                "name": name,
                "content": result_str,
            })
        # After a full batch of tool calls, if the streak hit the cap inject
        # a system-ish nudge before the next LLM turn. This breaks the loop
        # on the LLM side — the user's instruction wasn't achievable with
        # the available context, and we'd rather a quick honest answer than
        # burning iterations trying the same thing.
        if _unproductive_streak >= _UNPRODUCTIVE_CAP:
            console.print(
                f"  [yellow]⚠ {_unproductive_streak} tool calls sin progreso "
                f"— pidiendo cierre.[/yellow]"
            )
            messages.append({
                "role": "user",
                "content": (
                    f"Detectamos {_unproductive_streak} tool calls consecutivos "
                    "sin información útil. Parece que la instrucción no se puede "
                    "completar con el contexto del vault. Respondé en una oración "
                    "qué intentaste y por qué no pudiste completarlo. No sigas "
                    "llamando tools."
                ),
            })
            _unproductive_streak = 0
    else:
        console.print(f"[yellow]⚠ Cap de {max_iterations} iteraciones alcanzado.[/yellow]")

    # Show pending writes, confirm each.
    # Snapshot atómico bajo lock — iterar afuera para no retener el lock
    # durante prompts interactivos de Rich (pueden bloquear minutos).
    with _AGENT_PENDING_WRITES_lock:
        _pending_snapshot = list(_AGENT_PENDING_WRITES)
    if _pending_snapshot:
        console.print()
        console.print(Rule(title="[bold yellow]Cambios propuestos[/bold yellow]", style="yellow"))
        col = get_db()
        _kind_label = {
            "create": ("Crear", "Crear?"),
            "overwrite": ("Sobrescribir", "Sobrescribir (backup .bak.<ts> auto)?"),
            "append": ("Agregar", "Aplicar append?"),
        }
        for i, w in enumerate(_pending_snapshot, 1):
            kind = w.get("kind", "create")
            label, prompt_text = _kind_label.get(kind, (kind, "Aplicar?"))
            console.print()
            header = f"[bold]{i}. [{label}] {w['path']}[/bold]"
            if kind == "append" and w.get("section"):
                header += f"  [dim]bajo {w['section']!r}[/dim]"
            header += f"  [dim]({len(w['content'])} chars)[/dim]"
            console.print(header)
            if w.get("rationale"):
                console.print(f"   [dim italic]{w['rationale']}[/dim italic]")
            # Diff preview: unified diff para overwrite/append, + preview
            # para create. Renderizado con Syntax lexer=diff para los verdes
            # y rojos nativos del terminal.
            diff_text = _scribe_render_diff(w)
            if diff_text:
                try:
                    console.print(Syntax(
                        diff_text, "diff",
                        theme="ansi_dark", background_color="default",
                        word_wrap=True,
                    ))
                except Exception:
                    # Fallback defensivo: si Syntax falla por cualquier razón
                    # (pygments missing, theme error), mostrar el diff plano.
                    console.print(f"[dim]{diff_text}[/dim]")

            if yes:
                apply = True
            else:
                try:
                    resp = console.input(
                        f"   [bold green]{prompt_text}[/bold green] [y/N] "
                    ).strip().lower()
                except (KeyboardInterrupt, EOFError):
                    console.print("   [yellow]cancelado[/yellow]")
                    break
                apply = resp in ("y", "s", "yes", "si", "sí")

            if apply:
                try:
                    _scribe_apply_entry(w, col)
                    console.print(f"   [green]✓ aplicado:[/green] {w['path']}")
                except Exception as e:
                    console.print(f"   [red]✗ error al aplicar: {e}[/red]")
            else:
                console.print("   [dim]saltado[/dim]")
    else:
        console.print("[dim](sin cambios propuestos)[/dim]")


_WEATHER_ES: dict[str, str] = {
    "Clear": "Despejado", "Sunny": "Soleado", "Partly Cloudy": "Parcialmente nublado",
    "Partly cloudy": "Parcialmente nublado", "Cloudy": "Nublado", "Overcast": "Cubierto",
    "Mist": "Neblina", "Fog": "Niebla", "Light rain": "Lluvia leve",
    "Light drizzle": "Llovizna", "Drizzle": "Llovizna",
    "Patchy rain nearby": "Lluvia intermitente", "Patchy rain possible": "Posible lluvia",
    "Moderate rain": "Lluvia moderada", "Heavy rain": "Lluvia fuerte",
    "Light rain shower": "Chubasco leve", "Moderate or heavy rain shower": "Chubasco fuerte",
    "Thundery outbreaks possible": "Posibles tormentas",
    "Patchy light rain with thunder": "Lluvia leve con truenos",
    "Moderate or heavy rain with thunder": "Lluvia fuerte con truenos",
    "Light snow": "Nieve leve", "Heavy snow": "Nieve fuerte",
    "Patchy light drizzle": "Llovizna intermitente",
    "Light freezing rain": "Lluvia helada leve",
}


def _translate_weather(desc: str) -> str:
    parts = [_WEATHER_ES.get(p.strip(), p.strip()) for p in desc.split(",")]
    return ", ".join(parts)


@cli.command()
@click.argument("question", default="")
def weather(question: str):
    """Consultar el clima sin agent loop ni writes al vault."""
    data = _fetch_weather_forecast()
    if data is None:
        click.echo("Error: no se pudo obtener el pronóstico.")
        raise SystemExit(1)
    cur = data["current"]
    lines = [f"📍 {data['location']} — {_translate_weather(cur['description'])}, {cur['temp_C']}°C"]
    for d in data["days"]:
        rain = f", 🌧 {d['chanceofrain']}%" if d["chanceofrain"] > 10 else ""
        lines.append(f"  {d['date']}: {d['minC']}–{d['maxC']}°C, {_translate_weather(d['description'])}{rain}")
    forecast_block = "\n".join(lines)

    if question.strip():
        comment = _weather_comment(question, forecast_block)
        click.echo(f"{comment}\n\n{forecast_block}")
    else:
        click.echo(forecast_block)


# `_weather_comment` moved to `rag.integrations.weather` (Phase 1b, 2026-04-25).
# Re-exported at the bottom of this file so `rag._weather_comment` keeps
# resolving for tests + `serve` callers in this same module.


_CREATED_TS_BACKFILL_DONE = False

# Pseudo-table-name usado en `rag_schema_version` para persistir la completitud
# del backfill de created_ts a través de restarts. Valor sentinel — no hay
# tabla real con ese nombre.
_CREATED_TS_BACKFILL_MARKER = "_created_ts_backfill_complete"


def _created_ts_backfill_persisted() -> bool:
    """Check SQL-persisted flag (survives process restarts).

    Uses `rag_schema_version` as a generic key/value store — registra una
    fila `(table_name='_created_ts_backfill_complete', version=1)` cuando el
    backfill termina exitosamente. Los daemons con 100+ restarts (launchd
    KeepAlive) dejan de re-correr el scan de 3600 chunks + 580 file reads
    en la primera query con `date_range` post-restart.

    Best-effort: si la query SQL falla (DB lockeada, schema no inicializado),
    retorna False → el backfill in-memory vuelve a correr una vez.
    """
    try:
        col = get_db()
        row = col._db.execute(
            "SELECT version FROM rag_schema_version WHERE table_name = ?",
            (_CREATED_TS_BACKFILL_MARKER,),
        ).fetchone()
        return row is not None and row[0] >= 1
    except Exception:
        return False


def _mark_created_ts_backfill_persisted() -> None:
    """Marca el backfill como completado en SQL. Llamar solo tras un
    `col.update()` exitoso — si la escritura falla, el marker no se setea
    y la próxima invocación reintenta."""
    try:
        col = get_db()
        col._db.execute(
            "INSERT INTO rag_schema_version(table_name, version) VALUES(?, 1) "
            "ON CONFLICT(table_name) DO UPDATE SET version = 1",
            (_CREATED_TS_BACKFILL_MARKER,),
        )
        col._db.commit()
    except Exception as exc:
        _silent_log("created_ts_backfill_mark", exc)


def _maybe_backfill_created_ts() -> None:
    """Populate `created_ts` on chunks indexed before the temporal-retrieval
    feature landed. Metadata-only update (no re-embedding) — reads each file
    to get frontmatter `created:` or falls back to mtime, then `col.update()`
    in batches. Idempotent within a process AND across restarts (via SQL marker).

    Gated por el lazy hook para que los usuarios no paguen el scan cost hasta
    que realmente usen un date filter. Un índice fresh-reset tiene created_ts
    en cada chunk desde el arranque, así que este pass es un no-op y termina
    rápido. El SQL marker (`_created_ts_backfill_persisted()`) evita re-correr
    el escaneo en cada restart del web daemon (launchd restarted 149x en
    ~3 días — medido en web.log 2026-04-21, rastreable por el número de
    `[idle-sweep] ... disabled` prints).
    """
    global _CREATED_TS_BACKFILL_DONE
    if _CREATED_TS_BACKFILL_DONE:
        return
    # SQL persistence check — survives restarts. Si ya corrió en un proceso
    # anterior y escribió el marker, saltamos directo al fast-path.
    if _created_ts_backfill_persisted():
        _CREATED_TS_BACKFILL_DONE = True
        return
    _CREATED_TS_BACKFILL_DONE = True
    try:
        col = get_db()
        if col.count() == 0:
            return
        # sqlite-vec doesn't support {"$not_exists": ...} filters,
        # so we fetch all metadata and filter in Python. 521-note vault
        # produces ~2k chunks — negligible.
        data = col.get(include=["metadatas"])
    except Exception:
        return
    ids = data.get("ids") or []
    metas = data.get("metadatas") or []
    missing: dict[str, list[tuple[str, dict]]] = {}
    for id_, m in zip(ids, metas):
        if m is None:
            continue
        if "created_ts" in m:
            continue
        file_rel = m.get("file", "")
        if not file_rel:
            continue
        missing.setdefault(file_rel, []).append((id_, dict(m)))
    if not missing:
        # Nothing to backfill — marker is safe to set so the next process
        # skips this scan too.
        _mark_created_ts_backfill_persisted()
        return
    console.print(
        f"[dim]Backfill created_ts en {len(missing)} nota(s) "
        f"({sum(len(v) for v in missing.values())} chunks)…[/dim]"
    )
    update_ids: list[str] = []
    update_metas: list[dict] = []
    for file_rel, items in missing.items():
        abs_path = VAULT_PATH / file_rel
        try:
            mtime = abs_path.stat().st_mtime
            raw = abs_path.read_text(encoding="utf-8", errors="ignore") if abs_path.is_file() else ""
        except OSError:
            continue
        ts = _note_created_ts(raw, mtime) if raw else mtime
        for id_, m in items:
            m["created_ts"] = ts
            update_ids.append(id_)
            update_metas.append(m)
    if not update_ids:
        return
    try:
        # Batch writes for predictable memory usage.
        B = 500
        for i in range(0, len(update_ids), B):
            col.update(ids=update_ids[i:i + B], metadatas=update_metas[i:i + B])
        # Success — persist the marker so future processes skip the scan.
        _mark_created_ts_backfill_persisted()
    except Exception as e:
        console.print(f"[yellow]Backfill created_ts falló: {e}[/yellow]")


_URLS_BACKFILL_DONE = False


def _maybe_backfill_urls() -> None:
    """Auto-backfill the URL sub-index when it's empty but the main collection
    isn't — covers the "user upgraded past v0 and never ran `rag links
    --rebuild`" path. Idempotent within a process; runs at most once.
    """
    global _URLS_BACKFILL_DONE
    if _URLS_BACKFILL_DONE:
        return
    _URLS_BACKFILL_DONE = True
    try:
        col_urls = get_urls_db()
        if col_urls.count() > 0:
            return
        main = get_db()
        if main.count() == 0:
            return
    except Exception:
        return
    console.print(
        "[dim]URL index vacío — backfill automático (~1 min)…[/dim]"
    )
    try:
        _rebuild_urls_index()
    except Exception as e:
        console.print(f"[yellow]Backfill falló: {e}[/yellow]")


def _row_matches_source(meta: dict, source: str) -> bool:
    """Legacy rows (indexed before the `source` field existed) lack the key.
    Treat those as 'note' so `--source note` works without a reindex.
    """
    row_source = (meta or {}).get("source") or "note"
    return row_source == source


def find_urls(
    query: str,
    k: int = 10,
    folder: str | None = None,
    tag: str | None = None,
    source: str | None = None,
) -> list[dict]:
    """Semantic-by-context search over the URL sub-index.

    The collection embeds the prose around each URL (not the URL string), so a
    query like "documentación de claude code" matches notes that introduce or
    annotate the relevant link. Reranks the top candidates against the query
    with the cross-encoder, dedups by URL, returns up to k items.

    `source="note"` restricts to URLs extracted from vault notes (also matches
    legacy rows predating the field). `source="bookmark"` restricts to Chrome
    bookmarks. Default mixes both.

    First-call autopilot: if the URL collection is empty but the vault is
    indexed, runs `_rebuild_urls_index` silently so the user never has to
    remember `rag links --rebuild` after upgrading.
    """
    _maybe_backfill_urls()
    col_urls = get_urls_db()
    if col_urls.count() == 0:
        return []
    try:
        q_embed = embed([query])[0]
    except Exception:
        return []
    where = build_where(folder, tag)
    # Over-fetch when we'll post-filter by source — keeps the final pool wide.
    overshoot = 5 if source else 3
    n = min(k * overshoot + 5, col_urls.count())
    kwargs: dict = {
        "query_embeddings": [q_embed], "n_results": n,
        "include": ["documents", "metadatas", "distances"],
    }
    if where:
        kwargs["where"] = where
    res = col_urls.query(**kwargs)
    docs, metas, dists = res["documents"][0], res["metadatas"][0], res["distances"][0]
    if source:
        kept = [
            (d, m, dist) for d, m, dist in zip(docs, metas, dists)
            if _row_matches_source(m, source)
        ]
        if not kept:
            return []
        docs = [x[0] for x in kept]
        metas = [x[1] for x in kept]
        dists = [x[2] for x in kept]
    if not docs:
        return []
    try:
        reranker = get_reranker()
        scores = [float(s) for s in reranker.predict(
            [(query, d) for d in docs], show_progress_bar=False,
        )]
    except Exception:
        scores = [1.0 - float(d) for d in dists]
    items: list[dict] = []
    seen: set[str] = set()
    per_file: dict[str, int] = {}
    PER_FILE_CAP = 2  # diversify so one note can't dominate the top-k
    for d, m, score in sorted(
        zip(docs, metas, scores), key=lambda x: x[2], reverse=True,
    ):
        url = m.get("url", "")
        path_str = m.get("file", "")
        if not url or url in seen:
            continue
        if per_file.get(path_str, 0) >= PER_FILE_CAP:
            continue
        seen.add(url)
        per_file[path_str] = per_file.get(path_str, 0) + 1
        items.append({
            "url": url,
            "anchor": m.get("anchor", ""),
            "path": path_str,
            "note": m.get("note", ""),
            "line": m.get("line", 0),
            "context": d,
            "score": score,
            "source": m.get("source") or "note",
            "profile": m.get("profile", ""),
            "bookmark_folder": m.get("bookmark_folder", ""),
        })
        if len(items) >= k:
            break
    return items


# Same single-level-balanced-parens trick as NOTE_LINK_RE so URLs with
# `(…)` inside (Wikipedia, disambiguation pages) aren't half-matched.
_CTX_URL_MD_RE = re.compile(
    r"\[([^\]]+)\]\(https?://[^\s()]*(?:\([^)]*\)[^\s()]*)?\)"
)
_CTX_URL_BARE_RE = re.compile(r"https?://\S+")
_CTX_TABLE_SEP_RE = re.compile(r"\s*\|\s*")
_CTX_BACKTICKS_RE = re.compile(r"`([^`]+)`")
_CTX_FRONTMATTER_BLOCK_RE = re.compile(r"-{3,}.*?-{3,}", flags=re.DOTALL)
_CTX_FRONTMATTER_SEP_RE = re.compile(r"-{3,}")
_CTX_TAG_RE = re.compile(r"#[\w/-]+")
_CTX_WS_RE = re.compile(r"[ \t]+")


def _clean_link_context(ctx: str, own_url: str, max_len: int = 240) -> str:
    """Smooth the 240-char context snippet into readable prose.

    Flattens markdown links to their anchor text, drops bare URLs (they
    collide visually with the main URL shown above), removes the YAML
    frontmatter block when the snippet starts mid-note, collapses table
    pipes, strips backticks and inline #tags. Keeps plain prose intact so
    the snippet still functions as a preview.
    """
    if not ctx:
        return ""
    s = _CTX_FRONTMATTER_BLOCK_RE.sub(" ", ctx)
    s = _CTX_URL_MD_RE.sub(r"\1", s)
    s = s.replace(own_url, "")
    s = _CTX_URL_BARE_RE.sub("", s)
    s = _CTX_BACKTICKS_RE.sub(r"\1", s)
    s = _CTX_FRONTMATTER_SEP_RE.sub(" ", s)
    s = _CTX_TABLE_SEP_RE.sub(" · ", s)
    s = _CTX_TAG_RE.sub("", s)
    s = _CTX_WS_RE.sub(" ", s)
    s = re.sub(r"(?:\s*·\s*){2,}", " · ", s)
    s = s.strip(" \t·-|,;:.\n…*>)")
    if len(s) > max_len:
        s = s[: max_len - 1].rstrip() + "…"
    return s


def render_links(items: list[dict], plain: bool = False) -> None:
    """Render link-finder results. Plain mode = bot/script-friendly text."""
    if not items:
        if plain:
            click.echo("Sin URLs.")
        else:
            console.print("[yellow]Sin URLs en el vault para esa consulta.[/yellow]")
        return
    if plain:
        for i, it in enumerate(items, 1):
            click.echo(f"{i}. {it['url']}")
            label = it.get("anchor") or it.get("note", "")
            if label:
                click.echo(f"   {label}")
            click.echo(f"   en {it['path']}:{it.get('line', 0)}")
        return
    # Body mirrors the chat flow: header · markdown bullet list · Fuentes ·
    # Relacionadas. Keeps URL output visually consistent with regular chat
    # answers (the LLM emits the same `[label](url)` bullets).
    console.print()
    files = {it["path"] for it in items if it.get("path")}
    console.print(
        f"  [dim]🔗 links · {len(items)} url(s) · {len(files)} nota(s)[/dim]"
    )
    console.print()

    # Numeración `01.`, `02.` zero-padded. Un spans clickeable por item
    # (OSC 8 hyperlink abre la URL). Si hay anchor, mostramos sólo el
    # anchor — la URL está detrás del link, no hace falta duplicarla.
    # Sin anchor → URL bare clickeable.
    width = max(2, len(str(len(items))))
    for i, it in enumerate(items, 1):
        url = it["url"]
        anchor = (it.get("anchor") or "").strip()
        label = anchor if anchor and anchor != url else url
        line = Text()
        line.append(f"{i:0{width}d}. ", style="dim")
        line.append(label, style=_url_link_style(url, "blue"))
        console.print(line)

    # Fuentes + Relacionadas: look up full metas from the corpus so
    # `find_related` has tags/outlinks to work with. URL items only carry
    # {path, note, line} — the corpus has everything else.
    try:
        col = get_db()
        corpus = _load_corpus(col)
        by_file = {m.get("file", ""): m for m in corpus["metas"]}
    except Exception:
        by_file = {}

    seen_files: set[str] = set()
    metas: list[dict] = []
    for it in items:
        f = it.get("path", "")
        if not f or f in seen_files:
            continue
        seen_files.add(f)
        metas.append(by_file.get(f) or {
            "file": f, "note": it.get("note", ""), "tags": "", "folder": "",
        })
    scores = [float(it.get("score", 0.0)) for it in items if it.get("path") and it["path"] in seen_files][:len(metas)]
    # Pad with zeros if de-dup dropped some; render_sources just zips.
    while len(scores) < len(metas):
        scores.append(0.0)

    if metas:
        console.print()
        console.print(Rule(title="[dim]Fuentes[/dim]", style="dim", characters="╌"))
        console.print(render_sources(metas, scores))

    if metas and by_file:
        try:
            related = find_related(col, metas, limit=5)
        except Exception:
            related = []
        render_related(related)


def _rebuild_urls_index() -> dict:
    """Re-extract URLs from every note in the vault into the URL collection
    without touching chunk embeddings. Cheap (no LLM, no chunk re-embed) — use
    after upgrades that change URL extraction logic, or to backfill the URL
    index on a vault that was already chunk-indexed before this feature.
    """
    col_urls = get_urls_db()
    md_files = [
        p for p in VAULT_PATH.rglob("*.md")
        if not is_excluded(str(p.relative_to(VAULT_PATH)))
    ]
    console.print(f"[cyan]Re-extrayendo URLs de {len(md_files)} notas...[/cyan]")
    total = 0
    files_with_urls = 0
    for path in track(md_files, description="URLs..."):
        try:
            doc_id_prefix = str(path.relative_to(VAULT_PATH))
            folder = str(path.relative_to(VAULT_PATH).parent)
            raw = path.read_text(encoding="utf-8", errors="ignore")
            fm = parse_frontmatter(raw)
            tags = _normalize_fm_tags(fm)
            n = _index_urls(col_urls, doc_id_prefix, raw, path.stem, folder, tags)
            total += n
            if n:
                files_with_urls += 1
        except Exception:
            continue
    console.print(
        f"[green]Listo. {total} URLs en {files_with_urls} notas.[/green]"
    )
    return {"urls": total, "files": files_with_urls}


@cli.command()
@click.argument("query", required=False)
@click.option("-k", default=10, help="Cantidad de URLs a devolver (default: 10)")
@click.option("--folder", default=None, help="Filtrar por carpeta")
@click.option("--tag", default=None, help="Filtrar por tag")
@click.option("--open", "open_idx", type=int, default=None,
              help="Abrir la URL del rank N en el browser por defecto (macOS: open)")
@click.option("--plain", is_flag=True, help="Salida plana sin colores/paneles")
@click.option("--rebuild", is_flag=True,
              help="Re-extraer URLs de todas las notas sin re-embeddar chunks")
@click.option("--source", "source", type=click.Choice(["note", "bookmark"]),
              default=None,
              help="Filtrar por origen: solo URLs de notas o solo bookmarks de Chrome")
def links(query: str | None, k: int, folder: str | None, tag: str | None,
          open_idx: int | None, plain: bool, rebuild: bool,
          source: str | None):
    """Buscar URLs en el vault por contexto semántico — respuesta sin LLM."""
    if rebuild:
        _rebuild_urls_index()
        return
    if not query:
        console.print("[yellow]Pasá una query o usá --rebuild.[/yellow]")
        return
    warmup_async()
    t0 = time.perf_counter()
    items = find_urls(query, k=k, folder=folder, tag=tag, source=source)
    if open_idx is not None:
        if not (1 <= open_idx <= len(items)):
            msg = f"Índice {open_idx} fuera de rango (1-{len(items)})"
            click.echo(msg) if plain else console.print(f"[red]{msg}[/red]")
            return
        url = items[open_idx - 1]["url"]
        import subprocess
        try:
            subprocess.run(["open", url], check=False)
        except Exception as e:
            msg = f"No pude abrir: {e}"
            click.echo(msg) if plain else console.print(f"[red]{msg}[/red]")
            return
        click.echo(f"abierto: {url}") if plain else console.print(f"[green]✓ Abierto:[/green] {url}")
        return
    render_links(items, plain=plain)
    log_query_event({
        "cmd": "links", "q": query, "n_results": len(items),
        "folder": folder, "tag": tag,
        "top_url": items[0]["url"] if items else None,
        "timing": _round_timing_ms({"total_ms": (time.perf_counter() - t0) * 1000}),
    })


# ── `rag related <path>` ──────────────────────────────────────────────────────
# Wrap CLI de `find_related` para que el plugin de Obsidian tenga un fallback
# si el web server (puerto local) está caído. El plugin hace HTTP primero,
# spawnea este comando si falla. También sirve para shell scripting puntual
# ("dame las relacionadas a esta nota en JSON pa pipearlo a jq").
#
# El comportamiento es paralelo al endpoint GET /api/notes/related: misma
# función Python, mismo shape de output, mismas razones de empty-result
# ("empty_index", "not_indexed"). Si tocás uno y no el otro, el fallback
# del plugin va a divergir silenciosamente.
@cli.command()
@click.argument("path")
@click.option("--limit", default=10, show_default=True,
              help="Cantidad de notas relacionadas a devolver (1-50).")
@click.option("--json", "as_json", is_flag=True,
              help="Salida JSON (consumido por el plugin Obsidian / scripts).")
@click.option("--plain", is_flag=True,
              help="Salida tabular sin colores ni paneles (script-friendly).")
def related(path: str, limit: int, as_json: bool, plain: bool):
    """Notas relacionadas a PATH por shared tags + graph hops.

    PATH es vault-relative (ej. 02-Areas/Coaching/Autoridad.md). El ranking
    combina tags compartidos + edges del grafo (outlinks + backlinks), con
    tie-break por top-level folder en común. Cada item devuelve un `score`
    (entero) y un `reason` ('tags', 'link', 'tags+link') para que el UI
    decida cómo presentarlo.
    """
    t0 = time.perf_counter()
    if not path.endswith(".md"):
        msg = "path debe terminar en .md"
        if as_json:
            click.echo(json.dumps({"error": msg, "items": [], "source_path": path}))
        else:
            console.print(f"[red]Error: {msg}[/red]")
        sys.exit(2)

    limit = max(1, min(int(limit), 50))
    col = get_db()
    if col.count() == 0:
        payload = {"items": [], "source_path": path, "reason": "empty_index"}
        if as_json:
            click.echo(json.dumps(payload, ensure_ascii=False))
        else:
            console.print("[yellow]Índice vacío. Corré `rag index` primero.[/yellow]")
        return

    # Pasamos TODOS los chunks de la nota source — find_related agrega tags +
    # títulos por toda la lista. Ver comentario equivalente en
    # web/server.py:notes_related para la justificación detallada.
    c = _load_corpus(col)
    source_metas = [m for m in c["metas"] if m.get("file") == path]
    if not source_metas:
        payload = {"items": [], "source_path": path, "reason": "not_indexed"}
        if as_json:
            click.echo(json.dumps(payload, ensure_ascii=False))
        else:
            console.print(f"[yellow]La nota '{path}' no está en el índice.[/yellow]")
        return

    src_tags: set[str] = set()
    for m in source_metas:
        for t in (m.get("tags") or "").split(","):
            t = t.strip()
            if t:
                src_tags.add(t)

    results = find_related(col, source_metas, limit=limit)
    items: list[dict] = []
    for meta, score, reason in results:
        nei_tags = [
            t.strip() for t in (meta.get("tags") or "").split(",") if t.strip()
        ]
        items.append({
            "path": meta.get("file", ""),
            "note": meta.get("note", ""),
            "folder": meta.get("folder", ""),
            "tags": nei_tags,
            "shared_tags": sorted(src_tags.intersection(nei_tags)),
            "score": int(score),
            "reason": reason,
        })

    log_query_event({
        "cmd": "related", "path": path, "n_results": len(items),
        "limit": limit,
        "timing": _round_timing_ms({"total_ms": (time.perf_counter() - t0) * 1000}),
    })

    if as_json:
        click.echo(json.dumps(
            {"items": items, "source_path": path}, ensure_ascii=False,
        ))
        return

    if not items:
        msg = f"Sin notas relacionadas a {path}"
        click.echo(msg) if plain else console.print(f"[dim]{msg}[/dim]")
        return

    if plain:
        # Formato tabular: SCORE  REASON       PATH
        # Pensado para `rag related X --plain | awk` y similar.
        for it in items:
            click.echo(f"{it['score']}\t{it['reason']:<10}\t{it['path']}")
        return

    console.print()
    console.print(Rule(
        title=(
            f"[bold cyan]🔗 {len(items)} nota(s) relacionada(s) a "
            f"[magenta]{path}[/magenta][/bold cyan]"
        ),
        style="cyan",
    ))
    for it in items:
        reason_color = {
            "link": "green", "tags": "yellow", "tags+link": "cyan",
        }.get(it["reason"], "dim")
        console.print()
        console.print(
            f"[bold]{it['score']}[/bold] "
            f"[{reason_color}]· {it['reason']}[/{reason_color}]  "
            f"[magenta]{it['note']}[/magenta] "
            f"[dim]({it['path']})[/dim]"
        )
        if it["shared_tags"]:
            tags_str = " ".join(f"#{t}" for t in it["shared_tags"])
            console.print(f"   [dim]tags: {tags_str}[/dim]")


# ── `rag contradictions <path>` ──────────────────────────────────────────────
# Wrap CLI de `find_contradictions_for_note`. Paralelo al endpoint HTTP
# `/api/notes/contradictions` — mismo shape, mismas razones de empty-
# result. Usado como fallback por el plugin Obsidian cuando el web
# server está caído, y como utility de debugging manual.
@cli.command()
@click.argument("path")
@click.option("--limit", default=5, show_default=True,
              help="Cantidad máxima de contradicciones a devolver (1-10).")
@click.option("--json", "as_json", is_flag=True,
              help="Salida JSON (consumido por el plugin Obsidian / scripts).")
@click.option("--plain", is_flag=True,
              help="Salida tabular sin colores ni paneles (script-friendly).")
def contradictions(path: str, limit: int, as_json: bool, plain: bool):
    """Posibles contradicciones entre PATH y otras notas del vault.

    PATH es vault-relative (ej. 02-Areas/Coaching/Autoridad.md). Detecta
    fragmentos de OTRAS notas que contradicen afirmaciones de PATH. El
    LLM es conservador — raramente devuelve más de 2-3 resultados.

    Performance: 5-10s por call (chat model bound). El plugin cachea
    por 30 min.
    """
    t0 = time.perf_counter()
    if not path.endswith(".md"):
        msg = "path debe terminar en .md"
        if as_json:
            click.echo(json.dumps(
                {"error": msg, "items": [], "source_path": path},
            ))
        else:
            console.print(f"[red]Error: {msg}[/red]")
        sys.exit(2)

    limit = max(1, min(int(limit), 10))
    col = get_db()
    if col.count() == 0:
        payload = {"items": [], "source_path": path, "reason": "empty_index"}
        if as_json:
            click.echo(json.dumps(payload, ensure_ascii=False))
        else:
            console.print(
                "[yellow]Índice vacío. Corré `rag index` primero.[/yellow]"
            )
        return

    # Leer el body. Mismo preguard que el endpoint HTTP — body corto
    # retorna reason=too_short, no lista vacía sin contexto.
    note_path = VAULT_PATH / path
    if not note_path.is_file():
        payload = {"items": [], "source_path": path, "reason": "not_found"}
        if as_json:
            click.echo(json.dumps(payload, ensure_ascii=False))
        else:
            console.print(f"[yellow]Nota no encontrada: {path}[/yellow]")
        return
    body = note_path.read_text(encoding="utf-8", errors="ignore")
    if len(body.strip()) < 200:
        payload = {"items": [], "source_path": path, "reason": "too_short"}
        if as_json:
            click.echo(json.dumps(payload, ensure_ascii=False))
        else:
            console.print(
                "[yellow]Nota muy corta (<200 chars) para analizar "
                "contradicciones.[/yellow]"
            )
        return

    results = find_contradictions_for_note(
        col, body, exclude_paths={path}, k=limit,
    )
    items: list[dict] = []
    for r in results:
        p = r.get("path", "")
        folder = "/".join(p.split("/")[:-1]) if "/" in p else ""
        items.append({
            "path": p,
            "note": r.get("note", ""),
            "folder": folder,
            "snippet": r.get("snippet", ""),
            "why": r.get("why", ""),
        })

    log_query_event({
        "cmd": "contradictions", "path": path, "n_results": len(items),
        "limit": limit,
        "timing": _round_timing_ms(
            {"total_ms": (time.perf_counter() - t0) * 1000},
        ),
    })

    if as_json:
        click.echo(json.dumps(
            {"items": items, "source_path": path}, ensure_ascii=False,
        ))
        return

    if not items:
        msg = f"Sin contradicciones detectadas en {path}"
        click.echo(msg) if plain else console.print(f"[green]✓ {msg}[/green]")
        return

    if plain:
        # Formato tabular: PATH \t WHY
        for it in items:
            click.echo(f"{it['path']}\t{it['why']}")
        return

    console.print()
    console.print(Rule(
        title=(
            f"[bold yellow]⚠ {len(items)} posible(s) contradicción(es) "
            f"en [magenta]{path}[/magenta][/bold yellow]"
        ),
        style="yellow",
    ))
    for it in items:
        console.print()
        console.print(
            f"[magenta]{it['note']}[/magenta] "
            f"[dim]({it['path']})[/dim]"
        )
        if it["why"]:
            console.print(f"   [yellow]→[/yellow] [italic]{it['why']}[/italic]")
        if it["snippet"]:
            snip = it["snippet"][:200]
            console.print(f"   [dim]{snip}[/dim]")


# ── `rag loops <path>` ───────────────────────────────────────────────────────
# Wrap CLI de `_extract_followup_loops`. Paralelo al endpoint HTTP
# `/api/notes/loops` — mismo shape, mismas razones de empty-result.
# Cheap: sin LLM, sin embed, solo regex + frontmatter parse. Apto
# para uso reactive desde el plugin Obsidian (panel "Loops abiertos")
# o como debugging manual.
@cli.command()
@click.argument("path")
@click.option("--limit", default=50, show_default=True,
              help="Cantidad máxima de loops a devolver (1-100).")
@click.option("--json", "as_json", is_flag=True,
              help="Salida JSON (consumido por el plugin Obsidian / scripts).")
@click.option("--plain", is_flag=True,
              help="Salida tabular sin colores (script-friendly).")
def loops(path: str, limit: int, as_json: bool, plain: bool):
    """Loops abiertos (TODOs sin cerrar) en PATH.

    PATH es vault-relative. Detecta:
      - todos en frontmatter (kind=todo).
      - checkboxes `- [ ]` sin marcar (kind=checkbox).
      - clausulas imperativas en el body (kind=inline).

    Cheap (sin LLM). Si querés clasificar resolved/stale/activo del
    vault completo, mirá `rag pendientes`.
    """
    if not path.endswith(".md"):
        msg = "path debe terminar en .md"
        if as_json:
            click.echo(json.dumps(
                {"error": msg, "items": [], "source_path": path},
            ))
        else:
            console.print(f"[red]Error: {msg}[/red]")
        sys.exit(2)

    limit = max(1, min(int(limit), 100))
    note_path = VAULT_PATH / path
    if not note_path.is_file():
        payload = {"items": [], "source_path": path, "reason": "not_found"}
        if as_json:
            click.echo(json.dumps(payload, ensure_ascii=False))
        else:
            console.print(f"[yellow]Nota no encontrada: {path}[/yellow]")
        return

    raw = note_path.read_text(encoding="utf-8", errors="ignore")
    extracted_ts = _note_created_ts(raw, note_path.stat().st_mtime)
    loops = _extract_followup_loops(raw, path, extracted_ts)
    now = datetime.now()
    items: list[dict] = []
    for loop in loops[:limit]:
        try:
            ex_dt = datetime.fromisoformat(loop.get("extracted_at", ""))
            if ex_dt.tzinfo is not None:
                ex_dt = ex_dt.astimezone().replace(tzinfo=None)
            age_days = max(0, (now - ex_dt).days)
        except Exception:
            age_days = 0
        items.append({
            "loop_text": loop.get("loop_text", ""),
            "kind": loop.get("kind", "inline"),
            "age_days": age_days,
            "extracted_at": loop.get("extracted_at", ""),
        })

    if as_json:
        click.echo(json.dumps(
            {"items": items, "source_path": path}, ensure_ascii=False,
        ))
        return

    if not items:
        msg = f"Sin loops abiertos en {path}"
        click.echo(msg) if plain else console.print(f"[green]✓ {msg}[/green]")
        return

    if plain:
        # Formato tabular: AGE_DAYS \t KIND \t TEXT
        for it in items:
            click.echo(f"{it['age_days']}\t{it['kind']}\t{it['loop_text']}")
        return

    console.print()
    console.print(Rule(
        title=(
            f"[bold cyan]✎ {len(items)} loop(s) en "
            f"[magenta]{path}[/magenta][/bold cyan]"
        ),
        style="cyan",
    ))
    for it in items:
        kind_color = {
            "todo": "magenta", "checkbox": "cyan", "inline": "yellow",
        }.get(it["kind"], "dim")
        age_color = "red" if it["age_days"] > 14 else (
            "yellow" if it["age_days"] > 7 else "green"
        )
        console.print()
        console.print(
            f"[{age_color}]{it['age_days']}d[/{age_color}] "
            f"[{kind_color}]· {it['kind']}[/{kind_color}]  "
            f"{it['loop_text']}"
        )


@cli.command()
@click.option("--threshold", default=0.85, show_default=True,
              help="Cosine mínimo para considerar duplicado (sobre centroides)")
@click.option("--folder", default=None, help="Acotar a este folder")
@click.option("--limit", default=50, show_default=True,
              help="Top N pares a mostrar")
@click.option("--plain", is_flag=True, help="Salida plana sin colores")
def dupes(threshold: float, folder: str | None, limit: int, plain: bool):
    """Buscar pares de notas potencialmente duplicadas (centroides similares)."""
    t0 = time.perf_counter()
    pairs = find_duplicate_notes(col=get_db(), threshold=threshold, folder=folder, limit=limit)
    if not pairs:
        msg = f"Sin pares con cosine ≥ {threshold}."
        click.echo(msg) if plain else console.print(f"[yellow]{msg}[/yellow]")
        return
    if plain:
        for p in pairs:
            click.echo(f"{p['similarity']:.2f}  {p['a_path']}  ↔  {p['b_path']}")
        return
    console.print()
    console.print(Rule(
        title=f"[bold yellow]🔁 {len(pairs)} par(es) sospechoso(s) (cosine ≥ {threshold})[/bold yellow]",
        style="yellow",
    ))
    for p in pairs:
        console.print()
        console.print(
            f"[bold]{p['similarity']:.3f}[/bold]  "
            f"[magenta]{p['a_note']}[/magenta] "
            f"[dim]({p['a_path']})[/dim]"
        )
        console.print(
            f"      ↔  [magenta]{p['b_note']}[/magenta] "
            f"[dim]({p['b_path']})[/dim]"
        )
        if p.get("snippet_a"):
            console.print(f"      [dim]A:[/dim] [dim italic]{p['snippet_a'][:140]}[/dim italic]")
        if p.get("snippet_b"):
            console.print(f"      [dim]B:[/dim] [dim italic]{p['snippet_b'][:140]}[/dim italic]")
    log_query_event({
        "cmd": "dupes", "threshold": threshold, "folder": folder,
        "n_pairs": len(pairs),
        "timing": _round_timing_ms({"total_ms": (time.perf_counter() - t0) * 1000}),
    })


@cli.command()
@click.option("--sim-threshold", default=0.78, show_default=True,
              help="Cosine mínimo entre centroides para considerar un par")
@click.option("--min-hops", default=3, show_default=True,
              help="Distancia mínima en el grafo (≥3 = ni vecinos ni vecinos-de-vecinos)")
@click.option("--top", default=5, show_default=True,
              help="Máximo de puentes a proponer por corrida")
@click.option("--skip-young-days", default=7, show_default=True,
              help="Ignorar notas más nuevas que este umbral (siguen evolucionando)")
@click.option("--no-llm", is_flag=True,
              help="No generar 'por qué' (más rápido, útil para debugging)")
@click.option("--plain", is_flag=True, help="Salida plana sin colores")
def surface(sim_threshold: float, min_hops: int, top: int,
            skip_young_days: int, no_llm: bool, plain: bool):
    """Puentes no hechos: pares de notas cercanas en significado pero lejanas en el grafo.

    Corrida proactiva — ideal como cron nocturno antes del morning brief, o manual
    cuando querés densificar el grafo. Cada corrida loguea a surface.jsonl para
    después alimentar el ranker del feedback loop.
    """
    import time as _time
    t0 = _time.time()
    pairs = find_surface_bridges(
        col=get_db(),
        sim_threshold=sim_threshold,
        min_hops=min_hops,
        top=top,
        skip_young_days=skip_young_days,
    )
    duration_ms = int((_time.time() - t0) * 1000)

    if not pairs:
        msg = f"Sin puentes con cosine ≥ {sim_threshold} y dist ≥ {min_hops}. Bajá --sim-threshold si querés explorar."
        click.echo(msg) if plain else console.print(f"[yellow]{msg}[/yellow]")
        _surface_log_run({
            "n_pairs": 0, "sim_threshold": sim_threshold, "min_hops": min_hops,
            "top": top, "skip_young_days": skip_young_days, "llm": not no_llm,
            "duration_ms": duration_ms,
        }, [])
        return

    if not no_llm:
        for p in pairs:
            p["reason"] = _surface_generate_reason(p)
    duration_ms = int((_time.time() - t0) * 1000)

    _surface_log_run({
        "n_pairs": len(pairs), "sim_threshold": sim_threshold,
        "min_hops": min_hops, "top": top, "skip_young_days": skip_young_days,
        "llm": not no_llm, "duration_ms": duration_ms,
    }, pairs)

    if plain:
        for i, p in enumerate(pairs, 1):
            click.echo(f"{i}. {p['similarity']:.2f}  {p['a_path']}  ↔  {p['b_path']}")
            if p.get("reason"):
                click.echo(f"   {p['reason']}")
        return

    console.print()
    console.print(Rule(
        title=f"[bold magenta]🔗 {len(pairs)} puente(s) sugerido(s) (cosine ≥ {sim_threshold}, hops ≥ {min_hops})[/bold magenta]",
        style="magenta",
    ))
    for i, p in enumerate(pairs, 1):
        console.print()
        console.print(
            f"[bold]{i}.[/bold] [bold]{p['similarity']:.3f}[/bold]  "
            f"[magenta]{p['a_note']}[/magenta] [dim]({p['a_path']})[/dim]"
        )
        console.print(
            f"     ↔  [magenta]{p['b_note']}[/magenta] [dim]({p['b_path']})[/dim]"
        )
        if p.get("reason"):
            console.print(f"     [cyan]→[/cyan] [italic]{p['reason']}[/italic]")
    console.print()
    console.print(f"[dim]{duration_ms}ms · log: {SURFACE_LOG_PATH}[/dim]")


def _filing_source_label(pr: dict) -> str:
    """Etiqueta corta de la procedencia de la propuesta. Vacía si baseline puro
    (no agregamos ruido visual cuando no hay personalización)."""
    src = pr.get("source", "baseline")
    ev = pr.get("evidence", []) or []
    if src == "agreed":
        return f"agreed · {len(ev)} similar(es) en este folder"
    if src == "personalized":
        return f"personalized · {len(ev)} similar(es) confirman"
    if src == "baseline+history":
        # Hay history pero no convence — útil saberlo (el usuario puede edit).
        return "baseline · history apunta a otros folders"
    return ""


def _render_filing_proposal(i: int, total: int, pr: dict, plain: bool) -> None:
    """Renderer compartido por dry-run y apply. Muestra una propuesta; no pide
    input ni decide — solo layout."""
    if plain:
        if "error" in pr:
            click.echo(f"[{i}/{total}] {pr['path']}  [error: {pr['error']}]")
            return
        conf = pr["confidence"]
        tag = ("firm" if conf >= FILING_CONFIDENCE_FIRM
               else "tentative" if conf >= FILING_CONFIDENCE_TENTATIVE
               else "low")
        click.echo(f"[{i}/{total}] {pr['note']}  ({pr['path']})")
        target = pr["folder"] or "(sin propuesta)"
        line = f"         -> {target}  (conf {conf:.2f}, {tag})"
        src_label = _filing_source_label(pr)
        if src_label:
            line += f"  [{src_label}]"
        click.echo(line)
        if pr["upward_title"]:
            click.echo(f"         ^ [[{pr['upward_title']}]] ({pr['upward_kind']})")
        return
    if "error" in pr:
        console.print(
            f"\n[bold]{i}/{total}[/bold] [red]{pr['path']}[/red] "
            f"[dim](error: {pr['error']})[/dim]"
        )
        return
    console.print(
        f"\n[bold]{i}/{total}[/bold] [bold]{pr['note']}[/bold] "
        f"[dim]({pr['path']})[/dim]"
    )
    conf = pr["confidence"]
    if conf >= FILING_CONFIDENCE_FIRM:
        style, label = "green", f"firm · {conf:.2f}"
    elif conf >= FILING_CONFIDENCE_TENTATIVE:
        style, label = "yellow", f"tentative · {conf:.2f}"
    else:
        style, label = "red", f"low · {conf:.2f}"
    target = pr["folder"] or "(sin propuesta)"
    src_label = _filing_source_label(pr)
    src_style = {
        "agreed · ": "green dim",
        "personalized · ": "magenta dim",
        "baseline · ": "yellow dim",
    }
    src_color = "dim"
    for prefix, color in src_style.items():
        if src_label.startswith(prefix.rstrip()):
            src_color = color
            break
    line = (
        f"   [cyan]→[/cyan] [bold]{target}[/bold] "
        f"[dim]·[/dim] [{style}]{label}[/{style}]"
    )
    if src_label:
        line += f"  [{src_color}]· {src_label}[/{src_color}]"
    console.print(line)
    if pr["upward_title"]:
        badge = "📍 MOC" if pr["upward_kind"] == "moc" else "↔ nearest"
        console.print(
            f"   [cyan]↑[/cyan] [[[magenta]{pr['upward_title']}[/magenta]]] "
            f"[dim]{badge}[/dim]"
        )


@cli.command(name="file")
@click.argument("path", required=False)
@click.option("--folder", default="00-Inbox", show_default=True,
              help="Folder a escanear si no pasás path")
@click.option("--one", is_flag=True, help="Solo la nota más vieja del inbox")
@click.option("--limit", default=20, show_default=True,
              help="Máximo de notas a procesar por corrida")
@click.option("-k", "k", default=8, show_default=True,
              help="Cantidad de vecinos semánticos a considerar")
@click.option("--apply", "do_apply", is_flag=True,
              help="Modo interactivo: mover + upward-link + reindex con confirmación y/n/e/s/q")
@click.option("--undo", "do_undo", is_flag=True,
              help="Revertir el último batch de --apply (lee filing_batches/)")
@click.option("--plain", is_flag=True, help="Salida plana sin colores")
def file_cmd(path: str | None, folder: str, one: bool, limit: int,
             k: int, do_apply: bool, do_undo: bool, plain: bool):
    """Filing asistido de Inbox: destino PARA + upward-link sugeridos.

    Sin flags: dry-run (propone y loguea, no mueve nada).
    --apply:   interactivo — y/n/e(edit)/s(skip)/q(quit) por nota.
    --undo:    revierte el último batch aplicado.

    Contrato de seguridad: --apply mueve archivos solo tras tu 'y'. Cada
    move se persiste en filing_batches/<ts>.jsonl para que --undo sepa
    exactamente qué revertir. Edit permite cambiar el folder destino sin
    volver a sugerir desde cero.
    """
    col = get_db()

    if do_apply and do_undo:
        msg = "No podés combinar --apply y --undo."
        click.echo(msg) if plain else console.print(f"[red]{msg}[/red]")
        return

    # ── UNDO path ────────────────────────────────────────────────────────────
    if do_undo:
        batch = _last_filing_batch()
        if batch is None:
            msg = "No hay batches previos para revertir."
            click.echo(msg) if plain else console.print(f"[yellow]{msg}[/yellow]")
            return
        results = _rollback_filing_batch(col, batch)
        ok = sum(1 for r in results if r.get("ok"))
        fail = len(results) - ok
        # Renombrar el batch a .undone para trazabilidad sin borrar.
        try:
            batch.rename(batch.with_suffix(".undone"))
        except Exception:
            pass
        if plain:
            click.echo(f"undo: {ok} movido(s) de vuelta, {fail} error(es). batch: {batch.name}")
            for r in results:
                status = "✓" if r.get("ok") else f"✗ {r.get('error', '')}"
                click.echo(f"  {status}  {r['dst']} -> {r['src']}")
            return
        console.print()
        console.print(Rule(
            title=f"[bold magenta]↩ undo: {ok} movido(s) de vuelta, {fail} error(es)[/bold magenta]",
            style="magenta",
        ))
        for r in results:
            if r.get("ok"):
                console.print(f"  [green]✓[/green] [dim]{r['dst']}[/dim] → [cyan]{r['src']}[/cyan]")
            else:
                console.print(f"  [red]✗[/red] {r['dst']}  [dim]({r.get('error','?')})[/dim]")
        console.print(f"\n[dim]batch renombrado a {batch.with_suffix('.undone').name}[/dim]")
        return

    # ── Collect target notes ─────────────────────────────────────────────────
    if path:
        full = Path(path) if path.startswith("/") else VAULT_PATH / path
        notes = [full] if full.is_file() else []
        if not notes:
            msg = f"No existe: {full}"
            click.echo(msg) if plain else console.print(f"[red]{msg}[/red]")
            return
    else:
        inbox_dir = VAULT_PATH / folder
        if not inbox_dir.is_dir():
            msg = f"No existe el folder: {inbox_dir}"
            click.echo(msg) if plain else console.print(f"[red]{msg}[/red]")
            return
        notes = sorted(inbox_dir.glob("*.md"), key=lambda p: p.stat().st_mtime)
        notes = notes[:1] if one else notes[:limit]

    if not notes:
        msg = f"Sin notas en {folder}."
        click.echo(msg) if plain else console.print(f"[yellow]{msg}[/yellow]")
        return

    # Frontmatter opt-out: file: skip respeta la elección del usuario.
    eligible: list[Path] = []
    skipped_by_fm: list[str] = []
    for p in notes:
        try:
            raw = p.read_text(encoding="utf-8", errors="ignore")
            fm = parse_frontmatter(raw)
            if fm.get("file") == "skip":
                skipped_by_fm.append(str(p.relative_to(VAULT_PATH)))
                continue
        except Exception:
            pass
        eligible.append(p)

    if skipped_by_fm and not plain:
        console.print(
            f"[dim]Skip por frontmatter `file: skip`: {len(skipped_by_fm)}[/dim]"
        )

    if not eligible:
        msg = "Todas las notas tienen `file: skip` en frontmatter."
        click.echo(msg) if plain else console.print(f"[yellow]{msg}[/yellow]")
        return

    # ── Build proposals ──────────────────────────────────────────────────────
    # Cargamos history una vez por batch — evita releer filing.jsonl N veces.
    # Si está bajo el umbral, igual se pasa (build_filing_proposal lo ignora).
    history = _load_filing_decisions()
    if not plain and len(history) >= FILING_PERSONALIZE_MIN_HISTORY:
        console.print(
            f"[dim]Personalización activa · {len(history)} decisión(es) en history[/dim]"
        )

    proposals: list[tuple[Path, dict]] = []
    for p in eligible:
        rel = str(p.relative_to(VAULT_PATH))
        prop = build_filing_proposal(col, rel, k=k, history=history)
        proposals.append((p, prop))

    # ── Dry-run path: print + log, bail ──────────────────────────────────────
    if not do_apply:
        if not plain:
            console.print()
            console.print(Rule(
                title=f"[bold magenta]📥 {len(proposals)} propuesta(s) de filing[/bold magenta]",
                style="magenta",
            ))
        for i, (_, pr) in enumerate(proposals, 1):
            _render_filing_proposal(i, len(proposals), pr, plain)
            _filing_log_proposal(pr)
        if plain:
            click.echo(f"\nlog: {FILING_LOG_PATH}")
        else:
            console.print(
                f"\n[dim]Dry-run — nada se movió. Log: {FILING_LOG_PATH}[/dim]\n"
                f"[dim]Correr con --apply para mover interactivo.[/dim]"
            )
        return

    # ── Apply path: interactive loop ─────────────────────────────────────────
    if not plain:
        console.print()
        console.print(Rule(
            title=f"[bold magenta]📥 Apply: {len(proposals)} nota(s) · y/n/e/s/q[/bold magenta]",
            style="magenta",
        ))

    try:
        with vault_write_lock("file --apply", blocking=False):
            batch_entries: list[dict] = []
            batch_path = _open_filing_batch()
            for i, (src_path, pr) in enumerate(proposals, 1):
                _render_filing_proposal(i, len(proposals), pr, plain)
                if "error" in pr:
                    _filing_log_proposal(pr, decision="error")
                    continue

                target = pr["folder"]
                if not target:
                    # Sin propuesta de folder → solo edit o skip.
                    choice = click.prompt("   [e]dit target / [s]kip / [q]uit",
                                          default="s", show_default=False).strip().lower()
                else:
                    choice = click.prompt(
                        "   [y]es · [n]o · [e]dit · [s]kip · [q]uit",
                        default="y", show_default=False,
                    ).strip().lower()

                if choice == "q":
                    _filing_log_proposal(pr, decision="quit")
                    click.echo("Quit — guardando batch con lo aplicado hasta ahora.") if plain else console.print("[dim]Quit — guardando batch con lo aplicado hasta ahora.[/dim]")
                    break
                if choice in ("s", "skip"):
                    _filing_log_proposal(pr, decision="skip")
                    continue
                if choice in ("n", "no"):
                    _filing_log_proposal(pr, decision="reject")
                    continue
                if choice in ("e", "edit"):
                    new_target = click.prompt("   Nuevo folder (vault-relative, ej 02-Areas/Salud)").strip()
                    if not new_target:
                        _filing_log_proposal(pr, decision="skip")
                        continue
                    target = new_target
                    decision = "edit"
                else:
                    # 'y' o default
                    if not target:
                        _filing_log_proposal(pr, decision="skip")
                        continue
                    decision = "accept"

                # Ejecutar move + upward-link + reindex.
                try:
                    entry = _apply_filing_move(col, pr["path"], target, pr.get("upward_title") or "")
                except FileExistsError as ex:
                    msg = f"   [destino ya existe: {ex}] skip"
                    click.echo(msg) if plain else console.print(f"[red]{msg}[/red]")
                    _filing_log_proposal(pr, decision="error")
                    continue
                except Exception as ex:
                    msg = f"   [error: {ex}] skip"
                    click.echo(msg) if plain else console.print(f"[red]{msg}[/red]")
                    _filing_log_proposal(pr, decision="error")
                    continue

                batch_entries.append(entry)
                _append_filing_batch(batch_path, entry)
                logged = dict(pr)
                logged["applied_to"] = entry["dst"]
                _filing_log_proposal(logged, decision=decision)
                if plain:
                    click.echo(f"   ✓ {entry['src']} -> {entry['dst']}")
                else:
                    console.print(f"   [green]✓[/green] movido a [cyan]{entry['dst']}[/cyan]")

            if not batch_entries:
                batch_path.unlink(missing_ok=True)
                batch_path = None

            if plain:
                click.echo(f"\n{len(batch_entries)} aplicada(s).")
                if batch_path:
                    click.echo(f"batch: {batch_path}  (rag file --undo para revertir)")
            else:
                console.print()
                if batch_entries:
                    console.print(
                        f"[green]✓ {len(batch_entries)} aplicada(s).[/green] "
                        f"[dim]batch: {batch_path.name if batch_path else '(ninguno)'}[/dim]"
                    )
                    console.print("[dim]`rag file --undo` revierte este batch.[/dim]")
                else:
                    console.print("[yellow]Nada aplicado.[/yellow]")
    except RuntimeError as ex:
        msg = f"{ex}  — probá otra vez cuando termine el otro proceso."
        click.echo(msg) if plain else console.print(f"[red]{msg}[/red]")


@cli.command()
@click.option("--folder", default="00-Inbox", show_default=True,
              help="Folder de Inbox a triar")
@click.option("--apply", is_flag=True,
              help="Mover + taggear + linkificar (default = dry-run)")
@click.option("--max-tags", default=5, show_default=True)
@click.option("--limit", default=20, show_default=True,
              help="Máximo de notas a procesar por corrida")
@click.option("--folder-min-conf", default=0.4, show_default=True,
              help="Confianza mínima para mover (--apply)")
@click.option("--no-folder", is_flag=True, help="No sugerir destino")
@click.option("--no-tags", is_flag=True, help="No sugerir tags")
@click.option("--no-wikilinks", is_flag=True, help="No sugerir wikilinks")
def inbox(folder: str, apply: bool, max_tags: int, limit: int,
          folder_min_conf: float, no_folder: bool, no_tags: bool,
          no_wikilinks: bool):
    """Triar notas de Inbox: sugerir destino + tags + wikilinks + duplicados.

    Compone retrieve (vecino semántico para folder), autotag, find_wikilink_
    suggestions y find_near_duplicates_for. Con --apply mueve cada nota a su
    destino sugerido (si la confianza supera --folder-min-conf), agrega los
    tags nuevos al frontmatter, aplica los wikilinks y re-indexa.
    """
    inbox_dir = VAULT_PATH / folder
    if not inbox_dir.is_dir():
        console.print(f"[red]No existe el folder:[/red] {inbox_dir}")
        return
    notes = sorted(inbox_dir.glob("*.md"))[:limit]
    if not notes:
        console.print(f"[yellow]Sin notas en {folder}.[/yellow]")
        return

    col = get_db()
    if apply:
        try:
            _inbox_lock = vault_write_lock("inbox --apply", blocking=False)
            _inbox_lock.__enter__()
        except RuntimeError as ex:
            console.print(f"[red]{ex}  — probá otra vez cuando termine el otro proceso.[/red]")
            return
    else:
        _inbox_lock = None
    moved = 0
    tagged = 0
    linkified = 0
    flagged_dupes = 0
    for path in notes:
        rel = str(path.relative_to(VAULT_PATH))
        try:
            t = triage_inbox_note(col, rel, max_tags=max_tags)
        except Exception as e:
            console.print(f"[red]Error en {rel}: {e}[/red]")
            continue

        console.print()
        console.print(Rule(style="dim", characters="╌"))
        console.print(f"[bold cyan]{rel}[/bold cyan]")

        if not no_folder and t.get("folder_suggested"):
            conf = t["folder_confidence"]
            color = "green" if conf >= folder_min_conf else "yellow"
            console.print(
                f"  📁 destino: [{color}]{t['folder_suggested']}[/{color}] "
                f"[dim]({conf:.2f} conf)[/dim]"
            )
        if not no_tags and t.get("tags_new"):
            console.print(
                f"  🏷  tags nuevos: [yellow]{', '.join(t['tags_new'])}[/yellow] "
                f"[dim](actuales: {', '.join(t['tags_current']) or '—'})[/dim]"
            )
        if not no_wikilinks and t.get("wikilinks"):
            wl_titles = [w["title"] for w in t["wikilinks"][:6]]
            extra = len(t["wikilinks"]) - len(wl_titles)
            extras_str = f" [dim]+{extra} más[/dim]" if extra > 0 else ""
            console.print(
                f"  🔗 wikilinks: [magenta]{', '.join(wl_titles)}[/magenta]{extras_str}"
            )
        for d in (t.get("duplicates") or []):
            flagged_dupes += 1
            console.print(
                f"  ⚠  posible duplicado: [red]{d['note']}[/red] "
                f"[dim]({d['path']}, sim {d['similarity']})[/dim]"
            )

        if not apply:
            continue

        # Apply: move (only if confidence ≥ min), tag, linkify, reindex.
        target_path = path
        if not no_folder and t.get("folder_suggested") and t["folder_confidence"] >= folder_min_conf:
            target_dir = VAULT_PATH / t["folder_suggested"]
            target_dir.mkdir(parents=True, exist_ok=True)
            candidate = target_dir / path.name
            if candidate.exists():
                console.print("  [red]✗ destino ya existe, no muevo[/red]")
            else:
                import shutil
                shutil.move(str(path), str(candidate))
                # Drop chunks of the old path; the new path will be added below.
                _index_single_file(col, path, skip_contradict=True)
                target_path = candidate
                moved += 1
                console.print(
                    f"  [green]✓ movido a {target_path.relative_to(VAULT_PATH)}[/green]"
                )

        if not no_tags and t.get("tags_new"):
            merged = list(dict.fromkeys([*t["tags_current"], *t["tags_new"]]))[:max_tags]
            if _apply_frontmatter_tags(target_path, merged):
                tagged += 1
                console.print("  [green]✓ tags actualizados[/green]")

        if not no_wikilinks:
            # Recompute against the (possibly new) path; the file content may
            # have shifted offsets after the tag-write above.
            new_rel = str(target_path.relative_to(VAULT_PATH))
            fresh = find_wikilink_suggestions(col, new_rel, max_per_note=10)
            if fresh:
                n, _ = apply_wikilink_suggestions(new_rel, fresh)
                if n:
                    linkified += 1
                    console.print(f"  [green]✓ {n} wikilinks aplicados[/green]")

        # Final reindex picks up moved path + tag/wikilink edits in one pass.
        try:
            _index_single_file(col, target_path, skip_contradict=True)
        except Exception:
            pass

    console.print()
    if apply:
        console.print(
            f"[green]✓ Triaje aplicado:[/green] "
            f"{moved} movidas · {tagged} tags actualizados · "
            f"{linkified} con wikilinks · {flagged_dupes} dupes flaggeados"
        )
        if _inbox_lock is not None:
            _inbox_lock.__exit__(None, None, None)
    else:
        console.print(
            f"[cyan]Plan generado para {len(notes)} nota(s).[/cyan] "
            f"[dim]Re-correr con --apply para ejecutar.[/dim]"
        )


def _slug(text: str, maxlen: int = 50) -> str:
    """Slugify for filenames: lowercase, alphanum + hyphens, capped."""
    s = re.sub(r"[^a-z0-9]+", "-", text.lower()).strip("-")
    return s[:maxlen] or "topic"


@cli.command()
@click.argument("topic")
@click.option("-k", default=8, show_default=True,
              help="Chunks de contexto principal a recuperar")
@click.option("--folder", default=None,
              help="Limitar el contexto a este folder (e.g., '02-Areas/Coaching')")
@click.option("--save", is_flag=True,
              help="Guardar el brief en 00-Inbox/ y auto-indexar")
@click.option("--no-urls", is_flag=True, help="Saltear URLs")
@click.option("--no-related", is_flag=True, help="Saltear notas relacionadas (graph)")
@click.option("--plain", is_flag=True,
              help="Salida plana sin colores/streaming overlay")
def prep(topic: str, k: int, folder: str | None, save: bool,
         no_urls: bool, no_related: bool, plain: bool):
    """Preparar un brief de contexto sobre una persona / proyecto / tema.

    Compone retrieve + find_related + find_urls y le pide a command-r que
    arme un brief estructurado en 1ra persona (background, threads abiertos,
    preguntas para explorar, URLs). Sin --save imprime al terminal; con
    --save escribe `00-Inbox/YYYY-MM-DD-prep-<slug>.md` y lo indexa.
    """
    col = get_db()
    if col.count() == 0:
        msg = "Índice vacío. Ejecuta: rag index"
        click.echo(msg) if plain else console.print(f"[red]{msg}[/red]")
        return

    # 1. Main retrieval — direct topic search.
    main = retrieve(
        col, topic, k=k, folder=folder, tag=None,
        precise=False, multi_query=True, auto_filter=True,
    )
    sources_main = main["metas"]
    if not sources_main:
        msg = f"Sin contexto en el vault para '{topic}'."
        click.echo(msg) if plain else console.print(f"[yellow]{msg}[/yellow]")
        return

    # 2. Graph neighbours of the top sources.
    related = [] if no_related else find_related(col, sources_main, limit=6)

    # 3. URLs scoped to topic — surface bookmarks/refs the brief should mention.
    urls = [] if no_urls else find_urls(topic, k=5, folder=folder)

    # 4. Build the context block. Cap chunk length so the brief stays focused.
    chunks_text = "\n\n---\n\n".join(
        f"[{i+1}] [[{m.get('note','')}]] (ruta: {m.get('file','')})\n{d[:600]}"
        for i, (d, m) in enumerate(zip(main["docs"], sources_main))
    )
    related_text = (
        "\n".join(
            f"- [[{m.get('note','')}]] ({m.get('file','')})  ×{score} {reason}"
            for m, score, reason in related[:6]
        )
        or "(sin relacionadas)"
    )
    urls_text = (
        "\n".join(
            f"- {u['url']}  ({u.get('anchor') or u.get('note','')})"
            for u in urls[:5]
        )
        or "(sin URLs en el vault para esto)"
    )

    # 2026-04-29: cargar el prompt via load_prompt() para que prepend
    # `language_es_AR.v1` (forzar español rioplatense, sin pt/galego leaks).
    # Antes era un literal inline acá sin regla de idioma — vulnerable a
    # que el LLM emitiera portugués cuando el contexto tenía palabras
    # parecidas (reportado el 2026-04-29 con `rag query "Que tenes de
    # Grecia?"` → "Tus notas... falam sobre tua experiência").
    rules = load_prompt("prep", version="v1")
    prompt = (
        f"{rules}\n\n"
        f"TEMA / PERSONA / PROYECTO: {topic}\n\n"
        f"NOTAS RELEVANTES:\n{chunks_text}\n\n"
        f"NOTAS RELACIONADAS (graph):\n{related_text}\n\n"
        f"URLS RELEVANTES:\n{urls_text}\n\n"
        "Generá el brief en Markdown con esta estructura exacta:\n\n"
        f"# Prep: {topic}\n\n"
        "## Resumen ejecutivo\n"
        "(2-3 líneas, lo más importante para entrar en contexto YA)\n\n"
        "## Background\n"
        "(lo que ya sé sobre esto desde mis notas — un párrafo sólido)\n\n"
        "## Threads abiertos\n"
        "(decisiones/acciones pendientes que detectes en las notas; bullets)\n\n"
        "## Preguntas para explorar\n"
        "(qué preguntas valdría hacer/considerar en una conversación sobre "
        "esto; bullets, máximo 5)\n\n"
        "## URLs y fuentes\n"
        "(URLs relevantes literales + lista de notas citadas como [[wikilinks]])\n\n"
        "Mantenete entre 350 y 550 palabras."
    )

    t_start = time.perf_counter()
    parts: list[str] = []
    if plain:
        for chunk in ollama.chat(
            model=resolve_chat_model(),
            messages=[{"role": "user", "content": prompt}],
            options=CHAT_OPTIONS,
            stream=True,
            keep_alive=chat_keep_alive(),
        ):
            parts.append(chunk.message.content)
        # Same WA/TG-friendly link rewrite as `query --plain`.
        click.echo(convert_obsidian_links("".join(parts)))
    else:
        with console.status("[dim]armando brief…[/dim]", spinner="dots"):
            # Drain the stream silently first, then redraw with link styling.
            for chunk in ollama.chat(
                model=resolve_chat_model(),
                messages=[{"role": "user", "content": prompt}],
                options=CHAT_OPTIONS,
                stream=True,
                keep_alive=chat_keep_alive(),
            ):
                parts.append(chunk.message.content)
        full = "".join(parts)
        console.print()
        console.print(render_response(full))

    full = "".join(parts)
    t_gen = time.perf_counter() - t_start

    log_query_event({
        "cmd": "prep", "topic": topic, "folder": folder,
        "n_sources": len(sources_main), "n_related": len(related),
        "n_urls": len(urls), "answer_len": len(full),
        "t_gen": round(t_gen, 2),
        "timing": _round_timing_ms({"total_ms": t_gen * 1000}),
    })

    if save:
        date = datetime.now().strftime("%Y-%m-%d")
        slug = _slug(topic)
        target_dir = VAULT_PATH / "00-Inbox"
        target_dir.mkdir(parents=True, exist_ok=True)
        candidate = target_dir / f"{date}-prep-{slug}.md"
        i = 2
        while candidate.exists():
            candidate = target_dir / f"{date}-prep-{slug}-{i}.md"
            i += 1
        source_links = ", ".join(
            f"'[[{m.get('note','')}]]'" for m in sources_main
        )
        fm = (
            "---\n"
            f"created: {datetime.now().isoformat(timespec='seconds')}\n"
            "type: prep\n"
            f"topic: \"{topic}\"\n"
            "tags: [prep]\n"
            f"sources: [{source_links}]\n"
            "---\n\n"
        )
        candidate.write_text(fm + full + "\n", encoding="utf-8")
        try:
            _index_single_file(col, candidate, skip_contradict=True)
        except Exception:
            pass
        rel = candidate.relative_to(VAULT_PATH)
        click.echo(f"guardado: {rel}") if plain else console.print(
            f"\n[green]✓ Guardado:[/green] [bold cyan]{rel}[/bold cyan]"
        )


@cli.group()
def bookmarks():
    """Indexar bookmarks de Chrome al sub-índice de URLs (rag links)."""


@bookmarks.command("sync")
@click.option("--profile", default=None,
              help="Solo ese Chrome profile (ej: 'Default', 'Profile 1'). "
                   "Omitir = todos los profiles.")
def bookmarks_sync(profile: str | None):
    """Parsear bookmarks de Chrome y escribirlos al sub-índice de URLs.

    Las filas se etiquetan con `source=bookmark` así `rag links <q>` las mezcla
    con las URLs de notas, y podés aislarlas con `rag links <q> --source bookmark`.
    Idempotente: cada profile reemplaza sus filas previas, así nuevos/borrados
    se reflejan al resyncar.
    """
    if not chrome_bookmark_files():
        console.print(
            "[yellow]No encontré Chrome en "
            f"{_chrome_bookmarks_root()}.[/yellow]"
        )
        return
    with console.status("[dim]Sincronizando bookmarks…[/dim]", spinner="dots"):
        stats = sync_chrome_bookmarks(profile=profile)
    if stats["profiles"] == 0:
        console.print(
            f"[yellow]Profile '{profile}' no existe.[/yellow]"
            if profile else "[yellow]No hay profiles con bookmarks.[/yellow]"
        )
        return
    for prof, n in stats["per_profile"].items():
        console.print(f"  [cyan]{prof}[/cyan] · {n} bookmarks")
    console.print(
        f"[green]✓ Total:[/green] {stats['total']} bookmarks en "
        f"{stats['profiles']} profile(s)"
    )


# ── Semantic response cache management (GC#1 2026-04-22) ─────────────────────


@cli.group()
def cache():
    """Semantic response cache — hits para queries repetidas sobre vault unchanged."""


def _cache_telemetry_stats(days: int = 7) -> dict:
    """Cross-reference rag_queries.extra_json against rag_response_cache
    to compute real-world hit rate + miss-reason distribution + saved latency.

    Returns dict::

        {
            "window_days": int,
            "eligible": int,        # rows where cache_probe was populated
            "hits": int,            # rows with extra_json.cache_hit = true
            "hit_rate_pct": float,  # hits / eligible * 100
            "miss_reasons": {reason: count, ...},
            "top_queries": [(question, hit_count), ...],  # from rag_response_cache
            "saved_ms_avg": float,  # avg t_gen_ms of cache misses
            "saved_ms_total": float,  # saved_ms_avg × hits (rough)
        }

    Errors degrade to empty fields — never raises. Used by ``rag cache stats``.
    """
    out: dict = {
        "window_days": days,
        "eligible": 0,
        "hits": 0,
        "hit_rate_pct": 0.0,
        "miss_reasons": {},
        "top_queries": [],
        "saved_ms_avg": 0.0,
        "saved_ms_total": 0.0,
    }
    try:
        with _ragvec_state_conn() as conn:
            # Eligible = rows where cache_probe was populated (the lookup path
            # ran). cache_probe is a JSON object in extra_json; if present
            # AND result != 'skipped'/'disabled' it's a real lookup attempt.
            rows = conn.execute(
                "SELECT json_extract(extra_json, '$.cache_probe.result') AS res,"
                "       json_extract(extra_json, '$.cache_probe.reason') AS reason,"
                "       json_extract(extra_json, '$.cache_hit') AS hit,"
                "       t_gen"
                " FROM rag_queries"
                " WHERE ts > datetime('now', ?)"
                "   AND json_extract(extra_json, '$.cache_probe') IS NOT NULL",
                (f"-{int(days)} days",),
            ).fetchall()
            miss_latencies: list[float] = []
            for res, reason, hit, t_gen in rows:
                # Skip rows where the cache was explicitly disabled or not
                # attempted — they distort hit rate analysis.
                if res in ("skipped", "disabled"):
                    continue
                out["eligible"] += 1
                if hit:
                    out["hits"] += 1
                else:
                    if reason:
                        out["miss_reasons"][reason] = out["miss_reasons"].get(reason, 0) + 1
                    # Only count non-cached t_gen for "saved latency" estimate.
                    # Cached rows have t_gen=0 by construction.
                    if t_gen is not None and float(t_gen) > 0:
                        miss_latencies.append(float(t_gen))
            if out["eligible"] > 0:
                out["hit_rate_pct"] = round(100.0 * out["hits"] / out["eligible"], 2)
            if miss_latencies:
                avg_ms = sum(miss_latencies) / len(miss_latencies) * 1000.0
                out["saved_ms_avg"] = round(avg_ms, 1)
                out["saved_ms_total"] = round(avg_ms * out["hits"], 0)

            # Top cached queries by hit_count — shows which questions are
            # actually benefiting from the cache in production.
            top_rows = conn.execute(
                "SELECT question, hit_count, intent, last_hit_ts"
                " FROM rag_response_cache"
                " WHERE hit_count > 0"
                " ORDER BY hit_count DESC LIMIT 10"
            ).fetchall()
            out["top_queries"] = [
                {
                    "question": q[:80] if q else "",
                    "hit_count": int(hc or 0),
                    "intent": intent,
                    "last_hit_ts": lts,
                }
                for q, hc, intent, lts in top_rows
            ]
    except Exception as exc:
        _log_sql_state_error("cache_telemetry_stats_failed", err=repr(exc))
    return out


@cache.command("stats")
@click.option("--days", default=7, show_default=True, type=int,
              help="Ventana en días para hit-rate telemetry.")
def cache_stats(days: int):
    """Mostrar stats del cache: rows, hits totales, corpus_hashes distintos, edad.

    Incluye además los counters in-process de hit/miss ratios para los caches
    del retrieval pipeline (embed, corpus, feedback_golden, semantic), útil
    para dimensionar LRUs y detectar invalidation triggers agresivos.

    Con `--days N` agrega hit rate real del período desde
    `rag_queries.extra_json.cache_probe` + distribución de miss reasons +
    ahorro de latencia estimado + top queries cacheadas.
    """
    stats = semantic_cache_stats()
    if "error" in stats:
        console.print(f"[red]Error leyendo el cache: {stats['error']}[/red]")
        return
    console.print("[bold]Semantic response cache (persistente, SQL)[/bold]")
    console.print(f"  enabled         : {'[green]yes[/green]' if stats['enabled'] else '[red]no[/red]'}")
    console.print(f"  rows            : {stats['rows']}")
    console.print(f"  corpus_hashes   : {stats['corpus_hashes']}")
    console.print(f"  total hits (DB) : {stats['hits']}")
    console.print(f"  cosine threshold: {stats['cosine_threshold']:.3f}")
    console.print(f"  default TTL     : {stats['default_ttl_s']}s")
    if stats.get("oldest_ts"):
        console.print(f"  oldest row      : {stats['oldest_ts']}")
    if stats.get("newest_ts"):
        console.print(f"  newest row      : {stats['newest_ts']}")

    # Hit-rate telemetry desde rag_queries (últimos N días).
    tel = _cache_telemetry_stats(days=days)
    if tel["eligible"] > 0:
        console.print()
        console.print(f"[bold]Telemetría últimos {tel['window_days']} días[/bold]")
        hr = tel["hit_rate_pct"]
        hr_color = "green" if hr >= 15 else ("yellow" if hr >= 5 else "red")
        console.print(
            f"  queries elegibles : {tel['eligible']}"
        )
        console.print(
            f"  cache hits        : [bold {hr_color}]{tel['hits']}[/bold {hr_color}]  "
            f"([{hr_color}]{hr:.1f}%[/{hr_color}] hit rate)"
        )
        if tel["saved_ms_avg"] > 0 and tel["hits"] > 0:
            saved_s = tel["saved_ms_total"] / 1000.0
            console.print(
                f"  ahorro estimado   : ~{tel['saved_ms_avg']/1000:.1f}s/query × "
                f"{tel['hits']} hits ≈ [green]{saved_s:.0f}s[/green] ({saved_s/60:.1f} min)"
            )
        if tel["miss_reasons"]:
            console.print()
            console.print("  [dim]miss reasons:[/dim]")
            for reason, cnt in sorted(tel["miss_reasons"].items(), key=lambda x: -x[1]):
                console.print(f"    {reason:20s}: {cnt}")
        if tel["top_queries"]:
            console.print()
            console.print("  [dim]top queries cacheadas (hit_count):[/dim]")
            for q in tel["top_queries"][:10]:
                console.print(
                    f"    [cyan]{q['hit_count']:>3}×[/cyan]  "
                    f"{q['question']}"
                )

    # In-process cache counters (reset on process restart). Útil como
    # sanity check en sesiones largas: embed > 70% hit rate esperable en
    # chat multi-turn, corpus > 95% (invalida solo en index deltas),
    # feedback_golden casi siempre 100% post-primera carga.
    in_proc = cache_stats_snapshot()
    if in_proc:
        console.print()
        console.print("[bold]In-process caches (sesión actual)[/bold]")
        for name in sorted(in_proc.keys()):
            s = in_proc[name]
            ratio_pct = s["ratio"] * 100
            color = "green" if ratio_pct >= 70 else ("yellow" if ratio_pct >= 30 else "red")
            console.print(
                f"  {name:16s}: {s['hits']:>6}/{s['total']:<6}  "
                f"[{color}]{ratio_pct:5.1f}%[/{color}]  hit rate"
            )
    else:
        console.print()
        console.print("[dim]In-process caches: sin eventos en esta sesión.[/dim]")


@cache.command("clear")
@click.option("--all", "clear_all", is_flag=True,
              help="Borrar todas las filas (todos los corpus_hashes). "
                   "Sin esta flag solo se borran las del corpus_hash actual.")
@click.option("--yes", is_flag=True, help="Skip confirmation prompt.")
def cache_clear(clear_all: bool, yes: bool):
    """Limpiar el cache. Por default solo borra filas del corpus actual."""
    if clear_all:
        if not yes:
            if not click.confirm("¿Borrar TODAS las filas del cache?"):
                return
        n = semantic_cache_clear()
        console.print(f"[green]✓[/green] {n} filas borradas (todos los corpus_hashes).")
        return
    try:
        col = get_db()
        h = _corpus_hash_cached(col)
    except Exception as exc:
        console.print(f"[red]No pude resolver corpus_hash actual: {exc}[/red]")
        return
    if not h:
        console.print("[yellow]Corpus_hash vacío (¿índice ausente?). Usá --all para borrar todo.[/yellow]")
        return
    n = semantic_cache_clear(corpus_hash=h)
    console.print(f"[green]✓[/green] {n} filas borradas para corpus_hash={h}.")


@bookmarks.command("stats")
def bookmarks_stats():
    """Contar bookmarks indexados por profile."""
    col_urls = get_urls_db()
    # Fetch only metadatas (no embeds) — cheap even with thousands of rows.
    res = col_urls.get(where={"source": "bookmark"}, include=["metadatas"])
    metas = res.get("metadatas") or []
    if not metas:
        console.print(
            "[yellow]Sin bookmarks indexados.[/yellow] "
            "Corré [bold]rag bookmarks sync[/bold]."
        )
        return
    per_profile: dict[str, int] = {}
    for m in metas:
        p = (m or {}).get("profile") or "unknown"
        per_profile[p] = per_profile.get(p, 0) + 1
    for prof, n in sorted(per_profile.items(), key=lambda x: -x[1]):
        console.print(f"  [cyan]{prof}[/cyan] · {n} bookmarks")
    console.print(f"[green]Total:[/green] {len(metas)} bookmarks")


@bookmarks.command("clear")
@click.option("--profile", default=None,
              help="Solo ese profile. Omitir = borrar TODOS los bookmarks.")
@click.confirmation_option(prompt="¿Borrar filas source=bookmark del sub-índice?")
def bookmarks_clear(profile: str | None):
    """Eliminar bookmarks del sub-índice (no toca las notas)."""
    col_urls = get_urls_db()
    where: dict = {"source": "bookmark"}
    if profile:
        where = {"$and": [{"source": "bookmark"}, {"profile": profile}]}
    existing = col_urls.get(where=where, include=[])
    ids = existing.get("ids") or []
    if not ids:
        console.print("[yellow]Nada para borrar.[/yellow]")
        return
    col_urls.delete(ids=ids)
    console.print(f"[green]✓ Borradas {len(ids)} filas.[/green]")


@cli.group()
def wikilinks():
    """Densificar el grafo: sugerir [[wikilinks]] faltantes."""


@wikilinks.command("suggest")
@click.option("--note", "note_path", default=None,
              help="Solo esta nota (vault-relative)")
@click.option("--folder", default=None, help="Solo notas bajo este folder")
@click.option("--apply", is_flag=True,
              help="Aplicar las sugerencias (default = dry-run)")
@click.option("--max-per-note", default=30, show_default=True,
              help="Cap de sugerencias por nota")
@click.option("--min-len", default=4, show_default=True,
              help="Largo mínimo del título a considerar (filtro de colisiones)")
@click.option("--show", default=5, show_default=True,
              help="Sugerencias por nota a imprimir en dry-run")
@click.option("--json", "as_json", is_flag=True,
              help="Salida JSON (consumido por el plugin Obsidian / scripts).")
def wikilinks_suggest(
    note_path: str | None, folder: str | None, apply: bool,
    max_per_note: int, min_len: int, show: int, as_json: bool,
):
    """Encontrar menciones a títulos de notas que NO están wikilinkeadas y
    proponerlas. Skipea código, frontmatter, links existentes, y títulos
    ambiguos (mismo string en varias notas).
    """
    col = get_db()
    if note_path:
        paths = [note_path]
    else:
        c = _load_corpus(col)
        paths = sorted({m.get("file", "") for m in c["metas"] if m.get("file")})
        if folder:
            paths = [p for p in paths if p.startswith(folder.rstrip("/") + "/") or p == folder]

    if not paths:
        if as_json:
            click.echo(json.dumps({"items": [], "source_path": note_path or ""}))
        else:
            console.print("[yellow]No hay notas que procesar.[/yellow]")
        return

    total_suggestions = 0
    notes_with_suggestions = 0
    notes_applied = 0
    by_note: list[tuple[str, list[dict]]] = []
    # Skip rich `track()` progress bar bajo --json — emite escapes ANSI a
    # stderr que el plugin no espera. Usamos un loop plano cuando hay
    # output máquina.
    iterable = paths if as_json else track(paths, description="Analizando...")
    for path in iterable:
        try:
            sugs = find_wikilink_suggestions(
                col, path, min_title_len=min_len, max_per_note=max_per_note,
            )
        except Exception:
            continue
        if not sugs:
            continue
        notes_with_suggestions += 1
        total_suggestions += len(sugs)
        by_note.append((path, sugs))

        if apply:
            try:
                n_applied, _ = apply_wikilink_suggestions(path, sugs)
                if n_applied:
                    notes_applied += 1
                    # Re-index the rewritten note so retrieval picks up the new
                    # outlinks. Skip contradiction check — wikilinks aren't a
                    # claim change, just graph noise; saves an LLM call.
                    try:
                        _index_single_file(
                            col, VAULT_PATH / path, skip_contradict=True,
                        )
                    except Exception:
                        pass
            except Exception as e:
                console.print(f"[red]Error aplicando en {path}: {e}[/red]")

    if as_json:
        # Output paralelo al endpoint HTTP /api/notes/wikilink-suggestions:
        # cuando hay 1 nota (--note), devolvemos {items, source_path} (mismo
        # shape). Cuando hay N notas (default sin --note), devolvemos
        # {by_note: [{path, items}, ...], total_suggestions, notes_with_suggestions}
        # para que scripts agrupen.
        if note_path:
            items = by_note[0][1] if by_note else []
            click.echo(json.dumps(
                {"items": items, "source_path": note_path},
                ensure_ascii=False,
            ))
        else:
            click.echo(json.dumps({
                "by_note": [{"path": p, "items": s} for p, s in by_note],
                "total_suggestions": total_suggestions,
                "notes_with_suggestions": notes_with_suggestions,
                "notes_processed": len(paths),
                "applied": notes_applied if apply else 0,
            }, ensure_ascii=False))
        return

    if not apply:
        for path, sugs in by_note:
            console.print(
                f"\n[bold cyan]{path}[/bold cyan] [dim]({len(sugs)} sugerencia(s))[/dim]"
            )
            for s in sugs[:show]:
                console.print(
                    f"  [yellow]{s['title']}[/yellow] → [magenta]{s['target']}[/magenta]"
                    f" [dim]línea {s['line']}[/dim]"
                )
                ctx = s["context"]
                if len(ctx) > 140:
                    ctx = ctx[:140] + "…"
                console.print(f"    [dim]{ctx}[/dim]")
            if len(sugs) > show:
                console.print(f"    [dim]+ {len(sugs) - show} más…[/dim]")
        console.print(
            f"\n[cyan]{total_suggestions} sugerencia(s) en "
            f"{notes_with_suggestions}/{len(paths)} nota(s).[/cyan] "
            f"[dim]Re-correr con --apply para escribir.[/dim]"
        )
    else:
        console.print(
            f"\n[green]✓ Aplicado:[/green] {total_suggestions} wikilinks en "
            f"{notes_applied}/{len(paths)} notas."
        )


# ── QUICK CAPTURE (rag capture) ──────────────────────────────────────────────
# Atomic building block: take a string (from stdin or arg) and land it in the
# vault as a fresh Inbox note. Used directly by the user and indirectly by the
# WhatsApp voice capture path.

_CAPTURE_FOLDER = "00-Inbox"


def _capture_slug(text: str, maxlen: int = 40) -> str:
    """First non-empty line, slugged."""
    first = next((ln.strip() for ln in text.splitlines() if ln.strip()), "capture")
    return _slug(first, maxlen=maxlen)


def capture_note(
    text: str,
    tags: list[str] | None = None,
    source: str | None = None,
    title: str | None = None,
) -> Path:
    """Create `<vault>/00-Inbox/YYYY-MM-DD-HHMM-<slug>.md` with the given text
    and minimal frontmatter. Returns the written path.

    Idempotent on name collision: appends a ``-2``, ``-3`` suffix.
    """
    text = (text or "").strip()
    if not text:
        raise ValueError("capture text is empty")
    now = datetime.now()
    stamp = now.strftime("%Y-%m-%d-%H%M")
    slug = _slug(title, maxlen=40) if title else _capture_slug(text)
    target_dir = VAULT_PATH / _CAPTURE_FOLDER
    target_dir.mkdir(parents=True, exist_ok=True)
    candidate = target_dir / f"{stamp}-{slug}.md"
    i = 2
    while candidate.exists():
        candidate = target_dir / f"{stamp}-{slug}-{i}.md"
        i += 1
    fm_lines = [
        "---",
        f"created: '{now.isoformat(timespec='seconds')}'",
        "type: capture",
    ]
    all_tags = list(dict.fromkeys(["capture", *(tags or [])]))
    fm_lines.append("tags:")
    for t in all_tags:
        fm_lines.append(f"- {t}")
    if source:
        fm_lines.append(f"source: {source}")
    fm_lines.append("---")
    body = "\n".join(fm_lines) + f"\n\n{text.strip()}\n"
    candidate.write_text(body, encoding="utf-8")
    return candidate


@cli.command()
@click.argument("text", required=False)
@click.option("--stdin", "from_stdin", is_flag=True,
              help="Leer texto de stdin (ignora arg posicional)")
@click.option("--tag", "tags", multiple=True,
              help="Tag extra (además de 'capture'). Repetible.")
@click.option("--source", default=None,
              help="Etiqueta de origen (ej: 'voice', 'whatsapp', 'cli')")
@click.option("--title", default=None,
              help="Título custom (slug del filename). Default: primera línea.")
@click.option("--image", "image_path", type=click.Path(exists=True, dir_okay=False, path_type=Path),
              default=None,
              help="Path a una imagen — OCR el texto, creá la nota con ese "
                   "contenido, y si parece una cita, agendala automáticamente.")
@click.option("--plain", is_flag=True, help="Salida plana (ruta only)")
def capture(text: str | None, from_stdin: bool, tags: tuple[str, ...],
            source: str | None, title: str | None,
            image_path: Path | None, plain: bool):
    """Capturar una nota rápida al 00-Inbox/ del vault.

    Uso:
      rag capture "idea suelta"
      echo "nota" | rag capture --stdin --tag voice --source whatsapp
      rag capture --image ~/Desktop/turno-dentista.png

    Con `--image`, OCR-ea la imagen con Apple Vision (gratis, local), crea
    una nota con el texto extraído + referencia al archivo original, y si
    el detector identifica una cita / turno / evento con fecha → lo agenda
    automáticamente en Calendar (auto-undo 10s en el flow de chat; aquí
    imprime el event_uid y podés borrarlo a mano si es false positive).
    """
    # Image-first branch: if --image supplied, text is optional (wrapper fills it).
    if image_path is not None:
        # Reset del budget VLM por-run — cada `rag capture --image` es su
        # propia oportunidad de caption sin chocar contra un cap de un run
        # anterior en el mismo proceso.
        _vlm_caption_budget_reset()
        ocr_text = ""
        img_source = ""
        try:
            ocr_text, img_source = _image_text_or_caption(image_path)
        except Exception as exc:
            msg = f"Lectura de imagen falló: {exc}"
            click.echo(msg) if plain else console.print(f"[red]{msg}[/red]")
            return
        if not ocr_text.strip():
            msg = (
                f"Ni OCR ni VLM pudieron leer {image_path.name}. "
                f"Revisá: ocrmac instalado (`uv pip install ocrmac`), "
                f"VLM pulled (`ollama pull {VLM_MODEL}`), y que la "
                f"imagen no esté corrupta."
            )
            click.echo(msg) if plain else console.print(f"[yellow]{msg}[/yellow]")
            return
        # Merge OCR/caption con texto opcional (si el user pasó ambos, se
        # prepende el comentario del user antes del texto de la imagen).
        user_blurb = (text or "").strip()
        if from_stdin and not user_blurb:
            import sys
            user_blurb = sys.stdin.read().strip()
        body_parts = []
        body_parts.append(f"![[{image_path.name}]]")
        if user_blurb:
            body_parts.append(user_blurb)
        # Marker discrimina OCR literal vs VLM-inferred caption. Útil si en
        # el futuro el usuario busca "solo texto real" vs "descripción IA".
        text_marker = "VLM-caption" if img_source == "vlm" else "OCR"
        body_parts.append(f"<!-- {text_marker}: {image_path} -->\n{ocr_text}")
        note_text = "\n\n".join(body_parts)
        try:
            note_path = capture_note(
                note_text,
                tags=list(tags) + ["image"],
                source=source or "image-capture",
                title=title,
            )
        except ValueError as e:
            click.echo(str(e)) if plain else console.print(f"[red]{e}[/red]")
            return
        try:
            _index_single_file(get_db(), note_path, skip_contradict=True)
        except Exception:
            pass
        # Cita detector — silent-fail, no bloquea el capture normal.
        cita_result: dict | None = None
        try:
            cita_result = _maybe_create_cita_from_ocr(
                ocr_text, image_path, source="capture",
            )
        except Exception as exc:
            _silent_log(f"cita_detect_capture:{image_path}", exc)
        rel = note_path.relative_to(VAULT_PATH)
        if plain:
            click.echo(str(rel))
            if cita_result:
                dec = cita_result.get("decision")
                if dec == "cita":
                    click.echo(f"evento: {cita_result.get('event_uid')}")
                elif dec == "reminder":
                    click.echo(f"recordatorio: {cita_result.get('reminder_id')}")
            return
        console.print(f"[green]✓ Capturado:[/green] [bold cyan]{rel}[/bold cyan]")
        if img_source == "vlm":
            # Transparencia: el usuario tiene derecho a saber que el texto
            # no vino de OCR literal sino de una descripción inferida. El
            # caption puede estar equivocado (VLMs halucinan), y es
            # importante que el usuario lo sepa para reality-check la nota.
            console.print(
                f"  [dim]Fuente del texto: VLM caption ({VLM_MODEL}) — "
                f"OCR estaba vacío[/dim]"
            )
        if cita_result:
            dec = cita_result.get("decision")
            title_s = cita_result.get("title") or ""
            when_s = cita_result.get("when") or cita_result.get("start") or ""
            loc_s = cita_result.get("location") or ""
            if dec == "cita":
                console.print(
                    f"[bold green]📅 Evento creado:[/bold green] "
                    f"[cyan]{title_s}[/cyan] — [dim]{when_s}[/dim]"
                    + (f" · {loc_s}" if loc_s else "")
                )
            elif dec == "reminder":
                tail = f" — [dim]{when_s}[/dim]" if when_s else " [dim](sin fecha)[/dim]"
                console.print(
                    f"[bold magenta]✓ Recordatorio creado:[/bold magenta] "
                    f"[cyan]{title_s}[/cyan]{tail}"
                )
                console.print(
                    f"  [dim]Imagen adjunta: {image_path}[/dim]"
                )
            elif dec == "duplicate":
                console.print(
                    f"[yellow]📅 Ya estaba en el calendario:[/yellow] "
                    f"[dim]{title_s}[/dim]"
                )
            elif dec == "ambiguous":
                console.print(
                    "[dim]📅 Parece una cita pero la fecha es ambigua — "
                    "no se agendó. Revisá la nota.[/dim]"
                )
            elif dec == "note":
                # Info sin acción — la nota ya quedó en 00-Inbox, nada
                # más que hacer. Silent por default para no ruido.
                pass
            elif dec in ("no", "low_confidence"):
                # Silent: el helper no clasificó o no tuvo confianza.
                pass
        return

    # Text-only branch (legacy).
    if from_stdin:
        import sys
        text = sys.stdin.read()
    if not (text and text.strip()):
        msg = "Sin texto. Pasá arg o --stdin."
        click.echo(msg) if plain else console.print(f"[red]{msg}[/red]")
        return
    try:
        path = capture_note(
            text, tags=list(tags), source=source, title=title,
        )
    except ValueError as e:
        click.echo(str(e)) if plain else console.print(f"[red]{e}[/red]")
        return
    # Auto-index so the captured note is retrievable inmediatly — `rag watch`
    # would pick it up too, but we don't want to wait for its debounce.
    try:
        _index_single_file(get_db(), path, skip_contradict=True)
    except Exception:
        pass
    rel = path.relative_to(VAULT_PATH)
    if plain:
        click.echo(str(rel))
    else:
        console.print(f"[green]✓ Capturado:[/green] [bold cyan]{rel}[/bold cyan]")


# ── SCAN-CITAS (rag scan-citas) ──────────────────────────────────────────────
# Barrido masivo de un folder arbitrario (NO acotado al vault) buscando
# citas en screenshots. Usa el mismo _ocr_image + _detect_cita_from_ocr +
# _maybe_create_cita_from_ocr — con el sidecar `rag_cita_detections`
# deduplica contra runs previos, así que correrlo dos veces sobre la
# misma carpeta es O(n) en sqlite hits, cero llamadas al helper.
#
# Default DRY-RUN: imprime lo que haría sin crear nada. `--apply` flippea
# a modo real. Pensado para limpiar Downloads / Desktop / Screenshots de
# golpe sin riesgo.


@cli.command(name="scan-citas")
@click.argument("folder", type=click.Path(exists=True, file_okay=False,
                                          dir_okay=True, path_type=Path))
@click.option("--apply", "do_apply", is_flag=True,
              help="Crear los eventos de verdad. Sin esto es dry-run (default).")
@click.option("--min-confidence", "min_conf", type=float, default=None,
              help="Override del umbral (0.70 default). "
                   "Bajá a 0.5 para barridos agresivos.")
@click.option("--recursive/--no-recursive", default=True,
              help="Bajar a subdirs. Default: sí.")
@click.option("--plain", is_flag=True, help="Salida plana (ruta + decisión por línea).")
def scan_citas(folder: Path, do_apply: bool, min_conf: float | None,
               recursive: bool, plain: bool):
    """Escanear un folder entero por citas en imágenes y agendarlas.

    Uso:
      rag scan-citas ~/Desktop/Screenshots          # dry-run
      rag scan-citas ~/Downloads --apply             # crea eventos + reminders
      rag scan-citas . --apply --min-confidence 0.5  # más agresivo

    El folder NO tiene que estar adentro del vault — podés pasar
    `~/Downloads`, `/tmp`, lo que sea. Cada imagen (.png .jpg .jpeg
    .heic .webp .gif .bmp .tiff .tif) se OCR-ea (cache en
    `rag_ocr_cache` por abs path + mtime), pasa por qwen2.5:3b, y el
    detector clasifica en 3 kinds:

      - event    → cita / turno / reunión → Calendar.app
      - reminder → tarea / compra / factura → Apple Reminders (con
                   path de la imagen en el body del recordatorio)
      - note     → info sin acción (receta, meme, código) → no-op

    Con `--apply`: cada event crea un evento, cada reminder crea un
    recordatorio. Notes no hacen nada (solo se loggean). Sin `--apply`
    es dry-run y muestra la clasificación.

    Dedup: el sidecar `rag_cita_detections` persiste hash-based decisions
    — re-correr sobre la misma carpeta no gasta llamadas al helper ni
    duplica eventos / recordatorios.
    """
    # Collect images — respect _IMAGE_EXTENSIONS del module OCR.
    pattern = "**/*" if recursive else "*"
    all_candidates = [p for p in folder.glob(pattern) if p.is_file()]
    images = [p for p in all_candidates if p.suffix.lower() in _IMAGE_EXTENSIONS]
    if not images:
        msg = f"Sin imágenes en {folder}."
        click.echo(msg) if plain else console.print(f"[yellow]{msg}[/yellow]")
        return

    threshold = float(min_conf) if min_conf is not None else _CITA_MIN_CONFIDENCE
    mode = "APPLY" if do_apply else "DRY-RUN"
    if not plain:
        console.print(
            f"[bold]Scan-citas[/bold] · "
            f"[cyan]{folder}[/cyan] · {len(images)} imágenes · "
            f"[{'green' if do_apply else 'yellow'}]{mode}[/] · "
            f"umbral={threshold:.2f}"
        )

    # Reset del budget VLM al arrancar el barrido. Sin esto, un run
    # anterior en el mismo proceso (poco común en CLI one-shot, pero
    # posible si el user hace múltiples `rag scan-citas` encadenados en
    # un shell script) dejaría el cap ya consumido.
    _vlm_caption_budget_reset()

    # Counters for summary. `vlm_captioned` cuenta cuántas imágenes usaron
    # el fallback VLM (OCR vacío/corto); útil para el usuario saber qué
    # porción del vault se beneficia del modelo de visión.
    counts = {
        "cita": 0, "reminder": 0, "note": 0, "duplicate": 0,
        "no": 0, "low_confidence": 0,
        "ambiguous": 0, "error": 0, "skipped": 0,
        "vlm_captioned": 0,
    }
    rows: list[tuple[str, str, str, float, str, str]] = []

    for img in sorted(images, key=lambda p: str(p)):
        try:
            ocr_text, img_source = _image_text_or_caption(img)
        except Exception as exc:
            _silent_log(f"scan_citas_read:{img}", exc)
            counts["skipped"] += 1
            continue
        if not ocr_text or len(ocr_text.strip()) < _CITA_MIN_CHARS:
            counts["skipped"] += 1
            continue
        if img_source == "vlm":
            counts["vlm_captioned"] += 1

        if do_apply:
            try:
                result = _maybe_create_cita_from_ocr(
                    ocr_text, img, source="scan-citas",
                    min_confidence=threshold,
                )
            except Exception as exc:
                _silent_log(f"scan_citas_create:{img}", exc)
                counts["error"] += 1
                continue
            if result is None:
                counts["skipped"] += 1
                continue
            dec = result.get("decision") or "error"
            kind = result.get("kind") or ""
        else:
            # Dry-run: sólo correr el detector (sin sidecar write que
            # podría afectar un apply posterior). Es una decisión de
            # UX — preferimos que dry-run NO persista 'no' en el sidecar
            # así un apply posterior re-evalúa (el user puede haber
            # bajado el threshold). El cache de OCR sí persiste (es
            # barato y deseable).
            try:
                detected = _detect_cita_from_ocr(ocr_text)
            except Exception as exc:
                _silent_log(f"scan_citas_detect:{img}", exc)
                counts["error"] += 1
                continue
            if detected is None:
                counts["skipped"] += 1
                continue
            kind = detected.get("kind") or "note"
            if detected.get("confidence", 0.0) < threshold:
                dec = "low_confidence"
            elif kind == "note":
                dec = "note"
            elif kind == "event":
                # Dry-run: would be either "cita" or "ambiguous" (if
                # `when` is empty). Predecirlo sin llamar a
                # `_parse_natural_datetime` es aproximado pero útil.
                dec = "cita" if (detected.get("when") or "") else "ambiguous"
            elif kind == "reminder":
                dec = "reminder"
            else:
                dec = "error"
            result = {
                "decision": dec,
                "kind": kind,
                "title": detected.get("title", ""),
                "when": detected.get("when", ""),
                "start": detected.get("when", ""),
                "location": detected.get("location", ""),
                "confidence": detected.get("confidence", 0.0),
                "event_uid": None,
                "reminder_id": None,
            }

        counts[dec] = counts.get(dec, 0) + 1
        rows.append((
            str(img.relative_to(folder)) if img.is_relative_to(folder) else str(img),
            dec,
            kind or "-",
            float(result.get("confidence", 0.0) or 0.0),
            str(result.get("title", ""))[:60],
            str(result.get("when", "") or result.get("start", ""))[:40],
        ))

    # Render.
    if plain:
        for path_s, dec, kind_s, conf, title_s, when_s in rows:
            click.echo(f"{path_s}\t{dec}\t{kind_s}\t{conf:.2f}\t{title_s}\t{when_s}")
        return

    from rich.table import Table
    t = Table(show_header=True, header_style="bold")
    t.add_column("Imagen", overflow="fold")
    t.add_column("Decisión")
    t.add_column("Tipo")
    t.add_column("Conf", justify="right")
    t.add_column("Título")
    t.add_column("Cuándo")
    for path_s, dec, kind_s, conf, title_s, when_s in rows:
        dec_style = {
            "cita": "green", "reminder": "magenta", "note": "cyan",
            "duplicate": "yellow",
            "no": "dim", "low_confidence": "dim",
            "ambiguous": "yellow", "error": "red",
        }.get(dec, "white")
        t.add_row(
            path_s,
            f"[{dec_style}]{dec}[/{dec_style}]",
            kind_s,
            f"{conf:.2f}",
            title_s,
            when_s,
        )
    console.print(t)
    console.print(
        f"[bold]Resumen[/bold] · "
        f"[green]cita={counts.get('cita',0)}[/green] "
        f"[magenta]reminder={counts.get('reminder',0)}[/magenta] "
        f"[cyan]note={counts.get('note',0)}[/cyan] "
        f"[yellow]dup={counts.get('duplicate',0)}[/yellow] "
        f"[dim]low={counts.get('low_confidence',0)}[/dim] "
        f"[yellow]ambig={counts.get('ambiguous',0)}[/yellow] "
        f"[red]err={counts.get('error',0)}[/red] "
        f"[dim]skip={counts.get('skipped',0)}[/dim]"
    )
    if counts.get("vlm_captioned", 0) > 0:
        console.print(
            f"[dim]↳ {counts.get('vlm_captioned', 0)} imágenes sin OCR "
            f"se captionearon vía VLM ({VLM_MODEL}).[/dim]"
        )
    if not do_apply:
        actionable = counts.get("cita", 0) + counts.get("reminder", 0)
        if actionable > 0:
            console.print(
                f"[dim]→ {actionable} candidatas "
                f"({counts.get('cita',0)} eventos + {counts.get('reminder',0)} "
                f"recordatorios). Correlo con [bold]--apply[/bold] para "
                f"crearlas.[/dim]"
            )


# ── URL INGEST (rag read) ────────────────────────────────────────────────────
# Fetch an external URL, summarize in 1st-person Spanish, and ingest into the
# vault as a linked note. Stdlib-only HTTP, readability via regex strip.

_READ_FOLDER = "00-Inbox"
# Dedicated folders for specific content types — YouTube transcripts are too
# noisy to leave in Inbox and form a logical PARA Resource category.
_READ_YOUTUBE_FOLDER = "03-Resources/Transcriptions"
# Inbox changelog — every note created OUTSIDE 00-Inbox appends a wikilink here
# under the `## YYYY-MM-DD` section. Keeps Inbox as the "what entered the vault
# today" view even when notes route to topic folders.
_DAILY_NOTE_NAME = "Daily note.md"
_READ_USER_AGENT = (
    "Mozilla/5.0 (Macintosh; Apple Silicon) obsidian-rag/1.0 (+local)"
)
_READ_TIMEOUT_SECS = 20
_READ_MIN_CHARS = 500
_READ_MAX_CHARS = 16000

_READ_STRIP_TAGS = ("script", "style", "nav", "header", "footer",
                    "noscript", "aside", "form", "svg", "iframe")
_READ_TITLE_RE = re.compile(r"<title[^>]*>(.*?)</title>", re.IGNORECASE | re.DOTALL)
_READ_TAG_RE = re.compile(r"<[^>]+>")
_READ_WHITESPACE_RE = re.compile(r"[ \t\f\v]+")
_READ_NEWLINES_RE = re.compile(r"\n{3,}")


def _is_safe_public_url(url: str) -> tuple[bool, str]:
    """Audit 2026-04-26 (BUG #2): SSRF guard.

    Resuelve el host del URL y rechaza si apunta a IP privada/loopback/
    link-local (incluye AWS metadata 169.254.169.254). Si DNS falla,
    deny — fail-closed.
    """
    import urllib.parse  # noqa: PLC0415
    import socket  # noqa: PLC0415
    import ipaddress  # noqa: PLC0415
    try:
        parsed = urllib.parse.urlparse(url)
    except Exception:
        return (False, "URL malformada")
    host = (parsed.hostname or "").strip()
    if not host:
        return (False, "URL sin host")
    if parsed.scheme not in ("http", "https"):
        return (False, f"scheme no permitido: {parsed.scheme}")
    try:
        infos = socket.getaddrinfo(host, None)
    except Exception as exc:
        return (False, f"DNS resolución falló: {exc}")
    for info in infos:
        try:
            ip = ipaddress.ip_address(info[4][0])
        except Exception:
            continue
        if (ip.is_private or ip.is_loopback or ip.is_link_local
                or ip.is_multicast or ip.is_reserved):
            return (False, f"host resuelve a IP privada/local: {ip}")
    return (True, "")


def _read_fetch_url(url: str, timeout: int = _READ_TIMEOUT_SECS) -> tuple[str, dict]:
    """Fetch URL, return (decoded_html, headers_dict). Raises RuntimeError on
    network failure. Stdlib urllib only — no third-party.

    Audit 2026-04-26 (BUG #2): SSRF guard pre-fetch + post-redirect.
    Custom HTTPRedirectHandler valida cada hop — `urlopen` por default
    sigue redirects sin validar destino.
    """
    import urllib.request
    import urllib.error
    ok, reason = _is_safe_public_url(url)
    if not ok:
        raise RuntimeError(f"URL no permitida: {reason}")

    class _SafeRedirectHandler(urllib.request.HTTPRedirectHandler):
        def redirect_request(self, req, fp, code, msg, headers, newurl):
            ok2, reason2 = _is_safe_public_url(newurl)
            if not ok2:
                raise RuntimeError(f"redirect a URL no permitida: {reason2}")
            return super().redirect_request(req, fp, code, msg, headers, newurl)

    opener = urllib.request.build_opener(_SafeRedirectHandler())
    req = urllib.request.Request(
        url,
        headers={
            "User-Agent": _READ_USER_AGENT,
            "Accept": "text/html,application/xhtml+xml;q=0.9,*/*;q=0.5",
            "Accept-Language": "en,es;q=0.9",
        },
    )
    try:
        with opener.open(req, timeout=timeout) as resp:
            raw = resp.read()
            charset = resp.headers.get_content_charset() or "utf-8"
            headers = dict(resp.headers.items())
    except urllib.error.HTTPError as e:
        raise RuntimeError(f"HTTP {e.code}: {e.reason}") from e
    except urllib.error.URLError as e:
        raise RuntimeError(f"Error de red: {e.reason}") from e
    except (TimeoutError, OSError) as e:
        raise RuntimeError(f"Timeout/error: {e}") from e
    try:
        html = raw.decode(charset, errors="replace")
    except LookupError:
        html = raw.decode("utf-8", errors="replace")
    return html, headers


# ── YouTube support for `rag read` ──────────────────────────────────────────
# YouTube pages don't expose useful readable text (SPA, transcripts behind JS),
# so `_read_extract` on the HTML returns near-empty content and the gate aborts.
# Bypass: detect YouTube URL → fetch captions via youtube-transcript-api (free,
# no API key — scrapes public caption endpoint) and the video title via oEmbed
# (free, no API key). Transcript is joined into plain prose matching what
# `_read_extract` returns, so the downstream pipeline (summary, related, tags)
# needs zero changes.

_YOUTUBE_URL_RE = re.compile(
    r"""^https?://(?:
        (?:www\.|m\.)?youtube\.com/(?:watch\?v=|shorts/|live/|embed/)
      | youtu\.be/
    )([A-Za-z0-9_-]{11})""",
    re.IGNORECASE | re.VERBOSE,
)

_YOUTUBE_LANG_PREFERENCES = ("es", "es-419", "es-ES", "en", "en-US", "en-GB", "pt")


def _is_youtube_url(url: str) -> bool:
    return bool(_YOUTUBE_URL_RE.match(url or ""))


def _extract_youtube_id(url: str) -> str | None:
    m = _YOUTUBE_URL_RE.match(url or "")
    return m.group(1) if m else None


def _fetch_youtube_title(url: str) -> str:
    """Video title + channel via YouTube oEmbed (public, keyless). Returns "" on
    any failure — caller falls back to the URL as the heading.
    """
    import urllib.parse
    import urllib.request
    try:
        endpoint = (
            "https://www.youtube.com/oembed?"
            + urllib.parse.urlencode({"url": url, "format": "json"})
        )
        req = urllib.request.Request(endpoint, headers={"User-Agent": _READ_USER_AGENT})
        with urllib.request.urlopen(req, timeout=_READ_TIMEOUT_SECS) as resp:
            data = json.loads(resp.read().decode("utf-8", errors="replace"))
    except Exception:
        return ""
    title = (data.get("title") or "").strip()
    author = (data.get("author_name") or "").strip()
    if title and author:
        return f"{title} — {author}"
    return title or author


def _fetch_youtube_transcript(video_id: str) -> str:
    """Join transcript snippets into plain prose. Tries the language preferences
    in order. Raises RuntimeError if no transcript is available (private video,
    captions disabled, region-locked).
    """
    from youtube_transcript_api import YouTubeTranscriptApi
    try:
        api = YouTubeTranscriptApi()
        transcript = api.fetch(video_id, languages=list(_YOUTUBE_LANG_PREFERENCES))
    except Exception as exc:
        raise RuntimeError(f"Sin transcript disponible: {exc}") from exc
    lines = [s.text.strip() for s in transcript.snippets if s.text and s.text.strip()]
    if not lines:
        raise RuntimeError("Transcript vacío.")
    text = " ".join(lines)
    text = _READ_WHITESPACE_RE.sub(" ", text)
    text = text.strip()
    if len(text) > _READ_MAX_CHARS:
        text = text[:_READ_MAX_CHARS].rstrip() + "…"
    return text


def _fetch_youtube_content(url: str) -> tuple[str, str]:
    """`(title, text)` for a YouTube URL — shape matches ``_read_extract``.
    Title via oEmbed, text via caption API. Raises RuntimeError on either
    transcript failure (caller converts to user-facing error).
    """
    vid = _extract_youtube_id(url)
    if not vid:
        raise RuntimeError("URL de YouTube no parseable.")
    title = _fetch_youtube_title(url)
    text = _fetch_youtube_transcript(vid)
    return title, text


def _read_extract(html: str) -> tuple[str, str]:
    """Return (title, text) by parsing HTML with a real stdlib parser.

    Replaces the pre-2026-04-20 regex-based strip: that approach worked for
    well-formed pages but malformed markup (unclosed tags, attributes
    containing `>`, nested scripts) leaked attribute content like
    `onerror="..."` into the extracted text. When the extracted text
    lands in a vault note and that note is later rendered in the web
    UI (via marked.js), a payload like `<img src=x onerror="alert(1)">`
    could partially survive as visible "alert(1)" text — low-risk in
    practice (the sanitiser in app.js still strips on render) but
    defence-in-depth is cheap.

    Uses `html.parser.HTMLParser` from stdlib:
      - parses structure, not regex — nested tags, self-closing, malformed
        markup all handled correctly
      - SKIP_TAGS set with depth counter → nested scripts-in-scripts etc.
        are skipped fully, not partially
      - attribute content is never exposed to the output (only
        handle_data char content is collected)
      - convert_charrefs=True unescapes entities automatically
      - on parse error (really malformed input), keeps whatever was
        collected so far rather than raising — the summary pipeline
        treats a short extract as a gate ("< 500 chars = error") so
        partial extraction degrades gracefully into the existing error path
    """
    from html.parser import HTMLParser

    class _Extractor(HTMLParser):
        # Tags whose inner content is noise or hostile payload. Both are
        # tracked with a depth counter so `<script><script>...</script></script>`
        # (rare but valid-ish) balances correctly.
        _SKIP = frozenset({
            "script", "style", "nav", "header", "footer", "aside",
            "iframe", "noscript", "svg", "math",
        })

        def __init__(self) -> None:
            super().__init__(convert_charrefs=True)
            self.title_parts: list[str] = []
            self.text_parts: list[str] = []
            self._in_title = False
            self._skip_depth = 0
            # Block-level tags insert a newline into text_parts on close
            # so paragraph structure survives the flattening below.
            self._block_tags = frozenset({
                "p", "br", "hr", "li", "div", "section", "article",
                "h1", "h2", "h3", "h4", "h5", "h6", "blockquote",
                "tr", "td", "th", "pre",
            })

        def handle_starttag(self, tag: str, attrs) -> None:
            t = tag.lower()
            if t == "title" and self._skip_depth == 0:
                self._in_title = True
            elif t in self._SKIP:
                self._skip_depth += 1

        def handle_startendtag(self, tag: str, attrs) -> None:
            # Void / self-closing tags don't emit data; just inject
            # newline for <br/>.
            if tag.lower() == "br" and self._skip_depth == 0:
                self.text_parts.append("\n")

        def handle_endtag(self, tag: str) -> None:
            t = tag.lower()
            if t == "title":
                self._in_title = False
            elif t in self._SKIP and self._skip_depth > 0:
                self._skip_depth -= 1
            elif t in self._block_tags and self._skip_depth == 0:
                self.text_parts.append("\n")

        def handle_data(self, data: str) -> None:
            if self._skip_depth > 0:
                return
            if self._in_title:
                self.title_parts.append(data)
            else:
                self.text_parts.append(data)

    ex = _Extractor()
    try:
        ex.feed(html)
        ex.close()
    except Exception:
        # Malformed HTML: use whatever got collected up to the error.
        pass

    title = " ".join(ex.title_parts).strip()
    title = re.sub(r"\s+", " ", title)[:200]

    text = "".join(ex.text_parts)
    # Normalise: collapse inline runs of whitespace, then keep paragraph
    # breaks as double newlines. Strip per-line to drop indentation from
    # the source HTML's pretty-printing.
    text = re.sub(r"[ \t\r\f\v]+", " ", text)
    text = "\n".join(ln.strip() for ln in text.splitlines())
    text = re.sub(r"\n{3,}", "\n\n", text).strip()
    if len(text) > _READ_MAX_CHARS:
        text = text[:_READ_MAX_CHARS].rstrip() + "…"
    return title, text


def _find_related_by_embedding(
    col: SqliteVecCollection,
    query_embedding: list[float],
    limit: int = 5,
) -> list[dict]:
    """Semantic neighbours of an embedding — returns up to `limit` note-level
    metas (deduped by file, best chunk wins). Used by `rag read` where we have
    a summary but no in-vault source metas for the graph-based `find_related`.
    """
    if col.count() == 0:
        return []
    try:
        res = col.query(
            query_embeddings=[query_embedding],
            n_results=min(limit * 4, col.count()),
            include=["metadatas", "distances"],
        )
    except Exception:
        return []
    metas = res.get("metadatas", [[]])[0] or []
    distances = res.get("distances", [[]])[0] or []
    seen: dict[str, tuple[float, dict]] = {}
    for m, dist in zip(metas, distances):
        f = m.get("file") or ""
        if not f or is_excluded(f):
            continue
        cur = seen.get(f)
        if cur is None or dist < cur[0]:
            seen[f] = (dist, m)
    ranked = sorted(seen.values(), key=lambda x: x[0])
    return [m for _, m in ranked[:limit]]


def _read_summary_prompt(
    url: str,
    title: str,
    text: str,
    related_titles: list[str],
) -> str:
    related_block = (
        ", ".join(f"[[{t}]]" for t in related_titles)
        if related_titles else "(ninguna)"
    )
    title_line = f"TÍTULO DETECTADO: {title}\n" if title else ""
    return (
        "Sos un asistente que resume artículos externos para archivarlos en "
        "mis notas personales. Escribí en 1ra persona, en español rioplatense, "
        "tono calmo y directo, como en mis reviews matutinos. NO inventes "
        "datos que no estén en el texto; si algo no está, omitilo.\n\n"
        f"URL: {url}\n"
        f"{title_line}"
        f"NOTAS RELACIONADAS EN MI VAULT (podés citar con [[wikilink]] cuando "
        f"sea pertinente): {related_block}\n\n"
        "TEXTO FUENTE:\n"
        f"{text}\n\n"
        "Generá un resumen de 150-300 palabras que cubra: de qué va el "
        "artículo, los 2-4 puntos centrales, y cómo se conecta con lo que "
        "ya tengo en el vault (si aplica). Insertá [[wikilinks]] a las notas "
        "relacionadas SOLO donde la conexión sea clara; no fuerces links. "
        "Devolvé SOLO el cuerpo en Markdown — sin título, sin frontmatter, "
        "sin preámbulo."
    )


def _read_generate_summary(prompt: str) -> str:
    try:
        resp = _chat_capped_client().chat(
            model=resolve_chat_model(),
            messages=[{"role": "user", "content": prompt}],
            options=CHAT_OPTIONS,
            keep_alive=chat_keep_alive(),
        )
        # 2026-04-29: filter PT→ES post-gen — el resumen de URL se guarda
        # en `03-Resources/` y se renderiza en el CLI (`rag read <url>`).
        # Sin filter, leaks del LLM con texto pt llegan a la nota guardada.
        from rag.iberian_leak_filter import replace_iberian_leaks
        return replace_iberian_leaks((resp.message.content or "").strip())
    except Exception:
        return ""


def _read_slug_from(title: str, url: str) -> str:
    if title and title.strip():
        return _slug(title, maxlen=40)
    try:
        import urllib.parse as _up
        host = _up.urlparse(url).netloc or ""
    except Exception:
        host = ""
    host = host.replace("www.", "")
    return _slug(host, maxlen=40) if host else "read"


def _read_build_note(
    url: str,
    title: str,
    summary: str,
    tags: list[str],
    related_titles: list[str],
    created_iso: str,
) -> str:
    """Compose frontmatter + body for the read-note."""
    fm_lines = ["---", f"created: '{created_iso}'", "type: read",
                f"source: {url}"]
    safe_title = title.replace('"', "'") if title else ""
    fm_lines.append(f'title: "{safe_title}"')
    all_tags = list(dict.fromkeys(["read", *tags]))
    fm_lines.append("tags:")
    for t in all_tags:
        fm_lines.append(f"- {t}")
    if related_titles:
        rel_yaml = ", ".join(f'"[[{t}]]"' for t in related_titles)
        fm_lines.append(f"related: [{rel_yaml}]")
    else:
        fm_lines.append("related: []")
    fm_lines.append("---")
    heading = title or url
    body = "\n".join(fm_lines) + f"\n\n# {heading}\n\n{summary.strip()}\n"
    return body


def _append_to_daily_note(
    note_path: Path, title: str, folder: str, when: datetime,
) -> None:
    """Append a wikilink entry to `00-Inbox/Daily note.md` under the `## YYYY-MM-DD`
    section for `when`. Creates the file + today's section on first call of the
    day; reuses existing sections on subsequent calls.

    The wikilink uses just the note stem (Obsidian resolves it unambiguously if
    the vault has no stem collisions — which stamped filenames ensure). The
    destination folder is shown so the user knows where to find it without
    opening the link.

    Silent contract: raises on unrecoverable I/O errors only. The caller wraps
    in try/except because a broken Daily note must never block ingestion.
    """
    daily_path = VAULT_PATH / _READ_FOLDER / _DAILY_NOTE_NAME
    daily_path.parent.mkdir(parents=True, exist_ok=True)
    date_header = f"## {when.strftime('%Y-%m-%d')}"
    time_label = when.strftime("%H:%M")
    try:
        rel = note_path.relative_to(VAULT_PATH)
    except ValueError:
        rel = note_path
    stem = note_path.stem
    entry = f"- [{time_label}] [[{stem}|{title}]] → `{folder}/`"

    if not daily_path.is_file():
        frontmatter = (
            "---\n"
            f"created: '{when.isoformat(timespec='seconds')}'\n"
            "type: daily-index\n"
            "tags:\n- daily-index\n"
            "---\n\n"
            "# Daily note\n\n"
            "Registro de notas que entran al vault fuera de `00-Inbox/`. "
            "Append-only, agrupado por fecha.\n\n"
        )
        daily_path.write_text(
            frontmatter + f"{date_header}\n{entry}\n", encoding="utf-8",
        )
        return

    content = daily_path.read_text(encoding="utf-8")
    if date_header in content:
        # Append under today's section — find the next `## ` or EOF and insert
        # the entry at the end of the current section.
        lines = content.splitlines()
        try:
            i = lines.index(date_header)
        except ValueError:
            lines.append(date_header)
            lines.append(entry)
        else:
            # Walk forward to the section boundary (next `## ` or EOF).
            j = i + 1
            while j < len(lines) and not lines[j].startswith("## "):
                j += 1
            # Insert before the blank line that precedes the next section (if
            # any) so the structure stays clean.
            insert_at = j
            while insert_at > i + 1 and lines[insert_at - 1].strip() == "":
                insert_at -= 1
            lines.insert(insert_at, entry)
        daily_path.write_text("\n".join(lines) + "\n", encoding="utf-8")
        return

    # New day — append a fresh section at the end.
    tail = content if content.endswith("\n") else content + "\n"
    daily_path.write_text(
        tail + f"\n{date_header}\n{entry}\n", encoding="utf-8",
    )


def ingest_read_url(
    col: SqliteVecCollection,
    url: str,
    save: bool = False,
    fetcher=None,
) -> dict:
    """Core pipeline for `rag read`. Fetch → extract → summarize → (optionally)
    write to 00-Inbox. Returns a dict with keys `title`, `summary`, `tags`,
    `related` (list of titles), `path` (Path or None), `text_len`.

    `fetcher` override is for tests; default uses stdlib urllib.
    """
    is_youtube = _is_youtube_url(url)
    if is_youtube:
        # YouTube SPA has no useful body text; pull captions + title directly.
        # Skip HTML fetch — `fetcher` override is only consumed on the generic
        # path (tests that inject fake HTML don't cover YouTube).
        title, text = _fetch_youtube_content(url)
    else:
        fetch = fetcher or (lambda u: _read_fetch_url(u))
        html, _ = fetch(url)
        title, text = _read_extract(html)
    if len(text) < _READ_MIN_CHARS:
        hint = (
            "¿Captions deshabilitados, video privado, o región bloqueada?"
            if is_youtube else
            "¿Paywall, SPA sin SSR, o redirect?"
        )
        raise RuntimeError(
            f"Contenido insuficiente: {len(text)} caracteres extraídos "
            f"(mínimo {_READ_MIN_CHARS}). {hint}"
        )

    # First pass: quick related lookup using the raw text so we can feed the
    # titles to the summary prompt (command-r can then choose to link them).
    related_metas: list[dict] = []
    if col.count() > 0:
        try:
            seed_embed = embed([text[:2000]])[0]
            related_metas = _find_related_by_embedding(col, seed_embed, limit=5)
        except Exception:
            related_metas = []
    related_titles = [
        m.get("note", "") for m in related_metas if m.get("note")
    ]

    prompt = _read_summary_prompt(url, title, text, related_titles)
    summary = _read_generate_summary(prompt)
    if not summary:
        raise RuntimeError("Modelo devolvió un resumen vacío.")

    # Refine related: embed the summary itself (higher signal than raw text).
    if col.count() > 0:
        try:
            summary_embed = embed([summary])[0]
            refined = _find_related_by_embedding(col, summary_embed, limit=5)
            if refined:
                related_metas = refined
                related_titles = [
                    m.get("note", "") for m in related_metas if m.get("note")
                ]
        except Exception as exc:
            _silent_log('read_related_titles_gather', exc)

    note_title_for_tags = title or url
    try:
        tags = _suggest_tags_for_note(col, summary, note_title_for_tags, max_tags=5)
    except Exception:
        tags = []

    # YouTube: the folder is "Transcriptions" so the note must carry the actual
    # transcript, not just an LLM summary. Keep the summary as a leading
    # orientation block (useful for quick scan + wikilinks) and append the
    # full captions below under `## Transcripción`. For generic web reads,
    # the summary alone is the point.
    body_text = summary
    if is_youtube and text:
        body_text = f"{summary}\n\n## Transcripción\n\n{text}"

    created_iso = datetime.now().isoformat(timespec="seconds")
    note_body = _read_build_note(
        url, title, body_text, tags, related_titles, created_iso,
    )

    result = {
        "url": url, "title": title, "summary": summary, "tags": tags,
        "related": related_titles, "path": None,
        "text_len": len(text), "body": note_body,
    }

    if not save:
        return result

    now = datetime.now()
    stamp = now.strftime("%Y-%m-%d-%H%M")
    slug = _read_slug_from(title, url)
    # Route YouTube transcripts to the Transcriptions resource folder; other
    # reads stay in 00-Inbox. Notes that land outside Inbox get logged in the
    # Daily note so the user still sees "what entered the vault today" from
    # 00-Inbox alone.
    folder = _READ_YOUTUBE_FOLDER if is_youtube else _READ_FOLDER
    target_dir = VAULT_PATH / folder
    target_dir.mkdir(parents=True, exist_ok=True)
    candidate = target_dir / f"{stamp}-read-{slug}.md"
    i = 2
    while candidate.exists():
        candidate = target_dir / f"{stamp}-read-{slug}-{i}.md"
        i += 1
    candidate.write_text(note_body, encoding="utf-8")
    try:
        _index_single_file(col, candidate, skip_contradict=True)
    except Exception as exc:
        _silent_log('read_post_save_index', exc)
    # Daily note changelog — only for notes outside 00-Inbox (Inbox notes are
    # already visible when listing the folder). Silent-fail so a malformed
    # daily note never blocks the actual ingestion.
    if folder != _READ_FOLDER:
        try:
            _append_to_daily_note(candidate, title or url, folder, now)
        except Exception as exc:
            _silent_log('read_daily_note_append', exc)
    result["path"] = candidate
    return result


@cli.command("read")
@click.argument("url")
@click.option("--save", is_flag=True,
              help="Escribir la nota en 00-Inbox/ (default: dry-run)")
@click.option("--plain", is_flag=True,
              help="Salida plana sin ANSI (para bots)")
def read_cmd(url: str, save: bool, plain: bool):
    """Ingerir una URL externa como nota estructurada en el vault.

    Fetchea la página, resume con command-r en 1ra persona, busca notas
    relacionadas y arma una nota con frontmatter `type: read` + `source: <url>`.
    Sin --save imprime el preview; con --save escribe a
    `00-Inbox/YYYY-MM-DD-HHMM-read-<slug>.md` y la indexa.
    """
    if not (url.startswith("http://") or url.startswith("https://")):
        msg = "URL inválida: debe empezar con http:// o https://"
        click.echo(msg) if plain else console.print(f"[red]{msg}[/red]")
        raise SystemExit(1)

    col = get_db()
    t0 = time.perf_counter()
    try:
        result = ingest_read_url(col, url, save=save)
    except RuntimeError as e:
        click.echo(str(e)) if plain else console.print(f"[red]{e}[/red]")
        raise SystemExit(1)

    _total_s = time.perf_counter() - t0
    log_query_event({
        "cmd": "read", "url": url, "saved": bool(save),
        "title": result.get("title", ""),
        "text_len": result.get("text_len", 0),
        "n_related": len(result.get("related") or []),
        "n_tags": len(result.get("tags") or []),
        "t_retrieve": round(_total_s, 3),
        "timing": _round_timing_ms({"total_ms": _total_s * 1000}),
    })

    if plain:
        if save and result.get("path"):
            rel = result["path"].relative_to(VAULT_PATH)
            click.echo(f"guardado: {rel}")
        else:
            click.echo(result["body"])
        return

    header = result["title"] or url
    console.rule(f"[bold]📄 {header}[/bold]")
    console.print(f"[dim]URL:[/dim] {url}")
    if result.get("tags"):
        console.print(f"[dim]Tags:[/dim] {', '.join(result['tags'])}")
    if result.get("related"):
        rel_txt = ", ".join(f"[[{t}]]" for t in result["related"])
        console.print(f"[dim]Relacionadas:[/dim] {rel_txt}")
    console.print()
    console.print(render_response(result["summary"]))
    if save and result.get("path"):
        rel = result["path"].relative_to(VAULT_PATH)
        console.print(
            f"\n[green]✓ Guardado:[/green] [bold cyan]{rel}[/bold cyan]"
        )
    elif not save:
        console.print(
            "\n[dim]Dry-run. Re-correr con --save para escribir la nota.[/dim]"
        )


# ── MORNING BRIEF (rag morning) ──────────────────────────────────────────────
# Proactive daily brief: what happened yesterday + what's pending + what to
# focus today. Composes recent-notes / inbox / todo-frontmatter / new
# contradictions / low-conf queries. Writes to 04-Archive/99-obsidian-system/99-AI/reviews/YYYY-MM-DD.md.
# Auto-fires via launchd weekday mornings.

MORNING_FOLDER = "04-Archive/99-obsidian-system/99-AI/reviews"


# ── Daemon-generated paths ─────────────────────────────────────────────────
# Subcarpetas escritas por daemons / ingesters automáticos. Estas notas SÍ
# se indexan (el user puede preguntarle al RAG "qué eventos tengo en W18"),
# pero NO califican como "actividad del user" para el morning brief: están
# escritas por procesos que corren todos los días, así que su mtime no
# representa intención humana.
#
# Sin este filtro, el brief muestra `[[2026-04-29]]` (GitHub events daily),
# `[[2026-W18]]` (Calendar weekly), `[[2026-04-28]]` (Screentime daily),
# `[[_index]]` (Screentime index), etc. en "🎯 Foco sugerido" y "📝 Vaults",
# desplazando notas reales que el user editó. Mantenemos `is_excluded()`
# intacto (los daemons siguen siendo retrievable) y aplicamos esta lista
# solo en `_collect_morning_evidence` y `_fetch_vault_activity`.
_DAEMON_GENERATED_PREFIXES = (
    "03-Resources/Calendar/",
    "03-Resources/Chrome/",
    "03-Resources/GitHub/",
    "03-Resources/Gmail/",
    "03-Resources/Reminders/",
    "03-Resources/Screentime/",
    "03-Resources/WhatsApp/",
    "03-Resources/YouTube/",
    "03-Resources/GoogleDrive/",
    "00-Inbox/WA-",  # 00-Inbox/WA-YYYY-MM-DD.md (whatsapp listener daily)
    # mem-vault auto-saves: el agente escribe estas notas al cerrar tareas
    # no-triviales (decisions, bug patterns, gotchas). Se indexan para
    # retrieval (`is_excluded` las deja pasar arriba) pero su mtime NO es
    # actividad del user — es output del agente. Sin este filtro, una
    # sesión donde el agente guarda 5 memorias inflaba `recent_notes` con
    # 5 títulos "wa_draft_cjk_leak…", "feedback_ollama_runner…", etc. y
    # el LLM del brief intentaba narrar eso como "tu actividad".
    "04-Archive/99-obsidian-system/99-AI/memory/",
    # MOZE finance ETL: dumps mensuales/diarios de gastos. Ya se surfacean
    # en su propio bucket (`💸 Finanzas`) con totales calculados — meterlas
    # también como "notas tocadas" duplica la señal y empuja al LLM a
    # mezclar nombres de categorías ("House", "Consumibles") en el recap.
    "02-Areas/Personal/Finanzas/",
)


def _is_daemon_generated_path(rel_path: str) -> bool:
    """True si el path lo escribe un daemon/ingester automático y NO es
    actividad humana. Usado solo para depurar el morning brief — no afecta
    indexing ni retrieval. Defensivo ante None / paths absolutos.
    """
    if not rel_path:
        return False
    rel = rel_path.lstrip("/")
    return any(rel.startswith(p) for p in _DAEMON_GENERATED_PREFIXES)


# ── Apple integrations (Calendar / Reminders / Mail) ─────────────────────────
# osascript-backed evidence for the morning brief. Silent-fail by design:
# a timeout, missing app, or denied Automation permission returns []. First
# run triggers the macOS Automation prompt for Calendar/Reminders/Mail; user
# declines → integration stays dark, rest of the brief still works. Disable
# globally with OBSIDIAN_RAG_NO_APPLE=1.


def _osascript(script: str, timeout: float = 15.0) -> str:
    """Run AppleScript via osascript. Returns stdout stripped, or '' on any
    failure (timeout, non-zero exit, missing binary, permission denial).
    """
    import subprocess
    try:
        res = subprocess.run(
            ["osascript", "-e", script],
            capture_output=True, text=True, timeout=timeout,
        )
    except (FileNotFoundError, subprocess.TimeoutExpired, OSError):
        return ""
    if res.returncode != 0:
        return ""
    return (res.stdout or "").strip()


# Calendar.app AppleScript `whose` over events is O(all events) and times
# out in >2min on vaults with any history. EventKit via JXA is fast but
# osascript lacks the entitlement to see iCloud CalDAV calendars (it only
# exposes local ones — useless for an iCloud-primary user). The one
# pragmatic path is icalBuddy (`brew install ical-buddy`): talks to Calendar.app
# directly, sees all calendars, returns in <1s. If absent, Calendar section
# is silently skipped.


# `_REMINDERS_SCRIPT` and `_COMPLETED_REMINDERS_SCRIPT` moved to
# `rag.integrations.reminders` (Phase 1b, 2026-04-25). Re-exported at the
# bottom of this file.


# `_MAIL_SCRIPT` moved to `rag.integrations.apple_mail` (Phase 1b, 2026-04-25).
# Re-exported at the bottom of this file.


def _apple_enabled() -> bool:
    return os.environ.get("OBSIDIAN_RAG_NO_APPLE", "").strip() not in ("1", "true", "yes")


def _icalbuddy_path() -> str | None:
    """Resolve icalBuddy binary. Returns None if not installed."""
    import shutil
    for p in ("/opt/homebrew/bin/icalBuddy", "/usr/local/bin/icalBuddy"):
        if Path(p).is_file():
            return p
    return shutil.which("icalBuddy")


# `_fetch_calendar_today` moved to `rag.integrations.calendar` (Phase 1b,
# 2026-04-25). Re-exported at the bottom of this file.


# `_fetch_reminders_due` moved to `rag.integrations.reminders` (Phase 1b,
# 2026-04-25). Re-exported at the bottom of this file.


# ── NL datetime + recurrence parsing (feeds propose_reminder / propose_event) ─

# Weekday map for recurrence regex. RFC 5545 RRULE uses MO/TU/WE/TH/FR/SA/SU.
_RECUR_WEEKDAY_MAP = {
    # Spanish
    "lunes": "MO", "martes": "TU", "miércoles": "WE", "miercoles": "WE",
    "jueves": "TH", "viernes": "FR", "sábado": "SA", "sabado": "SA",
    "domingo": "SU",
    # English
    "monday": "MO", "tuesday": "TU", "wednesday": "WE", "thursday": "TH",
    "friday": "FR", "saturday": "SA", "sunday": "SU",
}


# Rioplatense idioms dateparser silently mangles or misses entirely.
# Regex is applied IN ORDER — keep the more specific patterns first.
# Each entry is (pattern, replacement) passed to `re.sub` with IGNORECASE.
# Tested empirically against `dateparser 1.4.0` on macOS / es-AR.
_RIOPLATENSE_REWRITES: tuple[tuple[str, str], ...] = (
    # Bug 2026-04-28: el "el" prefix antes de "DD de MES_ES" rompe
    # dateparser.parse() en versiones actuales. Lo strippeamos como
    # preproc para que la frase llegue limpia ("20 de septiembre").
    (
        r"\bel\s+(\d{1,2}\s+de\s+(?:enero|febrero|marzo|abril|mayo|junio|julio|"
        r"agosto|septiembre|setiembre|octubre|noviembre|diciembre)\b)",
        r"\1",
    ),
    # "18hs" / "18 hs" / "18h" / "18:30hs" → "18:00" / "18:30"
    # Handles bare "Xhs" by appending ":00"; leaves "X:Yhs" intact (just strips
    # the hs suffix). Only 1-2 digit hour blocks to avoid eating IDs/dates.
    (r"\b(\d{1,2}):(\d{2})\s*(?:hs?|h)\b\.?", r"\1:\2"),
    (r"\b(\d{1,2})\s*(?:hs?|h)\b\.?", r"\1:00"),
    # "X que viene" / "X que vienen" → bare English weekday / "next week"
    # / "next month" / "next year". Weekdays keep bare form (no "next ")
    # because dateparser 1.4 silently rejects "next <weekday>"; with
    # PREFER_DATES_FROM=future bare weekday rolls forward deterministic.
    (r"\bla\s+semana\s+que\s+vienen?\b", "next week"),
    (r"\bel\s+lunes\s+que\s+vienen?\b", "monday"),
    (r"\bel\s+martes\s+que\s+vienen?\b", "tuesday"),
    (r"\bel\s+mi[eé]rcoles\s+que\s+vienen?\b", "wednesday"),
    (r"\bel\s+jueves\s+que\s+vienen?\b", "thursday"),
    (r"\bel\s+viernes\s+que\s+vienen?\b", "friday"),
    (r"\bel\s+s[aá]bado\s+que\s+vienen?\b", "saturday"),
    (r"\bel\s+domingo\s+que\s+vienen?\b", "sunday"),
    (r"\bel\s+mes\s+que\s+vienen?\b", "next month"),
    (r"\bel\s+a[ñn]o\s+que\s+vienen?\b", "next year"),
    # "a las N de la mañana/tarde/noche" — dateparser can't pattern-match
    # Spanish "de la X" time-of-day qualifiers. Rewrite to am/pm.
    (r"\ba\s+las\s+(\d{1,2})(?::(\d{2}))?\s+de\s+la\s+ma[ñn]ana\b",
     lambda m: f"{m.group(1)}:{m.group(2) or '00'} am"),
    (r"\ba\s+las\s+(\d{1,2})(?::(\d{2}))?\s+de\s+la\s+tarde\b",
     lambda m: f"{int(m.group(1)) + (0 if int(m.group(1)) >= 12 else 12)}:{m.group(2) or '00'}"),
    (r"\ba\s+las\s+(\d{1,2})(?::(\d{2}))?\s+de\s+la\s+noche\b",
     lambda m: f"{int(m.group(1)) + (0 if int(m.group(1)) >= 12 else 12)}:{m.group(2) or '00'}"),
    # "a las Nam" / "a las Npm" / "a las N:MMam" — common bilingual form.
    # The "a las" prefix confuses dateparser (Spanish literal), and the
    # bare "a las N" rule below wouldn't match because the word boundary
    # between the digit and the "am"/"pm" letter doesn't fire. Strip
    # the "a las" so dateparser sees just "Nam"/"Npm".
    (r"\ba\s+las\s+(\d{1,2})(?::(\d{2}))?\s*(am|pm)\b",
     lambda m: f"{m.group(1)}:{m.group(2) or '00'}{m.group(3)}"),
    # Bare "a las N" / "a las N:MM" → explicit HH:MM. dateparser interprets
    # bare "a las 10" as "day 10" — this coerces it to a time.
    (r"\ba\s+las\s+(\d{1,2}):(\d{2})\b", r"\1:\2"),
    (r"\ba\s+las\s+(\d{1,2})\b(?!\s*:)", r"\1:00"),
    # "al mediodía" / "al medio día" → 12:00 literal.
    (r"\bal\s+medio\s*d[ií]a\b", "12:00"),
    (r"\ba\s+la\s+medianoche\b", "00:00"),
    # Diminutives are noise for dateparser.
    (r"\bhoritas?\b", "horas"),
    (r"\bminutit[oa]s?\b", "minutos"),
    # "después/antes/luego/tras de <actividad>" — temporal idiom for
    # "time-of-day relative to an activity", not a date. "El miércoles
    # después de gimnasia" means Wednesday at gym-end time, NOT the day
    # after gym. Strip the verb + optional `de[l]` + optional article +
    # <word> block when <word> is an activity noun (not a temporal
    # anchor). "tras" typically doesn't take `de` in rioplatense
    # ("tras el entrenamiento"), hence both `de...` and bare article
    # are optional. Allow list preserves "después de mañana" (day
    # after tomorrow), "antes del almuerzo" (late morning), etc.
    (
        r"\s+(?:despu[eé]s|antes|luego|tras)\s+"
        r"(?:(?:del|de\s+(?:la|el|los|las)|de)\s+)?"
        r"(?:(?:la|el|los|las)\s+)?"
        r"(?!ma[ñn]ana|hoy|ayer|medio\s*d[ií]a|medianoche|almuerzo|desayuno|"
        r"cena|comida|semana|mes|a[ñn]o)\w+",
        "",
    ),
    # "pasado mañana" — dateparser 1.4 falla silenciosamente en es;
    # el inglés "day after tomorrow" lo resuelve perfectamente.
    (r"\bpasado\s+ma[ñn]ana\b", "day after tomorrow"),
    # "el finde" — ambiguous between sábado/domingo; bias toward sábado.
    # Con PREFER_DATES_FROM=future dateparser resuelve el próximo.
    (r"\bel\s+finde\b", "saturday"),
    # Bare "el <weekday>" / "este <weekday>" / "próximo <weekday>" →
    # English weekday name solo. Con PREFER_DATES_FROM=future dateparser
    # lo interpreta como próximo <weekday> determinista. "next <weekday>"
    # NO funciona (dateparser 1.4 lo rechaza silenciosamente).
    (r"\b(?:el|este|pr[oó]xim[oa])\s+lunes\b(?!\s+que)", "monday"),
    (r"\b(?:el|este|pr[oó]xim[oa])\s+martes\b(?!\s+que)", "tuesday"),
    (r"\b(?:el|este|pr[oó]xim[oa])\s+mi[eé]rcoles\b(?!\s+que)", "wednesday"),
    (r"\b(?:el|este|pr[oó]xim[oa])\s+jueves\b(?!\s+que)", "thursday"),
    (r"\b(?:el|este|pr[oó]xim[oa])\s+viernes\b(?!\s+que)", "friday"),
    (r"\b(?:el|este|pr[oó]xim[oa])\s+s[aá]bado\b(?!\s+que)", "saturday"),
    (r"\b(?:el|este|pr[oó]xim[oa])\s+domingo\b(?!\s+que)", "sunday"),
    # "a la mañana" / "a la tarde" / "a la noche" — dateparser no lo parsea;
    # mapeamos a horas defaults razonables.
    (r"\ba\s+la\s+ma[ñn]ana(?:\s+temprano)?\b", "09:00"),
    (r"\ba\s+la\s+tarde\b", "16:00"),
    (r"\ba\s+la\s+noche\b", "20:00"),
    (r"\ba\s+la\s+tardecita\b", "17:00"),
    (r"\ba\s+la\s+nochecita\b", "20:00"),
    # "tipo N" / "a eso de las N" → "N:00". "Tipo" es idiom rioplatense
    # de aproximación. La variante "a eso de las N de la mañana/tarde/noche"
    # necesita su propia regla (se aplica ANTES de la versión bare para
    # que la bare no le coma el número).
    (r"\ba\s+eso\s+de\s+las?\s+(\d{1,2})(?::(\d{2}))?\s+de\s+la\s+ma[ñn]ana\b",
     lambda m: f"{m.group(1)}:{m.group(2) or '00'} am"),
    (r"\ba\s+eso\s+de\s+las?\s+(\d{1,2})(?::(\d{2}))?\s+de\s+la\s+tarde\b",
     lambda m: f"{int(m.group(1)) + (0 if int(m.group(1)) >= 12 else 12)}:{m.group(2) or '00'}"),
    (r"\ba\s+eso\s+de\s+las?\s+(\d{1,2})(?::(\d{2}))?\s+de\s+la\s+noche\b",
     lambda m: f"{int(m.group(1)) + (0 if int(m.group(1)) >= 12 else 12)}:{m.group(2) or '00'}"),
    (r"\btipo\s+(\d{1,2}):(\d{2})\b", r"\1:\2"),
    (r"\btipo\s+(\d{1,2})\b(?!\s*:)", r"\1:00"),
    (r"\ba\s+eso\s+de\s+las?\s+(\d{1,2}):(\d{2})\b", r"\1:\2"),
    (r"\ba\s+eso\s+de\s+las?\s+(\d{1,2})\b(?!\s*:)", r"\1:00"),
)

_RIOPLATENSE_COMPILED = tuple(
    (re.compile(pat, re.IGNORECASE), rep) for pat, rep in _RIOPLATENSE_REWRITES
)


def _preprocess_rioplatense_datetime(text: str) -> str:
    """Normalise common rioplatense idioms so dateparser can resolve them.

    Surface-level substitutions only — time-of-day aliases (`18hs`,
    `al mediodía`), "X que viene" constructions, diminutives, `el finde`.
    Semantic interpretation (e.g. "a la tardecita" → 17:00) is left to
    the LLM fallback; hard-coding those would need per-user calibration.
    """
    if not text:
        return text
    s = text
    for pat, rep in _RIOPLATENSE_COMPILED:
        s = pat.sub(rep, s)
    return s


# Tokens that indicate the input carries a time-of-day reference. Used to
# detect the dateparser "anchor echo" failure mode — when it silently
# returns the anchor datetime's time because it couldn't parse the time
# portion of a rioplatense-flavoured input ("a las 10 de la mañana"
# → anchor time instead of 10:00).
_TIME_MARKER_RE = re.compile(
    r"\b(las|hora|minuto|medio.?d[ií]a|medianoche|ma[ñn]ana|tarde|noche|"
    r"tardecita|nochecita|tempran)\b"
    r"|\d{1,2}\s*(?:hs?|h|am|pm|:)",
    re.IGNORECASE,
)

# Narrower counterpart used by `_parse_natural_datetime` to decide whether
# the input had an EXPLICIT clock — i.e. a specific hour the user meant.
# `_TIME_MARKER_RE` above also matches `mañana` as a "time marker" because
# it doubles as period-of-day ("a la mañana"), but on its own "mañana"
# is a day word. When the input is day-only we want to normalize to a
# default hour (09:00) instead of echoing dateparser's leak of the
# anchor's runtime hour + microseconds (the "2026-04-22T03:01:35.115"
# bug reported 2026-04-21).
#
# Matches:
#   - Digit clocks: 20hs / 20h / 20:30 / 8am / 4pm / 14:00
#   - Period words only when preceded by "a la/las/medio/eso de" →
#     "a la mañana" (≈09:00), "a la tarde" (≈16:00), "al mediodía"
#     (12:00). Bare "mañana"/"tarde"/"noche" DO NOT qualify.
_CLOCK_RE_EXPLICIT = re.compile(
    r"\d{1,2}\s*(?:hs?|h|am|pm|:)"
    r"|\d{1,2}:\d{2}"
    r"|\ba\s+las?\s+\d{1,2}"
    r"|\b(?:al|a\s+la)\s+(?:medio.?d[ií]a|medianoche|ma[ñn]ana|tarde|noche|"
    r"tardecita|nochecita)\b"
    r"|\beso\s+de\s+las?\s+\d{1,2}",
    re.IGNORECASE,
)


# ── Create-intent detection (shared by web `/api/chat` + CLI `rag chat`) ─────
#
# Moved here from web/server.py so the CLI chat loop can reuse it without
# importing the FastAPI module. `_detect_propose_intent(q)` returns True
# when the user's message should trigger propose_reminder /
# propose_calendar_event tool calls (bypassing vault retrieval).
#
# Three branches:
#   1. Explicit create verb — "recordame X", "creá un evento", "calendarizalo",
#      "agendá una reunión", "anotá en el calendario".
#   2. Statement with event noun + temporal anchor + not a question.
#      "mañana tengo daily", "hay standup el jueves", "me citaron para
#      entrevista el viernes 3pm".
#   3. Statement with visit pattern (viene/pasa/llega/visita X) + temporal
#      + not a question. "mañana viene gracia a casa".

# Bare meta-chat messages — greetings, thanks, "what can you do". They
# should NOT go through retrieval + the `_WEB_SYSTEM_PROMPT` "engancháte
# con el contexto" rule, which otherwise produces "Según tus notas, tenés
# varias interacciones con diferentes contactos por WhatsApp..." for a
# simple "hola" (reported 2026-04-21 Playwright probe, Fer F.). The web
# handler short-circuits with a canned response; CLI/WA use their own
# flows but can borrow the detector for consistency.
#
# Matching strategy: tight. False negatives ("qué tal el proyecto") are
# fine — they route through the normal retrieve pipeline and get a useful
# answer. False positives (a real question matched as meta) are bad —
# user gets a canned "¡Hola!" instead of a real answer.
_METACHAT_RE = re.compile(
    # Optional opening "¿" (rioplatense question mark). Hoisted out of the
    # per-alternative list so every branch gets it — previously only meta-
    # question alternatives carried the `¿?\s*` prefix, so "¿cómo estás?"
    # didn't match.
    r"^\s*¿?\s*(?:"
    # Greetings
    r"hola|holi|holis|buenas(?:\s+tardes|\s+noches|\s+d[ií]as)?|buen\s+d[ií]a|"
    r"hi|hey|hello|saludos|qu[eé]\s+tal|qu[eé]\s+onda|"
    # 2026-04-28 wave-6: "cómo va" tightened — antes matchaba "cómo va a
    # estar la semana?" como metachat (false positive). Ahora requiere que
    # "cómo está/andás/va" sea la última cosa significativa antes del
    # cierre — bloqueamos la continuación con "a estar/el clima/...".
    r"c[oó]mo\s+(?:est[aá]s|and[aá]s)(?:\s+(?:hoy|tod[ao]|amig[oa]|che|loco))?(?!\s+\w)|"
    r"c[oó]mo\s+va(?!\s+a\s+|\s+el\s|\s+la\s|\s+los\s|\s+las\s)|"
    # Casual check-ins (2026-04-28 wave-5 — "todo bien" antes ruteaba
    # a reminders_due porque "tengo recordatorios pendientes" matchea
    # confidence > weak. Bare check-ins son metachat, no queries.)
    r"todo\s+bien|todo\s+ok|todo\s+okey|"
    r"como\s+est[aá]\s+todo|c[oó]mo\s+va\s+todo|qu[eé]\s+m[aá]s|"
    # Thanks / closings (bare, not followed by content)
    r"gracias|muchas\s+gracias|mil\s+gracias|dale\s+gracias|thanks|thx|"
    r"chau|bye|adi[oó]s|nos\s+vemos|"
    # Meta-questions about the bot
    r"qu[eé]\s+pod[eé]s\s+hacer|"
    r"qu[eé]\s+sab[eé]s\s+hacer|"
    r"c[oó]mo\s+(?:funcion[aá]s|te\s+us[oa]|te\s+uso)|"
    r"qu[eé]\s+comandos\s+(?:hay|tenes|ten[eé]s|ten[eé]i?s)|"
    r"ayuda|help|"
    r"qui[eé]n\s+sos|qui[eé]n\s+es\s+este\s+bot"
    r")"
    # Optional very short trailing text (up to 20 chars), then end.
    # This lets "hola, cómo estás?" through but rejects long queries
    # that happen to start with "hola".
    r"\s*[!?.¡¿,:;]*\s*.{0,20}$",
    re.IGNORECASE,
)


def _detect_metachat_intent(q: str) -> bool:
    """Return True if `q` is a bare greeting / thank-you / meta-question
    about the bot. Used by the web `/api/chat` handler to short-circuit
    retrieval + LLM generation with a canned response — otherwise the
    _WEB_SYSTEM_PROMPT "engancháte con el CONTEXTO" rule produces
    fabricated "según tus notas..." prose for inputs that have no real
    question to answer.

    Tight matcher by design: false-negative "qué tal el proyecto" → still
    routes through retrieve (good); false-positive "hola" → canned reply
    (fine). See `_METACHAT_RE` for the full pattern list.
    """
    if not q:
        return False
    s = q.strip()
    if not s:
        return False
    # Only fire on short messages — long queries that happen to start
    # with "hola" ("hola necesito saber X") should still hit retrieval.
    if len(s) > 40:
        return False
    return bool(_METACHAT_RE.match(s))


_PROPOSE_INTENT_RE = re.compile(
    # Reminder triggers. `anot[aá](?:me|rme)` + `apunt[aá](?:me|rme)` +
    # `no te olvides de` added 2026-04-21 after the Fer F. Playwright probe
    # found that "anotame llamar al plomero el viernes" fell through to a
    # plain retrieval path and the LLM fabricated "Se ha registrado tu
    # recordatorio…" without calling any tool (silent hallucination —
    # user thinks something was saved, nothing was). Mirrors
    # `detectReminderIntent` in whatsapp-listener/listener.ts which already
    # covered these verbs.
    r"\brecord[aá](?:me|te|rme|arme|d)?\b"
    r"|\brecu[eé]rda(?:me)?\b"
    r"|\bacord[aá](?:te|rme|ate|áte|me)\b"
    r"|\banot[aá](?:me|rme)?\b"
    r"|\bapunt[aá](?:me|rme)?\b"
    r"|\bno\s+te\s+olvides(?:\s+de)?\b"
    r"|\bagend[aá]me\b"
    r"|\bpon[eé](?:me|te|le)?\s+(?:un\s+)?recordatorio\b"
    r"|\bagreg(?:á|a|ar)\s+(?:un\s+)?recordatorio\b"
    # Calendar triggers (create verb + event noun). Require the noun to
    # avoid matching queries like "qué eventos tengo" (already covered by
    # calendar_ahead read-intent).
    r"|\b(?:cre[aá]|crear|agend[aá]|bloque[aá]|pon[eé]|agreg[aá])\b"
    r"[^.?!]*"
    r"\b(?:evento|reuni[oó]n|cita|turno|llamad[ao]|meeting|appointment)\b"
    # Calendar-specific verbs that carry create intent on their own —
    # "calendarizalo", "agendalo/agendala/agendame/agendar", "anotá en el
    # calendario/agenda", "poné en el calendario/agenda". No event noun
    # required because these verbs directly mean "put this in the calendar".
    r"|\bcalendariz(?:á|ar|arl[oa]|al[oa]|ame|armel[oa]|amel[oa])\b"
    r"|\bagend[aá](?:l[oa]|ame(?:l[oa])?|r|ar)\b"
    r"|\bpon(?:é|el[oa]|eme|ele)\s+(?:en\s+)?(?:el\s+|la\s+)?(?:calendario|agenda)\b"
    # WhatsApp-send triggers (Fer F. 2026-04-24 report: el chat web no
    # disparaba `propose_whatsapp_send` con "enviale un mensaje a Grecia:
    # ..." porque no estaba en ningún propose-intent list — caía a prosa
    # sin tool). Verbos rioplatenses de "escribir a tercero" con
    # encliticos -le/-rle (pronombre indirecto marca "a un tercero").
    # Dos formas:
    #   A) verbo-con-le + sustantivo de mensaje o whatsapp:
    #      "enviale un mensaje", "mandale un whatsapp", "decile un wzp"
    #   B) verbo-con-le + "a <Nombre>":
    #      "mandale a Grecia", "decile a Papá", "escribile a mi hermano"
    # El {0,40} interno entre el verbo y el target evita matchear cosas
    # como "enviarle la plata a Juan" (no es un message intent).
    r"|\b(?:m[aá]nd[aá](?:le|sel[oa]|sele|rle)?"
    r"|env[ií][aá](?:le|sel[oa]|sele|rle)?"
    r"|escrib[ií](?:le|rle)"
    r"|avis[aá](?:le|rle)"
    r"|dec[ií]le|decirle)"
    r"\s+(?:[^.?!]{0,40})?"
    r"(?:un\s+(?:mensaje|whats.?app|wzp|wsp|texto|chat)"
    r"|a\s+[A-ZÁÉÍÓÚÑ][\wáéíóúñ]+)"
    # WhatsApp-REPLY triggers (2026-04-24 wa-reply feature). Verbos rioplatenses
    # de "responder a un mensaje" — distinto del send a un tercero porque acá
    # el target es un mensaje específico, no un contacto en abstracto.
    # Forms cubiertas:
    #   - "respondele a Juan ..."
    #   - "contestale a Grecia ..."
    #   - "replyle a Pedro ..."
    #   - "responde el mensaje de X ..."
    #   - "contesta el último de Mariana ..."
    # Sin "le" trailing también aceptamos cuando aparece "el mensaje/último/wzp".
    r"|\b(?:respond[eé](?:le|rle|sele)?"
    r"|contest[aá](?:le|rle|sele)?"
    r"|reply\s*le?|replic[aá](?:le|rle)?)"
    r"\s+(?:[^.?!]{0,60})?"
    r"(?:el\s+(?:mensaje|[uú]ltimo|wzp|wsp|whats.?app)"
    r"|al\s+(?:mensaje|wzp|wsp)"
    r"|a\s+[A-ZÁÉÍÓÚÑ][\wáéíóúñ]+)",
    re.IGNORECASE,
)

_EVENT_NOUN_RE = re.compile(
    r"\b(?:reuni[oó]n|evento|cita|turno|llamada|daily|stand-?up|meeting|"
    r"entrevista|\bcall\b|sync|retro(?:spectiva)?|planning|demo|all.?hands|"
    r"sprint(?:\s+(?:review|planning))?|visita|clase|entrenamiento|"
    r"sesi[oó]n|taller|workshop|webinar|conferencia|almuerzo|cena|show|"
    r"concierto|partido|cumplea[ñn]os|cumple|aniversario|viaje|vuelo|appointment|"
    r"1:1|1on1|one.?on.?one|uno.?a.?uno)\b",
    re.IGNORECASE,
)

_VISIT_PATTERN_RE = re.compile(
    r"\b(?:viene|vienen|viene\s+a|pasa|pasan|llega|llegan|visit[ao]|"
    r"trae|traen|trae\s+a|recojo|recoger|buscamos|busco|busc[aá]n)\b",
    re.IGNORECASE,
)

_TEMPORAL_ANCHOR_RE = re.compile(
    r"\b(?:ma[ñn]ana|pasado\s+ma[ñn]ana|hoy|esta\s+(?:noche|tarde|ma[ñn]ana)|"
    r"(?:el|este|pr[oó]xim[oa])\s+(?:lunes|martes|mi[eé]rcoles|jueves|"
    r"viernes|s[aá]bado|domingo|finde|semana|mes|a[ñn]o)|"
    r"la\s+semana\s+que\s+vienen?|el\s+(?:finde|mes\s+que\s+vienen?|"
    r"a[ñn]o\s+que\s+vienen?)|"
    r"a\s+las?\s+\d|tipo\s+\d|a\s+eso\s+de\s+las|"
    r"en\s+\d+\s+(?:minutos?|horas?|d[ií]as?|semanas?))\b"
    r"|\b\d{1,2}\s*(?:hs|h|am|pm)\b|\d{1,2}:\d{2}"
    # Absolute date forms — 2026-04-21 Fer F. probe: "el 26 de Mayo es el
    # cumple de Astor" fell through every detector because no branch
    # recognised the "<day> de <month>" anchor. Now covered:
    #   - "el 26 de mayo" / "el 5 de enero" (with optional leading "el/este/próximo")
    #   - "26 de mayo" bare
    #   - "26/05" / "26-05" / "26/5/2026" numeric
    # `\w+` in Python is Unicode-aware by default so accented month names
    # like "febrero" / "diciembre" match without explicit listing.
    r"|\b(?:el|este|pr[oó]xim[oa])?\s*\d{1,2}\s+de\s+"
    r"(?:enero|febrero|marzo|abril|mayo|junio|julio|"
    r"agosto|septiembre|setiembre|octubre|noviembre|diciembre)\b"
    r"|\b\d{1,2}[/-]\d{1,2}(?:[/-]\d{2,4})?\b",
    re.IGNORECASE,
)

_QUESTION_START_RE = re.compile(
    # Opcional `¿` inicial (rioplatense/es típicamente abre preguntas así).
    # 2026-04-21 regression: "¿qué hago el viernes 20hs?" se colaba como
    # propose-intent por branch 4 (declaration+time) porque el regex antiguo
    # exigía la palabra interrogativa como primer carácter no-blanco, sin
    # contemplar el `¿`. Mismo fix que se hizo en whatsapp-listener.
    r"^\s*¿?\s*(?:qu[eé]|qui[eé]n(?:es)?|cu[aá]ndo|cu[aá]nto|cu[aá]nta|cu[aá]l|"
    r"d[oó]nde|c[oó]mo|por\s+qu[eé]|a\s+qu[eé]|de\s+qu[eé])\b",
    re.IGNORECASE,
)

# Imperativos de consulta — el user pide ver/listar algo existente, no
# crear. "decime/contame/dime/mostrame/tirame/dale, decime" son formas
# comunes rioplatenses equivalentes a "¿qué ...?". Sin este check, queries
# como "decime que tengo para la semana que viene" caían al branch 3
# propose-intent (visit_pattern matcheaba "viene" dentro de "que viene")
# y el flow terminaba con el LLM alucinando un tool_call fake (2026-04-24
# Fer F. report). Por diseño solo cubre inicio de string — si aparece
# en el medio del texto no descalifica.
_IMPERATIVE_QUERY_RE = re.compile(
    r"^\s*¿?\s*(?:dec[ií]me|cont[aá]me|dime|d[ií]game|mostr[aá]me|"
    r"most[eé]ename|tir[aá]me|dale\s+dec[ií]me|list[aá]me|list[aá]|"
    r"mostr[aá]|muestra(?:me)?|enumer[aá](?:me)?)\b",
    re.IGNORECASE,
)

# Matchea frases temporales idiomáticas donde "viene/vienen" es parte del
# idiom (semana/mes/año/finde que viene = next week/month/year/weekend),
# no un verbo de visita. El stripping lo usa `_detect_propose_intent`
# para evitar que el VISIT_PATTERN confunda "la semana que viene" con
# una visita real ("Juan viene el viernes").
_TEMPORAL_VIENE_IDIOM_RE = re.compile(
    # IMPORTANTE: `mes(?:es)?` en vez de `meses?` — el suffix `s?` solo
    # hace opcional la última letra, así que `meses?` matchea "mese"
    # y "meses" pero NO "mes" singular. Mismo trato para "día/días"
    # y otros singulares/plurales donde el plural agrega >1 char.
    r"\b(?:la|el|este|esta|pr[oó]xim[oa])\s+"
    r"(?:semanas?|mes(?:es)?|a[ñn]os?|fin(?:es)?\s+de\s+semanas?|findes?|"
    r"d[ií]as?|tardes?|ma[ñn]anas?|noches?)\s+"
    r"que\s+vienen?\b",
    re.IGNORECASE,
)

# 2026-04-28 wave-4: detector de queries de weather/forecast como
# disqualifier de propose intent. "clima en X para mañana" cae bajo
# branch 4 (has_explicit_time porque "mañana" matchea como time-of-day
# adverb) → mal flag de propose intent → bypass del weather pre-router →
# LLM emite "工具调用：propose_weather_forecast(...)" en chino. Guard
# explícito al inicio de _detect_propose_intent corrige el routing.
_WEATHER_QUERY_PREFIX_RE = re.compile(
    r"\b(?:clima|tiempos?|pron[oó]stico|temperatur[ao]s?|"
    r"qu[eé]\s+tiempo\s+(?:hace|va\s+a\s+hacer))\b",
    re.IGNORECASE,
)


def _detect_propose_intent(q: str) -> bool:
    """Return True if `q` looks like a CREATE request (reminder or event).

    Three-branch detection described at the module-level comment above.
    Used by both the web chat endpoint (to force the LLM tool-decide
    round and bypass vault retrieval) and the CLI `rag chat` loop (to
    route the turn to the tool-calling helper instead of query-RAG).
    """
    if not q:
        return False
    # 2026-04-28 wave-4: queries de clima/tiempo NUNCA son propose-intent.
    # "mañana" en "clima en Mendoza para mañana" se interpretaba como
    # explicit_time → propose_intent → bypass del weather pre-router.
    # Repro Playwright: la query devolvía "工具调用：propose_weather_forecast(...)"
    # en chino porque el LLM no podía rutear correctamente. Guard explícito
    # acá previene el cross-fire.
    if _WEATHER_QUERY_PREFIX_RE.search(q):
        return False
    if _PROPOSE_INTENT_RE.search(q):
        return True
    # Disqualifiers antes de los branches implícitos — cualquiera de los
    # dos gates descarta la query como propose sin importar temporal/visit.
    # (a) Question-word start ("¿qué hago el viernes?").
    # (b) Imperative-query start ("decime qué tengo la semana que viene")
    #     — son formas de pedir info sobre lo existente, no create.
    if _QUESTION_START_RE.match(q) or _IMPERATIVE_QUERY_RE.match(q):
        return False
    has_temporal = bool(_TEMPORAL_ANCHOR_RE.search(q))
    if not has_temporal:
        return False
    if _EVENT_NOUN_RE.search(q):
        return True
    # Antes del visit-pattern check, strip los idioms "X que viene" donde
    # "viene" no es visita sino parte del temporal anchor (la semana que
    # viene / el año que viene / etc.). Sin esto, "decime qué tengo la
    # semana que viene" caía acá con match false-positive sobre "viene".
    q_stripped = _TEMPORAL_VIENE_IDIOM_RE.sub("", q)
    if _VISIT_PATTERN_RE.search(q_stripped):
        return True
    # Branch 4 — declaration with explicit clock time. Mirror of the
    # whatsapp-listener `detectCalendarIntent` branch 3 (commit 8a08192).
    # Regression 2026-04-21 Fer F.: "el viernes 20hs tengo que ir de Seba"
    # was handled correctly on WA (branch 3 added there) but the web chat
    # still fell through to the generic RAG prose because this function
    # didn't catch it. The missing branch is also what CLI `rag chat`
    # consults, so it now picks up declarations there too.
    #
    # Signal: `_has_explicit_time` (20hs / 15:30 / a las 10 / 8pm /
    # medianoche / al mediodía) + the already-checked `has_temporal` (el
    # viernes / mañana / ...) + not a question. That combo is rarely
    # ambiguous — the user doesn't need an event noun like "reunión" for
    # us to realize they're describing a scheduled moment.
    if _has_explicit_time(q):
        return True
    return False


def _has_explicit_time(text: str) -> bool:
    """Return True if `text` mentions a specific time of day.

    Used by propose_calendar_event to decide between all-day vs timed
    event: if the user said "el miercoles viene Grecia" without a time
    → all-day; "el miercoles a las 4pm" → 16:00-17:00 timed slot.

    Matches any of:
      - `a las N` / `las N` / `N hora(s)` / `N minuto(s)`
      - `al mediodía` / `a la medianoche` / `a la mañana|tarde|noche`
      - `tardecita` / `nochecita` / `tempranito` / `tempran*`
      - Digit patterns: `18hs`, `18h`, `10am`, `4pm`, `14:30`

    Pure substring regex, no side effects — safe for tool fast path.

    2026-04-28 wave-8 fix: usaba `_TIME_MARKER_RE` que matchea "mañana"
    sola (porque doublea como period-of-day en "a la mañana"), lo cual
    rompía propose-intent: "y mañana?" caía en branch 4 con
    has_temporal=True + has_explicit_time=True → True. Pero "mañana"
    sola es DAY word, no clock. La constante narrow `_CLOCK_RE_EXPLICIT`
    fue definida exactamente para este caso (require digit clock o
    "a la|al + period"); plug-in pendiente desde 2026-04-21.
    """
    if not text:
        return False
    return bool(_CLOCK_RE_EXPLICIT.search(text))


def _parse_natural_datetime(
    text: str,
    now: datetime | None = None,
    *,
    prefer_future: bool = True,
    lang: tuple[str, ...] = ("es", "en"),
) -> datetime | None:
    """Parse a natural-language date/time string to a concrete `datetime`.

    Pipeline:
      1. `_preprocess_rioplatense_datetime` rewrites common AR idioms
         (`18hs` → `18:00`, `al mediodía` → `12:00`, `el X que viene` →
         `próximo X`, diminutives, `el finde`).
      2. `dateparser` (es + en, `PREFER_DATES_FROM=future`) tries to parse.
      3. Anchor-echo guard: if the input carries a time marker but
         dateparser returned a datetime whose time equals the anchor's
         (a known dateparser failure mode on partial time parses), we
         discard it and fall through.
      4. LLM fallback: qwen2.5:3b helper with a rioplatense-aware prompt
         returns `{iso: …}` or `{iso: null}`.

    Returns `None` if all three fail. Callers decide whether to treat as
    error or prompt the user for clarification.
    """
    s = (text or "").strip()
    if len(s) < 3:
        return None

    anchor = now or datetime.now()
    s_norm = _preprocess_rioplatense_datetime(s)
    # Timezone: explicit Argentina (UTC-3) by default, overridable via
    # RAG_TIMEZONE. Without this, dateparser's absolute-date parsing on
    # inputs with offsets or UTC Z-suffix could shift the final datetime
    # relative to what the user meant. Naive datetimes (no offset in
    # input) pass through unchanged; only affects ISO strings / RFC
    # forms that carry tzinfo. We then strip tzinfo below so the rest
    # of the codebase (AppleScript creators, log timestamps) sees a
    # naive local datetime.
    _tz = os.environ.get("RAG_TIMEZONE", "").strip() or "America/Argentina/Buenos_Aires"
    settings = {
        "RELATIVE_BASE": anchor,
        "PREFER_DATES_FROM": "future" if prefer_future else "current_period",
        "RETURN_AS_TIMEZONE_AWARE": False,
        "TIMEZONE": _tz,
        "TO_TIMEZONE": _tz,
    }
    try:
        import dateparser  # noqa: PLC0415
        dt = dateparser.parse(s_norm, languages=list(lang), settings=settings)
    except Exception:
        dt = None

    if isinstance(dt, datetime):
        if dt.tzinfo is not None:
            dt = dt.replace(tzinfo=None)
        # Anchor-echo sanity: dateparser sometimes echoes the anchor
        # ENTIRELY (same date AND time) when it only matched a stray token
        # and treated the rest as context ("a las 10 de la mañana" →
        # anchor). If the input looks time-bearing and dt == anchor
        # minute-wise, distrust and fall through to LLM. We intentionally
        # NO LONGER check hour-only equality — that produced false
        # positives on valid parses like "friday 15:00" when anchor also
        # happened to be at 15:00.
        _has_time_marker = bool(_TIME_MARKER_RE.search(s_norm))
        if _has_time_marker and dt.replace(second=0, microsecond=0) == anchor.replace(second=0, microsecond=0):
            dt = None
        else:
            # No EXPLICIT clock time in the input → dateparser defaulted
            # to the anchor's time component ("mañana" with anchor=
            # 03:01:35.115 returns tomorrow at 03:01:35.115). That leaks
            # the bot's runtime hour + microseconds into the reminder's
            # due_iso; users see "recordame X mañana" produce
            # "2026-04-22T03:01:35.115539" (reported 2026-04-21 Playwright
            # probe, Fer F.).
            #
            # `_TIME_MARKER_RE` is too broad for this guard — it flags
            # "mañana" (the day word) as a time marker because the same
            # literal is also used as period-of-day ("a la mañana" ≈
            # 09:00). Use `_CLOCK_RE_EXPLICIT` below to require a
            # digit-bearing clock or a period-word preceded by "a la…".
            # Without that, every day-only input like "mañana" /
            # "el viernes" / "hoy" fell into the else branch and kept
            # the leaked anchor time.
            #
            # Normalize day-only inputs to a sensible default hour:
            # 09:00 AR-local is the slot Siri uses when users create
            # day-only reminders via dictation. Zero out seconds /
            # microseconds for clock-bearing inputs so downstream ISOs
            # are clean.
            if not _CLOCK_RE_EXPLICIT.search(s_norm):
                dt = dt.replace(hour=9, minute=0, second=0, microsecond=0)
            else:
                dt = dt.replace(second=0, microsecond=0)
            return dt

    # LLM fallback. Prompt explicitly flags rioplatense so the helper
    # model doesn't regress on idioms like "la semana que viene" or
    # "a la tardecita". Anchor is given both in ISO and a Spanish weekday
    # label to help the model anchor relative references correctly —
    # qwen2.5:3b otherwise mixes up "el jueves" (should roll forward) with
    # the current day on deterministic seed. We pass the pre-processed
    # form as a hint alongside the original so the model sees e.g.
    # "el jueves 16:00" when the user wrote "el jueves a las 4 de la tarde"
    # — makes am/pm interpretation unambiguous.
    _es_weekdays = ["lunes", "martes", "miércoles", "jueves", "viernes", "sábado", "domingo"]
    _es_anchor_day = _es_weekdays[anchor.weekday()]
    _hint_line = f' Hint: "{s_norm}"' if s_norm != s else ""
    prompt = (
        "Parseá esta fecha/hora en lenguaje natural. "
        "El usuario habla español argentino (rioplatense). "
        "Zona horaria: Argentina (UTC-3). Semana arranca el LUNES "
        "(convención ISO: lunes=1, domingo=7).\n"
        "Idioms rioplatense frecuentes: "
        "'la semana que viene' (~7 días después, próximo lunes), "
        "'a la tardecita' (~17:00), 'a la nochecita' (~20:00), "
        "'a la noche' (~20:00), 'tempranito' (~7:00), "
        "'el finde' (sábado), '18hs' (18:00), 'a eso de las X' (~X:00), "
        "'4 de la tarde' (16:00), 'tipo X' (~X:00).\n"
        f"Ahora es {anchor.strftime('%Y-%m-%d %H:%M')} ({_es_anchor_day}) "
        "en hora local Argentina. "
        "Si el usuario dice un día de la semana sin más contexto "
        "('el jueves'), asumí el PRÓXIMO de esa semana (rollforward). "
        "Si no dio hora, usá 09:00.\n\n"
        f'Texto: "{s}"{_hint_line}\n\n'
        'Respondé SOLO con JSON válido: {"iso": "YYYY-MM-DDTHH:MM"} '
        '(sin offset, hora local argentina) '
        'o {"iso": null} si no hay fecha clara. '
        "Sin prosa, sin bloques de código."
    )
    try:
        resp = _helper_client().chat(
            model=HELPER_MODEL,
            messages=[{"role": "user", "content": prompt}],
            options=HELPER_OPTIONS,
            keep_alive=OLLAMA_KEEP_ALIVE,
        )
        raw = (resp.message.content or "").strip()
    except Exception:
        return None

    # Strip common code-fence wrappers the helper sometimes emits.
    if raw.startswith("```"):
        raw = re.sub(r"^```(?:json)?\s*|\s*```$", "", raw, flags=re.IGNORECASE)
    try:
        data = json.loads(raw)
    except Exception:
        return None
    iso = data.get("iso") if isinstance(data, dict) else None
    if not iso or not isinstance(iso, str):
        return None
    try:
        return datetime.fromisoformat(iso)
    except Exception:
        return None


def _parse_natural_recurrence(text: str | None) -> dict | None:
    """Parse recurrence hints → RRULE-shaped dict, or `None` if unrecognized.

    Shape: `{freq: DAILY|WEEKLY|MONTHLY|YEARLY, interval: int, byday?: [..]}`.
    Covers common ES/EN patterns:
      - "todos los días" / "diariamente" / "every day"    → DAILY
      - "todos los lunes" / "cada martes" / "every monday" → WEEKLY + BYDAY
      - "cada N semanas" / "every N weeks"                 → WEEKLY interval=N
      - "mensualmente" / "todos los meses" / "monthly"     → MONTHLY
      - "anualmente" / "yearly" / "cada año"               → YEARLY

    Unrecognized → `None` (not an error — recurrence is optional).
    """
    if not text:
        return None
    s = text.strip().lower()
    if not s:
        return None

    # Weekly by specific weekday: "todos los lunes" / "cada martes" / "every monday"
    m = re.search(
        r"\b(?:todos?\s+los?|cada|every)\s+"
        r"(lunes|martes|mi[eé]rcoles|jueves|viernes|s[aá]bado|domingo|"
        r"monday|tuesday|wednesday|thursday|friday|saturday|sunday)\b",
        s,
    )
    if m:
        day = _RECUR_WEEKDAY_MAP.get(m.group(1))
        if day:
            return {"freq": "WEEKLY", "interval": 1, "byday": [day]}

    # "cada N semanas" / "every N weeks"
    m = re.search(r"\bcada\s+(\d+)\s+semanas?\b|\bevery\s+(\d+)\s+weeks?\b", s)
    if m:
        n = int(m.group(1) or m.group(2))
        return {"freq": "WEEKLY", "interval": max(1, n)}

    # "cada N días" / "every N days"
    m = re.search(r"\bcada\s+(\d+)\s+d[ií]as?\b|\bevery\s+(\d+)\s+days?\b", s)
    if m:
        n = int(m.group(1) or m.group(2))
        return {"freq": "DAILY", "interval": max(1, n)}

    # "cada N meses" / "every N months"
    m = re.search(r"\bcada\s+(\d+)\s+meses?\b|\bevery\s+(\d+)\s+months?\b", s)
    if m:
        n = int(m.group(1) or m.group(2))
        return {"freq": "MONTHLY", "interval": max(1, n)}

    # Simple adverbs. Check after byday/interval so "todos los lunes" wins.
    if re.search(r"\b(todos?\s+los?\s+d[ií]as|diariamente|daily|every\s+day)\b", s):
        return {"freq": "DAILY", "interval": 1}
    if re.search(r"\b(todas?\s+las?\s+semanas|semanalmente|weekly|every\s+week)\b", s):
        return {"freq": "WEEKLY", "interval": 1}
    if re.search(
        r"\b(todos?\s+los?\s+meses|mensualmente|monthly|every\s+month|"
        r"cada\s+mes)\b", s,
    ):
        return {"freq": "MONTHLY", "interval": 1}
    if re.search(
        r"\b(anualmente|yearly|every\s+year|cada\s+a[nñ]o|todos?\s+los?\s+a[nñ]os)\b", s,
    ):
        return {"freq": "YEARLY", "interval": 1}

    return None


def _build_rrule_string(recurrence: dict | None) -> str:
    """Compose an iCalendar RRULE string from a recurrence dict.

    Shape: `{freq, interval, byday?}` → `"FREQ=X;INTERVAL=N[;BYDAY=MO,TU]"`.
    Returns empty string if input is falsy or missing `freq`.
    """
    if not isinstance(recurrence, dict):
        return ""
    freq = (recurrence.get("freq") or "").upper()
    if freq not in ("DAILY", "WEEKLY", "MONTHLY", "YEARLY"):
        return ""
    interval = int(recurrence.get("interval") or 1)
    parts = [f"FREQ={freq}", f"INTERVAL={max(1, interval)}"]
    byday = recurrence.get("byday") or []
    if isinstance(byday, (list, tuple)) and byday:
        valid_days = {"MO", "TU", "WE", "TH", "FR", "SA", "SU"}
        clean = [d for d in byday if d in valid_days]
        if clean:
            parts.append("BYDAY=" + ",".join(clean))
    return ";".join(parts)


def _create_reminder(
    name: str,
    due_token: str | None = None,
    list_name: str | None = None,
    *,
    due_dt: datetime | None = None,
    priority: int | None = None,
    notes: str | None = None,
    recurrence: dict | None = None,
) -> tuple[bool, str]:
    """Create a new Apple Reminder. Returns `(ok, id_or_error)`.

    Fields:
      - `name`: title (required, non-empty after strip).
      - `due_dt`: specific datetime (wins over `due_token`). Day is set to 1
        first inside AppleScript to avoid month-overflow when the current
        day-of-month doesn't exist in the target month.
      - `due_token="tomorrow"`: legacy path for the home UI's brief — due
        tomorrow 09:00 local. Ignored if `due_dt` is given.
      - `list_name`: destination Reminders list. Omitted → default (first).
      - `priority`: Apple priority number `1|5|9` (high|medium|low). None
        leaves priority unset. No validation beyond int cast.
      - `notes`: free-form body text. Double quotes escaped.
      - `recurrence`: `{freq, interval, byday?}` → RRULE. Best-effort:
        Reminders.app AppleScript dictionary's `recurrence rule` is
        inconsistent across macOS versions, so we wrap the property
        assignment in its own `try/on error` block — the reminder itself
        still gets created without recurrence if the property is rejected.
        The caller's UX should advise manual verification in Reminders.app.

    Unknown list name → osascript error surfaced verbatim.
    """
    nm = (name or "").strip()
    if not nm:
        return False, "nombre vacío"
    if not _apple_enabled():
        return False, "Apple integration deshabilitada"
    # Audit 2026-04-26 (HIGH): backslash-then-quote en orden correcto.
    # Pre-fix solo escapaba `"` → un title con `\` (ej. `"cosa \n importante"`)
    # quedaba `"cosa \\n importante"` que AppleScript interpretaba como
    # newline literal y rompía el script, o peor inyectaba un newline
    # estructural que cambiaba la AS evaluación. Mismo orden ya usado en
    # `notes` (línea 35220).
    safe_name = nm.replace("\\", "\\\\").replace('"', '\\"')
    list_selector = ""
    if list_name:
        safe_list = list_name.replace("\\", "\\\\").replace('"', '\\"')
        list_selector = f' of list "{safe_list}"'

    # Build properties block. `name` always goes in the with-properties.
    # `body` too if notes present, since it's cleaner than a follow-up set.
    props = [f'name:"{safe_name}"']
    if notes:
        safe_notes = notes.replace("\\", "\\\\").replace('"', '\\"').replace("\n", "\\n")
        props.append(f'body:"{safe_notes}"')
    props_str = ", ".join(props)

    # Due date block.
    due_block = ""
    if due_dt is not None:
        due_block = (
            '    set _d to (current date)\n'
            '    set day of _d to 1\n'
            f'    set year of _d to {due_dt.year}\n'
            f'    set month of _d to {due_dt.month}\n'
            f'    set day of _d to {due_dt.day}\n'
            f'    set hours of _d to {due_dt.hour}\n'
            f'    set minutes of _d to {due_dt.minute}\n'
            '    set seconds of _d to 0\n'
            '    set due date of _r to _d\n'
        )
    elif due_token == "tomorrow":
        due_block = (
            '    set _d to (current date) + (1 * days)\n'
            '    set hours of _d to 9\n'
            '    set minutes of _d to 0\n'
            '    set seconds of _d to 0\n'
            '    set due date of _r to _d\n'
        )

    # Priority: 1=high, 5=medium, 9=low. Omit entirely when None.
    priority_block = ""
    if priority is not None:
        pv = int(priority)
        priority_block = f'    set priority of _r to {pv}\n'

    # Recurrence: best-effort inner try so the reminder still lands if
    # AppleScript rejects the property on this macOS version.
    rrule = _build_rrule_string(recurrence)
    recurrence_block = ""
    if rrule:
        recurrence_block = (
            '    try\n'
            f'      set recurrence of _r to "{rrule}"\n'
            '    on error\n'
            '    end try\n'
        )

    script = (
        'tell application "Reminders"\n'
        '  try\n'
        f'    set _r to make new reminder{list_selector} with properties {{{props_str}}}\n'
        f'{due_block}'
        f'{priority_block}'
        f'{recurrence_block}'
        '    return id of _r\n'
        '  on error errMsg\n'
        '    return "err: " & errMsg\n'
        '  end try\n'
        'end tell\n'
    )
    out = _osascript(script, timeout=15.0)
    if out.startswith("err:"):
        return False, out[4:].strip() or "error creando reminder"
    if out:
        return True, out
    return False, "osascript devolvió vacío"


def _complete_reminder(reminder_id: str) -> tuple[bool, str]:
    """Mark an Apple Reminder as completed by its stable `id` (the
    `x-apple-reminder://UUID` form returned by `id of reminder`).

    Returns `(ok, message)`. Used by the web UI's check-off control.
    Silent-fail semantics for osascript errors so the endpoint can
    surface a clean message without tracing.
    """
    rid = (reminder_id or "").strip()
    if not rid:
        return False, "reminder id vacío"
    if not _apple_enabled():
        return False, "Apple integration deshabilitada"
    # Use `first reminder whose id = …`; wrap id in double-quotes (AppleScript
    # string literal) and escape any pre-existing quotes defensively. Apple
    # reminder ids are stable URIs without quotes, but better safe.
    safe = rid.replace('"', '\\"')
    script = (
        'tell application "Reminders"\n'
        '  try\n'
        f'    set _r to first reminder whose id is "{safe}"\n'
        '    set completed of _r to true\n'
        '    return "ok"\n'
        '  on error errMsg\n'
        '    return "err: " & errMsg\n'
        '  end try\n'
        'end tell\n'
    )
    out = _osascript(script, timeout=15.0)
    if out == "ok":
        return True, "completada"
    if out.startswith("err:"):
        return False, out[4:].strip() or "reminder no encontrado"
    return False, "osascript devolvió vacío"


def _applescript_date_lines(var: str, dt: datetime, indent: str = "    ") -> str:
    """Emit AppleScript to construct `var` as a date at `dt` (locale-safe).

    Pattern: `set _x to (current date)`, then numeric property assignments.
    Day is set to 1 first to avoid month-overflow glitches when the current
    day-of-month doesn't exist in the target month (e.g. today=Jan 31 and
    target month=Feb). All assignments are numeric, so no month-name
    localization hazards.
    """
    return (
        f'{indent}set {var} to (current date)\n'
        f'{indent}set day of {var} to 1\n'
        f'{indent}set year of {var} to {dt.year}\n'
        f'{indent}set month of {var} to {dt.month}\n'
        f'{indent}set day of {var} to {dt.day}\n'
        f'{indent}set hours of {var} to {dt.hour}\n'
        f'{indent}set minutes of {var} to {dt.minute}\n'
        f'{indent}set seconds of {var} to 0\n'
    )


def _create_calendar_event(
    title: str,
    start: datetime,
    end: datetime | None = None,
    *,
    calendar: str | None = None,
    location: str | None = None,
    notes: str | None = None,
    all_day: bool = False,
    recurrence: dict | None = None,
) -> tuple[bool, str]:
    """Create a Calendar.app event. Returns `(ok, uid_or_error)`.

    Fields:
      - `title`: summary (required, non-empty after strip).
      - `start`: datetime (required). End defaults to `start + 1h`.
      - `end`: explicit end datetime. Must be ≥ start.
      - `calendar`: target calendar name. None → first writable calendar.
        Calendar.app aggregates iCloud CalDAV calendars, so writes to
        iCloud destinations go through even though JXA EventKit can't
        read them back (this is why we `_fetch_calendar_*` via icalBuddy
        but create via AppleScript-to-Calendar.app — different surfaces).
      - `location`, `notes`: optional strings. Quotes escaped.
      - `all_day=True`: sets the `allday event` property; `start`'s date
        wins, times are ignored.
      - `recurrence`: `{freq, interval, byday?}` → RRULE string. Unlike
        Reminders, Calendar.app's `recurrence` property is stable across
        recent macOS — we don't wrap it in a nested try/on error.

    Returns the event's UID (stable identifier) on success so the caller
    can surface a deep-link / deletion path in the UX.
    """
    nm = (title or "").strip()
    if not nm:
        return False, "título vacío"
    if not _apple_enabled():
        return False, "Apple integration deshabilitada"

    if end is None:
        end = start + timedelta(hours=1)
    if end < start:
        return False, "end date antes de start date"

    # ── Fast path: EventKit (audit 2026-04-25 R2-Calendar #2) ──────────
    # AppleScript create no es tan lento como el delete (que escaneaba
    # por uid 55-58s en calendarios grandes). Pero el timeout defensivo
    # de 20s sigue siendo demasiado para casos donde Calendar.app está
    # lento o la cuenta tiene CalDAV remotos (iCloud sync pendiente).
    # EventKit nativo crea el evento en ~50-100ms con commit local.
    #
    # Skip EventKit para recurrencias — EKRecurrenceRule es complejo de
    # mappear desde nuestro dict {freq, interval, byday}. AppleScript
    # toma un RRULE string así nomás. Las recurrencias caen al fallback.
    if recurrence is None:
        try:
            import objc  # noqa: PLC0415
            from Foundation import NSBundle, NSDate, NSURL  # noqa: PLC0415

            ek_bundle = NSBundle.bundleWithPath_(
                "/System/Library/Frameworks/EventKit.framework"
            )
            if ek_bundle is not None and ek_bundle.load():
                EKEventStore = objc.lookUpClass("EKEventStore")
                EKEvent = objc.lookUpClass("EKEvent")
                store = EKEventStore.alloc().init()
                ev = EKEvent.eventWithEventStore_(store)
                ev.setTitle_(nm)
                # NSDate desde epoch — cubrimos tz porque datetime ya
                # viene tz-aware del caller (parseado con _AR_OFFSET).
                ev.setStartDate_(
                    NSDate.dateWithTimeIntervalSince1970_(start.timestamp())
                )
                ev.setEndDate_(
                    NSDate.dateWithTimeIntervalSince1970_(end.timestamp())
                )
                if all_day:
                    ev.setAllDay_(True)
                if location:
                    ev.setLocation_(location)
                if notes:
                    ev.setNotes_(notes)
                # Calendar destino: el primero con allowsContentModifications
                # cuando el caller no pidió uno específico. Si pidió uno,
                # buscalo por título — match exacto, case-sensitive.
                target_cal = None
                if calendar:
                    cals = store.calendarsForEntityType_(0)  # 0=event
                    for c in cals:
                        if str(c.title()) == calendar:
                            target_cal = c
                            break
                else:
                    target_cal = store.defaultCalendarForNewEvents()
                if target_cal is None:
                    # No matchea — caemos al AppleScript path para tener
                    # el mismo selector "first writable" que tenía antes.
                    raise RuntimeError("calendar no encontrado en EventKit")
                ev.setCalendar_(target_cal)

                # Save: span=0 (ThisEventOnly, no aplica a recurrencias
                # porque skipeamos esa rama). commit=True para flush
                # inmediato al store. err=None devuelve tuple en pyobjc.
                ok = store.saveEvent_span_commit_error_(ev, 0, True, None)
                if isinstance(ok, tuple):
                    ok_flag = bool(ok[0])
                    err = ok[1] if len(ok) > 1 else None
                else:
                    ok_flag = bool(ok)
                    err = None
                if ok_flag:
                    # eventIdentifier es el UUID que devuelve AppleScript
                    # `uid of _ev` — verificado en `_delete_calendar_event`
                    # que ese identifier funciona contra `eventWithIdentifier_`.
                    return True, str(ev.eventIdentifier())
                if err is not None and hasattr(err, "localizedDescription"):
                    # No tan crítico — caemos al fallback AppleScript.
                    pass
        except Exception:
            # Cualquier error en EventKit → fallback silencioso.
            pass

    # ── Fallback: AppleScript (timeout reducido 20s→8s) ──────────────
    # Audit 2026-04-25: 20s era margen excesivo. Si AppleScript no
    # respondió en 8s, hay un problema real (Calendar.app frozen,
    # autocompletion lock, etc.) y prefiero fallar rápido para que el
    # caller decida (retry / show error / queue).
    safe_title = nm.replace("\\", "\\\\").replace('"', '\\"')

    # Calendar selector: named or first-writable fallback.
    if calendar:
        safe_cal = calendar.replace("\\", "\\\\").replace('"', '\\"')
        cal_sel = f'set _cal to first calendar whose name is "{safe_cal}"\n'
    else:
        cal_sel = "set _cal to first calendar whose writable is true\n"

    start_lines = _applescript_date_lines("_s", start)
    end_lines = _applescript_date_lines("_e", end)

    # Properties block.
    props = [
        'summary:"' + safe_title + '"',
        "start date:_s",
        "end date:_e",
    ]
    if all_day:
        props.append("allday event:true")
    if location:
        safe_loc = location.replace("\\", "\\\\").replace('"', '\\"')
        props.append(f'location:"{safe_loc}"')
    if notes:
        safe_desc = notes.replace("\\", "\\\\").replace('"', '\\"').replace("\n", "\\n")
        props.append(f'description:"{safe_desc}"')
    props_str = ", ".join(props)

    recurrence_block = ""
    rrule = _build_rrule_string(recurrence)
    if rrule:
        recurrence_block = f'    set recurrence of _ev to "{rrule}"\n'

    script = (
        'tell application "Calendar"\n'
        '  try\n'
        f'  {cal_sel}'
        f'{start_lines}'
        f'{end_lines}'
        f'    set _ev to make new event at end of events of _cal with properties {{{props_str}}}\n'
        f'{recurrence_block}'
        '    return uid of _ev\n'
        '  on error errMsg\n'
        '    return "err: " & errMsg\n'
        '  end try\n'
        'end tell\n'
    )
    out = _osascript(script, timeout=8.0)
    if out.startswith("err:"):
        return False, out[4:].strip() or "error creando evento"
    if out:
        return True, out
    return False, "osascript devolvió vacío"


def _delete_reminder(reminder_id: str) -> tuple[bool, str]:
    """Permanently delete an Apple Reminder by its stable `id`
    (`x-apple-reminderkit://REMCDReminder/UUID`). Returns `(ok, message)`.

    Used by the chat auto-create + undo flow: after a reminder lands via
    `_create_reminder`, the UI shows a 10s toast with a Deshacer button;
    click dispatches `DELETE /api/reminders/{id}` which calls this.

    Implementation note (2026-04-25 R2-Calendar #3): aplicamos el mismo
    patrón EventKit del `_delete_calendar_event` — Reminders.app via
    AppleScript también escanea linealmente sobre `id`, lento en
    cuentas grandes. EventKit/EKReminder con `calendarItemWithIdentifier_`
    es lookup indexado, ~50ms en lugar de varios segundos.

    EventKit framework cubre tanto Calendar como Reminders (mismo bundle,
    mismo EKEventStore). Si carga, su respuesta es autoritativa.
    Fallback a AppleScript con timeout reducido (15s→5s) para casos
    donde el framework no carga.
    """
    rid = (reminder_id or "").strip()
    if not rid:
        return False, "reminder id vacío"
    if not _apple_enabled():
        return False, "Apple integration deshabilitada"

    # ── Fast path: EventKit ──────────────────────────────────────────
    # Solo retornamos desde acá en caso de éxito O de "reminder no
    # encontrado" (autoritativo). Cualquier otro error cae al fallback
    # AppleScript silenciosamente.
    try:
        import objc  # noqa: PLC0415
        from Foundation import NSBundle  # noqa: PLC0415

        ek_bundle = NSBundle.bundleWithPath_(
            "/System/Library/Frameworks/EventKit.framework"
        )
        if ek_bundle is not None and ek_bundle.load():
            EKEventStore = objc.lookUpClass("EKEventStore")
            store = EKEventStore.alloc().init()
            # Reminders heredan de EKCalendarItem — el lookup correcto
            # es calendarItemWithIdentifier_, NO eventWithIdentifier_
            # (ese es solo para EKEvent del Calendar app).
            item = store.calendarItemWithIdentifier_(rid)
            if item is None:
                return False, "reminder no encontrado"
            # removeReminder_commit_error_ es el método específico para
            # EKReminder (no removeEvent). Soporta el mismo pyobjc tuple
            # return pattern.
            ok = store.removeReminder_commit_error_(item, True, None)
            if isinstance(ok, tuple):
                ok_flag = bool(ok[0])
                err = ok[1] if len(ok) > 1 else None
            else:
                ok_flag = bool(ok)
                err = None
            if ok_flag:
                return True, "borrada"
            if err is not None and hasattr(err, "localizedDescription"):
                return False, f"EventKit: {err.localizedDescription()}"
            # Falló el remove sin error útil — caer al fallback.
    except Exception:
        # Cualquier error en el path EventKit (framework no carga,
        # pyobjc roto, lookup falla, etc) → fallback silencioso.
        pass

    # ── Fallback: AppleScript (timeout reducido 15s→5s) ──────────────
    safe = rid.replace('"', '\\"')
    script = (
        'tell application "Reminders"\n'
        '  try\n'
        f'    set _r to first reminder whose id is "{safe}"\n'
        '    delete _r\n'
        '    return "ok"\n'
        '  on error errMsg\n'
        '    return "err: " & errMsg\n'
        '  end try\n'
        'end tell\n'
    )
    out = _osascript(script, timeout=5.0)
    if out == "ok":
        return True, "borrada"
    if out.startswith("err:"):
        return False, out[4:].strip() or "reminder no encontrado"
    return False, "osascript devolvió vacío"


def _delete_calendar_event(event_uid: str) -> tuple[bool, str]:
    """Permanently delete a Calendar.app event by its stable `uid`
    (returned by `_create_calendar_event`). Returns `(ok, message)`.

    Same contract as `_delete_reminder` — feeds the undo button on the
    chat's auto-create toast for events.

    Implementation note (revised 2026-04-25): el approach previo via
    AppleScript era inviable. Calendar.app expone una API que NO usa
    los índices internos: `every event of _cal whose uid is X` hace
    scan linear sobre los eventos del calendar. Medido empíricamente
    en una cuenta con 1363 eventos: 55-58s. Cualquier filter (`whose
    uid is`, `whose start date`, `whose summary is`) toma lo mismo,
    y JXA tampoco mejora. El timeout default rompía el botón
    [↩ deshacer] del chip auto-creado.

    El fix real es **EventKit nativo** via objc.lookUpClass —
    `EKEventStore.eventWithIdentifier_(uid)` es lookup INDEXADO (NSDictionary
    interno keyed por identifier). Bench: 160ms vs 58s = 360× más rápido.

    EventKit framework se carga dinámicamente con NSBundle (ya viene
    en macOS, no requiere instalar pyobjc-framework-eventkit; basta
    pyobjc-core que ya está como dep transitivo de ocrmac). Si el
    framework no carga (macOS futuro lo deprecó? sandbox raro?), cae
    al path AppleScript lento como fallback.

    El `uid` que retorna AppleScript `_create_calendar_event` matchea
    1:1 con `eventIdentifier` de EventKit — verificado empíricamente
    2026-04-25: el UUID que devuelve `uid of _ev` se puede pasar
    directo a `eventWithIdentifier_()` sin transformación.
    """
    uid = (event_uid or "").strip()
    if not uid:
        return False, "event uid vacío"
    if not _apple_enabled():
        return False, "Apple integration deshabilitada"

    # ── Path rápido: EventKit (~160ms con calendar de 1363 eventos) ──
    # Si el framework carga + el lookup retorna None, devolvemos
    # "evento no encontrado" autoritativo (no scan AppleScript inútil).
    # Cualquier otro error en el path → fallback silencioso al AppleScript.
    try:
        import objc  # noqa: PLC0415
        from Foundation import NSBundle  # noqa: PLC0415

        ek_bundle = NSBundle.bundleWithPath_(
            "/System/Library/Frameworks/EventKit.framework"
        )
        if ek_bundle is not None and ek_bundle.load():
            EKEventStore = objc.lookUpClass("EKEventStore")
            store = EKEventStore.alloc().init()
            ev = store.eventWithIdentifier_(uid)
            if ev is None:
                return False, "evento no encontrado"
            # EKSpan: 0=ThisEventOnly (no toca recurrencias futuras),
            # 1=FutureEvents. Para undo del chat queremos solo este.
            EK_SPAN_THIS_EVENT = 0
            # PyObjc devuelve True/False directo, o tuple (bool, err)
            # según versión. Normalizamos.
            ok = store.removeEvent_span_commit_error_(
                ev, EK_SPAN_THIS_EVENT, True, None
            )
            if isinstance(ok, tuple):
                ok_flag = bool(ok[0])
                err = ok[1] if len(ok) > 1 else None
            else:
                ok_flag = bool(ok)
                err = None
            if ok_flag:
                return True, "borrado"
            if err is not None and hasattr(err, "localizedDescription"):
                return False, f"EventKit: {err.localizedDescription()}"
            # Remove falló sin error útil — caer al fallback.
    except Exception:
        # Si el framework no cargó / pyobjc roto / etc → fallback.
        pass

    # ── Fallback: AppleScript scan linear (lento pero compat) ──────
    safe = uid.replace('"', '\\"')
    script = (
        'tell application "Calendar"\n'
        '  try\n'
        '    repeat with _cal in (every calendar whose writable is true)\n'
        '      try\n'
        '        repeat with _ev in (every event of _cal)\n'
        f'          if uid of _ev is "{safe}" then\n'
        '            delete _ev\n'
        '            return "ok"\n'
        '          end if\n'
        '        end repeat\n'
        '      on error\n'
        '        -- calendar problemático, seguir.\n'
        '      end try\n'
        '    end repeat\n'
        '    return "err: evento no encontrado"\n'
        '  on error errMsg\n'
        '    return "err: " & errMsg\n'
        '  end try\n'
        'end tell\n'
    )
    out = _osascript(script, timeout=60.0)
    if out == "ok":
        return True, "borrado"
    if out.startswith("err:"):
        return False, out[4:].strip() or "evento no encontrado"
    return False, "osascript devolvió vacío"


# ── Chat-tool wrappers (shared by web /api/chat + CLI rag chat) ──────────
#
# Moved here from web/tools.py so the CLI chat loop can register them
# directly with ollama's tool-calling API. web/tools.py re-exports them
# as `propose_reminder` / `propose_calendar_event`, unchanged for ollama
# schema-extraction purposes.
#
# Each tool:
#   1. Parses the when/start text via _parse_natural_datetime.
#   2. If parse fails (no datetime AND text was non-empty) → returns a
#      proposal payload with `needs_clarification: true`.
#   3. Otherwise CREATES the reminder/event via _create_reminder /
#      _create_calendar_event and returns `{created: true, <id>, fields}`.
#   4. Calendar events auto-flip to all_day when no time marker detected
#      in the start text (`_has_explicit_time`).

# Patrones temporales para detectar info que el LLM puede dropear de
# `when` cuando el user lo dijo en el query original. Bug del 2026-04-28:
# query "recordame regar las plantas el sábado a las 11am" → LLM
# pasaba when="a las 11am" (sin "el sábado") → reminder iba a mañana
# en vez del sábado próximo. El post-check abajo lo recupera.
_REMINDER_WEEKDAY_RE = re.compile(
    r"\b(?:lunes|martes|mi[eé]rcoles|jueves|viernes|s[aá]bado|domingo)\b",
    re.IGNORECASE,
)
_REMINDER_RELATIVE_DAY_RE = re.compile(
    r"\b(?:hoy|ma[ñn]ana|pasado\s+ma[ñn]ana)\b",
    re.IGNORECASE,
)


def _validate_reminder_when(
    when_from_llm: str | None,
    original_query: str | None,
) -> tuple[str, list[str]]:
    """Post-check: si el LLM droppeó info temporal del `when` que el
    query original tenía, la recuperamos.

    Casos detectados:
      1. Query tiene día concreto (lunes/.../domingo) pero `when` no →
         agrega el día al `when`.
      2. Query tiene día relativo (hoy/mañana/pasado mañana) pero
         `when` no → agrega.
      (NO chequeamos hora porque el LLM rara vez dropea hora — el bug
      observado siempre fue dropear día.)

    Es defensivo: solo agrega tokens encontrados textualmente en el
    query original. NO inventa nada. Si el query no menciona ningún
    día/hora, retorna `when_from_llm` sin tocar.

    Args:
        when_from_llm: el valor de `when` que pasó el LLM (puede ser
            vacío, None, o frase parcial).
        original_query: el mensaje crudo del user (para extraer info
            que el LLM perdió).

    Returns:
        `(when_fixed, issues)` — when_fixed es el `when` corregido,
        issues es lista de strings descriptivos de qué se recuperó
        (vacía si no hubo problemas).
    """
    when_fixed = (when_from_llm or "").strip()
    issues: list[str] = []
    query = (original_query or "").strip()
    if not query:
        return when_fixed, issues

    # 1) Weekday concreto
    has_weekday_in_query = bool(_REMINDER_WEEKDAY_RE.search(query))
    has_weekday_in_when = bool(_REMINDER_WEEKDAY_RE.search(when_fixed))
    if has_weekday_in_query and not has_weekday_in_when:
        m = _REMINDER_WEEKDAY_RE.search(query)
        if m:
            day = m.group(0).lower()
            issues.append(f"recovered weekday '{day}' from query")
            when_fixed = f"{day} {when_fixed}".strip() if when_fixed else day

    # 2) Día relativo (solo si no recuperamos un weekday — evita
    #    duplicados como "lunes mañana").
    if not has_weekday_in_query:
        has_rel_in_query = bool(_REMINDER_RELATIVE_DAY_RE.search(query))
        has_rel_in_when = bool(_REMINDER_RELATIVE_DAY_RE.search(when_fixed))
        if has_rel_in_query and not has_rel_in_when:
            m = _REMINDER_RELATIVE_DAY_RE.search(query)
            if m:
                rel = m.group(0).lower()
                issues.append(f"recovered relative day '{rel}' from query")
                when_fixed = f"{rel} {when_fixed}".strip() if when_fixed else rel

    return when_fixed, issues


def _validate_reminder_title(
    title_from_llm: str | None,
    original_query: str | None,
) -> tuple[str, list[str]]:
    """Post-check: si el title del LLM es prefijo demasiado corto del
    query original, intentar recuperar el objeto directo.

    Bug 2026-04-28: qwen2.5:7b a veces extrae solo el verbo del title
    ('regar' en vez de 'regar las plantas'). Heurística: si el title
    es 1 palabra Y el query tiene 'recordame TITLE OBJ DIRECTO'
    seguido de fecha/hora, recuperar 'TITLE OBJ DIRECTO'.

    CONSERVADOR: solo activa si el title es muy corto (<3 palabras) Y
    el query tiene una estructura clara post-verbo. Si dudoso, NO toca.

    Returns:
        (title_fixed, issues) — title_fixed puede ser igual al original.
    """
    title_fixed = (title_from_llm or "").strip()
    issues: list[str] = []
    query = (original_query or "").strip()
    if not query or not title_fixed:
        return title_fixed, issues

    # Solo activar si el title es 1 palabra
    if len(title_fixed.split()) > 1:
        return title_fixed, issues

    # Buscar en el query: "recordame VERBO ... DÍA/HORA"
    # Patron: "recordame TITLE [palabras hasta] (el/los) (lunes|...|domingo|hoy|mañana|a las|en N)"
    # Quantifier non-greedy ({1,5}?): si pongo greedy el regex come hasta
    # el último anchor posible y deja "regar las plantas el sábado"; con
    # non-greedy backtrack al primer anchor → "regar las plantas".
    verb = title_fixed.lower()
    pat = (
        r"\brecord[aá](?:me|te|rme)?\s+"
        rf"({re.escape(verb)}(?:\s+\w+){{1,5}}?)"
        r"\s+(?:el|este|próximo|próxima|los|los?\s+\w+|en\s+|a\s+las\s+|hoy|mañana|"
        r"lunes|martes|miércoles|miercoles|jueves|viernes|sábado|sabado|domingo|"
        r"\d|por\s+la\s+(?:mañana|tarde|noche))"
    )
    m = re.search(pat, query, re.IGNORECASE)
    if m:
        candidate = m.group(1).strip()
        # Sanity: el candidate debe contener el title como primera palabra
        if candidate.lower().split()[0] == verb:
            issues.append(f"title expanded from '{title_fixed}' to '{candidate}'")
            title_fixed = candidate

    return title_fixed, issues


def propose_reminder(
    title: str,
    when: str = "",
    list: str | None = None,
    priority: int | None = None,
    notes: str | None = None,
    recurrence_text: str | None = None,
    _original_query: str | None = None,
) -> str:
    """Agregar un recordatorio a Apple Reminders. Si la fecha/hora parsea
    clara, se CREA automáticamente. Si es ambigua, vuelve como propuesta
    para confirmación manual.

    Args:
        title: Texto del recordatorio.
        when: Fecha/hora en lenguaje natural ("mañana a las 10", "el jueves
            4pm", "en 2 horas"). Vacío = recordatorio sin fecha.
        list: Lista de Reminders destino. None = lista default del sistema.
        priority: 1 (alta), 5 (media), 9 (baja). None = sin prioridad.
        notes: Texto adicional para el body del recordatorio.
        recurrence_text: Recurrencia NL ("todos los lunes", "cada 2 semanas").

    Returns:
        JSON. Si creado: `{kind, created:true, reminder_id, fields}`.
        Ambiguo: `{kind, proposal_id, needs_clarification:true, fields}`.
        Error: `{kind, created:false, error, fields}`.
    """
    now = datetime.now()
    # POST-CHECK 2026-04-28: title truncation (BUG-5 del eval).
    # qwen2.5:7b a veces drop el objeto directo del title.
    if _original_query:
        _title_fixed, _title_issues = _validate_reminder_title(
            title, _original_query
        )
        if _title_issues:
            try:
                _ambient_log_event({
                    "cmd": "propose_reminder_title_fixed",
                    "original_title": title,
                    "fixed_title": _title_fixed,
                    "issues": _title_issues,
                })
            except Exception:
                pass
        title = _title_fixed
    # Post-check 2026-04-28: si el LLM droppeó info temporal del `when`
    # (típicamente día concreto como "el sábado"), la recuperamos del
    # query original. Documentación + ejemplos en _validate_reminder_when.
    if _original_query:
        _when_fixed, _issues = _validate_reminder_when(when, _original_query)
        if _issues:
            try:
                _ambient_log_event({
                    "cmd": "propose_reminder_when_fixed",
                    "original_when": when,
                    "fixed_when": _when_fixed,
                    "issues": _issues,
                })
            except Exception:
                pass
        when = _when_fixed
    due = _parse_natural_datetime(when, now=now) if when and when.strip() else None
    recurrence = _parse_natural_recurrence(recurrence_text) if recurrence_text else None
    needs_clarif = bool(when and when.strip()) and due is None

    fields = {
        "title": title,
        "due_iso": due.isoformat() if due else None,
        "due_text": when or "",
        "list": list,
        "priority": priority,
        "notes": notes,
        "recurrence": recurrence,
        "recurrence_text": recurrence_text,
    }

    if needs_clarif:
        return json.dumps({
            "kind": "reminder",
            "proposal_id": f"prop-{uuid.uuid4()}",
            "needs_clarification": True,
            "fields": fields,
        }, ensure_ascii=False)

    ok, reminder_id = _create_reminder(
        title, list_name=list,
        due_dt=due, priority=priority, notes=notes, recurrence=recurrence,
    )
    if not ok:
        return json.dumps({
            "kind": "reminder",
            "created": False,
            "error": reminder_id,
            "fields": fields,
        }, ensure_ascii=False)
    return json.dumps({
        "kind": "reminder",
        "created": True,
        "reminder_id": reminder_id,
        "fields": fields,
    }, ensure_ascii=False)


def _normalize_title_for_dedup(s: str) -> str:
    """Lowercase + strip accents + collapse whitespace + drop leading
    "cumpleaños de " / "cumple de " to compare event titles semantically.
    "Cumpleaños de Astor" and "cumple Astor" should dedup against each
    other; the raw string match would miss it.
    """
    s = unicodedata.normalize("NFD", (s or "")).encode("ascii", "ignore").decode("ascii")
    s = s.lower().strip()
    s = re.sub(r"^(?:cumplea?n?os?|cumple|aniversario)\s+(?:de\s+)?", "", s)
    s = re.sub(r"\s+", " ", s)
    return s.strip()


def _find_duplicate_calendar_event(
    title: str,
    start_dt: datetime,
    all_day: bool,
    *,
    now: datetime | None = None,
) -> dict | None:
    """Return the existing calendar event that matches `title` + `start_dt`
    closely enough to be considered a duplicate, or None if no dup.

    Match rules:
      - All-day: same calendar date, normalized-title overlap (substring
        either way after stripping accents + "cumpleaños de" prefixes).
      - Timed: start within ±30min of `start_dt`, same title match.

    Only runs when target is within 400 days of `now` to keep icalBuddy
    query bounded. Events further out (typically yearly cumples the user
    IS re-declaring) bypass the check — creating the second event is
    the right move there.

    Silent-fail: any icalBuddy error → None (let the create proceed).
    """
    anchor = now or datetime.now()
    delta_days = (start_dt.date() - anchor.date()).days
    if delta_days < 0 or delta_days > 400:
        return None
    horizon = max(1, delta_days + 2)
    try:
        events = _fetch_calendar_ahead(days_ahead=horizon, max_events=400)
    except Exception:
        return None
    if not events:
        return None

    target_title = _normalize_title_for_dedup(title)
    if not target_title:
        return None
    target_date_iso = start_dt.date().isoformat()

    for ev in events:
        ev_title = _normalize_title_for_dedup(ev.get("summary") or "")
        if not ev_title:
            continue
        # Title overlap: either direction contains the other (handles
        # "cumpleaños de Astor" vs "Astor cumple" both mapping to "astor").
        title_matches = (
            target_title == ev_title
            or target_title in ev_title
            or ev_title in target_title
        )
        if not title_matches:
            continue
        ev_start_raw = ev.get("start_iso") or ev.get("start") or ""
        try:
            ev_start = datetime.fromisoformat(ev_start_raw.replace("Z", "+00:00"))
            if ev_start.tzinfo is not None:
                ev_start = ev_start.replace(tzinfo=None)
        except ValueError:
            continue
        if all_day:
            if ev_start.date().isoformat() == target_date_iso:
                return {
                    "summary": ev.get("summary"),
                    "start_iso": ev_start.isoformat(),
                    "calendar": ev.get("calendar"),
                }
        else:
            # Timed: accept ±30 min window.
            if abs((ev_start - start_dt).total_seconds()) <= 30 * 60:
                return {
                    "summary": ev.get("summary"),
                    "start_iso": ev_start.isoformat(),
                    "calendar": ev.get("calendar"),
                }
    return None


def _validate_calendar_recurrence(
    recurrence_text_from_llm: str | None,
    original_query: str | None,
) -> tuple[str | None, list[str]]:
    """Post-check: si el query original menciona cumple/cumpleaños/aniversario
    pero el LLM no pasó recurrence_text='yearly', lo forzamos.

    Bug 2026-04-28 (T6/T9 del eval autónomo): qwen2.5:7b ignora la guía
    soft del system prompt para cumpleaños y deja recurrence_text=null.
    Resultado: evento de un solo año (inútil para cumples). El helper
    detecta el patrón en el query original y fuerza yearly.

    Defensivo: solo activa si query menciona el patrón Y recurrence_text
    está vacío. NO sobreescribe valores explícitos del LLM.

    Returns:
        (recurrence_fixed, issues) — recurrence_fixed es 'yearly' si se
        detectó cumple sin recurrence, issues describen el cambio.
    """
    recurrence_fixed = (recurrence_text_from_llm or "").strip()
    issues: list[str] = []
    query = (original_query or "").strip()
    if not query:
        return recurrence_fixed or None, issues

    has_birthday = bool(
        re.search(r"\b(cumple|cumpleañ?os?|anivers[aá]rios?)\b",
                  query, re.IGNORECASE)
    )
    if has_birthday and not recurrence_fixed:
        issues.append("birthday/anniversary detected, forced recurrence=yearly")
        recurrence_fixed = "yearly"
    return (recurrence_fixed or None), issues


def propose_calendar_event(
    title: str,
    start: str,
    end: str | None = None,
    calendar: str | None = None,
    location: str | None = None,
    notes: str | None = None,
    all_day: bool = False,
    recurrence_text: str | None = None,
    _original_query: str | None = None,
) -> str:
    """Agregar un evento a Calendar.app. Si la fecha parsea clara, se CREA
    automáticamente. Si es ambigua, vuelve como propuesta.

    Auto all-day: si el user no incluyó marcador de hora en `start` (ej.
    "el miercoles", "cumpleaños de X el viernes"), el tool flippea
    all_day=True automáticamente. Passar all_day=False explícito para
    overridear.

    Args:
        title: Summary del evento.
        start: Fecha/hora en NL. "jueves 4pm" → timed; "el jueves" → all-day.
        end: Fecha/hora de fin. None + all_day=True → start + 1 día.
            None + timed → start + 1h.
        calendar: Calendario destino. None = primer writable (iCloud).
        location: Ubicación (string libre).
        notes: Descripción / notas del evento.
        all_day: Evento de día completo. Auto-flip si no hay hora en start.
        recurrence_text: Recurrencia NL.

    Returns:
        JSON. Si creado: `{kind, created:true, event_uid, fields}`.
        Ambiguo: `{kind, proposal_id, needs_clarification:true, fields}`.
        Error: `{kind, created:false, error, fields}`.
    """
    now = datetime.now()
    # POST-CHECK 2026-04-28: si el query original tenía cumple/aniversario
    # y el LLM no pasó recurrence_text="yearly", forzarlo. Símil al
    # validator de propose_reminder.
    if _original_query:
        _rec_fixed, _rec_issues = _validate_calendar_recurrence(
            recurrence_text, _original_query
        )
        if _rec_issues:
            try:
                _ambient_log_event({
                    "cmd": "propose_calendar_recurrence_fixed",
                    "original": recurrence_text,
                    "fixed": _rec_fixed,
                    "issues": _rec_issues,
                })
            except Exception:
                pass
        recurrence_text = _rec_fixed
    start_dt = _parse_natural_datetime(start, now=now) if start and start.strip() else None
    end_dt: datetime | None = None
    if end and end.strip():
        end_dt = _parse_natural_datetime(end, now=start_dt or now)

    # Auto all-day detection (see propose_calendar_event docstring in
    # web/tools.py original for full rationale).
    if start_dt and not all_day and not _has_explicit_time(start):
        all_day = True

    if not end_dt:
        if all_day:
            _s_midnight = start_dt.replace(hour=0, minute=0, second=0, microsecond=0) if start_dt else None
            end_dt = _s_midnight + timedelta(days=1) if _s_midnight else None
            start_dt = _s_midnight
        elif start_dt:
            end_dt = start_dt + timedelta(hours=1)

    recurrence = _parse_natural_recurrence(recurrence_text) if recurrence_text else None
    needs_clarif = start_dt is None

    fields = {
        "title": title,
        "start_iso": start_dt.isoformat() if start_dt else None,
        "start_text": start or "",
        "end_iso": end_dt.isoformat() if end_dt else None,
        "end_text": end or "",
        "calendar": calendar,
        "location": location,
        "notes": notes,
        "all_day": bool(all_day),
        "recurrence": recurrence,
        "recurrence_text": recurrence_text,
    }

    if needs_clarif:
        return json.dumps({
            "kind": "event",
            "proposal_id": f"prop-{uuid.uuid4()}",
            "needs_clarification": True,
            "fields": fields,
        }, ensure_ascii=False)

    # Dedup against existing Calendar events. If the same-ish event is
    # already on the calendar in the same day (all_day) or overlapping
    # ±30min window (timed), skip creation and surface the existing one
    # so the UI can show "ya lo tenés" instead of silently doubling.
    # Cheap: one icalBuddy call, ~100-300ms. Only fires when the target
    # date is within 400 days (covers almost every real use case;
    # further dates typically mean yearly cumples where the user IS
    # re-declaring on purpose).
    if start_dt:
        try:
            _dup_hit = _find_duplicate_calendar_event(
                title, start_dt, bool(all_day), now=now,
            )
        except Exception:
            _dup_hit = None
        if _dup_hit:
            return json.dumps({
                "kind": "event",
                "created": False,
                "duplicate": True,
                "existing": _dup_hit,
                "fields": fields,
            }, ensure_ascii=False)

    ok, res = _create_calendar_event(
        title, start_dt, end_dt,
        calendar=calendar, location=location, notes=notes,
        all_day=bool(all_day), recurrence=recurrence,
    )
    if not ok:
        return json.dumps({
            "kind": "event",
            "created": False,
            "error": res,
            "fields": fields,
        }, ensure_ascii=False)
    return json.dumps({
        "kind": "event",
        "created": True,
        "event_uid": res,
        "fields": fields,
    }, ensure_ascii=False)


def propose_mail_send(
    to: str,
    subject: str,
    body: str,
    cc: str | None = None,
    bcc: str | None = None,
) -> str:
    """Draft a Gmail message for confirmation. DOES NOT send.

    Mirror intencional de ``propose_whatsapp_send``: acción destructiva a
    un tercero → siempre volvemos ``needs_clarification=True`` para que la
    UI muestre la tarjeta con [Enviar] / [Editar] / [Descartar]. Auto-send
    nunca es aceptable; el user confirma explícitamente con un click.

    El body se envía via ``_send_gmail`` (scope gmail.modify), disparado
    por ``POST /api/mail/send`` cuando el user toca [Enviar] en la UI.
    Acá solo armamos el draft + validamos que el destinatario parezca
    un email razonable.

    Args:
        to: Destinatario (email válido — se valida contiene ``@``).
        subject: Asunto. Vacío → "(sin asunto)".
        body: Cuerpo text/plain. Vacío permitido — el user puede
            editarlo en el textarea de la tarjeta antes de mandar.
        cc: Opcional. Comma-separated si hay varios destinatarios.
        bcc: Opcional. Comma-separated si hay varios.

    Returns:
        JSON ``{kind: "mail", proposal_id, needs_clarification: True,
        fields: {to, subject, body, cc?, bcc?, error?}}``. ``error`` se
        setea si el to no parsea como email (la tarjeta igual se renderiza
        para que el user edite el destinatario antes de enviar).
    """
    to_clean = (to or "").strip()
    subj_clean = (subject or "").strip() or "(sin asunto)"
    body_clean = body or ""
    error: str | None = None
    if not to_clean:
        error = "empty_to"
    elif "@" not in to_clean:
        error = "invalid_email"
    fields = {
        "to": to_clean,
        "subject": subj_clean,
        "body": body_clean,
        "cc": (cc or "").strip() or None,
        "bcc": (bcc or "").strip() or None,
        "error": error,
    }
    return json.dumps({
        "kind": "mail",
        "proposal_id": f"prop-{uuid.uuid4()}",
        "needs_clarification": True,
        "fields": fields,
    }, ensure_ascii=False)



# `_fetch_completed_reminders` moved to `rag.integrations.reminders` (Phase 1b,
# 2026-04-25). Re-exported at the bottom of this file.


MAIL_VIP_CONFIG_PATH = Path.home() / ".config/obsidian-rag/mail-vip.json"


def _strip_html_to_preview(s: str, cap: int = 200) -> str:
    """HTML→text preview: strip tags, collapse whitespace, cap length."""
    if not s:
        return ""
    s = re.sub(r"<[^>]+>", " ", s)
    s = re.sub(r"\s+", " ", s).strip()
    return s[:cap]


def _load_mail_vips() -> set[str]:
    """VIP sender substrings from ``MAIL_VIP_CONFIG_PATH``. Returns lowercased
    set. Missing file → empty. Malformed JSON or wrong shape → warning + empty.
    """
    p = MAIL_VIP_CONFIG_PATH
    if not p.is_file():
        return set()
    try:
        data = json.loads(p.read_text(encoding="utf-8"))
    except (OSError, ValueError) as exc:
        console.print(f"[yellow]mail-vip: config no parseable: {exc}[/yellow]")
        return set()
    vips = data.get("vips") if isinstance(data, dict) else None
    if not isinstance(vips, list):
        console.print(
            "[yellow]mail-vip: esperaba {\"vips\": [...]}, ignorado.[/yellow]"
        )
        return set()
    return {str(v).strip().lower() for v in vips if str(v).strip()}


def _is_vip_sender(sender: str, vips: set[str]) -> bool:
    if not sender or not vips:
        return False
    s = sender.lower()
    return any(v in s for v in vips)


# `_fetch_mail_unread` moved to `rag.integrations.apple_mail` (Phase 1b,
# 2026-04-25). Re-exported at the bottom of this file.


# Gmail integration block (`GMAIL_CREDS_DIR`, `GMAIL_SCOPES`, `_gmail_service`,
# `_gmail_send_service`, `_gmail_thread_last_meta`, `_fetch_gmail_evidence`)
# moved to `rag.integrations.gmail` (Phase 1b, 2026-04-25). Re-exported at the
# bottom of this file. `_send_gmail` stays here because it's a higher-level
# helper that composes the send service with mime + base64 — not a leaf
# integration.


def _send_gmail(to: str, subject: str, body: str,
                cc: str | None = None, bcc: str | None = None) -> dict:
    """Enviar un mail vía Gmail API. Reusa las creds del gmail-send MCP
    (`~/.gmail-mcp/credentials.json` — scope `gmail.modify` incluye send).

    Args:
        to: Destinatario — email válido.
        subject: Asunto.
        body: Cuerpo text/plain (no HTML por ahora — el 95% de casos).
        cc: Opcional, comma-separated si hay varios.
        bcc: Opcional, comma-separated si hay varios.

    Returns:
        Dict `{ok: bool, message_id?: str, error?: str}`. Silent-fail
        — cualquier excepción se convierte en `{ok: False, error: ...}`.
    """
    import email.mime.text
    import email.utils
    import base64

    to = (to or "").strip()
    subject = (subject or "").strip()
    body = body or ""
    if not to:
        return {"ok": False, "error": "to vacío"}
    if "@" not in to:
        return {"ok": False, "error": f"to no parece email válido: {to!r}"}
    if not subject:
        subject = "(sin asunto)"

    svc = _gmail_send_service()
    if svc is None:
        return {"ok": False, "error": "no hay creds gmail-send (chequear ~/.gmail-mcp/)"}

    try:
        msg = email.mime.text.MIMEText(body, "plain", "utf-8")
        msg["To"] = to
        msg["Subject"] = subject
        msg["Date"] = email.utils.formatdate(localtime=True)
        msg["Message-ID"] = email.utils.make_msgid()
        if cc:
            msg["Cc"] = cc.strip()
        if bcc:
            msg["Bcc"] = bcc.strip()
        raw = base64.urlsafe_b64encode(msg.as_bytes()).decode("ascii")
        sent = svc.users().messages().send(
            userId="me", body={"raw": raw},
        ).execute()
        return {
            "ok": True,
            "message_id": sent.get("id", ""),
            "thread_id": sent.get("threadId", ""),
        }
    except Exception as exc:
        _silent_log("send_gmail", exc)
        return {"ok": False, "error": f"{type(exc).__name__}: {str(exc)[:200]}"}


# Drive integration block (`GDRIVE_CREDS_DIR`, `GDRIVE_SCOPES`,
# `_GDRIVE_MIME_LABEL`, `_GDRIVE_SEARCH_STOPWORDS`, `_drive_service`,
# `_fetch_drive_evidence`, `_drive_search_tokens`) moved to
# `rag.integrations.drive` (Phase 1b, 2026-04-25). Re-exported at the bottom
# of this file. `_GDRIVE_EXPORT_MIME` stays here because it's only used by
# `_agent_tool_drive_search` (chat tool, not a leaf integration).
_GDRIVE_EXPORT_MIME: dict[str, str] = {
    "application/vnd.google-apps.document": "text/plain",
    "application/vnd.google-apps.spreadsheet": "text/csv",
    "application/vnd.google-apps.presentation": "text/plain",
}


# ── Person/contact alias resolution (cross-source) ──────────────────────────
# Motivación (2026-04-24, user report Fer F. iter 3): aunque el user dice
# "Alexis", en WhatsApp / Contacts aparece como "Alexis Herrera", y el
# archivo de Drive que contiene su info está nombrado "Alex - Cuotas
# Macbook" (diminutivo). Drive `name contains 'alexis'` no matchea "Alex"
# porque el tokenizer de fullText trata "alexis" y "alex" como tokens
# diferentes. Resultado: drive_search encontraba la planilla sólo porque
# "macbook" sí coincidía con el nombre. Para queries donde el único hint
# es el nombre de la persona (ej. "lo de Alexis", "planilla de Mama"),
# esto fallaba silenciosamente.
#
# Solución: resolver nombres a TODAS sus variantes conocidas antes de
# armar la query. Fuentes consultadas en orden:
#
#   1. **WhatsApp contacts** (SQLite local del bridge, ~10ms): es la fuente
#      más rica del user — probablemente tiene a todos sus contactos
#      directos con el nombre completo ("Alexis Herrera" vs "Alexis V.").
#   2. **Apple Contacts** (AppleScript, ~100-500ms): backup/complemento,
#      puede tener gente que no está en WA (trabajo, familia extendida).
#   3. **99-Mentions/** del vault: notas manuales de personas frequentes
#      con alias/canonical explícitos en frontmatter.
#
# Se cachea en un dict módulo-level — repetir el mismo nombre en un
# segundo turn / query es gratis. Silent-fail: cualquier fuente puede
# faltar sin romper el resto. Cache bounded a 256 entradas (LRU manual
# — la 257a entrada evicta la más vieja por orden de inserción).

_PERSON_ALIAS_CACHE: "OrderedDict[str, tuple[str, ...]]" = OrderedDict()
_PERSON_ALIAS_CACHE_MAX = 256

# Punctuation / emoji chars that WhatsApp contact names frequently use as
# decoration ("Maria 🍷", "Pepe (hermano)"). Strip them so we don't
# pollute Drive `name contains` clauses with literal garbage that would
# never match file names.
_ALIAS_STRIP_RE = re.compile(r"[^a-záéíóúñü\s'-]", flags=re.IGNORECASE)


def _clean_alias(raw: str) -> str:
    """Normalize a WhatsApp/Contacts chunk for use as a Drive name-match
    token: lowercase, strip decorative emoji/punctuation, collapse
    whitespace, trim. Returns empty string if nothing useful remains.

    Preserves: letters (incl. acentos + ñ/ü), spaces, apostrophes,
    hyphens. Strips: emojis, parens, brackets, digits, punctuation.
    """
    cleaned = _ALIAS_STRIP_RE.sub(" ", (raw or "").lower())
    # Collapse whitespace + trim. Hyphens/apostrophes in middle of words
    # are preserved (ej. "jean-luc", "o'brien").
    return re.sub(r"\s+", " ", cleaned).strip()


def _resolve_person_aliases(name: str) -> tuple[str, ...]:
    """Resolver un nombre a variantes conocidas (diminutivos, apellidos,
    alias) via WhatsApp + Apple Contacts + mentions index.

    Args:
        name: Token corto (típicamente un nombre de pila o apellido).
            Lowercase-normalizado; acentos no se tocan porque Drive
            `name contains` respeta unicode.

    Returns:
        Tupla de strings deduplicadas, ordenadas shortest-first (strings
        cortos tienen más poder de match como substring en Drive). Cap
        a 8 variantes para que la query Drive no se infle.

        El `name` original NO aparece en el output (lo agregamos aparte
        en el caller). Tokens <3 chars se filtran — demasiado genéricos
        para producir matches útiles en Drive.

    Performance: ~10ms si el caché del proceso está caliente; ~50-500ms
    fresh (SQLite + AppleScript). Para una query con 3 tokens name-like
    el costo está en el orden de 1-2s worst-case, aceptable para un
    tool que ya tarda ~1s contra Drive.
    """
    name_clean = (name or "").strip().lower()
    if len(name_clean) < 3:
        return ()

    cached = _PERSON_ALIAS_CACHE.get(name_clean)
    if cached is not None:
        # LRU: marcar como recién usado para no ser evictado enseguida.
        _PERSON_ALIAS_CACHE.move_to_end(name_clean)
        return cached

    candidates: set[str] = set()
    # Flag: did ANY source (WA / AC / mentions) recognize this as a
    # known person? Si no, tratamos el token como NO-nombre y saltamos
    # el diminutivo heurístico (evita agregar "macb" cuando el user
    # pregunta por "macbook"). Si alguna fuente pegó, aunque sea con
    # una sola variante, asumimos que es un nombre propio y entonces
    # sí tiene sentido generar el prefijo diminutivo.
    is_known_person = False

    # 1. WhatsApp contacts (SQLite). Substring-match insensible a caso.
    #    El bridge guarda `chats.name` como lo ve WhatsApp (full name
    #    registrado en el perfil del contacto). Tomamos name + tokens
    #    individuales ≥3 chars. Stripping de paréntesis, emojis,
    #    paréntesis-sueltos, y otros caracteres no-alfabéticos que
    #    contaminan el output (ej. "Maria (amiga)" splitea en tokens
    #    `[maria, (amiga)]` — el segundo es puro noise para Drive).
    if WHATSAPP_DB_PATH.is_file():
        try:
            import sqlite3
            con = sqlite3.connect(
                f"file:{WHATSAPP_DB_PATH}?mode=ro", uri=True, timeout=2.0,
            )
            try:
                rows = con.execute(
                    "SELECT DISTINCT name FROM chats "
                    "WHERE name IS NOT NULL AND LOWER(name) LIKE ? LIMIT 10",
                    (f"%{name_clean}%",),
                ).fetchall()
            finally:
                con.close()
            for (chat_name,) in rows or []:
                if not chat_name:
                    continue
                cn_clean = _clean_alias(chat_name.lower())
                if cn_clean:
                    candidates.add(cn_clean)
                    is_known_person = True
                for tok in cn_clean.split():
                    tok_stripped = _clean_alias(tok)
                    if tok_stripped and len(tok_stripped) >= 3:
                        candidates.add(tok_stripped)
        except sqlite3.Error:
            pass
        except Exception:
            pass

    # 2. Apple Contacts via osascript — usa el helper ya probado con
    #    timeout de 3s + cache interno. Retorna `{full_name, phones,
    #    emails, birthday}` o None.
    ac = _osascript_contact_search("name contains", name_clean)
    if ac and ac.get("full_name"):
        fn = _clean_alias(ac["full_name"])
        if fn:
            candidates.add(fn)
            is_known_person = True
            for tok in fn.split():
                if len(tok) >= 3:
                    candidates.add(tok)

    # 3. Mentions index del vault. Si el user ya creó `99-Mentions/Seba.md`
    #    con alias "Sebas" / "Sebastián", ambos terminan en el índice
    #    apuntando al mismo path — tomamos los tokens del índice que
    #    matchean el input (prefix/suffix share). Emails del índice
    #    (contienen "@") se descartan porque los nombres de archivo en
    #    Drive raramente incluyen email literal.
    try:
        idx = _load_mentions_index()
        for token, path in (idx or {}).items():
            if not isinstance(token, str) or len(token) < 3:
                continue
            if "@" in token:
                continue
            if name_clean in token or token in name_clean:
                tok_clean = _clean_alias(token)
                if tok_clean and len(tok_clean) >= 3:
                    candidates.add(tok_clean)
                    is_known_person = True
                stem = Path(path).stem.lower() if path else ""
                stem_clean = _clean_alias(stem)
                if stem_clean and len(stem_clean) >= 3:
                    candidates.add(stem_clean)
                    is_known_person = True
    except Exception:
        pass

    # 4. Diminutivos/prefijos para nombres propios ES — regla empírica:
    #    el diminutivo típico es el first-4-chars del nombre ("Alexis"
    #    → "Alex", "Federico" → "Fede", "Sebastián" → "Seba", "Mauricio"
    #    → "Mauri" truncado). SÓLO aplica cuando alguna fuente (WA / AC /
    #    mentions) reconoció el token como persona — evita agregar "macb"
    #    cuando el user pregunta por "macbook" o "adeu" cuando pregunta
    #    por "adeuda". Para cada candidato ≥5 chars de 1 sola palabra,
    #    agregamos su prefijo de 4 chars si matchea al name_clean como
    #    super/subcadena.
    if is_known_person:
        for c in list(candidates):
            if " " in c or len(c) < 5 or len(c) > 20:
                continue
            if not (name_clean in c or c in name_clean):
                continue
            prefix4 = c[:4]
            if len(prefix4) >= 3 and prefix4 != name_clean:
                candidates.add(prefix4)

        # También probamos el prefijo del `name_clean` original — cubre
        # el caso inverso: user dice "Alexis" (aparece en WA/AC) →
        # agregamos "alex" como variante diminutiva, aunque "alex" no
        # esté literalmente en ningún contacto como token separado.
        if len(name_clean) >= 5 and " " not in name_clean:
            candidates.add(name_clean[:4])

    # Remove the original name (the caller already has it in the query)
    # + strip over-long artifacts (max 30 chars — longer ones are likely
    # full paths or noise that wouldn't be file-name components anyway).
    candidates.discard(name_clean)
    result = tuple(sorted(
        (c for c in candidates if 3 <= len(c) <= 30),
        key=len,
    )[:8])

    # Bounded cache con LRU real via OrderedDict — evict el LRU
    # (least recently used) cuando está lleno. move_to_end en el getter
    # arriba mantiene el orden correcto.
    if len(_PERSON_ALIAS_CACHE) >= _PERSON_ALIAS_CACHE_MAX:
        try:
            _PERSON_ALIAS_CACHE.popitem(last=False)
        except KeyError:
            pass
    _PERSON_ALIAS_CACHE[name_clean] = result
    return result


def _agent_tool_whatsapp_search(
    query: str,
    contact: str | None = None,
    k: int = 8,
) -> str:
    """Buscar mensajes de WhatsApp en el corpus indexado por contenido.

    Esto es complementario a `whatsapp_pending` (que sólo lista chats
    sin respuesta): acá hacemos retrieval semántico + BM25 sobre los
    chunks WA (`source="whatsapp"`) para preguntas tipo "qué me dijo
    Juan sobre la deuda?" / "cuándo quedamos con Grecia para el
    doctor?". Devuelve mensajes matcheantes ordenados por score.

    Args:
        query: Texto a buscar en lenguaje natural.
        contact: Nombre del contacto a filtrar (resolved via Apple
            Contacts → JID candidates por last-10-digits suffix). Si no
            se resuelve, hacemos búsqueda sin filtro y agregamos un
            campo `warning` en el output para que el LLM se lo cuente
            al user.
        k: Cantidad máxima de mensajes a devolver (1–8, default 8).

    Returns:
        JSON string `{query, contact_filter, messages: [{jid, contact,
        ts, who, text, score}], warning?, error?}`. Silent-fail: si
        retrieve raisea, devuelve `{messages: [], error: "..."}`. Nunca
        propaga excepciones — el chat loop se rompe si lo hace.

    Notes:
        - `who` = "outbound" si el primer mensaje del chunk lo mandó
          el user (sender == "yo"), "inbound" en cualquier otro caso.
        - `text` es el body del chunk (rendering `Speaker: content` de
          la ventana de mensajes), capado a 400 chars.
        - `ts` es el timestamp del primer mensaje del chunk en formato
          ISO UTC (ej. "2026-04-20T15:23:10Z").
        - Cuando hay filtro de contacto, hacemos overfetch (k×3, cap
          30) para compensar chunks de otros contactos que vendrían
          ordenados por score antes del filtro JID.
    """
    k = max(1, min(8, int(k)))
    q = (query or "").strip()
    if not q:
        return json.dumps({
            "query": "",
            "contact_filter": None,
            "messages": [],
            "error": "query vacía",
        }, ensure_ascii=False)

    contact_filter: str | None = None
    jid_suffixes: set[str] = set()
    warning: str | None = None

    cn = (contact or "").strip()
    if cn:
        try:
            lookup = _whatsapp_jid_from_contact(cn)
        except Exception as exc:
            lookup = {
                "jid": None, "full_name": None, "phones": [],
                "error": f"lookup_failed: {str(exc)[:80]}",
            }
        if lookup.get("jid"):
            contact_filter = lookup.get("full_name") or cn
            # Build digit-suffix candidates: last 10 digits of every
            # phone we know about, plus the primary JID local-part.
            # Last-10 handles AR's optional `9` mobile prefix +
            # country-code variance — `+5491134567890` and
            # `1134567890` both end in the same 10 digits.
            for ph in (lookup.get("phones") or []):
                d = re.sub(r"\D+", "", ph or "")
                if len(d) >= 8:
                    jid_suffixes.add(d[-10:] if len(d) >= 10 else d)
            primary_local = lookup["jid"].split("@")[0]
            d = re.sub(r"\D+", "", primary_local)
            if len(d) >= 8:
                jid_suffixes.add(d[-10:] if len(d) >= 10 else d)
        else:
            err = lookup.get("error") or "not_found"
            warning = (
                f"contact_not_resolved: '{cn}' no se encontró en Apple "
                f"Contacts ({err}); búsqueda sin filtro de contacto."
            )

    try:
        col = get_db()
        # Overfetch when filtering — chunks de otros chats matchean por
        # contenido y aparecen mezclados; necesitamos margen para que
        # el filtro JID nos deje los k pedidos. Cap a 30 para no
        # explotar el reranker en queries con WA-only source.
        retrieve_k = min(k * 3, 30) if jid_suffixes else k
        result = retrieve(
            col, q, retrieve_k,
            folder=None, tag=None, precise=False,
            multi_query=False, auto_filter=True,
            source="whatsapp",
        )
    except Exception as exc:
        return json.dumps({
            "query": q,
            "contact_filter": contact_filter,
            "messages": [],
            "warning": warning,
            "error": f"retrieve_failed: {str(exc)[:120]}",
        }, ensure_ascii=False)

    docs = result.get("docs") or []
    metas = result.get("metas") or []
    scores = result.get("scores") or []

    messages: list[dict] = []
    for doc, meta, score in zip(docs, metas, scores):
        meta = meta or {}
        chat_jid = str(meta.get("chat_jid") or "")
        if jid_suffixes:
            jid_local = chat_jid.split("@")[0]
            jid_digits = re.sub(r"\D+", "", jid_local)
            if not jid_digits or not any(
                jid_digits.endswith(s) for s in jid_suffixes
            ):
                continue
        ts_raw = meta.get("first_ts") or meta.get("created_ts") or 0
        try:
            # `Z` suffix denota UTC explícito en el output del tool;
            # usamos `tz=timezone.utc` (en vez de `utcfromtimestamp`,
            # deprecated en 3.12) y stripeamos el `+00:00` que el
            # isoformat agrega para no duplicar el offset.
            ts_iso = (
                datetime.fromtimestamp(float(ts_raw), tz=timezone.utc)
                .isoformat(timespec="seconds")
                .replace("+00:00", "Z")
            )
        except (TypeError, ValueError, OSError, OverflowError):
            ts_iso = ""
        sender = str(meta.get("sender") or "").strip().lower()
        who = "outbound" if sender == "yo" else "inbound"
        text = str(doc or "").strip()[:400]
        contact_name = str(meta.get("chat_name") or "").strip()
        messages.append({
            "jid": chat_jid,
            "contact": contact_name,
            "ts": ts_iso,
            "who": who,
            "text": text,
            "score": round(float(score), 3),
        })
        if len(messages) >= k:
            break

    out: dict = {
        "query": q,
        "contact_filter": contact_filter,
        "messages": messages,
    }
    if warning:
        out["warning"] = warning
    return json.dumps(out, ensure_ascii=False)


def _agent_tool_whatsapp_thread(
    contact_name: str,
    max_messages: int = 15,
    days: int = 7,
) -> str:
    """Leer los últimos N mensajes literales de un chat 1:1 con un contacto.

    Distinto a `_agent_tool_whatsapp_search` (búsqueda semántica por
    contenido sobre el corpus indexado): acá vamos directo al SQLite
    del bridge (`messages.db`) y traemos las últimas N filas del chat
    de ese contacto, en orden cronológico (DESC por timestamp). El uso
    típico es que el LLM lo combine con `propose_calendar_event` —
    "fijate qué quedamos con Juan ayer y agendalo": el chat agente
    pide los mensajes, ve "el jueves 4pm" en el último inbound, y
    arma la propuesta de evento. NO hay regex de detección de
    reuniones — el LLM parsea el thread.

    Args:
        contact_name: Nombre tal como aparece en Apple Contacts.
        max_messages: Mensajes a devolver. Cap duro 1–30 para no
            inflar el CONTEXTO del LLM.
        days: Ventana en días hacia atrás. Cap duro 1–30 (mismo
            motivo: contexto).

    Returns:
        JSON string ``{contact_name, jid, messages: [{ts, who:
        "inbound"|"outbound", text}], count, days_back}``. En orden
        cronológico ascendente (más viejo → más nuevo) para que el
        LLM lea el thread como una conversación normal.

        Si el contacto no se resuelve → ``{"messages": [], "error":
        "contact_not_found", "contact_name": ...}``.
        Si el bridge DB no existe → ``{"messages": [], "error":
        "bridge_db_missing"}``.
        Otros fallos → ``{"messages": [], "error": "..."}``. Silent-
        fail: NUNCA propaga excepciones — el chat loop se rompe.

    Notes:
        - Sólo chats 1:1 (`@s.whatsapp.net`). Grupos (`@g.us`) NO
          soportados — la UX de "qué hablamos con X" en grupo es
          ambigua (X podría ser cualquiera del grupo).
        - JID matching por suffix de últimos 10 dígitos, igual que
          `_whatsapp_resolve_reply_target` — robusto a variaciones de
          country-code y al `9` mobile prefix de AR.
        - `text` capado a 400 chars/mensaje.
    """
    cn = (contact_name or "").strip()
    if not cn:
        return json.dumps({
            "messages": [],
            "error": "empty_contact",
            "contact_name": "",
        }, ensure_ascii=False)

    # Hard caps — el LLM verboso (o un user pidiendo "todo el chat")
    # podría meter max=999 / days=365 y fundirnos el num_ctx. 30/30 es
    # suficiente para ~todos los casos de "qué hablamos los últimos N
    # días" sin romper el budget.
    max_messages = max(1, min(30, int(max_messages)))
    days = max(1, min(30, int(days)))

    try:
        lookup = _whatsapp_jid_from_contact(cn)
    except Exception as exc:
        return json.dumps({
            "messages": [],
            "error": f"contact_lookup_failed: {str(exc)[:80]}",
            "contact_name": cn,
        }, ensure_ascii=False)

    if not lookup.get("jid"):
        err = lookup.get("error") or "not_found"
        return json.dumps({
            "messages": [],
            "error": "contact_not_found",
            "contact_name": cn,
            "lookup_error": err,
        }, ensure_ascii=False)

    primary_jid = lookup["jid"]
    full_name = lookup.get("full_name") or cn

    # Build last-10-digit suffix candidates — same logic as
    # `_whatsapp_resolve_reply_target` so cross-country contacts and
    # mobile-prefix variants ("+5491134567890" vs "1134567890") match.
    suffixes: set[str] = set()
    primary_local = primary_jid.split("@")[0]
    d = re.sub(r"\D+", "", primary_local)
    if len(d) >= 8:
        suffixes.add(d[-10:] if len(d) >= 10 else d)
    for ph in (lookup.get("phones") or []):
        d2 = re.sub(r"\D+", "", ph or "")
        if len(d2) >= 8:
            suffixes.add(d2[-10:] if len(d2) >= 10 else d2)

    if not suffixes:
        return json.dumps({
            "messages": [],
            "error": "contact_no_phone_digits",
            "contact_name": full_name,
        }, ensure_ascii=False)

    db = WHATSAPP_BRIDGE_DB_PATH
    if not db.exists():
        return json.dumps({
            "messages": [],
            "error": "bridge_db_missing",
            "contact_name": full_name,
        }, ensure_ascii=False)

    import sqlite3 as _sqlite3
    try:
        conn = _sqlite3.connect(f"file:{db}?mode=ro", uri=True, timeout=2.0)
    except _sqlite3.Error as exc:
        return json.dumps({
            "messages": [],
            "error": f"bridge_db_open_failed: {str(exc)[:80]}",
            "contact_name": full_name,
        }, ensure_ascii=False)

    # Pull a windowed superset and filter client-side. SQL `LIKE
    # '%XXXXXXXXXX@s.whatsapp.net'` would work for a single suffix,
    # but Apple Contacts can return multiple phones → multiple
    # suffixes; doing the suffix match in Python keeps the SQL stable
    # and bounded. 1500 rows is enough headroom for a chat that the
    # user might have spammed with stickers/media in the last 30 days.
    cutoff = datetime.now().timestamp() - days * 86400.0
    try:
        cur = conn.execute(
            "SELECT id, chat_jid, sender, content, timestamp, is_from_me "
            "FROM messages "
            "WHERE chat_jid LIKE '%@s.whatsapp.net' "
            "  AND content IS NOT NULL AND content != '' "
            "ORDER BY timestamp DESC "
            "LIMIT 1500"
        )
        rows = cur.fetchall()
    except _sqlite3.Error as exc:
        try:
            conn.close()
        except Exception:
            pass
        return json.dumps({
            "messages": [],
            "error": f"bridge_db_query_failed: {str(exc)[:80]}",
            "contact_name": full_name,
        }, ensure_ascii=False)
    finally:
        try:
            conn.close()
        except Exception:
            pass

    matched_jid: str | None = None
    collected: list[dict] = []
    for _mid, chat_jid, _sender, content, ts_raw, is_from_me in rows:
        local = (chat_jid or "").split("@")[0]
        ldigits = re.sub(r"\D+", "", local)
        if not ldigits:
            continue
        if not any(ldigits.endswith(s) for s in suffixes):
            continue
        ts = _parse_bridge_timestamp(ts_raw)
        if ts is None:
            continue
        if ts < cutoff:
            # Rows are DESC by ts — once we cross the cutoff, every
            # subsequent row is older. We can `break` to short-circuit
            # the scan.
            break
        if matched_jid is None:
            matched_jid = chat_jid
        collected.append({
            "ts": datetime.fromtimestamp(ts).isoformat(timespec="seconds"),
            "ts_epoch": ts,
            "who": "outbound" if bool(is_from_me) else "inbound",
            "text": str(content or "").strip()[:400],
        })
        if len(collected) >= max_messages:
            break

    # `collected` is DESC (newest first). Flip to ASC for chronological
    # readability — the LLM consumes the thread top-to-bottom like a
    # human reading the chat.
    collected.reverse()
    for m in collected:
        m.pop("ts_epoch", None)

    return json.dumps({
        "contact_name": full_name,
        "jid": matched_jid or primary_jid,
        "messages": collected,
        "count": len(collected),
        "days_back": days,
    }, ensure_ascii=False)


def _agent_tool_drive_search(query: str, max_files: int = 5, body_cap: int = 3500) -> str:
    """Buscar archivos en Google Drive por contenido y devolver body exportado.

    Args:
        query: Pregunta o keywords en lenguaje natural. Stopwords ES/EN se
            filtran automáticamente (ej. "busca en mi drive info de alexis
            y la macbook pro" → tokens ["info", "alexis", "macbook", "pro"]).
        max_files: Máximo de archivos a devolver con body (1–8, default 5).
        body_cap: Máx caracteres de body por archivo (default 3500).

    Returns:
        JSON string con `{query_used, tokens, files: [{name, path, mime,
        modified, link, body}]}`. Si falta auth o la API falla, devuelve
        `{"files": [], "error": "..."}`. Nunca raisea — el chat loop
        renderea esto en el CONTEXTO directamente.
    """
    max_files = max(1, min(8, int(max_files)))
    body_cap = max(500, min(8000, int(body_cap)))
    tokens = _drive_search_tokens(query or "")
    if not tokens:
        return json.dumps({
            "files": [], "tokens": [], "query_used": "",
            "error": "query vacía después de filtrar stopwords",
        }, ensure_ascii=False)

    svc = _drive_service()
    if svc is None:
        return json.dumps({
            "files": [], "tokens": tokens, "query_used": " ".join(tokens),
            "error": "no_google_credentials",
        }, ensure_ascii=False)

    # Drive's `fullText contains 'a b c'` matches files whose indexed text
    # has all of those tokens (space-separated acts as AND, not phrase).
    # Escape single quotes per the API spec: ' → \\'.
    #
    # 2026-04-24 regression (Fer F. report): "alexis macbook pro" no
    # devolvía el spreadsheet "Alex - Cuotas Macbook" porque el contenido
    # del file son sólo números + fechas (celdas del spreadsheet), SIN
    # las palabras "alexis" / "macbook" indexadas como fullText. Pero
    # el NOMBRE del archivo sí las tiene. Fix: OR entre `fullText
    # contains` (tokens AND) y `name contains` (cualquier token). Drive
    # limita a 1 `name contains` por clause — usamos un `or` chain
    # explícito por token. Esto surfacea spreadsheets / docs con nombres
    # descriptivos aunque su contenido sea numérico. Trade-off: puede
    # traer falsos positivos si un token común ("pro", "info") matchea
    # nombres genéricos — mitigado por el tokenizer que filtra stopwords
    # + cap de `max_files` + ordenar por `modifiedTime desc`.
    joined = " ".join(tokens).replace("\\", "\\\\").replace("'", "\\'")
    # name_or solo con tokens "específicos" (≥5 chars) — descarta palabras
    # cortas como "pro" / "info" / "app" / "foo" que producen demasiados
    # falsos positivos por matchear nombres de archivos genéricos. El
    # umbral 5 es empírico: "alexis" (6), "macbook" (7), "adeuda" (6),
    # "factura" (7) — todos quedan. "pro" (3), "mail" (4), "doc" (3) no.
    name_tokens = [t for t in tokens if len(t) >= 5]

    # Alias expansion (2026-04-24 iter 3): el user dice "alexis" pero el
    # archivo se llama "Alex - Cuotas Macbook". `name contains 'alexis'`
    # NO matchea "Alex" porque son tokens distintos. Fix: por cada token
    # ≥5 chars, resolvemos via `_resolve_person_aliases` (WhatsApp +
    # Apple Contacts + mentions) para traer diminutivos, apellidos y
    # alias conocidos del contacto. El resultado se agrega al name-OR
    # chain. Dedup insensible a caso. Cap a 10 aliases totales para
    # mantener la query Drive bounded.
    expanded: list[str] = list(name_tokens)
    seen_lc = {t.lower() for t in expanded}
    for t in name_tokens:
        for alias in _resolve_person_aliases(t):
            if alias.lower() not in seen_lc and 3 <= len(alias) <= 30:
                expanded.append(alias)
                seen_lc.add(alias.lower())
            if len(expanded) >= 10:
                break
        if len(expanded) >= 10:
            break
    name_tokens = expanded

    if name_tokens:
        name_or = " or ".join(
            f"name contains '{t.replace(chr(92), chr(92)*2).replace(chr(39), chr(92)+chr(39))}'"
            for t in name_tokens
        )
        q = (
            f"(fullText contains '{joined}' or ({name_or})) "
            "and trashed = false"
        )
    else:
        # Si todos los tokens son muy cortos, confiamos sólo en fullText.
        q = f"fullText contains '{joined}' and trashed = false"
    try:
        resp = svc.files().list(
            q=q,
            orderBy="modifiedTime desc",
            pageSize=max_files,
            fields=(
                "files(id,name,mimeType,modifiedTime,webViewLink,"
                "lastModifyingUser(displayName))"
            ),
            spaces="drive",
        ).execute()
    except Exception as exc:
        return json.dumps({
            "files": [], "tokens": tokens, "query_used": " ".join(tokens),
            "error": f"search_failed: {str(exc)[:120]}",
        }, ensure_ascii=False)

    raw_files = resp.get("files") or []
    out_files: list[dict] = []
    for f in raw_files[:max_files]:
        mime = f.get("mimeType") or ""
        label = _GDRIVE_MIME_LABEL.get(mime, "archivo")
        body_text = ""
        export_mime = _GDRIVE_EXPORT_MIME.get(mime)
        if export_mime:
            try:
                raw = svc.files().export(fileId=f["id"], mimeType=export_mime).execute()
                if isinstance(raw, bytes):
                    raw = raw.decode("utf-8", errors="ignore")
                body_text = (raw or "").strip()[:body_cap]
            except Exception:
                body_text = ""
        out_files.append({
            "name": f.get("name") or "(sin nombre)",
            "mime_label": label,
            "modified": f.get("modifiedTime") or "",
            "link": f.get("webViewLink") or "",
            "modifier": (f.get("lastModifyingUser") or {}).get("displayName") or "",
            "body": body_text,
        })
    return json.dumps({
        "tokens": tokens,
        "query_used": " ".join(tokens),
        "files": out_files,
    }, ensure_ascii=False)


# ── Chrome bookmarks used (History join Bookmarks) — moved to
# `rag.integrations.chrome_bookmarks` (Phase 1b, 2026-04-25). The re-export
# at the bottom of this file keeps `rag._fetch_chrome_bookmarks_used`
# resolvable for tests + `web/server.py` imports.


# ── Per-vault activity (multi-vault aware, never mixes data) ─────────────────
def _fetch_vault_activity(hours: int = 48, n_per_vault: int = 5) -> dict:
    """Per-vault recent-notes snapshot — iterates every registered vault.

    Returns `{vault_name: [{path, title, modified, snippet}, ...]}` sorted
    by mtime desc. Honors `is_excluded` (drops `.trash`, `.obsidian`, etc.)
    and skips MORNING_FOLDER so the section doesn't re-surface the brief
    itself. Silent-fail per vault — a single unreadable path doesn't tank
    the others.

    Designed for dashboards that need to keep personal/work vaults visibly
    separated (user has explicit `vaults.json` config with both).
    """
    from datetime import timedelta as _td
    vaults = resolve_vault_paths(["all"])
    if not vaults:
        return {}

    cutoff = datetime.now() - _td(hours=hours)
    out: dict[str, list[dict]] = {}
    for name, vault in vaults:
        if not vault.is_dir():
            continue
        items: list[dict] = []
        try:
            for p in vault.rglob("*.md"):
                try:
                    rel = str(p.relative_to(vault))
                except ValueError:
                    continue
                if is_excluded(rel):
                    continue
                if rel.startswith(f"{MORNING_FOLDER}/"):
                    continue
                if _is_daemon_generated_path(rel):
                    continue
                try:
                    mtime = datetime.fromtimestamp(p.stat().st_mtime)
                except OSError:
                    continue
                if mtime < cutoff:
                    continue
                try:
                    raw = p.read_text(encoding="utf-8", errors="ignore")
                except OSError:
                    raw = ""
                items.append({
                    "path": rel,
                    "title": p.stem,
                    "modified": mtime.isoformat(timespec="seconds"),
                    "snippet": clean_md(raw)[:140].strip() if raw else "",
                })
        except OSError:
            continue
        items.sort(key=lambda r: r["modified"], reverse=True)
        out[name] = items[:n_per_vault]
    return out


# WhatsApp leaf integrations (`WHATSAPP_DB_PATH`, `WHATSAPP_BOT_JID`,
# `_fetch_whatsapp_unread`, `WA_TASKS_*`, `_wa_tasks_load_state`,
# `_wa_tasks_save_state`, `_wa_chat_label`, `_fetch_whatsapp_window`) moved
# to `rag.integrations.whatsapp` (Phase 1b, 2026-04-25). Re-exported at the
# bottom of this file. The cross-ref helper below stays here because it
# orchestrates `_fetch_contact` (vault) + WA + datetime parsing — not a leaf.


# ── WhatsApp cross-reference for entity queries ─────────────────────────────
# When the user asks about a person from 99-Mentions/ (e.g. "qué sabés de
# Grecia"), surface the last N WhatsApp messages where that person is the
# chat name or appears in the content. If any message carries a parseable
# datetime commitment ("nos vemos mañana 19hs"), produce a propose payload
# so the UI can offer to create a reminder/calendar event inline.
#
# Design choices:
#   - Read directly from the bridge SQLite (ro). The vault index is
#     15-min stale; the bridge is seconds fresh. Tradeoff: we can't
#     ride the RAG relevance signal, but for "última actividad con X"
#     freshness matters more than semantic similarity.
#   - Match on chat name first (exact), content second (substring).
#     Chat-name matches are always more relevant than content hits
#     because they're 1:1 (a chat called "Grecia" is probably the
#     direct chat with her), whereas content hits may mention her
#     in passing in a group.
#   - Cap at WA_CROSS_REF_LIMIT (3) — the user picked "últimos 3, sin
#     filtro temporal" in the UX round, so no `since` clause.
#   - Propose uses the SAME `_parse_natural_datetime` + `_has_explicit_time`
#     already wired to the /chat tool-calling surface, so the render
#     matches the inline create-intent chips from web + CLI chat.

WA_CROSS_REF_LIMIT = 3


# Informal nickname → how the bot addresses the user ("Fer, ¿te agendo…?").
# Source priority: first `aliases:` entry in `Yo.md` (user-chosen informal
# form) > last token of "Apellido / nombre completo" body line (works for
# AR format "Ferrari Fernando" → Fernando) > None (bot falls back to no-
# name phrasing). Cached per Yo.md mtime so edits propagate without restart.
_user_nickname_cache: tuple[float, str | None] | None = None
_user_nickname_cache_lock = threading.Lock()


def _load_user_nickname(vault_root: Path | None = None) -> str | None:
    """Return the short form the bot should use to address the user, or
    None if Yo.md is missing / has no extractable name.

    Resolution rules:
      1. If `Yo.md` frontmatter has `aliases:` with ≥1 non-empty entry,
         use the first (user-chosen informal form — "Fer", "Fede", etc.).
      2. Else parse the body line `- **Apellido / nombre completo**: X Y`,
         take the last whitespace-separated token (AR convention is
         "Apellido Nombre" → last token = nombre de pila).
      3. Else None.

    Cached by Yo.md mtime.
    """
    global _user_nickname_cache
    root = (vault_root or VAULT_PATH) / _MENTIONS_FOLDER / "Yo.md"
    if not root.is_file():
        return None
    try:
        mtime = root.stat().st_mtime
    except OSError:
        return None
    with _user_nickname_cache_lock:
        if _user_nickname_cache and _user_nickname_cache[0] == mtime:
            return _user_nickname_cache[1]

    try:
        txt = root.read_text(encoding="utf-8")
    except Exception:
        return None

    nick: str | None = None
    # Step 1 — aliases.
    dossier = _parse_mention_dossier("Yo.md", vault_root=(vault_root or VAULT_PATH) / _MENTIONS_FOLDER)
    # _parse_mention_dossier expects a path relative to vault_root; we
    # pass the MENTIONS dir as the root so "Yo.md" resolves there.
    if dossier.get("aliases"):
        candidate = dossier["aliases"][0].strip()
        if candidate:
            nick = candidate

    # Step 2 — body fallback. Matches `- **Apellido / nombre completo**: Foo Bar`
    # or the lenient `Apellido / nombre completo: Foo Bar`. Skips empty values.
    if nick is None:
        import re as _re
        m = _re.search(
            r"Apellido\s*/\s*nombre\s+completo\s*\**\s*:\s*(.+?)(?:\n|$)",
            txt, _re.IGNORECASE,
        )
        if m:
            full = m.group(1).strip()
            if full:
                tokens = full.split()
                if tokens:
                    nick = tokens[-1]

    with _user_nickname_cache_lock:
        _user_nickname_cache = (mtime, nick)
    return nick


def _parse_mention_dossier(rel_path: str, vault_root: Path | None = None) -> dict:
    """Extract `{name, aliases, phone_digits}` from a 99-Mentions/ dossier.

    `name` is the filename stem. `aliases` are frontmatter `aliases:` entries
    (both inline `[a, b]` and multiline `  - a`), empty list if missing or
    parse fails. `phone_digits` is the digits-only normalization of the
    `- **Teléfono**: …` body line (used by the WA cross-ref render to map
    JID senders → human names). Returns sensible empty defaults on
    unreadable files — caller treats as "entity with no cross-ref possible".
    """
    root = vault_root or VAULT_PATH
    p = root / rel_path
    out: dict = {"name": p.stem, "aliases": [], "phone_digits": ""}
    try:
        txt = p.read_text(encoding="utf-8")
    except Exception:
        return out
    # Phone via centralized parser — matches the full label set (tel|phone|
    # cel|whatsapp|wa|…), not just "Teléfono". Before 2026-04-21 this regex
    # was narrower than `_MENTIONS_PHONE_RE` en el mentions index, dejando
    # a contactos con `- Cel: +54...` fuera del phone_digits. Mantengo el
    # floor original de 10 dígitos (el dossier_phones helper usa 8; 10 es
    # más estricto para evitar que placeholders tipo "+54 9 ..." entren).
    phones = [d for d in _parse_dossier_phones(txt) if len(d) >= 10]
    if phones:
        out["phone_digits"] = phones[0]
    if not txt.startswith("---\n"):
        return out
    end = txt.find("\n---", 4)
    if end == -1:
        return out
    fm = txt[4:end]
    aliases: list[str] = []
    in_aliases = False
    for line in fm.split("\n"):
        if line.startswith("aliases:"):
            rest = line.split(":", 1)[1].strip()
            if rest.startswith("[") and rest.endswith("]"):
                for a in rest[1:-1].split(","):
                    a = a.strip().strip("'\"")
                    if a:
                        aliases.append(a)
            else:
                in_aliases = True
            continue
        if in_aliases:
            if line.startswith("  - "):
                a = line[4:].strip().strip("'\"")
                if a:
                    aliases.append(a)
            elif line and not line.startswith(" "):
                in_aliases = False
    out["aliases"] = aliases
    return out


# Reverse index: phone_digits → entity name (filename stem). Built lazily
# from 99-Mentions/ dossiers, cached by the folder mtime (same invalidation
# strategy as `_mentions_cache`). Used by `_lookup_wa_mentions_for_entity`
# to resolve group-message senders (JIDs like 34084894028025@s.whatsapp.net)
# into human names when the JID happens to belong to a known Mention.
_phone_index_cache: dict | None = None
_phone_index_cache_lock = threading.Lock()


def _load_phone_index(vault_root: Path | None = None) -> dict[str, str]:
    """Return `{phone_digits: entity_name}` for every 99-Mentions/ dossier
    that declares a phone number in its body. Digits-only keys so lookups
    can tolerate `+54 9 …` formatting differences. Caches per MAX(mtime)
    of the mentions folder; same invalidation as `_load_mentions_index`.
    """
    global _phone_index_cache
    root = (vault_root or VAULT_PATH) / _MENTIONS_FOLDER
    if not root.exists():
        return {}
    files = [p for p in root.glob("*.md") if not p.name.startswith("_")]
    mtime_max = max((p.stat().st_mtime for p in files), default=0.0)
    cache_key = str(root.resolve())
    with _phone_index_cache_lock:
        if (
            _phone_index_cache
            and _phone_index_cache.get("key") == cache_key
            and _phone_index_cache.get("mtime") == mtime_max
        ):
            return _phone_index_cache["index"]
    idx: dict[str, str] = {}
    for p in files:
        try:
            d = _parse_mention_dossier(
                str(p.relative_to(vault_root or VAULT_PATH)),
                vault_root=vault_root or VAULT_PATH,
            )
        except Exception:
            continue
        digits = d.get("phone_digits") or ""
        if len(digits) >= 10:
            idx[digits] = d["name"]
    with _phone_index_cache_lock:
        _phone_index_cache = {"key": cache_key, "mtime": mtime_max, "index": idx}
    return idx


def _resolve_sender_to_name(
    sender_raw: str,
    fallback: str = "",
    *,
    vault_root: Path | None = None,
) -> str:
    """Resolve a WA message sender (JID or phone) to a human-friendly
    name. Fallback strategies, in order:

      1. If `sender_raw` is empty → `fallback` (usually the chat name).
      2. Strip `@s.whatsapp.net` / `@g.us` suffix.
      3. If the digits-only form matches a Mention dossier's `Teléfono`
         line → return the dossier filename stem ("Grecia", "Seba").
      4. Consult Apple Contacts by phone suffix (`_fetch_contact_by_phone`).
         Cached per last-8-digits key, silent-fail on permission denied.
         Returns the contact's `full_name` when present — "María Pérez"
         rather than the dossier stem lets user display familiar contact
         casing without editing the vault.
      5. If digits long enough, show `…<last 4>` (`"…8025"`) instead of
         the full JID number — groups of unmapped senders become
         readable without leaking PII.
      6. Otherwise return whatever we had after stripping.
    """
    s = (sender_raw or "").strip()
    if not s:
        return fallback or "?"
    local = s.split("@")[0]
    digits = "".join(c for c in local if c.isdigit())
    if len(digits) >= 10:
        idx = _load_phone_index(vault_root=vault_root)
        if digits in idx:
            return idx[digits]
        # Also try matching the last 10-13 digits against any dossier
        # phone (handles stored numbers with/without country code).
        for k, v in idx.items():
            if k.endswith(digits[-10:]) or digits.endswith(k[-10:]):
                return v
        # Dossier miss — fall through to Apple Contacts before masking.
        # This gives a name automatically for every WA contact that lives
        # in Contacts.app, without forcing manual `99 Mentions/` creation.
        contact = _fetch_contact_by_phone(digits)
        if contact and contact.get("full_name"):
            return contact["full_name"]
        return f"…{digits[-4:]}"
    return local or fallback or "?"


def _lookup_wa_mentions_for_entity(
    mention_rel_path: str,
    limit: int = WA_CROSS_REF_LIMIT,
    *,
    vault_root: Path | None = None,
    db_path: Path | None = None,
) -> list[dict]:
    """Return the last `limit` WhatsApp messages relevant to the person in
    `mention_rel_path` (vault-relative path of the 99-Mentions/ dossier).

    Match strategy — chat-name > content hit. For each candidate message,
    the relevance is:
      - `match`: "chat" if `chats.name` equals the entity name/alias
                 (case-insensitive, accent-insensitive), "content" if
                 `messages.content` contains the token instead.

    Deduplicates by message id. Orders newest first. Skips the bot JID,
    status broadcasts, empty/media-only messages. Caps result at `limit`.

    Returns `[]` on any error (missing DB, SQL failure, unreadable dossier)
    — callers treat the cross-ref as absent.
    """
    db = db_path or WHATSAPP_DB_PATH
    if not db.is_file():
        return []
    dossier = _parse_mention_dossier(mention_rel_path, vault_root=vault_root)
    tokens: list[str] = [dossier["name"]] + list(dossier["aliases"])
    tokens = [t.strip() for t in tokens if t and len(t.strip()) >= _MENTIONS_MIN_TOKEN_LEN]
    if not tokens:
        return []

    import sqlite3
    try:
        con = sqlite3.connect(
            f"file:{db}?mode=ro", uri=True, timeout=5.0,
        )
    except sqlite3.Error:
        return []
    try:
        con.row_factory = sqlite3.Row
        # Build WHERE clause: chat name matches OR content contains any token.
        # Use COLLATE NOCASE for chat name; content LIKE is already
        # case-insensitive for ASCII but we OR a folded variant to catch
        # accented tokens.
        or_clauses: list[str] = []
        params: list = []
        for t in tokens:
            # chats.name contains token (word-ish match — "Grecia's group"
            # should match entity "Grecia"; dedicated-chat matches are
            # boosted in the post-fetch sort).
            or_clauses.append("LOWER(c.name) LIKE LOWER(?)")
            params.append(f"%{t}%")
            # messages.content contains token (substring)
            or_clauses.append("m.content LIKE ?")
            params.append(f"%{t}%")
        where = " OR ".join(or_clauses)
        sql = f"""
            SELECT
              m.id AS id,
              m.chat_jid AS jid,
              m.sender AS sender,
              m.content AS content,
              m.timestamp AS ts,
              m.is_from_me AS is_from_me,
              m.media_type AS media_type,
              c.name AS chat_name
            FROM messages m
            LEFT JOIN chats c ON c.jid = m.chat_jid
            WHERE m.chat_jid != ?
              AND m.chat_jid NOT LIKE '%status@broadcast'
              AND ({where})
            ORDER BY m.timestamp DESC
            LIMIT ?
        """
        # Overfetch 6× the limit: content-LIKE may match our own quoting
        # of the entity in outbound messages; we also want headroom to
        # promote chat-name hits (match="chat") over scattered content
        # hits after the post-fetch re-sort.
        rows = con.execute(
            sql, (WHATSAPP_BOT_JID, *params, limit * 6),
        ).fetchall()
    except sqlite3.Error:
        return []
    finally:
        con.close()

    lower_tokens = [t.lower() for t in tokens]
    seen_ids: set[str] = set()
    candidates: list[dict] = []
    for r in rows:
        msg_id = r["id"] or ""
        if msg_id and msg_id in seen_ids:
            continue
        content = (r["content"] or "").strip().replace("\n", " ")
        if not content and r["media_type"]:
            content = f"[{r['media_type']}]"
        if not content:
            continue
        chat_name = r["chat_name"] or ""
        is_from_me = bool(r["is_from_me"])
        # 2026-04-21 pushname fix: raw JID senders in groups were surfacing
        # as "34084894028025" — noise. Resolve via phone → Mentions lookup
        # first, then fall back to "…<last 4>" if unmapped. For DMs where
        # the sender is already human-named through `chat_name`, prefer
        # that.
        who = (
            "yo" if is_from_me
            else _resolve_sender_to_name(
                r["sender"] or "", fallback=chat_name,
                vault_root=vault_root,
            )
        )
        # Match classification — "chat" wins when the chat name contains
        # the token (dedicated conversation OR their group), even if the
        # content doesn't. This is the signal we want to boost because it
        # means ~every message in that chat is about them.
        chat_lower = chat_name.lower()
        content_lower = content.lower()
        hit_chat = any(t in chat_lower for t in lower_tokens)
        hit_content = any(t in content_lower for t in lower_tokens)
        match = "chat" if hit_chat else ("content" if hit_content else "other")
        candidates.append({
            "id": msg_id,
            "ts": r["ts"] or "",
            "who": who,
            "text": content[:400],
            "chat_name": chat_name,
            "jid": r["jid"] or "",
            "is_from_me": is_from_me,
            "match": match,
        })
        seen_ids.add(msg_id)

    # Promote chat-name hits over content hits, then newest first within
    # each bucket. A dedicated chat with the person (or their group) is
    # nearly always more relevant than a scattered mention in some other
    # conversation — even if the scattered one is newer.
    chat_hits = sorted(
        (c for c in candidates if c["match"] == "chat"),
        key=lambda c: c["ts"], reverse=True,
    )
    other_hits = sorted(
        (c for c in candidates if c["match"] != "chat"),
        key=lambda c: c["ts"], reverse=True,
    )
    return (chat_hits + other_hits)[:limit]


def _build_wa_cross_ref(
    query: str,
    *,
    now: datetime | None = None,
    vault_root: Path | None = None,
) -> dict | None:
    """Assemble the WhatsApp cross-reference payload for a factual query.

    Returns `None` if:
      - No entity from 99-Mentions/ appears in the query, OR
      - No WA messages found for that entity.

    Otherwise returns::

        {
          "entity": "Grecia",
          "mention_path": "04-Archive/.../Grecia.md",
          "messages": [{ts, who, text, chat_name, is_from_me, match}, ...],
          "propose": {
            "kind": "calendar_event" | "reminder",
            "title": "...",
            "when_iso": "2026-04-16T19:00:00",
            "source_msg_idx": 0,
          } | null,
        }

    `propose` is non-null only when at least one message contains a
    parseable datetime. When multiple messages have datetimes, the newest
    wins. `kind` is "calendar_event" if the message has an explicit time
    (hinting at a real meet-up), else "reminder" (day-only). Matches the
    kind selection logic in `propose_reminder` / `propose_calendar_event`
    so the UX is consistent across surfaces.
    """
    mentions = _match_mentions_in_query(query, vault_root=vault_root)
    if not mentions:
        return None
    mention_path = mentions[0]  # first mention wins — already ordered by occurrence
    dossier = _parse_mention_dossier(mention_path, vault_root=vault_root)
    entity_name = dossier["name"] or Path(mention_path).stem
    msgs = _lookup_wa_mentions_for_entity(
        mention_path, vault_root=vault_root,
    )
    if not msgs:
        return None

    # Detect commitment: iterate msgs newest→oldest, parse each text for
    # a datetime. First hit wins. Skip outbound messages (is_from_me) —
    # "nos vemos mañana" coming from yo is an invitation we already know
    # about; the value of the cross-ref is surfacing OTHERS' commitments
    # back at us.
    anchor = now or datetime.now()
    propose: dict | None = None
    for idx, m in enumerate(msgs):
        if m["is_from_me"]:
            continue
        text = m["text"]
        dt = _parse_natural_datetime(text, now=anchor)
        if dt is None:
            continue
        # Must be in the future — past dates in chat history aren't
        # actionable (e.g. "te vi ayer" → dt = yesterday, skip).
        if dt <= anchor:
            continue
        has_time = _has_explicit_time(text)
        # Title: fall back on a short, human-readable hint. The user will
        # see the msg text above the propose card, so the title is mostly
        # for calendar/reminder display.
        short_text = text.strip()
        if len(short_text) > 60:
            short_text = short_text[:57] + "…"
        propose = {
            "kind": "calendar_event" if has_time else "reminder",
            "title": f"{entity_name}: {short_text}",
            "when_iso": dt.strftime("%Y-%m-%dT%H:%M:%S"),
            "source_msg_idx": idx,
        }
        break

    return {
        "entity": entity_name,
        "mention_path": mention_path,
        "messages": msgs,
        "propose": propose,
    }


# `_wa_extract_actions`, `_wa_chat_month_link`, `_wa_tasks_write_note` moved
# to `rag.integrations.whatsapp` (Phase 1b, 2026-04-25). Re-exported at the
# bottom of this file.


# ── Recent user queries ─────────────────────────────────────────────────────

def _fetch_recent_queries(
    query_log: Path, now: datetime, hours: int = 24, max_items: int = 8,
) -> list[dict]:
    """Queries the user issued in the last `hours`. Dedupes by text, keeps
    most recent occurrence. Excludes eval/ambient synthetic queries.
    """
    if not query_log.is_file():
        return []
    try:
        lines = query_log.read_text(encoding="utf-8").splitlines()
    except OSError:
        return []
    start = now - timedelta(hours=hours)
    seen: dict[str, dict] = {}
    for line in reversed(lines):
        line = line.strip()
        if not line:
            continue
        try:
            e = json.loads(line)
        except Exception:
            continue
        if e.get("cmd") != "query":
            continue
        try:
            ts = datetime.fromisoformat(e.get("ts", ""))
        except Exception:
            continue
        if ts < start or ts > now:
            continue
        q = (e.get("q") or "").strip()
        if not q:
            continue
        key = q.lower()
        if key in seen:
            continue
        seen[key] = {"q": q, "ts": ts.isoformat(timespec="minutes")}
        if len(seen) >= max_items:
            break
    return list(seen.values())


# Weather block (`WEATHER_LOCATION`, `WEATHER_RAIN_THRESHOLD`,
# `_WMO_WEATHER_CODES`, `_fetch_weather_rain`, `_fetch_weather_openmeteo`,
# `_fetch_weather_forecast`) moved to `rag.integrations.weather`
# (Phase 1b, 2026-04-25). Re-exported at the bottom of this file.


def _parse_applescript_date(s: str) -> datetime | None:
    """AppleScript `as string` dates are locale-formatted (e.g. 'lunes, 14 de abril
    de 2026, 09:00:00'). Try a few common locales/formats; return None on miss.
    """
    s = s.strip()
    if not s:
        return None
    fmts = [
        "%A, %B %d, %Y at %I:%M:%S %p",
        "%A, %d %B %Y at %H:%M:%S",
        "%A %d %B %Y %H:%M:%S",
        "%Y-%m-%d %H:%M:%S",
        "%Y-%m-%dT%H:%M:%S",
    ]
    for fmt in fmts:
        try:
            return datetime.strptime(s, fmt)
        except ValueError:
            continue
    # Spanish locale fallback: "miércoles, 15 de abril de 2026, 9:40:00 a. m."
    import re as _re
    m = _re.search(
        r"(\d{1,2})\s+de\s+([a-záéíóú]+)\s+de\s+(\d{4}),?\s+"
        r"(\d{1,2}):(\d{2})(?::(\d{2}))?"
        r"(?:\s*(a\.?\s*m\.?|p\.?\s*m\.?))?",
        s, _re.IGNORECASE,
    )
    if m:
        months_es = {
            "enero": 1, "febrero": 2, "marzo": 3, "abril": 4, "mayo": 5, "junio": 6,
            "julio": 7, "agosto": 8, "septiembre": 9, "setiembre": 9,
            "octubre": 10, "noviembre": 11, "diciembre": 12,
        }
        month = months_es.get(m.group(2).lower())
        if month:
            hour = int(m.group(4))
            ampm = (m.group(7) or "").lower().replace(" ", "").replace(".", "")
            if ampm == "pm" and hour < 12:
                hour += 12
            elif ampm == "am" and hour == 12:
                hour = 0
            try:
                return datetime(
                    int(m.group(3)), month, int(m.group(1)),
                    hour, int(m.group(5)),
                    int(m.group(6) or 0),
                )
            except ValueError:
                return None
    return None


def _fetch_system_activity(
    now: datetime, lookback_hours: int = 36,
) -> dict:
    """Qué hizo el sistema por su cuenta en las últimas `lookback_hours`.

    Agrega 3 fuentes on-disk (no toca el vault):
      - `ambient.jsonl` → eventos del hook ambient con wikilinks aplicados,
        dupes detectados o related notes. Se cuentan solo entries con ts en
        ventana y con al menos un signal > 0.
      - `filing_batches/*.jsonl` → audit log de moves (filing + archive).
        Conteo por MTIME del archivo dentro de la ventana. Archive runs
        se diferencian por prefijo de nombre `archive-`.
      - `tune.jsonl` → runs de `rag tune` (auto-calibración del ranker).
        `tune_last_delta` devuelve el `delta` de la run más reciente.

    Pure read: archivos inexistentes → ceros. Nunca crashea — errores de
    parsing en líneas individuales se ignoran.
    """
    from datetime import timedelta as _td
    start = now - _td(hours=lookback_hours)
    start_ts = start.timestamp()

    out = {
        "ambient_events": 0,
        "ambient_wikilinks": 0,
        "filing_moves": 0,
        "archive_moves": 0,
        "tune_runs": 0,
        "tune_last_delta": None,
    }

    # 1. Ambient: lineas con ts en ventana + al menos un signal > 0.
    if AMBIENT_LOG_PATH.is_file():
        try:
            for line in AMBIENT_LOG_PATH.read_text(encoding="utf-8").splitlines():
                line = line.strip()
                if not line:
                    continue
                try:
                    e = json.loads(line)
                except Exception:
                    continue
                try:
                    ts = datetime.fromisoformat(e.get("ts", ""))
                except Exception:
                    continue
                if ts < start or ts >= now:
                    continue
                wl = int(e.get("wikilinks_applied") or 0)
                dupes = len(e.get("dupes") or [])
                rel = int(e.get("related_count") or 0)
                if wl > 0 or dupes > 0 or rel > 0:
                    out["ambient_events"] += 1
                    out["ambient_wikilinks"] += wl
        except OSError:
            pass

    # 2. Filing batches: iterar archivos jsonl en la carpeta, contar rows
    # por mtime dentro de la ventana. Archive-* se cuenta también en
    # `archive_moves`.
    if FILING_BATCHES_DIR.is_dir():
        try:
            for batch in FILING_BATCHES_DIR.glob("*.jsonl"):
                try:
                    mtime = batch.stat().st_mtime
                except OSError:
                    continue
                if mtime < start_ts:
                    continue
                try:
                    n_rows = sum(
                        1 for ln in batch.read_text(encoding="utf-8").splitlines()
                        if ln.strip()
                    )
                except OSError:
                    continue
                out["filing_moves"] += n_rows
                if batch.name.startswith("archive-"):
                    out["archive_moves"] += n_rows
        except OSError:
            pass

    # 3. Tune runs: líneas con ts en ventana.
    last_delta: float | None = None
    last_ts: datetime | None = None
    if TUNE_LOG_PATH.is_file():
        try:
            for line in TUNE_LOG_PATH.read_text(encoding="utf-8").splitlines():
                line = line.strip()
                if not line:
                    continue
                try:
                    e = json.loads(line)
                except Exception:
                    continue
                try:
                    ts = datetime.fromisoformat(e.get("ts", ""))
                except Exception:
                    continue
                if ts < start or ts >= now:
                    continue
                out["tune_runs"] += 1
                d = e.get("delta")
                if isinstance(d, (int, float)):
                    if last_ts is None or ts > last_ts:
                        last_ts = ts
                        last_delta = float(d)
        except OSError:
            pass
    out["tune_last_delta"] = last_delta

    return out


# Screen Time block (`SCREENTIME_DB`, `_SCREENTIME_*`, `_screentime_app_label`,
# `_screentime_category`, `_collect_screentime`, `_render_screentime_section`)
# moved to `rag.integrations.screentime` (Phase 1b, 2026-04-25). Re-exported
# at the bottom of this file. `_fmt_hm` stays here because it's a generic
# duration formatter used by other consumers (`web/server.py`, tests).


def _fmt_hm(secs: int) -> str:
    """Format seconds as "Hh MMm" / "MMm" / "SSs" for brief rendering."""
    if secs >= 3600:
        h, r = divmod(secs, 3600)
        m = r // 60
        return f"{h}h {m:02d}m" if m else f"{h}h"
    if secs >= 60:
        return f"{secs // 60}m"
    return f"{secs}s"


# `_render_screentime_section` moved to `rag.integrations.screentime`
# (Phase 1b, 2026-04-25). Re-exported at the bottom of this file.


def _render_system_activity_section(act: dict) -> str:
    """Bullets determinísticos de "lo que el sistema hizo solo".

    Retorna "" si no hay actividad significativa (todos los conteos 0,
    ignorando `tune_last_delta`). Headers y bullets son code-owned — no
    LLM toca este bloque.
    """
    if not act:
        return ""
    has_ambient = (
        int(act.get("ambient_events") or 0) > 0
        or int(act.get("ambient_wikilinks") or 0) > 0
    )
    filing = int(act.get("filing_moves") or 0)
    archive = int(act.get("archive_moves") or 0)
    tune_runs = int(act.get("tune_runs") or 0)
    if not (has_ambient or filing or archive or tune_runs):
        return ""

    bullets: list[str] = []
    wl = int(act.get("ambient_wikilinks") or 0)
    ev = int(act.get("ambient_events") or 0)
    if wl > 0 or ev > 0:
        if wl > 0 and ev > 0:
            bullets.append(
                f"- ambient aplicó {wl} [[wikilinks]] automáticos en {ev} captura{'s' if ev != 1 else ''}"
            )
        elif wl > 0:
            bullets.append(f"- ambient aplicó {wl} [[wikilinks]] automáticos")
        else:
            bullets.append(f"- ambient detectó señales en {ev} captura{'s' if ev != 1 else ''}")
    # `archive_moves` es subset de `filing_moves`; reportar ambos, pero el
    # no-archive (filing manual / `rag file`) solo si hubo moves que no fueron archive.
    non_archive = filing - archive
    if archive > 0:
        bullets.append(
            f"- archiver movió {archive} dead note{'s' if archive != 1 else ''} a 04-Archive"
        )
    if non_archive > 0:
        bullets.append(
            f"- filing movió {non_archive} nota{'s' if non_archive != 1 else ''} a su carpeta"
        )
    if tune_runs > 0:
        delta = act.get("tune_last_delta")
        if isinstance(delta, (int, float)):
            bullets.append(
                f"- rag tune recalibró pesos ({delta:+.3f} objetivo)"
            )
        else:
            bullets.append(
                f"- rag tune corrió {tune_runs} ve{'ces' if tune_runs != 1 else 'z'}"
            )
    return "## ⚙️ Lo que el sistema hizo solo\n" + "\n".join(bullets)


def _collect_morning_evidence(
    now: datetime,
    vault: Path,
    query_log: Path,
    contradiction_log: Path,
    lookback_hours: int = 36,
) -> dict:
    """Gather yesterday-ish signals. 36h lookback covers the gap between
    morning runs on different days (skipping a day doesn't lose yesterday).
    """
    from datetime import timedelta as _td
    start = now - _td(hours=lookback_hours)

    recent: list[dict] = []
    inbox: list[dict] = []
    todos: list[dict] = []
    if vault.is_dir():
        for p in vault.rglob("*.md"):
            try:
                rel = str(p.relative_to(vault))
            except ValueError:
                continue
            if is_excluded(rel):
                continue
            try:
                mtime = datetime.fromtimestamp(p.stat().st_mtime)
            except OSError:
                continue
            try:
                raw = p.read_text(encoding="utf-8", errors="ignore")
            except OSError:
                continue
            fm = parse_frontmatter(raw)
            title = p.stem
            if rel.startswith(f"{_CAPTURE_FOLDER}/") and not _is_daemon_generated_path(rel):
                inbox.append({
                    "path": rel, "title": title,
                    "modified": mtime.isoformat(timespec="seconds"),
                    "snippet": clean_md(raw)[:160].strip(),
                })
            if (
                start <= mtime < now
                and not rel.startswith(f"{MORNING_FOLDER}/")
                and not _is_daemon_generated_path(rel)
            ):
                recent.append({
                    "path": rel, "title": title,
                    "modified": mtime.isoformat(timespec="seconds"),
                    "snippet": clean_md(raw)[:220].strip(),
                })
            t = fm.get("todo")
            d = fm.get("due")
            if t or d:
                todos.append({
                    "path": rel, "title": title,
                    "todo": t if t else None,
                    "due": str(d) if d else None,
                })

    new_contrad: list[dict] = []
    if contradiction_log.is_file():
        try:
            lines = contradiction_log.read_text(encoding="utf-8").splitlines()
        except OSError:
            lines = []
        for line in lines:
            line = line.strip()
            if not line:
                continue
            try:
                e = json.loads(line)
            except Exception:
                continue
            try:
                ts = datetime.fromisoformat(e.get("ts", ""))
            except Exception:
                continue
            if ts < start or ts >= now:
                continue
            if e.get("cmd") != "contradict_index":
                continue
            entries = e.get("contradicts") or []
            if not entries:
                continue
            new_contrad.append({
                "subject_path": e.get("subject_path", ""),
                "targets": [
                    {"path": c.get("path", ""), "why": c.get("why", "")}
                    for c in entries if isinstance(c, dict)
                ],
            })

    low_conf: list[dict] = []
    if query_log.is_file():
        try:
            lines = query_log.read_text(encoding="utf-8").splitlines()
        except OSError:
            lines = []
        for line in lines:
            line = line.strip()
            if not line:
                continue
            try:
                e = json.loads(line)
            except Exception:
                continue
            try:
                ts = datetime.fromisoformat(e.get("ts", ""))
            except Exception:
                continue
            if ts < start or ts >= now:
                continue
            if e.get("cmd") != "query":
                continue
            score = e.get("top_score")
            if isinstance(score, (int, float)) and score <= CONFIDENCE_RERANK_MIN:
                q = (e.get("q") or "").strip()
                if q:
                    low_conf.append({"q": q, "top_score": float(score)})

    recent.sort(key=lambda r: r["modified"], reverse=True)
    inbox.sort(key=lambda r: r["modified"], reverse=True)

    weather = _fetch_weather_rain()
    # Mensajes WhatsApp programados para HOY (TZ AR). Si la cola está
    # vacía o el módulo no está disponible, queda lista vacía. El render
    # del prompt solo agrega la sección si hay items, así que no
    # contamina los días sin pendings.
    try:
        from rag import wa_scheduled as _wa_sched  # noqa: PLC0415
        wa_today = _wa_sched.list_today_pending(now=now)
    except Exception:
        wa_today = []
    ev = {
        "recent_notes": recent,
        "inbox_pending": inbox,
        "todos": todos,
        "new_contradictions": new_contrad,
        "low_conf_queries": low_conf,
        "calendar_today": _fetch_calendar_today(),
        "reminders_due": _fetch_reminders_due(now),
        "mail_unread": _fetch_mail_unread(),
        "gmail": _fetch_gmail_evidence(now),
        "drive": _fetch_drive_evidence(now, days=5),
        "bookmarks_used": _fetch_chrome_bookmarks_used(hours=48, n=5),
        "vault_activity": _fetch_vault_activity(hours=48, n_per_vault=5),
        "whatsapp_unread": _fetch_whatsapp_unread(),
        "wa_scheduled_today": wa_today,
        "recent_queries": _fetch_recent_queries(query_log, now),
        "weather_rain": weather,  # dict or None
        "system_activity": _fetch_system_activity(now, lookback_hours=lookback_hours),
        "screentime": _collect_screentime(start, now),
    }
    # Dedup: if a vault todo matches an Apple Reminder (Jaccard ≥ 0.6 on
    # normalized tokens), drop the todo — the reminder is the actionable
    # source. Prevents "comprar pan" appearing twice in the brief.
    ev["todos"] = _dedup_todos_vs_reminders(ev["todos"], ev["reminders_due"])
    return ev


def _render_morning_prompt(date_label: str, ev: dict) -> str:
    parts = [
        f"Generás un morning brief para el {date_label}, en 1ra persona, "
        "en español rioplatense, tono calmo y directo.",
        "",
        "Contexto real del vault (NO inventes lo que no esté acá):",
        "",
    ]
    if ev["recent_notes"]:
        parts.append(f"## Notas modificadas ayer ({len(ev['recent_notes'])}):")
        for r in ev["recent_notes"][:12]:
            parts.append(f"- [[{r['title']}]] ({r['path']}): {r['snippet'][:200]}")
        parts.append("")
    if ev["inbox_pending"]:
        parts.append(f"## En 00-Inbox/ ({len(ev['inbox_pending'])} sin triar):")
        for r in ev["inbox_pending"][:10]:
            parts.append(f"- [[{r['title']}]]: {r['snippet'][:160]}")
        parts.append("")
    if ev["todos"]:
        parts.append(f"## Notas con todo/due ({len(ev['todos'])}):")
        for r in ev["todos"][:10]:
            bits = []
            if r.get("due"):
                bits.append(f"due={r['due']}")
            if r.get("todo"):
                bits.append("todo=Y")
            parts.append(f"- [[{r['title']}]] ({r['path']}) {', '.join(bits)}")
        parts.append("")
    if ev["new_contradictions"]:
        parts.append(
            f"## Contradicciones nuevas detectadas ({len(ev['new_contradictions'])}):"
        )
        for c in ev["new_contradictions"][:5]:
            targets = ", ".join(t["path"] for t in c["targets"][:3])
            parts.append(f"- {c['subject_path']} ↔ {targets}")
        parts.append("")
    if ev["low_conf_queries"]:
        parts.append(f"## Queries sin respuesta buena ({len(ev['low_conf_queries'])}):")
        for q in ev["low_conf_queries"][:6]:
            parts.append(f"- \"{q['q']}\" (score {q['top_score']:+.2f})")
        parts.append("")
    if ev.get("calendar_today"):
        parts.append(f"## Calendar — eventos de hoy ({len(ev['calendar_today'])}):")
        for e in ev["calendar_today"][:12]:
            parts.append(f"- {e['title']} ({e['start']})")
        parts.append("")
    if ev.get("reminders_due"):
        parts.append(f"## Reminders — vencidos/hoy ({len(ev['reminders_due'])}):")
        for r in ev["reminders_due"][:12]:
            tag = r["bucket"]
            lst = f" [{r['list']}]" if r.get("list") else ""
            parts.append(f"- ({tag}) {r['name']} due={r['due']}{lst}")
        parts.append("")
    if ev.get("wa_scheduled_today"):
        parts.append(
            f"## WhatsApp — mensajes programados para hoy "
            f"({len(ev['wa_scheduled_today'])}):"
        )
        for w in ev["wa_scheduled_today"][:12]:
            contact = w["contact_name"] or "(sin nombre)"
            preview = w.get("message_text_preview") or ""
            parts.append(
                f"- {w['scheduled_for_local']} → {contact}: \"{preview}\""
            )
        parts.append("")
    if ev.get("mail_unread"):
        parts.append(f"## Mail — no leídos últimas 36h ({len(ev['mail_unread'])}):")
        for m in ev["mail_unread"][:10]:
            prefix = "**VIP** · " if m.get("is_vip") else ""
            parts.append(f"- {prefix}{m['subject']} — {m['sender']}")
            preview = (m.get("body_preview") or "").strip()
            if preview:
                parts.append(f"    _{preview}_")
        parts.append("")
    gm = ev.get("gmail") or {}
    if gm.get("unread_count") or gm.get("starred") or gm.get("awaiting_reply"):
        unread_total = int(gm.get("unread_count") or 0)
        parts.append(f"## Gmail — {unread_total} sin leer total en inbox:")
        for m in gm.get("starred") or []:
            parts.append(
                f"- ⭐ {m.get('subject', '')} — {m.get('from', '')}: "
                f"{m.get('snippet', '')}"
            )
        for m in gm.get("awaiting_reply") or []:
            days = m.get("days_old") or 0
            parts.append(
                f"- ⏳ esperando mi respuesta hace {days}d: "
                f"{m.get('subject', '')} — {m.get('from', '')}: "
                f"{m.get('snippet', '')}"
            )
        parts.append("")
    if ev.get("whatsapp_unread"):
        parts.append(
            f"## WhatsApp — chats con actividad últimas 24h "
            f"({len(ev['whatsapp_unread'])}):"
        )
        for w in ev["whatsapp_unread"][:8]:
            snip = f" — “{w['last_snippet']}”" if w.get("last_snippet") else ""
            parts.append(f"- {w['name']} ({w['count']} msgs){snip}")
        parts.append("")
    if ev.get("recent_queries"):
        parts.append(
            f"## Preguntas que me hiciste al RAG últimas 24h "
            f"({len(ev['recent_queries'])}):"
        )
        for q in ev["recent_queries"][:8]:
            parts.append(f"- \"{q['q']}\"")
        parts.append("")
    if ev.get("weather_rain"):
        w = ev["weather_rain"]
        parts.append("## Clima — lluvia pronosticada hoy:")
        parts.append(f"- {w.get('summary', '')}")
        parts.append("")
    parts.extend([
        "Formato de salida (Markdown, EXACTO):",
        "",
        "## 📬 Ayer en una línea",
        "(1 oración: qué pasó en el vault ayer)",
        "",
        "## 📅 Hoy en la agenda",
        "(si hay eventos de Calendar, reminders vencidos/hoy, mails relevantes "
        "sin leer o WhatsApp con actividad últimas 24h, integrarlos en bullets cortos "
        "con horario/remitente/nombre si aplica; si nada de esto existe, omitir la sección. "
        "Si hay lluvia pronosticada, mencionala en una línea al final de esta sección.)",
        "",
        "## 🎯 Foco sugerido para hoy",
        "(3 bullets con [[wikilink]] a la nota relevante si aplica; "
        "priorizar lo urgente/frágil; cruzar con eventos de Calendar y reminders; "
        "si no hay nada crítico, decilo honestamente)",
        "",
        "## 🗂 Pendientes que asoman",
        "(si hay inbox o todos, listarlos cortos; si no, omitir la sección)",
        "",
        "## ⚠ Atender",
        "(si hay contradicciones nuevas, gaps persistentes, o preguntas recientes "
        "sin responder bien, nombrarlos; si no, omitir la sección)",
        "",
        "Entre 140 y 320 palabras total. Citá notas con [[Título]].",
    ])
    return "\n".join(parts)


def _generate_morning_narrative(prompt: str) -> str:
    try:
        resp = _chat_capped_client().chat(
            model=resolve_chat_model(),
            messages=[{"role": "user", "content": prompt}],
            options=CHAT_OPTIONS,
            keep_alive=chat_keep_alive(),
        )
        # 2026-04-29: aplicar el filter PT→ES post-gen como defense-in-depth.
        # El prompt del morning brief vive inline (no via load_prompt) y por
        # ahora no incluye `language_es_AR.v1`. El brief se manda al usuario
        # via WhatsApp + se guarda en `00-Inbox/`, así que cualquier leak pt
        # es visible. Filter es idempotente y safe sobre texto en es puro.
        from rag.iberian_leak_filter import replace_iberian_leaks
        return replace_iberian_leaks((resp.message.content or "").strip())
    except Exception:
        return ""


# ── Template-first morning (structured JSON output) ─────────────────────────
# El prompt monolítico + LLM-draftea-todo sufría dos problemas: (1) tokens
# altos porque el LLM re-transcribe evidencia ya estructurada, (2) drift —
# a veces inventaba secciones vacías con "(nada)" y otras las omitía. Este
# pipeline invierte el control: el código arma el esqueleto + sección 📅
# Agenda (determinística desde calendar/reminders/weather), y el LLM SÓLO
# devuelve JSON con 4 fields textuales. Bloques sin evidencia se omiten
# sin preguntarle al modelo.


HEAVY_RAIN_THRESHOLD = 70  # max_chance% at or above → indoor suggestion


def _render_morning_agenda_section(ev: dict) -> str:
    """Deterministic render of 📅 Agenda from calendar + reminders + weather.
    Returns "" if there's nothing to show — caller omits the section entirely.

    Weather heuristic: if `max_chance ≥ HEAVY_RAIN_THRESHOLD` we append a
    short "💡 considerá foco indoor" line below the rain summary. Pure code,
    no LLM — predictable and cheap.
    """
    bullets: list[str] = []
    for e in ev.get("calendar_today", [])[:10]:
        when = e.get("start") or ""
        bullets.append(f"- {e.get('title', '(sin título)')} · {when}")
    for r in ev.get("reminders_due", [])[:10]:
        bucket = r.get("bucket") or ""
        lst = f" [{r['list']}]" if r.get("list") else ""
        name = r.get("name", "(sin nombre)")
        if bucket == "undated":
            bullets.append(f"- 📌 {name}{lst}")
        else:
            tag = f"({bucket}) " if bucket else ""
            due = f" · {r['due']}" if r.get("due") else ""
            bullets.append(f"- {tag}{name}{due}{lst}")
    if ev.get("weather_rain"):
        w = ev["weather_rain"]
        summary = w.get("summary") or "lluvia pronosticada"
        bullets.append(f"- 🌧 {summary}")
        # Heavy-rain hint: if ≥70% at any block today, suggest indoor focus.
        max_chance = int(w.get("max_chance") or 0)
        if max_chance >= HEAVY_RAIN_THRESHOLD:
            bullets.append(
                f"  💡 lluvia fuerte ({max_chance}%) — "
                "priorizá trabajo indoor y evitá compromisos outdoor."
            )
    if not bullets:
        return ""
    return "## 📅 Hoy en la agenda\n" + "\n".join(bullets)


def _format_gmail_from(raw: str) -> str:
    """Extract the display name from a Gmail `From` header, falling back to
    the bare address. `"Susana L." <s@x.com>` → `Susana L.`. `s@x.com` → `s@x.com`.
    """
    if not raw:
        return ""
    m = re.match(r"\s*\"?([^\"<]+?)\"?\s*<[^>]+>\s*$", raw)
    if m:
        name = m.group(1).strip().strip("'")
        if name:
            return name
    return raw.strip()


def _render_morning_gmail_section(ev: dict) -> str:
    """Deterministic render of 📧 Gmail section. Surfaces two always-relevant
    signals: threads where I haven't replied in ≥3 days (⏳) and starred
    threads I explicitly flagged (⭐). Adds a trailing total-unread line if
    > 0. Returns "" when none of the three apply.

    Owned by code so these signals survive LLM compression — the previous
    LLM-only path soft-dropped them on noisy mornings.
    """
    gm = ev.get("gmail") or {}
    awaiting = gm.get("awaiting_reply") or []
    starred = gm.get("starred") or []
    unread = int(gm.get("unread_count") or 0)
    if not awaiting and not starred and not unread:
        return ""
    bullets: list[str] = []
    # awaiting_reply first — highest actionability
    for m in awaiting[:5]:
        subj = (m.get("subject") or "(sin asunto)").strip()
        who = _format_gmail_from(m.get("from") or "")
        days = m.get("days_old") or 0
        bullets.append(f"- ⏳ {days}d · **{subj}** — {who}")
        snip = (m.get("snippet") or "").strip()
        if snip:
            bullets.append(f"  _{snip}_")
    for m in starred[:3]:
        subj = (m.get("subject") or "(sin asunto)").strip()
        who = _format_gmail_from(m.get("from") or "")
        bullets.append(f"- ⭐ **{subj}** — {who}")
        snip = (m.get("snippet") or "").strip()
        if snip:
            bullets.append(f"  _{snip}_")
    if unread:
        bullets.append(f"- 📬 {unread} sin leer en inbox")
    return "## 📧 Gmail\n" + "\n".join(bullets)


def _render_morning_drive_section(ev: dict) -> str:
    """Deterministic render of 📁 Drive — files modified in the last `window_days`.
    Returns "" if no recent activity. Owned by code (not LLM) so the signal
    survives noisy mornings. Each bullet: `- Nd · Doc/Sheet/Slide · Name`.
    Modifier name is appended when it's not just the user themselves.
    """
    dv = ev.get("drive") or {}
    files = dv.get("files") or []
    if not files:
        return ""
    window = int(dv.get("window_days") or 5)
    bullets: list[str] = []
    for f in files[:5]:
        name = (f.get("name") or "(sin nombre)").strip()
        label = f.get("mime_label") or "archivo"
        days_ago = f.get("days_ago") or 0
        line = f"- {days_ago}d · {label} · **{name}**"
        modifier = (f.get("modifier") or "").strip()
        if modifier:
            line += f" _— {modifier}_"
        bullets.append(line)
    return f"## 📁 Drive (últimos {window}d)\n" + "\n".join(bullets)


def _render_morning_bookmarks_section(ev: dict) -> str:
    """Deterministic render of 🔖 Bookmarks — saved pages the user actually
    reached for in the last 48h. Returns "" if none. Code-owned so the
    list survives noisy mornings and doesn't get hallucinated.
    """
    bm = ev.get("bookmarks_used") or []
    if not bm:
        return ""
    bullets: list[str] = []
    for b in bm[:5]:
        name = (b.get("name") or "").strip() or b.get("url") or "(sin título)"
        url = b.get("url") or ""
        folder = (b.get("folder") or "").strip()
        count = int(b.get("visit_count") or 0)
        line = f"- **{name}** — [{url}]({url})"
        extras: list[str] = []
        if folder:
            extras.append(folder)
        if count:
            extras.append(f"{count}×")
        if extras:
            line += " · " + " · ".join(extras)
        bullets.append(line)
    return "## 🔖 Bookmarks (últimas 48h)\n" + "\n".join(bullets)


def _render_morning_vaults_section(ev: dict) -> str:
    """Deterministic render of 📝 Vaults — per-vault recent activity, never
    mixed. One subsection per registered vault ("home", "work", …) so
    personal/work stay visibles separated. Returns "" if *all* vaults are
    empty in the 48h window.

    El bullet usa `obsidian://open?vault=<dir>&file=<path>` para que un
    click en macOS/iOS abra la nota directo en Obsidian (markdown links a
    paths relativos no abren nada). El nombre del vault para la URI viene
    de la dir-basename del path registrado, no del display-name.
    """
    va = ev.get("vault_activity") or {}
    if not va or not any(v for v in va.values()):
        return ""
    # Resolver display-name → dir-name (para la URI obsidian://). Si el
    # registry no devuelve el vault (test mode, registry vacío), caemos a
    # `VAULT_PATH.name` que es el default sensible.
    name_to_dir: dict[str, str] = {}
    try:
        for name, path in resolve_vault_paths(["all"]):
            name_to_dir[name] = Path(path).name
    except Exception:
        pass
    parts: list[str] = ["## 📝 Vaults (últimas 48h)"]
    for name in sorted(va.keys()):
        items = va.get(name) or []
        if not items:
            continue
        parts.append(f"### {name} ({len(items)})")
        vault_dir = name_to_dir.get(name) or VAULT_PATH.name
        for n in items[:5]:
            title = (n.get("title") or "").strip() or "(sin título)"
            path = n.get("path") or ""
            # Strip .md and url-encode for the obsidian URI (Obsidian agrega
            # el .md solo). El display label sigue siendo el path relativo
            # legible.
            file_param = path[:-3] if path.endswith(".md") else path
            uri = (
                f"obsidian://open?vault={urllib.parse.quote(vault_dir, safe='')}"
                f"&file={urllib.parse.quote(file_param, safe='/')}"
            )
            parts.append(f"- [[{title}]] · [{path}]({uri})")
    return "\n".join(parts)


# ── Dedup todos-del-vault vs reminders-de-Apple ─────────────────────────────
# Si tengo una nota con `todo: "comprar pan"` Y un Apple Reminder "comprar
# pan", el brief los listaba duplicados — ruido. Drop el del vault (el
# reminder ya es la fuente actionable con due y notificación). Jaccard
# sobre tokens normalizados (≥3 chars, acentos foldeados).

_TASK_DEDUP_JACCARD = 0.6


def _normalize_task_text(s: str) -> str:
    if not s:
        return ""
    n = unicodedata.normalize("NFD", s.lower())
    n = "".join(c for c in n if not unicodedata.combining(c))
    n = re.sub(r"[^\w\s]", " ", n)
    return re.sub(r"\s+", " ", n).strip()


def _task_tokens(s: str) -> set[str]:
    return {t for t in _normalize_task_text(s).split() if len(t) >= 3}


def _task_text_from_todo(t: dict) -> str:
    """Best-effort task string from a todo entry. `todo` can be a string,
    a list of strings, or None; fall back to the note title."""
    v = t.get("todo")
    if isinstance(v, list):
        return " ".join(str(x) for x in v if x)
    if v:
        return str(v)
    return str(t.get("title") or "")


def _dedup_todos_vs_reminders(
    todos: list[dict], reminders: list[dict],
    threshold: float = _TASK_DEDUP_JACCARD,
) -> list[dict]:
    """Remove todos whose task text overlaps (Jaccard ≥ threshold) with any
    reminder name. Returns a new list — does not mutate input. Pure.
    """
    if not todos or not reminders:
        return todos
    rem_tokens = [_task_tokens(r.get("name", "")) for r in reminders]
    rem_tokens = [t for t in rem_tokens if t]
    if not rem_tokens:
        return todos
    out: list[dict] = []
    for t in todos:
        tokens = _task_tokens(_task_text_from_todo(t))
        if not tokens:
            out.append(t)
            continue
        if any(
            len(tokens & rt) / len(tokens | rt) >= threshold
            for rt in rem_tokens
        ):
            continue  # dup with a reminder — drop from todos
        out.append(t)
    return out


def _match_loop_to_completed_reminder(
    loop_text: str,
    completed: list[dict],
    threshold: float = _TASK_DEDUP_JACCARD,
) -> dict | None:
    """Return the completed reminder (or None) whose `name` matches `loop_text`
    at Jaccard ≥ `threshold` over normalized tokens (≥3 chars, accent-folded).

    Picks the best match when multiple qualify — highest overlap wins. Pure.
    Deterministic across reruns: newest-first stable sort from upstream
    `_fetch_completed_reminders` breaks score ties toward the more recent
    closure (which is usually the one the user meant).
    """
    if not loop_text or not completed:
        return None
    loop_tokens = _task_tokens(loop_text)
    if not loop_tokens:
        return None
    best: tuple[float, dict] | None = None
    for rem in completed:
        name = rem.get("name") or ""
        rt = _task_tokens(name)
        if not rt:
            continue
        j = len(loop_tokens & rt) / len(loop_tokens | rt)
        if j < threshold:
            continue
        if best is None or j > best[0]:
            best = (j, rem)
    return best[1] if best else None


def _render_morning_structured_prompt(date_label: str, ev: dict) -> str:
    """Compact prompt — evidence only, asks for tight JSON. LLM ya NO
    genera el esqueleto ni la sección 📅 (el código la arma).
    """
    parts = [
        f"Sos asistente personal. Generás contenido del morning brief para el {date_label}, "
        "en 1ra persona, español rioplatense, tono calmo y directo.",
        "",
        "EVIDENCIA REAL del vault (nada fuera de acá):",
        "",
    ]
    if ev.get("recent_notes"):
        parts.append(f"Notas modificadas ayer ({len(ev['recent_notes'])}):")
        for r in ev["recent_notes"][:12]:
            parts.append(f"- [[{r['title']}]] ({r['path']}): {r['snippet'][:180]}")
    if ev.get("inbox_pending"):
        parts.append(f"\n00-Inbox ({len(ev['inbox_pending'])} sin triar):")
        for r in ev["inbox_pending"][:10]:
            parts.append(f"- [[{r['title']}]]: {r['snippet'][:140]}")
    if ev.get("todos"):
        parts.append(f"\nNotas con todo/due ({len(ev['todos'])}):")
        for r in ev["todos"][:10]:
            bits = []
            if r.get("due"): bits.append(f"due={r['due']}")
            if r.get("todo"): bits.append("todo=Y")
            parts.append(f"- [[{r['title']}]] ({r['path']}) {', '.join(bits)}")
    if ev.get("new_contradictions"):
        parts.append(f"\nContradicciones nuevas ({len(ev['new_contradictions'])}):")
        for c in ev["new_contradictions"][:5]:
            tgt = ", ".join(t["path"] for t in c["targets"][:3])
            parts.append(f"- {c['subject_path']} ↔ {tgt}")
    if ev.get("low_conf_queries"):
        parts.append(f"\nQueries sin respuesta buena ({len(ev['low_conf_queries'])}):")
        for q in ev["low_conf_queries"][:6]:
            parts.append(f"- \"{q['q']}\" (score {q['top_score']:+.2f})")
    if ev.get("recent_queries"):
        parts.append(f"\nQueries recientes del RAG ({len(ev['recent_queries'])}):")
        for q in ev["recent_queries"][:6]:
            parts.append(f"- \"{q['q']}\"")
    if ev.get("mail_unread"):
        parts.append(f"\nMail no leído ({len(ev['mail_unread'])}):")
        for m in ev["mail_unread"][:10]:
            prefix = "**VIP** · " if m.get("is_vip") else ""
            parts.append(f"- {prefix}{m.get('subject', '')} — {m.get('sender', '')}")
            preview = (m.get("body_preview") or "").strip()
            if preview:
                parts.append(f"    _{preview}_")
    gm = ev.get("gmail") or {}
    if gm.get("unread_count") or gm.get("starred") or gm.get("awaiting_reply"):
        unread_total = int(gm.get("unread_count") or 0)
        parts.append(
            f"\nGmail — {unread_total} sin leer "
            "(NO re-imprimas, el código arma la sección 📧 Gmail):"
        )
        for m in gm.get("starred") or []:
            parts.append(
                f"- ⭐ {m.get('subject', '')} — {m.get('from', '')}: "
                f"{m.get('snippet', '')}"
            )
        for m in gm.get("awaiting_reply") or []:
            days = m.get("days_old") or 0
            parts.append(
                f"- ⏳ esperando mi respuesta hace {days}d: "
                f"{m.get('subject', '')} — {m.get('from', '')}: "
                f"{m.get('snippet', '')}"
            )
    dv = ev.get("drive") or {}
    dv_files = dv.get("files") or []
    if dv_files:
        parts.append(
            f"\nDrive — {len(dv_files)} archivo(s) modificados últimos "
            f"{dv.get('window_days', 5)}d "
            "(NO re-imprimas, el código arma la sección 📁 Drive):"
        )
        for f in dv_files[:5]:
            parts.append(
                f"- {f.get('mime_label','archivo')}: {f.get('name','')} "
                f"(hace {f.get('days_ago',0)}d)"
            )
    bm_used = ev.get("bookmarks_used") or []
    if bm_used:
        parts.append(
            f"\nBookmarks usados últimas 48h — {len(bm_used)} "
            "(NO re-imprimas, el código arma la sección 🔖 Bookmarks):"
        )
        for b in bm_used[:5]:
            parts.append(
                f"- {b.get('name','')} ({b.get('folder','')})"
            )
    va = ev.get("vault_activity") or {}
    active_vaults = {k: v for k, v in va.items() if v}
    if active_vaults:
        parts.append(
            "\nActividad por vault últimas 48h — personal/laboral separados "
            "(NO re-imprimas, el código arma la sección 📝 Vaults):"
        )
        for name in sorted(active_vaults.keys()):
            items = active_vaults[name]
            titles = ", ".join((n.get("title") or "")[:40] for n in items[:3])
            parts.append(f"- {name} ({len(items)} notas): {titles}")
    # Agenda (calendar/reminders/weather) ya la arma el código — igual la
    # mencionamos como contexto para que el LLM pueda cruzar referencias
    # ("hoy tenés reunión con X → priorizá la nota [[X]]").
    if ev.get("calendar_today") or ev.get("reminders_due") or ev.get("weather_rain"):
        parts.append("\nAgenda (para cruzar con el foco; NO la re-imprimas):")
        for e in (ev.get("calendar_today") or [])[:8]:
            parts.append(f"- evento: {e.get('title')} ({e.get('start')})")
        for r in (ev.get("reminders_due") or [])[:8]:
            parts.append(f"- reminder: {r.get('name')} ({r.get('bucket', '')})")
        if ev.get("weather_rain"):
            parts.append(f"- clima: {ev['weather_rain'].get('summary', 'lluvia')}")
    # Contexto automatizado — NO pedir al LLM que re-imprima, el código arma
    # la sección ⚙️ determinísticamente. Solo sirve para que pueda cruzar
    # referencias (ej: "ambient linkeó X → priorizá la [[nota]] asociada").
    act = ev.get("system_activity") or {}
    if any(int(act.get(k) or 0) > 0 for k in (
        "ambient_events", "ambient_wikilinks", "filing_moves", "tune_runs",
    )):
        parts.append(
            "\nSistema automatizado últimas 24h (NO la re-imprimas, el código la renderiza):"
        )
        parts.append(
            f"- ambient aplicó {int(act.get('ambient_wikilinks') or 0)} wikilinks, "
            f"archiver movió {int(act.get('archive_moves') or 0)} notas, "
            f"rag tune corrió {int(act.get('tune_runs') or 0)} veces"
        )
    parts.extend([
        "",
        "DEVOLVÉ SOLO este JSON (sin ``` ni prosa extra):",
        '{"yesterday": "...", "focus": [...], "pending": [...], "attention": [...]}',
        "",
        "Reglas estrictas:",
        "- yesterday: 1 oración 15-30 palabras. Si no hay evidencia de ayer → string vacío.",
        "- focus: 2-4 bullets con [[wikilink]] a la nota relevante. Priorizá lo urgente. "
        "Si realmente no hay nada crítico → array vacío.",
        "- pending: SOLO bullets que vengan de 00-Inbox sin triar, todos/due en notas, "
        "mail no leído, WhatsApp no leído o WA programado. NO inventes 'revisar Drive', "
        "'mirar bookmarks', 'actualizar Vaults' — Drive/Bookmarks/Vaults/Pantalla ya tienen "
        "su propia sección, no son pendientes per se. Max 5. Vacío si no hay.",
        "- attention: SOLO contradicciones nuevas + low-conf queries reales del día. "
        "NO inventes 'gaps' genéricos ni 'falta programar X' si no hay evidencia explícita. "
        "Max 4. Vacío si no hay.",
        "- NUNCA inventes placeholders como '(nada)' ni repitas las secciones determinísticas "
        "(Agenda, Gmail, Drive, Bookmarks, Vaults, Pantalla, Sistema).",
    ])
    return "\n".join(parts)


def _generate_morning_json(prompt: str) -> dict | None:
    """One LLM call, JSON-formatted output. Returns the parsed dict or None
    if parse fails (caller falls back to the legacy text-based path).
    """
    try:
        resp = _chat_capped_client().chat(
            model=resolve_chat_model(),
            messages=[{"role": "user", "content": prompt}],
            options=CHAT_OPTIONS,
            keep_alive=chat_keep_alive(),
            format="json",
        )
        raw = (resp.message.content or "").strip()
        if not raw:
            return None
        data = json.loads(raw)
        if not isinstance(data, dict):
            return None
        # 2026-04-29: aplicar filter PT→ES recursivamente a todos los
        # strings del dict — el morning brief json se manda a WhatsApp y
        # se guarda en `00-Inbox/`. Sin filter, leaks pt en cualquier
        # field del JSON ("celebrate", "gaps", etc.) llegan al user.
        from rag.iberian_leak_filter import replace_iberian_leaks

        def _filter_strings(v):
            if isinstance(v, str):
                return replace_iberian_leaks(v)
            if isinstance(v, dict):
                return {k: _filter_strings(x) for k, x in v.items()}
            if isinstance(v, list):
                return [_filter_strings(x) for x in v]
            return v
        return _filter_strings(data)
    except Exception:
        return None


def _yesterday_evening_link(target: datetime, vault: Path) -> str:
    """Return a markdown footer linking to yesterday's evening review if it
    exists. Closes the daily loop — the morning brief picks up where the
    previous `rag today` left off.
    """
    yesterday = target - timedelta(days=1)
    rel = f"04-Archive/99-obsidian-system/99-AI/reviews/{yesterday.strftime('%Y-%m-%d')}-evening.md"
    if not (vault / rel).is_file():
        return ""
    title = f"{yesterday.strftime('%Y-%m-%d')}-evening"
    return f"\n\n---\n_ayer cerraste con:_ [[{title}]]"


_MORNING_PLACEHOLDER_RE = re.compile(
    r"^\s*\W*\s*("
    r"nada\s+qued|no\s+hubo|no\s+hay\b|no\s+habia|"
    r"ninguna|ningun\b|sin\s+novedades?|sin\s+actividad|sin\s+nada|"
    r"no\s+se\s+registr|no\s+se\s+detect|no\s+aparec|"
    r"no\s+hay\s+datos?\s+suficientes|no\s+aplica|"
    r"todo\s+(quedo|esta)\s+(en\s+orden|al\s+dia|categorizado)"
    r")",
    re.IGNORECASE,
)


def _is_placeholder_bullet(text: str) -> bool:
    """True si el bullet del LLM es solo prosa de relleno tipo 'Nada quedó
    suelto', 'No hay novedades', 'Ninguna pregunta abierta', etc. Accent-fold
    para que matchee con/sin tildes.
    """
    if not text:
        return True
    folded = unicodedata.normalize("NFD", text)
    folded = "".join(c for c in folded if not unicodedata.combining(c))
    return bool(_MORNING_PLACEHOLDER_RE.match(folded))


def _sanitize_morning_parts(parts: dict, ev: dict) -> dict:
    """Anti-alucinación post-LLM: descarta bullets que no tienen sustento en
    la evidencia real. El LLM tiende a inventar contradicciones, low-conf
    queries y "gaps" aun cuando se le dice explícitamente "vacío si no hay" —
    este filtro aplica esa regla en código.

    Reglas:
      - `attention` se vacía si no hay contradicciones nuevas NI low-conf
        queries. (Si el LLM solo detectó "gaps" generic-de-cualquier-cosa
        y no hay evidencia dura, no vale la pena imprimirlo.)
      - `pending` se vacía si no hay inbox-pending NI todos NI mail unread
        NI WA unread NI WA scheduled today NI recent_notes (post-filtro).
      - `focus` filtra wikilinks que apuntan a paths daemon-generated. Si
        después del filtro queda 0, se vacía.
      - `yesterday` se vacía si no hay recent_notes Y no hay evidencia
        cruzada (calendar/reminders/gmail/recent_queries). Sin material,
        el LLM no puede más que inventar.
      - Cualquier bullet de `focus`/`pending`/`attention` que sea solo
        placeholder ("Nada quedó suelto", "Ninguna pregunta", etc.) se
        descarta. Si el LLM puebla la lista entera con placeholders, la
        lista queda vacía y la sección desaparece.

    No muta el dict de input. Devuelve uno nuevo con las mismas claves.
    """
    if not isinstance(parts, dict):
        return parts
    out = dict(parts)
    # Pre-filter: drop placeholder bullets en focus/pending/attention.
    # Si el LLM contestó "Ninguna pregunta abierta" como bullet, no es
    # un bullet — es relleno y debe desaparecer (ni el header se muestra
    # si la lista queda vacía).
    for key in ("focus", "pending", "attention"):
        v = out.get(key)
        if isinstance(v, list):
            out[key] = [
                b for b in v
                if isinstance(b, str) and b.strip()
                and not _is_placeholder_bullet(b)
            ]
    if out.get("yesterday") and isinstance(out["yesterday"], str):
        if _is_placeholder_bullet(out["yesterday"]):
            out["yesterday"] = ""

    has_contrad = bool(ev.get("new_contradictions"))
    has_low_conf = bool(ev.get("low_conf_queries"))
    if not has_contrad and not has_low_conf:
        out["attention"] = []

    has_inbox = bool(ev.get("inbox_pending"))
    has_todos = bool(ev.get("todos"))
    has_mail = bool(ev.get("mail_unread"))
    gm = ev.get("gmail") or {}
    has_gmail = bool(
        gm.get("awaiting_reply") or gm.get("starred") or gm.get("unread_count")
    )
    has_wa_unread = bool(ev.get("whatsapp_unread"))
    has_wa_sched = bool(ev.get("wa_scheduled_today"))
    has_recent = bool(ev.get("recent_notes"))
    if not (
        has_inbox or has_todos or has_mail or has_gmail
        or has_wa_unread or has_wa_sched or has_recent
    ):
        out["pending"] = []
    else:
        # Bullet-level filter — el LLM tiende a re-imprimir Drive/Bookmarks
        # como "pendientes" aun cuando se le dice explícitamente que no.
        # Si un bullet solo menciona el nombre de un archivo Drive o el
        # nombre de un bookmark (y nada más), lo descartamos: esa info ya
        # está en su sección determinística. Leemos de `out` (no `parts`)
        # para encadenar correctamente con el filter de placeholders.
        pending = out.get("pending") or []
        if isinstance(pending, list) and pending:
            drive_names = {
                _normalize_task_text(f.get("name") or "")
                for f in (ev.get("drive") or {}).get("files") or []
                if (f.get("name") or "").strip()
            }
            bookmark_names = {
                _normalize_task_text(b.get("name") or "")
                for b in ev.get("bookmarks_used") or []
                if (b.get("name") or "").strip()
            }
            noise_keywords = drive_names | bookmark_names
            cleaned: list[str] = []
            for b in pending:
                if not isinstance(b, str) or not b.strip():
                    continue
                btxt = _normalize_task_text(b)
                # Drop si el bullet contiene un nombre Drive/Bookmark.
                # Threshold: el nombre tiene que tener ≥3 chars para que
                # cuente (evita falsos positivos con palabras genéricas).
                if any(
                    name and len(name) >= 3 and name in btxt
                    for name in noise_keywords
                ):
                    continue
                cleaned.append(b)
            out["pending"] = cleaned

    focus = out.get("focus") or []
    if isinstance(focus, list) and focus:
        wl_re = re.compile(r"\[\[([^\]|#]+)")
        # Map title → known real path from filtered evidence (recent_notes
        # already excludes daemon paths). If a [[wikilink]] in focus matches
        # a daemon-generated title we know about, drop the bullet.
        daemon_titles: set[str] = set()
        for r in ev.get("recent_notes_unfiltered") or []:
            if _is_daemon_generated_path(r.get("path", "")):
                t = (r.get("title") or "").strip()
                if t:
                    daemon_titles.add(t)
        cleaned: list[str] = []
        for b in focus:
            if not isinstance(b, str):
                continue
            m = wl_re.search(b)
            if m:
                title = m.group(1).strip()
                # Drop YYYY-MM-DD, YYYY-WNN, YYYY-MM, _index — patterns that
                # are *always* daemon-generated regardless of where they live.
                if (
                    re.match(r"^\d{4}-\d{2}-\d{2}$", title)
                    or re.match(r"^\d{4}-W\d{1,2}$", title)
                    or re.match(r"^\d{4}-\d{2}$", title)
                    or title == "_index"
                    or title in daemon_titles
                ):
                    continue
            cleaned.append(b)
        out["focus"] = cleaned

    yesterday = (parts.get("yesterday") or "").strip()
    if yesterday:
        has_calendar = bool(ev.get("calendar_today"))
        has_reminders = bool(ev.get("reminders_due"))
        has_recent_q = bool(ev.get("recent_queries"))
        if not (
            has_recent or has_calendar or has_reminders or has_gmail
            or has_recent_q or has_inbox or has_todos
        ):
            out["yesterday"] = ""

    return out


def _assemble_morning_brief(
    date_label: str, agenda_md: str, parts: dict, continuity: str,
    system_md: str = "", gmail_md: str = "", drive_md: str = "",
    bookmarks_md: str = "", vaults_md: str = "", screentime_md: str = "",
) -> str:
    """Put the brief together skipping empty sections. Headers are fixed;
    content comes from `parts` (LLM JSON), `agenda_md` + `system_md` +
    `gmail_md` + `drive_md` + `bookmarks_md` + `vaults_md` (deterministic
    code-owned blocks).

    Layout: `📬 Ayer → 📅 Agenda → 📧 Gmail → 📁 Drive → 🔖 Bookmarks →
    📝 Vaults → ⚙️ Sistema → 🎯 Foco → 🗂 Pendientes → ⚠ Atender`. Empty
    blocks drop out. All `*_md` args default to "" so legacy callers
    without the new sections still work.
    """
    sections: list[str] = []
    y = (parts.get("yesterday") or "").strip()
    if y:
        sections.append(f"## 📬 Ayer en una línea\n{y}")
    if agenda_md:
        sections.append(agenda_md)
    if gmail_md:
        sections.append(gmail_md)
    if drive_md:
        sections.append(drive_md)
    if bookmarks_md:
        sections.append(bookmarks_md)
    if vaults_md:
        sections.append(vaults_md)
    if screentime_md:
        sections.append(screentime_md)
    if system_md:
        sections.append(system_md)
    focus = parts.get("focus") or []
    if isinstance(focus, list) and focus:
        bullets = "\n".join(f"- {str(b).strip()}" for b in focus if str(b).strip())
        if bullets:
            sections.append(f"## 🎯 Foco sugerido para hoy\n{bullets}")
    pending = parts.get("pending") or []
    if isinstance(pending, list) and pending:
        bullets = "\n".join(f"- {str(b).strip()}" for b in pending if str(b).strip())
        if bullets:
            sections.append(f"## 🗂 Pendientes que asoman\n{bullets}")
    attention = parts.get("attention") or []
    if isinstance(attention, list) and attention:
        bullets = "\n".join(f"- {str(b).strip()}" for b in attention if str(b).strip())
        if bullets:
            sections.append(f"## ⚠ Atender\n{bullets}")
    return f"# Morning brief — {date_label}\n\n" + "\n\n".join(sections) + continuity


@cli.command()
@click.option("--dry-run", is_flag=True,
              help="Imprimir el brief sin escribir el archivo")
@click.option("--date", "date_opt", default=None,
              help="Fecha objetivo YYYY-MM-DD (default: hoy)")
@click.option("--lookback-hours", default=36, show_default=True,
              help="Ventana de evidencia hacia atrás")
@click.option("--voice", "voice_flag", is_flag=True,
              help="Generar audio (TTS via macOS `say`) y mandarlo junto al texto al WhatsApp ambient")
def morning(dry_run: bool, date_opt: str | None, lookback_hours: int,
            voice_flag: bool):
    """Brief matutino: qué pasó ayer + qué enfocar hoy.

    Consume notas modificadas, 00-Inbox/ pending, todo/due frontmatter,
    contradicciones index-time del sidecar y queries low-confidence.
    command-r arma un brief de 120-280 palabras. Escribe a
    `04-Archive/99-obsidian-system/99-AI/reviews/YYYY-MM-DD.md` (auto-indexado) salvo --dry-run.

    `--voice` (o env ``RAG_MORNING_VOICE=1``, configurable desde el plist):
    además del texto, sintetiza el brief a OGG/Opus via macOS ``say`` (voz
    ``TTS_VOICE`` o ``Mónica`` default) y lo manda como voice note antes
    del texto al WhatsApp ambient. Si TTS falla, sale solo el texto
    (fallback transparente). Audio cacheado en
    ``~/.local/share/obsidian-rag/voice_briefs/<date>-morning.ogg``.
    """
    _diff_brief_signal()  # compare yesterday's brief vs on-disk state → behavior events
    if date_opt:
        try:
            target = datetime.fromisoformat(date_opt)
        except ValueError:
            console.print(f"[red]Fecha inválida: {date_opt}[/red]")
            return
    else:
        target = datetime.now()

    ev = _collect_morning_evidence(
        target, VAULT_PATH, LOG_PATH, CONTRADICTION_LOG_PATH,
        lookback_hours=lookback_hours,
    )
    total = (
        len(ev["recent_notes"]) + len(ev["inbox_pending"])
        + len(ev["todos"]) + len(ev["new_contradictions"])
        + len(ev["low_conf_queries"])
        + len(ev.get("calendar_today", []))
        + len(ev.get("reminders_due", []))
        + len(ev.get("mail_unread", []))
        + len(ev.get("whatsapp_unread", []))
        + len(ev.get("recent_queries", []))
        + (1 if ev.get("weather_rain") else 0)
        + len((ev.get("gmail") or {}).get("starred") or [])
        + len((ev.get("gmail") or {}).get("awaiting_reply") or [])
        + (1 if (ev.get("gmail") or {}).get("unread_count") else 0)
        + len((ev.get("drive") or {}).get("files") or [])
    )
    if total == 0:
        console.print(
            "[yellow]Mañana en blanco:[/yellow] sin notas modificadas, "
            "inbox vacío, 0 todos, 0 contradicciones, "
            "calendar/reminders/mail/wa/queries vacíos, sin lluvia."
        )
        return

    console.print(
        f"[dim]Evidencia:[/dim] {len(ev['recent_notes'])} recientes · "
        f"{len(ev['inbox_pending'])} inbox · {len(ev['todos'])} todos · "
        f"{len(ev['new_contradictions'])} contrad · "
        f"{len(ev['low_conf_queries'])} low-conf · "
        f"{len(ev.get('calendar_today', []))} cal · "
        f"{len(ev.get('reminders_due', []))} rem · "
        f"{len(ev.get('mail_unread', []))} mail · "
        f"{len(ev.get('whatsapp_unread', []))} wa · "
        f"{len(ev.get('recent_queries', []))} queries · "
        f"{(ev.get('gmail') or {}).get('unread_count', 0)} gmail-unread · "
        f"{len((ev.get('gmail') or {}).get('awaiting_reply') or [])} await-reply · "
        f"{len((ev.get('drive') or {}).get('files') or [])} drive-5d · "
        f"{len(ev.get('bookmarks_used') or [])} bookmarks-48h · "
        f"{sum(len(v) for v in (ev.get('vault_activity') or {}).values())} vault-48h"
        + (" · 🌧" if ev.get("weather_rain") else "")
    )

    date_label = target.strftime("%Y-%m-%d")
    # Template-first: Python owns the skeleton + agenda; LLM returns JSON
    # with only the textual fields (yesterday/focus/pending/attention).
    # Fallback to the legacy monolithic prompt if JSON parse fails.
    agenda_md = _render_morning_agenda_section(ev)
    system_md = _render_system_activity_section(ev.get("system_activity") or {})
    gmail_md = _render_morning_gmail_section(ev)
    drive_md = _render_morning_drive_section(ev)
    bookmarks_md = _render_morning_bookmarks_section(ev)
    vaults_md = _render_morning_vaults_section(ev)
    screentime_md = _render_screentime_section(ev.get("screentime") or {})
    structured_prompt = _render_morning_structured_prompt(date_label, ev)
    with console.status("[dim]Armando brief…[/dim]", spinner="dots"):
        parts = _generate_morning_json(structured_prompt)
    continuity = _yesterday_evening_link(target, VAULT_PATH)
    if parts is not None:
        parts = _sanitize_morning_parts(parts, ev)
        brief_body = _assemble_morning_brief(
            date_label, agenda_md, parts, continuity,
            system_md=system_md, gmail_md=gmail_md, drive_md=drive_md,
            bookmarks_md=bookmarks_md, vaults_md=vaults_md,
            screentime_md=screentime_md,
        )
    else:
        # Legacy fallback — one-shot text generation with the old monolithic
        # prompt. Not ideal but keeps morning working if the JSON path fails.
        prompt = _render_morning_prompt(date_label, ev)
        narrative = _generate_morning_narrative(prompt)
        if not narrative:
            console.print("[red]Modelo devolvió respuesta vacía.[/red]")
            return
        brief_body = f"# Morning brief — {date_label}\n\n{narrative}{continuity}"

    now_iso = datetime.now().isoformat(timespec="seconds")
    fm_lines = [
        "---",
        f"created: '{now_iso}'",
        "type: morning-brief",
        "tags:",
        "- review",
        "- morning-brief",
        f"date: '{date_label}'",
        "---",
    ]
    body = "\n".join(fm_lines) + "\n\n" + brief_body + "\n"

    if dry_run:
        console.rule(f"[bold]Morning brief {date_label} (dry-run)[/bold]")
        console.print(body, markup=False, highlight=False)
        return

    path = VAULT_PATH / MORNING_FOLDER / f"{date_label}.md"
    path.parent.mkdir(parents=True, exist_ok=True)
    # Audit 2026-04-26 (BUG #14): pre-fix creaba `YYYY-MM-DD (HHMMSS).md`
    # si el archivo ya existía → 2 runs el mismo día (re-arme manual,
    # retry post error, etc.) generaban briefs duplicados, y el brief
    # diff signal comparaba contra el archivo viejo. Idempotencia
    # correcta: sobrescribir.
    path.write_text(body, encoding="utf-8")
    try:
        _index_single_file(get_db(), path, skip_contradict=True)
    except Exception:
        pass
    rel = path.relative_to(VAULT_PATH)
    console.print(f"[green]✓ Brief guardado:[/green] [bold cyan]{rel}[/bold cyan]")
    # Record citations for tomorrow's diff signal.
    try:
        wikilinks = _extract_wikilinks_from_markdown(brief_body)
        c = _load_corpus(get_db())
        cited_paths, _ambig = _resolve_wikilinks_to_paths(
            wikilinks, c["title_to_paths"], VAULT_PATH,
        )
        by_section = _citations_by_section(
            brief_body, c["title_to_paths"], VAULT_PATH,
        )
        record_brief_written("morning", rel, cited_paths, by_section)
    except Exception:
        pass
    # Push to WhatsApp if ambient is enabled — landing the brief in the chat
    # at 7:00 means the user wakes up to the brief instead of having to open
    # Obsidian to find it.
    voice_enabled = voice_flag or os.environ.get("RAG_MORNING_VOICE", "").strip().lower() in ("1", "true", "yes")
    audio_path: Path | None = None
    if voice_enabled:
        try:
            from rag.voice_brief import synthesize_brief_audio  # noqa: PLC0415
            audio_path = synthesize_brief_audio(
                brief_body, kind="morning", date_str=date_label,
            )
            if audio_path:
                console.print(
                    f"[dim]→ audio:[/dim] [bold]{audio_path}[/bold] "
                    f"[dim]({audio_path.stat().st_size / 1024:.0f} KB)[/dim]"
                )
            else:
                console.print("[dim]→ audio: TTS no disponible o falló — text-only[/dim]")
        except Exception as exc:
            _silent_log("morning_voice_brief", exc)
            audio_path = None
    if _brief_push_to_whatsapp(
        f"Morning {date_label}", str(rel), brief_body,
        audio_path=audio_path,
    ):
        console.print("[dim]→ enviado a WhatsApp[/dim]")


# ── rag voice-brief — generar audio de un brief manual ────────────────────
# Anticipatory Phase 2.C (2026-04-29). El comando manual permite:
#   - regenerar el audio de un brief ya escrito (ej. el listener perdió
#     el push original y querés re-mandarlo)
#   - probar TTS con un texto custom sin escribir un brief al vault
#   - debug del pipeline say → ffmpeg → OGG sin ejecutar morning/today
@cli.group(name="voice-brief", invoke_without_command=True)
@click.pass_context
def voice_brief_grp(ctx: click.Context):
    """Generar / mandar el audio TTS de un brief.

    Subcomandos:
      rag voice-brief generate --date YYYY-MM-DD            # del brief en disco
      rag voice-brief generate --text "..."                 # texto custom
      rag voice-brief generate --date 2026-04-29 --apply    # también lo manda al WhatsApp
    """
    if ctx.invoked_subcommand is None:
        click.echo(ctx.get_help())


@voice_brief_grp.command("generate")
@click.option("--date", "date_opt", default=None,
              help="Fecha del brief en disco (YYYY-MM-DD). Si se omite + --text, default=hoy.")
@click.option("--text", "text_override", default=None,
              help="Texto custom a sintetizar (en lugar de leer un brief del vault).")
@click.option("--kind", default="morning", show_default=True,
              type=click.Choice(["morning", "evening", "digest"]),
              help="Tipo del brief — afecta el filename del audio + el path del brief.")
@click.option("--apply", "apply_flag", is_flag=True,
              help="Después de generar, mandar el audio al WhatsApp ambient (jid de _ambient_config).")
@click.option("--voice", "voice_override", default=None,
              help="Voz override (default: env TTS_VOICE → Mónica).")
def voice_brief_generate(date_opt: str | None, text_override: str | None,
                         kind: str, apply_flag: bool,
                         voice_override: str | None):
    """Genera el audio del brief y opcionalmente lo manda al WhatsApp.

    Modos:

    1. ``--text "..."`` — sintetiza el texto literal pasado por flag.
       Ideal para testing: ``rag voice-brief generate --text "hola mundo"``.

    2. ``--date YYYY-MM-DD`` (sin ``--text``) — busca el brief en disco
       (``04-Archive/99-obsidian-system/99-AI/reviews/<date>.md`` para
       morning, ``-evening.md`` para evening, etc.) y lo sintetiza.

    Por default solo guarda el ``.ogg`` en el cache. Con ``--apply``
    también lo manda como voice note al WhatsApp ambient (mismo jid que
    el morning push). El texto del brief NO se reenvía — este comando
    asume que ya salió por su daemon habitual; sirve para complementar
    con audio cuando el text-only ya está en el chat.
    """
    from rag.voice_brief import (  # noqa: PLC0415
        synthesize_brief_audio, send_audio_to_whatsapp,
    )

    if text_override is None and date_opt is None:
        # Default: ``--text`` exige --date solo si no hay text. Si no
        # pasaron ninguno, asumimos --date=hoy (intuitive para
        # "regeneráme el de hoy").
        date_opt = datetime.now().strftime("%Y-%m-%d")

    if text_override is not None:
        text = text_override
        date_label = date_opt or datetime.now().strftime("%Y-%m-%d")
    else:
        # Read from vault. Naming sigue el convention de morning/today/digest.
        if kind == "morning":
            brief_filename = f"{date_opt}.md"
        else:
            brief_filename = f"{date_opt}-{kind}.md"
        brief_path = VAULT_PATH / MORNING_FOLDER / brief_filename
        if not brief_path.is_file():
            console.print(
                f"[red]Brief no encontrado:[/red] {brief_path.relative_to(VAULT_PATH)}"
            )
            raise click.exceptions.Exit(1)
        try:
            text = brief_path.read_text(encoding="utf-8")
        except OSError as exc:
            console.print(f"[red]Error leyendo brief:[/red] {exc}")
            raise click.exceptions.Exit(1)
        date_label = date_opt

    audio_path = synthesize_brief_audio(
        text, kind=kind, date_str=date_label, voice=voice_override,
    )
    if audio_path is None:
        console.print(
            "[yellow]Audio no generado.[/yellow] TTS no disponible "
            "(¿`say` instalado? ¿`ffmpeg`?) o el archivo superó 5MB."
        )
        raise click.exceptions.Exit(1)
    size_kb = audio_path.stat().st_size / 1024
    console.print(
        f"[green]✓ Audio:[/green] [bold]{audio_path}[/bold] "
        f"[dim]({size_kb:.0f} KB)[/dim]"
    )

    if apply_flag:
        cfg = _ambient_config()
        if cfg is None:
            console.print(
                "[yellow]Sin ambient config — no se manda.[/yellow] "
                "Habilitalo desde el bot de WhatsApp con /enable_ambient."
            )
            return
        ok = send_audio_to_whatsapp(cfg["jid"], audio_path)
        if ok:
            console.print(f"[green]✓ Enviado a[/green] {cfg['jid']}")
        else:
            console.print(
                "[red]Send failed.[/red] Bridge down? "
                f"({AMBIENT_WHATSAPP_BRIDGE_URL})"
            )


# ── EVENING BRIEF (rag today) ────────────────────────────────────────────────
# End-of-day closure: mirrors morning's structure but looks BACK at the day
# that just closed. Evidence window is [today 00:00 local, now]. Writes to
# 04-Archive/99-obsidian-system/99-AI/reviews/YYYY-MM-DD-evening.md so it doesn't collide with morning's file.


def _today_window(now: datetime) -> tuple[datetime, datetime]:
    start = now.replace(hour=0, minute=0, second=0, microsecond=0)
    return start, now


def _collect_today_evidence(
    now: datetime,
    vault: Path,
    query_log: Path,
    contradiction_log: Path,
) -> dict:
    """Gather signals for the day that just closed. Window: today 00:00 → now
    in local time. Mirrors `_collect_morning_evidence` but:
      - `recent_notes` are notes created/modified today (mtime in window)
      - `inbox_today` are Inbox notes whose mtime lands in the window (the
        ones captured during the day — might still need folder/tags)
      - `low_conf_queries` scan only today's queries
    """
    start, end = _today_window(now)

    recent: list[dict] = []
    inbox_today: list[dict] = []
    todos: list[dict] = []
    if vault.is_dir():
        for p in vault.rglob("*.md"):
            try:
                rel = str(p.relative_to(vault))
            except ValueError:
                continue
            if is_excluded(rel):
                continue
            try:
                mtime = datetime.fromtimestamp(p.stat().st_mtime)
            except OSError:
                continue
            try:
                raw = p.read_text(encoding="utf-8", errors="ignore")
            except OSError:
                continue
            fm = parse_frontmatter(raw)
            title = p.stem
            in_window = start <= mtime < end
            if in_window and rel.startswith(f"{_CAPTURE_FOLDER}/"):
                tags = _normalize_fm_tags(fm)
                inbox_today.append({
                    "path": rel, "title": title,
                    "modified": mtime.isoformat(timespec="seconds"),
                    "snippet": clean_md(raw)[:180].strip(),
                    "tags": tags,
                })
            if (
                in_window
                and not rel.startswith(f"{MORNING_FOLDER}/")
                and not rel.startswith(f"{_CAPTURE_FOLDER}/")
                # Excluir paths daemon-generated (calendar/screentime/github/
                # gmail/chrome/youtube ingesters + memory auto-saves del
                # agente + finance ETL). Sin esto, "Notas tocadas hoy"
                # se llenaba de output automático y el LLM intentaba
                # narrarlo como actividad del user. Mismo filtro que
                # `_collect_morning_evidence` (línea ~41028) y
                # `_fetch_vault_activity`. Bug observado 2026-04-30:
                # 33/60 recent_notes eran auto-saves a 99-AI/memory/, 19/60
                # eran finance ETL, 0/60 eran notas reales del user.
                and not _is_daemon_generated_path(rel)
            ):
                recent.append({
                    "path": rel, "title": title,
                    "modified": mtime.isoformat(timespec="seconds"),
                    "snippet": clean_md(raw)[:220].strip(),
                })
            if in_window:
                t = fm.get("todo")
                d = fm.get("due")
                if t or d:
                    todos.append({
                        "path": rel, "title": title,
                        "todo": t if t else None,
                        "due": str(d) if d else None,
                    })

    new_contrad: list[dict] = []
    if contradiction_log.is_file():
        try:
            lines = contradiction_log.read_text(encoding="utf-8").splitlines()
        except OSError:
            lines = []
        for line in lines:
            line = line.strip()
            if not line:
                continue
            try:
                e = json.loads(line)
            except Exception:
                continue
            try:
                ts = datetime.fromisoformat(e.get("ts", ""))
            except Exception:
                continue
            if ts < start or ts >= end:
                continue
            if e.get("cmd") != "contradict_index":
                continue
            entries = e.get("contradicts") or []
            if not entries:
                continue
            new_contrad.append({
                "subject_path": e.get("subject_path", ""),
                "targets": [
                    {"path": c.get("path", ""), "why": c.get("why", "")}
                    for c in entries if isinstance(c, dict)
                ],
            })

    low_conf: list[dict] = []
    if query_log.is_file():
        try:
            lines = query_log.read_text(encoding="utf-8").splitlines()
        except OSError:
            lines = []
        for line in lines:
            line = line.strip()
            if not line:
                continue
            try:
                e = json.loads(line)
            except Exception:
                continue
            try:
                ts = datetime.fromisoformat(e.get("ts", ""))
            except Exception:
                continue
            if ts < start or ts >= end:
                continue
            if e.get("cmd") != "query":
                continue
            score = e.get("top_score")
            if isinstance(score, (int, float)) and score <= CONFIDENCE_RERANK_MIN:
                q = (e.get("q") or "").strip()
                if q:
                    low_conf.append({"q": q, "top_score": float(score)})

    recent.sort(key=lambda r: r["modified"], reverse=True)
    inbox_today.sort(key=lambda r: r["modified"], reverse=True)

    # WhatsApp pending de hoy. El today brief corre típicamente a las
    # 22hs — a esta hora los pendings programados para hoy deberían
    # estar todos en `sent`/`sent_late`. Si queda alguno en `pending`,
    # es señal de problema (worker caído, bridge inalcanzable). El
    # render del prompt lo destaca como warning para que el user lo
    # note antes de cerrar el día.
    try:
        from rag import wa_scheduled as _wa_sched  # noqa: PLC0415
        wa_today_pending = _wa_sched.list_today_pending()
    except Exception:
        wa_today_pending = []

    return {
        "recent_notes": recent,
        "inbox_today": inbox_today,
        "todos": todos,
        "new_contradictions": new_contrad,
        "low_conf_queries": low_conf,
        "wa_scheduled_today_pending": wa_today_pending,
    }


def _render_today_prompt(
    date_label: str, ev: dict, extras: dict | None = None,
) -> str:
    extras = extras or {}
    # ¿Tenemos señales cross-source más allá del vault? Si sí, el prompt
    # cambia el énfasis: en lugar de un recap solo del vault, le pedimos
    # al LLM que busque conexiones entre fuentes (gmail × calendar × wa
    # × notas × drive). Esto es lo que diferencia un dump plano de un
    # brief útil — el modelo tiene que agrupar items que aparecen en
    # múltiples fuentes y nombrar el patrón.
    has_cross_source = any(
        extras.get(k) for k in (
            # TODAY-only buckets (corte 00:00 local)
            "gmail_today", "whatsapp_today", "calendar_today", "youtube_today",
            # Rolling windows / stale buckets
            "gmail_unread", "whatsapp_unreplied", "tomorrow_calendar",
            "drive_recent", "youtube_watched", "youtube_recent",
            "chrome_bookmarks",
            "vault_activity", "pagerank_top", "followup_aging",
            "loops_stale", "loops_activo", "reminders_overdue",
            "mail_unread",
        )
    )
    parts = [
        f"# Evening brief — {date_label}",
        "",
        "## REGLAS (leer antes de generar)",
        "",
        "1. **VOZ — 2da persona, tuteo rioplatense**. Hablás AL usuario "
        "sobre SU propio día. Usá: 'recibiste', 'estuviste', 'tocaste', "
        "'tenés', 'mandaste'. NUNCA uses 1ra persona ('recibí', 'estuve', "
        "'me centré', 'trabajé', 'mi'): vos sos el observador, no el "
        "actor. Si te encontrás escribiendo 'yo / me / mi / nos', "
        "cambialo a 'vos / te / tu'.",
        "   Ejemplo MAL: 'Hoy trabajé intensamente en la auditoría'.",
        "   Ejemplo BIEN: 'Hoy trabajaste intenso en la auditoría'.",
        "",
        "2. **SOLO escribí las secciones marcadas como output abajo**. "
        "NO repitas estas reglas, NO escribas 'Entre X y Y palabras', "
        "NO incluyas comentarios meta. Tu respuesta empieza con "
        "`## 🪞 Lo que pasó hoy` y termina con la última línea de la "
        "última sección.",
        "",
        "3. **NO inventes datos**. Citá solo lo que aparece en los "
        "bloques de contexto. Si un dato no está, no lo menciones.",
        "",
        "4. **Dedupe ingester vs TODAY**. Cuando un dato aparezca tanto "
        "en una nota `03-Resources/Gmail/<fecha>.md` como en un bucket "
        "TODAY (`## Gmail — recibido HOY`), priorizá el bucket TODAY "
        "(tiene subject + remitente + snippet). NO cites las notas "
        "ingester como 'tocaste una nota'.",
        "",
        "5. **Tono**: calmo, honesto, factual. Mirás hacia atrás. NO "
        "proyectes la agenda de mañana como tareas; solo semillas "
        "derivadas de lo de hoy.",
        "",
        "6. **NO especulés sobre nombres ni mensajes triviales**. Si una "
        "persona aparece SOLO en WhatsApp con un mensaje corto y trivial "
        "(\"buenos días\", \"gracias\", \"jaja\", \"ok\"), describilo "
        "literal o ignoralo — NO armes hipótesis sobre colaboración "
        "futura, sinergia, intención, relación profesional, ni nada que "
        "no esté en la evidencia. Ejemplos de errores reales que NO "
        "tenés que repetir:",
        "   ❌ \"Guardia Los Molinos envió un mensaje de buenos días, lo "
        "cual podría ser un indicador de una futura colaboración o "
        "sinergia\" (es un guarda del barrio mandando un saludo, NO un "
        "partner — no inventes contexto).",
        "   ❌ \"Llamar a Joana para discutir las tareas pendientes\" "
        "cuando lo único que dice el contexto es \"Joana: Fer me podes "
        "llamar?\" (no hay 'tareas pendientes' en la evidencia — "
        "describí el pedido literal: \"Joana te pidió que la llames\").",
        "   ✅ Si solo tenés UN dato sobre alguien, citá el dato y stop.",
        "   ✅ Si NO podés explicar QUÉ aporta mencionar a alguien, mejor "
        "no mencionarlo.",
        "",
        "7. **NO inventes acciones, decisiones o trabajo que no esté en "
        "la evidencia**. Si la lista de notas tocadas está vacía, NO "
        "digas \"trabajaste en X\" — decí \"hoy no editaste notas en el "
        "vault\". Si no hay queries low-conf, NO inventes preguntas "
        "abiertas. Si no hay calendar de mañana, NO armes agenda. La "
        "evidencia manda — si la sección no tiene material concreto, "
        "OMITILA ENTERA (regla #4 de output).",
        "",
        "## CONTEXTO DEL DÍA",
        "",
    ]
    # ── ENTIDADES CROSS-SOURCE (pre-correlated en Python por
    # `rag.today_correlator`). Personas + temas que YA aparecen en ≥2
    # fuentes — no las tiene que descubrir el LLM. Esta sección va PRIMERA
    # de todo para que el modelo tenga el "esqueleto" del cross-source
    # antes de leer los buckets crudos.
    correlations = extras.get("correlations") or {}
    people = correlations.get("people") or []
    topics = correlations.get("topics") or []
    gaps = correlations.get("gaps") or []
    if people or topics or gaps:
        parts.append("## 🔗 ENTIDADES CROSS-SOURCE (ya correlacionadas):")
        parts.append("(personas, temas y cabos sueltos que aparecen en "
                     "MÚLTIPLES fuentes — úsalos literal en el brief. "
                     "NO inventes correlaciones fuera de esta lista. Si "
                     "esta lista está vacía y vos querés afirmar 'X conecta "
                     "con Y', NO lo hagas.)")
        parts.append("")
        if people:
            parts.append(f"### Personas en ≥2 fuentes ({len(people)}):")
            for p in people[:6]:
                src_tags = ", ".join(
                    f"{a['source']}({a.get('context','')[:50]})"
                    for a in p["appearances"][:4]
                )
                parts.append(f"- **{p['name']}** ({p['sources_count']} "
                             f"fuentes): {src_tags}")
            parts.append("")
        if topics:
            parts.append(f"### Temas en ≥2 fuentes ({len(topics)}):")
            for t in topics[:8]:
                src_list = " + ".join(t["sources"])
                parts.append(
                    f"- **{t['topic']}** aparece en: {src_list}"
                )
            parts.append("")
        if gaps:
            parts.append(f"### ⚠ Cabos sueltos sin slot ({len(gaps)}):")
            for g in gaps[:5]:
                hours = g.get("hours_waiting") or 0
                person = g.get("person") or "?"
                snippet = (g.get("snippet") or "")[:80]
                parts.append(
                    f"- **{person}** te escribió hace {hours:.0f}h por "
                    f"WhatsApp: \"{snippet}\" — y NO aparece en el "
                    f"calendar de mañana. Posible action: agendar tiempo "
                    f"para responderle."
                )
            parts.append("")
    # ── BUCKETS TODAY (corte 00:00 local) — PRIMERO en el prompt
    # porque son la señal más fresca + accionable. El LLM lee primero
    # estos y luego puede mezclarlos con las notas tocadas / capturas.
    gmail_today = extras.get("gmail_today") or []
    if gmail_today:
        parts.append(f"## 📧 Gmail — recibido HOY ({len(gmail_today)} hilos):")
        for m in gmail_today[:8]:
            subj = (m.get("subject") or "(sin asunto)")[:80]
            sender = m.get("from") or m.get("sender") or "?"
            snippet = (m.get("snippet") or "")[:120]
            parts.append(f"- \"{subj}\" — {sender}: {snippet}")
        parts.append("")
    wa_today = extras.get("whatsapp_today") or []
    if wa_today:
        parts.append(
            f"## 💬 WhatsApp — recibido HOY ({len(wa_today)} chats):"
        )
        for w in wa_today[:8]:
            name = w.get("name") or "(sin nombre)"
            count = w.get("count") or 0
            snippet = (w.get("last_snippet") or "")[:90]
            parts.append(f"- {name} ({count} msgs): \"{snippet}\"")
        parts.append("")
    cal_today = extras.get("calendar_today") or []
    if cal_today:
        parts.append(f"## 📅 Calendar — eventos de HOY ({len(cal_today)}):")
        for c in cal_today[:10]:
            title = c.get("title") or "(sin título)"
            start = c.get("start") or ""
            end = c.get("end") or ""
            time_label = (
                f"{start}–{end}" if start and end and start != end
                else (start or end or "")
            )
            parts.append(
                f"- {time_label} — {title}" if time_label else f"- {title}"
            )
        parts.append(
            "(eventos del día — los pasados ya ocurrieron, los futuros del "
            "día están por venir; usá esto para el recap del día)"
        )
        parts.append("")
    yt_today = extras.get("youtube_today") or []
    if yt_today:
        parts.append(f"## 📺 YouTube — visto HOY ({len(yt_today)}):")
        for v in yt_today[:6]:
            title = (v.get("title") or "?")[:90]
            parts.append(f"- {title}")
        parts.append("")
    if ev["recent_notes"]:
        parts.append(f"## Notas tocadas hoy ({len(ev['recent_notes'])}):")
        for r in ev["recent_notes"][:12]:
            parts.append(f"- [[{r['title']}]] ({r['path']}): {r['snippet'][:200]}")
        parts.append("")
    if ev["inbox_today"]:
        parts.append(f"## Capturado hoy en 00-Inbox/ ({len(ev['inbox_today'])}):")
        for r in ev["inbox_today"][:10]:
            tag_hint = " [sin-tags]" if not r.get("tags") else ""
            parts.append(f"- [[{r['title']}]]{tag_hint}: {r['snippet'][:160]}")
        parts.append("")
    if ev["todos"]:
        parts.append(f"## Todos/due tocados hoy ({len(ev['todos'])}):")
        for r in ev["todos"][:10]:
            bits = []
            if r.get("due"):
                bits.append(f"due={r['due']}")
            if r.get("todo"):
                bits.append("todo=Y")
            parts.append(f"- [[{r['title']}]] ({r['path']}) {', '.join(bits)}")
        parts.append("")
    if ev["new_contradictions"]:
        parts.append(
            f"## Contradicciones surgidas hoy ({len(ev['new_contradictions'])}):"
        )
        for c in ev["new_contradictions"][:5]:
            targets = ", ".join(t["path"] for t in c["targets"][:3])
            parts.append(f"- {c['subject_path']} ↔ {targets}")
        parts.append("")
    if ev["low_conf_queries"]:
        parts.append(
            f"## Preguntas sin buena respuesta hoy ({len(ev['low_conf_queries'])}):"
        )
        for q in ev["low_conf_queries"][:6]:
            parts.append(f"- \"{q['q']}\" (score {q['top_score']:+.2f})")
        parts.append("")
    # Pendings de WhatsApp que aún no se mandaron — a esta hora del día
    # (22hs) deberían estar todos en sent/sent_late, así que cualquier
    # pending acá indica un problema operativo (worker caído, bridge
    # inalcanzable). Mencionarlo permite al user tomar acción antes de
    # cerrar el día.
    if ev.get("wa_scheduled_today_pending"):
        parts.append(
            f"## ⚠ WhatsApp — mensajes que NO salieron todavía hoy "
            f"({len(ev['wa_scheduled_today_pending'])}):"
        )
        for w in ev["wa_scheduled_today_pending"][:6]:
            contact = w["contact_name"] or "(sin nombre)"
            preview = w.get("message_text_preview") or ""
            parts.append(
                f"- {w['scheduled_for_local']} → {contact}: \"{preview}\""
            )
        parts.append(
            "(si quedaron pending a esta hora, el worker tuvo problemas — "
            "revisá `launchctl list | grep wa-scheduled-send` y los logs)"
        )
        parts.append("")
    # ── BUCKETS rolling-window (últimos N días/horas, NO solo hoy).
    # Estos vienen del fan-out de `_home_compute` en web/server.py.
    # Los buckets TODAY ya se renderearon arriba (al inicio del prompt)
    # con prioridad — los rolling complementan con info "stale" o
    # acumulada que NO se generó hoy específicamente.
    gmail = extras.get("gmail_unread") or {}
    if gmail and (gmail.get("unread_count") or gmail.get("awaiting_reply")):
        unread = int(gmail.get("unread_count") or 0)
        awaiting = gmail.get("awaiting_reply") or []
        parts.append(f"## 📧 Gmail — bandeja al cierre del día ({unread} sin leer):")
        for m in awaiting[:5]:
            subj = (m.get("subject") or "(sin asunto)")[:80]
            sender = m.get("sender") or m.get("from") or "?"
            days = m.get("days_old")
            tail = f" ({days}d esperando respuesta)" if days else ""
            parts.append(f"- \"{subj}\" — {sender}{tail}")
        parts.append("")
    mail_unread = extras.get("mail_unread") or []
    if mail_unread:
        parts.append(f"## 📨 Apple Mail — VIP / sin leer ({len(mail_unread)}):")
        for m in mail_unread[:5]:
            subj = (m.get("subject") or "(sin asunto)")[:80]
            sender = m.get("sender") or "?"
            vip = " ⭐VIP" if m.get("is_vip") else ""
            parts.append(f"- \"{subj}\" — {sender}{vip}")
        parts.append("")
    wa_un = extras.get("whatsapp_unreplied") or []
    if wa_un:
        parts.append(
            f"## 💬 WhatsApp — esperando que respondas ({len(wa_un)} chats):"
        )
        for w in wa_un[:6]:
            name = w.get("name") or "(sin nombre)"
            snippet = (w.get("last_snippet") or "")[:90]
            hours = w.get("hours_waiting") or 0
            parts.append(f"- {name} ({hours:.0f}h esperando): \"{snippet}\"")
        parts.append("")
    cal_tomorrow = extras.get("tomorrow_calendar") or []
    if cal_tomorrow:
        parts.append(f"## 📅 Calendario — mañana ({len(cal_tomorrow)} eventos):")
        for c in cal_tomorrow[:8]:
            title = c.get("title") or "(sin título)"
            tr = c.get("time_range") or ""
            parts.append(f"- {tr} — {title}")
        parts.append(
            "(NO armes una agenda con esto — solo úsalo para mencionar el clima "
            "del día siguiente o conectarlo con cabos sueltos de hoy)"
        )
        parts.append("")
    drive_recent = extras.get("drive_recent") or []
    if drive_recent:
        parts.append(f"## 🗂 Drive — archivos recientes ({len(drive_recent)}):")
        for d in drive_recent[:5]:
            name = d.get("name") or d.get("title") or "?"
            parts.append(f"- {name}")
        parts.append("")
    # Aceptamos tanto `youtube_recent` (key nueva, ya excluye los de hoy)
    # como `youtube_watched` (key legacy del primer commit) para que tests
    # viejos sigan andando.
    yt = extras.get("youtube_recent") or extras.get("youtube_watched") or []
    if yt:
        parts.append(
            f"## 📺 YouTube — visto últimos 7 días (excluye hoy) "
            f"({len(yt)} videos):"
        )
        for v in yt[:5]:
            title = (v.get("title") or "?")[:90]
            parts.append(f"- {title}")
        parts.append("")
    bm = extras.get("chrome_bookmarks") or []
    if bm:
        parts.append(f"## 🔖 Chrome bookmarks usados ({len(bm)}):")
        for b in bm[:5]:
            name = (b.get("name") or "?")[:80]
            folder = b.get("folder") or ""
            tail = f" [{folder}]" if folder else ""
            parts.append(f"- {name}{tail}")
        parts.append("")
    loops_stale = extras.get("loops_stale") or []
    if loops_stale:
        parts.append(f"## 🔄 Loops viejos sin tocar (>30d) ({len(loops_stale)}):")
        for lp in loops_stale[:5]:
            note = lp.get("source_note") or "?"
            text = (lp.get("loop_text") or "")[:120]
            age = lp.get("age_days") or 0
            parts.append(f"- [[{note}]] ({age}d): {text}")
        parts.append("")
    pagerank_top = extras.get("pagerank_top") or []
    if pagerank_top:
        parts.append(
            f"## 🌟 Notas centrales del vault (PageRank top {len(pagerank_top)}):"
        )
        for n in pagerank_top[:5]:
            parts.append(f"- [[{n.get('title') or '?'}]]")
        parts.append(
            "(si tocaste hoy alguna de estas, dale más peso en el recap)"
        )
        parts.append("")
    fin = ev.get("finance") or {}
    ars = fin.get("ars") or {}
    has_finance = bool(ars.get("this_month"))
    if has_finance:
        m_label = fin.get("month_label", "")
        elapsed = fin.get("days_elapsed")
        in_month = fin.get("days_in_month")
        this_m = ars.get("this_month", 0.0)
        prev_m = ars.get("prev_month", 0.0) or 0.0
        delta = ars.get("delta_pct")
        projected = ars.get("projected")
        parts.append(f"## Finanzas {m_label} (MOZE, ARS):")
        parts.append(f"- gastado: {this_m:,.0f} ARS ({elapsed}/{in_month} días)")
        if prev_m:
            sign = "+" if (delta or 0) >= 0 else ""
            parts.append(f"- mes anterior: {prev_m:,.0f} ARS ({sign}{delta:.0f}%)")
        if projected:
            parts.append(f"- proyección fin de mes: {projected:,.0f} ARS")
        cats = ars.get("top_categories") or []
        if cats:
            bits = ", ".join(
                f"{c['name']} {c['amount']:,.0f} ({c['share']*100:.0f}%)"
                for c in cats[:3]
            )
            parts.append(f"- top categorías: {bits}")
        parts.append("")
    extra_sections = []
    if has_cross_source:
        extra_sections.append("`## 🔗 Conexiones del día`")
    if has_finance:
        extra_sections.append("`## 💸 Finanzas`")
    extras_clause = (
        f". Agregá {' y '.join(extra_sections)} SOLO si recibiste "
        "el bloque correspondiente en el contexto de arriba."
    ) if extra_sections else "."
    word_budget = (
        "250 a 450 palabras" if has_cross_source
        else "150 a 250 palabras"
    )
    sections_hint = (
        f"## OUTPUT — formato (longitud total: {word_budget})\n\n"
        "Empezá tu respuesta con `## 🪞 Lo que pasó hoy`. Las secciones de "
        "abajo son OPCIONALES — si una no tiene contenido real, OMITILA "
        "ENTERA (header + body). NO escribas placeholders como "
        "'nada quedó suelto', 'no hay datos suficientes', "
        "'ninguna pregunta abierta', 'sin novedades' — preferimos un "
        "brief más corto antes que un header con relleno" + extras_clause
        + " Citá notas con [[Título]]. Citá personas por nombre cuando "
        "aparezcan en gmail/wa/calendar."
    )
    parts.extend([
        sections_hint,
        "",
        "## 🪞 Lo que pasó hoy",
        "(3-4 líneas concretas: qué notas tocaste, qué temas aparecieron, "
        "qué mails/mensajes movieron la aguja. Si no hubo casi nada, decilo "
        "breve. Mezclá señales — no listés solo notas. Esta sección SIEMPRE "
        "va, aun si es 1 línea breve.)",
        "",
        "## 📥 Sin procesar",
        "(listar capturas de hoy que todavía no tienen carpeta/tags + mails "
        "VIP sin responder + chats WhatsApp esperando respuesta. SI NO HAY "
        "NADA, OMITÍ LA SECCIÓN ENTERA — no escribas el header.)",
        "",
        "## 🔍 Preguntas abiertas",
        "(queries low-confidence de hoy → notas que podrías escribir; "
        "citá las preguntas literales. SI NO HUBO NINGUNA, OMITÍ LA "
        "SECCIÓN ENTERA — no escribas el header.)",
        "",
        "## 🌅 Para mañana",
        "(2-3 action items concretos derivados de cabos sueltos de hoy. "
        "Si hay eventos en el calendario de mañana, mencionalos SOLO si "
        "se conectan con algo de hoy — no copies la agenda. NO agenda "
        "genérica — todo tiene que venir del contexto real. SI NO HAY "
        "NADA accionable, OMITÍ LA SECCIÓN ENTERA — no escribas el header.)",
    ])
    if has_cross_source:
        parts.extend([
            "",
            "## 🔗 Conexiones del día",
            "(escribí UNA línea por cada item del bloque '🔗 ENTIDADES "
            "CROSS-SOURCE' de arriba. Para cada PERSONA en ≥2 fuentes, "
            "narrá QUÉ HACE conectar las superficies: ej. 'Pablo te "
            "escribió 5 veces por WA + lo tenés mañana 10hs en calendar "
            "— probable que el WA sea para confirmar el sync'. Para cada "
            "TEMA en ≥2 fuentes, narrá QUÉ INDICA el patrón: ej. "
            "'Ghostty aparece en youtube + notas + screentime — el deep "
            "work del día fue tu setup de terminal'. **NO inventes "
            "conexiones fuera de ese bloque** — si una persona/tema "
            "aparece SOLO en una fuente (WA pero no en calendar, o "
            "notas pero no en youtube), NO va a esta sección por más "
            "que se te ocurra una hipótesis. Si el bloque está vacío, "
            "OMITÍ esta sección entera (incluyendo el header). Cada "
            "línea debe agregar valor — si solo podés decir 'X aparece "
            "en gmail y wa' sin un insight derivado de la evidencia "
            "concreta, mejor omitir esa línea. Mejor 0 líneas honestas "
            "que 3 inventadas.)",
        ])
    if has_finance:
        parts.extend([
            "",
            "## 💸 Finanzas",
            "(1-2 líneas: total del mes + si el run-rate proyecta arriba/abajo "
            "del mes pasado, y 1 categoría que destaca. Sé factual, sin juicio.)",
        ])
    return "\n".join(parts)


def _today_brief_model() -> str:
    """Modelo para el evening brief de `rag today`. Default `qwen2.5:7b`
    (el mismo del chat). Probamos qwen2.5:14b primero pero en mac M-chip
    con num_ctx=6144 + num_predict=500 tardaba 187s (timeout en
    `_today_brief_client`). El gap real de calidad para este task viene
    del prompt enriquecido (14 buckets cross-source), no del tamaño del
    modelo — qwen2.5:7b warm + prompt completo escribe briefs ricos en
    ~10-15s.
    Override por env si el user quiere probar `qwen2.5:14b` con paciencia
    o `command-r:latest`. Pipeline:
      1. `OBSIDIAN_RAG_TODAY_MODEL` (env)
      2. `qwen2.5:7b` (default — ya warm en VRAM por `OLLAMA_KEEP_ALIVE=-1`)
    No cae a `resolve_chat_model()` para mantener el brief desacoplado
    del modelo del chat — si después cambiamos `OBSIDIAN_RAG_WEB_CHAT_MODEL`,
    el brief sigue usando qwen2.5:7b a menos que se override explícito.
    """
    return os.environ.get("OBSIDIAN_RAG_TODAY_MODEL") or "qwen2.5:7b"


# Options dedicadas al today brief — distinto del CHAT_OPTIONS general que
# usa todo el sistema (chat web, helpers, etc.).
#   - `temperature` 0.4 vs 0 del chat → da variedad mínima entre runs (no
#     queremos texto idéntico cada noche aunque los inputs cambien poco;
#     temperature=0+seed=42 hacía que el brief fuera 100% determinístico).
#   - `seed` ausente → cada call usa una semilla nueva, así dos runs con
#     el mismo prompt entregan paráfrasis distintas en lugar del clon.
#   - `num_ctx` 4096 (igual que CHAT_OPTIONS) → el prompt con todos los
#     buckets pesa ~2200-2500 tokens; entra justo dejando ~1500 para
#     output. Importante mantener el MISMO num_ctx que el chat porque
#     subirlo fuerza a ollama a reinicializar el KV cache (200ms→4400ms
#     prefill, según comentario en CHAT_OPTIONS) y disparara cold-load
#     del modelo cada vez.
#   - `num_predict` 500 vs 384 del chat → cap de 250-450 palabras pedidas.
TODAY_BRIEF_OPTIONS = {
    "temperature": 0.4,
    "top_p": 0.9,
    "num_ctx": 4096,
    "num_predict": 500,
}


# Cliente dedicado con timeout MÁS ALTO (120s vs 90s del general). Con
# qwen2.5:7b warm el inference tarda ~10-15s; cold path puede pegar 30-60s
# si ollama lo descargó por memory pressure. 120s deja margen sin tener
# que esperar 3 minutos.
_TODAY_BRIEF_CLIENT = None


def _today_brief_client():
    global _TODAY_BRIEF_CLIENT
    if _TODAY_BRIEF_CLIENT is None:
        _TODAY_BRIEF_CLIENT = _TimedOllamaProxy(timeout=120.0)
    return _TODAY_BRIEF_CLIENT


def _strip_empty_today_sections(narrative: str) -> str:
    """Drop secciones del evening cuyo body es solo placeholder ("nada quedó
    suelto", "no hubo X", "ninguna pregunta", etc.) o está vacío.

    El prompt le dice al LLM "OMITÍ la sección entera" pero qwen2.5:7b
    igual rellena con frases tipo "Nada quedó suelto que no haya sido ya
    categorizado" — ese tipo de header sin contenido real es exactamente
    lo que el user pidió sacar.

    Heurística: para cada `## Section`, miramos el body (líneas hasta el
    próximo `## ` o EOF). Si toda la prosa hace match contra patrones
    placeholder (case-insensitive, accent-folded), drop header + body.
    Conservador: si hay UNA sola línea no-placeholder, mantenemos.
    """
    if not narrative:
        return narrative
    placeholder_re = re.compile(
        r"^\s*\W*\s*("
        r"nada\s+qued|no\s+hubo|no\s+hay\b|no\s+habia|"
        r"ninguna|ningun\b|sin\s+novedades?|sin\s+actividad|sin\s+nada|"
        r"no\s+se\s+registr|no\s+se\s+detect|no\s+aparec|"
        r"no\s+hay\s+datos?\s+suficientes|no\s+aplica|"
        r"todo\s+(quedo|esta)\s+(en\s+orden|al\s+dia|categorizado)"
        r")",
        re.IGNORECASE,
    )

    def _is_placeholder_body(body: str) -> bool:
        # Strip todas las líneas en blanco / list-marker only / "(nota)" lines
        lines = [
            ln.strip()
            for ln in body.splitlines()
            if ln.strip() and not ln.strip() in ("-", "*")
        ]
        if not lines:
            return True
        # Accent-fold para los regexes
        folded = []
        for ln in lines:
            n = unicodedata.normalize("NFD", ln)
            n = "".join(c for c in n if not unicodedata.combining(c))
            folded.append(n)
        # Drop si TODAS las líneas matchean placeholder
        return all(placeholder_re.match(ln) for ln in folded)

    # Split por headers `## ` (top-level del brief). Mantenemos el primer
    # bloque pre-header como prefacio (suele ser vacío).
    pieces = re.split(r"(?m)^(?=## )", narrative)
    # Si no hay ningún `## ` header, el split devuelve [narrative] entero —
    # nada que strippear, devolver tal cual para preservar el contrato del
    # caller (que puede esperar sin trailing-newline).
    if len(pieces) == 1 and not pieces[0].startswith("## "):
        return narrative
    out_pieces: list[str] = []
    for piece in pieces:
        if not piece.strip():
            continue
        if not piece.startswith("## "):
            out_pieces.append(piece)
            continue
        # Header + body
        nl_idx = piece.find("\n")
        if nl_idx < 0:
            # Solo el header sin body — drop
            continue
        body = piece[nl_idx + 1:]
        if _is_placeholder_body(body):
            continue
        out_pieces.append(piece)
    if not out_pieces:
        return ""
    return "\n\n".join(p.rstrip() for p in out_pieces) + "\n"


def _generate_today_narrative(prompt: str) -> str:
    try:
        resp = _today_brief_client().chat(
            model=_today_brief_model(),
            messages=[{"role": "user", "content": prompt}],
            options=TODAY_BRIEF_OPTIONS,
            keep_alive=chat_keep_alive(),
        )
        raw = (resp.message.content or "").strip()
    except Exception:
        return ""
    # Post-processing — el prompt prohíbe 1ª persona pero qwen2.5:7b
    # se desliza ~10% del tiempo ("trabajé", "me centré"). Este pass
    # final reemplaza verbos / pronombres en 1ª persona singular y
    # plural por 2ª persona singular ("trabajaste", "te centraste").
    # Preserva citas literales entre comillas para no destrozar texto
    # del usuario citado.
    try:
        from rag.today_correlator import normalize_voice_to_2da_persona
        normalized = normalize_voice_to_2da_persona(raw)
    except Exception:
        normalized = raw
    # Sacar secciones con placeholder ("nada quedó suelto", etc.) — el
    # user pidió explícitamente que si está vacío no se muestre ni el
    # título.
    return _strip_empty_today_sections(normalized)


# ── Phase 4b: `rag wa-tasks` Click command moved to `rag.wa_tasks` ──────
# Thin CLI wrapper that orchestrates `_fetch_whatsapp_window` →
# `_wa_extract_actions` → `_wa_tasks_write_note` (all already in
# `rag.integrations.whatsapp` since Phase 1b). Re-imported at the bottom
# of this file so `rag.wa_tasks` resolves the same Click command.


@cli.command("remind-wa")
@click.option("--dry-run", is_flag=True,
              help="Calcular las acciones sin mandar al bridge ni marcar dedup")
@click.option("--window-min", type=int, default=5, show_default=True,
              help="Ventana ± minutos: reminders con due en [now - window, now + window] se notifican")
@click.option("--max-overdue-min", type=int, default=1440, show_default=True,
              help="Cap absoluto de overdue: reminders con due anterior a now - max-overdue se skipean")
def remind_wa(dry_run: bool, window_min: int, max_overdue_min: int):
    """Push de Apple Reminders próximos a vencer / recién vencidos al JID ambient.

    Idempotente vía la tabla `rag_reminder_wa_pushed` — un reminder no se
    notifica dos veces aunque el script corra cada 5min. Si el bridge falla
    en un envío puntual, esa row NO se marca y se reintenta en el próximo
    run. El cron `com.fer.obsidian-rag-reminder-wa-push` (StartInterval=300)
    invoca este comando.

    Short-circuits: sin `~/.local/share/obsidian-rag/ambient.json` válido →
    `reason=no_ambient_config`. Con `reminder_push_enabled=false` →
    `reason=reminder_push_disabled`. Ambos retornan summary vacío sin tocar
    el bridge.
    """
    summary = push_due_reminders_to_whatsapp(
        window_min=int(window_min),
        max_overdue_min=int(max_overdue_min),
        dry_run=bool(dry_run),
    )
    reason = summary.get("reason")
    tag = "[dim]dry-run[/dim]" if dry_run else "[green]live[/green]"
    if reason:
        console.print(
            f"{tag} reminder push · [yellow]{reason}[/yellow] · "
            f"pushed={summary['pushed']} skipped={summary['skipped']} "
            f"failed={summary['failed']}"
        )
        return
    console.print(
        f"{tag} reminder push · pushed={summary['pushed']} "
        f"skipped={summary['skipped']} failed={summary['failed']} "
        f"items={len(summary.get('items') or [])}"
    )


@cli.command("wa-scheduled-send")
@click.option("--dry-run", is_flag=True,
              help="Calcular las acciones sin enviar al bridge ni mover status")
@click.option("--late-threshold-min", type=int, default=5, show_default=True,
              help="Si el delta now-scheduled_for supera estos minutos el status final es 'sent_late' (no 'sent')")
@click.option("--max-retries", type=int, default=5, show_default=True,
              help="Tras N reintentos fallidos, el row queda en 'failed' y deja de pickearse")
@click.option("--max-per-run", type=int, default=20, show_default=True,
              help="Cap de cuántos pendings procesa por corrida (limita ráfagas si la cola se llenó)")
def wa_scheduled_send(dry_run: bool, late_threshold_min: int,
                      max_retries: int, max_per_run: int):
    """Worker — envía mensajes de WhatsApp programados cuyo `scheduled_for_utc`
    ya venció. Lo dispara el plist `com.fer.obsidian-rag-wa-scheduled-send`
    cada 5 minutos.

    Idempotente: cada row se mueve de `pending` a `sent` / `sent_late` /
    `failed` en una sola transacción; si el bridge está caído, el row
    queda `pending` con `attempt_count` incrementado y se reintenta en
    el próximo ciclo del cron. Tras `max-retries` fallos consecutivos
    pasa a `failed` y deja de pickearse (el dashboard lo muestra para
    reenvío manual).

    Si la Mac estuvo dormida, el delta `now - scheduled_for` puede ser
    grande — política decidida con el usuario: mandamos igual y marcamos
    `sent_late` con `delta_minutes` para que el dashboard lo destaque
    en naranja. NO se cancela el envío por estar tarde.

    Silent-fail completo: cualquier excepción inesperada se loguea a
    `rag_ambient` con `cmd=whatsapp_scheduled_worker_error` y el comando
    sale exit 0 para no romper launchd. El cuerpo del mensaje NUNCA se
    persiste en el log (privacidad) — solo metadata operativa.
    """
    from rag import wa_scheduled  # noqa: PLC0415 (lazy: el módulo abre SQLite)
    summary = wa_scheduled.run_due_worker(
        late_threshold_minutes=int(late_threshold_min),
        max_retries=int(max_retries),
        max_per_run=int(max_per_run),
        dry_run=bool(dry_run),
    )
    tag = "[dim]dry-run[/dim]" if dry_run else "[green]live[/green]"
    if not summary.get("ok"):
        reason = summary.get("reason") or "unknown_error"
        console.print(f"{tag} wa-scheduled-send · [red]{reason}[/red]")
        return
    processed = summary.get("processed", 0)
    sent = summary.get("sent", 0)
    sent_late = summary.get("sent_late", 0)
    failed = summary.get("failed", 0)
    retried = summary.get("retried", 0)
    color = "yellow" if sent_late or failed else "green"
    console.print(
        f"{tag} wa-scheduled-send · processed={processed} "
        f"sent=[{color}]{sent}[/{color}] sent_late=[yellow]{sent_late}[/yellow] "
        f"failed=[red]{failed}[/red] retried={retried}"
    )


# ── `rag bridge` — manage the WhatsApp bridge daemon ────────────────
#
# Constants para el bridge daemon. Rutas hardcodeadas porque los plists
# y scripts ya las usan de fábrica — si alguna vez se mueven, hay que
# bumpearlas en este bloque + en `~/Library/LaunchAgents/com.fer.whatsapp-
# bridge.plist` + en `bridge.log` filenames del watchdog. Defer hasta
# que sea un problema real (multi-host setup, etc.).
_WA_BRIDGE_LAUNCHD_LABEL = "com.fer.whatsapp-bridge"
_WA_BRIDGE_PLIST = Path.home() / "Library/LaunchAgents/com.fer.whatsapp-bridge.plist"
_WA_BRIDGE_BINARY = Path.home() / ".local/bin/whatsapp-bridge"
_WA_BRIDGE_REPO = Path("/Users/fer/repositories/whatsapp-mcp/whatsapp-bridge")
_WA_BRIDGE_SESSION_DB = _WA_BRIDGE_REPO / "store/whatsapp.db"
_WA_BRIDGE_MESSAGES_DB = _WA_BRIDGE_REPO / "store/messages.db"
_WA_BRIDGE_SENTINEL = _WA_BRIDGE_REPO / "store/.needs-reauth"
_WA_BRIDGE_LOG = Path.home() / ".local/share/whatsapp-bridge/bridge.log"
_WA_BRIDGE_HEALTH_URL = "http://localhost:8080/api/health"


def _wa_bridge_uid() -> int:
    """Resolve the user UID for the launchd domain (`gui/<uid>`).

    `launchctl` requires the explicit UID for user-level (per-session)
    daemons under macOS 10.10+. We read it once via `os.getuid()` since
    the CLI always runs as the user that owns the plist (no sudo
    paths). If somebody's running this with sudo, `os.getuid()` returns
    0 and `launchctl` will fail loudly — that's a bug they should fix
    in their setup, not silently swallow.
    """
    return os.getuid()


def _wa_bridge_is_loaded() -> bool:
    """Return True if the launchd label is currently loaded.

    We use `launchctl print` (macOS 10.10+) instead of the legacy
    `launchctl list | grep` because `print` returns a non-zero exit
    code if the label isn't loaded, which is what we want — much
    cheaper than parsing `list` output.
    """
    try:
        result = subprocess.run(
            ["launchctl", "print", f"gui/{_wa_bridge_uid()}/{_WA_BRIDGE_LAUNCHD_LABEL}"],
            capture_output=True, text=True, timeout=5,
        )
        return result.returncode == 0
    except Exception:
        return False


def _wa_bridge_http_probe() -> tuple[bool, str]:
    """Probe the bridge's `/api/health` to check WA connectivity.

    Returns `(is_healthy, detail)` where `is_healthy` is True iff the
    bridge process is alive AND has an active WebSocket connection to
    WhatsApp servers. The `/api/health` endpoint is side-effect-free:
    no fake send attempts that could double-deliver to a real contact.

    Possible outcomes:
      - HTTP 200 + `{"connected": true, "logged_in": true}` → all OK.
      - HTTP 200 + `{"connected": false, "logged_in": true}` → socket
        dropped but session still valid; bridge will auto-reconnect
        (or you wait & retry).
      - HTTP 200 + `{"connected": false, "logged_in": false}` → no
        paired device; need `rag bridge reauth` to scan QR.
      - HTTP 404 → bridge running but doesn't expose `/api/health`
        yet (old binary). Caller should fall back to /api/send probe
        or just rebuild the bridge.
      - ConnectionRefusedError → daemon not running.
    """
    import urllib.request
    import urllib.error
    try:
        req = urllib.request.Request(_WA_BRIDGE_HEALTH_URL)
        with urllib.request.urlopen(req, timeout=2) as resp:
            body = resp.read().decode("utf-8", errors="replace")
            try:
                data = json.loads(body)
            except json.JSONDecodeError:
                return False, f"HTTP {resp.status}: invalid_json: {body[:80]}"
            connected = bool(data.get("connected"))
            logged_in = bool(data.get("logged_in"))
            if connected and logged_in:
                return True, f"connected (jid={data.get('jid', '')[:30]})"
            if not logged_in:
                return False, "not_paired (no session — run `rag bridge reauth`)"
            return False, "logged_in but socket dropped (auto-reconnect pending)"
    except urllib.error.HTTPError as exc:
        if exc.code == 404:
            return False, "no_health_endpoint (old bridge binary — `cd ~/repositories/whatsapp-mcp/whatsapp-bridge && go build -o ~/.local/bin/whatsapp-bridge .`)"
        return False, f"HTTP {exc.code}"
    except (ConnectionRefusedError, urllib.error.URLError) as exc:
        return False, f"unreachable: {exc!r}"
    except Exception as exc:
        return False, f"probe_error: {exc!r}"


@cli.group()
def bridge():
    """Gestionar el daemon `whatsapp-bridge` (login, status, re-auth).

    El bridge es el proceso Go que mantiene la conexión con WhatsApp Web
    via WebSocket. Cuando WA expulsa la sesión (rotación, dispositivo
    duplicado, etc.) el proceso queda zombie con session inválida —
    todo `propose_whatsapp_send` empieza a fallar con `send_failed`.
    Este grupo de comandos te deja diagnosticar y recuperarlo sin
    memorizar los 6 pasos de launchctl + sqlite manual.
    """


@bridge.command("status")
def bridge_status():
    """Mostrar estado actual del bridge (daemon, conexión WA, sentinel).

    Diagnóstico rápido — no toca nada. Útil cuando un send falla con
    `send_failed` y no sabés si es problema del bridge o del propose
    tool. Reporta:

      - launchd: cargado / no cargado
      - HTTP probe: conectado / no conectado / unreachable
      - Sentinel `.needs-reauth`: presente (con timestamp) / ausente
      - Última línea de `LoggedOut` / `Connected` en bridge.log

    Si todo está verde, el bridge está sano. Si hay algo en rojo,
    leer la guía en pantalla — usualmente es `rag bridge reauth`.
    """
    is_loaded = _wa_bridge_is_loaded()
    is_connected, detail = _wa_bridge_http_probe()
    sentinel_ts = None
    if _WA_BRIDGE_SENTINEL.exists():
        try:
            sentinel_ts = _WA_BRIDGE_SENTINEL.read_text().strip()
        except Exception as exc:
            sentinel_ts = f"<read error: {exc!r}>"

    # Last LoggedOut / Connected events in bridge.log (best-effort)
    last_logged_out = None
    last_connected = None
    if _WA_BRIDGE_LOG.exists():
        try:
            tail = subprocess.run(
                ["tail", "-n", "5000", str(_WA_BRIDGE_LOG)],
                capture_output=True, text=True, timeout=3,
            )
            for line in tail.stdout.splitlines():
                if "Device logged out" in line:
                    last_logged_out = line.strip()[:160]
                elif "Connected to WhatsApp" in line and "Successfully" not in line:
                    last_connected = line.strip()[:160]
        except Exception:
            pass

    # Compose console output
    console.print()
    console.print("[bold]WhatsApp Bridge — Status[/bold]")
    console.print(f"  label:      [cyan]{_WA_BRIDGE_LAUNCHD_LABEL}[/cyan]")
    console.print(f"  binary:     [cyan]{_WA_BRIDGE_BINARY}[/cyan]")
    console.print(
        f"  daemon:     "
        + ("[green]✓ loaded[/green]" if is_loaded else "[red]✗ not loaded[/red]")
    )
    console.print(
        f"  connection: "
        + ("[green]✓ connected[/green]" if is_connected else "[red]✗ disconnected[/red]")
        + f"  [dim]({detail})[/dim]"
    )
    if sentinel_ts:
        console.print(
            f"  sentinel:   [yellow]⚠ .needs-reauth[/yellow] [dim](since {sentinel_ts})[/dim]"
        )
    else:
        console.print("  sentinel:   [green]✓ none[/green]")
    if last_connected:
        console.print(f"  last-conn:  [dim]{last_connected}[/dim]")
    if last_logged_out:
        console.print(f"  last-out:   [yellow]{last_logged_out}[/yellow]")
    console.print()

    if not is_connected:
        console.print(
            "[yellow]→ Para recuperar:[/yellow] [bold]rag bridge reauth[/bold]"
        )
        console.print()
        # Exit code 1 so cron/scripts can detect "needs attention".
        raise click.exceptions.Exit(1)


@bridge.command("reauth")
@click.option("--keep-session", is_flag=True,
              help="No borrar `whatsapp.db` (intenta reconectar sin re-pair). "
                   "Solo útil si sospechás que el bridge se cuelga sin haber "
                   "perdido la sesión real. Default: borra session DB.")
@click.option("--yes", "-y", is_flag=True,
              help="Saltarse el prompt de confirmación.")
def bridge_reauth(keep_session: bool, yes: bool):
    """Re-autenticar el bridge con un escaneo de QR fresco.

    Automatiza los 6 pasos manuales que normalmente hay que hacer cuando
    WhatsApp expulsa la sesión:

      1. Detener el daemon (`launchctl bootout`).
      2. Backup + borrar `store/whatsapp.db` (la session DB; deja
         `messages.db` intacto — historial preservado).
      3. Lanzar el bridge en foreground attaché al TTY actual.
      4. Mostrar el QR que el bridge imprime → vos lo escaneás con
         WhatsApp en el teléfono (Settings → Linked Devices → Link a
         Device).
      5. Esperar el "Successfully connected and authenticated!".
      6. Vos hacés Ctrl-C cuando ves el success → reload del daemon
         con `launchctl bootstrap`.

    REQUIERE TTY interactiva — el QR usa half-block Unicode chars que
    sólo se renderizan en una terminal real (no en pipes ni redirects).
    Si corrés esto vía SSH sin -t, sale con error.

    El backup de la session DB queda en
    `store/whatsapp.db.backup-<timestamp>` — si algo sale mal podés
    restaurarlo manualmente y reintentar.
    """
    if not sys.stdin.isatty() or not sys.stdout.isatty():
        console.print(
            "[red]✗[/red] `rag bridge reauth` requiere TTY interactiva — "
            "el QR usa half-block Unicode que no se renderiza en pipes."
        )
        console.print(
            "[dim]Si estás en SSH, reconectá con `ssh -t`. Si estás en "
            "tmux/screen, abrí una pane real.[/dim]"
        )
        raise click.exceptions.Exit(2)

    if not _WA_BRIDGE_BINARY.exists():
        console.print(
            f"[red]✗[/red] No existe el binario del bridge en "
            f"[cyan]{_WA_BRIDGE_BINARY}[/cyan]. Buildealo primero con:"
        )
        console.print(
            f"  [dim]cd {_WA_BRIDGE_REPO} && go build -o {_WA_BRIDGE_BINARY} .[/dim]"
        )
        raise click.exceptions.Exit(2)

    if not _WA_BRIDGE_REPO.exists():
        console.print(
            f"[red]✗[/red] No existe el repo del bridge en "
            f"[cyan]{_WA_BRIDGE_REPO}[/cyan]. Cloneá `jagoff/whatsapp-mcp`."
        )
        raise click.exceptions.Exit(2)

    # Pre-flight summary
    console.print()
    console.print("[bold]WhatsApp Bridge — Re-auth flow[/bold]")
    console.print(f"  daemon:        [cyan]{_WA_BRIDGE_LAUNCHD_LABEL}[/cyan]")
    console.print(f"  session DB:    [cyan]{_WA_BRIDGE_SESSION_DB}[/cyan]"
                  + (" [dim](preserved)[/dim]" if keep_session else " [dim](será borrada)[/dim]"))
    console.print(f"  messages DB:   [cyan]{_WA_BRIDGE_MESSAGES_DB}[/cyan] [dim](preserved)[/dim]")
    console.print()

    if not yes:
        try:
            ans = click.prompt(
                "¿Continuar? [y/N]", default="n", show_default=False,
            )
        except click.exceptions.Abort:
            console.print("[dim]cancelado.[/dim]")
            return
        if (ans or "").strip().lower() not in {"y", "yes", "s", "si", "sí"}:
            console.print("[dim]cancelado.[/dim]")
            return

    # ── Step 1: stop the daemon ───────────────────────────────────────
    if _wa_bridge_is_loaded():
        console.print("[dim]→ deteniendo daemon…[/dim]", end=" ")
        try:
            subprocess.run(
                ["launchctl", "bootout",
                 f"gui/{_wa_bridge_uid()}/{_WA_BRIDGE_LAUNCHD_LABEL}"],
                capture_output=True, text=True, timeout=10, check=False,
            )
        except Exception as exc:
            console.print(f"[yellow]warn:[/yellow] launchctl bootout: {exc!r}")
        # Wait for bridge to release port 8080. Up to 5s — usually <1s.
        for _ in range(50):
            time.sleep(0.1)
            if not _wa_bridge_is_loaded():
                break
        console.print("[green]✓[/green]")
    else:
        console.print("[dim]→ daemon no estaba cargado (skip stop)[/dim]")

    # ── Step 2: backup + delete the session DB ────────────────────────
    if not keep_session and _WA_BRIDGE_SESSION_DB.exists():
        import shutil
        ts = datetime.now().strftime("%Y%m%d-%H%M%S")
        backup = _WA_BRIDGE_SESSION_DB.with_suffix(f".db.backup-{ts}")
        try:
            shutil.copy2(_WA_BRIDGE_SESSION_DB, backup)
            _WA_BRIDGE_SESSION_DB.unlink()
            # Also delete WAL + SHM siblings; sqlite reconstructs them.
            for ext in ("-wal", "-shm"):
                sib = _WA_BRIDGE_SESSION_DB.with_name(_WA_BRIDGE_SESSION_DB.name + ext)
                if sib.exists():
                    try:
                        sib.unlink()
                    except Exception:
                        pass
            console.print(
                f"[dim]→ session DB borrada (backup: [cyan]{backup.name}[/cyan])[/dim] "
                f"[green]✓[/green]"
            )
        except Exception as exc:
            console.print(f"[red]✗[/red] error backup/borrado: {exc!r}")
            raise click.exceptions.Exit(3)

    # Clear the sentinel — next *Connected event in the new run will
    # also clear it, but anticipate so `bridge status` queries during
    # the reauth window don't show stale yellow.
    if _WA_BRIDGE_SENTINEL.exists():
        try:
            _WA_BRIDGE_SENTINEL.unlink()
        except Exception:
            pass

    # ── Step 3: run bridge in foreground ──────────────────────────────
    console.print()
    console.print("[bold yellow]Próximos pasos (manuales):[/bold yellow]")
    console.print("  1. Voy a lanzar el bridge attached a esta terminal.")
    console.print("  2. Va a aparecer un QR code grande.")
    console.print("  3. Abrí WhatsApp en el [bold]teléfono[/bold] →")
    console.print("     Settings → Linked Devices → [bold]Link a Device[/bold]")
    console.print("     → escaneá el QR.")
    console.print("  4. Esperá hasta que veas:")
    console.print("     [green]\"Successfully connected and authenticated!\"[/green]")
    console.print("  5. Cuando aparezca, presioná [bold]Ctrl-C[/bold] para detener")
    console.print("     el bridge interactivo — yo me encargo del resto.")
    console.print()
    console.print("[dim]Lanzando bridge en 2s…[/dim]")
    time.sleep(2)
    console.print()

    bridge_proc = None
    try:
        # Run with TTY inherited from the parent so qrterminal renders
        # correctly. We DON'T capture stdout/stderr — let it stream
        # straight to the user's terminal. We pass `cwd=_WA_BRIDGE_REPO`
        # so `store/whatsapp.db` resolves correctly (the bridge uses a
        # relative `file:store/whatsapp.db` path).
        bridge_proc = subprocess.Popen(
            [str(_WA_BRIDGE_BINARY)],
            cwd=str(_WA_BRIDGE_REPO),
        )
        bridge_proc.wait()
    except KeyboardInterrupt:
        # User saw "Successfully connected" and pressed Ctrl-C — that's
        # expected. SIGINT propagated to the child and it should exit
        # cleanly. Wait up to 3s for the child to finish.
        if bridge_proc and bridge_proc.poll() is None:
            try:
                bridge_proc.wait(timeout=3)
            except subprocess.TimeoutExpired:
                bridge_proc.kill()
        console.print()
        console.print("[dim]→ bridge interactivo terminado.[/dim]")

    # ── Step 4: bootstrap the daemon back ─────────────────────────────
    if not _WA_BRIDGE_PLIST.exists():
        console.print(
            f"[red]✗[/red] No existe el plist en [cyan]{_WA_BRIDGE_PLIST}[/cyan]. "
            "Reauth completo, pero el daemon NO se va a auto-restartar."
        )
        raise click.exceptions.Exit(0)

    console.print("[dim]→ recargando daemon…[/dim]", end=" ")
    try:
        result = subprocess.run(
            ["launchctl", "bootstrap",
             f"gui/{_wa_bridge_uid()}", str(_WA_BRIDGE_PLIST)],
            capture_output=True, text=True, timeout=10, check=False,
        )
        if result.returncode != 0:
            console.print(f"[yellow]warn:[/yellow] launchctl bootstrap rc={result.returncode}: {result.stderr.strip()}")
        else:
            console.print("[green]✓[/green]")
    except Exception as exc:
        console.print(f"[red]✗[/red] launchctl bootstrap: {exc!r}")

    # ── Step 5: verify with HTTP probe ────────────────────────────────
    # Wait up to 8s for the bridge to come up + reconnect.
    console.print("[dim]→ verificando…[/dim]", end=" ")
    for _ in range(40):
        time.sleep(0.2)
        ok, detail = _wa_bridge_http_probe()
        if ok:
            console.print("[green]✓ conectado[/green]")
            console.print()
            console.print("[green bold]✓ Re-auth completo. WhatsApp está activo.[/green bold]")
            return
        # If detail says "not_connected" the daemon is up but session
        # didn't take — keep waiting.
    console.print("[yellow]⚠ daemon arrancó pero el HTTP probe sigue fallando.[/yellow]")
    console.print(f"[dim]Último detail: {detail}[/dim]")
    console.print(
        "[dim]Mirá `tail -f ~/.local/share/whatsapp-bridge/bridge.log` "
        "y reintentá si hace falta.[/dim]"
    )


@cli.command("contact-note")
@click.argument("contact_name")
@click.argument("observation")
@click.option("--category", default=None,
              help="Categoría tipo bullet existente (Preferencias, Trabajo, "
                   "Notas, etc.). Si matchea, smart-append al value de ese "
                   "bullet. Si no, crea bullet nuevo. Si NO se da, solo va "
                   "a `## Observaciones`.")
@click.option("--source-kind", default="manual",
              type=click.Choice(["manual", "chat", "wa", "audio"]),
              help="Origen de la observación. `manual` (default) para CLI, "
                   "los otros se reservan para hooks automáticos.")
@click.option("--source-excerpt", default=None,
              help="Texto crudo del mensaje original (e.g. \"Seba te llevo "
                   "un vino\") — se loguea en italic junto a la observación.")
def contact_note(contact_name: str, observation: str,
                 category: str | None, source_kind: str,
                 source_excerpt: str | None):
    """Anotar info viva sobre un contacto en su nota del vault.

    Las notas de `04-Archive/99-obsidian-system/99-Contacts/` son contactos
    "vivos" — cada vez que el user (o el LLM) detecta info relevante sobre
    alguien, esta función la guarda ahí. Doble write:

      1. Sección `## Observaciones` al final, con bullet timestamped
         + el texto crudo en italic (auditoría completa).
      2. Si `--category` matchea un bullet `**<X>**:` existente del
         template (`Notas`, `Trabajo / contexto`, etc.), append al
         value de ese bullet. Si no existe, crea uno nuevo.

    Idempotente: si la observación ya está literal, skip silencioso.

    Ejemplos:

      \b
      # Solo a la sección de auditoría:
      rag contact-note Seba "Le gusta el vino" \\
        --source-excerpt "Seba te llevo un vino"

      # También consolida en bullet **Preferencias**:
      rag contact-note Seba "Vino" --category Preferencias

      # Update de trabajo:
      rag contact-note Mama "Jubilada en Santa Fe" \\
        --category "Trabajo / contexto"
    """
    from rag.integrations.whatsapp import _append_contact_observation
    result = _append_contact_observation(
        contact_name,
        observation,
        category=category,
        source_kind=source_kind,
        source_excerpt=source_excerpt,
    )
    if not result.get("ok"):
        reason = result.get("reason", "unknown")
        if reason == "contact_not_in_vault":
            console.print(
                f"[red]✗ no encontré '{contact_name}' en el vault "
                f"`99-Contacts/`[/red]\n"
                f"[dim]creá la nota primero (copiá `_template.md`) o "
                f"chequeá el alias[/dim]"
            )
        else:
            console.print(f"[red]✗ falló: {reason}[/red]")
        raise click.exceptions.Exit(1)

    if result.get("reason") == "duplicate_skipped":
        console.print(
            f"[yellow]· ya estaba registrado en {result['file']}[/yellow]"
        )
        return

    parts = []
    if result.get("observation_added"):
        parts.append("Observaciones")
    if result.get("category_updated"):
        effective_category = result.get("category") or category
        if result.get("category_inferred"):
            parts.append(f"**{effective_category}** [i]inferida por LLM[/i]")
        else:
            parts.append(f"**{effective_category}**")
    where = " + ".join(parts) if parts else "(nada cambió)"
    console.print(
        f"[green]✓ anotado en {result['file']}[/green] "
        f"[dim]→ {where}[/dim]"
    )


def _build_today_extras_for_cli(target: datetime) -> dict:
    """Construye el dict `extras` cross-source para el CLI `rag today`.

    Paridad con `web/server.py:_home_compute` regenerate=True path. Corre
    los 4 fetchers TODAY (gmail/wa/calendar/youtube) en paralelo + el
    correlator + tomorrow_calendar (para detectar personas en agenda
    futura). NO incluye buckets web-specific (signals, pagerank, eval,
    drive, bookmarks rolling) — esos requieren un web compute pool y la
    DB del corpus, que el CLI no tiene a mano. Suficiente para el brief
    de cierre de día tras la terminal.

    Silent-fail por fetcher: si gmail OAuth expiró o calendar no tiene
    icalBuddy instalado, ese bucket queda `[]` y el resto sigue.
    """
    from concurrent.futures import ThreadPoolExecutor

    with ThreadPoolExecutor(max_workers=5, thread_name_prefix="cli-today") as pool:
        fut_gmail = pool.submit(_fetch_gmail_today, target, 8)
        fut_wa = pool.submit(_fetch_whatsapp_today, target, 8)
        fut_cal_today = pool.submit(_fetch_calendar_today, 15)
        fut_yt_today = pool.submit(_fetch_youtube_today, target, 5)
        fut_cal_tomorrow = pool.submit(_fetch_calendar_ahead, 1, 10)

        def _safe(fut, default, timeout: float):
            try:
                return fut.result(timeout=timeout) or default
            except Exception:
                return default

        gmail_today = _safe(fut_gmail, [], 10.0)
        wa_today = _safe(fut_wa, [], 5.0)
        cal_today = _safe(fut_cal_today, [], 10.0)
        yt_today = _safe(fut_yt_today, [], 5.0)
        cal_tomorrow = _safe(fut_cal_tomorrow, [], 10.0)

    extras: dict = {
        "gmail_today": gmail_today,
        "whatsapp_today": wa_today,
        "calendar_today": cal_today,
        "youtube_today": yt_today,
        "tomorrow_calendar": cal_tomorrow,
    }
    # Pre-correlate cross-source antes de pasar al LLM. Misma lógica que
    # el web — el LLM 7B no descubre patrones cross-source flat, los
    # narra mejor cuando recibe el bloque pre-armado.
    try:
        from rag.today_correlator import correlate_today_signals as _corr
        extras["correlations"] = _corr({}, extras)
    except Exception:
        extras["correlations"] = {"people": [], "topics": []}
    return extras


@cli.command()
@click.option("--dry-run", is_flag=True,
              help="Imprimir el brief sin escribir el archivo")
@click.option("--plain", is_flag=True, help="Sin ANSI / sin Rich markup")
@click.option("--date", "date_opt", default=None,
              help="Fecha objetivo YYYY-MM-DD (default: hoy)")
def today(dry_run: bool, plain: bool, date_opt: str | None):
    """Cierre del día: qué pasó hoy + cabos sueltos + semillas para mañana.

    Ventana: hoy 00:00 → ahora. Evidencia: notas modificadas hoy, capturas del
    día en 00-Inbox/, todos/due tocados, contradicciones nuevas, queries
    low-confidence. command-r arma un brief de 150-250 palabras. Escribe a
    `04-Archive/99-obsidian-system/99-AI/reviews/YYYY-MM-DD-evening.md` (auto-indexado) salvo --dry-run. Si no
    hay actividad, imprime "sin actividad hoy" y termina.
    """
    _diff_brief_signal()  # compare yesterday's brief vs on-disk state → behavior events
    if date_opt:
        try:
            target = datetime.fromisoformat(date_opt)
        except ValueError:
            msg = f"Fecha inválida: {date_opt}"
            click.echo(msg) if plain else console.print(f"[red]{msg}[/red]")
            return
    else:
        target = datetime.now()

    ev = _collect_today_evidence(
        target, VAULT_PATH, LOG_PATH, CONTRADICTION_LOG_PATH,
    )
    total = (
        len(ev["recent_notes"]) + len(ev["inbox_today"])
        + len(ev["todos"]) + len(ev["new_contradictions"])
        + len(ev["low_conf_queries"])
    )
    if total == 0:
        msg = "sin actividad hoy"
        click.echo(msg) if plain else console.print(f"[yellow]{msg}[/yellow]")
        return

    if not plain:
        console.print(
            f"[dim]Evidencia:[/dim] {len(ev['recent_notes'])} tocadas · "
            f"{len(ev['inbox_today'])} capturas · {len(ev['todos'])} todos · "
            f"{len(ev['new_contradictions'])} contrad · "
            f"{len(ev['low_conf_queries'])} low-conf"
        )

    # Cross-source extras: paridad con el web `/api/home?regenerate=1`.
    # Antes el CLI solo veía el vault (notas + inbox + todos), ahora ve
    # también gmail/wa/calendar/youtube de hoy + tomorrow_calendar + el
    # correlator pre-arma personas + temas cross-source. Sin esto el
    # `rag today` desde la terminal generaba un brief mucho más pobre que
    # el regenerate del web. Silent-fail por fetcher: si gmail OAuth está
    # roto el resto sigue.
    extras = _build_today_extras_for_cli(target)
    date_label = target.strftime("%Y-%m-%d")
    prompt = _render_today_prompt(date_label, ev, extras=extras)
    if plain:
        narrative = _generate_today_narrative(prompt)
    else:
        with console.status("[dim]Armando cierre del día…[/dim]", spinner="dots"):
            narrative = _generate_today_narrative(prompt)
    if not narrative:
        msg = "Modelo devolvió respuesta vacía."
        click.echo(msg) if plain else console.print(f"[red]{msg}[/red]")
        return

    now_iso = datetime.now().isoformat(timespec="seconds")
    fm_lines = [
        "---",
        f"created: '{now_iso}'",
        "type: evening-brief",
        "tags:",
        "- review",
        "- evening-brief",
        f"date: '{date_label}'",
        "---",
    ]
    body = "\n".join(fm_lines) + f"\n\n# Evening brief — {date_label}\n\n{narrative}\n"

    if dry_run:
        if plain:
            click.echo(convert_obsidian_links(body))
        else:
            console.rule(f"[bold]Evening brief {date_label} (dry-run)[/bold]")
            console.print(body, markup=False, highlight=False)
        return

    path = VAULT_PATH / MORNING_FOLDER / f"{date_label}-evening.md"
    path.parent.mkdir(parents=True, exist_ok=True)
    # Audit 2026-04-26 (BUG #14): idempotencia — sobrescribir si re-corre el
    # mismo día (igual que morning brief). Pre-fix duplicaba con timestamp.
    path.write_text(body, encoding="utf-8")
    try:
        _index_single_file(get_db(), path, skip_contradict=True)
    except Exception:
        pass
    rel = path.relative_to(VAULT_PATH)
    if plain:
        click.echo(str(rel))
    else:
        console.print(f"[green]✓ Brief guardado:[/green] [bold cyan]{rel}[/bold cyan]")
    # Record citations for tomorrow's diff signal.
    try:
        wikilinks = _extract_wikilinks_from_markdown(narrative)
        c = _load_corpus(get_db())
        cited_paths, _ambig = _resolve_wikilinks_to_paths(
            wikilinks, c["title_to_paths"], VAULT_PATH,
        )
        by_section = _citations_by_section(
            narrative, c["title_to_paths"], VAULT_PATH,
        )
        record_brief_written("today", rel, cited_paths, by_section)
    except Exception:
        pass
    if _brief_push_to_whatsapp(f"Evening {date_label}", str(rel), narrative):
        if not plain:
            console.print("[dim]→ enviado a WhatsApp[/dim]")


# ── DEAD NOTES (rag dead) ────────────────────────────────────────────────────
# Candidates for archive: notes with 0 graph edges + never retrieved + old mtime.
# Pure Python. Surfaces candidates only — never moves/deletes.


def _note_created_ts(raw: str, mtime: float) -> float:
    """Best-effort creation timestamp for a note. iCloud sync bumps mtimes
    constantly, so mtime-only age is noisy. Prefer frontmatter `created:` when
    parseable, fall back to mtime.
    """
    if not raw.startswith("---"):
        return mtime
    fm = parse_frontmatter(raw)
    for key in ("created", "date"):
        v = fm.get(key)
        if not v:
            continue
        s = str(v).strip().strip("'\"")
        for fmt in ("%Y-%m-%dT%H:%M:%S", "%Y-%m-%d %H:%M:%S", "%Y-%m-%d"):
            try:
                return datetime.strptime(s[:len(fmt) + 2].rstrip("Z"), fmt).timestamp()
            except ValueError:
                continue
        try:
            return datetime.fromisoformat(s).timestamp()
        except ValueError:
            continue
    return mtime


def find_dead_notes(
    col: SqliteVecCollection,
    vault: Path,
    query_log: Path,
    min_age_days: int = 365,
    query_window_days: int = 180,
    exclude_folders: tuple[str, ...] = (
        "00-Inbox", "04-Archive",
    ),
    use_frontmatter_date: bool = True,
) -> list[dict]:
    """Dead-note candidates. AND of: 0 outlinks + 0 backlinks + not retrieved
    in `query_window_days` + age > `min_age_days` + outside `exclude_folders`.

    Age source: frontmatter `created:` if present (more reliable in iCloud
    vaults where sync constantly bumps mtime), else mtime. Disable with
    `use_frontmatter_date=False`.

    Audit 2026-04-26 (BUG #11): pre-fix leía `queries.jsonl` (param
    `query_log`) que post-T10 (2026-04-19) está casi vacío de eventos
    `cmd=query` reales — solo recibe `conversation_turn_written` desde
    el split de telemetría. `retrieved_paths` quedaba vacío → cualquier
    nota retrieved en últimos 180d pasaba el filtro AND como dead
    candidate → `rag archive --apply` archivaba notas que el user usó
    en la última semana. CRÍTICO. Fix: leer SQL `rag_queries` directamente.
    """
    from datetime import timedelta as _td
    corpus = _load_corpus(col)
    title_to_paths = corpus["title_to_paths"]
    paths_with_outlinks = {
        p for p, links in corpus["outlinks"].items() if links
    }
    backlinked_paths: set[str] = set()
    for title, sources in corpus["backlinks"].items():
        if sources:
            backlinked_paths.update(title_to_paths.get(title, set()))

    retrieved_paths: set[str] = set()
    cutoff_iso = (datetime.now() - _td(days=query_window_days)).isoformat(timespec="seconds")
    try:
        with _ragvec_state_conn() as _conn:
            for (paths_json,) in _conn.execute(
                "SELECT paths_json FROM rag_queries "
                "WHERE ts >= ? AND paths_json IS NOT NULL AND paths_json <> ''",
                (cutoff_iso,),
            ):
                try:
                    paths = json.loads(paths_json) if paths_json else []
                except Exception:
                    continue
                if isinstance(paths, list):
                    for p in paths:
                        if isinstance(p, str) and p:
                            retrieved_paths.add(p)
    except Exception as _exc:
        try:
            _silent_log("find_dead_notes_sql_read_failed", _exc)
        except Exception:
            pass

    files_info: dict[str, tuple[float, float]] = {}  # rel → (age_ts, mtime)
    if vault.is_dir():
        for p in vault.rglob("*.md"):
            try:
                rel = str(p.relative_to(vault))
            except ValueError:
                continue
            if is_excluded(rel):
                continue
            try:
                mtime = p.stat().st_mtime
            except OSError:
                continue
            age_ts = mtime
            if use_frontmatter_date:
                try:
                    raw = p.read_text(encoding="utf-8", errors="ignore")
                    age_ts = _note_created_ts(raw, mtime)
                except OSError:
                    pass
            files_info[rel] = (age_ts, mtime)

    age_cutoff = datetime.now().timestamp() - (min_age_days * 86400)
    candidates: list[dict] = []
    for rel, (age_ts, mtime) in files_info.items():
        if any(
            rel == ex or rel.startswith(ex.rstrip("/") + "/")
            for ex in exclude_folders
        ):
            continue
        if age_ts >= age_cutoff:
            continue
        if rel in paths_with_outlinks:
            continue
        if rel in backlinked_paths:
            continue
        if rel in retrieved_paths:
            continue
        age_days = int((datetime.now().timestamp() - age_ts) // 86400)
        candidates.append({
            "path": rel,
            "age_days": age_days,
            "mtime": datetime.fromtimestamp(mtime).isoformat(timespec="seconds"),
            "age_source": "frontmatter" if age_ts != mtime else "mtime",
        })
    candidates.sort(key=lambda r: -r["age_days"])
    return candidates


# ── WAKE-UP PACK (rag wake-up) ─────────────────────────────────────────────
# Orquestador "todo en uno" pensado para correr via launchd a las 04:00:
# cuando el user se despierta, todo está fresco — ETLs corridos, vault
# reindexado, caches limpios, radares actualizados, brief matutino
# pre-renderizado en 04-Archive/99-obsidian-system/99-AI/reviews/, y el chat model cargado en RAM con
# keep_alive=-1 para que el primer `rag chat` responda sin cold-start.
#
# Cada paso es independiente: si `rag maintenance` falla, `rag morning`
# igual corre. Al final imprime un resumen con qué pasó y exit code
# non-zero si algún paso falló (para que launchd lo registre en
# `last exit code` y aparezca rojo en la /status page).
#
# No reemplaza los plists individuales (morning 07:00, maintenance 03:30,
# patterns domingo 20:00, emergent viernes 10:00) — solo los amortigua.
# Si la Mac estaba en sleep a alguna de esas horas y launchd no pudo
# disparar el job, el wake-up lo re-ejecuta a las 04:00. Lo contrario
# también: si el user reinstala y no corrió morning desde los plists,
# wake-up se encarga.


@cli.command(name="wake-up")
@click.option("--dry-run", is_flag=True,
              help="Reportar los pasos sin ejecutar nada")
@click.option("--skip-index", is_flag=True,
              help="Saltear `rag index` (ETLs + reindex)")
@click.option("--skip-bookmarks", is_flag=True,
              help="Saltear `rag bookmarks sync` (Chrome bookmarks). "
                   "Nota: `rag index` ya los sincroniza automáticamente "
                   "desde 2026-04-25 — este paso es redundante por default "
                   "pero queda explícito para que se vea en el log y para "
                   "cubrir el caso `--skip-index`.")
@click.option("--skip-wa-tasks", is_flag=True,
              help="Saltear `rag wa-tasks` (action items de WhatsApp al Inbox)")
@click.option("--skip-maintenance", is_flag=True,
              help="Saltear `rag maintenance`")
@click.option("--skip-radars", is_flag=True,
              help="Saltear `rag patterns` + `rag emergent`")
@click.option("--skip-brief", is_flag=True,
              help="Saltear pre-render de `rag morning`")
@click.option("--skip-warmup", is_flag=True,
              help="Saltear el Ollama warmup")
@click.pass_context
def wake_up(ctx, dry_run: bool, skip_index: bool, skip_bookmarks: bool,
            skip_wa_tasks: bool, skip_maintenance: bool, skip_radars: bool,
            skip_brief: bool, skip_warmup: bool):
    """Wake-up pack: traé todo fresco antes de despertarte.

    Orquesta en este orden (cada paso es independiente — si uno falla,
    los demás siguen):

    \b
      1. `rag index`           — ETLs de todas las fuentes + reindex del vault.
      2. `rag bookmarks sync`  — Chrome bookmarks → sub-índice URLs (rag links).
      3. `rag wa-tasks`        — extractor de action items de WhatsApp al Inbox.
      4. `rag maintenance`     — WAL checkpoint, rotación de logs, cleanup.
      5. `rag patterns`        — radar de feedback dominante.
      6. `rag emergent`        — radar de temas emergentes en queries.
      7. `rag morning`         — brief matutino pre-renderizado a 04-Archive/99-obsidian-system/99-AI/reviews/.
      8. Ollama warmup         — carga el chat model con keep_alive=-1.

    Nota sobre bookmarks: `rag index` ya los sincroniza automáticamente
    como parte del pre-sync cross-source desde 2026-04-25. El paso 2
    (`rag bookmarks sync`) está acá por dos razones: (a) queda visible
    en el log del wake-up — sino se "esconde" dentro de los logs de
    `rag index`; (b) cubre el caso `--skip-index`, donde igual querés
    refrescar bookmarks sin reindexar todo el vault. El costo es ~100ms
    de duplicación cuando ambos corren (idempotente, segunda corrida
    es no-op por hash-skip).

    Pensado para launchd a las 04:00 — `rag setup` instala el plist.
    Exit code != 0 si algún paso falla (launchd lo marca rojo).

    Flags de skip útiles para debug o cuando un subsistema específico
    está roto y querés correr el resto igual.
    """
    # `wa_tasks` se carga al final de rag/__init__.py (línea ~51565), después
    # de la definición de wake_up. Lazy import para evitar el orden de import.
    from rag.wa_tasks import wa_tasks as wa_tasks_cmd

    steps: list[tuple[str, object, dict]] = []
    if not skip_index:
        # Defaults matchean los que usa el plist `com.fer.obsidian-rag-ingest-*`
        # y el flow normal de `rag index`: incremental, contradictions ON,
        # sin --source (= vault + todos los pre-syncs cross-source).
        steps.append(("rag index", index, dict(
            reset=False, no_contradict=False, source_opt=None,
            since_opt=None, dry_run=False, max_chats=None, vault_scope=None,
        )))
    if not skip_bookmarks:
        # `profile=None` = sincroniza todos los Chrome profiles registrados.
        # Idempotente: si ya corrió en `rag index` el hash-skip lo deja en no-op.
        steps.append(("rag bookmarks sync", bookmarks_sync, dict(profile=None)))
    if not skip_wa_tasks:
        # `hours=None` = ventana incremental desde último run (state file).
        # `force=False` = no reprocesa mensajes ya procesados.
        # `dry_run=False` = escribe `00-Inbox/WA-YYYY-MM-DD.md` si hay items.
        # Es idempotente con el cron de 30min (`com.fer.obsidian-rag-wa-tasks`):
        # la segunda corrida del día desde el cron es no-op si esta ya procesó
        # los mensajes nuevos.
        steps.append(("rag wa-tasks", wa_tasks_cmd, dict(
            dry_run=False, hours=None, force=False,
        )))
    if not skip_maintenance:
        # skip_reindex=True porque `rag index` ya corrió arriba. El resto
        # (WAL, logs, dead, orphan HNSW) sí queremos.
        steps.append(("rag maintenance", maintenance, dict(
            dry_run=False, skip_reindex=True, skip_logs=False, verbose=False,
            as_json=False, rollback_state=False, validate_cutover=False,
            force=False,
        )))
    if not skip_radars:
        # patterns/emergent escriben notas al vault si detectan algo
        # relevante; push=False para no mandar WhatsApp en mute hours.
        steps.append(("rag patterns", patterns, dict(
            last=500, min_share=0.30, dry_run=False, push=False,
        )))
        steps.append(("rag emergent", emergent, dict(
            days=7, min_size=5, threshold=0.35, dry_run=False, push=False,
        )))
    if not skip_brief:
        steps.append(("rag morning", morning, dict(
            dry_run=False, date_opt=None, lookback_hours=36,
        )))

    total_steps = len(steps) + (0 if skip_warmup else 1)
    succeeded: list[str] = []
    failed: list[tuple[str, str]] = []

    total_start = time.perf_counter()
    console.print()
    console.print(Rule(title=f"[bold cyan]wake-up[/bold cyan] · "
                       f"{total_steps} pasos",
                       style="cyan"))

    for i, (label, fn, kwargs) in enumerate(steps, 1):
        console.print()
        console.print(f"[bold cyan]▶ [{i}/{total_steps}][/bold cyan] {label}")
        if dry_run:
            console.print("  [dim]dry-run: skippeado[/dim]")
            continue
        step_start = time.perf_counter()
        try:
            ctx.invoke(fn, **kwargs)
            ms = int((time.perf_counter() - step_start) * 1000)
            succeeded.append(f"{label} ({ms}ms)")
        except SystemExit as e:
            # Click commands raise SystemExit en error paths. Mapeamos
            # a "failed step" pero seguimos con el resto.
            ms = int((time.perf_counter() - step_start) * 1000)
            code = e.code if e.code is not None else 0
            if code == 0:
                succeeded.append(f"{label} ({ms}ms)")
            else:
                failed.append((label, f"exit {code} ({ms}ms)"))
        except Exception as e:
            ms = int((time.perf_counter() - step_start) * 1000)
            failed.append((label, f"{type(e).__name__}: {e} ({ms}ms)"))
            console.print(f"  [red]✗[/red] {type(e).__name__}: {e}")

    if not skip_warmup:
        idx = len(steps) + 1
        console.print()
        console.print(f"[bold cyan]▶ [{idx}/{total_steps}][/bold cyan] ollama warmup")
        if dry_run:
            console.print("  [dim]dry-run: skippeado[/dim]")
        else:
            step_start = time.perf_counter()
            try:
                model = resolve_chat_model()
                # Tiny prompt — solo trigger del model load + keep_alive=-1.
                # qwen2.5:7b carga en ~3-5s en M3 Max. Con keep_alive=-1
                # queda en RAM hasta que ollama lo desaloje por presión
                # de memoria o restart. El primer `rag chat` post-wake-up
                # no paga el cold-start (~400ms de prefill vs. 5s cold).
                ollama.chat(
                    model=model,
                    messages=[{"role": "user", "content": "."}],
                    options=CHAT_OPTIONS,
                    keep_alive=-1,
                )
                ms = int((time.perf_counter() - step_start) * 1000)
                succeeded.append(f"ollama warmup · {model} ({ms}ms)")
                console.print(f"  [green]✓[/green] {model} caliente "
                              f"(keep_alive=-1, {ms}ms)")
            except Exception as e:
                ms = int((time.perf_counter() - step_start) * 1000)
                failed.append(("ollama warmup",
                               f"{type(e).__name__}: {e} ({ms}ms)"))
                console.print(f"  [red]✗[/red] {type(e).__name__}: {e}")

    total_ms = int((time.perf_counter() - total_start) * 1000)
    console.print()
    style = "green" if not failed else "yellow"
    verdict = "OK" if not failed else f"{len(failed)} falló(s)"
    console.print(Rule(
        title=f"[bold]wake-up done[/bold] · {verdict} · "
              f"{len(succeeded)} ok · {total_ms}ms",
        style=style,
    ))
    if failed:
        console.print()
        console.print("[yellow]Fallaron:[/yellow]")
        for label, reason in failed:
            console.print(f"  · [bold]{label}[/bold]: {reason}")
        # Exit non-zero para que launchd registre el fallo en
        # `last exit code` → aparece rojo en la /status page.
        raise SystemExit(1)


# ── EPISODIC MEMORY — PHASE 2 CONSOLIDATION (rag consolidate) ───────────────
# Promotes recurring conversation clusters from
# 04-Archive/99-obsidian-system/99-AI/conversations/ into PARA and
# archives the originals. All heavy lifting lives in
# scripts/consolidate_conversations.py — this is just the CLI shim so the
# command shows up in `rag --help` + the weekly launchd service can invoke
# it as `rag consolidate`. See plans/episodic-memory.md for rationale.


@cli.command()
@click.option("--window-days", default=14, show_default=True,
              help="Conversaciones a considerar (por mtime)")
@click.option("--threshold", default=0.75, show_default=True,
              help="Cosine mínimo para agrupar (0.0–1.0)")
@click.option("--min-cluster", default=3, show_default=True,
              help="Tamaño mínimo de cluster para promover")
@click.option("--apply", is_flag=True,
              help="Escribir cambios al vault (default: dry-run)")
@click.option("--json", "as_json", is_flag=True,
              help="Emitir summary como JSON (para servicios / scripts)")
def consolidate(window_days: int, threshold: float, min_cluster: int,
                apply: bool, as_json: bool):
    """Agrupar conversaciones relacionadas y promover a PARA (Phase 2).

    Por default es dry-run — pasá --apply para escribir al vault.

    Barre `04-Archive/99-obsidian-system/99-AI/conversations/` buscando clusters semánticamente similares
    (embedding cosine ≥ --threshold, tamaño ≥ --min-cluster) en la ventana
    de --window-days. Cada cluster se sintetiza en una sola nota consolidada
    (qwen2.5:7b default) y se promueve a `01-Projects/` o `03-Resources/`
    según un clasificador de intención (verbos de acción + fechas → project,
    resto → resource). Los originales se archivan en
    `04-Archive/conversations/YYYY-MM/` (excluido del índice).

    Corre semanalmente via launchd (Lunes 06:00) — instalable con `rag setup`.
    El plist generado incluye --apply; re-corré `rag setup` si actualizaste.
    """
    dry_run = not apply  # invertimos: --apply activa, default es dry-run
    from scripts.consolidate_conversations import run as _run
    summary = _run(
        window_days=window_days,
        threshold=threshold,
        min_cluster=min_cluster,
        dry_run=dry_run,
    )
    if as_json:
        click.echo(json.dumps(summary, ensure_ascii=False, indent=2))
        return
    prefix = "[dry-run] " if dry_run else ""
    console.print(
        f"{prefix}{summary['n_conversations']} conversaciones en ventana · "
        f"{summary['n_clusters']} clusters · "
        f"[green]{summary['n_promoted']}[/green] promovidos · "
        f"{summary['n_archived']} archivados · "
        f"[dim]{summary['duration_s']}s[/dim]"
    )
    for c in summary["clusters"]:
        size = c.get("size", 0)
        target = c.get("target", "?")
        title = c.get("title", "(sin título)")
        if "error" in c:
            console.print(
                f"  [red]✗[/red] [{size}] {target}: {title} — "
                f"[dim]{c['error']}[/dim]"
            )
        elif dry_run:
            console.print(f"  [yellow]→[/yellow] [{size}] {target}: {title}")
        else:
            console.print(f"  [green]✓[/green] [{size}] {target}: {title}")


# ── VAULT TRANSIENT CLEANUP (rag vault-cleanup) ─────────────────────────────
# El vault Obsidian acumula carpetas de "sistema" (outputs de scripts, chat
# transcripts, drafts de commit msg, exports auto-regenerados) bajo
# `04-Archive/99-obsidian-system/99-AI/`. `is_excluded()` ya filtra ese
# subtree del indexado del RAG, pero los archivos siguen ocupando espacio +
# ensucian el graph view + las búsquedas full-text del Obsidian nativo.
# Este command los purga moviéndolos al `.trash/` del vault (reversible).
# Heavy lifting en `scripts/cleanup_vault_transient.py` — ver docstring ahí
# para la tabla de políticas por carpeta. Daemon diario via launchd a 02:00.


@cli.command(name="vault-cleanup")
@click.option("--dry-run", is_flag=True,
              help="Simular sin mover archivos")
@click.option("--json", "as_json", is_flag=True,
              help="Emitir summary como JSON (para servicios/scripts)")
def vault_cleanup_cmd(dry_run: bool, as_json: bool):
    """Mover archivos transitorios del vault al `.trash/`.

    Carpetas bajo `04-Archive/99-obsidian-system/99-AI/` con TTLs por
    política: `tmp/` 7d · `conversations/` 30d · `sessions/` 30d ·
    `Wiki/` wipe total · `plans/` 180d · `system/<slug>/` 180d ·
    `reviews/` 365d. `memory/` y `skills/` están en whitelist (intactos).
    Files se mueven a `<vault>/.trash/` (Obsidian convention) — recuperables
    hasta vaciar la papelera de Obsidian.

    Corre diario via launchd a 02:00 — instalable con `rag setup`.
    """
    from scripts.cleanup_vault_transient import run as _run, _print_human
    summary = _run(dry_run=dry_run)
    if as_json:
        click.echo(json.dumps(summary, ensure_ascii=False, indent=2))
    else:
        _print_human(summary)
    if not summary.get("ok", False):
        raise SystemExit(1)


@cli.command()
@click.option("--min-age-days", default=365, show_default=True,
              help="Edad mínima por mtime")
@click.option("--query-window-days", default=180, show_default=True,
              help="Ventana para considerar que una nota 'fue usada' en queries")
@click.option("--limit", default=50, show_default=True,
              help="Cap del listado")
@click.option("--folder", default=None, help="Acotar a una subcarpeta")
@click.option("--plain", is_flag=True, help="Salida plana (path por línea)")
def dead(min_age_days: int, query_window_days: int, limit: int,
         folder: str | None, plain: bool):
    """Listar notas candidatas a archivar (dead code del vault).

    Criterio AND: 0 outlinks + 0 backlinks + no recuperada en N días +
    mtime > N días + fuera de Inbox/Archive/Reviews. No borra nada.
    """
    col = get_db()
    t0 = time.perf_counter()
    items = find_dead_notes(
        col, VAULT_PATH, LOG_PATH,
        min_age_days=min_age_days,
        query_window_days=query_window_days,
    )
    if folder:
        prefix = folder.rstrip("/") + "/"
        items = [
            it for it in items
            if it["path"] == folder or it["path"].startswith(prefix)
        ]
    items = items[:limit]

    log_query_event({
        "cmd": "dead", "min_age_days": min_age_days,
        "query_window_days": query_window_days,
        "folder": folder, "n_candidates": len(items),
        "timing": _round_timing_ms({"total_ms": (time.perf_counter() - t0) * 1000}),
    })

    if not items:
        msg = "Sin candidatos a dead notes."
        click.echo(msg) if plain else console.print(f"[green]{msg}[/green]")
        return
    if plain:
        for it in items:
            click.echo(f"{it['age_days']}d\t{it['path']}")
        return
    console.print()
    console.print(Rule(
        title=f"[bold yellow]🪦 {len(items)} nota(s) candidatas a archivar[/bold yellow]",
        style="yellow",
    ))
    tbl = Table(show_header=True, header_style="bold", box=None, pad_edge=False)
    tbl.add_column("edad", style="yellow", justify="right")
    tbl.add_column("última modif", style="dim")
    tbl.add_column("path", style="cyan")
    for it in items:
        tbl.add_row(f"{it['age_days']}d", it["mtime"][:10], it["path"])
    console.print(tbl)
    console.print(
        "\n[dim]Criterio AND: 0 outlinks · 0 backlinks · "
        f"no recuperada en {query_window_days}d · mtime > {min_age_days}d.[/dim]"
    )


# ── ARCHIVER (rag archive) ───────────────────────────────────────────────────
# Cyclical cleanup: mueve las notas detectadas por `find_dead_notes` a
# `04-Archive/` preservando la jerarquía PARA original (01-Projects/X/nota.md
# → 04-Archive/01-Projects/X/nota.md). Frontmatter stamp archived_at /
# archived_from / archived_reason para que el move sea reversible. Gate de
# confirmación si hay más de N candidatos (evita masacres silenciosas cuando
# la ventana o la edad afloja). Reusa el detector de `rag dead` — mismos
# criterios AND (0 outlinks + 0 backlinks + no retrieved + age > N + fuera
# de Inbox/Archive/Reviews). Opt-out por nota con `archive: never` o
# `type: moc|index|permanent` en frontmatter.

_ARCHIVE_ROOT = "04-Archive"
ARCHIVE_GATE_DEFAULT = 20
ARCHIVE_LOG_PATH = Path.home() / ".local/share/obsidian-rag/archive.jsonl"
_ARCHIVE_OPT_OUT_TYPES = ("moc", "index", "permanent")


def _archive_target_path(src_rel: str) -> str:
    """Mirror source path under 04-Archive/. Preserves the PARA folder below
    the root so `01-Projects/app-X/nota.md` lands at
    `04-Archive/01-Projects/app-X/nota.md`. Already-archived paths are
    returned unchanged (detector should skip them anyway).
    """
    if src_rel.startswith(_ARCHIVE_ROOT + "/") or src_rel == _ARCHIVE_ROOT:
        return src_rel
    return f"{_ARCHIVE_ROOT}/{src_rel}"


def _archive_resolve_collision(vault: Path, dst_rel: str) -> str:
    """If destination exists, append `-archived-YYYY-MM` to the stem. Walks
    a counter if that variant also collides (rare).
    """
    dst = vault / dst_rel
    if not dst.exists():
        return dst_rel
    parent_rel = str(Path(dst_rel).parent)
    stem = Path(dst_rel).stem
    suffix = Path(dst_rel).suffix
    tag = datetime.now().strftime("%Y-%m")
    for i in range(1, 50):
        extra = f"-archived-{tag}" if i == 1 else f"-archived-{tag}-{i}"
        candidate = f"{parent_rel}/{stem}{extra}{suffix}" if parent_rel != "." else f"{stem}{extra}{suffix}"
        if not (vault / candidate).exists():
            return candidate
    return dst_rel  # give up; caller will fail explicitly on the move


def _is_archive_opt_out(raw: str) -> bool:
    """True if the note frontmatter opts out of archiving via `archive: never`
    or `type: moc|index|permanent`. Permanent-knowledge notes (MOCs, indexes,
    evergreen references) shouldn't die just for lacking edits.

    `type:` may be a scalar (`type: moc`) or a list (`type: [moc, reference]`).
    Both forms are honored — list form was silently unmatched before because
    stringifying the list yielded `"['moc', 'reference']"`.
    """
    fm = parse_frontmatter(raw)
    if str(fm.get("archive", "")).strip().lower() == "never":
        return True
    raw_type = fm.get("type")
    if isinstance(raw_type, list):
        types = [str(x).strip().lower() for x in raw_type]
    else:
        types = [str(raw_type or "").strip().lower()]
    return any(t in _ARCHIVE_OPT_OUT_TYPES for t in types)


def _archive_stamp_frontmatter(raw: str, orig_rel: str,
                                reason: str = "dead") -> str:
    """Inject `archived_at / archived_from / archived_reason` into the
    frontmatter. Creates a fresh YAML block if the note has none. Idempotent:
    re-stamping overwrites prior archived_* fields.
    """
    today = datetime.now().strftime("%Y-%m-%d")
    stamps = {
        "archived_at": today,
        "archived_from": orig_rel,
        "archived_reason": reason,
    }
    if raw.startswith("---\n"):
        end = raw.find("\n---\n", 4)
        if end >= 0:
            fm_text = raw[4:end]
            rest = raw[end + 5:]
            kept_lines: list[str] = []
            for line in fm_text.splitlines():
                key = line.split(":", 1)[0].strip()
                if key in stamps:
                    continue  # drop prior stamp; we're rewriting
                kept_lines.append(line)
            extra = "\n".join(f"{k}: {v}" for k, v in stamps.items())
            body = "\n".join(kept_lines).rstrip()
            block = f"{body}\n{extra}" if body else extra
            return f"---\n{block}\n---\n{rest}"
    # No frontmatter (or malformed): prepend a fresh one.
    fresh = "\n".join(f"{k}: {v}" for k, v in stamps.items())
    return f"---\n{fresh}\n---\n\n{raw}"


def _open_archive_batch() -> Path:
    """One-batch-per-run audit log for rollback. Lives alongside filing
    batches but with an `archive-` prefix so `rag file --undo` doesn't pick
    it up accidentally.
    """
    FILING_BATCHES_DIR.mkdir(parents=True, exist_ok=True)
    ts = datetime.now().strftime("%Y%m%d-%H%M%S")
    path = FILING_BATCHES_DIR / f"archive-{ts}.jsonl"
    path.touch()
    return path


def _append_archive_batch(batch_path: Path, entry: dict) -> None:
    with batch_path.open("a", encoding="utf-8") as f:
        f.write(json.dumps(entry, ensure_ascii=False) + "\n")
        f.flush()
        os.fsync(f.fileno())


def _log_archive_event(event: dict) -> None:
    e = {"ts": datetime.now().isoformat(timespec="seconds"), **event}

    def _do() -> None:
        with _ragvec_state_conn() as conn:
            _sql_append_event(conn, "rag_archive_log",
                               _map_archive_row(e))
    _sql_write_with_retry(_do, "archive_sql_write_failed")


def _archive_move_one(
    col: "SqliteVecCollection", src_rel: str, dst_rel: str,
) -> dict:
    """Move a single note. Stamps frontmatter in place FIRST (so the moved
    file carries the stamp), then `shutil.move`, then two reindex calls:
    old path (now gone → sqlite-vec deletes its chunks) + new path (fresh chunks
    under the new `file=` metadata key).
    """
    import shutil
    src = (VAULT_PATH / src_rel).resolve()
    src.relative_to(VAULT_PATH.resolve())
    if not src.is_file():
        raise FileNotFoundError(src_rel)
    dst = (VAULT_PATH / dst_rel).resolve()
    dst.relative_to(VAULT_PATH.resolve())
    if dst.exists():
        raise FileExistsError(dst_rel)
    raw = src.read_text(encoding="utf-8", errors="ignore")
    stamped = _archive_stamp_frontmatter(raw, src_rel)
    src.write_text(stamped, encoding="utf-8")
    dst.parent.mkdir(parents=True, exist_ok=True)
    shutil.move(str(src), str(dst))
    # Clean old path from sqlite-vec + add new path. Both best-effort — the next
    # full `rag index` would converge regardless.
    try:
        _index_single_file(col, src, skip_contradict=True)
    except Exception:
        pass
    try:
        _index_single_file(col, dst, skip_contradict=True)
    except Exception:
        pass
    return {
        "src": src_rel,
        "dst": dst_rel,
        "ts": datetime.now().isoformat(timespec="seconds"),
    }


def archive_dead_notes(
    col: "SqliteVecCollection",
    vault: Path,
    candidates: list[dict],
    apply: bool,
    force: bool,
    gate: int = ARCHIVE_GATE_DEFAULT,
) -> dict:
    """Plan (and optionally execute) the archive moves. Pure function — takes
    precomputed candidates from `find_dead_notes`. Returns:
        {"plan": [...], "applied": [...], "skipped": [...], "gated": bool,
         "batch_path": str | None}
    """
    plan: list[dict] = []
    skipped: list[dict] = []
    seen_dst: set[str] = set()
    for c in candidates:
        src_rel = c["path"]
        src_full = vault / src_rel
        if not src_full.is_file():
            skipped.append({"path": src_rel, "reason": "missing"})
            continue
        try:
            raw = src_full.read_text(encoding="utf-8", errors="ignore")
        except OSError:
            skipped.append({"path": src_rel, "reason": "unreadable"})
            continue
        if _is_archive_opt_out(raw):
            skipped.append({"path": src_rel, "reason": "opt-out"})
            continue
        dst_rel = _archive_target_path(src_rel)
        if dst_rel == src_rel:
            skipped.append({"path": src_rel, "reason": "already-archived"})
            continue
        dst_rel = _archive_resolve_collision(vault, dst_rel)
        # Collision across this same batch (two src stems mapping to the same
        # dst after suffixing) — add a second suffix to the later one.
        if dst_rel in seen_dst:
            stem = Path(dst_rel).stem
            suffix = Path(dst_rel).suffix
            parent_rel = str(Path(dst_rel).parent)
            for i in range(2, 50):
                tag = datetime.now().strftime("%Y-%m")
                candidate = (
                    f"{parent_rel}/{stem}-{i}{suffix}" if parent_rel != "."
                    else f"{stem}-{i}{suffix}"
                )
                if candidate not in seen_dst and not (vault / candidate).exists():
                    dst_rel = candidate
                    break
        seen_dst.add(dst_rel)
        plan.append({
            "src": src_rel, "dst": dst_rel,
            "age_days": c.get("age_days", 0),
        })

    gated = apply and bool(plan) and not force and len(plan) > gate
    applied: list[dict] = []
    batch_path: Path | None = None
    if apply and not gated and plan:
        batch_path = _open_archive_batch()
        for entry in plan:
            try:
                result = _archive_move_one(col, entry["src"], entry["dst"])
                result["age_days"] = entry["age_days"]
                _append_archive_batch(batch_path, result)
                applied.append(result)
            except Exception as e:
                skipped.append({"path": entry["src"], "reason": str(e)})
    return {
        "plan": plan,
        "applied": applied,
        "skipped": skipped,
        "gated": gated,
        "batch_path": str(batch_path) if batch_path else None,
    }


def _render_archive_result(result: dict, apply: bool, plain: bool) -> None:
    plan = result["plan"]
    applied = result["applied"]
    skipped = result["skipped"]
    gated = result["gated"]

    if plain:
        for e in (applied if apply and not gated else plan):
            click.echo(f"{e['src']}\t→\t{e['dst']}")
        return

    if not plan and not skipped:
        console.print("[green]Sin candidatos a archivar.[/green]")
        return

    title = (
        f"[bold yellow]📦 {len(plan)} nota(s) a archivar"
        f"{' (dry-run)' if not apply else ''}[/bold yellow]"
    )
    console.print()
    console.print(Rule(title=title, style="yellow"))

    if plan:
        tbl = Table(show_header=True, header_style="bold", box=None, pad_edge=False)
        tbl.add_column("edad", style="yellow", justify="right")
        tbl.add_column("origen", style="cyan")
        tbl.add_column("→", style="dim")
        tbl.add_column("destino", style="magenta")
        for e in plan:
            tbl.add_row(
                f"{e['age_days']}d",
                e["src"],
                "→",
                e["dst"],
            )
        console.print(tbl)

    if gated:
        console.print(
            f"\n[yellow]⚠ Gate activo[/yellow]: {len(plan)} > gate. "
            "Corré con [bold]--force[/bold] para aplicar (o achicá la ventana)."
        )
    elif apply:
        console.print(
            f"\n[green]✓[/green] Aplicados: {len(applied)}. "
            f"Batch log: [dim]{result.get('batch_path') or '—'}[/dim]"
        )

    if skipped:
        console.print(
            f"\n[dim]{len(skipped)} skipped — "
            + ", ".join(f"{s['reason']}" for s in skipped[:5])
            + (" …" if len(skipped) > 5 else "")
            + "[/dim]"
        )


def _write_archive_report(result: dict, apply: bool) -> Path | None:
    """Write a human-readable Markdown report to 04-Archive/99-obsidian-system/99-AI/reviews/YYYY-MM-archive.md.
    Appends a dated section if the file already exists (monthly cadence can
    hit the same file twice if triggered manually between cycles).
    """
    plan = result["plan"]
    skipped = result["skipped"]
    if not plan and not skipped:
        return None
    reviews_dir = VAULT_PATH / "04-Archive/99-obsidian-system/99-AI/reviews"
    reviews_dir.mkdir(parents=True, exist_ok=True)
    ym = datetime.now().strftime("%Y-%m")
    path = reviews_dir / f"{ym}-archive.md"
    header = (
        f"\n\n## {datetime.now().strftime('%Y-%m-%d %H:%M')} — "
        f"{'apply' if apply and not result['gated'] else 'dry-run'}\n\n"
    )
    lines = [header]
    if plan:
        lines.append(f"**{len(plan)} nota(s) planeadas:**\n")
        for e in plan:
            lines.append(f"- `{e['src']}` → `{e['dst']}` ({e['age_days']}d)")
        lines.append("")
    if result["gated"]:
        lines.append("> ⚠ Gate activo — no se aplicó. Revisá y corré `rag archive --apply --force`.\n")
    elif apply:
        lines.append(f"**Aplicadas**: {len(result['applied'])}")
        if result.get("batch_path"):
            lines.append(f"**Batch log**: `{result['batch_path']}`")
        lines.append("")
    if skipped:
        lines.append(f"**{len(skipped)} skipped:**\n")
        for s in skipped[:20]:
            lines.append(f"- `{s['path']}` — {s['reason']}")
        if len(skipped) > 20:
            lines.append(f"- _… {len(skipped) - 20} más_")
    body = "\n".join(lines) + "\n"
    if path.is_file():
        existing = path.read_text(encoding="utf-8")
        path.write_text(existing + body, encoding="utf-8")
    else:
        frontmatter = (
            "---\n"
            f"type: archive-report\n"
            f"created: {datetime.now().isoformat(timespec='seconds')}\n"
            "tags:\n- archive\n- review\n"
            "---\n\n"
            f"# Archive report — {ym}\n"
        )
        path.write_text(frontmatter + body, encoding="utf-8")
    return path


def _push_archive_notification(result: dict, apply: bool) -> bool:
    """Fire-and-forget WhatsApp push via the ambient bridge. Silently no-ops
    if ambient isn't configured. Message is compact: counts + top-3 folders.
    """
    cfg = _ambient_config()
    if cfg is None:
        return False
    plan = result["plan"]
    if not plan and not result["skipped"]:
        return False
    from collections import Counter
    folder_counts = Counter(str(Path(e["src"]).parent) for e in plan)
    top = folder_counts.most_common(3)
    verb = "archivadas" if apply and not result["gated"] else "candidatas"
    lines = [f"📦 *Archive* — {len(plan)} {verb}"]
    if result["gated"]:
        lines.append(f"⚠ gate activo (> {ARCHIVE_GATE_DEFAULT}) — revisar y correr `rag archive --apply --force`")
    elif apply:
        lines.append(f"✓ aplicadas: {len(result['applied'])}")
    if top:
        lines.append("\nPor carpeta:")
        for folder, n in top:
            lines.append(f"• `{folder}` — {n}")
    if result["skipped"]:
        lines.append(f"\n_{len(result['skipped'])} skipped_")
    msg = "\n".join(lines)
    sent = _ambient_whatsapp_send(cfg["jid"], msg)
    _ambient_log_event({
        "cmd": "archive_push",
        "n_plan": len(plan),
        "n_applied": len(result["applied"]),
        "gated": result["gated"],
        "whatsapp_sent": sent,
    })
    return sent


@cli.command()
@click.option("--min-age-days", default=365, show_default=True,
              help="Edad mínima (frontmatter created: preferido, mtime fallback)")
@click.option("--query-window-days", default=180, show_default=True,
              help="Ventana para considerar que una nota 'fue usada' en queries")
@click.option("--folder", default=None, help="Acotar a una subcarpeta")
@click.option("--limit", default=100, show_default=True,
              help="Cap absoluto de candidatos procesados en una corrida")
@click.option("--gate", default=ARCHIVE_GATE_DEFAULT, show_default=True,
              help="Si el plan tiene más de N notas, requiere --force para aplicar")
@click.option("--apply", is_flag=True,
              help="Ejecutar moves. Sin este flag es dry-run (default).")
@click.option("--force", is_flag=True, help="Bypass del gate de confirmación")
@click.option("--notify/--no-notify", default=True,
              help="Push a WhatsApp si ambient está configurado")
@click.option("--report/--no-report", default=True,
              help="Escribe reporte a 04-Archive/99-obsidian-system/99-AI/reviews/YYYY-MM-archive.md")
@click.option("--plain", is_flag=True, help="Salida plana (src\\tdst por línea)")
def archive(min_age_days: int, query_window_days: int, folder: str | None,
            limit: int, gate: int, apply: bool, force: bool,
            notify: bool, report: bool, plain: bool):
    """Mover notas muertas a 04-Archive/ preservando la jerarquía PARA.

    Candidatos: los mismos que `rag dead` (0 outlinks + 0 backlinks +
    no retrieved + age > N + fuera de Inbox/Archive/Reviews). Destino:
    `04-Archive/<ruta-original>`. Frontmatter stamp archived_at /
    archived_from / archived_reason para que el move sea reversible.

    Opt-out por nota: frontmatter `archive: never` o `type: moc|index|permanent`.

    Sin --apply: dry-run. Con --apply: aplica si el plan ≤ --gate, si no
    pide --force. Batch log en ~/.local/share/obsidian-rag/filing_batches/.
    """
    col = get_db()
    candidates = find_dead_notes(
        col, VAULT_PATH, LOG_PATH,
        min_age_days=min_age_days,
        query_window_days=query_window_days,
    )
    if folder:
        prefix = folder.rstrip("/") + "/"
        candidates = [
            it for it in candidates
            if it["path"] == folder or it["path"].startswith(prefix)
        ]
    candidates = candidates[:limit]

    if apply:
        with vault_write_lock("archive"):
            result = archive_dead_notes(
                col, VAULT_PATH, candidates,
                apply=True, force=force, gate=gate,
            )
    else:
        result = archive_dead_notes(
            col, VAULT_PATH, candidates,
            apply=False, force=force, gate=gate,
        )

    _log_archive_event({
        "cmd": "archive", "min_age_days": min_age_days,
        "query_window_days": query_window_days, "folder": folder,
        "dry_run": not apply, "force": force, "gate": gate,
        "n_candidates": len(candidates),
        "n_plan": len(result["plan"]),
        "n_applied": len(result["applied"]),
        "n_skipped": len(result["skipped"]),
        "gated": result["gated"],
        "batch_path": result.get("batch_path"),
    })

    _render_archive_result(result, apply=apply, plain=plain)
    if report:
        report_path = _write_archive_report(result, apply=apply)
        if report_path and not plain:
            console.print(
                f"[dim]Reporte: {report_path.relative_to(VAULT_PATH)}[/dim]"
            )
    if notify:
        _push_archive_notification(result, apply=apply)


# ── FOLLOW-UP SCANNER (rag followup) ─────────────────────────────────────────
# Surfaces "open loops" across the vault — things the user said they'd do /
# explore — and classifies each as resolved / stale / activo based on whether
# later notes show semantic evidence of follow-through. Three loop kinds:
# frontmatter todo/due, unchecked markdown checkboxes, and inline imperative
# clauses ("tengo que X", "pendiente Y", "revisar Z"). Resolution check reuses
# `retrieve()` scoped to notes modified AFTER the loop was written; the helper
# LLM acts as a conservative yes/no judge. Never mutates notes — read-only.

FOLLOWUP_STALE_DAYS = 14
FOLLOWUP_RESOLVE_MIN_SCORE = 0.03
_FOLLOWUP_CACHE_TTL = 600.0  # segundos — igual al intervalo del daemon anticipate
_followup_loops_cache: dict | None = None  # {ts: float, max_mtime: float, result: list}
_followup_loops_cache_lock = threading.Lock()

_FOLLOWUP_CHECKBOX_LINE_RE = re.compile(
    r"^\s*[-*]\s*\[[ xX]\][^\n]*", re.MULTILINE,
)

_FOLLOWUP_IMPERATIVE_RE = re.compile(
    r"\b(tengo que|pendiente[:\s]|revisar|explorar|profundizar|chequear)\b"
    r"[\s:]+([^.\n\r]{1,80})",
    re.IGNORECASE,
)
_CHECKBOX_OPEN_RE = re.compile(r"^\s*[-*]\s*\[\s\]\s+(.+?)\s*$", re.MULTILINE)


def _coerce_loop_items(value) -> list[str]:
    """Flatten a frontmatter `todo:` / `due:` value into a list of strings.
    Accepts str, list of str, list of dicts with common keys."""
    if value is None:
        return []
    if isinstance(value, str):
        s = value.strip()
        return [s] if s else []
    if isinstance(value, (int, float)):
        return [str(value)]
    import datetime as _dt
    if isinstance(value, (_dt.date, _dt.datetime)):
        return [value.isoformat()]
    if isinstance(value, list):
        out: list[str] = []
        for item in value:
            if isinstance(item, str):
                s = item.strip()
                if s:
                    out.append(s)
            elif isinstance(item, dict):
                for k in ("text", "task", "title", "item"):
                    if isinstance(item.get(k), str) and item[k].strip():
                        out.append(item[k].strip())
                        break
            elif item is not None:
                out.append(str(item))
        return out
    return []


def _body_without_frontmatter(raw: str) -> tuple[str, int]:
    """Return (body, offset) where `offset` is how many chars of `raw` were
    frontmatter. Preserves line structure of the body for regex scanning."""
    if not raw.startswith("---"):
        return raw, 0
    m = re.match(r"^---\n.*?\n---\n", raw, re.DOTALL)
    if not m:
        return raw, 0
    return raw[m.end():], m.end()


def _extract_followup_loops(
    raw: str, rel_path: str, extracted_ts: float,
) -> list[dict]:
    """Scan one note's raw content and return every open loop found.

    Each loop: {source_note, loop_text, extracted_at (iso), kind}.
    Kinds: "todo" (frontmatter todo/due), "checkbox" (unchecked -[ ]),
    "inline" (imperative regex in body).
    """
    loops: list[dict] = []
    extracted_iso = datetime.fromtimestamp(extracted_ts).isoformat(timespec="seconds")
    fm = parse_frontmatter(raw)
    for key in ("todo", "due"):
        for item in _coerce_loop_items(fm.get(key)):
            loops.append({
                "source_note": rel_path,
                "loop_text": item[:200],
                "extracted_at": extracted_iso,
                "kind": "todo",
            })

    body, _ = _body_without_frontmatter(raw)
    body_no_fences = CODE_FENCE_RE.sub(
        lambda m: "\n" * m.group(0).count("\n"), body,
    )

    for m in _CHECKBOX_OPEN_RE.finditer(body_no_fences):
        text = m.group(1).strip()
        if not text:
            continue
        loops.append({
            "source_note": rel_path,
            "loop_text": text[:200],
            "extracted_at": extracted_iso,
            "kind": "checkbox",
        })

    checkbox_spans = [m.span() for m in _FOLLOWUP_CHECKBOX_LINE_RE.finditer(body_no_fences)]
    def _in_checkbox(pos: int) -> bool:
        return any(s <= pos < e for s, e in checkbox_spans)

    seen_inline: set[str] = set()
    for m in _FOLLOWUP_IMPERATIVE_RE.finditer(body_no_fences):
        if _in_checkbox(m.start()):
            continue
        verb = m.group(1).strip().rstrip(":").lower()
        obj = m.group(2).strip()
        obj = re.split(r"[.;\n\r]", obj, maxsplit=1)[0].strip()
        if not obj or len(obj) < 3:
            continue
        clause = f"{verb} {obj}"[:200]
        key = clause.lower()
        if key in seen_inline:
            continue
        seen_inline.add(key)
        loops.append({
            "source_note": rel_path,
            "loop_text": clause,
            "extracted_at": extracted_iso,
            "kind": "inline",
        })
    return loops


def _followup_judge(loop_text: str, candidate_snippet: str) -> tuple[bool, str]:
    """Ask the chat LLM whether `candidate_snippet` constitutes evidence
    that `loop_text` was followed through. Strict JSON, bias toward "no".
    Returns (resolved, reason). Any parse failure collapses to (False, "").

    Uses the chat model (not qwen2.5:3b). The helper proved non-deterministic
    and emitted malformed JSON on judgment tasks — same failure mode as the
    contradiction detector, which is also chat-model-only.
    """
    prompt = (
        "Eres un juez conservador. Dada una tarea/pendiente y un fragmento de "
        "una nota POSTERIOR, decidí si el fragmento evidencia que la tarea fue "
        "realizada o resuelta. Sesgo hacia 'no': si hay duda, responde false.\n\n"
        f"TAREA: {loop_text}\n\n"
        f"FRAGMENTO POSTERIOR:\n{candidate_snippet[:800]}\n\n"
        'Responde SOLO JSON: {"resolved": true|false, "reason": "<20 palabras"}'
    )
    try:
        resp = _chat_capped_client().chat(
            model=resolve_chat_model(),
            messages=[{"role": "user", "content": prompt}],
            # num_ctx=4096 to keep the web chat's KV cache warm (see CHAT_OPTIONS).
            options={**CHAT_OPTIONS, "num_predict": 128},
            keep_alive=chat_keep_alive(),
        )
        raw = resp.message.content.strip()
    except Exception:
        return False, ""
    m = re.search(r"\{.*\}", raw, re.DOTALL)
    if not m:
        return False, ""
    try:
        data = json.loads(m.group(0))
    except Exception:
        return False, ""
    resolved = bool(data.get("resolved"))
    reason = str(data.get("reason") or "").strip()[:200]
    return resolved, reason


def _classify_followup_loop(
    col: SqliteVecCollection,
    loop: dict,
    now: datetime,
    stale_days: int = FOLLOWUP_STALE_DAYS,
    min_score: float = FOLLOWUP_RESOLVE_MIN_SCORE,
    judge_fn=None,
    completed_reminders: list[dict] | None = None,
) -> dict:
    """Run resolution check + classification. Returns the loop dict enriched
    with `status`, `age_days`, and optionally `resolution_path`/`reason`.
    Status is one of: resolved | stale | activo.

    Fast path: si `completed_reminders` incluye un nombre que matchea el
    loop por Jaccard (token overlap ≥ 0.6), marcamos resolved inmediatamente
    con reason "reminder completado <date>" y saltamos la vuelta por
    retrieve + LLM judge. Ahorra un call por loop cuando el cierre vivió
    en Apple Reminders en vez del vault.
    """
    judge = judge_fn or _followup_judge
    try:
        extracted_dt = datetime.fromisoformat(loop["extracted_at"])
    except Exception:
        extracted_dt = now
    age_days = max(0, int((now - extracted_dt).total_seconds() // 86400))
    out = dict(loop)
    out["age_days"] = age_days
    out["status"] = "stale" if age_days > stale_days else "activo"
    out["resolution_path"] = None
    out["reason"] = None
    out["resolved_by"] = None

    # Fast path: ¿la completaste en Apple Reminders?
    if completed_reminders:
        match = _match_loop_to_completed_reminder(
            loop.get("loop_text", ""), completed_reminders,
        )
        if match is not None:
            comp_date = str(match.get("completed_date", ""))[:10]
            list_name = match.get("list", "")
            out["status"] = "resolved"
            out["resolution_path"] = f"(Apple Reminders · {list_name})" if list_name else "(Apple Reminders)"
            out["reason"] = f"reminder completado {comp_date}" if comp_date else "reminder completado"
            out["resolved_by"] = "reminder"
            return out

    # `caller="followup"` (2026-04-28): el find_followup_loops daemon corre
    # automáticamente y dispara retrieve() para cada loop pendiente. Sin
    # caller explícito, esos impressions se mezclaban con user signal en
    # rag_behavior. Ver doc en `retrieve()` y commit `fd97829`.
    try:
        result = retrieve(
            col, loop["loop_text"], k=5, folder=None,
            multi_query=False, auto_filter=False,
            caller="followup",
        )
    except Exception:
        return out
    metas = result.get("metas") or []
    docs = result.get("docs") or []
    scores = result.get("scores") or []
    source = loop.get("source_note", "")
    candidates: list[tuple[float, dict, str]] = []
    for meta, doc, score in zip(metas, docs, scores):
        mpath = meta.get("file", "")
        if not mpath or mpath == source:
            continue
        mtime_iso = meta.get("modified") or ""
        mtime_dt = None
        if mtime_iso:
            try:
                mtime_dt = datetime.fromisoformat(str(mtime_iso))
            except Exception:
                mtime_dt = None
        if mtime_dt is None:
            full = VAULT_PATH / mpath
            try:
                mtime_dt = datetime.fromtimestamp(full.stat().st_mtime)
            except OSError:
                continue
        if mtime_dt.tzinfo is not None:
            mtime_dt = mtime_dt.astimezone().replace(tzinfo=None)
        if mtime_dt <= extracted_dt:
            continue
        candidates.append((float(score), meta, doc))
    if not candidates:
        return out
    candidates.sort(key=lambda x: -x[0])
    top_score, top_meta, top_doc = candidates[0]
    if top_score < min_score:
        return out
    resolved, reason = judge(loop["loop_text"], top_doc)
    if resolved:
        out["status"] = "resolved"
        out["resolution_path"] = top_meta.get("file", "")
        out["reason"] = reason
        out["resolved_by"] = "note"
    return out


def _followup_vault_max_mtime(vault: Path) -> float | None:
    """Devuelve el max(mtime) de los .md del vault con os.scandir recursivo.
    Retorna None si hay error de permisos irrecuperable."""
    try:
        max_mtime = 0.0
        stack = [vault]
        while stack:
            d = stack.pop()
            try:
                with os.scandir(d) as it:
                    for entry in it:
                        if entry.is_dir(follow_symlinks=False):
                            stack.append(Path(entry.path))
                        elif entry.name.endswith(".md"):
                            try:
                                st = entry.stat()
                                if st.st_mtime > max_mtime:
                                    max_mtime = st.st_mtime
                            except OSError:
                                pass
            except OSError:
                pass
        return max_mtime
    except Exception:
        return None


def find_followup_loops(
    col: SqliteVecCollection,
    vault: Path,
    days: int = 30,
    stale_days: int = FOLLOWUP_STALE_DAYS,
    min_score: float = FOLLOWUP_RESOLVE_MIN_SCORE,
    now: datetime | None = None,
    judge_fn=None,
    completed_reminders: list[dict] | None = None,
) -> list[dict]:
    """Walk the vault for notes modified in the last `days`, extract every
    open loop, and classify each. Returns a list sorted stale→activo→resolved,
    oldest-first within each group.

    `completed_reminders` opcional: si viene una lista (shape
    `_fetch_completed_reminders`), el classifier prioriza matches Jaccard
    contra ellas antes de caer al retrieval + LLM judge. None → fetch
    automático con ventana = `days`.

    Cache TTL 10min + invalidación por max(mtime) del vault. Se inhabilita
    cuando el caller pasa now/judge_fn/completed_reminders explícitos para
    preservar el comportamiento determinístico de los tests.
    """
    global _followup_loops_cache  # noqa: PLW0603

    # Cache solo cuando el caller no sobreescribe parámetros sensibles al tiempo
    _use_cache = now is None and judge_fn is None and completed_reminders is None
    current_max_mtime: float | None = None

    if _use_cache:
        current_max_mtime = _followup_vault_max_mtime(vault)
        call_ts = datetime.now().timestamp()
        with _followup_loops_cache_lock:
            c = _followup_loops_cache
            if (
                c is not None
                and current_max_mtime is not None
                and (call_ts - c["ts"]) < _FOLLOWUP_CACHE_TTL
                and c["max_mtime"] == current_max_mtime
                and c["days"] == days
                and c["stale_days"] == stale_days
                and c["min_score"] == min_score
            ):
                return list(c["result"])  # copia superficial — evita mutación del cache

    from datetime import timedelta as _td

    now = now or datetime.now()
    start = now - _td(days=days)
    all_loops: list[dict] = []
    if not vault.is_dir():
        return []
    for p in vault.rglob("*.md"):
        try:
            rel = str(p.relative_to(vault))
        except ValueError:
            continue
        if is_excluded(rel):
            continue
        try:
            st = p.stat()
        except OSError:
            continue
        mtime = st.st_mtime
        if datetime.fromtimestamp(mtime) < start:
            continue
        try:
            raw = p.read_text(encoding="utf-8", errors="ignore")
        except OSError:
            continue
        extracted_ts = _note_created_ts(raw, mtime)
        all_loops.extend(_extract_followup_loops(raw, rel, extracted_ts))

    # One osascript call para toda la corrida — evita N calls en
    # `_classify_followup_loop`. Ventana de reminders = ventana de loops
    # porque no tiene sentido matchear un loop de hoy contra una reminder
    # completada hace 6 meses.
    if completed_reminders is None:
        completed_reminders = _fetch_completed_reminders(now, days=days)

    classified = [
        _classify_followup_loop(
            col,
            loop,
            now,
            stale_days=stale_days,
            min_score=min_score,
            judge_fn=judge_fn,
            completed_reminders=completed_reminders,
        )
        for loop in all_loops
    ]
    order = {"stale": 0, "activo": 1, "resolved": 2}
    classified.sort(key=lambda r: (order.get(r["status"], 3), -r["age_days"]))

    if _use_cache and current_max_mtime is not None:
        with _followup_loops_cache_lock:
            _followup_loops_cache = {
                "ts": datetime.now().timestamp(),
                "max_mtime": current_max_mtime,
                "days": days,
                "stale_days": stale_days,
                "min_score": min_score,
                "result": list(classified),
            }

    return classified


@cli.command()
@click.option("--days", default=30, show_default=True,
              help="Ventana para scanear notas modificadas")
@click.option("--status", type=click.Choice(["stale", "activo", "resolved"]),
              default=None, help="Filtrar por status")
@click.option("--json", "as_json", is_flag=True, help="Salida JSON")
@click.option("--plain", is_flag=True, help="Sin ANSI")
@click.option("--stale-days", default=FOLLOWUP_STALE_DAYS, show_default=True,
              help="Umbral (días) para marcar un loop como stale")
def followup(days: int, status: str | None, as_json: bool, plain: bool,
             stale_days: int):
    """Open loops del vault: qué dijiste que harías y no quedó cerrado.

    Escanea frontmatter todo/due, checkboxes `- [ ]` y cláusulas imperativas
    ("tengo que X", "pendiente Y", "revisar Z") en notas modificadas en la
    última ventana. Clasifica cada loop como resolved / stale / activo según
    si hay evidencia semántica de follow-through en notas posteriores.
    """
    col = get_db()
    t0 = time.perf_counter()
    items = find_followup_loops(col, VAULT_PATH, days=days, stale_days=stale_days)
    if status:
        items = [it for it in items if it["status"] == status]

    counts = {"stale": 0, "activo": 0, "resolved": 0}
    for it in items:
        counts[it["status"]] = counts.get(it["status"], 0) + 1

    _total_s = time.perf_counter() - t0
    log_query_event({
        "cmd": "followup", "days": days, "status": status,
        "n_loops": len(items), "counts": counts,
        "t_retrieve": round(_total_s, 3),
        "timing": _round_timing_ms({"total_ms": _total_s * 1000}),
    })

    if as_json:
        click.echo(json.dumps(items, ensure_ascii=False))
        return

    if not items:
        msg = "Sin open loops en esta ventana."
        click.echo(msg) if plain else console.print(f"[green]{msg}[/green]")
        return

    if plain:
        for it in items:
            click.echo(
                f"{it['status']}\t{it['age_days']}d\t{it['kind']}\t"
                f"{it['source_note']}\t{it['loop_text']}"
            )
        return

    badge_style = {
        "stale": "bold red",
        "activo": "bold yellow",
        "resolved": "dim green",
    }
    kind_icon = {"todo": "📌", "checkbox": "☐", "inline": "✎"}
    for group in ("stale", "activo", "resolved"):
        group_items = [it for it in items if it["status"] == group]
        if not group_items:
            continue
        title = {
            "stale": f"🕸  {len(group_items)} stale (> {stale_days}d sin cerrar)",
            "activo": f"🔥 {len(group_items)} activo(s)",
            "resolved": f"✅ {len(group_items)} resuelto(s)",
        }[group]
        console.print()
        console.print(Rule(
            title=f"[{badge_style[group]}]{title}[/{badge_style[group]}]",
            style=badge_style[group],
        ))
        if group == "resolved":
            for it in group_items[:10]:
                line = Text()
                by = it.get("resolved_by")
                if by == "reminder":
                    line.append("  ✓ reminder: ", style="bold green")
                else:
                    line.append("  ✓ ", style="green")
                line.append(it["loop_text"][:80], style="dim")
                line.append("  ← ", style="dim")
                rpath = it.get("resolution_path") or ""
                if rpath:
                    # Reminders no son paths — no darles file-link estilizado.
                    if by == "reminder":
                        line.append(rpath, style="green dim")
                    else:
                        line.append(rpath, style=_file_link_style(rpath, "cyan"))
                console.print(line)
            if len(group_items) > 10:
                console.print(f"  [dim]… y {len(group_items) - 10} más[/dim]")
            continue
        for it in group_items:
            line = Text()
            icon = kind_icon.get(it["kind"], "•")
            line.append(f"  {icon} ", style="dim")
            line.append(f"{it['age_days']:>3}d ", style="yellow")
            line.append(it["loop_text"][:100])
            line.append("   ", style="dim")
            line.append(
                it["source_note"],
                style=_file_link_style(it["source_note"], "cyan dim"),
            )
            console.print(line)

    console.print()
    console.print(
        f"[dim]Total: {counts['stale']} stale · "
        f"{counts['activo']} activo · {counts['resolved']} resuelto. "
        f"Ventana: {days}d. Umbral stale: {stale_days}d.[/dim]"
    )


# ── AUTOMATION (launchd) ─────────────────────────────────────────────────────
# Two services keep the RAG alive without manual rituals:
#  - obsidian-rag-watch: runs `rag watch` (auto-reindex on vault changes).
#  - obsidian-rag-digest: weekly `rag digest`, Sunday 22:00 local.
# Both managed by `rag setup` / `rag setup --remove`. Idempotent reload on each
# install. Logs land in ~/.local/share/obsidian-rag/ for tail-ability.

_LAUNCH_AGENTS_DIR = Path.home() / "Library/LaunchAgents"
_RAG_LOG_DIR = Path.home() / ".local/share/obsidian-rag"


def _rag_binary() -> str:
    """Best-effort path to the installed `rag` binary. Default uv tool path
    first; fall back to PATH lookup. The launchd service runs without our
    interactive PATH so we resolve it once at install time.
    """
    candidates = [
        Path.home() / ".local/bin/rag",
        Path("/usr/local/bin/rag"),
        Path("/opt/homebrew/bin/rag"),
    ]
    for p in candidates:
        if p.is_file():
            return str(p)
    import shutil
    found = shutil.which("rag")
    return found or str(candidates[0])


def _watch_plist(rag_bin: str) -> str:
    """Persistent watchdog observing ALL registered vaults in a single process.

    `--all-vaults` (2026-04-22): prior plist invoked `rag watch` bare, which
    defaults to the active vault only — a 2-vault setup (e.g. home + work)
    left the non-active vault silently un-watched. New notes in `work`
    required a manual `rag index --vault work`. With `--all-vaults` a single
    watchdog observer monitors every registered vault in one process
    (sqlite-vec + sentence-transformers imported once, not per vault), so
    ~3-4 GB of RAM savings vs. running a second watch service.
    """
    return f"""<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
  <key>Label</key><string>com.fer.obsidian-rag-watch</string>
  <key>ProgramArguments</key>
  <array>
    <string>{rag_bin}</string>
    <string>watch</string>
    <string>--all-vaults</string>
  </array>
  <key>EnvironmentVariables</key>
  <dict>
    <key>HOME</key><string>{Path.home()}</string>
    <key>PATH</key><string>/opt/homebrew/bin:/usr/local/bin:/usr/bin:/bin:{Path.home()}/.local/bin</string>
  </dict>
  <key>RunAtLoad</key><true/>
  <key>KeepAlive</key><true/>
  <key>ThrottleInterval</key><integer>30</integer>
  <key>StandardOutPath</key><string>{_RAG_LOG_DIR}/watch.log</string>
  <key>StandardErrorPath</key><string>{_RAG_LOG_DIR}/watch.error.log</string>
</dict>
</plist>
"""


def _serve_plist(rag_bin: str) -> str:
    """Persistent `rag serve` HTTP query server on port 7832.

    This is the hot path for the WhatsApp listener (and any other bot
    integration): it keeps the reranker, bge-m3 embedder, BM25 corpus, and
    chat model warm in memory so each request skips the ~5-10s subprocess
    cold-start that listener.ts's fallback pays per message.

    Env vars mirror the web plist: OLLAMA_KEEP_ALIVE=-1 (models pinned in
    VRAM forever), RAG_RERANKER_NEVER_UNLOAD=1 (cross-encoder stays resident,
    no 9s reload after idle eviction), RAG_LOCAL_EMBED=1 (in-process
    SentenceTransformer for query embedding, ~10-30ms vs ~140ms via ollama
    HTTP), RAG_STATE_SQL=1 (deployment symmetry — no-op post-T10),
    HF_HUB_OFFLINE=1 + TRANSFORMERS_OFFLINE=1 (close the race where HEAD
    probes to huggingface.co fire BEFORE rag.py's module-init setdefault —
    see test_plist_web_serve.py for rationale; was causing 64× [local-embed]
    unavailable + fallback-to-ollama in web.error.log pre-2026-04-22),
    RAG_MEMORY_PRESSURE_INTERVAL=20 (the default 60s missed the MPS-OOM
    window measured in web.error.log; 20s gives the watchdog 3 samples per
    minute to catch memory pressure before Metal returns
    `kIOGPUCommandBufferCallbackErrorOutOfMemory`).

    KeepAlive + RunAtLoad mean launchd will resurrect it if it crashes or
    the host reboots. ThrottleInterval=30 prevents crash loops from burning
    CPU.
    """
    return f"""<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
  <key>Label</key><string>com.fer.obsidian-rag-serve</string>
  <key>ProgramArguments</key>
  <array>
    <string>{rag_bin}</string>
    <string>serve</string>
    <string>--port</string>
    <string>7832</string>
  </array>
  <key>EnvironmentVariables</key>
  <dict>
    <key>HOME</key><string>{Path.home()}</string>
    <key>PATH</key><string>/opt/homebrew/bin:/usr/local/bin:/usr/bin:/bin:{Path.home()}/.local/bin</string>
    <key>NO_COLOR</key><string>1</string>
    <key>TERM</key><string>dumb</string>
    <key>PYTHONUNBUFFERED</key><string>1</string>
    <key>OLLAMA_KEEP_ALIVE</key><string>-1</string>
    <key>RAG_RERANKER_NEVER_UNLOAD</key><string>1</string>
    <key>RAG_LOCAL_EMBED</key><string>1</string>
    <key>RAG_STATE_SQL</key><string>1</string>
    <key>HF_HUB_OFFLINE</key><string>1</string>
    <key>TRANSFORMERS_OFFLINE</key><string>1</string>
    <key>FASTEMBED_CACHE_PATH</key><string>{Path.home()}/.cache/fastembed</string>
    <key>RAG_MEMORY_PRESSURE_INTERVAL</key><string>20</string>
  </dict>
  <key>RunAtLoad</key><true/>
  <key>KeepAlive</key><true/>
  <key>ThrottleInterval</key><integer>30</integer>
  <key>StandardOutPath</key><string>{_RAG_LOG_DIR}/serve.log</string>
  <key>StandardErrorPath</key><string>{_RAG_LOG_DIR}/serve.error.log</string>
</dict>
</plist>
"""


def _web_plist(rag_bin: str) -> str:
    """Persistent FastAPI web UI + SSE chat endpoint on port 8765.

    Historical gap (2026-04-22): this plist was installed manually once (Apr
    19 2026) and therefore had no single source of truth for its env vars.
    The manual version was missing HF_HUB_OFFLINE=1 + TRANSFORMERS_OFFLINE=1,
    so `sentence_transformers` hit huggingface.co on every cold load; the
    2026-04-22 `web.error.log` had **64 `[local-embed] unavailable
    (couldn't connect to huggingface.co)` entries** that silently dropped
    the daemon back to ollama embed (~140ms vs ~10-30ms in-process).

    It also lacked RAG_MEMORY_PRESSURE_INTERVAL, which the default of 60s
    left too coarse — `web.error.log` recorded **23 MPS Metal command-
    buffer OOMs** (`kIOGPUCommandBufferCallbackErrorOutOfMemory`) that
    happened inside the 60s sampling window. 20s gives the watchdog 3
    chances per minute to unload the chat model / reranker before the
    next MPS encoding starves.

    Note: the entry point is `python web/server.py` directly (not `rag
    web`), so env vars set via `os.environ.setdefault` at the top of rag.py
    run only after FastAPI's module graph is already partly loaded —
    anything that transitively pulls huggingface_hub before
    `from rag import ...` misses the setdefault. Setting the offline flags
    in the plist dict eliminates that race.
    """
    # Repo root is two levels up from this file (rag/__init__.py); the venv
    # and web/ subtree both live at the repo root, NOT inside the `rag/`
    # package dir. Using `.parent` only (a single level) yielded
    # `…/obsidian-rag/rag/.venv/bin/python` and `…/obsidian-rag/rag/web/server.py`
    # — paths that don't exist — and left the daemon crashing with exit 78
    # until the plist was patched by hand. Bug found 2026-04-26.
    repo_root = Path(__file__).resolve().parent.parent
    venv_python = repo_root / ".venv" / "bin" / "python"
    web_server = repo_root / "web" / "server.py"
    working_dir = repo_root
    # Youtube key is optional — include only if present in the env to avoid
    # hard-coding a secret at setup time. Most installs leave it blank.
    youtube_key = os.environ.get("YOUTUBE_API_KEY", "")
    yt_line = (
        f"    <key>YOUTUBE_API_KEY</key><string>{youtube_key}</string>\n"
        if youtube_key else ""
    )
    chat_model = os.environ.get("OBSIDIAN_RAG_WEB_CHAT_MODEL", "qwen2.5:7b")
    # 2026-04-28 (eval Playwright MEDIUM #12 — server crashes mid-conversation):
    # `launchctl print` mostraba `runs = 46` en 2h con un mix de SIGKILL by
    # launchd[1] + SIGTERM-then-SIGKILL escalado. Diagnóstico:
    #   1. RAG_MEMORY_PRESSURE_THRESHOLD default=85% reaccionaba TARDE — el
    #      jetsam macOS pegaba antes que el watchdog descargara modelos.
    #      Bajamos a 80% para desalojar chat model + reranker proactivamente.
    #   2. ExitTimeOut implícito de 5s (visible en `launchctl print`) cortaba
    #      el graceful shutdown de uvicorn cuando había una SSE en vuelo:
    #      launchd → SIGTERM → 5s → SIGKILL aunque la respuesta estuviera
    #      por terminar. 20s da margen al pipeline de chat (typical 8-15s
    #      end-to-end) para drenar antes que escale a SIGKILL.
    #   3. ProcessType=Interactive le indica a launchd que es un servicio
    #      foreground (web UI activamente en uso) → menos agresivo bajo
    #      memory pressure. Sin esto launchd lo trataba como Background,
    #      jetsam priority alta, primero en la cola para morir.
    # Síntoma user-facing pre-fix: "tu › qué decías sobre LangChain? error:
    # network error" + "tu › a ver si tengo otra referencia error: Failed to
    # fetch" — 2 turnos perdidos por turno de respawn. Ver
    # docs/eval-2026-04-28/playwright-conversations-bug-log.md MEDIUM #12.
    return f"""<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
  <key>Label</key><string>com.fer.obsidian-rag-web</string>
  <key>ProgramArguments</key>
  <array>
    <string>{venv_python}</string>
    <string>{web_server}</string>
  </array>
  <key>EnvironmentVariables</key>
  <dict>
    <key>HOME</key><string>{Path.home()}</string>
    <key>PATH</key><string>/opt/homebrew/bin:/usr/local/bin:/usr/bin:/bin:{Path.home()}/.local/bin</string>
    <key>PYTHONUNBUFFERED</key><string>1</string>
    <key>OBSIDIAN_RAG_WEB_CHAT_MODEL</key><string>{chat_model}</string>
    <key>OLLAMA_KEEP_ALIVE</key><string>-1</string>
    <key>RAG_LOCAL_EMBED</key><string>1</string>
    <key>RAG_RERANKER_NEVER_UNLOAD</key><string>1</string>
    <key>RAG_STATE_SQL</key><string>1</string>
    <key>HF_HUB_OFFLINE</key><string>1</string>
    <key>TRANSFORMERS_OFFLINE</key><string>1</string>
    <key>FASTEMBED_CACHE_PATH</key><string>{Path.home()}/.cache/fastembed</string>
    <key>RAG_MEMORY_PRESSURE_INTERVAL</key><string>20</string>
    <key>RAG_MEMORY_PRESSURE_THRESHOLD</key><string>80</string>
    <key>RAG_AUTO_FIX_WORKER</key><string>1</string>
    <key>RAG_AUTO_FIX_HOURLY_CAP</key><string>12</string>
{yt_line}  </dict>
  <key>RunAtLoad</key><true/>
  <key>KeepAlive</key><true/>
  <key>ThrottleInterval</key><integer>30</integer>
  <key>ExitTimeOut</key><integer>20</integer>
  <key>ProcessType</key><string>Interactive</string>
  <key>WorkingDirectory</key><string>{working_dir}</string>
  <key>StandardOutPath</key><string>{_RAG_LOG_DIR}/web.log</string>
  <key>StandardErrorPath</key><string>{_RAG_LOG_DIR}/web.error.log</string>
</dict>
</plist>
"""


def _digest_plist(rag_bin: str, hour: int = 22, minute: int = 0) -> str:
    """Weekly digest plist — Sunday `hour:minute` (default 22:00).

    `hour`/`minute` honor a `rag_brief_schedule_prefs` override when
    `_services_spec()` reads one (auto-tune feature, 2026-04-29).
    Defaults preserve the historical schedule when no pref exists; the
    auto-tune writer enforces the safe band before persisting, so a
    pref-driven override never lands outside `[21:00, 23:30]`.
    """
    return f"""<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
  <key>Label</key><string>com.fer.obsidian-rag-digest</string>
  <key>ProgramArguments</key>
  <array>
    <string>{rag_bin}</string>
    <string>digest</string>
  </array>
  <key>EnvironmentVariables</key>
  <dict>
    <key>HOME</key><string>{Path.home()}</string>
    <key>PATH</key><string>/opt/homebrew/bin:/usr/local/bin:/usr/bin:/bin:{Path.home()}/.local/bin</string>
    <key>NO_COLOR</key><string>1</string>
    <key>TERM</key><string>dumb</string>
  </dict>
  <key>StartCalendarInterval</key>
  <dict>
    <key>Weekday</key><integer>0</integer>
    <key>Hour</key><integer>{int(hour)}</integer>
    <key>Minute</key><integer>{int(minute)}</integer>
  </dict>
  <key>StandardOutPath</key><string>{_RAG_LOG_DIR}/digest.log</string>
  <key>StandardErrorPath</key><string>{_RAG_LOG_DIR}/digest.error.log</string>
</dict>
</plist>
"""


def _morning_plist(rag_bin: str, hour: int = 7, minute: int = 0) -> str:
    """Morning brief plist — Mon-Fri `hour:minute` (default 07:00).

    `hour`/`minute` honor a `rag_brief_schedule_prefs` override when
    `_services_spec()` reads one (auto-tune feature, 2026-04-29).
    Defaults preserve the historical schedule when no pref exists; the
    auto-tune writer enforces the safe band before persisting, so a
    pref-driven override never lands outside `[06:30, 09:00]`.

    Voice brief opt-in (Anticipatory Phase 2.C, 2026-04-29):
    ``RAG_MORNING_VOICE`` se inyecta vacío por default — text-only
    behavior. Para activar el audio matinal: el user edita el plist
    seteando el value a ``1`` (o ``true``/``yes``) y hace
    ``launchctl bootout`` + ``bootstrap`` (o re-instala con
    ``rag setup``). Voz de la lectura: env var ``TTS_VOICE`` (default
    ``Mónica``). Cap de audio: 5MB; si excede, fallback a text-only
    silencioso. Audios viejos (>30d) limpiados por ``rag maintenance``.
    """
    h = int(hour)
    m = int(minute)
    return f"""<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
  <key>Label</key><string>com.fer.obsidian-rag-morning</string>
  <key>ProgramArguments</key>
  <array>
    <string>{rag_bin}</string>
    <string>morning</string>
  </array>
  <key>EnvironmentVariables</key>
  <dict>
    <key>HOME</key><string>{Path.home()}</string>
    <key>PATH</key><string>/opt/homebrew/bin:/usr/local/bin:/usr/bin:/bin:{Path.home()}/.local/bin</string>
    <key>NO_COLOR</key><string>1</string>
    <key>TERM</key><string>dumb</string>
    <key>RAG_EXPLORE</key><string>1</string>
    <key>RAG_MORNING_VOICE</key><string></string>
  </dict>
  <key>StartCalendarInterval</key>
  <array>
    <dict><key>Weekday</key><integer>1</integer><key>Hour</key><integer>{h}</integer><key>Minute</key><integer>{m}</integer></dict>
    <dict><key>Weekday</key><integer>2</integer><key>Hour</key><integer>{h}</integer><key>Minute</key><integer>{m}</integer></dict>
    <dict><key>Weekday</key><integer>3</integer><key>Hour</key><integer>{h}</integer><key>Minute</key><integer>{m}</integer></dict>
    <dict><key>Weekday</key><integer>4</integer><key>Hour</key><integer>{h}</integer><key>Minute</key><integer>{m}</integer></dict>
    <dict><key>Weekday</key><integer>5</integer><key>Hour</key><integer>{h}</integer><key>Minute</key><integer>{m}</integer></dict>
  </array>
  <key>StandardOutPath</key><string>{_RAG_LOG_DIR}/morning.log</string>
  <key>StandardErrorPath</key><string>{_RAG_LOG_DIR}/morning.error.log</string>
</dict>
</plist>
"""


