def _ingest_reminders_plist(rag_bin: str) -> str:
    """Cross-source: Apple Reminders ingester, cada 1h.

    AppleScript full-scan (~7-100s dependiendo de cuántos reminders). Incremental
    via content-hash diff post-fetch — solo re-embedea los cambiados. En steady
    state con 0 cambios el run termina en ~7s (solo el scan sin embedding).

    Interval bajado de 6h → 1h (2026-04-22): empíricamente "37 fetched · 0
    indexados · 0 borrados · 7s" — el costo es negligible y reminders es la
    fuente MÁS dinámica en el día a día del usuario (marcar como done, crear
    nuevos). Alineado con gmail/calendar (1h) así las queries tipo "qué tengo
    esta semana" + "qué reminders pendientes" devuelven data fresh.

    `RunAtLoad=true`: corre inmediatamente al instalar / post-reboot, no hay
    que esperar 1h para ver el primer refresh.

    Local-only (EventKit via osascript); no OAuth quota. Si el AppleScript
    falla (Full Disk Access denegado, Reminders.app not running), el
    ingester silent-drops y la próxima corrida lo reintenta.
    """
    return f"""<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
  <key>Label</key><string>com.fer.obsidian-rag-ingest-reminders</string>
  <key>ProgramArguments</key>
  <array>
    <string>{rag_bin}</string>
    <string>index</string>
    <string>--source</string>
    <string>reminders</string>
  </array>
  <key>EnvironmentVariables</key>
  <dict>
    <key>HOME</key><string>{Path.home()}</string>
    <key>PATH</key><string>/opt/homebrew/bin:/usr/local/bin:/usr/bin:/bin:{Path.home()}/.local/bin</string>
    <key>NO_COLOR</key><string>1</string>
    <key>TERM</key><string>dumb</string>
    <key>OLLAMA_KEEP_ALIVE</key><string>-1</string>
  </dict>
  <key>StartInterval</key><integer>3600</integer>
  <key>RunAtLoad</key><true/>
  <key>StandardOutPath</key><string>{_RAG_LOG_DIR}/ingest-reminders.log</string>
  <key>StandardErrorPath</key><string>{_RAG_LOG_DIR}/ingest-reminders.error.log</string>
</dict>
</plist>
"""


def _wake_up_plist(rag_bin: str) -> str:
    """Wake-up pack — 04:00 diario.

    Orquesta `rag index` + `maintenance` + `patterns` + `emergent` +
    `morning` + ollama warmup en ese orden. ~15-20min end-to-end.

    Corre a las 04:00 (no 06:00) para darle tiempo a completar todo
    antes de que el user se despierte. Asume que la Mac está prendida
    overnight (plugged-in o no en sleep agresivo). Si la Mac estaba en
    sleep, launchd dispara el job al wake y puede solaparse con el
    `morning` plist de las 07:00 — rag maneja esto porque cada paso es
    idempotente (hash-skip en ETLs, reindex incremental, etc.).

    No reemplaza los plists individuales de morning/maintenance/
    patterns/emergent — los amortigua (si alguno no corrió porque la
    Mac estaba en sleep a su horario, wake-up lo re-ejecuta).
    """
    return f"""<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
  <key>Label</key><string>com.fer.obsidian-rag-wake-up</string>
  <key>ProgramArguments</key>
  <array>
    <string>{rag_bin}</string>
    <string>wake-up</string>
  </array>
  <key>EnvironmentVariables</key>
  <dict>
    <key>HOME</key><string>{Path.home()}</string>
    <key>PATH</key><string>/opt/homebrew/bin:/usr/local/bin:/usr/bin:/bin:{Path.home()}/.local/bin</string>
    <key>NO_COLOR</key><string>1</string>
    <key>TERM</key><string>dumb</string>
    <key>OLLAMA_KEEP_ALIVE</key><string>-1</string>
  </dict>
  <key>StartCalendarInterval</key>
  <dict>
    <key>Hour</key><integer>4</integer>
    <key>Minute</key><integer>0</integer>
  </dict>
  <key>StandardOutPath</key><string>{_RAG_LOG_DIR}/wake-up.log</string>
  <key>StandardErrorPath</key><string>{_RAG_LOG_DIR}/wake-up.error.log</string>
</dict>
</plist>
"""


def _serve_watchdog_plist(rag_bin: str) -> str:  # noqa: ARG001 (rag_bin no usado)
    """Watchdog del web server — corre cada 60s, healthcheck HTTP +
    catchup de plists nightly que se saltearon su window por Mac dormida.

    Originalmente vivía en `scripts/com.fer.obsidian-rag-serve-watchdog.plist`
    con paths hardcoded al repo (`~/repositories/obsidian-rag/scripts/...`).
    Migrado a generación dinámica el 2026-04-27 (después del audit
    subagent 2297bb6e que detectó el riesgo: si Fer mueve el repo, el
    plist viejo apunta a un path que ya no existe).

    El script bash `rag-serve-watchdog.sh` queda en el repo (es lógica
    no-Python que se mantiene mejor como bash standalone). El plist
    apunta a su path absoluto vía `Path(__file__).resolve().parent.parent
    / "scripts" / "rag-serve-watchdog.sh"` — si el repo se mueve, el
    siguiente `rag setup` regenera el plist con el path nuevo.

    Schedule: `StartInterval=60` + `RunAtLoad=true` (corre al boot).
    Lo de catchup de nightly plists se documenta dentro del script.
    """
    repo_root = Path(__file__).resolve().parent.parent
    watchdog_script = repo_root / "scripts" / "rag-serve-watchdog.sh"
    return f"""<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
  <key>Label</key><string>com.fer.obsidian-rag-serve-watchdog</string>
  <key>ProgramArguments</key>
  <array>
    <string>/bin/bash</string>
    <string>{watchdog_script}</string>
  </array>
  <key>EnvironmentVariables</key>
  <dict>
    <key>HOME</key><string>{Path.home()}</string>
    <key>PATH</key><string>/opt/homebrew/bin:/usr/local/bin:/usr/bin:/bin</string>
  </dict>
  <key>StartInterval</key><integer>60</integer>
  <key>RunAtLoad</key><true/>
  <key>StandardOutPath</key><string>{_RAG_LOG_DIR}/serve-watchdog.stdout.log</string>
  <key>StandardErrorPath</key><string>{_RAG_LOG_DIR}/serve-watchdog.stderr.log</string>
</dict>
</plist>
"""


def _brief_auto_tune_plist(rag_bin: str) -> str:
    """Sunday 03:00 weekly auto-tune of brief schedules (2026-04-29).

    Reads `rag_brief_feedback`, decides whether to shift any of the
    morning/today/digest plists' StartCalendarInterval forward, and
    applies the override via `rag_brief_schedule_prefs`. Sunday 03:00
    is chosen so:

      - It runs AFTER online-tune (03:30 daily) on the only day it
        matters in the same window — actually online-tune is at 03:30,
        so 03:00 sneaks in BEFORE it. That's deliberate: the auto-tune
        write only touches `rag_brief_schedule_prefs` (a single-row PK
        upsert), zero contention with the heavy SQL of online-tune.
      - It's well before `rag digest` (Sunday 22:00 by default, or its
        override) so any shift takes effect on the same Sunday's digest.
      - The user is asleep — no UX surprise from a plist re-bootstrap.

    `--apply` writes the override AND re-bootstraps only the affected
    kind via `launchctl`. `RunAtLoad=false` so `rag setup` doesn't
    fire it on install (no point — there's nothing to tune yet).
    """
    return f"""<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
  <key>Label</key><string>com.fer.obsidian-rag-brief-auto-tune</string>
  <key>ProgramArguments</key>
  <array>
    <string>{rag_bin}</string>
    <string>brief</string>
    <string>schedule</string>
    <string>auto-tune</string>
    <string>--apply</string>
  </array>
  <key>EnvironmentVariables</key>
  <dict>
    <key>HOME</key><string>{Path.home()}</string>
    <key>PATH</key><string>/opt/homebrew/bin:/usr/local/bin:/usr/bin:/bin:{Path.home()}/.local/bin</string>
    <key>NO_COLOR</key><string>1</string>
    <key>TERM</key><string>dumb</string>
    <key>RAG_STATE_SQL</key><string>1</string>
  </dict>
  <key>StartCalendarInterval</key>
  <dict>
    <key>Weekday</key><integer>0</integer>
    <key>Hour</key><integer>3</integer>
    <key>Minute</key><integer>0</integer>
  </dict>
  <key>RunAtLoad</key><false/>
  <key>KeepAlive</key><false/>
  <key>StandardOutPath</key><string>{_RAG_LOG_DIR}/brief-auto-tune.log</string>
  <key>StandardErrorPath</key><string>{_RAG_LOG_DIR}/brief-auto-tune.error.log</string>
</dict>
</plist>
"""


def _services_spec(rag_bin: str) -> list[tuple[str, str, str]]:
    """Return [(label, plist_filename, plist_xml), ...].

    Brief schedule overrides (2026-04-29): morning/today/digest plists
    consult `rag_brief_schedule_prefs` via `rag.brief_schedule.
    get_brief_schedule_pref()` BEFORE generating their XML. If a row
    exists, the override `(hour, minute)` is substituted; otherwise the
    historical defaults from the plist functions kick in. The lookup
    is silent-fail on any SQL error (fresh DB, locked file, etc.) so
    `rag setup` on a brand-new install never blocks on telemetry.
    """
    # Lazy import keeps module-load lightweight + avoids a circular
    # import (brief_schedule lazy-imports back into rag for SQL conn).
    try:
        from rag.brief_schedule import get_brief_schedule_pref
    except Exception:
        def get_brief_schedule_pref(_kind):  # type: ignore
            return None

    def _override(kind: str, default_hour: int, default_minute: int) -> tuple[int, int]:
        try:
            pref = get_brief_schedule_pref(kind)
        except Exception:
            pref = None
        if pref is None:
            return (default_hour, default_minute)
        return (int(pref.get("hour", default_hour)), int(pref.get("minute", default_minute)))

    morning_h, morning_m = _override("morning", 7, 0)
    today_h, today_m = _override("today", 22, 0)
    digest_h, digest_m = _override("digest", 22, 0)

    return [
        ("com.fer.obsidian-rag-watch", "com.fer.obsidian-rag-watch.plist",
         _watch_plist(rag_bin)),
        ("com.fer.obsidian-rag-serve", "com.fer.obsidian-rag-serve.plist",
         _serve_plist(rag_bin)),
        # Web UI daemon — previously installed manually outside `rag setup`
        # (Apr 2026), which left HF_HUB_OFFLINE + RAG_MEMORY_PRESSURE_INTERVAL
        # missing in the actual plist and produced 64× [local-embed] falls +
        # 23× MPS Metal OOMs. Now generated from source.
        ("com.fer.obsidian-rag-web", "com.fer.obsidian-rag-web.plist",
         _web_plist(rag_bin)),
        ("com.fer.obsidian-rag-digest", "com.fer.obsidian-rag-digest.plist",
         _digest_plist(rag_bin, hour=digest_h, minute=digest_m)),
        ("com.fer.obsidian-rag-morning", "com.fer.obsidian-rag-morning.plist",
         _morning_plist(rag_bin, hour=morning_h, minute=morning_m)),
        ("com.fer.obsidian-rag-today", "com.fer.obsidian-rag-today.plist",
         _today_plist(rag_bin, hour=today_h, minute=today_m)),
        ("com.fer.obsidian-rag-wake-up", "com.fer.obsidian-rag-wake-up.plist",
         _wake_up_plist(rag_bin)),
        ("com.fer.obsidian-rag-emergent", "com.fer.obsidian-rag-emergent.plist",
         _emergent_plist(rag_bin)),
        ("com.fer.obsidian-rag-patterns", "com.fer.obsidian-rag-patterns.plist",
         _patterns_plist(rag_bin)),
        ("com.fer.obsidian-rag-archive", "com.fer.obsidian-rag-archive.plist",
         _archive_plist(rag_bin)),
        ("com.fer.obsidian-rag-wa-tasks", "com.fer.obsidian-rag-wa-tasks.plist",
         _wa_tasks_plist(rag_bin)),
        # Reminder push — Apple Reminders due en una ventana corta se
        # notifican al JID ambient via WhatsApp bridge. Cron a 5min
        # porque la feature es time-sensitive (un reminder en 10min
        # tiene que llegar antes de los 10min, no a los 25min como con
        # el cron de wa-tasks).
        ("com.fer.obsidian-rag-reminder-wa-push",
         "com.fer.obsidian-rag-reminder-wa-push.plist",
         _reminder_wa_push_plist(rag_bin)),
        # Scheduled WhatsApp messages — el user programa un mensaje
        # ("mandale a Grecia mañana 9hs ...") y este worker pickea el
        # row cuando vence y lo dispara al bridge. Misma cadencia que
        # reminder-wa-push (5min) por la misma razón: precisión sin
        # ráfagas de CPU. Idempotente vía status enum en la tabla.
        ("com.fer.obsidian-rag-wa-scheduled-send",
         "com.fer.obsidian-rag-wa-scheduled-send.plist",
         _wa_scheduled_send_plist(rag_bin)),
        ("com.fer.obsidian-rag-auto-harvest", "com.fer.obsidian-rag-auto-harvest.plist",
         _auto_harvest_plist(rag_bin)),
        # Active-learning nudge (C.6, 2026-04-29) — Lunes 10am: cuenta
        # queries low-conf ultimos 7d sin labels y manda push al RagNet
        # con link a /learning si supera 20 candidates. Reemplazo del
        # bash inline que disparaba osascript notification.
        ("com.fer.obsidian-rag-active-learning-nudge",
         "com.fer.obsidian-rag-active-learning-nudge.plist",
         _active_learning_nudge_plist(rag_bin)),
        # Implicit corrective_path inference — corre 03:25, 5 min antes
        # del online-tune. Pre-popula corrective_paths desde behavior
        # post-👎 sin pedir input al user. Sprint 1 del cierre del loop
        # de auto-aprendizaje (2026-04-26).
        ("com.fer.obsidian-rag-implicit-feedback",
         "com.fer.obsidian-rag-implicit-feedback.plist",
         _implicit_feedback_plist(rag_bin)),
        ("com.fer.obsidian-rag-online-tune", "com.fer.obsidian-rag-online-tune.plist",
         _online_tune_plist(rag_bin)),
        ("com.fer.obsidian-rag-calibrate", "com.fer.obsidian-rag-calibrate.plist",
         _calibration_plist(rag_bin)),
        ("com.fer.obsidian-rag-maintenance", "com.fer.obsidian-rag-maintenance.plist",
         _maintenance_plist(rag_bin)),
        ("com.fer.obsidian-rag-consolidate", "com.fer.obsidian-rag-consolidate.plist",
         _consolidate_plist(rag_bin)),
        # Daily vault transient cleanup (2026-04-27) — barre carpetas de
        # "sistema" bajo 04-Archive/99-obsidian-system/99-AI/ con TTLs por
        # carpeta y mueve archivos viejos a `.trash/` del vault. Whitelist:
        # `memory/` + `skills/`. Lógica en scripts/cleanup_vault_transient.py.
        ("com.fer.obsidian-rag-vault-cleanup",
         "com.fer.obsidian-rag-vault-cleanup.plist",
         _vault_cleanup_plist(rag_bin)),
        # Anticipatory agent (2026-04-24) — game-changer push proactivo cada
        # 10 min. Comparte daily_cap=3 con emergent/patterns. Silenciable
        # per-kind: `rag silence anticipate-calendar`. Kill global:
        # RAG_ANTICIPATE_DISABLED=1.
        ("com.fer.obsidian-rag-anticipate", "com.fer.obsidian-rag-anticipate.plist",
         _anticipate_plist(rag_bin)),
        # Cross-source ingesters (2026-04-21) — Phase 1.a-1.d ya implementados
        # en código; estos plists los ponen en loop para que el corpus
        # cross-source esté fresh sin intervención manual. Calendar se skipea
        # al install si `~/.calendar-mcp/credentials.json` no existe — el
        # usuario corre el OAuth flow primero (ver docstring de
        # `_ingest_calendar_plist`), después re-corre `rag setup`.
        ("com.fer.obsidian-rag-ingest-whatsapp",
         "com.fer.obsidian-rag-ingest-whatsapp.plist",
         _ingest_whatsapp_plist(rag_bin)),
        ("com.fer.obsidian-rag-ingest-gmail",
         "com.fer.obsidian-rag-ingest-gmail.plist",
         _ingest_gmail_plist(rag_bin)),
        ("com.fer.obsidian-rag-ingest-reminders",
         "com.fer.obsidian-rag-ingest-reminders.plist",
         _ingest_reminders_plist(rag_bin)),
        ("com.fer.obsidian-rag-ingest-calendar",
         "com.fer.obsidian-rag-ingest-calendar.plist",
         _ingest_calendar_plist(rag_bin)),
        # Serve watchdog — antes en scripts/com.fer.obsidian-rag-
        # serve-watchdog.plist con paths hardcoded; migrado a generación
        # dinámica 2026-04-27. HTTP healthcheck del web server cada 60s
        # + catchup de plists nightly que se saltearon (Mac dormida).
        ("com.fer.obsidian-rag-serve-watchdog",
         "com.fer.obsidian-rag-serve-watchdog.plist",
         _serve_watchdog_plist(rag_bin)),
        # Brief schedule auto-tune (2026-04-29) — Sunday 03:00 reads
        # rag_brief_feedback last 30d, decides whether to shift any of
        # morning/today/digest plists' StartCalendarInterval forward
        # (within safe bands), and re-bootstraps only the affected kind.
        # Silent-fail end-to-end — no UX disruption from a stuck cron.
        ("com.fer.obsidian-rag-brief-auto-tune",
         "com.fer.obsidian-rag-brief-auto-tune.plist",
         _brief_auto_tune_plist(rag_bin)),
    ]


@cli.command()
@click.option("--remove", is_flag=True,
              help="Desinstalar los servicios en lugar de instalarlos")
def setup(remove: bool):
    """Instalar (o desinstalar) los servicios launchd que mantienen el RAG vivo
    sin intervención: `rag watch` (auto-reindex) y `rag digest` (semanal).
    Idempotente — re-correr lo recarga.
    """
    import subprocess
    rag_bin = _rag_binary()
    if not Path(rag_bin).is_file():
        console.print(f"[red]No encuentro el binario `rag`:[/red] {rag_bin}")
        # Incluir el extra `[entities]` por default — sin él, gliner no se
        # instala en el uv tool venv y los ingesters loggean
        # `[feature: entities] dep \`gliner\` not available` cada corrida +
        # la feature de entity-aware retrieval queda desactivada
        # silenciosamente. Aprendido el 2026-04-25 en una sesión donde los
        # 5 *.error.log se llenaron de ese warning durante días sin que
        # nadie lo notara. Si querés MUY mínimo (e.g. CI sin GPU/MPS),
        # corré `uv tool install --reinstall --editable .` (sin extra) y
        # exportá `RAG_EXTRACT_ENTITIES=0` para silenciar.
        console.print("[dim]Instalá primero: uv tool install --reinstall --editable '.[entities]'[/dim]")
        return
    _LAUNCH_AGENTS_DIR.mkdir(parents=True, exist_ok=True)
    _RAG_LOG_DIR.mkdir(parents=True, exist_ok=True)

    for label, fname, content in _services_spec(rag_bin):
        plist_path = _LAUNCH_AGENTS_DIR / fname
        # Always unload first so a stale version doesn't linger after reinstall.
        if plist_path.exists():
            subprocess.run(
                ["launchctl", "unload", str(plist_path)],
                check=False, capture_output=True,
            )
        if remove:
            if plist_path.exists():
                plist_path.unlink()
                console.print(f"[green]✓[/green] removido: {label}")
            else:
                console.print(f"[dim]· no estaba instalado: {label}[/dim]")
            continue
        # Calendar gate: sin OAuth config, instalar el plist sólo loggearía
        # errors cada hora. Skipear con nota — el user re-corre `rag setup`
        # tras el OAuth flow.
        if label == "com.fer.obsidian-rag-ingest-calendar":
            cal_creds = Path.home() / ".calendar-mcp" / "credentials.json"
            if not cal_creds.is_file():
                console.print(
                    f"[yellow]·[/yellow] skip {label}: falta "
                    f"[dim]~/.calendar-mcp/credentials.json[/dim] "
                    f"(correr OAuth flow primero)"
                )
                continue
        plist_path.write_text(content, encoding="utf-8")
        try:
            subprocess.run(
                ["launchctl", "load", str(plist_path)],
                check=True, capture_output=True,
            )
            console.print(f"[green]✓[/green] cargado: [bold]{label}[/bold]")
        except subprocess.CalledProcessError as e:
            stderr = e.stderr.decode(errors="ignore") if e.stderr else ""
            console.print(f"[red]✗[/red] falló cargar {label}: {stderr.strip()}")

    if not remove:
        # Pre-build Apple Contacts disk cache. La primera invocación del
        # resolver `_resolve_sender_to_name` dispara `_load_contacts_phone_index()`
        # que dumpea el address book completo via osascript — ~85s para ~350
        # contactos en el host del autor. Si `rag setup` no lo calienta, ese
        # costo lo paga la primera query cross-source post-install (suele ser
        # `rag serve` handling un WA inbound). Pre-buildearlo acá mueve el
        # hit al setup, donde el user ya está esperando.
        #
        # Silent-fail: si Contacts.app está restringido o el dump falla, el
        # resolver degrada al mask fallback (`…XXXX`) — no bloquea el setup.
        # Solo corre si el cache en disk no existe o expiró (TTL 24h).
        try:
            cache_path = _CONTACTS_PHONE_INDEX_PATH
            cache_stale = (
                not cache_path.is_file()
                or (time.time() - cache_path.stat().st_mtime) > _CONTACTS_PHONE_INDEX_TTL_S
            )
            if cache_stale:
                console.print()
                console.print(
                    "[dim]Pre-building Apple Contacts phone index "
                    "(primer run, ~1-2min)…[/dim]"
                )
                t0 = time.time()
                idx = _load_contacts_phone_index()
                if idx:
                    console.print(
                        f"[green]✓[/green] contacts cache: "
                        f"{len(idx)} phones indexados en {time.time()-t0:.1f}s"
                    )
                else:
                    console.print(
                        "[yellow]·[/yellow] contacts cache vacío "
                        "(Contacts.app no accesible o sin teléfonos) — "
                        "el resolver usa mask fallback"
                    )
        except Exception as exc:
            _silent_log("setup_contacts_warmup", exc)
            console.print(
                "[yellow]·[/yellow] contacts cache warmup falló — continuá sin ello"
            )

        console.print()
        console.print(
            f"[dim]Logs en {_RAG_LOG_DIR}/{{watch,digest,morning,today,emergent,patterns,archive,"
            f"wa-tasks,online-tune,consolidate,ingest-whatsapp,ingest-gmail,ingest-reminders}}"
            f".{{log,error.log}}[/dim]"
        )


@cli.group()
def ambient():
    """Ambient Agent: reacciona a capturas en 00-Inbox con wikilinks+dupes+related."""


@ambient.command("status")
def ambient_status():
    """¿Está habilitado? ¿A qué jid manda?"""
    cfg = _ambient_config()
    if cfg is None:
        if not AMBIENT_CONFIG_PATH.is_file():
            console.print("[yellow]Deshabilitado[/yellow] — no hay config. Enviá /enable_ambient al bot de WhatsApp.")
        else:
            # Detectar schema viejo para dar un hint útil.
            try:
                raw = json.loads(AMBIENT_CONFIG_PATH.read_text(encoding="utf-8"))
            except Exception:
                raw = {}
            if raw.get("chat_id") or raw.get("bot_token"):
                console.print(
                    "[yellow]Deshabilitado[/yellow] — config tiene schema viejo "
                    "(chat_id/bot_token del bot anterior). Re-habilitá con "
                    "/enable_ambient en el bot de WhatsApp."
                )
            else:
                console.print(
                    "[yellow]Deshabilitado[/yellow] — config existe pero está mal "
                    "o tiene enabled=false."
                )
        return
    console.print(
        f"[green]Habilitado[/green] · jid=[cyan]{cfg['jid']}[/cyan]"
    )
    if AMBIENT_STATE_PATH.is_file():
        try:
            n = sum(1 for _ in AMBIENT_STATE_PATH.open())
            console.print(f"[dim]State: {n} análisis registrados[/dim]")
        except Exception:
            pass


@ambient.command("disable")
def ambient_disable():
    """Deshabilitar ambient (deja el config pero con enabled=false)."""
    if not AMBIENT_CONFIG_PATH.is_file():
        console.print("[dim]No había config.[/dim]")
        return
    try:
        c = json.loads(AMBIENT_CONFIG_PATH.read_text(encoding="utf-8"))
    except Exception:
        c = {}
    c["enabled"] = False
    AMBIENT_CONFIG_PATH.write_text(json.dumps(c, indent=2), encoding="utf-8")
    console.print("[green]✓[/green] ambient deshabilitado. Re-habilitar con /enable_ambient en el bot.")


@ambient.command("test")
@click.argument("path", required=False)
def ambient_test(path: str | None):
    """Simular análisis sobre una nota existente (dry-run en vivo, sí escribe)."""
    col = get_db()
    if path is None:
        inbox = VAULT_PATH / _CAPTURE_FOLDER
        candidates = sorted(inbox.glob("*.md"))[:1]
        if not candidates:
            console.print(f"[yellow]Sin notas en {inbox}[/yellow]")
            return
        p = candidates[0]
    else:
        p = VAULT_PATH / path if not path.startswith("/") else Path(path)
    if not p.is_file():
        console.print(f"[red]No existe:[/red] {p}")
        return
    doc_id_prefix = str(p.relative_to(VAULT_PATH))
    raw = p.read_text(encoding="utf-8", errors="ignore")
    h = file_hash(raw)
    console.print(f"[cyan]Triggereando ambient hook sobre:[/cyan] {doc_id_prefix}")
    _ambient_hook(col, p, doc_id_prefix, h)
    console.print("[green]✓[/green] Listo. Ver log: tail ~/.local/share/obsidian-rag/ambient.jsonl")


def _load_raw_ambient_config() -> dict:
    """Read raw ambient config JSON (no filtering). Empty dict if missing."""
    if not AMBIENT_CONFIG_PATH.is_file():
        return {}
    try:
        c = json.loads(AMBIENT_CONFIG_PATH.read_text(encoding="utf-8"))
        return c if isinstance(c, dict) else {}
    except Exception:
        return {}


def _save_raw_ambient_config(cfg: dict) -> None:
    """Atomic-ish write of the raw ambient config. Preserves other keys."""
    AMBIENT_CONFIG_PATH.parent.mkdir(parents=True, exist_ok=True)
    AMBIENT_CONFIG_PATH.write_text(
        json.dumps(cfg, indent=2, ensure_ascii=False), encoding="utf-8"
    )


@ambient.group("folders")
def ambient_folders():
    """Administrar carpetas donde corre el hook ambient (default 00-Inbox)."""


@ambient_folders.command("list")
def ambient_folders_list():
    """Listar allowed_folders actuales."""
    cfg = _load_raw_ambient_config()
    folders = cfg.get("allowed_folders") or []
    if not folders:
        console.print(
            f"[dim]Default:[/dim] [cyan]{_CAPTURE_FOLDER}[/cyan] "
            "[dim](no hay allowed_folders seteado)[/dim]"
        )
        return
    console.print("[cyan]Ambient corre sobre:[/cyan]")
    for f in folders:
        console.print(f"  · [cyan]{f}[/cyan]")


@ambient_folders.command("add")
@click.argument("folder")
def ambient_folders_add(folder: str):
    """Agregar una carpeta del vault a allowed_folders (dedup + valida)."""
    folder = folder.rstrip("/").strip()
    if not folder:
        console.print("[red]Folder vacío.[/red]")
        return
    target = VAULT_PATH / folder
    if not target.is_dir():
        console.print(
            f"[red]No existe en el vault:[/red] {target}"
        )
        return
    cfg = _load_raw_ambient_config()
    if not cfg:
        console.print(
            "[yellow]No hay ambient config[/yellow] — enviá /enable_ambient "
            "al bot de WhatsApp primero."
        )
        return
    folders = list(cfg.get("allowed_folders") or [])
    if folder in folders:
        console.print(f"[dim]Ya estaba:[/dim] {folder}")
        return
    folders.append(folder)
    cfg["allowed_folders"] = folders
    _save_raw_ambient_config(cfg)
    console.print(f"[green]✓[/green] Agregado [cyan]{folder}[/cyan]")
    console.print(f"[dim]Ahora:[/dim] {', '.join(folders)}")


@ambient_folders.command("remove")
@click.argument("folder")
def ambient_folders_remove(folder: str):
    """Quitar carpeta. Si queda vacía → vuelve a default [00-Inbox]."""
    folder = folder.rstrip("/").strip()
    cfg = _load_raw_ambient_config()
    if not cfg:
        console.print("[yellow]No hay ambient config.[/yellow]")
        return
    folders = list(cfg.get("allowed_folders") or [])
    if folder not in folders:
        console.print(f"[dim]No estaba:[/dim] {folder}")
        return
    folders = [f for f in folders if f != folder]
    if not folders:
        # Wipe the field → the config reader falls back to default.
        cfg.pop("allowed_folders", None)
        _save_raw_ambient_config(cfg)
        console.print(
            f"[green]✓[/green] Quitado {folder}. Default restaurado: "
            f"[cyan]{_CAPTURE_FOLDER}[/cyan]"
        )
        return
    cfg["allowed_folders"] = folders
    _save_raw_ambient_config(cfg)
    console.print(f"[green]✓[/green] Quitado [cyan]{folder}[/cyan]")
    console.print(f"[dim]Ahora:[/dim] {', '.join(folders)}")


@ambient.command("log")
@click.option("-n", default=10, show_default=True, help="Últimos N eventos")
def ambient_log(n: int):
    """Tail del log de eventos ambient."""
    if not AMBIENT_LOG_PATH.is_file():
        console.print(f"[yellow]Aún no hay log en {AMBIENT_LOG_PATH}[/yellow]")
        return
    lines = AMBIENT_LOG_PATH.read_text(encoding="utf-8").splitlines()[-n:]
    for line in lines:
        try:
            e = json.loads(line)
        except Exception:
            continue
        ts = e.get("ts", "")[-8:]
        applied = e.get("wikilinks_applied", 0)
        dupes = len(e.get("dupes") or [])
        rel = e.get("related_count", 0)
        sent = "📨" if e.get("whatsapp_sent") else ("🔇" if e.get("quiet") else "✗")
        console.print(
            f"[dim]{ts}[/dim] {sent} "
            f"[cyan]{e.get('path', '—')}[/cyan] "
            f"[yellow]links={applied}[/yellow] "
            f"[magenta]dupes={dupes}[/magenta] "
            f"[blue]rel={rel}[/blue]"
        )


# ── Tasks-mode: intent + time-scope for WhatsApp/web/CLI agenda queries ─────
# When the user asks "qué tengo que hacer esta semana" the right answer is not
# a vault RAG retrieve (that picks up recent WA markdown and answers with a
# chat fragment) — it's the live services layer filtered to the right window.
# Helpers here are consumed by `rag serve` `/query` and by `web/server.py`.

_TASKS_INTENT_TOKENS = re.compile(
    r"\b(pendientes?|agenda|recordatorios?|to-?dos?|tasks?|reminders?|"
    r"tareas?|reuniones?|meetings?|prioridad(?:es)?|prioriz|"
    r"compromisos?|obligaciones?|deberes?)",
    re.IGNORECASE,
)
_TASKS_INTENT_PHRASES = re.compile(
    r"(qu[eé]\s+(tengo|hacer|debo|hay|me\s+falta|me\s+queda)|"
    r"what\s+do\s+i\s+(have|need)|"
    r"(tengo|hay)\s+(algo|cosas?|eventos?|citas?)\s+(pendiente|hoy|mañana|esta\s+semana)|"
    r"que\s+hay\s+(para\s+)?(hoy|mañana|esta\s+semana)|"
    r"organiz(ar|ame)\s+(el\s+d[ií]a|la\s+semana))",
    re.IGNORECASE,
)


def _is_tasks_query(q: str) -> bool:
    if not q:
        return False
    return bool(_TASKS_INTENT_TOKENS.search(q) or _TASKS_INTENT_PHRASES.search(q))


# Weather intent detector (2026-04-22 WhatsApp latency fix).
#
# Measurement: three separate "llueve hoy?" queries cost 50-72s each on
# the WA/serve endpoint (rag_queries, 30d window). Root cause: the query
# ran the full retrieve + LLM pipeline, which (a) has no rain data, (b)
# hallucinated or returned "No tengo esa información" after a round trip.
#
# Expected cost post-fix: _fetch_weather_forecast (~500ms wttr.in call)
# + _weather_comment (~1-2s qwen2.5:3b helper). Total ~2-3s vs 50-70s
# previous. ~20-30× speedup on this class of query.
#
# Token list stays narrow to prevent false positives — "clima laboral"
# / "clima de equipo" are semantic queries about vault content, not
# meteorological. The additional exclusion list below filters those.
# `tiempo` is the most ambiguous ("tengo tiempo para X" is chronological)
# — require co-occurrence with a weather action verb/adjective to count.
_WEATHER_KEYWORDS = re.compile(
    r"\b("
    # All verb conjugations of `llover`: llueve, llover, llovía, lloviendo, etc.
    # Match the root llov/lluev + common endings. `lluvi` covers the noun forms.
    r"llueve|llover[aá]?s?|llov[ií](?:a|[oó]|ese)|lloviendo|"
    r"lluvia|lluvi[ao]s[ao]?|precipitaciones?|"
    r"tormenta|chaparr[oó]n|granizo|"
    r"temperatura|frio|fr[ií]o|calor|caluroso|"
    r"sol|soleado|nublado|nubes?|niebla|"
    r"viento|vendaval|"
    # Pronóstico / pronostico — variants with/without accents.
    r"pron[oó]st[ií]co|clima"
    r")\b",
    re.IGNORECASE,
)
# Multi-word constructs that flip "tiempo" (ambiguous) and "clima"
# (ambiguous in workplace contexts) to non-weather interpretations.
# Match any of these → suppress the weather classifier.
_WEATHER_EXCLUDES = re.compile(
    r"\b(clima\s+(laboral|de\s+equipo|organizacional|escolar)|"
    r"tengo\s+tiempo|hay\s+tiempo|tiempo\s+(libre|que|para\s+[a-z]))",
    re.IGNORECASE,
)
# Max tokens for a query to be considered weather. "llueve hoy?" = 2
# tokens, "cómo va a estar el clima mañana?" = 7. Anything longer is
# likely context-heavy and should go through the RAG path.
_WEATHER_MAX_TOKENS = 10


def _is_weather_query(q: str) -> bool:
    """Return True if `q` is a simple weather question (llueve hoy?, cómo
    va el clima, etc.). Used by the serve endpoint to short-circuit past
    retrieve + LLM — the pipeline has no weather data and wastes ~60s per
    query hallucinating or bailing."""
    if not q:
        return False
    stripped = q.strip()
    if not stripped:
        return False
    # Short-query gate — long queries often embed meteorological keywords
    # incidentally ("ayer pasamos frío con la familia…") and shouldn't
    # hijack retrieval.
    if len(stripped.split()) > _WEATHER_MAX_TOKENS:
        return False
    if _WEATHER_EXCLUDES.search(stripped):
        return False
    return bool(_WEATHER_KEYWORDS.search(stripped))


# Finance + tarjetas short-circuit — espeja el patrón del weather. El
# WhatsApp listener pega al `rag serve /query` que NO tiene el pre-router
# de tools del web `/api/chat`, así que queries como "cuánto gasté de
# tarjeta este mes" terminaban en retrieve genérico → 90 notas random
# del vault → LLM alucinaba (user report 2026-04-26).
#
# Regex en sync con `_TOOL_INTENT_RULES` de `web/server.py:187-209`. Si
# se cambia uno, cambiar el otro — comparten semántica.
_FINANCE_CARDS_KEYWORDS = re.compile(
    r"\btarjet|\bvisa\b|\bmaster(?:card)?\b|\bamex\b|\bcr[eé]dito\b"
    r"|saldo.*paga|fecha.*cierre|fecha.*vencim|resumen.*tarjeta"
    r"|cu[aá]nto.*deb[oe]"
    r"|\b(?:[uú]ltim[oa]s?|recientes?)\s+(?:gastos?|consumos?|movimientos?|compras?|cargos?|transac)\b"
    r"|\b(?:consumos?|movimientos?|cargos?)\s+(?:de|del|en|con|mi)"
    r"|gast[oéó]s?|gast[aá][mn]os|gastar|presupuesto|plata|finanz|moze",
    re.IGNORECASE,
)
_FINANCE_CARDS_MAX_TOKENS = 16


def _is_finance_or_cards_query(q: str) -> bool:
    """True si `q` pide datos del módulo financiero (MOZE export + xlsx
    de tarjetas en iCloud `/Finances`). El short-circuit consulta
    `_fetch_finance` y/o `_fetch_credit_cards` en lugar de hacer
    retrieve sobre el vault — esos archivos no son notas indexadas y el
    retrieve siempre los miss.
    """
    if not q:
        return False
    stripped = q.strip()
    if not stripped:
        return False
    if len(stripped.split()) > _FINANCE_CARDS_MAX_TOKENS:
        return False
    return bool(_FINANCE_CARDS_KEYWORDS.search(stripped))


def _format_finance_cards_block(finance: dict | None, cards: list[dict] | None) -> str:
    """Datos de finance + cards pegados como bloques markdown plain.
    Diseñado para entrar literal en el prompt del LLM helper sin
    transformación, así el LLM no tiene chance de inventar números.
    """
    parts: list[str] = []

    if cards:
        lines = ["### Tarjetas (resumen del banco)"]
        for c in cards:
            brand = c.get("brand") or "Tarjeta"
            last4 = c.get("last4") or "----"
            lines.append(f"- {brand} ····{last4}:")
            total_bits: list[str] = []
            if c.get("total_ars"):
                total_bits.append(f"${int(round(c['total_ars'])):,}".replace(",", "."))
            if c.get("total_usd"):
                total_bits.append(f"U$S{c['total_usd']:.2f}")
            if total_bits:
                lines.append(f"    Total a pagar: {' + '.join(total_bits)}")
            if c.get("due_date"):
                lines.append(f"    Vence: {c['due_date']}")
            if c.get("closing_date"):
                lines.append(f"    Cerró: {c['closing_date']}")
            top = (c.get("top_purchases_ars") or [])[:3]
            if top:
                lines.append("    Top consumos ARS:")
                for p in top:
                    desc = p.get("description") or "—"
                    amt = f"${int(round(p.get('amount') or 0)):,}".replace(",", ".")
                    lines.append(f"      - {desc} · {amt}")
            usd_top = (c.get("top_purchases_usd") or [])[:2]
            if usd_top:
                lines.append("    Top consumos USD:")
                for p in usd_top:
                    desc = p.get("description") or "—"
                    amt = f"U$S{p.get('amount') or 0:.2f}"
                    lines.append(f"      - {desc} · {amt}")
        parts.append("\n".join(lines))

    if finance and isinstance(finance, dict) and finance.get("ars"):
        ars = finance["ars"]
        lines = ["### Gastos del mes (MOZE — gastos cargados manualmente)"]
        lines.append(f"- Mes: {finance.get('month_label') or '—'}")
        lines.append(
            f"- Día: {finance.get('days_elapsed')}/{finance.get('days_in_month')}"
        )
        if ars.get("this_month"):
            this_m = f"${int(round(ars['this_month'])):,}".replace(",", ".")
            lines.append(f"- Gasto ARS este mes: {this_m}")
        if ars.get("prev_month"):
            prev_m = f"${int(round(ars['prev_month'])):,}".replace(",", ".")
            delta = ars.get("delta_pct")
            delta_str = f" ({delta:+.1f}%)" if delta is not None else ""
            lines.append(f"- Mes anterior: {prev_m}{delta_str}")
        if ars.get("projected"):
            proj = f"${int(round(ars['projected'])):,}".replace(",", ".")
            lines.append(f"- Proyectado fin de mes: {proj}")
        cats = (ars.get("top_categories") or [])[:5]
        if cats:
            lines.append("- Top categorías ARS:")
            for cat in cats:
                amt = f"${int(round(cat.get('amount') or 0)):,}".replace(",", ".")
                share = round((cat.get("share") or 0) * 100)
                lines.append(f"    - {cat.get('name') or '—'}: {amt} ({share}%)")
        usd = finance.get("usd") or {}
        if usd.get("this_month"):
            lines.append(f"- Gasto USD este mes: U$S{usd['this_month']:,.2f}")
        parts.append("\n".join(lines))

    return "\n\n".join(parts).strip()


def _detect_finance_intent(question: str) -> str:
    """Clasifica la pregunta financiera del user para decidir qué fuente
    pasar al LLM. Tres buckets:

      - `cards`:  query menciona tarjeta/visa/master/amex/crédito/banco
                  → solo CSV del banco, MOZE oculto del prompt.
      - `moze`:   query menciona MOZE/efectivo/gastos diarios/día a día
                  → solo MOZE, tarjetas ocultas.
      - `generic`: query genérica (cuánto gasté este mes, total de gastos)
                  → ambas fuentes etiquetadas, el LLM cita las dos por
                  separado.

    Regla del user (2026-04-26): MOZE y tarjetas son fuentes SEPARADAS
    de gastos personales — sumar los montos es alucinación.
    """
    q = (question or "").lower()
    cards_re = re.compile(
        r"\btarjeta(s)?\b|\bvisa\b|\bmaster(card)?\b|\bamex\b|\b"
        r"american\s+express\b|\bcr[eé]dito\b|\bbanco\b|\bdebitos?\s+autom"
    )
    moze_re = re.compile(
        r"\bmoze\b|\befectivo\b|\bgastos?\s+diarios?\b|\bd[ií]a\s+a\s+d[ií]a\b"
    )
    if cards_re.search(q):
        return "cards"
    if moze_re.search(q):
        return "moze"
    return "generic"


def _wants_finance_detail(question: str) -> bool:
    """Detecta si el user quiere TODOS los movimientos (detalle completo)
    en lugar del summary corto con top 3-5. Triggers:

      - Sustantivo "detalle" / "detalles" / "detallado"
      - Verbo "detallar" conjugado (imperativo voseo/tuteo + infinitivo):
        "detallame", "detalláme", "detallá", "detalla", "detállame",
        "detallanos", "detallarme", "detallarlos" — user report
        2026-04-26 voice "detallame el consumo de la tarjeta de credito"
        no disparaba detail porque solo matcheaba el sustantivo.
      - "resumen" / "resúmen" / "resúmenes" — en dominio de tarjetas
        "el resumen" = el documento del banco con todos los movimientos.
      - "todos los movimientos/gastos/consumos/cargos"
      - "movimientos" / "consumos" / "cargos" (plurales solos)
      - "consumo" singular (el short-circuit ya filtró por tarjeta/visa/etc.
        antes, así que no hay falso-positivo "mi consumo de agua")
      - "lista completa" / "lista de consumos"
      - "items" / "ítems"
      - "mostrame/dame/ver todo"

    Sin matches: respuesta corta default (top consumos).
    """
    q = (question or "").lower()
    return bool(re.search(
        # Sustantivo detalle / adjetivo detallado
        r"\bdetalles?\b|\bdetallad[oa]\b|"
        # Verbo detallar conjugado — imperativo voseo/tuteo + infinitivo con
        # clíticos. Cubre: detalla, detallá, detallame, detalláme, detállame,
        # detallanos, detallarme, detallarlo, detallarla, detallarlos, etc.
        r"\bdet[aá]ll[aá](?:me|nos|lo|la|los|las|rme|rlo|rla|rlos|rlas)?\b|"
        # Sustantivo resumen / plural
        r"\bres[uú]men(?:es)?\b|"
        r"\btodos\s+los\s+(movimientos|gastos|consumos|cargos)\b|"
        r"\b(movimientos|consumos|cargos)\b|"
        # Singular "consumo" — OK porque _is_finance_or_cards_query filtró
        # por contexto financiero antes de llegar acá.
        r"\bconsumo\b|"
        r"\blista\s+(completa|de\s+(consumos|movimientos|gastos|cargos))\b|"
        r"\b\u00edtems?\b|\bitems\b|"
        r"\b(mostrame|dame|ver)\s+todo\b",
        q,
    ))


_DESC_NOISE_RE = re.compile(
    # Códigos del banco que son ruido — no aportan al user:
    # "Merpago*idilicadeco" → "idilicadeco" (sacamos prefijo del processor)
    # "Claro deb aut 000021416263265" → "Claro" (sacamos "deb aut <numbers>")
    # "Pago tic ppt adventistas" → ok como está
    # "Rapipago x123456" → "Rapipago"
    r"^(merpago|mercadopago|mercpago)\*\s*|"
    r"\s*(deb(\.|ito)?\s*aut(\.|om(a|á)tico)?|debito\s+autom|"
    r"d\.?\s*automatico)\s+\d{5,}.*$|"
    r"\s+x?\d{6,}\s*$|"
    r"\s+ref\.?\s*\d+\s*$|"
    r"\s+ord\.?\s*\d+\s*$",
    re.IGNORECASE,
)


def _clean_purchase_description(desc: str) -> str:
    """Limpia descripciones crudas del banco para que sean legibles.

    Ejemplos:
      "Merpago*idilicadeco"            → "idilicadeco"
      "Claro deb aut 000021416263265"  → "Claro"
      "Pago tic ppt adventistas"       → "Pago tic ppt adventistas" (no toca)
      "Rapipago x123456"               → "Rapipago"
      "Payu*ar*uber"                   → "Payu/ar/uber" (asteriscos como
                                         separador, no markdown italic)

    No agresivo — preserva descripciones que ya son legibles. Solo
    strippea patterns de ruido bancario explícitos.

    También: reemplaza `*` por `/` en el texto restante. El frontend
    del chat web renderea la respuesta como markdown — los `*` quedan
    interpretados como italic abriendo/cerrando spans de `<em>`. Para
    descripciones tipo "Payu*ar*uber" el output era "Payu<em>ar</em>uber".
    Reemplazar `*` por `/` mantiene el sentido (separador entre componentes
    del comercio: payu / ar / uber) sin disparar markdown formatting.
    """
    if not desc:
        return ""
    cleaned = _DESC_NOISE_RE.sub("", desc).strip()
    # Si después del clean queda vacío (la regex match consumió todo),
    # fallback al original — mejor algo legible que vacío.
    cleaned = cleaned or desc.strip()
    # Escape: asteriscos en descripciones del banco (separadores tipo
    # "Payu*ar*uber") se renderean como italic en markdown. Cambiarlos
    # por "/" preserva el sentido sin formatting accidental.
    return cleaned.replace("*", "/")


def _finance_short_circuit_answer(
    question: str,
) -> tuple[str, int, bool, float] | None:
    """Resuelve queries de finance/tarjetas sin pasar por retrieve.

    Tupla retornada: ``(answer, n_cards, has_moze, t_gen_seconds)``.
    Devuelve ``None`` si:
      - la query NO es finance/cards (caller sigue al path normal),
      - falla el lazy-import de `web.server` (caller sigue al path normal),
      - el LLM helper falla sin texto (caller sigue al path normal).

    Datos vienen de `_fetch_finance` (MOZE CSV) y `_fetch_credit_cards`
    (xlsx del banco), ambos en `web/server.py`. La respuesta la genera
    `_finance_cards_comment` con un prompt anti-alucinación inline.

    Compartido entre `_handle_query` (`/query`) y `_handle_chat`
    (`/chat`) — el WhatsApp listener rutea `/search ...` al primero y
    bare text al segundo, ambos paths necesitaban el short-circuit
    para que "decime cuanto gasté de tarjeta este mes" funcione tanto
    via comando como via voice transcript.
    """
    if not _is_finance_or_cards_query(question):
        return None
    t0 = time.perf_counter()
    try:
        # Lazy import — `web.server` es importable standalone (no
        # requiere FastAPI corriendo) pero no quiero forzar el import
        # en cada arranque del serve si no hay queries de finance.
        from web.server import _fetch_credit_cards, _fetch_finance
        finance_data = _fetch_finance()
        cards_data = _fetch_credit_cards()
    except Exception as exc:
        _silent_log("serve_finance_fetch", exc)
        return None

    if not finance_data and not cards_data:
        answer = (
            "No tengo data fresca de tus tarjetas ni de MOZE — "
            "el último export del banco/Money app puede no estar al día."
        )
    else:
        try:
            answer = _finance_cards_comment(question, finance_data, cards_data)
        except Exception as exc:
            _silent_log("serve_finance_comment", exc)
            return None

    if not answer:
        return None
    return (
        answer,
        len(cards_data or []),
        bool(finance_data),
        time.perf_counter() - t0,
    )


def _fmt_ars(amount) -> str:
    """Formato ARS estándar: `$1.234.567` (puntos como separador miles)."""
    try:
        n = int(round(float(amount or 0)))
    except Exception:
        return "$0"
    return f"${n:,}".replace(",", ".")


def _fmt_usd(amount) -> str:
    """Formato USD estándar: `U$S98.93`."""
    try:
        return f"U$S{float(amount or 0):.2f}"
    except Exception:
        return "U$S0.00"


def _finance_cards_comment(question: str, finance: dict | None, cards: list[dict] | None) -> str:
    """Genera respuesta determinística (sin LLM) para queries financieras
    de WhatsApp. Diseño:

    - Detecta el intent (cards/moze/generic) vía `_detect_finance_intent`.
    - Renderea la respuesta DIRECTAMENTE desde los dicts. El LLM nunca
      ve los números — no puede alucinar ni mezclar fuentes.

    Decisión 2026-04-26 (user report): el LLM helper (qwen2.5:3b temp=0)
    seguía mezclando MOZE con tarjeta aunque le pasáramos solo una
    fuente filtrada en el bloque. Reemplazamos el LLM con render
    programático — más rápido (~5ms vs 2-10s), 0% alucinación, totales
    siempre exactos.

    Si los datos son nulos o no hay nada que reportar, devuelve un
    mensaje específico al intent.
    """
    intent = _detect_finance_intent(question)
    detail = _wants_finance_detail(question)

    if intent == "cards":
        return _render_cards_answer(cards, detail=detail)
    if intent == "moze":
        return _render_moze_answer(finance, detail=detail)
    return _render_generic_finance_answer(finance, cards, detail=detail)


def _render_cards_answer(cards: list[dict] | None, *, detail: bool = False) -> str:
    """Respuesta para queries tipo "cuánto gasté de tarjeta este mes".
    SOLO datos del CSV de tarjeta — MOZE explícitamente excluido.

    Si `detail=True` (user pidió "detalle"/"todos los movimientos"),
    devuelve formato multi-línea con TODOS los consumos del ciclo en
    lugar del summary corto con top 3-5.
    """
    if not cards:
        return (
            "No tengo data fresca de tus tarjetas — "
            "el último export del banco puede no estar al día."
        )
    # Sumamos ARS + listamos USD por tarjeta (no se suman entre divisas).
    total_ars = sum(float(c.get("total_ars") or 0) for c in cards)
    total_usd = sum(float(c.get("total_usd") or 0) for c in cards)
    parts: list[str] = []
    if total_ars:
        parts.append(_fmt_ars(total_ars))
    if total_usd:
        parts.append(_fmt_usd(total_usd))
    if not parts:
        return (
            "Tus tarjetas figuran en el sistema pero sin montos del último "
            "ciclo — revisá el export del banco."
        )

    # ── Modo DETALLE: lista completa de movimientos ─────────────────
    if detail:
        out_lines = []
        for c in cards:
            brand = c.get("brand") or "Tarjeta"
            last4 = c.get("last4") or "----"
            sub_parts = []
            if c.get("total_ars"):
                sub_parts.append(_fmt_ars(c["total_ars"]))
            if c.get("total_usd"):
                sub_parts.append(_fmt_usd(c["total_usd"]))
            header = f"📇 {brand} ····{last4} — {' + '.join(sub_parts)}"
            if c.get("closing_date"):
                header += f" (cerró {c['closing_date']})"
            out_lines.append(header)
            # ARS — preferimos `all_purchases_ars` si está disponible
            # (no truncado), sino caemos a `top_purchases_ars`.
            ars_list = c.get("all_purchases_ars") or c.get("top_purchases_ars") or []
            if ars_list:
                out_lines.append("\nMovimientos ARS:")
                for p in ars_list:
                    desc = _clean_purchase_description(p.get("description") or "—")
                    amt = _fmt_ars(p.get("amount") or 0)
                    date = p.get("date") or "?"
                    out_lines.append(f"  · {date} · {desc} · {amt}")
            usd_list = c.get("all_purchases_usd") or c.get("top_purchases_usd") or []
            if usd_list:
                out_lines.append("\nMovimientos USD:")
                for p in usd_list:
                    desc = _clean_purchase_description(p.get("description") or "—")
                    amt = _fmt_usd(p.get("amount") or 0)
                    date = p.get("date") or "?"
                    out_lines.append(f"  · {date} · {desc} · {amt}")
            # Otros conceptos = impuestos/IVA/retenciones. Sin esto,
            # `sum(movimientos) != total_ars` y el user cree que se
            # pierde plata. Antes de 2026-04-26 el parser los ignoraba
            # y el render no los mostraba — detectamos el gap cuando
            # el user preguntó por qué el resumen decía $549k pero los
            # movimientos visibles sumaban $494k (diff = impuestos).
            other_charges = c.get("other_charges") or []
            if other_charges:
                out_lines.append("\nOtros conceptos (IVA, sellos, retenciones):")
                for oc in other_charges:
                    desc = oc.get("description") or "—"
                    amt = _fmt_ars(oc.get("amount") or 0)
                    out_lines.append(f"  · {desc} · {amt}")
                oc_total = c.get("other_charges_total_ars") or 0
                if oc_total:
                    out_lines.append(f"  Subtotal otros conceptos: {_fmt_ars(oc_total)}")
            out_lines.append("")  # separador entre tarjetas
        return "\n".join(out_lines).rstrip()

    # ── Modo SUMMARY default: top 3 consumos ────────────────────────
    if len(cards) == 1:
        c = cards[0]
        brand = c.get("brand") or "Tarjeta"
        last4 = c.get("last4") or "----"
        top = (c.get("top_purchases_ars") or [])[:3]
        if top:
            descs = [
                _clean_purchase_description(p.get("description") or "—")
                for p in top
            ]
            return (
                f"Tarjeta ({brand} ····{last4}): {' + '.join(parts)} — "
                f"top consumos: {', '.join(descs)}."
            )
        return f"Tarjeta ({brand} ····{last4}): {' + '.join(parts)}."
    # Múltiples tarjetas — desagregamos.
    breakdown = []
    for c in cards:
        brand = c.get("brand") or "Tarjeta"
        last4 = c.get("last4") or "----"
        bits = []
        if c.get("total_ars"):
            bits.append(_fmt_ars(c["total_ars"]))
        if c.get("total_usd"):
            bits.append(_fmt_usd(c["total_usd"]))
        if bits:
            breakdown.append(f"{brand} ····{last4} {' + '.join(bits)}")
    if breakdown:
        return f"Tarjetas: {' / '.join(breakdown)}. Total: {' + '.join(parts)}."
    return f"Tarjetas: {' + '.join(parts)}."


def _render_moze_answer(finance: dict | None, *, detail: bool = False) -> str:
    """Respuesta para queries tipo "cuánto gasté en MOZE/efectivo este mes".
    SOLO datos de MOZE — tarjetas explícitamente excluidas.

    `detail=True`: lista TODAS las categorías + USD (no solo top 1).
    """
    _ = detail  # acepta el flag para uniformidad — render extendido abajo
    if not finance or not isinstance(finance, dict):
        return (
            "No tengo data fresca de MOZE — "
            "el último export de la app puede no estar al día."
        )
    ars = finance.get("ars") or {}
    this_month = ars.get("this_month")
    if not this_month:
        return (
            "No tengo data fresca de MOZE — "
            "el último export de la app puede no estar al día."
        )
    if detail:
        # Modo detalle: header + tabla de categorías + USD.
        out = [f"💰 MOZE — {_fmt_ars(this_month)}"]
        prev = ars.get("prev_month")
        delta_pct = ars.get("delta_pct")
        if prev and delta_pct is not None:
            sign = "+" if delta_pct >= 0 else ""
            out.append(f"  Mes anterior: {_fmt_ars(prev)} ({sign}{delta_pct:.1f}%)")
        proj = ars.get("projected")
        if proj:
            out.append(f"  Proyectado fin de mes: {_fmt_ars(proj)}")
        # Todas las categorías.
        cats = ars.get("top_categories") or []
        if cats:
            out.append("\nCategorías:")
            for c in cats:
                share = round((c.get("share") or 0) * 100)
                out.append(
                    f"  · {c.get('name') or '—'}: {_fmt_ars(c.get('amount') or 0)} ({share}%)"
                )
        usd = (finance.get("usd") or {}).get("this_month")
        if usd:
            out.append(f"\nUSD este mes: {_fmt_usd(usd)}")
        return "\n".join(out)

    # Modo summary default.
    parts = [f"MOZE: {_fmt_ars(this_month)}"]
    prev = ars.get("prev_month")
    delta_pct = ars.get("delta_pct")
    if prev and delta_pct is not None:
        sign = "+" if delta_pct >= 0 else ""
        parts.append(f"vs mes ant {_fmt_ars(prev)} ({sign}{delta_pct:.1f}%)")
    cats = (ars.get("top_categories") or [])[:1]
    if cats:
        c = cats[0]
        share = round((c.get("share") or 0) * 100)
        parts.append(f"top: {c.get('name') or '—'} {share}%")
    usd = (finance.get("usd") or {}).get("this_month")
    if usd:
        parts.append(f"+ {_fmt_usd(usd)}")
    return " — ".join(parts) + "."


def _render_generic_finance_answer(
    finance: dict | None, cards: list[dict] | None, *, detail: bool = False,
) -> str:
    """Respuesta para queries genéricas tipo "cuánto gasté este mes" (sin
    discriminar fuente). Cita las dos fuentes ETIQUETADAS por separado —
    NO suma ni da total combinado salvo que el user lo pida explícito.

    `detail=True`: emite versión larga de cards + MOZE concatenadas.
    """
    if detail:
        # Combinamos los dos detalles separados con header.
        return (
            _render_cards_answer(cards, detail=True)
            + "\n\n"
            + _render_moze_answer(finance, detail=True)
        )
    have_cards = cards and any(c.get("total_ars") or c.get("total_usd") for c in cards)
    have_moze = (
        finance and isinstance(finance, dict)
        and (finance.get("ars") or {}).get("this_month")
    )
    if not have_cards and not have_moze:
        return (
            "No tengo data fresca de tus tarjetas ni de MOZE — "
            "el último export del banco/Money app puede no estar al día."
        )
    bits = []
    if have_cards:
        total_ars = sum(float(c.get("total_ars") or 0) for c in cards)
        total_usd = sum(float(c.get("total_usd") or 0) for c in cards)
        card_parts = []
        if total_ars:
            card_parts.append(_fmt_ars(total_ars))
        if total_usd:
            card_parts.append(_fmt_usd(total_usd))
        if card_parts:
            bits.append(f"Tarjeta {' + '.join(card_parts)}")
    if have_moze:
        moze_amt = (finance.get("ars") or {}).get("this_month")
        bits.append(f"MOZE {_fmt_ars(moze_amt)}")
    return " + ".join(bits) + " (fuentes separadas — no se suman)."

# Path histórico (LLM helper) eliminado 2026-04-26 — sumaba MOZE+tarjeta
# como "alucinación" pesar del prompt anti-mix. Para recuperarlo: `git
# log -S "_finance_cards_comment_legacy" -- rag/__init__.py`.


_SCOPE_N_DAYS = re.compile(
    r"\bpr[oó]xim[oa]s?\s+(\d+)\s+d[ií]as?\b|\bnext\s+(\d+)\s+days?\b",
    re.IGNORECASE,
)
_SCOPE_WEEK = re.compile(
    r"\besta\s+semana\b|\bpr[oó]xima\s+semana\b|\bsemana\s+que\s+viene\b|"
    r"\bthis\s+week\b|\bnext\s+week\b",
    re.IGNORECASE,
)
_SCOPE_TOMORROW = re.compile(r"\bma(?:ñ|n)ana\b|\btomorrow\b", re.IGNORECASE)
_SCOPE_TODAY = re.compile(
    r"\bhoy\b|\bahora\b|\btoday\b|\beste\s+momento\b", re.IGNORECASE,
)


def _detect_time_scope(q: str) -> dict:
    """Return the time scope carried by the query. Priority: explicit N days
    beats week beats tomorrow beats today; unmarked queries get a 14-day
    reminders window + 7-day calendar window.
    """
    m = _SCOPE_N_DAYS.search(q or "")
    if m:
        n = int(m.group(1) or m.group(2) or 0)
        n = max(1, min(30, n))
        return {
            "key": "n_days", "label": f"próximos {n} días",
            "reminders_horizon": n + 1, "calendar_ahead": n,
        }
    if _SCOPE_WEEK.search(q or ""):
        return {
            "key": "week", "label": "esta semana",
            "reminders_horizon": 8, "calendar_ahead": 7,
        }
    if _SCOPE_TOMORROW.search(q or ""):
        return {
            "key": "tomorrow", "label": "mañana",
            "reminders_horizon": 2, "calendar_ahead": 1,
        }
    if _SCOPE_TODAY.search(q or ""):
        return {
            "key": "today", "label": "hoy",
            "reminders_horizon": 1, "calendar_ahead": 0,
        }
    return {
        "key": "general", "label": "próximas 2 semanas",
        "reminders_horizon": 14, "calendar_ahead": 7,
    }


# `_fetch_calendar_ahead` moved to `rag.integrations.calendar` (Phase 1b,
# 2026-04-25). Re-exported at the bottom of this file.


# ── Cross-source enrichment for web chat ─────────────────────────────────
# After a chat answer streams to the user, run a fast entity extraction +
# parallel scan of WhatsApp/Calendar/Reminders so the UI can show a
# "📎 contexto relacionado" footer with cross-channel signals (e.g.
# "📅 esta reunión ya está en tu calendar mañana 15hs").
# Wall budget: ~1.5s. Soft-fail per source — never block the answer.

_ENRICH_HELPER_PROMPT = (
    "Extraé entidades mencionadas en la respuesta sobre las notas del usuario. "
    "Devolvé SOLO JSON con esta forma exacta: "
    '{"people":[],"events":[],"topics":[]}. '
    "people: nombres propios de personas (sin títulos). "
    "events: reuniones, viajes, llamadas, deadlines. "
    "topics: 1-3 temas principales. "
    "Cada lista vacía si no hay nada. NADA fuera del JSON."
)


def extract_enrich_entities(question: str, answer: str) -> dict:
    """Single helper-LLM pass to mine names/events/topics from the answer.
    Used by build_enrich_payload to feed cross-source lookups.
    Returns {"people": [...], "events": [...], "topics": [...]}.
    Skipped (returns empty) for very short answers or on any error.
    """
    empty = {"people": [], "events": [], "topics": []}
    if not answer or len(answer.strip()) < 40:
        return empty
    user_msg = f"Pregunta: {question}\n\nRespuesta:\n{answer[:1500]}"
    # Reuse the resident chat model (qwen2.5:7b, already pinned via the
    # web prewarmer) instead of qwen2.5:3b — avoids the 2-5s cold load
    # that blew the enrich budget repeatedly. JSON-mode + 160 tokens lands
    # at ~600-900ms warm, well inside the wall ceiling.
    try:
        rsp = ollama.chat(
            model=resolve_chat_model(),
            messages=[
                {"role": "system", "content": _ENRICH_HELPER_PROMPT},
                {"role": "user", "content": user_msg},
            ],
            options={**CHAT_OPTIONS, "num_predict": 160, "num_ctx": 2048, "format": "json"},
            keep_alive=chat_keep_alive(),
        )
        raw = (rsp.message.content or "").strip()
        data = json.loads(raw)
        return {
            "people": [str(p).strip() for p in (data.get("people") or []) if str(p).strip()][:5],
            "events": [str(e).strip() for e in (data.get("events") or []) if str(e).strip()][:5],
            "topics": [str(t).strip() for t in (data.get("topics") or []) if str(t).strip()][:5],
        }
    except Exception:
        return empty


def _humanize_relative_es(ts_str: str) -> str:
    """ISO/SQLite timestamp → 'hoy' / 'ayer' / 'hace 3 días' / 'hace 2 semanas'.
    Handles both 'YYYY-MM-DD HH:MM:SS±HH:MM' (WA SQLite) and ISO-8601.
    """
    if not ts_str:
        return ""
    try:
        s = ts_str.replace("Z", "+00:00")
        if " " in s and "T" not in s:
            s = s.replace(" ", "T", 1)
        dt = datetime.fromisoformat(s)
        # Drop tz so we can subtract from naive datetime.now()
        if dt.tzinfo is not None:
            dt = dt.replace(tzinfo=None)
    except (ValueError, TypeError):
        return ""
    delta = datetime.now() - dt
    if delta.days < 0:
        return ""
    if delta.days == 0:
        return "hoy"
    if delta.days == 1:
        return "ayer"
    if delta.days < 7:
        return f"hace {delta.days} días"
    weeks = delta.days // 7
    return f"hace {weeks} semana{'s' if weeks > 1 else ''}"


def _enrich_terms(entities: dict, min_len: int = 3) -> list[str]:
    raw = entities.get("people", []) + entities.get("events", []) + entities.get("topics", [])
    out: list[str] = []
    seen: set[str] = set()
    for t in raw:
        k = (t or "").strip().lower()
        if len(k) < min_len or k in seen:
            continue
        seen.add(k)
        out.append(t)
    return out


_CONTACT_NAME_CACHE: dict[str, str] = {}


def _apple_contact_name(phone: str) -> str | None:
    """Look up a phone number in macOS Contacts via osascript. Returns the
    contact's name or None. Cached in-process — Contacts isn't going to
    change mid-process and osascript is ~200ms per call. `phone` is
    normalised to digits-only before query (Contacts stores formatted
    numbers, the `whose ... contains` predicate matches substrings).
    """
    if not _apple_enabled() or not phone:
        return None
    digits = "".join(ch for ch in phone if ch.isdigit())
    if len(digits) < 8:
        return None
    if digits in _CONTACT_NAME_CACHE:
        return _CONTACT_NAME_CACHE[digits] or None
    import subprocess
    script = (
        'tell application "Contacts" to '
        'set _ppl to (every person whose value of phones contains "' + digits + '")\n'
        'if (count of _ppl) is 0 then return ""\n'
        'return name of (item 1 of _ppl)'
    )
    try:
        res = subprocess.run(
            ["osascript", "-e", script],
            capture_output=True, text=True, timeout=3,
        )
        name = (res.stdout or "").strip()
    except Exception:
        name = ""
    _CONTACT_NAME_CACHE[digits] = name
    return name or None


def _enrich_wa(entities: dict, days: int = 7, max_hits: int = 2) -> list[dict]:
    """Recent WhatsApp messages mentioning any entity term. SQLite read-only."""
    terms = _enrich_terms(entities)
    if not terms or not WHATSAPP_DB_PATH.is_file():
        return []
    import sqlite3
    cutoff = (datetime.now() - timedelta(days=days)).isoformat(sep=" ", timespec="seconds")
    like_clauses = " OR ".join(["LOWER(content) LIKE ?"] * len(terms))
    params: list = [cutoff] + [f"%{t.lower()}%" for t in terms]
    sql = f"""
      SELECT m.chat_jid, m.content, m.timestamp,
             COALESCE(c.name, m.chat_jid) AS chat_name
      FROM messages m
      LEFT JOIN chats c ON c.jid = m.chat_jid
      WHERE m.timestamp > ? AND m.content IS NOT NULL AND m.content != ''
        AND ({like_clauses})
      ORDER BY m.timestamp DESC
      LIMIT 50
    """
    try:
        con = sqlite3.connect(f"file:{WHATSAPP_DB_PATH}?mode=ro&immutable=1", uri=True)
        rows = list(con.execute(sql, params))
        con.close()
    except sqlite3.Error:
        return []
    seen_chats: set[str] = set()
    hits: list[dict] = []
    for jid, content, ts, chat_name in rows:
        if jid in seen_chats:
            continue
        seen_chats.add(jid)
        snippet = (content or "").replace("\n", " ").strip()[:80]
        # Pretty label: prefer chat name; fall back to phone (DM) or "grupo"
        is_group = jid.endswith("@g.us")
        is_lid = jid.endswith("@lid")  # WhatsApp opaque privacy identifier
        bare_name = (chat_name or "").strip()
        # chat_name often falls back to the bare jid (just digits) when the
        # contact wasn't synced — try Apple Contacts before falling back to
        # the raw phone (and skip the +<digits> fallback for @lid which is
        # a privacy identifier, not a real phone).
        if not bare_name or bare_name == jid or bare_name.isdigit() or bare_name == jid.split("@")[0]:
            phone = jid.split("@")[0]
            resolved = None
            if phone.isdigit() and not is_lid:
                resolved = _apple_contact_name(phone)
            if resolved:
                bare_name = resolved
            elif is_lid:
                bare_name = "contacto sin nombre"
            else:
                bare_name = (f"+{phone}" if phone.isdigit() else phone) or "WhatsApp"
        chat_label = f"grupo «{bare_name}»" if is_group else bare_name
        hits.append({
            "icon": "💬",
            "text": f"hablaste en {chat_label}",
            "snippet": snippet,
            "relative": _humanize_relative_es(ts),
            "channel": "wa",
        })
        if len(hits) >= max_hits:
            break
    return hits


def _enrich_calendar(entities: dict, max_hits: int = 2) -> list[dict]:
    """Calendar events whose title matches an entity term."""
    terms = [t.lower() for t in _enrich_terms(entities)]
    if not terms:
        return []
    today = _fetch_calendar_today(max_events=15)
    ahead = _fetch_calendar_ahead(days_ahead=7, max_events=40)
    seen: set[str] = set()
    hits: list[dict] = []
    for ev in today + ahead:
        title = (ev.get("title") or "").strip()
        title_l = title.lower()
        if not title or title_l in seen:
            continue
        if not any(t in title_l for t in terms):
            continue
        seen.add(title_l)
        when = ev.get("start") or ev.get("date_label") or ""
        time_range = ev.get("time_range") or ""
        when_label = " ".join(p for p in [when, time_range] if p).strip()
        hits.append({
            "icon": "📅",
            "text": f"está en tu calendar: «{title}»",
            "snippet": when_label,
            "relative": "",
            "channel": "calendar",
        })
        if len(hits) >= max_hits:
            break
    return hits


def _enrich_reminders(entities: dict, max_hits: int = 2) -> list[dict]:
    """Reminders whose name matches an entity term."""
    terms = [t.lower() for t in _enrich_terms(entities)]
    if not terms:
        return []
    items = _fetch_reminders_due(datetime.now(), horizon_days=14, max_items=40)
    bucket_label = {"overdue": "vencido", "today": "hoy", "upcoming": "próximo", "undated": "sin fecha"}
    hits: list[dict] = []
    for it in items:
        name = (it.get("name") or "").strip()
        if not any(t in name.lower() for t in terms):
            continue
        hits.append({
            "icon": "✓",
            "text": f"reminder relacionado: «{name}»",
            "snippet": bucket_label.get(it.get("bucket", ""), ""),
            "relative": "",
            "channel": "reminders",
        })
        if len(hits) >= max_hits:
            break
    return hits


def build_enrich_payload(question: str, answer: str, top_score: float) -> dict | None:
    """Compose the cross-source enrichment block for the web chat footer.

    Pipeline: extract entities → fan out to WA/Calendar/Reminders → merge,
    cap to 5 lines, prioritise Calendar > Reminders > WA. Returns
    `{"lines": [...], "entities": {...}}` or None when nothing surfaces.
    Skipped on short answers or low-confidence retrieval.
    """
    if not answer or len(answer.strip()) < 40:
        return None
    if top_score < CONFIDENCE_RERANK_MIN:
        return None
    entities = extract_enrich_entities(question, answer)
    if not (entities["people"] or entities["events"] or entities["topics"]):
        return None
    cal = _enrich_calendar(entities) if _apple_enabled() else []
    rem = _enrich_reminders(entities) if _apple_enabled() else []
    wa = _enrich_wa(entities)
    lines = (cal + rem + wa)[:5]
    if not lines:
        return None
    return {"lines": lines, "entities": entities}


def _collect_scoped_tasks_evidence(col, now: datetime, scope: dict) -> dict:
    """`_pendientes_collect` under the hood, then override `reminders` and
    `calendar_range` with scope-aware fetches. Ensures `whatsapp` always
    populated even if the base collector skipped silently.

    Single-vault version kept for callers that pass a sqlite-vec collection
    directly (rag morning/today still use this). Multi-vault tasks-mode
    uses `_collect_scoped_tasks_evidence_multi` instead.

    Reminders / Calendar / WhatsApp fetchers run in parallel — each is an
    independent IPC round-trip (osascript / icalBuddy / sqlite) so serial
    execution wasted wall-clock for no gain. Silent-fail contract preserved
    per-future.
    """
    from concurrent.futures import ThreadPoolExecutor
    ev = _pendientes_collect(col, now, days=14)

    def _reminders():
        try:
            return _fetch_reminders_due(
                now, horizon_days=int(scope["reminders_horizon"]), max_items=40,
            )
        except Exception:
            return None

    def _calendar():
        try:
            return _fetch_calendar_ahead(int(scope["calendar_ahead"]))
        except Exception:
            return None

    def _whatsapp():
        try:
            return _fetch_whatsapp_unread(hours=24, max_chats=8)
        except Exception:
            return None

    with ThreadPoolExecutor(max_workers=3) as ex:
        f_rem = ex.submit(_reminders)
        f_cal = ex.submit(_calendar)
        f_wa = ex.submit(_whatsapp) if not ev.get("whatsapp") else None
        rem = f_rem.result()
        cal = f_cal.result()
        wa = f_wa.result() if f_wa else None
    if rem is not None:
        ev["reminders"] = rem
    if cal is not None:
        ev["calendar_range"] = cal
    if wa is not None:
        ev["whatsapp"] = wa
    return ev


def _collect_scoped_tasks_evidence_multi(
    vaults: list[tuple[str, Path]], now: datetime, scope: dict,
) -> dict:
    """Multi-vault tasks evidence: system services fetched once (Reminders,
    Calendar, Gmail, Apple Mail, WhatsApp — none of these are vault-scoped),
    vault loops + contradictions aggregated per-vault with `_vault` label.

    The user asked for both personal (`home`) and work (`work`) vaults to
    surface their open loops in the tasks-mode answer. Without this, the
    work vault's pending items were invisible on WhatsApp/web queries.

    All 6 system fetchers run in a ThreadPoolExecutor — each is an
    independent network / IPC call (osascript, icalBuddy, sqlite, Google
    HTTP, Open-Meteo HTTP), and serial execution added ~3-5s to tasks-mode
    latency for no correctness win. Each fetcher already silent-fails; the
    wrapper captures exceptions per-future so one slow/broken service can't
    take down the others.
    """
    from concurrent.futures import ThreadPoolExecutor

    def _safe(fn, *args, **kwargs):
        try:
            return fn(*args, **kwargs)
        except Exception:
            return None

    ev: dict = {}
    # System services — fan out in parallel. Max_workers matches the fetcher
    # count so each gets a thread; overhead is negligible vs the seconds
    # saved. No shared mutable state — each worker returns a plain value.
    with ThreadPoolExecutor(max_workers=6) as ex:
        f_mail = ex.submit(_safe, _fetch_mail_unread)
        f_rem = ex.submit(
            _safe, _fetch_reminders_due, now,
            int(scope["reminders_horizon"]), 40,
        )
        f_cal = ex.submit(
            _safe, _fetch_calendar_ahead, int(scope["calendar_ahead"]),
        )
        f_wa = ex.submit(_safe, _fetch_whatsapp_unread, 24, 8)
        f_weather = ex.submit(_safe, _fetch_weather_rain)
        f_gmail = ex.submit(_safe, _fetch_gmail_evidence, now)

        mail_v = f_mail.result()
        rem_v = f_rem.result()
        cal_v = f_cal.result()
        wa_v = f_wa.result()
        weather_v = f_weather.result()
        gmail_v = f_gmail.result()

    if mail_v is not None:
        ev["mail_unread"] = mail_v
    if rem_v is not None:
        ev["reminders"] = rem_v
    if cal_v is not None:
        ev["calendar_range"] = cal_v
    if wa_v is not None:
        ev["whatsapp"] = wa_v
    if weather_v is not None:
        ev["weather"] = weather_v
    if gmail_v is not None:
        ev["gmail"] = gmail_v

    # Per-vault — loops + contradictions. Stale threshold mirrors
    # `_pendientes_collect` (14 days). Cap per vault at 8 to avoid blowing
    # the LLM context when both vaults are active.
    all_stale: list[dict] = []
    all_activo: list[dict] = []
    all_contrad: list[dict] = []
    stale_days = 14
    for vname, vpath in (vaults or []):
        with contextlib.suppress(Exception):
            loops = _pendientes_extract_loops_fast(vpath, days=14, max_items=40)
            loops.sort(key=lambda x: x.get("age_days", 0), reverse=True)
            for loop in loops:
                loop["_vault"] = vname
            stale = [x for x in loops if x.get("age_days", 0) >= stale_days][:5]
            activo = [x for x in loops if x.get("age_days", 0) < stale_days][:5]
            all_stale.extend(stale)
            all_activo.extend(activo)
        with contextlib.suppress(Exception):
            # Contradictions log is per-vault via CONTRADICTION_LOG_PATH which
            # is global — but we'll still iterate to keep the interface
            # symmetric if per-vault logs appear later.
            contrad = _pendientes_recent_contradictions(
                CONTRADICTION_LOG_PATH, now, days=14,
            )
            for c in contrad:
                c["_vault"] = vname
            all_contrad.extend(contrad)
    all_stale.sort(key=lambda x: x.get("age_days", 0), reverse=True)
    all_activo.sort(key=lambda x: x.get("age_days", 0), reverse=True)
    ev["loops_stale"] = all_stale[:8]
    ev["loops_activo"] = all_activo[:8]
    # Dedup contradictions by subject_path (global log would repeat entries)
    seen = set()
    dedup_contrad = []
    for c in all_contrad:
        key = c.get("subject_path", "")
        if key and key not in seen:
            seen.add(key)
            dedup_contrad.append(c)
    ev["contradictions"] = dedup_contrad[:5]
    return ev


def _format_scoped_tasks_context(
    ev: dict, urgent: list[str], now: datetime, scope: dict,
) -> str:
    """Markdown evidence blob for the LLM, scope label front-and-centre."""
    lines: list[str] = [
        f"# Evidencia de servicios · {now.strftime('%Y-%m-%d %H:%M')}",
        f"**Ventana temporal pedida:** {scope['label']}",
    ]
    if urgent:
        lines.append(f"\n## 🚨 Urgente / Overdue ({len(urgent)})")
        lines.extend(f"- {u}" for u in urgent)
    cal = ev.get("calendar_range") or ev.get("calendar") or []
    if cal:
        lines.append(f"\n## 📅 Calendar ({len(cal)} eventos)")
        for e in cal[:20]:
            when_bits = [b for b in (e.get("date_label"), e.get("time_range")) if b]
            if not when_bits and e.get("start"):
                when_bits = [e["start"]]
            when = " · ".join(when_bits) or "sin hora"
            lines.append(f"- {when} — {e.get('title','')}")
    rem = ev.get("reminders") or []
    if rem:
        lines.append(f"\n## 📌 Apple Reminders ({len(rem)})")
        for bucket in ("overdue", "today", "upcoming", "undated"):
            bucket_items = [x for x in rem if (x.get("bucket") or "") == bucket]
            for r in bucket_items[:10]:
                due = f" (due {r['due']})" if r.get("due") else ""
                lst = f" [{r['list']}]" if r.get("list") else ""
                lines.append(f"- **{bucket}**: {r.get('name','')}{due}{lst}")
    gm = ev.get("gmail") or {}
    awaiting = gm.get("awaiting_reply") or []
    if awaiting:
        lines.append(f"\n## 📧 Gmail awaiting reply ({len(awaiting)})")
        for m in awaiting[:8]:
            lines.append(
                f"- {m.get('days_old',0)}d · {m.get('subject','')} — {m.get('from','')}"
            )
    mail = ev.get("mail_unread") or []
    if mail:
        lines.append(f"\n## 📬 Apple Mail unread 36h ({len(mail)})")
        for m in mail[:5]:
            vip = "VIP · " if m.get("is_vip") else ""
            lines.append(f"- {vip}{m.get('subject','')} — {m.get('sender','')}")
    wa = ev.get("whatsapp") or []
    if wa:
        total = sum(int(w.get("count", 0)) for w in wa)
        lines.append(
            f"\n## 💬 WhatsApp últimas 24h ({len(wa)} chats · {total} msgs)"
        )
        for w in wa[:10]:
            snip = (w.get("last_snippet") or "").strip()[:100]
            snip_part = f' — "{snip}"' if snip else ""
            lines.append(
                f"- {w.get('name','?')} ({w.get('count',0)} msgs){snip_part}"
            )
    stale = ev.get("loops_stale") or []
    activo = ev.get("loops_activo") or []
    if stale or activo:
        vault_names = sorted({
            l.get("_vault", "") for l in (stale + activo) if l.get("_vault")
        })
        vault_tag = f" ({', '.join(vault_names)})" if vault_names else ""
        lines.append(
            f"\n## 📁 Vault loops{vault_tag} "
            f"({len(stale)} stale · {len(activo)} activo)"
        )
        for it in stale[:5]:
            src = Path(it["source_note"]).stem
            vn = it.get("_vault", "")
            vprefix = f"[{vn}] " if vn else ""
            lines.append(
                f"- {vprefix}stale {it.get('age_days',0)}d: "
                f"{it.get('loop_text','')[:100]} [[{src}]]"
            )
        for it in activo[:5]:
            src = Path(it["source_note"]).stem
            vn = it.get("_vault", "")
            vprefix = f"[{vn}] " if vn else ""
            lines.append(
                f"- {vprefix}activo {it.get('age_days',0)}d: "
                f"{it.get('loop_text','')[:100]} [[{src}]]"
            )
    return "\n".join(lines)


def _build_tasks_system_rules(scope: dict) -> str:
    """SYSTEM prompt with concrete time-window embedded."""
    return (
        "Sos un asistente personal que organiza la agenda del usuario a "
        "partir de evidencia EN VIVO de sus servicios.\n\n"
        f"VENTANA TEMPORAL SOLICITADA: {scope['label']}.\n\n"
        "REGLA DE ORO: renderizá TODAS las secciones que el CONTEXTO trae "
        "con al menos 1 item. No te quedes sólo con las primeras 2 — el "
        "usuario necesita ver todos los frentes abiertos.\n\n"
        "Qué incluir (por sección):\n"
        "• 🚨 Urgente / Overdue — SIEMPRE mostrar todos los items listados.\n"
        "• 📅 Calendar — mostrar todos los eventos del CONTEXTO (ya fueron "
        "filtrados por la ventana al obtenerlos).\n"
        "• 📌 Reminders — mostrar items `overdue` y `undated` SIEMPRE "
        "(son tareas actuales, no futuras). De `today` / `upcoming`, "
        "mostrar los que caigan dentro de la ventana.\n"
        "• 📧 Gmail awaiting reply — SIEMPRE mostrar. Son mails a los que "
        "el usuario NO respondió; son tareas pendientes del ahora, no "
        "del futuro.\n"
        "• 📬 Apple Mail unread — SIEMPRE mostrar si el CONTEXTO trae "
        "items. Son mails sin leer en las últimas 36h; el usuario quiere "
        "verlos junto al resto de la bandeja.\n"
        "• 💬 WhatsApp últimas 24h — mostrar como 'contexto de lo que se "
        "está conversando', no como tareas. Breve (3-5 chats top).\n"
        "• 📁 Vault loops — SIEMPRE mostrar activos; stale sólo si hay "
        "espacio (máx 3).\n\n"
        "Formato:\n"
        "- Español, encabezados markdown con emoji, bullets con `-`.\n"
        "- Una línea por item, sin elaborar. Calendar: 'día + hora + "
        "título'. Reminders/loops: nombre + (lista o nota).\n"
        "- Orden de secciones: 🚨 Urgente → 📅 Calendar → 📌 Reminders "
        "→ 📧 Gmail → 📬 Mail → 📁 Loops → 💬 WhatsApp (al final, "
        "como contexto).\n"
        "- Omití secciones que NO vienen en el CONTEXTO o que quedan "
        "vacías tras el filtro.\n\n"
        "No inventes tareas, plazos ni eventos que no estén literalmente "
        "en el CONTEXTO. Si el CONTEXTO no trae NADA útil, respondé "
        "exactamente: 'No tengo nada trackeado para esa ventana.' y "
        "parate ahí."
    )


def _tasks_services_consulted(ev: dict) -> list[str]:
    out: list[str] = []
    if (ev.get("gmail") or {}).get("awaiting_reply"):
        out.append("Gmail")
    if ev.get("mail_unread"):
        out.append("Apple Mail")
    if ev.get("whatsapp"):
        out.append("WhatsApp")
    if ev.get("reminders"):
        out.append("Reminders")
    if ev.get("calendar_range") or ev.get("calendar"):
        out.append("Calendar")
    if ev.get("loops_stale") or ev.get("loops_activo"):
        out.append("Vault loops")
    return out


@cli.command()
@click.option("--host", default="127.0.0.1", help="Bind address")
@click.option("--port", default=7832, type=int, help="Port number")
def serve(host: str, port: int):
    """Persistent HTTP query server — keeps models warm between requests.

    Designed for WhatsApp/bot integrations that need fast response times.
    Eliminates the ~5s cold start of subprocess-per-query by keeping the
    reranker, embedder, and BM25 corpus resident in memory.

    Endpoints:
      GET  /health  — liveness + chunk count
      POST /query   — full retrieve + generate pipeline, returns JSON
    """
    import json as _json
    from http.server import HTTPServer, BaseHTTPRequestHandler

    col = get_db()
    if col.count() == 0:
        console.print("[red]Índice vacío. Ejecuta: rag index[/red]")
        return

    # Eager warmup — block until all models are ready.
    console.print("[dim]Warming up reranker…[/dim]")
    get_reranker()
    console.print("[dim]Warming up embedder…[/dim]")
    embed(["warmup"])
    # In-process bge-m3 SentenceTransformer — launchd sets RAG_LOCAL_EMBED=1
    # on the serve plist so query embeds go through the MPS fast path. Without
    # this warmup the FIRST WhatsApp turn after a daemon restart paid ~4s of
    # cold load on the critical path (confirmed 2026-04-21 in
    # rag_queries.extra_json: embed_ms 3455/4137/4898 on the first few turns,
    # dropping to 262/402 once resident). Self-gates on _local_embed_enabled().
    if _warmup_local_embedder():
        console.print("[dim]Warming up local bge-m3 embedder…[/dim]")
    console.print("[dim]Loading BM25 corpus…[/dim]")
    _load_corpus(col)
    chat_model = resolve_chat_model()
    # Pre-cargar el chat model en VRAM con un call mínimo. Sin esto la primera
    # query real paga el cold-start del LLM (command-r ~20-30s extra).
    console.print("[dim]Warming up chat model…[/dim]")
    try:
        for _ in ollama.chat(
            model=chat_model,
            messages=[{"role": "user", "content": "hi"}],
            options={**CHAT_OPTIONS, "num_predict": 1},
            stream=True,
            keep_alive=chat_keep_alive(chat_model),
        ):
            pass
    except Exception:
        pass  # Best-effort; si falla la primera query paga el costo.
    console.print("[green]All models warm.[/green]")

    # Arrancar el memory-pressure watchdog — evita beachballs si `rag do` +
    # web server + otras apps saturan los 36 GB mientras serve está corriendo.
    # Ver comentario extenso arriba de `_system_memory_used_pct()`.
    start_memory_pressure_watchdog()

    # WAL checkpointer — libera páginas WAL cada 30s en background. Sin
    # esto bajo carga sostenida el WAL crece a >20 MB y los writers
    # ragvec/telemetry chocan contra el busy_timeout (→ 402
    # semantic_cache_store_failed / 316 queries_sql_write_failed medidos
    # 2026-04-24). Ver comentario arriba de `_wal_checkpointer_loop`.
    start_wal_checkpointer()

    # ── Response cache — queries repetidas instantáneas ─────────────────────
    # WA users retype consultas idénticas ("llueve hoy?", "test") con alta
    # frecuencia; cachear evita re-correr embed + retrieve + rerank + LLM
    # (~20-30s) cuando nada cambió. Key: (question, session_id). TTL 5min
    # — balance entre freshness (notas nuevas indexadas) y hit rate. Cap 64
    # entries (LRU) — budget de memoria ~200KB.
    _serve_cache: "OrderedDict[str, tuple[float, dict]]" = OrderedDict()
    _SERVE_CACHE_MAX = 64
    _SERVE_CACHE_TTL = 300.0  # seconds

    def _cache_get(key: str) -> dict | None:
        hit = _serve_cache.get(key)
        if not hit:
            return None
        ts, payload = hit
        if time.time() - ts > _SERVE_CACHE_TTL:
            _serve_cache.pop(key, None)
            return None
        # LRU: marcar como recién usado para que no sea evictado en próximo put.
        _serve_cache.move_to_end(key)
        return payload

    def _cache_put(key: str, payload: dict) -> None:
        if len(_serve_cache) >= _SERVE_CACHE_MAX:
            # LRU: pop oldest (least recently used).
            try:
                _serve_cache.popitem(last=False)
            except KeyError:
                pass
        _serve_cache[key] = (time.time(), payload)

    def _handle_query(body: dict) -> dict:
        question = body.get("question", "").strip()
        if not question:
            return {"error": "empty question"}

        k = max(1, min(body.get("k", RERANK_TOP), 15))
        qfolder = body.get("folder")
        qtag = body.get("tag")
        sid = body.get("session_id")
        force = body.get("force", False)
        multi_q = body.get("multi_query", True)
        loose = body.get("loose", False)
        # num_predict override — default 256 para chat surfaces (WA/bot).
        # Respuestas median 38 chars, p95 236 tok; 256 deja buffer ajustado
        # y cap gen time a ~25s a 10 tok/s peor caso. CLI usa CHAT_OPTIONS=384.
        predict_cap = int(body.get("num_predict", 256))
        # retrieve_only (2026-04-28): skip LLM call y devolver solo sources +
        # excerpts. Diseñado para drafts del WhatsApp listener — necesita
        # contexto del corpus (notas/calendar/reminders/gmail/whatsapp) sin
        # pagar los 10-30s de un LLM call que va a descartar igual. El
        # listener arma su propio prompt para el draft con esos excerpts.
        # Bypassea metachat / weather / tasks / finance short-circuits — esos
        # NO usan retrieve y devolverían sources=[] inútil. Evitamos también
        # el cache (sources puede cambiar entre runs por reindexing) y la
        # session persistence (no es un turn de conversación).
        retrieve_only = bool(body.get("retrieve_only", False))

        # retrieve_only skipea expand_queries() — el caller (listener WA)
        # descarta el output LLM-side y solo usa sources, así que las 3
        # paráfrasis de qwen2.5:3b (1-3s) son overhead puro. Mismo patrón
        # que `RAG_WA_SKIP_PARAPHRASE` cuando source="whatsapp". Medido
        # 7d: serve.retrieve_only avg t_retrieve=25.3s; expand recorta
        # 1-3s de eso sin tocar recall (BM25 + semantic + rerank ya
        # cubren la query original).
        if retrieve_only:
            multi_q = False

        # Emit "received" event before processing — lets the dashboard surface
        # in-flight queries even when retrieval/generation hangs (the prior
        # behavior was to log only on success, so failures silently disappeared
        # from analytics).
        try:
            log_query_event({
                "cmd": "serve.received", "q": question[:200],
                "session": sid, "folder": qfolder, "tag": qtag,
            })
        except Exception:
            pass
        # Deep retrieval off-default para bot WA: el segundo pase duplica
        # retrieve + agrega 1 judge call (5-15s). El path rápido responde
        # suficientemente bien en la mayoría de queries reales.
        deep = body.get("deep", False)

        # Cache check — questiones idénticas en la misma sesión/vault sirven
        # de cache. Skip cuando `force` (usuario pidió re-run) o filtros
        # explícitos (cambian la respuesta sin cambiar la pregunta).
        cache_key = f"{sid or ''}|{qfolder or ''}|{qtag or ''}|{loose}|{question}"

        # WhatsApp cross-reference — when the query mentions a person from
        # 99-Mentions/, surface the last 3 WA messages + optional propose
        # card. Computed fresh on every call (bypasses the 5min cache)
        # because bridge messages arrive continuously; the cache holds the
        # expensive LLM answer, not the cheap SQL lookup. Failure returns
        # None silently — absent cross_ref is valid state.
        try:
            wa_cross_ref = _build_wa_cross_ref(question)
        except Exception:
            wa_cross_ref = None

        # User nickname → lets the listener personalize outgoing messages
        # ("Fer, te agendo?"). Resolved from 99-Mentions/Yo.md aliases or
        # the "nombre completo" body line. None if unknown → listener
        # falls back to name-less phrasing. Cached by mtime so edits
        # propagate without a reload.
        try:
            user_nickname = _load_user_nickname()
        except Exception:
            user_nickname = None

        if not force and not qfolder and not qtag:
            cached = _cache_get(cache_key)
            if cached is not None:
                cached = {**cached, "cached": True}
                if wa_cross_ref is not None:
                    cached["wa_cross_ref"] = wa_cross_ref
                if user_nickname is not None:
                    cached["user_nickname"] = user_nickname
                return cached

        # Session
        sess = ensure_session(sid, mode="serve") if sid else None
        history = session_history(sess) if sess else None

        # Weather short-circuit (2026-04-22 WA latency fix) — 3 prior
        # "llueve hoy?" queries cost 50-72s each on this endpoint. No
        # point running retrieve + command-r when we have a dedicated
        # weather pipeline (~2-3s total). Conservative keyword matcher
        # with exclude list for "clima laboral" / "tengo tiempo" FPs.
        #
        # `retrieve_only` bypassea TODOS los short-circuits — el caller
        # (listener para drafts) quiere sources del corpus, no answers
        # canned. Si la query es weather/metachat/tasks/finance Y
        # retrieve_only=true, igual corre el retrieve normal: las
        # sources que devuelva pueden ser irrelevantes (vault no tiene
        # info de "hola" o "llueve hoy?") pero el listener decide
        # qué hacer con eso (filtra por score abajo).
        if not retrieve_only and _is_weather_query(question):
            t_w0 = time.perf_counter()
            try:
                forecast_block = _fetch_weather_forecast()
            except Exception as exc:
                forecast_block = None
                _silent_log("serve_weather_fetch", exc)
            if forecast_block is None:
                # Wttr.in + Open-Meteo both down — fall through to RAG
                # (better to waste 60s than leave the user without an
                # answer). Log the fall-through for analytics.
                try:
                    log_query_event({
                        "cmd": "serve.weather_fallback", "q": question,
                        "session": sid,
                    })
                except Exception:
                    pass
            else:
                # qwen2.5:3b comment. Light prompt so keep_alive of the
                # helper model is consistent with chat (~1-2s typical).
                try:
                    answer = _weather_comment(question, forecast_block)
                except Exception as exc:
                    _silent_log("serve_weather_comment", exc)
                    answer = forecast_block  # graceful fallback to raw
                t_w = time.perf_counter() - t_w0
                query_turn_id = new_turn_id()
                if sess:
                    append_turn(sess, {
                        "q": question, "a": answer,
                        "paths": [], "top_score": 0.0,
                        "turn_id": query_turn_id, "mode": "weather",
                    })
                    save_session(sess)
                try:
                    log_query_event({
                        "cmd": "serve.weather",
                        "turn_id": query_turn_id,
                        "session": sid, "q": question[:200],
                        "t_retrieve": 0.0,
                        "t_gen": round(t_w, 3),
                        "intent": "weather",
                    })
                except Exception:
                    pass
                weather_payload = {
                    "answer": answer,
                    "sources": [],
                    "mode": "weather",
                    "t_retrieve": 0.0,
                    "t_gen": round(t_w, 3),
                    "turn_id": query_turn_id,
                }
                if not force:
                    _cache_put(cache_key, weather_payload)
                return weather_payload

        # Finance / tarjetas short-circuit (2026-04-26) — queries financieras
        # bypassean retrieve. Helper compartido con `/chat`. Devuelve None
        # cuando la query NO es finance/cards o el helper falla, en cuyo
        # caso seguimos al pipeline normal.
        # `retrieve_only` skipea este short-circuit — ver explicación arriba.
        _fc_result = None if retrieve_only else _finance_short_circuit_answer(question)
        if _fc_result is not None:
            answer, n_cards, has_moze, t_fc = _fc_result
            query_turn_id = new_turn_id()
            if sess:
                append_turn(sess, {
                    "q": question, "a": answer,
                    "paths": [], "top_score": 0.0,
                    "turn_id": query_turn_id, "mode": "finance",
                })
                save_session(sess)
            try:
                log_query_event({
                    "cmd": "serve.finance",
                    "turn_id": query_turn_id,
                    "session": sid, "q": question[:200],
                    "t_retrieve": 0.0,
                    "t_gen": round(t_fc, 3),
                    "intent": "finance",
                    "n_cards": n_cards,
                    "has_moze": has_moze,
                })
            except Exception:
                pass
            finance_payload = {
                "answer": answer,
                "sources": [],
                "mode": "finance",
                "t_retrieve": 0.0,
                "t_gen": round(t_fc, 3),
                "turn_id": query_turn_id,
            }
            if not force:
                _cache_put(cache_key, finance_payload)
            return finance_payload

        # Metachat short-circuit — greetings / thanks / "qué podés hacer".
        # Matches the regex-based detector from rag.py:26314 (also used by
        # /api/chat). Bypass retrieve + LLM entirely: canned reply based
        # on the match kind. Pre-fix, "hola" ran the full pipeline and
        # typically produced a generic "según tus notas, tenés…"
        # hallucination.
        #
        # Inline reply keeps serve self-contained (web/server.py has its
        # own _pick_metachat_reply with richer time-aware variants; WA
        # stays with a compact single-line canned reply — matches the
        # conversational register).
        if not retrieve_only and _detect_metachat_intent(question):
            t_m0 = time.perf_counter()
            _q_lower = question.strip().lower()
            if any(w in _q_lower for w in ("gracias", "thanks", "thank")):
                reply = "De nada!"
            elif any(w in _q_lower for w in ("chau", "bye", "nos vemos")):
                reply = "Chau!"
            elif any(w in _q_lower for w in ("qué podés", "que podes",
                                              "cómo us", "como us",
                                              "qué sabés", "que sabes")):
                reply = ("Consulto tus notas de Obsidian. Preguntame algo "
                         "puntual (notas, gente, temas) o pedime recordatorios "
                         "y eventos.")
            else:
                reply = "¡Hola! Preguntame algo del vault y te busco."
            t_m = time.perf_counter() - t_m0
            query_turn_id = new_turn_id()
            if sess:
                append_turn(sess, {
                    "q": question, "a": reply,
                    "paths": [], "top_score": 0.0,
                    "turn_id": query_turn_id, "mode": "metachat",
                })
                save_session(sess)
            try:
                log_query_event({
                    "cmd": "serve.metachat",
                    "turn_id": query_turn_id,
                    "session": sid, "q": question[:200],
                    "t_retrieve": 0.0, "t_gen": round(t_m, 3),
                    "intent": "metachat",
                })
            except Exception:
                pass
            return {
                "answer": reply, "sources": [], "mode": "metachat",
                "t_retrieve": 0.0, "t_gen": round(t_m, 3),
                "turn_id": query_turn_id,
            }

        # Tasks / agenda intent short-circuit — vault RAG hallucinates on
        # "what do I have this week" queries (picks up recent WhatsApp
        # markdown and answers with a chat fragment). Bypass retrieve and
        # pull from the live services layer scoped to the query's window.
        if not retrieve_only and _is_tasks_query(question):
            t_tasks0 = time.perf_counter()
            scope = _detect_time_scope(question)
            # Tasks-mode always consults ALL registered vaults — user keeps
            # loops across both `home` (personal) and `work`, and wants both
            # surfaced. System services (Reminders/Gmail/Mail/Calendar/WA)
            # are fetched once; per-vault loops are labelled with their vault.
            try:
                all_vaults = resolve_vault_paths(["all"])
            except Exception:
                all_vaults = []
            try:
                if all_vaults:
                    ev = _collect_scoped_tasks_evidence_multi(
                        all_vaults, datetime.now(), scope,
                    )
                else:
                    ev = _collect_scoped_tasks_evidence(col, datetime.now(), scope)
            except Exception as exc:
                return {"error": f"servicios fallaron: {exc}"}
            urgent = _pendientes_urgent(ev, datetime.now())
            services = _tasks_services_consulted(ev)
            context = _format_scoped_tasks_context(
                ev, urgent, datetime.now(), scope,
            )
            system_rules = _build_tasks_system_rules(scope)
            t_retrieve_tasks = time.perf_counter() - t_tasks0

            if history:
                messages = (
                    [{"role": "system",
                      "content": f"{system_rules}\nCONTEXTO:\n{context}"}]
                    + history
                    + [{"role": "user", "content": question}]
                )
            else:
                messages = [{"role": "user", "content": (
                    f"{system_rules}\nCONTEXTO:\n{context}\n\n"
                    f"PREGUNTA: {question}\n\nRESPUESTA:"
                )}]

            # Tasks mode needs more tokens than the default 256 WA cap —
            # a full agenda/pendientes layout with 5-6 sections + bullets
            # easily runs 400-600 tokens. Truncation mid-section is worse
            # than a slightly longer response.
            tasks_predict_cap = max(predict_cap, 700)
            t_gen0 = time.perf_counter()

            # ── Streaming + TTFT tracking (2026-04-22) ─────────────────
            # Pre-fix el call era `chat(...)` síncrono no-streaming: el
            # main thread bloqueaba hasta el last token (15-70s medidos
            # en serve.tasks). Post-fix iteramos chunks y capturamos
            # TTFT (time-to-first-token) en ms.
            #
            # Por qué: streaming aquí NO baja wall-time percibido por
            # WhatsApp (el listener igual espera el JSON completo antes
            # de enviar el mensaje — WA no tiene streaming nativo). Pero
            # habilita dos cosas:
            #
            #   1. TTFT como métrica distinta de t_gen: diagnóstica si
            #      los 40-70s outliers (casos con Gmail + Apple Mail)
            #      son prefill largo (TTFT alto) o decode slow
            #      (TTFT bajo, t_gen alto). Rag_queries.extra_json.ttft_ms
            #      permite refinar futuras optimizaciones con data
            #      concreta en vez de hunches.
            #   2. Early-stop futuro: iterar chunks abre la puerta a
            #      detectar cierre natural (ej. triple newline + final
            #      separator) y abortar la generación antes del cap.
            #      No lo implementamos acá para no cambiar comportamiento
            #      (hoy = mismo payload al cliente), pero el fundamento
            #      queda.
            #
            # Clientes non-WA (CLI directo, scripts) podrían en el
            # futuro consumir el endpoint via streaming (chunked transfer)
            # y ver mejora real. Para WA, `answer` final sigue siendo
            # la concatenación full — idempotente con el pre-fix.
            parts: list[str] = []
            ttft_ms: int | None = None
            try:
                for chunk in _chat_capped_client().chat(
                    model=resolve_chat_model(),
                    messages=messages,
                    options={**CHAT_OPTIONS, "num_predict": tasks_predict_cap},
                    stream=True,
                    keep_alive=chat_keep_alive(),
                ):
                    content = chunk.message.content
                    if content:
                        if ttft_ms is None:
                            ttft_ms = int((time.perf_counter() - t_gen0) * 1000)
                        parts.append(content)
            except Exception as exc:
                return {"error": f"LLM falló: {exc}"}
            answer = "".join(parts).strip()
            t_gen = time.perf_counter() - t_gen0

            query_turn_id = new_turn_id()
            if sess:
                append_turn(sess, {
                    "q": question, "a": answer,
                    "paths": [], "top_score": 0.0,
                    "turn_id": query_turn_id, "mode": "tasks",
                })
                save_session(sess)
            try:
                log_query_event({
                    "cmd": "serve.tasks",
                    "turn_id": query_turn_id,
                    "session": sid, "q": question[:200],
                    "scope": scope["key"], "scope_label": scope["label"],
                    "services": services,
                    "n_urgent": len(urgent),
                    "n_reminders": len(ev.get("reminders") or []),
                    "n_calendar": len(
                        ev.get("calendar_range") or ev.get("calendar") or []
                    ),
                    "n_whatsapp": len(ev.get("whatsapp") or []),
                    "t_retrieve": round(t_retrieve_tasks, 3),
                    "t_gen": round(t_gen, 3),
                    "answer_len": len(answer),
                    # TTFT (time-to-first-token) en ms. Separado de t_gen
                    # para distinguir prefill del decode: ttft_ms alto +
                    # t_gen proporcional = prefill lento (contexto largo,
                    # probablemente por Gmail/Apple Mail). ttft_ms bajo +
                    # t_gen alto = decode lento (MPS contention, model
                    # size). Los outliers 40-70s de serve.tasks se
                    # diagnostican con este campo.
                    "ttft_ms": ttft_ms,
                    "timing": _round_timing_ms({
                        "total_ms": (t_retrieve_tasks + t_gen) * 1000,
                        "retrieve_ms": t_retrieve_tasks * 1000,
                        "gen_ms": t_gen * 1000,
                        "ttft_ms": ttft_ms,
                    }),
                })
            except Exception:
                pass

            tasks_payload = {
                "answer": answer or "(respuesta vacía)",
                "sources": [],
                "mode": "tasks",
                "scope": scope["label"],
                "services": services,
                "urgent_count": len(urgent),
                "t_retrieve": round(t_retrieve_tasks, 3),
                "t_gen": round(t_gen, 3),
                # Exponé TTFT al cliente por si quiere mostrar "respondiendo..."
                # con timing real. WA listener lo ignora; CLI/scripts custom
                # pueden loggearlo o pintarlo.
                "ttft_ms": ttft_ms,
                "turn_id": query_turn_id,
            }
            # Cachear igual que queries normales — respuestas idénticas en <5min
            # (ej. usuario re-pregunta "qué tengo hoy") sirven del cache.
            if not force:
                _cache_put(cache_key, tasks_payload)
            return tasks_payload

        # ── Semantic cache (SQL) — segundo layer post LRU miss (2026-04-23) ──
        # Espeja el wiring de /api/chat (web/server.py). El LRU arriba
        # (línea ~36410) captura repetidos exactos dentro del proceso;
        # el SQL cache matchea paraphrases + persiste cross-restart.
        # Gates: no history (follow-ups cambian con el contexto), no force
        # (usuario pidió re-run), no filters (cambian la respuesta), y el
        # question no es de weather/tasks (esos ya short-circuitean con
        # su propio path time-sensitive arriba, no llegan acá).
        _serve_sem_emb = None
        _serve_sem_hash = ""
        _serve_sem_probe: dict | None = None
        _serve_sem_eligible = (
            not history
            and not force
            and not qfolder
            and not qtag
        )
        if _serve_sem_eligible:
            try:
                if _semantic_cache_enabled():
                    _serve_sem_emb = embed([question])[0]
                    _serve_sem_hash = _corpus_hash_cached(col)
                    _serve_sem_hit, _serve_sem_probe = semantic_cache_lookup(
                        _serve_sem_emb, _serve_sem_hash, return_probe=True,
                    )
                    if _serve_sem_hit is not None:
                        # Reconstruir el payload en el shape que el listener
                        # espera (answer/sources/confidence/t_retrieve/t_gen).
                        _sem_paths = _serve_sem_hit.get("paths") or []
                        _sem_scores = _serve_sem_hit.get("scores") or []
                        _sem_top = _serve_sem_hit.get("top_score") or 0.0
                        _sem_text = _serve_sem_hit["response"]
                        from pathlib import Path as _SvP
                        _sem_sources = [
                            {
                                "note": _SvP(p).stem,
                                "path": p,
                                "score": round(float(s), 2),
                            }
                            for p, s in zip(_sem_paths, _sem_scores)
                        ]
                        _sem_payload = {
                            "answer": _sem_text,
                            "sources": _sem_sources,
                            "confidence": round(float(_sem_top), 2),
                            "t_retrieve": 0.0,
                            "t_gen": 0.0,
                            "cached": True,
                            "cache_layer": "semantic",
                        }
                        if wa_cross_ref is not None:
                            _sem_payload["wa_cross_ref"] = wa_cross_ref
                        if user_nickname is not None:
                            _sem_payload["user_nickname"] = user_nickname
                        # Hidratar el LRU así el próximo exact-repeat
                        # pega O(1) sin re-embed + re-lookup.
                        try:
                            _cache_put(cache_key, {
                                k: v for k, v in _sem_payload.items()
                                if k not in ("wa_cross_ref", "user_nickname")
                            })
                        except Exception:
                            pass
                        # Session append — la conversación continúa normal.
                        _sem_turn_id = new_turn_id()
                        if sess:
                            try:
                                append_turn(sess, {
                                    "q": question,
                                    "a": _sem_text,
                                    "paths": _sem_paths,
                                    "top_score": round(float(_sem_top), 3),
                                    "turn_id": _sem_turn_id,
                                    "cached": True,
                                    "cache_layer": "semantic",
                                })
                                save_session(sess)
                            except Exception:
                                pass
                        try:
                            log_query_event({
                                "cmd": "serve.cached_semantic",
                                "q": question[:200],
                                "session": sid,
                                "turn_id": _sem_turn_id,
                                "answered": True,
                                "cache_hit": True,
                                "cache_probe": _serve_sem_probe,
                                "cache_layer": "semantic",
                                "cache_cosine": round(
                                    float(_serve_sem_hit["cosine"]), 4,
                                ),
                                "cache_age_seconds": int(
                                    _serve_sem_hit["age_seconds"]
                                ),
                                "paths": _sem_paths,
                                "top_score": round(float(_sem_top), 2),
                                "t_retrieve": 0.0,
                                "t_gen": 0.0,
                            })
                        except Exception:
                            pass
                        return _sem_payload
            except Exception as _serve_sem_exc:
                _silent_log("serve_semantic_cache_lookup", _serve_sem_exc)
                _serve_sem_emb = None
                _serve_sem_hash = ""

        # Reformulate + expand (merged when history available)
        effective = question
        pre_variants: list[str] | None = None
        if history and multi_q:
            try:
                s_sum = session_summary(sess) if sess else None
                effective, pre_variants = reformulate_and_expand(
                    question, history, summary=s_sum,
                )
            except Exception:
                effective = question
        elif history:
            try:
                effective = reformulate_query(question, history)
            except Exception:
                effective = question

        # turn_id stamped on every serve turn so `rag feedback` / `rag fix`
        # pueden atarlo después (CLI ya lo hacía — serve estaba roto, el
        # feedback devolvía "el último turno no tiene turn_id (sesión
        # pre-upgrade)" aunque la sesión fuera fresh).
        query_turn_id = new_turn_id()
        t0 = time.perf_counter()
        # 2026-04-29: pool reducido cuando el caller solo quiere sources +
        # excerpts (typical: WA listener pidiendo vault context). Ver
        # comentario en RERANK_POOL_RETRIEVE_ONLY arriba para el racional
        # y la medición. El path normal (LLM answer) sigue con default
        # RERANK_POOL_MAX=25.
        _retrieve_pool = RERANK_POOL_RETRIEVE_ONLY if retrieve_only else None
        result = retrieve(
            col, effective, k, qfolder, tag=qtag, precise=False,
            multi_query=multi_q, auto_filter=True, variants=pre_variants,
            rerank_pool=_retrieve_pool,
        )
        if (deep and result["docs"]
                and result["confidence"] < CONFIDENCE_DEEP_THRESHOLD):
            result = deep_retrieve(
                col, effective, k, qfolder, tag=qtag, precise=False,
                multi_query=multi_q, auto_filter=True, variants=pre_variants,
                rerank_pool=_retrieve_pool,
            )
        t_retrieve = time.perf_counter() - t0

        sources = [
            {"note": m.get("note", ""), "path": m.get("file", ""),
             "score": round(float(s), 2)}
            for m, s in zip(result["metas"], result["scores"])
        ]

        if not result["docs"]:
            return {"answer": "", "sources": [], "t_retrieve": round(t_retrieve, 3)}

        # retrieve_only early return (2026-04-28): devolver sources +
        # excerpts sin tocar confidence gate ni LLM. El caller (listener
        # de drafts) ya filtra por `score` su lado — el gate de server
        # acá sería ruido. Los excerpts van truncados a 500 chars (c/u) —
        # el draft prompt no necesita el chunk completo, solo la evidencia.
        if retrieve_only:
            sources_with_excerpts = [
                {
                    "note": m.get("note", ""),
                    "path": m.get("file", ""),
                    "score": round(float(s), 2),
                    "excerpt": (d or "")[:500],
                    "source": m.get("source", ""),
                }
                for m, s, d in zip(
                    result["metas"], result["scores"], result["docs"],
                )
            ]
            try:
                log_query_event({
                    "cmd": "serve.retrieve_only",
                    "q": question[:200], "session": sid,
                    "n_sources": len(sources_with_excerpts),
                    "t_retrieve": round(t_retrieve, 3),
                    "top_score": round(float(result.get("confidence", 0.0)), 3),
                    "extra_json": {"expand_skipped": "retrieve_only"},
                })
            except Exception:
                pass
            return {
                "sources": sources_with_excerpts,
                "confidence": round(float(result.get("confidence", 0.0)), 2),
                "t_retrieve": round(t_retrieve, 3),
                "retrieve_only": True,
            }

        # Confidence gate — per-source threshold (scaffolding today: all
        # sources equal the baseline until production data calibrates them).
        _top_src = (result.get("metas") or [{}])[0].get("source")
        _gate = confidence_threshold_for_source(_top_src)
        if result["confidence"] < _gate and not force:
            if sess:
                append_turn(sess, {"q": question, "a": None, "gated": True,
                                   "paths": [m.get("file", "") for m in result["metas"]],
                                   "top_score": round(float(result["confidence"]), 3),
                                   "turn_id": query_turn_id})
                save_session(sess)
            gated_payload = {
                "answer": "No tengo esa información en tus notas.",
                "gated": True, "sources": sources,
                "confidence": round(float(result["confidence"]), 2),
                "t_retrieve": round(t_retrieve, 3),
            }
            if not qfolder and not qtag:
                _cache_put(cache_key, gated_payload)
            # WA cross-ref goes on top of the gated payload too — even when
            # the vault has nothing to say about an entity, their recent
            # WhatsApp activity is often the actual answer the user wanted.
            if wa_cross_ref is not None:
                gated_payload["wa_cross_ref"] = wa_cross_ref
            if user_nickname is not None:
                gated_payload["user_nickname"] = user_nickname
            return gated_payload

        # Dynamic top-k: high-confidence hits ya traen la respuesta en los 3
        # chunks más relevantes — mandar los 5 solo infla prefill sin cambiar
        # la answer. Borderline (≤0.5) sí se beneficia del pool completo
        # porque ninguno es obviamente el "el" chunk.
        send_k = 3 if result["confidence"] > 0.5 else len(result["docs"])
        ctx_docs = result["docs"][:send_k]
        ctx_metas = result["metas"][:send_k]

        # Truncar parent chunks 1200→600 chars. El reranker ya decidió que
        # este chunk es relevante; el párrafo completo rara vez aporta sobre
        # los primeros 600 chars, y el prefill escala lineal con bytes.
        # Cortamos en boundary de oración/whitespace para no mutilar texto.
        def _truncate_chunk(text: str, cap: int = 600) -> str:
            if len(text) <= cap:
                return text
            head = text[:cap]
            for boundary in ('. ', '.\n', '!\n', '?\n', '\n\n'):
                pos = head.rfind(boundary)
                if pos > cap * 0.6:
                    return head[:pos + 1] + " […]"
            pos = head.rfind(' ')
            return (head[:pos] if pos > cap * 0.6 else head) + " […]"

        # Generate. Truncate THEN format — _format_chunk_for_llm wraps the
        # body in <<<CHUNK>>> fences + redacts OTPs/secrets for prompt-injection
        # defence. Serve truncates aggressively (600 chars) for first-token
        # latency on WhatsApp chat.
        context = "\n\n---\n\n".join(
            _format_chunk_for_llm(_truncate_chunk(d), m, role="nota")
            for d, m in zip(ctx_docs, ctx_metas)
        )
        # Chat-compact rules default para serve — WA es voice/chat, necesita
        # respuestas cortas y rápidas. `loose` conserva SYSTEM_RULES (permite
        # <<ext>> para prosa externa marcada). STRICT ya no se usa en serve.
        rules = SYSTEM_RULES if loose else SYSTEM_RULES_CHAT
        ub = user_prompt_block()
        rules_full = f"{ub}{rules}" if ub else rules
        if history:
            messages = (
                [{"role": "system", "content": f"{rules_full}\nCONTEXTO:\n{context}"}]
                + history
                + [{"role": "user", "content": question}]
            )
        else:
            messages = [{"role": "user",
                         "content": f"{rules_full}\nCONTEXTO:\n{context}\n\nPREGUNTA: {question}\n\nRESPUESTA:"}]

        # Adaptive fast-path consumption (2026-04-22 WA latency fix).
        # `retrieve()` already sets result["fast_path"] when the
        # baseline gate (semantic intent + score>0.6) or the
        # WA-specific gate (score>0.3 + majority-WA top-3) fires
        # — per the _fast_path block in retrieve() at rag.py:~15339.
        # Previously the serve endpoint ignored the marker and always
        # used resolve_chat_model() + num_ctx=4096. Measured in
        # rag_queries (CLI, 7d): fast_path=1 avg t_gen=3.1s vs
        # fast_path=0 avg 8.5s — 2.75× speedup pure compute win
        # by switching to `_LOOKUP_MODEL` (qwen2.5:3b) + smaller
        # num_ctx. Same pattern as `rag chat` (rag.py:~20310) and
        # `rag query` (rag.py:~18963).
        _serve_fast_path = bool(result.get("fast_path", False))
        _serve_gen_model = (
            _LOOKUP_MODEL if _serve_fast_path else resolve_chat_model()
        )
        _serve_gen_options = (
            {**CHAT_OPTIONS, "num_ctx": _LOOKUP_NUM_CTX,
             "num_predict": predict_cap}
            if _serve_fast_path
            else {**CHAT_OPTIONS, "num_predict": predict_cap}
        )

        t_gen0 = time.perf_counter()
        parts: list[str] = []
        for chunk in ollama.chat(
            model=_serve_gen_model, messages=messages,
            options=_serve_gen_options,
            stream=True, keep_alive=chat_keep_alive(_serve_gen_model),
        ):
            parts.append(chunk.message.content)
        t_gen = time.perf_counter() - t_gen0
        # Aplicar `replace_iberian_leaks` ANTES de convert_obsidian_links —
        # el endpoint `/query` es el path principal del WhatsApp listener +
        # web UI. Los otros handlers (chat, brief, repair, crit, summarise)
        # ya lo aplican (líneas 33316, 37836, 42154, 58970, 59030); este
        # se quedó afuera y dejaba pasar leaks pt al user. Reportado el
        # 2026-04-30 con repro real: query "qué notas tengo sobre ideas
        # para landing pages?" devolvía "...usar testeomiento de um cliente
        # real acima do fold, não mais de 2 linhas". Bug intermitente
        # (depende del sampling), pero el filter es la última barrera —
        # debe correr siempre, igual que los otros handlers.
        from rag.iberian_leak_filter import replace_iberian_leaks
        answer = convert_obsidian_links(replace_iberian_leaks("".join(parts)))

        # Session persist
        if sess:
            append_turn(sess, {
                "q": question,
                "q_reformulated": effective if effective != question else None,
                "a": answer[:500],
                "paths": [m.get("file", "") for m in result["metas"]],
                "top_score": round(float(result["confidence"]), 3),
                "turn_id": query_turn_id,
            })
            save_session(sess)

        log_query_event({
            "cmd": "serve", "q": question,
            "filters": result.get("filters_applied"),
            "fast_path": _serve_fast_path,
            "gen_model": _serve_gen_model,
            "variants": result.get("query_variants"),
            "paths": [m.get("file", "") for m in result["metas"]],
            "scores": [round(float(s), 2) for s in result["scores"]],
            "top_score": round(float(result["confidence"]), 2),
            "t_retrieve": round(t_retrieve, 2), "t_gen": round(t_gen, 2),
            "timing": _round_timing_ms(result.get("timing")),
            "answered": True,
            # Deep-retrieve telemetry — `None` salvo si el caller corrió
            # deep. Ver web/server.py log_query_event "cmd=web" para el
            # rationale extendido. Audit 2026-04-25.
            "deep_retrieve_iterations": result.get("deep_retrieve_iterations"),
            "deep_retrieve_exit_reason": result.get("deep_retrieve_exit_reason"),
        })

        payload = {
            "answer": answer, "sources": sources,
            "confidence": round(float(result["confidence"]), 2),
            "t_retrieve": round(t_retrieve, 3), "t_gen": round(t_gen, 3),
        }
        # Cache only fresh successful answers (no force, no filters).
        # Note: cache the payload WITHOUT wa_cross_ref so the next hit
        # gets a fresh lookup — added after _cache_put below.
        if not force and not qfolder and not qtag:
            _cache_put(cache_key, payload)
            # Semantic cache store (SQL, persistent). Piggyback sobre el
            # embed + corpus_hash ya computados en el lookup arriba
            # (~línea 36720). background=True — serve es long-running
            # daemon; el atexit drop del CLI no aplica. Mismo gate que
            # semantic_cache_store aplica internamente (refusal detector,
            # low top_score, empty response).
            if _serve_sem_emb is not None and _serve_sem_hash:
                try:
                    _serve_sem_cache_paths = list(dict.fromkeys(
                        m.get("file", "")
                        for m in (result.get("metas") or [])
                        if m.get("file")
                    ))
                    semantic_cache_store(
                        _serve_sem_emb,
                        question=question,
                        response=answer,
                        paths=_serve_sem_cache_paths,
                        scores=[
                            round(float(s), 2)
                            for s in (result.get("scores") or [])[:len(_serve_sem_cache_paths)]
                        ],
                        top_score=round(float(result["confidence"]), 2),
                        intent=None,
                        corpus_hash=_serve_sem_hash,
                        background=True,
                    )
                except Exception as _serve_sem_put_exc:
                    _silent_log(
                        "serve_semantic_cache_store", _serve_sem_put_exc,
                    )
        if wa_cross_ref is not None:
            payload["wa_cross_ref"] = wa_cross_ref
        if user_nickname is not None:
            payload["user_nickname"] = user_nickname
        return payload

    # ── /chat — LLM directo, sin retrieval ──────────────────────────────────
    # Para mensajes conversacionales ("hola", "cómo estás") que NO quieren
    # tocar el vault. Reusa el command-r warm del serve, sin pagar retrieve
    # ni rerank (~3-5s típico para respuestas cortas vs 15-30s del /query).
    # Mantiene continuidad por session_id. El bot WA rutea bare text acá y
    # /search|/rag al /query. System prompt en `_SERVE_CHAT_SYSTEM` (módulo)
    # — ver comentarios en la definición para el razonamiento de las reglas.

    def _handle_chat(body: dict) -> dict:
        message = body.get("message", "").strip()
        if not message:
            return {"error": "empty message"}
        sid = body.get("session_id")
        predict_cap = int(body.get("num_predict", 256))

        sess = ensure_session(sid, mode="chat") if sid else None
        history = session_history(sess) if sess else None

        # Finance / tarjetas short-circuit — bare text routes here from the
        # WhatsApp listener (slash commands `/search`/`/rag` go to /query).
        # Pre-fix 2026-04-26: voice transcript "decime cuánto gasté de
        # tarjeta este mes" → bare text → /chat → `_SERVE_CHAT_SYSTEM`
        # told the LLM to suggest `/search ...` instead of answering.
        # Now we fast-path queries that have data backends (banco xlsx,
        # MOZE CSV) so the user gets the actual numbers regardless of
        # whether they typed `/search` or just spoke.
        _fc_result = _finance_short_circuit_answer(message)
        if _fc_result is not None:
            answer, n_cards, has_moze, t_fc = _fc_result
            chat_turn_id = new_turn_id()
            if sess:
                append_turn(sess, {
                    "q": message, "a": answer[:500],
                    "turn_id": chat_turn_id, "mode": "finance",
                })
                save_session(sess)
            try:
                log_query_event({
                    "cmd": "serve.chat.finance",
                    "turn_id": chat_turn_id,
                    "session": sid, "q": message[:200],
                    "t_gen": round(t_fc, 3),
                    "intent": "finance",
                    "n_cards": n_cards,
                    "has_moze": has_moze,
                })
            except Exception:
                pass
            return {"answer": answer, "t_gen": round(t_fc, 3)}

        messages = [{"role": "system", "content": _SERVE_CHAT_SYSTEM}]
        if history:
            messages += history
        messages.append({"role": "user", "content": message})

        t0 = time.perf_counter()
        parts: list[str] = []
        try:
            for chunk in ollama.chat(
                model=resolve_chat_model(), messages=messages,
                options={**CHAT_OPTIONS, "num_predict": predict_cap},
                stream=True, keep_alive=chat_keep_alive(),
            ):
                parts.append(chunk.message.content)
        except Exception as exc:
            return {"error": f"llm failed: {exc}"}
        t_gen = time.perf_counter() - t0
        answer = "".join(parts).strip()

        chat_turn_id = new_turn_id()
        if sess:
            append_turn(sess, {
                "q": message, "a": answer[:500], "turn_id": chat_turn_id,
            })
            save_session(sess)

        try:
            log_query_event({
                "cmd": "serve.chat", "q": message[:200],
                "session": sid, "t_gen": round(t_gen, 2),
                "answered": True,
                "timing": _round_timing_ms({"total_ms": t_gen * 1000}),
            })
        except Exception:
            pass
        return {"answer": answer, "t_gen": round(t_gen, 3)}

    # Connection-drop exceptions we treat as "client went away, do NOT log
    # the traceback" — the WA listener (the main client of this endpoint)
    # sometimes disconnects mid-request when the phone network flaps or
    # whisper transcription runs long and the listener times out. Before
    # 2026-04-26 these surfaced as noisy double-tracebacks in serve.error.log
    # (one for the failed 200 write, a second for the failed 500 fallback).
    _CLIENT_GONE = (BrokenPipeError, ConnectionResetError, ConnectionAbortedError)

    class _Handler(BaseHTTPRequestHandler):
        def do_GET(self):
            if self.path == "/health":
                self._json(200, {"status": "ok", "chunks": col.count()})
            else:
                self._json(404, {"error": "not found"})

        def do_POST(self):
            if self.path not in ("/query", "/chat"):
                self._json(404, {"error": "not found"})
                return
            body: dict = {}
            try:
                length = int(self.headers.get("Content-Length", 0))
                body = _json.loads(self.rfile.read(length)) if length else {}
                handler = _handle_chat if self.path == "/chat" else _handle_query
                result = handler(body)
                self._json(200, result)
            except _CLIENT_GONE:
                # Client already closed the socket (WA listener timeout /
                # phone network flap). Nothing to send back; the handler
                # did its work, we just can't deliver. Do NOT fall through
                # to the 500 path — that would try to write on the same
                # dead socket and produce a second traceback.
                return
            except Exception as exc:
                # Log so the dashboard surfaces failures instead of silently
                # returning 500 — log_query_event was inside the success path
                # and never fired on errors.
                try:
                    log_query_event({
                        "cmd": "serve.error",
                        "q": str(body.get("question") or body.get("message") if isinstance(body, dict) else "")[:200],
                        "session": body.get("session_id") if isinstance(body, dict) else None,
                        "error": str(exc)[:300],
                    })
                except Exception:
                    pass
                try:
                    self._json(500, {"error": str(exc)})
                except _CLIENT_GONE:
                    # Client dropped while we were assembling the 500. Give
                    # up quietly — the error is already logged above.
                    pass

        def _json(self, code: int, data: dict):
            payload = _json.dumps(data, ensure_ascii=False).encode()
            self.send_response(code)
            self.send_header("Content-Type", "application/json")
            self.send_header("Content-Length", str(len(payload)))
            self.end_headers()
            self.wfile.write(payload)

        def log_message(self, format, *args):  # noqa: A002
            pass  # Silence per-request logging

    class _QuietHTTPServer(HTTPServer):
        """`HTTPServer` subclass that suppresses tracebacks for the
        client-disconnected exception family. stdlib's `BaseServer.handle_error`
        prints a full traceback to stderr for any uncaught exception raised
        inside the handler — including `BrokenPipeError` from `wfile.write()`
        when the client already closed. We silence that specific family so
        `serve.error.log` stays readable; other exceptions bubble up as usual.
        """

        def handle_error(self, request, client_address):
            import sys as _sys
            exc_type = _sys.exc_info()[0]
            if exc_type is not None and issubclass(exc_type, _CLIENT_GONE):
                return
            super().handle_error(request, client_address)

    server = _QuietHTTPServer((host, port), _Handler)
    console.print(f"[bold green]rag serve[/bold green] → http://{host}:{port}")
    try:
        server.serve_forever()
    except KeyboardInterrupt:
        console.print("\n[yellow]Stopped.[/yellow]")


def _corpus_breakdown_by_source() -> list[tuple[str, int, str]]:
    """Return `[(source_label, count, last_indexed_iso)]` sorted desc by count.

    Pulls per-source chunk counts directly from the meta table. `last_indexed`
    comes from `rag_*_state` tables when available (reminders/gmail/whatsapp
    ingesters all maintain one); falls back to the content hash mtime on disk
    for `vault`. Sources without a state table show "—".

    Used by `rag stats` for the cross-source breakdown. Silent-fails per
    source — a missing state table doesn't break the overall report.
    """
    try:
        import sqlite3 as _sqlite3
        con = _sqlite3.connect(f"file:{DB_PATH / 'ragvec.db'}?mode=ro", uri=True)
    except Exception:
        return []
    try:
        cur = con.cursor()
        # Some meta tables don't have `source` column (pre-schema). Probe first.
        meta_table = f"meta_{COLLECTION_NAME}"
        try:
            rows = cur.execute(
                f'SELECT COALESCE(source, "vault") AS src, COUNT(*) '
                f'FROM "{meta_table}" GROUP BY src ORDER BY 2 DESC'
            ).fetchall()
        except Exception:
            return []
        # Per-source last_indexed. Las state tables son specific por ingester
        # — nombre + column del timestamp vivien en scripts/ingest_*.py.
        last_ts: dict[str, str] = {}
        for src, state_tbl, ts_col in [
            ("whatsapp", "rag_whatsapp_state", "updated_at"),
            ("gmail", "rag_gmail_state", "updated_at"),
            ("reminders", "rag_reminders_state", "last_seen_ts"),
            ("calendar", "rag_calendar_state", "updated_at"),
        ]:
            try:
                r = cur.execute(
                    f'SELECT MAX({ts_col}) FROM "{state_tbl}"'
                ).fetchone()
                if r and r[0]:
                    # Normalize numeric (epoch) timestamps to ISO.
                    if isinstance(r[0], (int, float)):
                        last_ts[src] = datetime.fromtimestamp(r[0]).isoformat(timespec="minutes")
                    else:
                        last_ts[src] = str(r[0])[:16]  # truncate to `YYYY-MM-DDTHH:MM`
            except Exception:
                continue
        return [(src, cnt, last_ts.get(src, "—")) for src, cnt in rows]
    finally:
        con.close()


def rag_health_report() -> dict:
    """Resumen compacto de la salud operativa del runtime.

    Devuelve un dict con tres claves:

      ``feature_deps``:
        Lista de strings describiendo features que estan default-ON por
        env pero cuya dependencia importable NO esta disponible — es decir,
        la feature aparenta estar activa pero falla silenciosamente en
        producción.  Hoy cubre:

          - RAG_EXTRACT_ENTITIES ON + gliner ausente (28+ dropping
            `gliner_import_failed` a silent_errors.jsonl/dia cuando el
            paquete `obsidian-rag[entities]` no se instaló).

        El operador las ve en `rag stats` y puede ejecutar
        `uv pip install obsidian-rag[entities]` o `export RAG_EXTRACT_ENTITIES=0`
        para silenciar el warning.

      ``silent_errors_24h``:
        `{where: count}` agregando todas las entradas de
        `SILENT_ERRORS_LOG_PATH` con `ts` dentro de las ultimas 24h.
        Tolerancia total a corrupción: líneas no-JSON o sin `ts` se
        skipean silenciosamente.

      ``sql_state_errors_24h``:
        Mismo shape pero sobre `_SQL_STATE_ERROR_LOG`, agrupado por
        `event`. Permite detectar de un vistazo si el retry wrapper
        esta absorbiendo contención o si algún error no-transient está
        escalando (e.g. `disk I/O error`).

    Todo read-only; nunca raisea (siempre retorna un dict con las 3
    claves, aunque los valores sean vacíos).
    """
    from datetime import datetime as _dt, timedelta as _td
    report: dict = {
        "feature_deps": [],
        "silent_errors_24h": {},
        "sql_state_errors_24h": {},
        # Post 2026-04-22 audit: surfacing cache stats in rag stats so the
        # operator can spot "0 hits on 1000 queries" without raw SQL.
        "cache_stats": {
            "rows": None,
            "total_hits": None,
            "hit_rate_24h": None,
            "threshold": _SEMANTIC_CACHE_COSINE,
        },
    }

    # ── silent_errors.jsonl / sql_state_errors.jsonl rollup ──
    # (computed first so the feature_deps block below can also infer a
    # degraded feature from repeated failures even when the sticky flag
    # hasn't been set in THIS process — `rag stats` itself never calls
    # `_get_gliner_model`, but the indexer/ingesters did, and their
    # misses land in the shared log.)
    cutoff = _dt.now() - _td(hours=24)

    def _rollup(path: Path, key_field: str) -> dict[str, int]:
        counts: dict[str, int] = {}
        try:
            if not path.is_file():
                return counts
            with path.open("r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        rec = json.loads(line)
                    except Exception:
                        continue
                    ts = rec.get("ts")
                    if not ts:
                        continue
                    try:
                        # ts format: "YYYY-MM-DDTHH:MM:SS"
                        rec_dt = _dt.fromisoformat(ts.rstrip("Z"))
                    except Exception:
                        continue
                    if rec_dt < cutoff:
                        continue
                    key = rec.get(key_field) or "(unknown)"
                    counts[key] = counts.get(key, 0) + 1
        except Exception:
            pass
        return counts

    report["silent_errors_24h"] = _rollup(SILENT_ERRORS_LOG_PATH, "where")
    report["sql_state_errors_24h"] = _rollup(_SQL_STATE_ERROR_LOG, "event")

    # ── feature deps ──
    # RAG_EXTRACT_ENTITIES default ON + gliner soft-dep. Flag on EITHER
    # the sticky in-process marker (this process tried + failed) OR
    # recent 24h evidence from the shared log (other processes keep
    # failing). Ensures `rag stats` surfaces the issue even though
    # `rag stats` itself never imports gliner.
    gliner_evidence = (
        report["silent_errors_24h"].get("gliner_import_failed", 0)
        + report["silent_errors_24h"].get("gliner_load_failed", 0)
    )
    if _entity_extraction_enabled() and (_gliner_load_failed or gliner_evidence > 0):
        report["feature_deps"].append(
            "RAG_EXTRACT_ENTITIES=1 pero `gliner` no se pudo importar — "
            "entity extraction roto (corre `uv pip install obsidian-rag[entities]` "
            "o seteá `RAG_EXTRACT_ENTITIES=0` para silenciar)"
        )

    # ── cache_stats: tamaño de la tabla + hit rate 24h ──
    # Lee de `rag_response_cache` + cuenta `"cache_hit":true` en
    # `rag_queries.extra_json`. Degrada gracefully si la tabla no existe
    # o la conexión falla (DB nueva, telemetry.db missing en un host
    # recién clonado, etc.) — el panel siempre renderea, con valores
    # None cuando no hay datos.
    try:
        with _ragvec_state_conn() as _hc_conn:
            try:
                _row = _hc_conn.execute(
                    "SELECT COUNT(*), COALESCE(SUM(hit_count), 0) "
                    "FROM rag_response_cache"
                ).fetchone()
                report["cache_stats"]["rows"] = int(_row[0] or 0)
                report["cache_stats"]["total_hits"] = int(_row[1] or 0)
            except Exception:
                # Tabla no existe aún — DB fresca pre-GC#1.
                report["cache_stats"]["rows"] = 0
                report["cache_stats"]["total_hits"] = 0
            try:
                # IMPORTANTE: filtrar por `cmd IN (user query cmds)` — antes
                # del 2026-04-22 el denominador contaba también rows de
                # `cmd=followup`/`cmd=read` (611 de 1667 en 7 días) que
                # son jobs no queries. El helper `is_user_query()` expone
                # el allowlist central; aquí materializamos la cláusula
                # SQL desde el set para mantener coherencia single-source.
                _placeholders = ",".join("?" * len(_USER_QUERY_CMDS))
                _row2 = _hc_conn.execute(
                    "SELECT "
                    " SUM(CASE WHEN extra_json LIKE '%\"cache_hit\":true%' THEN 1 ELSE 0 END),"
                    " COUNT(*) "
                    "FROM rag_queries "
                    "WHERE ts > datetime('now','-1 day') "
                    "  AND q IS NOT NULL AND q != '' "
                    f"  AND cmd IN ({_placeholders})",
                    tuple(_USER_QUERY_CMDS),
                ).fetchone()
                _hits = int(_row2[0] or 0)
                _total = int(_row2[1] or 0)
                if _total > 0:
                    report["cache_stats"]["hit_rate_24h"] = _hits / _total
            except Exception:
                pass
    except Exception:
        # _ragvec_state_conn failed to open (missing DB, locked beyond
        # retry, etc.). Leave the None defaults — `rag stats` renders
        # "cache: (unavailable)" in that branch.
        pass

    return report


@cli.command()
def stats():
    """Estado del índice."""
    col = get_db()
    count = col.count()
    try:
        urls_count = get_urls_db().count()
    except Exception:
        urls_count = 0
    console.print(f"[cyan]Chunks indexados:[/cyan] {count}")

    # Cross-source breakdown. Solo renderea si hay ≥2 sources en el corpus —
    # en un deploy vault-only no aporta nada.
    breakdown = _corpus_breakdown_by_source()
    distinct_sources = {src for src, _, _ in breakdown}
    if len(distinct_sources) >= 2:
        tbl = Table(
            show_header=True, box=None, pad_edge=False, padding=(0, 1),
            title_style="cyan", title="Por source",
        )
        tbl.add_column("source", style="bold")
        tbl.add_column("chunks", justify="right")
        tbl.add_column("%", justify="right", style="dim")
        tbl.add_column("last indexed", style="dim")
        total = sum(cnt for _, cnt, _ in breakdown)
        for src, cnt, last_ts in breakdown:
            pct = f"{100 * cnt / total:.1f}%" if total else "—"
            tbl.add_row(src or "(null)", f"{cnt:,}", pct, last_ts)
        console.print(tbl)

    console.print(f"[cyan]URLs indexadas:[/cyan] {urls_count}  [dim]({URLS_COLLECTION_NAME})[/dim]")
    # Identificar la fuente del vault (env / registry / default) ayuda al
    # debug en setups multi-vault.
    vault_src = "default"
    if os.environ.get("OBSIDIAN_RAG_VAULT"):
        vault_src = "env"
    else:
        _vcfg = _load_vaults_config()
        if _vcfg["current"] and _vcfg["current"] in _vcfg["vaults"]:
            vault_src = f"registry · {_vcfg['current']}"
    console.print(f"[cyan]Vault:[/cyan] {VAULT_PATH}  [dim]({vault_src})[/dim]")
    console.print(f"[cyan]DB dir:[/cyan] {DB_PATH}")

    def _fmt_db_size(p: Path) -> str:
        try:
            b = p.stat().st_size
            wal = p.with_suffix(p.suffix + "-wal")
            wal_b = wal.stat().st_size if wal.is_file() else 0
            total_mb = (b + wal_b) / (1024 * 1024)
            wal_note = f" + WAL {wal_b / (1024*1024):.1f}MB" if wal_b else ""
            return f"{total_mb:.1f}MB{wal_note}"
        except OSError:
            return "[dim](missing)[/dim]"

    ragvec_db = DB_PATH / "ragvec.db"
    telemetry_db = DB_PATH / _TELEMETRY_DB_FILENAME
    console.print(f"[cyan]  ragvec.db:[/cyan]    {_fmt_db_size(ragvec_db)}  [dim](vec + meta + ingester cursors)[/dim]")
    console.print(f"[cyan]  telemetry.db:[/cyan] {_fmt_db_size(telemetry_db)}  [dim](rag_* telemetry + entity graph + OCR cache)[/dim]")
    console.print(f"[cyan]Colección:[/cyan] {COLLECTION_NAME}")
    console.print(f"[cyan]Embed model:[/cyan] {EMBED_MODEL}")
    try:
        resolved = resolve_chat_model()
    except Exception as e:
        resolved = f"[red]{e}[/red]"
    console.print(f"[cyan]Chat model:[/cyan] {resolved}  [dim](preference: {', '.join(CHAT_MODEL_PREFERENCE)})[/dim]")
    console.print(f"[cyan]Helper model:[/cyan] {HELPER_MODEL}")
    console.print(f"[cyan]Reranker:[/cyan] {RERANKER_MODEL}")
    console.print("[cyan]Pipeline:[/cyan] HyDE + BM25 + RRF + cross-encoder rerank")
    pos, neg = feedback_counts()
    if pos or neg:
        console.print(f"[cyan]Feedback:[/cyan] 👍 {pos} · 👎 {neg}  [dim]({FEEDBACK_PATH})[/dim]")

    # ── Health ─────────────────────────────────────────────────────────────
    # Features ON por default con deps faltantes + rollup de últimas 24h
    # de silent_errors.jsonl y sql_state_errors.jsonl. Antes de este panel
    # el operador no tenía forma de saber que RAG_EXTRACT_ENTITIES=1 estaba
    # roto sin hacer `cat ~/.local/share/obsidian-rag/silent_errors.jsonl`.
    try:
        hr = rag_health_report()
    except Exception:
        hr = {"feature_deps": [], "silent_errors_24h": {}, "sql_state_errors_24h": {}}

    deps = hr.get("feature_deps") or []
    se24 = hr.get("silent_errors_24h") or {}
    sse24 = hr.get("sql_state_errors_24h") or {}
    cs = hr.get("cache_stats") or {}

    # Cache panel siempre se renderiza si la tabla existe (rows is not None),
    # aunque hit_rate sea 0 — el operador quiere ver "0 hits" para diagnosticar.
    _has_cache_info = cs.get("rows") is not None

    if deps or se24 or sse24 or _has_cache_info:
        console.print()
        console.print("[bold cyan]Health (últimas 24h):[/bold cyan]")
        for msg in deps:
            # `markup=False`: the message may contain `[entities]`, `[nli]`
            # literals that rich would otherwise interpret as style tags
            # and silently drop.
            console.print(f"  ⚠ {msg}", style="yellow", markup=False, highlight=False)
        if _has_cache_info:
            _rows = cs.get("rows", 0) or 0
            _hit_rate = cs.get("hit_rate_24h")
            _thr = cs.get("threshold")
            _hit_rate_str = (
                f"{_hit_rate:.1%}" if isinstance(_hit_rate, (int, float)) else "—"
            )
            _thr_str = f"{_thr:.2f}" if isinstance(_thr, (int, float)) else "—"
            _line = (
                f"  semantic cache: rows={_rows}, hit_rate(24h)={_hit_rate_str}, "
                f"cosine_threshold={_thr_str}"
            )
            # Si hit rate es 0% sobre >50 queries, marcar en amarillo — señal
            # de que el cache no está absorbiendo queries repetidas.
            if (isinstance(_hit_rate, (int, float)) and _hit_rate < 0.01
                    and _rows < 50):
                console.print(
                    _line + "  ⚠ tabla casi vacía (revisar sql_state_errors)",
                    style="yellow", markup=False,
                )
            else:
                console.print(_line, style="dim", markup=False)
        if se24:
            # Ordenado por count desc — el operador quiere ver el más ruidoso primero.
            top = sorted(se24.items(), key=lambda kv: kv[1], reverse=True)[:6]
            console.print(
                "  silent_errors: "
                + ", ".join(f"{k}={v}" for k, v in top),
                style="dim", markup=False,
            )
        if sse24:
            top = sorted(sse24.items(), key=lambda kv: kv[1], reverse=True)[:6]
            console.print(
                "  sql_state_errors: "
                + ", ".join(f"{k}={v}" for k, v in top),
                style="dim", markup=False,
            )


def _resolve_nth_source_from_last_query(
    nth: int, session: str | None,
) -> dict | None:
    """Resolve the Nth source (1-indexed) from the most recent rag_queries row.

    When ``session`` is given, scope la última query a esa session. Si no,
    busca la última query global (cualquier session). Returns dict::

        {
            "path": str,              # vault-relative
            "original_query_id": int,
            "query": str,
            "session": str | None,
            "total_sources": int,     # len(paths_json) en esa row
        }

    o None si:
      - nth es < 1 o > total_sources
      - no hay rag_queries row (session=X sin queries, o DB vacía)
      - la row existe pero paths_json está vacío / corrupto

    Motivación (2026-04-23): el usuario necesita un shortcut de 2
    keystrokes para generar training signal de clicks sin registrar
    el URL handler de x-rag-open://. `rag open --nth 3` abre el #3
    del último retrieve + loggea el behavior event con
    `original_query_id` poblado automáticamente. Signal quality igual
    que un path_match del backfill pero inline.
    """
    try:
        with _ragvec_state_conn() as conn:
            # Pickeamos la última query CON paths_json populado, saltéando
            # metachat / empty-retrieve / degenerate rows (esas tienen
            # paths_json=NULL y no aportan nada a un --nth). Sin este
            # filter, queries como "Hola" (metachat) se convierten en "la
            # última" y --nth reporta "no hay rag_queries row previa"
            # aunque haya queries reales de hace 30 segundos.
            if session:
                row = conn.execute(
                    "SELECT id, q, session, paths_json FROM rag_queries"
                    " WHERE session = ?"
                    " AND paths_json IS NOT NULL"
                    " AND paths_json != '[]'"
                    " AND paths_json != ''"
                    " ORDER BY ts DESC LIMIT 1",
                    (session,),
                ).fetchone()
            else:
                row = conn.execute(
                    "SELECT id, q, session, paths_json FROM rag_queries"
                    " WHERE paths_json IS NOT NULL"
                    " AND paths_json != '[]'"
                    " AND paths_json != ''"
                    " ORDER BY ts DESC LIMIT 1"
                ).fetchone()
        if not row:
            return None
        qid, q, sess, paths_json = row
        if not paths_json:
            return None
        try:
            paths = json.loads(paths_json)
        except Exception:
            return None
        if not isinstance(paths, list) or not paths:
            return None
        if nth < 1 or nth > len(paths):
            return {
                "path": None,
                "original_query_id": int(qid),
                "query": q,
                "session": sess,
                "total_sources": len(paths),
                "out_of_range": True,
            }
        return {
            "path": str(paths[nth - 1]),
            "original_query_id": int(qid),
            "query": q,
            "session": sess,
            "total_sources": len(paths),
            "out_of_range": False,
        }
    except Exception as exc:
        _log_sql_state_error(
            "resolve_nth_source_failed", err=repr(exc),
        )
        return None


@cli.command("open")
@click.argument("path", required=False, default=None)
@click.option("--nth", type=int, default=None,
              help="Abrir el N-ésimo source (1-indexed) del último rag_queries. "
                   "Alternativa a pasar PATH — auto-rellena `original_query_id` "
                   "y `rank` en el behavior event.")
@click.option("--query", default=None, help="Triggering query, forwarded to behavior log")
@click.option("--rank", default=None, type=int, help="1-indexed rank among results when opened")
@click.option("--source", default="cli", help="Event source: cli | whatsapp | web | brief")
@click.option("--session", default=None,
              help="Session id, forwarded to behavior log. Con --nth, "
                   "scopea la búsqueda del último query a esa session.")
def open_cmd(
    path: str | None, nth: int | None, query: str | None,
    rank: int | None, source: str, session: str | None,
):
    """Open a vault note and record an open event in behavior.jsonl.

    Dos modos de uso:

      • `rag open 02-Areas/nota.md`  — PATH explícito (vault-relative o
        absoluto). Se abre vía macOS `open`; si está dentro del vault
        emite `event=open`, si no `event=open_external`.

      • `rag open --nth 3`           — abre el N-ésimo source del último
        `rag_queries` (opcionalmente scoped por `--session`). Auto-
        rellena `original_query_id`, `query`, y `rank` en el behavior
        event, produciendo un par de training clean para el ranker-vivo
        fine-tune — sin que el user tenga que registrar el URL handler
        de `x-rag-open://` en macOS.

    Un evento de open se appendea a ~/.local/share/obsidian-rag/
    behavior.jsonl + rag_behavior SQL.

    Flag RAG_TRACK_OPENS=1 cambia los OSC 8 links a `x-rag-open://` —
    registrando `rag open` como handler de ese scheme, los clicks en el
    terminal se routean por acá (mode 1, path-explícito).
    """
    import subprocess

    # Validar modo: path XOR --nth, no ambos ni ninguno.
    if path is not None and nth is not None:
        click.echo(
            "error: --nth y PATH son mutuamente excluyentes. "
            "Pasá uno o el otro, no ambos.",
            err=True,
        )
        raise SystemExit(2)
    if path is None and nth is None:
        click.echo(
            "error: pasá un PATH o --nth N. Ejemplos:\n"
            "  rag open 02-Areas/nota.md\n"
            "  rag open --nth 3",
            err=True,
        )
        raise SystemExit(2)

    # Modo --nth: resolver desde la última rag_queries row.
    _resolved_from_nth: dict | None = None
    if nth is not None:
        _resolved_from_nth = _resolve_nth_source_from_last_query(
            nth=int(nth), session=session,
        )
        if _resolved_from_nth is None:
            click.echo(
                "error: no hay rag_queries row previa"
                + (f" para session={session!r}" if session else "")
                + ". Correr `rag query <...>` o `rag chat` primero.",
                err=True,
            )
            raise SystemExit(1)
        if _resolved_from_nth.get("out_of_range"):
            total = _resolved_from_nth["total_sources"]
            click.echo(
                f"error: --nth {nth} fuera de rango. La última query tuvo "
                f"{total} source(s).",
                err=True,
            )
            raise SystemExit(1)
        path = _resolved_from_nth["path"]
        # Heredar query / session del resolved si el user no los pasó.
        if query is None and _resolved_from_nth.get("query"):
            query = _resolved_from_nth["query"]
        if session is None and _resolved_from_nth.get("session"):
            session = _resolved_from_nth["session"]
        if rank is None:
            rank = int(nth)

    p = Path(path)
    if not p.is_absolute():
        resolved = VAULT_PATH / p
    else:
        resolved = p

    if not resolved.exists():
        click.echo(f"error: path not found: {resolved}", err=True)
        raise SystemExit(1)

    try:
        inside_vault = resolved.resolve().is_relative_to(VAULT_PATH.resolve())
    except Exception:
        inside_vault = False

    if inside_vault:
        rel_path = str(resolved.resolve().relative_to(VAULT_PATH.resolve()))
        ev: dict = {"source": source, "event": "open", "path": rel_path}
        if query is not None:
            ev["query"] = query
        if rank is not None:
            ev["rank"] = rank
        if session is not None:
            ev["session"] = session
        # `--nth` inyecta el original_query_id para que el ranker-vivo
        # construya el training pair sin tener que adivinar (vs el
        # fallback del `rag behavior backfill`, que usa heurísticas
        # temporales + path match). Señal directa = mayor calidad.
        if _resolved_from_nth is not None:
            ev["original_query_id"] = int(_resolved_from_nth["original_query_id"])
        log_behavior_event(ev)
    else:
        ev_ext: dict = {"source": source, "event": "open_external"}
        if query is not None:
            ev_ext["query"] = query
        if session is not None:
            ev_ext["session"] = session
        log_behavior_event(ev_ext)

    subprocess.run(["open", str(resolved)])

    # Feedback al user sobre qué se abrió (solo en modo --nth, donde
    # no pasó el path explícito). Útil como confirmación.
    if _resolved_from_nth is not None:
        click.echo(
            f"✓ opened #{nth}: {path}  "
            f"(query: {(_resolved_from_nth['query'] or '')[:60]!r})"
        )


# ── ``rag vault`` group: extraído a rag/cli/vault.py el 2026-04-29 ──────────
# Sub-chunk 1.1 del package-split CLI. El grupo ``vault`` y sus 5
# subcomandos (``add``, ``list``, ``use``, ``current``, ``remove``) viven
# ahora en ``rag/cli/vault.py``. Los helpers compartidos
# (``_load_vaults_config``, ``_save_vaults_config``, ``_resolve_vault_path``,
# ``_DEFAULT_VAULT``, ``VAULTS_CONFIG_PATH``) **siguen acá** porque también
# los usan retrieve / index / anticipatory / pendientes — moverlos
# requeriría refactor más amplio fuera de scope del piloto.
#
# El re-export ``rag.vault`` (que tests existentes usan vía
# ``runner.invoke(rag.vault, [...])``) se hace en el shim al pie del
# módulo ("CLI sub-package re-export shim"), después de que el bootstrap
# del monolito está completo.


@cli.group()
def session():
    """Administrar sesiones conversacionales (list / show / clear / cleanup)."""


@session.command("list")
@click.option("-n", "limit", default=20, help="Máximo de sesiones a listar (default: 20)")
def session_list(limit: int):
    """Lista las sesiones recientes."""
    rows = list_sessions(limit=limit)
    if not rows:
        console.print("[dim]No hay sesiones.[/dim]")
        return
    t = Table(title=f"Sesiones ({len(rows)})", show_header=True, header_style="bold")
    t.add_column("id", style="cyan")
    t.add_column("turns", justify="right")
    t.add_column("modo", style="dim")
    t.add_column("actualizada", style="dim")
    t.add_column("primer turno")
    for r in rows:
        t.add_row(
            r["id"], str(r["turns"]), r.get("mode", ""),
            r.get("updated_at", ""), r.get("first_q", ""),
        )
    console.print(t)


@session.command("show")
@click.argument("sid")
def session_show(sid: str):
    """Muestra los turnos de una sesión."""
    s = load_session(sid)
    if not s:
        console.print(f"[red]Sesión no encontrada: {sid}[/red]")
        return
    console.print(Panel(
        f"[bold cyan]{s['id']}[/bold cyan]  [dim]· {len(s.get('turns', []))} turnos · "
        f"{s.get('mode', '')}  · creada {s.get('created_at', '')}[/dim]",
        border_style="cyan",
    ))
    for i, turn in enumerate(s.get("turns", []), 1):
        console.print()
        console.print(f"[bold]{i}. ❯[/bold] {turn.get('q', '')}")
        if turn.get("q_reformulated"):
            console.print(f"   [dim italic]reformulada: {turn['q_reformulated']}[/dim italic]")
        if turn.get("a"):
            console.print(render_response(turn["a"]))
        paths = turn.get("paths") or []
        if paths:
            console.print(f"   [dim]sources: {', '.join(paths[:3])}{'…' if len(paths) > 3 else ''}[/dim]")


@session.command("clear")
@click.argument("sid")
@click.option("--yes", is_flag=True, help="No pedir confirmación")
def session_clear(sid: str, yes: bool):
    """Borra una sesión por id."""
    try:
        p = session_path(sid)
    except ValueError as e:
        console.print(f"[red]{e}[/red]")
        return
    if not p.exists():
        console.print(f"[yellow]No existe:[/yellow] {sid}")
        return
    if not yes:
        try:
            confirm = console.input(f"Borrar sesión [cyan]{sid}[/cyan]? [y/N] ").strip().lower()
        except (KeyboardInterrupt, EOFError):
            console.print("[dim]cancelado[/dim]")
            return
        if confirm != "y":
            console.print("[dim]cancelado[/dim]")
            return
    p.unlink()
    console.print(f"[green]✓ borrada:[/green] {sid}")


@session.command("cleanup")
@click.option("--days", default=SESSION_TTL_DAYS, show_default=True,
              help="Borrar sesiones más viejas que N días (mtime)")
def session_cleanup(days: int):
    """Purga sesiones viejas."""
    removed = cleanup_sessions(ttl_days=days)
    console.print(f"[cyan]{removed}[/cyan] sesión(es) borrada(s) (TTL {days}d)")


# ── session export (Feature #12 del 2026-04-23) ─────────────────────────
# Snapshot de una sesión completa a una .md nota del vault. Útil para
# preservar conversaciones importantes en PARA (01-Projects o 03-Resources)
# donde van a ser indexadas como contenido de primera clase.
#
# Sin folders new_nodeado: se escribe a 00-Inbox/ por default (es el patrón
# del resto del vault; el user mueve manualmente si quiere). Sobreescribir
# PREVENIDO: si el path existe, se agrega un sufijo timestamp.

def _render_session_to_markdown(sess: dict, *, include_sources: bool = True) -> str:
    """Convierte una sesión a markdown con frontmatter + turns.

    Frontmatter incluye: created, modified, session_id, tags=[conversation],
    source = "rag session export".
    """
    sid = sess.get("id", "unknown")
    created = sess.get("created_at", "")
    updated = sess.get("updated_at", "")
    turns = sess.get("turns") or []
    first_q = (turns[0].get("q") if turns else "") or "Conversación sin título"
    title = first_q[:80].strip().rstrip("?!.,;:") or "Conversación"

    lines: list[str] = []
    lines.append("---")
    lines.append(f"created: {created}")
    lines.append(f"modified: {updated}")
    lines.append(f"session_id: {sid}")
    lines.append(f"n_turns: {len(turns)}")
    lines.append(f"mode: {sess.get('mode', 'chat')}")
    lines.append("tags: [conversation, rag-export]")
    lines.append("source: rag session export")
    lines.append("---")
    lines.append("")
    lines.append(f"# {title}")
    lines.append("")
    lines.append(f"> Exportada de la sesión `{sid}` — {len(turns)} turnos, "
                 f"creada {created}.")
    lines.append("")

    for i, turn in enumerate(turns, 1):
        q = turn.get("q") or ""
        a = turn.get("a") or ""
        lines.append(f"## Turno {i}")
        lines.append("")
        lines.append(f"**Pregunta:** {q}")
        lines.append("")
        if turn.get("q_reformulated"):
            lines.append(f"*Reformulada:* {turn['q_reformulated']}")
            lines.append("")
        lines.append("**Respuesta:**")
        lines.append("")
        lines.append(a.strip() if a else "*(sin respuesta)*")
        lines.append("")
        paths = turn.get("paths") or []
        if include_sources and paths:
            lines.append("**Sources:**")
            for p in paths[:5]:
                lines.append(f"- [[{p}]]")
            if len(paths) > 5:
                lines.append(f"- *...y {len(paths) - 5} más*")
            lines.append("")
    return "\n".join(lines)


@session.command("export")
@click.argument("sid", required=False, default=None)
@click.option("--folder", default="00-Inbox",
              show_default=True,
              help="Carpeta destino (vault-relative).")
@click.option("--filename", default=None,
              help="Override del filename (sin .md). "
                   "Default: YYYY-MM-DD-HHMM-<sid>.md")
@click.option("--no-sources", is_flag=True,
              help="No incluir los paths de los sources en cada turno.")
@click.option("--stdout", "to_stdout", is_flag=True,
              help="Imprimir el markdown a stdout en lugar de escribir al vault.")
@click.option("--force", is_flag=True,
              help="Sobreescribir si el archivo existe (default: agrega sufijo).")
def session_export(
    sid: str | None, folder: str, filename: str | None,
    no_sources: bool, to_stdout: bool, force: bool,
):
    """Exportar una sesión a una nota markdown del vault.

    Ejemplos:
        rag session export               # última sesión → 00-Inbox/
        rag session export a3f2b1        # sesión específica
        rag session export --folder 01-Projects/notes
        rag session export --stdout      # imprimir sin escribir

    La nota incluye frontmatter con session_id + tags, y cada turno
    con pregunta, respuesta reformulada (si existe) y sources como
    wikilinks. Post-escritura trigger un re-index del archivo.
    """
    target_sid = sid or last_session_id()
    if not target_sid:
        console.print("[red]No hay sesión activa[/red] — pasá un SID explícito.")
        return
    sess = load_session(target_sid)
    if not sess:
        console.print(f"[red]Sesión no encontrada: {target_sid}[/red]")
        return
    if not sess.get("turns"):
        console.print(f"[yellow]Sesión vacía (sin turnos): {target_sid}[/yellow]")
        return

    md = _render_session_to_markdown(sess, include_sources=not no_sources)

    if to_stdout:
        click.echo(md)
        return

    # Compute filename.
    from datetime import datetime as _dt
    ts = _dt.now().strftime("%Y-%m-%d-%H%M")
    base_name = filename or f"{ts}-conversation-{target_sid[:8]}"
    if not base_name.endswith(".md"):
        base_name += ".md"

    try:
        vault = _resolve_vault_path()
    except Exception as exc:
        console.print(f"[red]Error resolving vault: {exc!r}[/red]")
        return
    target_dir = vault / folder
    target_dir.mkdir(parents=True, exist_ok=True)
    target_path = target_dir / base_name
    if target_path.exists() and not force:
        # Agregar sufijo timestamp second-level para evitar colisión.
        suffix = _dt.now().strftime("%S")
        stem = target_path.stem
        target_path = target_dir / f"{stem}-{suffix}.md"

    try:
        target_path.write_text(md, encoding="utf-8")
    except Exception as exc:
        console.print(f"[red]Error writing {target_path}: {exc!r}[/red]")
        return

    rel = target_path.relative_to(vault)
    console.print(f"[green]✓[/green] Exportada a [cyan]{rel}[/cyan]  "
                  f"[dim]({len(md)} chars, {len(sess.get('turns', []))} turns)[/dim]")

    # Best-effort reindex so the note is searchable immediately.
    try:
        col = get_db()
        _index_single_file(col, target_path)
        console.print("  [dim]reindexed OK[/dim]")
    except Exception:
        pass


# ── DASHBOARD ─────────────────────────────────────────────────────────────────
# Terminal-based analytics over queries.jsonl. Shows query patterns, retrieval
# quality distribution, latency breakdown, and feedback ratio.


def _dashboard_data(days: int = 30) -> dict:
    """Parse queries.jsonl into dashboard metrics."""
    entries = _scan_queries_log(days=days)
    if not entries:
        return {"n": 0}

    scores: list[float] = []
    t_retrieves: list[float] = []
    t_gens: list[float] = []
    gated = 0
    answered = 0
    topics: dict[str, int] = {}
    hours: dict[int, int] = {}
    cmds: dict[str, int] = {}

    for e in entries:
        ts_raw = e.get("ts") or e.get("timestamp")
        if ts_raw:
            try:
                hour = datetime.fromisoformat(ts_raw).hour
                hours[hour] = hours.get(hour, 0) + 1
            except Exception:
                pass

        cmd = e.get("cmd", "?")
        cmds[cmd] = cmds.get(cmd, 0) + 1

        top = e.get("top_score")
        if isinstance(top, (int, float)):
            scores.append(float(top))

        tr = e.get("t_retrieve")
        if isinstance(tr, (int, float)):
            t_retrieves.append(float(tr))

        tg = e.get("t_gen")
        if isinstance(tg, (int, float)) and tg > 0:
            t_gens.append(float(tg))

        if e.get("gated_low_confidence"):
            gated += 1
        if e.get("answered"):
            answered += 1

        # Topic extraction: first 3 words of query
        q = e.get("q", "")
        if q:
            words = q.lower().split()[:3]
            topic = " ".join(words)
            topics[topic] = topics.get(topic, 0) + 1

    # Percentiles helper
    def pct(values: list[float], p: float) -> float:
        if not values:
            return 0.0
        s = sorted(values)
        idx = int(len(s) * p / 100)
        return s[min(idx, len(s) - 1)]

    return {
        "n": len(entries),
        "days": days,
        "scores": scores,
        "t_retrieves": t_retrieves,
        "t_gens": t_gens,
        "gated": gated,
        "answered": answered,
        "topics": topics,
        "hours": hours,
        "cmds": cmds,
        "pct": pct,
    }


@cli.command()
@click.option("--days", default=30, show_default=True, help="Ventana temporal en días")
def dashboard(days: int):
    """Analytics dashboard — métricas del pipeline sobre queries.jsonl."""
    data = _dashboard_data(days)
    if data["n"] == 0:
        console.print("[yellow]Sin queries en el período.[/yellow]")
        return

    console.print()
    console.print(Rule(title="[bold cyan]Dashboard[/bold cyan]", style="cyan"))
    console.print(f"  [dim]{data['n']} queries · últimos {data['days']} días[/dim]")
    console.print()

    # ── Commands breakdown ──
    t = Table(title="Comandos", show_header=True, header_style="bold", box=None, padding=(0, 2))
    t.add_column("Comando", style="cyan")
    t.add_column("Count", justify="right")
    for cmd, count in sorted(data["cmds"].items(), key=lambda x: -x[1])[:8]:
        t.add_row(cmd, str(count))
    console.print(t)
    console.print()

    # ── Retrieval quality ──
    scores = data["scores"]
    pct = data["pct"]
    if scores:
        console.print(Rule(title="[dim]Retrieval Quality[/dim]", style="dim", characters="╌"))
        gate_rate = data["gated"] / data["n"] * 100 if data["n"] else 0
        answer_rate = data["answered"] / data["n"] * 100 if data["n"] else 0
        console.print(f"  Score p50: [bold]{pct(scores, 50):.3f}[/bold] · "
                      f"p95: [bold]{pct(scores, 95):.3f}[/bold] · "
                      f"min: {min(scores):.3f} · max: {max(scores):.3f}")
        console.print(f"  Gate rate: [{'red' if gate_rate > 30 else 'green'}]"
                      f"{gate_rate:.1f}%[/] · Answer rate: [green]{answer_rate:.1f}%[/]")
        # Score distribution histogram (inline)
        buckets = [0] * 10  # 0.0-0.1, 0.1-0.2, ..., 0.9-1.0
        for s in scores:
            clamped = max(0.0, min(s, 1.0))
            idx = min(int(clamped * 10), 9)
            buckets[idx] += 1
        max_b = max(buckets) or 1
        console.print("  Score distribution:")
        for i, b in enumerate(buckets):
            bar = "█" * int(b / max_b * 20) if b else ""
            label = f"  {i/10:.1f}-{(i+1)/10:.1f}"
            console.print(f"  {label} [{('green' if i >= 5 else 'yellow' if i >= 2 else 'red')}]{bar}[/] {b}")
        console.print()

    # ── Latency breakdown ──
    t_r = data["t_retrieves"]
    t_g = data["t_gens"]
    if t_r:
        console.print(Rule(title="[dim]Latency[/dim]", style="dim", characters="╌"))
        console.print(f"  Retrieve: p50 [bold]{pct(t_r, 50):.2f}s[/bold] · "
                      f"p95 [bold]{pct(t_r, 95):.2f}s[/bold]")
        if t_g:
            console.print(f"  Generate: p50 [bold]{pct(t_g, 50):.2f}s[/bold] · "
                          f"p95 [bold]{pct(t_g, 95):.2f}s[/bold]")
            total = [r + g for r, g in zip(t_r[:len(t_g)], t_g)]
            if total:
                console.print(f"  Total:    p50 [bold]{pct(total, 50):.2f}s[/bold] · "
                              f"p95 [bold]{pct(total, 95):.2f}s[/bold]")
        console.print()

    # ── Activity heatmap (by hour) ──
    hours = data["hours"]
    if hours:
        console.print(Rule(title="[dim]Activity by Hour[/dim]", style="dim", characters="╌"))
        max_h = max(hours.values()) or 1
        for h in range(24):
            count = hours.get(h, 0)
            bar = "█" * int(count / max_h * 30) if count else ""
            console.print(f"  {h:02d}:00 [cyan]{bar}[/] {count if count else ''}")
        console.print()

    # ── Hot topics (top queries by prefix) ──
    topics = data["topics"]
    if topics:
        console.print(Rule(title="[dim]Hot Topics[/dim]", style="dim", characters="╌"))
        for topic, count in sorted(topics.items(), key=lambda x: -x[1])[:10]:
            if count >= 2:
                console.print(f"  [bold]{count}×[/bold] {topic}")
        console.print()

    # ── Feedback stats ──
    try:
        if FEEDBACK_PATH.is_file():
            fb_lines = FEEDBACK_PATH.read_text(encoding="utf-8").splitlines()
            pos = sum(1 for l in fb_lines if '"rating": 1' in l or '"rating":1' in l)
            neg = sum(1 for l in fb_lines if '"rating": -1' in l or '"rating":-1' in l)
            corrective = sum(1 for l in fb_lines if '"corrective_path"' in l)
            console.print(Rule(title="[dim]Feedback[/dim]", style="dim", characters="╌"))
            total_fb = pos + neg
            ratio = pos / total_fb * 100 if total_fb else 0
            console.print(f"  👍 {pos} · 👎 {neg} · ratio: [{'green' if ratio > 70 else 'yellow'}]{ratio:.0f}%[/]")
            if corrective:
                console.print(f"  🎯 {corrective} corrective paths")
            console.print()
    except Exception:
        pass

    # ── Index stats (quick) ──
    try:
        col = get_db()
        n_chunks = col.count()
        console.print(Rule(title="[dim]Index[/dim]", style="dim", characters="╌"))
        console.print(f"  {n_chunks} chunks indexed")
        corpus = _load_corpus(col)
        console.print(f"  {len(corpus['tags'])} tags · "
                      f"{len(corpus['folders'])} folders · "
                      f"{len(corpus['title_to_paths'])} notes")
        pr = get_pagerank(col)
        if pr:
            top_pr = sorted(pr.items(), key=lambda x: -x[1])[:5]
            console.print("  Top PageRank:")
            for path, score in top_pr:
                console.print(f"    {score:.4f} {path}")
    except Exception:
        pass
    console.print()


# ── MAINTENANCE ──────────────────────────────────────────────────────────────
# Unified housekeeping: reindex, prune orphans, rotate logs, clean caches,
# rebuild derived state, report dead notes. Safe to run unattended (cron/launchd).

_JSONL_ROTATE_BYTES = 10 * 1024 * 1024  # 10 MB threshold for log rotation

_JSONL_LOG_PATHS: list[tuple[str, Path]] = [
    ("queries.jsonl", LOG_PATH),
    ("behavior.jsonl", BEHAVIOR_LOG_PATH),
    ("contradictions.jsonl", CONTRADICTION_LOG_PATH),
    ("ambient.jsonl", AMBIENT_LOG_PATH),
    ("ambient_state.jsonl", AMBIENT_STATE_PATH),
    ("tune.jsonl", TUNE_LOG_PATH),
    ("behavior.jsonl", BEHAVIOR_LOG_PATH),
    ("brief_written.jsonl", BRIEF_WRITTEN_PATH),
    ("brief_state.jsonl", BRIEF_STATE_PATH),
]


def _rotate_jsonl(path: Path, max_bytes: int = _JSONL_ROTATE_BYTES) -> str | None:
    """Rotate a JSONL file if it exceeds max_bytes. Keeps the most recent half
    of the lines and moves the rest to path.1. Returns description or None."""
    if not path.is_file():
        return None
    try:
        size = path.stat().st_size
    except OSError:
        return None
    if size < max_bytes:
        return None
    lines = path.read_text(encoding="utf-8").splitlines()
    if len(lines) < 2:
        return None
    keep = len(lines) // 2
    old = path.with_suffix(path.suffix + ".1")
    old.write_text("\n".join(lines[:len(lines) - keep]) + "\n", encoding="utf-8")
    path.write_text("\n".join(lines[len(lines) - keep:]) + "\n", encoding="utf-8")
    return f"{len(lines) - keep} lines kept, {len(lines) - keep} archived → {old.name} ({size / 1024:.0f} KB → {path.stat().st_size / 1024:.0f} KB)"


def _prune_context_cache(col: "SqliteVecCollection") -> int:
    """Remove context_summaries entries whose file hash is no longer in the index."""
    cache = _load_context_cache()
    if not cache:
        return 0
    existing = col.get(include=["metadatas"])
    live_hashes: set[str] = set()
    for m in existing["metadatas"]:
        h = m.get("hash", "")
        if h:
            live_hashes.add(h)
    with _context_cache_lock:
        stale = [k for k in cache if k not in live_hashes]
        for k in stale:
            del cache[k]
        if stale:
            global _context_cache_dirty
            _context_cache_dirty = True
    if stale:
        _save_context_cache()
    return len(stale)


def _prune_synthetic_q_cache(col: "SqliteVecCollection") -> int:
    """Remove synthetic_questions entries whose file hash is no longer in the index."""
    cache = _load_synthetic_q_cache()
    if not cache:
        return 0
    existing = col.get(include=["metadatas"])
    live_hashes: set[str] = set()
    for m in existing["metadatas"]:
        h = m.get("hash", "")
        if h:
            live_hashes.add(h)
    with _synthetic_q_cache_lock:
        stale = [k for k in cache if k not in live_hashes]
        for k in stale:
            del cache[k]
        if stale:
            global _synthetic_q_cache_dirty
            _synthetic_q_cache_dirty = True
    if stale:
        _save_synthetic_q_cache()
    return len(stale)


def _prune_ignored_notes(vault: Path) -> int:
    """Remove entries from ignored_notes.json whose files no longer exist."""
    paths = load_ignored_paths()
    if not paths:
        return 0
    stale = {p for p in paths if not (vault / p).exists()}
    if stale:
        save_ignored_paths(paths - stale)
    return len(stale)


def _prune_auto_index_state() -> int:
    """Remove auto_index_state entries for vaults not in the registry or default."""
    state = _auto_index_state_load()
    if not state:
        return 0
    valid_keys = {_vault_state_key(VAULT_PATH)}
    try:
        vcfg = _load_vaults_config()
        for vpath in vcfg["vaults"].values():
            valid_keys.add(_vault_state_key(Path(vpath)))
    except Exception:
        pass
    stale = [k for k in state if k not in valid_keys]
    if stale:
        for k in stale:
            del state[k]
        _auto_index_state_save(state)
    return len(stale)


_FILING_BATCH_TTL_DAYS = 90


def _prune_filing_batches(ttl_days: int = _FILING_BATCH_TTL_DAYS) -> int:
    """Delete filing batch files older than ttl_days."""
    if not FILING_BATCHES_DIR.is_dir():
        return 0
    cutoff = time.time() - ttl_days * 86400
    removed = 0
    for f in FILING_BATCHES_DIR.glob("*.jsonl"):
        try:
            if f.stat().st_mtime < cutoff:
                f.unlink()
                removed += 1
        except OSError:
            continue
    return removed


def _cleanup_tmp_files() -> int:
    """Remove orphan .tmp files from state directories (crashed writes)."""
    state_dir = Path.home() / ".local/share/obsidian-rag"
    removed = 0
    if not state_dir.is_dir():
        return 0
    for tmp in state_dir.glob("*.tmp"):
        try:
            # Only remove if older than 1 hour (avoid racing with live writes)
            if time.time() - tmp.stat().st_mtime > 3600:
                tmp.unlink()
                removed += 1
        except OSError:
            continue
    # Also check sessions dir
    if SESSIONS_DIR.is_dir():
        for tmp in SESSIONS_DIR.glob("*.tmp"):
            try:
                if time.time() - tmp.stat().st_mtime > 3600:
                    tmp.unlink()
                    removed += 1
            except OSError:
                continue
    return removed


def _cleanup_chat_uploads(*, ttl_days: int | None = None) -> dict:
    """Borra imágenes en chat-uploads/ con mtime > ttl_days.

    Las imágenes se guardan en ``~/.local/share/obsidian-rag/chat-uploads/``
    cuando el user las sube via ``/api/chat/upload-image``. Sin TTL, el dir
    crece sin bound (audit 2026-04-25 R2-Security #6). Idempotente — si
    una imagen ya fue copiada al vault con un naming cronológico
    (``00-Inbox/<timestamp>-<hash8>.ext``), borrar el cache no pierde data.

    Args:
      ttl_days: días de antigüedad mínima para borrar. Default lee la env
        var ``RAG_CHAT_UPLOADS_TTL_DAYS``, fallback 30.

    Returns:
      ``{"deleted": N, "bytes_freed": M, "errors": [...]}``. Nunca tira —
      si el dir no existe devuelve ceros; errores per-archivo se acumulan
      en ``errors`` para que el caller pueda loguearlos sin abortar la
      maintenance entera.
    """
    if ttl_days is None:
        ttl_days = int(os.environ.get("RAG_CHAT_UPLOADS_TTL_DAYS", "30"))
    upload_dir = Path.home() / ".local" / "share" / "obsidian-rag" / "chat-uploads"
    if not upload_dir.is_dir():
        return {"deleted": 0, "bytes_freed": 0, "errors": []}

    now = time.time()
    cutoff = now - (ttl_days * 86400)
    deleted = 0
    bytes_freed = 0
    errors: list[str] = []
    for fpath in upload_dir.iterdir():
        if not fpath.is_file():
            continue
        try:
            mtime = fpath.stat().st_mtime
            if mtime < cutoff:
                size = fpath.stat().st_size
                fpath.unlink()
                deleted += 1
                bytes_freed += size
        except Exception as e:  # noqa: BLE001 - best-effort, capturamos per-file
            errors.append(f"{fpath.name}: {e}")

    return {"deleted": deleted, "bytes_freed": bytes_freed, "errors": errors}


def _check_ollama_health() -> dict:
    """Verify required Ollama models are available. Returns {model: ok/missing}."""
    required = [EMBED_MODEL, HELPER_MODEL] + list(CHAT_MODEL_PREFERENCE)
    status: dict[str, str] = {}
    try:
        available = {m.model for m in ollama.list().models}
    except Exception as e:
        return {"error": str(e)}
    for model in required:
        # ollama.list() returns full names; match with and without :latest
        found = model in available or f"{model}:latest" in available
        if not found:
            # Try prefix match (e.g. "command-r" matches "command-r:latest")
            found = any(a.startswith(model.split(":")[0] + ":") for a in available)
        status[model] = "ok" if found else "missing"
    return status


def _prune_url_orphans(vault: Path) -> int:
    """Remove URL collection entries for files no longer on disk."""
    try:
        col_urls = get_urls_db()
        all_urls = col_urls.get(include=["metadatas"])
    except Exception:
        return 0
    if not all_urls["ids"]:
        return 0
    on_disk = {
        str(p.relative_to(vault))
        for p in vault.rglob("*.md")
        if not is_excluded(str(p.relative_to(vault)))
    }
    orphan_ids = [
        id_ for id_, meta in zip(all_urls["ids"], all_urls["metadatas"])
        if meta.get("file", "") not in on_disk
    ]
    if orphan_ids:
        # Chunk deletes for predictable memory usage.
        for i in range(0, len(orphan_ids), 5000):
            col_urls.delete(ids=orphan_ids[i:i + 5000])
    return len(orphan_ids)


def _prune_feedback_orphans(vault: Path) -> int:
    """Remove feedback.jsonl entries whose paths all point to deleted notes.
    Rewrites the file in place, preserving entries that have at least one live path."""
    if not FEEDBACK_PATH.is_file():
        return 0
    on_disk = {
        str(p.relative_to(vault))
        for p in vault.rglob("*.md")
        if not is_excluded(str(p.relative_to(vault)))
    }
    lines = FEEDBACK_PATH.read_text(encoding="utf-8").splitlines()
    kept: list[str] = []
    removed = 0
    for line in lines:
        line = line.strip()
        if not line:
            continue
        try:
            ev = json.loads(line)
        except Exception:
            kept.append(line)
            continue
        paths = ev.get("paths") or []
        # Keep if any path still exists, or if it's a session-scope rating (no paths)
        if not paths or any(p in on_disk for p in paths):
            kept.append(line)
        else:
            removed += 1
    if removed:
        FEEDBACK_PATH.write_text("\n".join(kept) + "\n" if kept else "", encoding="utf-8")
    return removed


def _find_orphan_collections() -> list[str]:
    """Detect sqlite-vec collections from old schema versions or removed vaults.

    Safety invariants
    -----------------
    1. Base names are never orphaned: _COLLECTION_BASE ("obsidian_notes_v9")
       and _URLS_COLLECTION_BASE ("obsidian_urls_v1") are unconditionally added
       to `known` so that if this process was launched with OBSIDIAN_RAG_VAULT
       pointing at a non-default vault, the default vault's unsuffixed collection
       is still protected and not classified as an orphan.

    2. No recency guard is implemented — sqlite-vec has no creation timestamp in
       schema.

    3. Audit: every candidate orphan is logged via _log_collection_op before
       being returned to the caller (which may delete it).
    """
    try:
        client = SqliteVecClient(path=str(DB_PATH))
        all_cols = [c.name for c in client.list_collections()]
    except Exception:
        return []
    known = {COLLECTION_NAME, URLS_COLLECTION_NAME}
    # Unconditionally protect the base names for the default vault.
    # If this process was started with OBSIDIAN_RAG_VAULT set to a work vault,
    # COLLECTION_NAME / URLS_COLLECTION_NAME resolve to the work-vault suffixed
    # names.  The unsuffixed default-vault collections would then fall through
    # as unknown and get wrongly classified as orphans without this guard.
    known.add(_COLLECTION_BASE)
    known.add(_URLS_COLLECTION_BASE)
    # Also include collections for registered vaults
    try:
        vcfg = _load_vaults_config()
        for vpath in vcfg["vaults"].values():
            vp = Path(vpath)
            known.add(_collection_name_for_vault(vp))
            known.add(_urls_collection_name_for_vault(vp))
    except Exception:
        pass
    orphans = [c for c in all_cols if c not in known]
    # Audit every candidate before returning to caller — caller may delete them.
    for cname in orphans:
        _log_collection_op("orphan_candidate", cname)
    return orphans


def _find_orphan_segment_dirs() -> list[tuple[Path, int]]:
    """sqlite-vec has no HNSW segment dirs on disk; stub retained
    for call-site compatibility with _prune_orphan_segment_dirs."""
    return []


def _prune_orphan_segment_dirs(dry_run: bool = False) -> dict:
    """Delete orphan HNSW segment dirs. Returns {count, bytes_freed, paths}."""
    orphans = _find_orphan_segment_dirs()
    total = sum(sz for _, sz in orphans)
    out: dict = {
        "count": len(orphans),
        "bytes_freed": total,
        "paths": [p.name for p, _ in orphans],
    }
    if dry_run or not orphans:
        return out
    import shutil as _shutil
    removed = 0
    freed = 0
    for path, sz in orphans:
        try:
            _shutil.rmtree(path)
            removed += 1
            freed += sz
        except OSError:
            pass
    out["count"] = removed
    out["bytes_freed"] = freed
    return out


def _wal_checkpoint_for(sqlite_path: Path, *, dry_run: bool = False) -> dict:
    """Run `PRAGMA wal_checkpoint(TRUNCATE)` against an arbitrary sqlite file.

    Safer than VACUUM — doesn't require exclusive lock and truncates the
    write-ahead log after flushing. Returns {before_bytes, after_bytes, ok}.
    Helper for post-split maintenance: ragvec.db and telemetry.db each have
    their own WAL and need independent checkpoints.
    """
    wal_path = sqlite_path.with_suffix(sqlite_path.suffix + "-wal")
    if not sqlite_path.is_file():
        return {"ok": False, "reason": "no sqlite file"}
    before = sqlite_path.stat().st_size + (wal_path.stat().st_size if wal_path.is_file() else 0)
    if dry_run:
        return {"ok": True, "before_bytes": before, "after_bytes": before, "dry_run": True}
    import sqlite3 as _sqlite
    try:
        conn = _sqlite.connect(str(sqlite_path), timeout=5.0)
        try:
            conn.execute("PRAGMA wal_checkpoint(TRUNCATE)")
            conn.commit()
        finally:
            conn.close()
    except Exception as e:
        return {"ok": False, "reason": str(e), "before_bytes": before}
    after = sqlite_path.stat().st_size + (wal_path.stat().st_size if wal_path.is_file() else 0)
    return {"ok": True, "before_bytes": before, "after_bytes": after}


def _vec_wal_checkpoint(dry_run: bool = False) -> dict:
    """Run `PRAGMA wal_checkpoint(TRUNCATE)` on ragvec.db (sqlite-vec workload)."""
    return _wal_checkpoint_for(DB_PATH / "ragvec.db", dry_run=dry_run)


def _telemetry_wal_checkpoint(dry_run: bool = False) -> dict:
    """Run `PRAGMA wal_checkpoint(TRUNCATE)` on telemetry.db.

    Post 2026-04-21 split — telemetry.db is the hot-path writes target (queries,
    behavior, memory/cpu metrics). Separate WAL from ragvec.db, so an
    unconditional checkpoint is fired in run_maintenance to keep the WAL
    bounded even when --skip-logs bypasses _sql_rotate_log_tables.
    """
    return _wal_checkpoint_for(DB_PATH / _TELEMETRY_DB_FILENAME, dry_run=dry_run)


# ── SQL log rotation (T7) ────────────────────────────────────────────────────
# Retention policies per log-style rag_* table. When RAG_STATE_SQL=1 and
# `rag maintenance` runs, rows with ts < now - retention are DELETEd. State-
# style tables (rag_ambient_state, rag_brief_state, rag_conversations_index,
# rag_feedback_golden, rag_feedback_golden_meta) are keyed upserts and MUST
# NOT appear here.
#
# Defaults chosen in T7:
#   90d: queries, behavior             — ranker-vivo signal window
#   60d: ambient, brief_written, wa_tasks, archive, filing, eval, surface,
#        proactive — useful historic context but not ranker input
#   30d: cpu_metrics, memory_metrics — sampled every minute by the web
#        sampler; bloat magnet otherwise
#   ∞ : feedback, tune, contradictions — small, high-signal, intentionally
#        kept (feedback golden depends on full rag_feedback history, tune
#        history feeds `rag dashboard`, contradictions are audit).
#
# Tables explicitly NOT rotated (empty tuple): retained forever.
_SQL_ROTATION_POLICY: tuple[tuple[str, int], ...] = (
    ("rag_queries", 90),
    ("rag_behavior", 90),
    ("rag_ambient", 60),
    ("rag_brief_written", 60),
    ("rag_wa_tasks", 60),
    ("rag_archive_log", 60),
    ("rag_filing_log", 60),
    ("rag_eval_runs", 60),
    ("rag_surface_log", 60),
    ("rag_proactive_log", 60),
    ("rag_cpu_metrics", 30),
    ("rag_memory_metrics", 30),
    ("system_memory_metrics", 30),
    # Audit 2026-04-26 BUG #2 telemetry: estas tablas son creadas por
    # writers fuera de _TELEMETRY_DDL (rag_ranker_lgbm/synthetic_queries.py
    # + hard_negatives.py + wa_scheduled.py + obsidian-rag-promises fork).
    # Pre-fix crecían sin rotation — `rag_synthetic_negatives` ya tiene
    # ~3K rows. Estas son señales temporales del fine-tune y la auto-
    # tuning pipeline; rotation 90d es generosa.
    ("rag_synthetic_queries", 90),
    ("rag_synthetic_negatives", 90),
    ("rag_promises", 90),
    ("rag_whatsapp_scheduled", 30),
)

# Tables that upsert on a PK instead of appending log rows. Listed here both
# for the rollback DROP loop and as documentation of the no-rotate contract.
_SQL_STATE_TABLES: tuple[str, ...] = (
    "rag_ambient_state",
    "rag_brief_state",
    "rag_conversations_index",
    "rag_feedback_golden",
    "rag_feedback_golden_meta",
)

# Log-style tables that are kept forever (no rotation row). Auditable in
# `test_rotation_different_retentions_per_table` — their row count must not
# decrease after rotation.
_SQL_KEEP_ALL_TABLES: tuple[str, ...] = (
    "rag_feedback",
    "rag_tune",
    "rag_contradictions",
)

# VACUUM gate: page_count * page_size must exceed last_vacuum_size by this
# delta before we pay the cost. ~500 MB matches the T4 spec — VACUUM serialises
# the whole DB and should only run weekly at most.
_VACUUM_DELTA_BYTES = 500 * 1024 * 1024

# Key in rag_feedback_golden_meta for the last-vacuum sentinel. Reuses the
# existing meta table to avoid schema churn during the cutover; the key
# namespace ("vacuum_*") is disjoint from the feedback-golden keys.
_VACUUM_META_KEY_BYTES = "vacuum_last_bytes"
_VACUUM_META_KEY_TS = "vacuum_last_ts"


def _sql_rotate_log_tables(*, dry_run: bool = False,
                            now_ts: float | None = None) -> dict:
    """DELETE old rows from rotatable log tables + optionally VACUUM.

    Returns
    -------
    {
      "rows_deleted": {table: int, ...},
      "wal_checkpoint": {ok: bool, before_bytes: int, after_bytes: int},
      "vacuum_ran": bool,
      "vacuum_before_bytes": int | None,
      "vacuum_after_bytes": int | None,
    }

    Only touches rows matching the retention policy; state tables and
    keep-all tables are untouched. Safe under dry_run — no DELETE/VACUUM
    runs but the cutoff-derived counts are reported so operators can see
    what a live run would do.
    """
    import sqlite3 as _sqlite
    from datetime import datetime as _dt

    # Post 2026-04-21 split: rag_* log-style tables live in telemetry.db.
    sqlite_path = DB_PATH / _TELEMETRY_DB_FILENAME
    out: dict = {
        "rows_deleted": {},
        "wal_checkpoint": None,
        "vacuum_ran": False,
        "vacuum_before_bytes": None,
        "vacuum_after_bytes": None,
    }
    if not sqlite_path.is_file():
        out["skipped"] = "no sqlite file"
        return out

    # Use a dedicated connection — telemetry writers use short-lived conns
    # anyway, so briefly exclusive VACUUM can fight a writer. busy_timeout
    # is generous (30s) because rotation is unattended.
    now = now_ts if now_ts is not None else time.time()
    try:
        conn = _sqlite.connect(str(sqlite_path), timeout=30.0)
        conn.execute("PRAGMA busy_timeout=30000")
    except _sqlite.Error as e:
        out["skipped"] = f"connect failed: {e}"
        return out

    try:
        # Figure out which tables exist — skipping silently lets maintenance
        # run on a pre-T1 DB without crashing.
        existing = {
            r[0] for r in conn.execute(
                "SELECT name FROM sqlite_master WHERE type='table'"
            ).fetchall()
        }

        for table, days in _SQL_ROTATION_POLICY:
            if table not in existing:
                continue
            cutoff_iso = _dt.fromtimestamp(now - days * 86400).isoformat(
                timespec="seconds"
            )
            if dry_run:
                row = conn.execute(
                    f"SELECT COUNT(*) FROM {table} WHERE ts < ?", (cutoff_iso,)
                ).fetchone()
                out["rows_deleted"][table] = int(row[0] if row else 0)
            else:
                cur = conn.execute(
                    f"DELETE FROM {table} WHERE ts < ?", (cutoff_iso,)
                )
                out["rows_deleted"][table] = cur.rowcount or 0

        if not dry_run:
            conn.commit()

        # WAL checkpoint once after all deletes — cheaper than N checkpoints.
        # Post-split: telemetry.db-wal (not ragvec.db-wal).
        wal_path = DB_PATH / (_TELEMETRY_DB_FILENAME + "-wal")
        before_wal = sqlite_path.stat().st_size + (
            wal_path.stat().st_size if wal_path.is_file() else 0
        )
        if not dry_run:
            try:
                conn.execute("PRAGMA wal_checkpoint(TRUNCATE)")
                conn.commit()
                after_wal = sqlite_path.stat().st_size + (
                    wal_path.stat().st_size if wal_path.is_file() else 0
                )
                out["wal_checkpoint"] = {
                    "ok": True,
                    "before_bytes": before_wal,
                    "after_bytes": after_wal,
                }
            except _sqlite.Error as e:
                out["wal_checkpoint"] = {"ok": False, "reason": str(e)}
        else:
            out["wal_checkpoint"] = {
                "ok": True,
                "before_bytes": before_wal,
                "after_bytes": before_wal,
                "dry_run": True,
            }

        # Conditional VACUUM — gated by delta since last vacuum.
        page_count = int(conn.execute("PRAGMA page_count").fetchone()[0])
        page_size = int(conn.execute("PRAGMA page_size").fetchone()[0])
        current_bytes = page_count * page_size
        last_bytes_row = None
        if "rag_feedback_golden_meta" in existing:
            last_bytes_row = conn.execute(
                "SELECT v FROM rag_feedback_golden_meta WHERE k=?",
                (_VACUUM_META_KEY_BYTES,),
            ).fetchone()
        last_bytes = int(last_bytes_row[0]) if last_bytes_row and last_bytes_row[0] else 0
        delta = current_bytes - last_bytes
        should_vacuum = delta >= _VACUUM_DELTA_BYTES

        if should_vacuum and not dry_run:
            out["vacuum_before_bytes"] = current_bytes
            # VACUUM can't run inside a transaction.
            conn.isolation_level = None
            conn.execute("VACUUM")
            new_page_count = int(conn.execute("PRAGMA page_count").fetchone()[0])
            new_page_size = int(conn.execute("PRAGMA page_size").fetchone()[0])
            new_bytes = new_page_count * new_page_size
            out["vacuum_ran"] = True
            out["vacuum_after_bytes"] = new_bytes
            # Persist sentinel so we don't VACUUM again until another delta.
            if "rag_feedback_golden_meta" in existing:
                now_iso = _dt.fromtimestamp(now).isoformat(timespec="seconds")
                conn.execute(
                    "INSERT OR REPLACE INTO rag_feedback_golden_meta (k, v) VALUES (?, ?)",
                    (_VACUUM_META_KEY_BYTES, str(new_bytes)),
                )
                conn.execute(
                    "INSERT OR REPLACE INTO rag_feedback_golden_meta (k, v) VALUES (?, ?)",
                    (_VACUUM_META_KEY_TS, now_iso),
                )
                conn.commit()
        elif should_vacuum and dry_run:
            out["vacuum_ran"] = False
            out["vacuum_would_run"] = True
            out["vacuum_before_bytes"] = current_bytes
    finally:
        try:
            conn.close()
        except Exception:
            pass
    return out


def _cleanup_bak_files(*, dry_run: bool = False,
                        max_age_days: int = 30,
                        now_ts: float | None = None) -> dict:
    """Delete migration-era `*.bak.<unix_ts>` files older than max_age_days.

    T2's migration script renames each legacy source to `name.bak.<unix_ts>`.
    After the 30-day cutover observation window the originals are unneeded
    and just waste disk. We parse the unix ts suffix directly rather than
    stat — the filename IS the canonical migration time, stat.mtime can drift
    under rsync/iCloud/etc.

    Filenames that don't match `*.bak.<digits>` are ignored (including
    legacy `.bak`, `.bak.notanumber`, or user-created `.baktemp`).

    Returns
    -------
    {"deleted": int, "bytes_freed": int, "skipped_non_bak": int}
    """
    state_dir = Path.home() / ".local/share/obsidian-rag"
    out = {"deleted": 0, "bytes_freed": 0, "skipped_non_bak": 0}
    if not state_dir.is_dir():
        return out
    now = now_ts if now_ts is not None else time.time()
    cutoff = now - max_age_days * 86400
    for f in state_dir.iterdir():
        if not f.is_file():
            continue
        # Must match .*\.bak\.<digits>$
        name = f.name
        try:
            idx = name.rindex(".bak.")
        except ValueError:
            continue
        suffix = name[idx + len(".bak."):]
        if not suffix.isdigit():
            out["skipped_non_bak"] += 1
            continue
        try:
            file_ts = int(suffix)
        except ValueError:
            out["skipped_non_bak"] += 1
            continue
        if file_ts >= cutoff:
            continue  # still fresh
        try:
            size = f.stat().st_size
        except OSError:
            size = 0
        if dry_run:
            out["deleted"] += 1
            out["bytes_freed"] += size
        else:
            try:
                os.unlink(f)
                out["deleted"] += 1
                out["bytes_freed"] += size
            except OSError:
                continue
    return out


# ── Rollback subcommand helpers (T7) ─────────────────────────────────────────
# `rag maintenance --rollback-state-migration` restores the JSONL baseline
# in case the SQL cutover misbehaves within the 30-day observation window.
# The inverse of T2's migration: rename each `name.bak.<ts>` back to `name`,
# drop every rag_*/system_memory_metrics table, remove the schema_version
# rows, checkpoint the WAL + VACUUM.
#
# Safety: refuses to run when `com.fer.obsidian-rag-*` launchd services have
# live pids — a writer mid-transaction against a table we're about to drop
# would cause data loss. `--force` bypasses the service check and the no-bak
# refusal; it is NOT a free pass for the DROP TABLE loop which always runs.

_ROLLBACK_TABLES: tuple[str, ...] = tuple(
    name for name, _ in _TELEMETRY_DDL
)


def _pgrep_obsidian_rag() -> list[str]:
    """Return list of pids matching `com.fer.obsidian-rag` launchd services.

    Same logic as scripts/migrate_state_to_sqlite.py::_check_running_services
    but inlined here so maintenance doesn't import the migration script.
    """
    import subprocess as _sp
    try:
        out = _sp.run(
            ["pgrep", "-f", "com.fer.obsidian-rag"],
            capture_output=True, text=True, timeout=5,
        )
    except (_sp.TimeoutExpired, FileNotFoundError):
        return []
    if out.returncode != 0:
        return []
    return [line for line in out.stdout.split() if line.strip()]


def _find_bak_files_for_rollback(*, max_age_days: int = 30,
                                  now_ts: float | None = None) -> dict[str, Path]:
    """Scan state_dir for `.bak.<ts>` files newer than max_age_days.

    Returns a {original_path_as_str → newest_bak_path} mapping so the caller
    restores exactly one bak per source. When multiple baks exist (e.g. a
    user re-ran the migration twice) the most recent ts wins — the oldest
    baks represent an intermediate state we don't want to revert to.
    """
    state_dir = Path.home() / ".local/share/obsidian-rag"
    if not state_dir.is_dir():
        return {}
    now = now_ts if now_ts is not None else time.time()
    cutoff = now - max_age_days * 86400
    # source_path → (ts, bak_path) to pick newest-wins
    best: dict[str, tuple[int, Path]] = {}
    for f in state_dir.iterdir():
        if not f.is_file():
            continue
        name = f.name
        try:
            idx = name.rindex(".bak.")
        except ValueError:
            continue
        suffix = name[idx + len(".bak."):]
        if not suffix.isdigit():
            continue
        try:
            file_ts = int(suffix)
        except ValueError:
            continue
        if file_ts < cutoff:
            continue  # older than window — nothing to restore to
        original_name = name[:idx]
        prev = best.get(original_name)
        if prev is None or file_ts > prev[0]:
            best[original_name] = (file_ts, f)
    return {orig: p for orig, (_, p) in best.items()}


def _rollback_state_migration(*, force: bool = False,
                               now_ts: float | None = None) -> dict:
    """Restore .bak.<ts> originals + drop rag_* tables.

    Returns
    -------
    {
      "ok": bool,
      "refused": str | None,                # human reason, if refused
      "files_restored": int,
      "tables_dropped": list[str],
      "bytes_reclaimed": int,
      "wal_checkpoint": dict,
      "vacuum_before_bytes": int,
      "vacuum_after_bytes": int,
    }
    """
    import sqlite3 as _sqlite

    out: dict = {
        "ok": False,
        "refused": None,
        "files_restored": 0,
        "tables_dropped": [],
        "bytes_reclaimed": 0,
        "wal_checkpoint": None,
        "vacuum_before_bytes": None,
        "vacuum_after_bytes": None,
    }

    # 1. Preflight — services must be stopped.
    pids = _pgrep_obsidian_rag()
    if pids and not force:
        out["refused"] = (
            f"pgrep matched {len(pids)} com.fer.obsidian-rag pid(s): "
            f"{' '.join(pids)}. Stop launchd services or pass --force."
        )
        return out

    # 2. Preflight — at least one .bak.<ts> within the 30-day window must
    # exist, otherwise we're restoring nothing and DROPs would be lossy.
    bak_map = _find_bak_files_for_rollback(now_ts=now_ts)
    if not bak_map and not force:
        out["refused"] = (
            "No *.bak.<unix_ts> files found within the 30-day window. "
            "Nothing to restore to — pass --force to DROP tables anyway."
        )
        return out

    state_dir = Path.home() / ".local/share/obsidian-rag"

    # 3. Restore files. os.replace is atomic; if the original still exists
    # it's overwritten (expected — T3 writers may have been running in
    # dual-write mode or before the flag was flipped off).
    for original_name, bak_path in bak_map.items():
        dest = state_dir / original_name
        try:
            os.replace(bak_path, dest)
            out["files_restored"] += 1
        except OSError as e:
            _log_sql_state_error("rollback_restore_failed",
                                  src=str(bak_path), dst=str(dest), err=repr(e))

    # 4. DROP rag_* tables in one transaction + clear schema_version rows.
    # Post 2026-04-21 split: rag_* tables now live in telemetry.db, not
    # ragvec.db. Rollback drops from the new file. If the operator is
    # rolling back to a pre-split checkpoint they should `git revert`
    # first (per CLAUDE.md rollback procedure), which restores the old
    # code that re-reads ragvec.db.
    sqlite_path = DB_PATH / _TELEMETRY_DB_FILENAME
    if sqlite_path.is_file():
        wal_path = DB_PATH / (_TELEMETRY_DB_FILENAME + "-wal")
        before_bytes = sqlite_path.stat().st_size + (
            wal_path.stat().st_size if wal_path.is_file() else 0
        )
        try:
            conn = _sqlite.connect(str(sqlite_path), timeout=30.0)
            conn.execute("PRAGMA busy_timeout=30000")
        except _sqlite.Error as e:
            out["refused"] = f"connect failed: {e}"
            return out
        try:
            existing = {
                r[0] for r in conn.execute(
                    "SELECT name FROM sqlite_master WHERE type='table'"
                ).fetchall()
            }
            conn.execute("BEGIN")
            dropped: list[str] = []
            for t in _ROLLBACK_TABLES:
                if t in existing:
                    conn.execute(f"DROP TABLE IF EXISTS {t}")
                    dropped.append(t)
            # Remove schema_version entries for the dropped tables.
            if "rag_schema_version" in existing and dropped:
                conn.executemany(
                    "DELETE FROM rag_schema_version WHERE table_name=?",
                    [(t,) for t in dropped],
                )
            conn.execute("COMMIT")
            out["tables_dropped"] = dropped

            # Checkpoint + VACUUM to reclaim pages. VACUUM rebuilds the db
            # file so the tables actually release their pages (DROP alone
            # only marks pages as free).
            conn.execute("PRAGMA wal_checkpoint(TRUNCATE)")
            conn.commit()
            # Sentinel: re-read size BEFORE vacuum so the reclaim metric
            # reflects the DROP+VACUUM combo, not just WAL truncation.
            out["vacuum_before_bytes"] = sqlite_path.stat().st_size
            conn.isolation_level = None
            conn.execute("VACUUM")
            out["vacuum_after_bytes"] = sqlite_path.stat().st_size
            out["wal_checkpoint"] = {"ok": True,
                                       "before_bytes": before_bytes,
                                       "after_bytes": sqlite_path.stat().st_size}
        except _sqlite.Error as e:
            try:
                conn.execute("ROLLBACK")
            except Exception:
                pass
            out["refused"] = f"sqlite error: {e}"
            return out
        finally:
            try:
                conn.close()
            except Exception:
                pass
        after_bytes = sqlite_path.stat().st_size + (
            wal_path.stat().st_size if wal_path.is_file() else 0
        )
        out["bytes_reclaimed"] = max(0, before_bytes - after_bytes)

    out["ok"] = True
    return out


# ── `rag free` — cleanup de bloat sin romper ─────────────────────────────────
# Cuatro categorias, cada una gateada por sanity checks independientes:
#   (a) Tablas legacy en ragvec.db que ya viven (con mas filas) en telemetry.db.
#       La sanity gate es `telemetry.count >= ragvec.count` por tabla. Si
#       ragvec.db quedo con mas filas (caso extremo tras un crash), se marca
#       `warn` y NO se dropea — preservar data > recuperar espacio.
#   (b) `.bak.<unix_ts>` mas viejos que min_age_days (default 30d). Son los
#       backups de T10 (1776624525 ≈ 2026-04-20) que quedaron congelados.
#   (c) Logs `.archived*` mas viejos que min_age_days (mtime).
#   (d) Snapshots `ranker.<ts>.<pid>.json` — retener los N mas nuevos (default 3)
#       para poder rollback; el resto es candidato. `ranker.json` vivo NUNCA
#       se toca (no tiene ts en el nombre).
#
# Safety:
#   - Whitelist implicito: solo tablas en `_TELEMETRY_DDL` (= `_ROLLBACK_TABLES`).
#     Las 4 state tables cross-source (`rag_whatsapp_state` etc) NO estan ahi y
#     sobreviven. `meta_*`, `vec_*`, `obsidian_*` ni siquiera se consideran.
#   - Preflight: refusa si `com.fer.obsidian-rag-*` launchd services vivos
#     (bypass con --force).
#   - Dry-run por default. `--apply --yes` para ejecutar.
#   - DROP en transaction + VACUUM fuera.

_RAG_FREE_MIN_AGE_DAYS_DEFAULT = 30
_RAG_FREE_RANKER_KEEP_DEFAULT = 3


def _rag_free_plan_tables() -> list[dict]:
    """Inventario de tablas legacy en ragvec.db comparadas con telemetry.db.

    Returns list of {table, ragvec_count, telemetry_count, status}. `status`
    is "safe" (telemetry >= ragvec, OK to drop) or "warn" (ragvec ahead —
    blocks the drop). Solo considera tablas en `_TELEMETRY_DDL`.
    """
    import sqlite3 as _sqlite3
    ragvec_path = DB_PATH / "ragvec.db"
    telemetry_path = DB_PATH / _TELEMETRY_DB_FILENAME
    if not ragvec_path.is_file():
        return []
    out: list[dict] = []
    rc = _sqlite3.connect(str(ragvec_path))
    tc = None
    try:
        ragvec_tables = {
            r[0] for r in rc.execute(
                "SELECT name FROM sqlite_master WHERE type='table'"
            ).fetchall()
        }
        if telemetry_path.is_file():
            tc = _sqlite3.connect(str(telemetry_path))
            telemetry_tables = {
                r[0] for r in tc.execute(
                    "SELECT name FROM sqlite_master WHERE type='table'"
                ).fetchall()
            }
        else:
            telemetry_tables = set()
        for t in _ROLLBACK_TABLES:
            if t not in ragvec_tables:
                continue
            try:
                ragvec_count = rc.execute(
                    f"SELECT COUNT(*) FROM {t}"
                ).fetchone()[0]
            except Exception:
                continue
            if tc is not None and t in telemetry_tables:
                try:
                    telemetry_count = tc.execute(
                        f"SELECT COUNT(*) FROM {t}"
                    ).fetchone()[0]
                except Exception:
                    telemetry_count = 0
            else:
                telemetry_count = 0
            status = "safe" if telemetry_count >= ragvec_count else "warn"
            out.append({
                "table": t,
                "ragvec_count": ragvec_count,
                "telemetry_count": telemetry_count,
                "status": status,
            })
    finally:
        try:
            rc.close()
        except Exception:
            pass
        if tc is not None:
            try:
                tc.close()
            except Exception:
                pass
    return out


def _rag_free_plan_baks(
    *,
    min_age_days: int = _RAG_FREE_MIN_AGE_DAYS_DEFAULT,
    now_ts: float | None = None,
    state_dir: Path | None = None,
) -> list[dict]:
    """`.bak.<unix_ts>` con ts del nombre mas viejo que min_age_days."""
    state_dir = state_dir or (Path.home() / ".local/share/obsidian-rag")
    if not state_dir.is_dir():
        return []
    now = now_ts if now_ts is not None else time.time()
    cutoff = now - min_age_days * 86400
    out: list[dict] = []
    for f in state_dir.iterdir():
        if not f.is_file():
            continue
        name = f.name
        try:
            idx = name.rindex(".bak.")
        except ValueError:
            continue
        suffix = name[idx + len(".bak."):]
        if not suffix.isdigit():
            continue
        try:
            file_ts = int(suffix)
        except ValueError:
            continue
        if file_ts > cutoff:
            continue  # mas nuevo que la ventana — todavia util
        try:
            size = f.stat().st_size
        except Exception:
            continue
        out.append({"path": f, "bytes": size, "ts": file_ts})
    return out


def _rag_free_plan_archived_logs(
    *,
    min_age_days: int = _RAG_FREE_MIN_AGE_DAYS_DEFAULT,
    now_ts: float | None = None,
    state_dir: Path | None = None,
) -> list[dict]:
    """Logs con `.archived` en el nombre y mtime > min_age_days."""
    state_dir = state_dir or (Path.home() / ".local/share/obsidian-rag")
    if not state_dir.is_dir():
        return []
    now = now_ts if now_ts is not None else time.time()
    cutoff = now - min_age_days * 86400
    out: list[dict] = []
    for f in state_dir.iterdir():
        if not f.is_file():
            continue
        if ".archived" not in f.name:
            continue
        try:
            st = f.stat()
        except Exception:
            continue
        if st.st_mtime > cutoff:
            continue
        out.append({"path": f, "bytes": st.st_size, "mtime": st.st_mtime})
    return out


def _rag_free_plan_ranker_snapshots(
    *,
    keep: int = _RAG_FREE_RANKER_KEEP_DEFAULT,
    state_dir: Path | None = None,
) -> list[dict]:
    """`ranker.<ts>.<pid>.json`: retiene los `keep` mas nuevos (por ts del
    nombre) para rollback; el resto es candidato. `ranker.json` vivo (sin
    ts) NUNCA es candidato — es el estado vigente del ranker-vivo.
    """
    state_dir = state_dir or (Path.home() / ".local/share/obsidian-rag")
    if not state_dir.is_dir():
        return []
    pat = re.compile(r"^ranker\.(\d+)\.\d+\.json$")
    entries: list[dict] = []
    for f in state_dir.iterdir():
        if not f.is_file():
            continue
        m = pat.match(f.name)
        if not m:
            continue
        try:
            ts = int(m.group(1))
            size = f.stat().st_size
        except Exception:
            continue
        entries.append({"path": f, "bytes": size, "ts": ts})
    # Mas nuevo primero; el exceso a partir del indice `keep` son candidatos.
    entries.sort(key=lambda e: e["ts"], reverse=True)
    return entries[keep:]


def _rag_free_execute(
    *,
    plan_tables: list[dict],
    plan_baks: list[dict],
    plan_logs: list[dict],
    plan_ranker: list[dict],
) -> dict:
    """Aplica el plan. DROP+VACUUM la DB, unlink() los archivos.

    Retorna {tables_dropped, files_removed, bytes_reclaimed_files,
    bytes_reclaimed_db, errors}.
    """
    import sqlite3 as _sqlite3
    out: dict = {
        "tables_dropped": [],
        "files_removed": [],
        "bytes_reclaimed_files": 0,
        "bytes_reclaimed_db": 0,
        "errors": [],
    }

    # 1. DROP tablas safe en ragvec.db
    safe_tables = [t["table"] for t in plan_tables if t["status"] == "safe"]
    if safe_tables:
        ragvec_path = DB_PATH / "ragvec.db"
        wal_path = DB_PATH / "ragvec.db-wal"
        before_bytes = 0
        if ragvec_path.is_file():
            before_bytes = ragvec_path.stat().st_size + (
                wal_path.stat().st_size if wal_path.is_file() else 0
            )
        conn = _sqlite3.connect(str(ragvec_path), isolation_level=None)
        try:
            conn.execute("PRAGMA journal_mode=WAL")
            conn.execute("BEGIN")
            for t in safe_tables:
                try:
                    conn.execute(f"DROP TABLE IF EXISTS {t}")
                    out["tables_dropped"].append(t)
                except Exception as e:
                    out["errors"].append(f"drop {t}: {e}")
            # Tambien limpiamos filas de rag_schema_version para las tablas
            # dropeadas — sin esto, futuras invocaciones de
            # `_ensure_telemetry_tables()` en ragvec.db re-crearian tablas
            # vacias (no lo hacen post-T10, pero defensive).
            if out["tables_dropped"]:
                placeholders = ",".join("?" for _ in out["tables_dropped"])
                conn.execute(
                    f"DELETE FROM rag_schema_version "
                    f"WHERE table_name IN ({placeholders})",
                    out["tables_dropped"],
                )
            conn.execute("COMMIT")
        except Exception as e:
            try:
                conn.execute("ROLLBACK")
            except Exception:
                pass
            out["errors"].append(f"transaction: {e}")
        finally:
            try:
                conn.close()
            except Exception:
                pass
        # VACUUM fuera de la transaction
        try:
            conn = _sqlite3.connect(str(ragvec_path), isolation_level=None)
            try:
                conn.execute("PRAGMA wal_checkpoint(TRUNCATE)")
                conn.execute("VACUUM")
            finally:
                conn.close()
        except Exception as e:
            out["errors"].append(f"vacuum: {e}")
        if ragvec_path.is_file():
            after_bytes = ragvec_path.stat().st_size + (
                wal_path.stat().st_size if wal_path.is_file() else 0
            )
            out["bytes_reclaimed_db"] = max(0, before_bytes - after_bytes)

    # 2. Borrar archivos (.bak, .archived, ranker snapshots)
    for entry in plan_baks + plan_logs + plan_ranker:
        p: Path = entry["path"]
        try:
            size = p.stat().st_size if p.is_file() else 0
            p.unlink()
            out["files_removed"].append(str(p))
            out["bytes_reclaimed_files"] += size
        except Exception as e:
            out["errors"].append(f"unlink {p}: {e}")

    return out


def run_maintenance(
    *,
    dry_run: bool = False,
    skip_reindex: bool = False,
    skip_logs: bool = False,
    verbose: bool = False,
) -> dict:
    """Run all maintenance tasks. Returns summary dict."""
    import time as _t
    t0 = _t.perf_counter()
    results: dict = {}

    # 1. Incremental reindex (cleans orphan chunks too)
    if not skip_reindex and not dry_run:
        try:
            idx = auto_index_vault(VAULT_PATH)
            results["reindex"] = idx
        except Exception as e:
            results["reindex_error"] = str(e)

    # 2. Session cleanup
    removed_sessions = cleanup_sessions()
    results["sessions_removed"] = removed_sessions

    # 3. Orphan collections
    orphan_cols = _find_orphan_collections()
    results["orphan_collections"] = orphan_cols
    if orphan_cols and not dry_run:
        with _collection_write_lock():
            client = SqliteVecClient(path=str(DB_PATH))
            for cname in orphan_cols:
                try:
                    _log_collection_op("delete", cname, {"reason": "run_maintenance orphan"})
                    client.delete_collection(cname)
                except Exception:
                    pass
        results["orphan_collections_removed"] = len(orphan_cols)

    # 3b. Orphan segment dirs stub (sqlite-vec stores all data in ragvec.db; no dirs)
    try:
        results["orphan_segments"] = _prune_orphan_segment_dirs(dry_run=dry_run)
    except Exception as e:
        results["orphan_segments_error"] = str(e)

    # 3c. WAL checkpoint — post-split we have two files with two WALs.
    # ragvec.db-wal compacts here; telemetry.db-wal compacts inside
    # _sql_rotate_log_tables (step 8) so it's always covered when logs
    # run, and we also fire an unconditional telemetry checkpoint below
    # so --skip-logs doesn't starve it.
    try:
        results["wal_checkpoint"] = _vec_wal_checkpoint(dry_run=dry_run)
    except Exception as e:
        results["wal_checkpoint_error"] = str(e)
    try:
        results["wal_checkpoint_telemetry"] = _telemetry_wal_checkpoint(dry_run=dry_run)
    except Exception as e:
        results["wal_checkpoint_telemetry_error"] = str(e)

    # 4. Context cache pruning
    try:
        col = get_db()
        if dry_run:
            cache = _load_context_cache()
            sq_cache = _load_synthetic_q_cache()
            existing = col.get(include=["metadatas"])
            live_hashes = {m.get("hash", "") for m in existing["metadatas"]} - {""}
            results["context_cache_pruned"] = sum(1 for k in cache if k not in live_hashes)
            results["synthetic_q_cache_pruned"] = sum(1 for k in sq_cache if k not in live_hashes)
        else:
            pruned = _prune_context_cache(col)
            results["context_cache_pruned"] = pruned
            pruned_sq = _prune_synthetic_q_cache(col)
            results["synthetic_q_cache_pruned"] = pruned_sq
    except Exception as e:
        results["context_cache_error"] = str(e)

    # 5. Feedback golden rebuild (SQL-only since T10).
    if not dry_run:
        try:
            with _ragvec_state_conn() as conn:
                golden = _rebuild_feedback_golden_from_sql_feedback(conn)
            results["feedback_golden"] = {
                "positives": len(golden.get("positives", [])),
                "negatives": len(golden.get("negatives", [])),
            }
        except Exception as e:
            results["feedback_golden_error"] = str(e)

    # 6. Log rotation.
    # When RAG_STATE_SQL=1 the JSONL files are no-longer written (T3 swap),
    # so we run SQL-aware rotation against the rag_* tables + clean up the
    # one-shot `.bak.<ts>` migration artefacts. When the flag is off we keep
    # the legacy JSONL rotation path unchanged.
    if not skip_logs:
        if RAG_STATE_SQL:
            # Audit 2026-04-26 (BUG #22): force re-ensure DDL antes de
            # rotation. Daemons long-lived no veían nuevos `_migrate_*`
            # del código → ALTERs nunca corrían.
            try:
                with _TELEMETRY_DDL_LOCK:
                    _TELEMETRY_DDL_ENSURED_PATHS.clear()
                results["ddl_re_ensured"] = True
            except Exception as e:
                results["ddl_re_ensure_error"] = str(e)
            try:
                results["sql_rotation"] = _sql_rotate_log_tables(dry_run=dry_run)
            except Exception as e:
                results["sql_rotation_error"] = str(e)
            try:
                results["bak_cleanup"] = _cleanup_bak_files(dry_run=dry_run)
            except Exception as e:
                results["bak_cleanup_error"] = str(e)
            # Keep JSONL rotation section empty for renderer compatibility so
            # downstream callers that already branch on "log_rotation" don't
            # explode when the flag is on.
            results["log_rotation"] = {}
        else:
            rotated = {}
            for label, path in _JSONL_LOG_PATHS:
                if dry_run:
                    try:
                        sz = path.stat().st_size if path.is_file() else 0
                        if sz >= _JSONL_ROTATE_BYTES:
                            rotated[label] = f"would rotate ({sz / 1024:.0f} KB)"
                    except OSError:
                        pass
                else:
                    r = _rotate_jsonl(path)
                    if r:
                        rotated[label] = r
            results["log_rotation"] = rotated

    # 7. Ignored notes orphans
    if dry_run:
        ign = load_ignored_paths()
        results["ignored_pruned"] = sum(1 for p in ign if not (VAULT_PATH / p).exists())
    else:
        results["ignored_pruned"] = _prune_ignored_notes(VAULT_PATH)

    # 8. Auto-index state orphans
    if dry_run:
        st = _auto_index_state_load()
        valid = {_vault_state_key(VAULT_PATH)}
        try:
            vcfg = _load_vaults_config()
            for vp in vcfg["vaults"].values():
                valid.add(_vault_state_key(Path(vp)))
        except Exception:
            pass
        results["index_state_pruned"] = sum(1 for k in st if k not in valid)
    else:
        results["index_state_pruned"] = _prune_auto_index_state()

    # 9. Filing batch pruning (>90d)
    if dry_run:
        cutoff = _t.time() - _FILING_BATCH_TTL_DAYS * 86400
        results["batches_pruned"] = sum(
            1 for f in (FILING_BATCHES_DIR.glob("*.jsonl") if FILING_BATCHES_DIR.is_dir() else [])
            if f.stat().st_mtime < cutoff
        )
    else:
        results["batches_pruned"] = _prune_filing_batches()

    # 10. Tmp file cleanup
    if dry_run:
        state_dir = Path.home() / ".local/share/obsidian-rag"
        n_tmp = 0
        for d in (state_dir, SESSIONS_DIR):
            if d.is_dir():
                n_tmp += sum(1 for t in d.glob("*.tmp") if _t.time() - t.stat().st_mtime > 3600)
        results["tmp_cleaned"] = n_tmp
    else:
        results["tmp_cleaned"] = _cleanup_tmp_files()

    # 10c. Voice brief audios TTL cleanup (Anticipatory Phase 2.C, 2026-04-29).
    # Los audios morning/today se cachean en
    # ``~/.local/share/obsidian-rag/voice_briefs/`` con naming
    # ``YYYY-MM-DD-<kind>.ogg``. Sin TTL ese dir crece sin bound. El
    # texto en el vault (`reviews/<date>.md`) es la fuente de verdad
    # histórica; el audio es transiente y se regenera on-demand con
    # ``rag voice-brief generate --date YYYY-MM-DD``. Default 30 días.
    if dry_run:
        try:
            from rag.voice_brief import get_voice_brief_dir as _gvbd  # noqa: PLC0415
            vb_dir = _gvbd()
            ttl_days = int(os.environ.get("RAG_VOICE_BRIEF_TTL_DAYS", "30"))
            cutoff = _t.time() - ttl_days * 86400
            n_vb = 0
            bytes_vb = 0
            if vb_dir.is_dir():
                for f in vb_dir.iterdir():
                    if not f.is_file():
                        continue
                    try:
                        if f.stat().st_mtime < cutoff:
                            n_vb += 1
                            bytes_vb += f.stat().st_size
                    except OSError:
                        continue
            results["voice_briefs_cleaned"] = {
                "deleted": n_vb, "bytes_freed": bytes_vb, "errors": [],
            }
        except Exception as e:
            results["voice_briefs_cleaned_error"] = str(e)
    else:
        try:
            from rag.voice_brief import cleanup_old_voice_briefs as _cobv  # noqa: PLC0415
            results["voice_briefs_cleaned"] = _cobv()
        except Exception as e:
            results["voice_briefs_cleaned_error"] = str(e)

    # 10b. Chat-uploads TTL cleanup (audit 2026-04-25 R2-Security #6).
    # Las imágenes que el user sube via /api/chat/upload-image quedan en
    # ~/.local/share/obsidian-rag/chat-uploads/ con naming hash-based;
    # sin TTL ese dir crece sin bound. Defensive try/except: si algo
    # explota acá, el resto de la maintenance sigue.
    if dry_run:
        upload_dir = Path.home() / ".local/share/obsidian-rag/chat-uploads"
        ttl_days = int(os.environ.get("RAG_CHAT_UPLOADS_TTL_DAYS", "30"))
        cutoff = _t.time() - ttl_days * 86400
        n_up = 0
        bytes_up = 0
        if upload_dir.is_dir():
            for f in upload_dir.iterdir():
                if not f.is_file():
                    continue
                try:
                    if f.stat().st_mtime < cutoff:
                        n_up += 1
                        bytes_up += f.stat().st_size
                except OSError:
                    continue
        results["chat_uploads_cleaned"] = {
            "deleted": n_up, "bytes_freed": bytes_up, "errors": [],
        }
    else:
        try:
            results["chat_uploads_cleaned"] = _cleanup_chat_uploads()
        except Exception as e:
            results["chat_uploads_cleaned_error"] = str(e)

    # 11. URL orphans (files deleted but URL rows remain)
    if dry_run:
        try:
            cu = get_urls_db()
            all_u = cu.get(include=["metadatas"])
            od = {
                str(p.relative_to(VAULT_PATH))
                for p in VAULT_PATH.rglob("*.md")
                if not is_excluded(str(p.relative_to(VAULT_PATH)))
            }
            results["url_orphans"] = sum(
                1 for m in all_u["metadatas"] if m.get("file", "") not in od
            )
        except Exception:
            results["url_orphans"] = 0
    else:
        results["url_orphans"] = _prune_url_orphans(VAULT_PATH)

    # 12. Feedback orphans (paths no longer in vault)
    if dry_run:
        try:
            od = {
                str(p.relative_to(VAULT_PATH))
                for p in VAULT_PATH.rglob("*.md")
                if not is_excluded(str(p.relative_to(VAULT_PATH)))
            }
            n_fb_orphan = 0
            if FEEDBACK_PATH.is_file():
                for line in FEEDBACK_PATH.read_text(encoding="utf-8").splitlines():
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        ev = json.loads(line)
                    except Exception:
                        continue
                    paths = ev.get("paths") or []
                    if paths and not any(p in od for p in paths):
                        n_fb_orphan += 1
            results["feedback_orphans"] = n_fb_orphan
        except Exception:
            results["feedback_orphans"] = 0
    else:
        results["feedback_orphans"] = _prune_feedback_orphans(VAULT_PATH)

    # 13. Ollama health (read-only)
    results["ollama"] = _check_ollama_health()

    # 14. Dead notes count (read-only)
    try:
        col = get_db()
        dead = find_dead_notes(col, VAULT_PATH, LOG_PATH)
        results["dead_notes"] = len(dead)
    except Exception:
        results["dead_notes"] = 0

    results["took_ms"] = int((_t.perf_counter() - t0) * 1000)
    return results


# ── Cutover validation (T10 pre-strip gate) ──────────────────────────────────
# Before T10 flips RAG_STATE_SQL to default-on + strips the JSONL fallback,
# we want a read-only way to verify every source migrated cleanly. The
# migration script renames each JSONL to <name>.bak.<unix_ts> on success;
# this helper walks the SOURCES map and compares SQL COUNT(*) vs JSONL
# line count. SQL ≥ JSONL = OK (post-cutover activity accumulated on top).
# SQL < JSONL = FAIL (lost rows — abort the strip).

_CUTOVER_SOURCES: tuple[tuple[str, str], ...] = (
    # (jsonl_filename, sql_table)
    ("queries.jsonl", "rag_queries"),
    ("behavior.jsonl", "rag_behavior"),
    ("feedback.jsonl", "rag_feedback"),
    ("tune.jsonl", "rag_tune"),
    ("contradictions.jsonl", "rag_contradictions"),
    ("ambient.jsonl", "rag_ambient"),
    ("brief_written.jsonl", "rag_brief_written"),
    ("wa_tasks.jsonl", "rag_wa_tasks"),
    ("archive.jsonl", "rag_archive_log"),
    ("filing.jsonl", "rag_filing_log"),
    ("eval.jsonl", "rag_eval_runs"),
    ("surface.jsonl", "rag_surface_log"),
    ("proactive.jsonl", "rag_proactive_log"),
    ("rag_cpu.jsonl", "rag_cpu_metrics"),
    ("rag_memory.jsonl", "rag_memory_metrics"),
    # state_latest_jsonl sources (upsert-style: SQL rows ≤ JSONL lines
    # because repeated keys collapse on write). WARN if SQL < unique-key
    # count, don't fail on raw count mismatch.
    ("ambient_state.jsonl", "rag_ambient_state"),
    ("brief_state.jsonl", "rag_brief_state"),
)


def _count_jsonl_lines(path: Path) -> int:
    """Count non-blank lines in a JSONL. Tolerates missing file → 0."""
    if not path.is_file():
        return 0
    try:
        with path.open("rb") as f:
            # Binary read avoids decoding a giant log we only want to
            # line-count. Filter blanks so trailing newline doesn't add 1.
            return sum(1 for line in f if line.strip())
    except OSError:
        return 0


def _validate_cutover_state() -> list[dict]:
    """Read-only audit comparing SQL row counts vs source JSONL line counts.

    For each (jsonl, table) in _CUTOVER_SOURCES:
      1. Find the newest <jsonl>.bak.<ts> in ~/.local/share/obsidian-rag/.
      2. Count lines in it.
      3. Run `SELECT COUNT(*) FROM <table>` in ragvec.db.
      4. Compute delta_pct = (sql - bak) / bak * 100 (0 if bak empty).
      5. status: "ok" if sql >= bak, "warn" if sql within -1% of bak,
         "fail" if sql < -1% of bak, "no_bak" if no .bak file exists.

    Returns a list of dicts; caller decides rendering and exit code.
    Never raises — individual source errors captured in the result.
    """
    state_dir = Path.home() / ".local/share/obsidian-rag"
    results: list[dict] = []
    for jsonl_name, table in _CUTOVER_SOURCES:
        entry: dict = {"source": jsonl_name, "table": table}
        # Find the newest .bak.<unix_ts>. sorted() is stable and the
        # unix timestamp suffix gives a chronological order.
        baks = sorted(state_dir.glob(f"{jsonl_name}.bak.*"))
        if not baks:
            entry.update({
                "status": "no_bak",
                "bak_lines": None,
                "sql_rows": None,
                "delta_pct": None,
            })
            results.append(entry)
            continue
        bak = baks[-1]
        bak_lines = _count_jsonl_lines(bak)
        # SQL count
        try:
            if not RAG_STATE_SQL:
                # Feature flag off = table either empty or never created.
                # Still report, but flag so the user knows why SQL=0.
                entry.update({
                    "status": "flag_off",
                    "bak_lines": bak_lines,
                    "sql_rows": None,
                    "delta_pct": None,
                    "bak_file": bak.name,
                })
                results.append(entry)
                continue
            with _ragvec_state_conn() as conn:
                row = conn.execute(
                    f"SELECT COUNT(*) FROM {table}"  # noqa: S608 - hardcoded table list
                ).fetchone()
                sql_rows = int(row[0]) if row else 0
        except Exception as exc:
            entry.update({
                "status": "sql_err",
                "err": repr(exc)[:200],
                "bak_lines": bak_lines,
                "sql_rows": None,
                "delta_pct": None,
                "bak_file": bak.name,
            })
            results.append(entry)
            continue
        delta_pct = ((sql_rows - bak_lines) / bak_lines * 100.0) if bak_lines else 0.0
        if sql_rows >= bak_lines:
            status = "ok"
        elif delta_pct >= -1.0:
            # Within 1% — tolerated (migration drops malformed rows; see
            # migrate_state_to_sqlite.py comments on 43 pre-existing bad
            # rows dropped during the 2026-04-19 cutover).
            status = "warn"
        else:
            status = "fail"
        entry.update({
            "status": status,
            "bak_lines": bak_lines,
            "sql_rows": sql_rows,
            "delta_pct": round(delta_pct, 2),
            "bak_file": bak.name,
        })
        results.append(entry)
    return results


def _render_cutover_validation(results: list[dict]) -> None:
    """Pretty-print the cutover validation table to the console."""
    console.print(Rule(title="[bold cyan]Cutover validation[/bold cyan]", style="cyan"))
    tbl = Table(show_lines=False)
    tbl.add_column("source", style="cyan", no_wrap=True)
    tbl.add_column("table", style="dim", no_wrap=True)
    tbl.add_column("bak lines", justify="right")
    tbl.add_column("SQL rows", justify="right")
    tbl.add_column("Δ%", justify="right")
    tbl.add_column("status", no_wrap=True)
    status_styles = {
        "ok": "green", "warn": "yellow", "fail": "red",
        "no_bak": "dim", "sql_err": "red", "flag_off": "dim yellow",
    }
    for r in results:
        status = r.get("status", "?")
        style = status_styles.get(status, "white")
        bak = r.get("bak_lines")
        sql = r.get("sql_rows")
        delta = r.get("delta_pct")
        tbl.add_row(
            r.get("source", "?"),
            r.get("table", "?"),
            "-" if bak is None else f"{bak:,}",
            "-" if sql is None else f"{sql:,}",
            "-" if delta is None else f"{delta:+.2f}%",
            f"[{style}]{status}[/{style}]",
        )
    console.print(tbl)
    fails = [r for r in results if r.get("status") == "fail"]
    warns = [r for r in results if r.get("status") == "warn"]
    if fails:
        console.print(
            f"[red]✗ {len(fails)} source(s) regressed — SQL has FEWER rows than "
            f"the .bak. DO NOT strip the JSONL fallback yet.[/red]"
        )
    elif warns:
        console.print(
            f"[yellow]⚠ {len(warns)} source(s) within 1% delta — acceptable "
            f"(migration drops malformed rows) but worth noting.[/yellow]"
        )
    else:
        console.print("[green]✓ All sources: SQL ≥ JSONL — safe to proceed with T10 strip.[/green]")


@cli.command()
@click.option("--dry-run", is_flag=True, help="Reportar sin modificar nada")
@click.option("--skip-reindex", is_flag=True, help="Saltear reindex incremental")
@click.option("--skip-logs", is_flag=True, help="Saltear rotación de logs")
@click.option("--verbose", "-v", is_flag=True, help="Mostrar detalles de cada paso")
@click.option("--json", "as_json", is_flag=True, help="Output JSON (para cron/scripts)")
@click.option("--rollback-state-migration", "rollback_state", is_flag=True,
               help="Escape hatch: restaurar .bak.<ts> originales + dropear rag_* tables (T7)")
@click.option("--validate-cutover", "validate_cutover", is_flag=True,
               help="Read-only: comparar COUNT(*) de cada rag_* table vs líneas en su .bak.<ts> (pre-T10 gate)")
@click.option("--force", is_flag=True,
               help="Bypass safety gates en --rollback-state-migration")
def maintenance(dry_run: bool, skip_reindex: bool, skip_logs: bool, verbose: bool,
                 as_json: bool, rollback_state: bool, validate_cutover: bool,
                 force: bool):
    """Mantenimiento integral: reindex, limpiar sesiones, podar caches, rotar logs, detectar dead notes.

    Seguro para correr periódicamente vía launchd/cron. Con --dry-run solo reporta.

    --rollback-state-migration deshace T2: renombra cada `.bak.<unix_ts>` a su
    nombre original + dropea las 21 rag_*/system_memory_metrics tables +
    VACUUM. Refuses si hay launchd services corriendo (usa --force para
    bypass) o si no hay .bak.<ts> dentro de la ventana de 30 días.

    --validate-cutover compara COUNT(*) de cada rag_* table con el line count
    del `.bak.<ts>` más reciente del JSONL que migró. Read-only, seguro en
    vivo. Propósito: gate pre-T10 — si algún delta es negativo (SQL < JSONL),
    significa que la migración perdió filas y NO se debe strippear el
    fallback. Útil en cron diario durante la ventana de observación.
    """
    if validate_cutover:
        results = _validate_cutover_state()
        if as_json:
            click.echo(json.dumps(results, ensure_ascii=False, indent=2))
            return
        _render_cutover_validation(results)
        # Non-zero exit if any source regressed (SQL < JSONL).
        if any(r.get("status") == "fail" for r in results):
            raise SystemExit(1)
        return
    if rollback_state:
        if not as_json:
            mode = "[yellow]DRY RUN[/yellow]" if dry_run else "[red]ROLLBACK[/red]"
            console.print(Rule(title=f"[bold cyan]State Migration Rollback[/bold cyan] {mode}",
                                style="cyan"))
            console.print()
        if dry_run:
            # Dry-run semantics: report what the rollback would touch without
            # renaming or dropping anything.
            pids = _pgrep_obsidian_rag()
            bak_map = _find_bak_files_for_rollback()
            summary = {
                "would_refuse": bool(pids and not force) or (not bak_map and not force),
                "running_pids": pids,
                "bak_files_found": len(bak_map),
                "tables_would_drop": [t for t in _ROLLBACK_TABLES],
            }
            if as_json:
                click.echo(json.dumps(summary, ensure_ascii=False, indent=2, default=str))
                return
            if summary["would_refuse"]:
                if pids and not force:
                    console.print(f"  [red]Refused:[/red] {len(pids)} launchd service(s) running — "
                                   "stop services or pass --force.")
                if not bak_map and not force:
                    console.print("  [red]Refused:[/red] no .bak.<unix_ts> files within 30-day window — "
                                   "nothing to restore to (pass --force to DROP anyway).")
            console.print(f"  [bold].bak.<ts> files:[/bold] {len(bak_map)} would be restored")
            console.print(f"  [bold]Tables would drop:[/bold] {len(summary['tables_would_drop'])}")
            return
        result = _rollback_state_migration(force=force)
        if as_json:
            click.echo(json.dumps(result, ensure_ascii=False, indent=2, default=str))
            return
        if not result["ok"]:
            console.print(f"  [red]Refused:[/red] {result.get('refused', 'unknown')}")
            raise click.exceptions.Exit(1)
        mb = result.get("bytes_reclaimed", 0) / (1024 * 1024)
        console.print(f"  [bold]Files restored:[/bold] {result['files_restored']}")
        console.print(f"  [bold]Tables dropped:[/bold] {len(result['tables_dropped'])}"
                       f" [dim]({', '.join(result['tables_dropped'][:4])}"
                       f"{', …' if len(result['tables_dropped']) > 4 else ''})[/dim]")
        console.print(f"  [bold]Disk reclaimed:[/bold] {mb:.1f} MB")
        return

    if not as_json:
        mode = "[yellow]DRY RUN[/yellow]" if dry_run else "[green]LIVE[/green]"
        console.print(Rule(title=f"[bold cyan]Maintenance[/bold cyan] {mode}", style="cyan"))
        console.print()

    results = run_maintenance(
        dry_run=dry_run,
        skip_reindex=skip_reindex,
        skip_logs=skip_logs,
        verbose=verbose,
    )

    if as_json:
        click.echo(json.dumps(results, ensure_ascii=False, indent=2, default=str))
        return

    # ── Reindex ──
    idx = results.get("reindex")
    if idx:
        kind = idx.get("kind", "?")
        color = {"no_changes": "dim", "incremental": "green", "first_time": "yellow"}.get(kind, "white")
        console.print(f"  [bold]Reindex:[/bold] [{color}]{kind}[/{color}]"
                      f" — {idx.get('indexed', 0)} indexed, {idx.get('removed', 0)} orphans removed"
                      f" [dim]({idx.get('scanned', 0)} scanned, {idx.get('took_ms', 0)}ms)[/dim]")
    elif "reindex_error" in results:
        console.print(f"  [bold]Reindex:[/bold] [red]error: {results['reindex_error']}[/red]")
    else:
        console.print("  [bold]Reindex:[/bold] [dim]skipped[/dim]")

    # ── Sessions ──
    n_sess = results.get("sessions_removed", 0)
    console.print(f"  [bold]Sessions:[/bold] {n_sess} expired removed" if n_sess else
                  "  [bold]Sessions:[/bold] [dim]none expired[/dim]")

    # ── Orphan collections ──
    orphans = results.get("orphan_collections", [])
    if orphans:
        action = "would remove" if dry_run else "removed"
        console.print(f"  [bold]Orphan collections:[/bold] [yellow]{action} {len(orphans)}[/yellow]: {', '.join(orphans)}")
    else:
        console.print("  [bold]Orphan collections:[/bold] [dim]none[/dim]")

    # ── Orphan segment dirs ──
    seg = results.get("orphan_segments") or {}
    n_seg = seg.get("count", 0)
    if n_seg:
        verb = "would free" if dry_run else "freed"
        mb = seg.get("bytes_freed", 0) / (1024 * 1024)
        console.print(f"  [bold]Orphan segments:[/bold] [yellow]{n_seg} dirs, {verb} {mb:.0f} MB[/yellow]")
    else:
        console.print("  [bold]Orphan segments:[/bold] [dim]none[/dim]")

    # ── WAL checkpoint ──
    wal = results.get("wal_checkpoint") or {}
    if wal.get("ok"):
        b = wal.get("before_bytes", 0) / (1024 * 1024)
        a = wal.get("after_bytes", 0) / (1024 * 1024)
        if dry_run:
            console.print(f"  [bold]WAL:[/bold] [dim]{b:.1f} MB (dry-run)[/dim]")
        else:
            console.print(f"  [bold]WAL:[/bold] checkpoint {b:.1f} → {a:.1f} MB")
    elif "wal_checkpoint_error" in results or wal.get("reason"):
        reason = results.get("wal_checkpoint_error") or wal.get("reason")
        console.print(f"  [bold]WAL:[/bold] [dim red]skipped: {reason}[/dim red]")

    # ── Context cache ──
    pruned = results.get("context_cache_pruned", 0)
    if pruned:
        verb = "would prune" if dry_run else "pruned"
        console.print(f"  [bold]Context cache:[/bold] [yellow]{pruned} stale entries {verb}[/yellow]")
    else:
        console.print("  [bold]Context cache:[/bold] [dim]clean[/dim]")

    # ── Feedback golden ──
    fg = results.get("feedback_golden")
    if fg:
        console.print(f"  [bold]Feedback golden:[/bold] rebuilt ({fg['positives']}+ / {fg['negatives']}-)")
    elif dry_run:
        console.print("  [bold]Feedback golden:[/bold] [dim]skipped (dry-run)[/dim]")

    # ── Log rotation ──
    rotated = results.get("log_rotation", {})
    if rotated:
        for label, detail in rotated.items():
            console.print(f"  [bold]Log rotation:[/bold] {label} — {detail}")
    elif not RAG_STATE_SQL:
        console.print("  [bold]Log rotation:[/bold] [dim]all under threshold[/dim]")

    # ── SQL log rotation (flag ON) ──
    sql_rot = results.get("sql_rotation") or {}
    if sql_rot:
        rows = sql_rot.get("rows_deleted", {}) or {}
        total = sum(rows.values())
        verb = "would delete" if dry_run else "deleted"
        if total:
            console.print(f"  [bold]SQL rotation:[/bold] [yellow]{verb} {total} rows[/yellow] "
                           f"across {sum(1 for v in rows.values() if v)} tables")
            if verbose:
                for t, n in sorted(rows.items(), key=lambda x: -x[1]):
                    if n:
                        console.print(f"    [dim]{t}: {n}[/dim]")
        else:
            console.print("  [bold]SQL rotation:[/bold] [dim]no rows past retention[/dim]")
        wal = sql_rot.get("wal_checkpoint") or {}
        if wal.get("ok"):
            b = wal.get("before_bytes", 0) / (1024 * 1024)
            a = wal.get("after_bytes", 0) / (1024 * 1024)
            if dry_run:
                console.print(f"  [bold]SQL WAL:[/bold] [dim]{b:.1f} MB (dry-run)[/dim]")
            else:
                console.print(f"  [bold]SQL WAL:[/bold] checkpoint {b:.1f} → {a:.1f} MB")
        if sql_rot.get("vacuum_ran"):
            bv = (sql_rot.get("vacuum_before_bytes") or 0) / (1024 * 1024)
            av = (sql_rot.get("vacuum_after_bytes") or 0) / (1024 * 1024)
            console.print(f"  [bold]VACUUM:[/bold] ran {bv:.1f} → {av:.1f} MB")
        elif sql_rot.get("vacuum_would_run"):
            console.print("  [bold]VACUUM:[/bold] [yellow]would run (delta ≥ 500 MB)[/yellow]")
        else:
            console.print("  [bold]VACUUM:[/bold] [dim]skipped (delta < 500 MB)[/dim]")
    elif "sql_rotation_error" in results:
        console.print(f"  [bold]SQL rotation:[/bold] [red]error: {results['sql_rotation_error']}[/red]")

    # ── Migration .bak cleanup ──
    bak = results.get("bak_cleanup") or {}
    if bak:
        n = bak.get("deleted", 0)
        mb = bak.get("bytes_freed", 0) / (1024 * 1024)
        if n:
            verb = "would purge" if dry_run else "purged"
            console.print(f"  [bold].bak cleanup:[/bold] [yellow]{verb} {n} files ({mb:.1f} MB)[/yellow]")
        else:
            console.print("  [bold].bak cleanup:[/bold] [dim]none >30d[/dim]")

    # ── Ignored notes ──
    ign = results.get("ignored_pruned", 0)
    if ign:
        verb = "would prune" if dry_run else "pruned"
        console.print(f"  [bold]Ignored notes:[/bold] [yellow]{ign} stale entries {verb}[/yellow]")
    else:
        console.print("  [bold]Ignored notes:[/bold] [dim]clean[/dim]")

    # ── Auto-index state ──
    idx_st = results.get("index_state_pruned", 0)
    if idx_st:
        verb = "would prune" if dry_run else "pruned"
        console.print(f"  [bold]Index state:[/bold] [yellow]{idx_st} orphan vault keys {verb}[/yellow]")
    else:
        console.print("  [bold]Index state:[/bold] [dim]clean[/dim]")

    # ── Filing batches ──
    batches = results.get("batches_pruned", 0)
    if batches:
        verb = "would prune" if dry_run else "pruned"
        console.print(f"  [bold]Filing batches:[/bold] [yellow]{batches} old batches {verb}[/yellow] [dim](>{_FILING_BATCH_TTL_DAYS}d)[/dim]")
    else:
        console.print("  [bold]Filing batches:[/bold] [dim]none expired[/dim]")

    # ── Tmp files ──
    tmps = results.get("tmp_cleaned", 0)
    if tmps:
        verb = "would remove" if dry_run else "removed"
        console.print(f"  [bold]Tmp files:[/bold] [yellow]{tmps} orphans {verb}[/yellow]")
    else:
        console.print("  [bold]Tmp files:[/bold] [dim]none[/dim]")

    # ── Chat uploads TTL (audit 2026-04-25 R2-Security #6) ──
    cu = results.get("chat_uploads_cleaned") or {}
    if cu:
        n = cu.get("deleted", 0)
        mb = cu.get("bytes_freed", 0) / (1024 * 1024)
        errs = cu.get("errors", []) or []
        if n:
            verb = "would purge" if dry_run else "purged"
            console.print(
                f"  [bold]Chat uploads:[/bold] [yellow]{verb} {n} files ({mb:.1f} MB)[/yellow]"
            )
        else:
            console.print("  [bold]Chat uploads:[/bold] [dim]none past TTL[/dim]")
        if errs and verbose:
            for err in errs:
                console.print(f"    [dim red]{err}[/dim red]")
    elif "chat_uploads_cleaned_error" in results:
        console.print(
            f"  [bold]Chat uploads:[/bold] [red]error: {results['chat_uploads_cleaned_error']}[/red]"
        )

    # ── URL orphans ──
    url_orph = results.get("url_orphans", 0)
    if url_orph:
        verb = "would prune" if dry_run else "pruned"
        console.print(f"  [bold]URL orphans:[/bold] [yellow]{url_orph} rows {verb}[/yellow]")
    else:
        console.print("  [bold]URL orphans:[/bold] [dim]clean[/dim]")

    # ── Feedback orphans ──
    fb_orph = results.get("feedback_orphans", 0)
    if fb_orph:
        verb = "would prune" if dry_run else "pruned"
        console.print(f"  [bold]Feedback orphans:[/bold] [yellow]{fb_orph} stale entries {verb}[/yellow]")
    else:
        console.print("  [bold]Feedback orphans:[/bold] [dim]clean[/dim]")

    # ── Ollama health ──
    oll = results.get("ollama", {})
    if "error" in oll:
        console.print(f"  [bold]Ollama:[/bold] [red]unreachable: {oll['error']}[/red]")
    else:
        missing = [m for m, s in oll.items() if s == "missing"]
        if missing:
            console.print(f"  [bold]Ollama:[/bold] [red]missing: {', '.join(missing)}[/red]")
        else:
            console.print(f"  [bold]Ollama:[/bold] [green]{len(oll)} models ok[/green]")

    # ── Dead notes ──
    dead = results.get("dead_notes", 0)
    if dead:
        console.print(f"  [bold]Dead notes:[/bold] [yellow]{dead} candidates[/yellow] [dim](run `rag archive` to act)[/dim]")
    else:
        console.print("  [bold]Dead notes:[/bold] [dim]none[/dim]")

    console.print()
    console.print(f"  [dim]Done in {results.get('took_ms', 0)}ms[/dim]")


@cli.command()
@click.option("--apply", is_flag=True,
              help="Ejecutar cleanup. Sin esto es dry-run (default).")
@click.option("--yes", is_flag=True,
              help="Confirmacion obligatoria para --apply. Sin esto imprime plan y sale.")
@click.option("--force", is_flag=True,
              help="Bypass del preflight que refusa con launchd services activos.")
@click.option("--json", "as_json", is_flag=True,
              help="Output JSON (para scripts)")
@click.option("--min-age-days", default=_RAG_FREE_MIN_AGE_DAYS_DEFAULT,
              show_default=True,
              help="Edad minima para .bak.<ts> (por ts del nombre) y .archived* (por mtime)")
@click.option("--ranker-keep", default=_RAG_FREE_RANKER_KEEP_DEFAULT,
              show_default=True,
              help="Snapshots ranker.<ts>.<pid>.json a conservar (los mas nuevos)")
@click.option("--skip-tables", is_flag=True,
              help="No dropear tablas legacy en ragvec.db")
@click.option("--skip-baks", is_flag=True,
              help="No borrar .bak.<unix_ts>")
@click.option("--skip-logs", is_flag=True,
              help="No borrar *.archived* viejos")
@click.option("--skip-ranker", is_flag=True,
              help="No borrar snapshots ranker.<ts>.json redundantes")
def free(apply: bool, yes: bool, force: bool, as_json: bool,
         min_age_days: int, ranker_keep: int,
         skip_tables: bool, skip_baks: bool,
         skip_logs: bool, skip_ranker: bool):
    """Liberar espacio sin romper.

    Dropea tablas legacy en ragvec.db que ya viven (con mas filas) en
    telemetry.db, borra .bak.<ts> de la migracion T10, logs .archived* y
    snapshots ranker.<ts>.json redundantes. Todo con safety checks.

    Sin flags es dry-run. Ejecutar con: `rag free --apply --yes`.
    """
    # 1. Construir el plan
    tables = [] if skip_tables else _rag_free_plan_tables()
    baks = [] if skip_baks else _rag_free_plan_baks(min_age_days=min_age_days)
    archived_logs = [] if skip_logs else _rag_free_plan_archived_logs(min_age_days=min_age_days)
    ranker_snaps = [] if skip_ranker else _rag_free_plan_ranker_snapshots(keep=ranker_keep)

    bytes_files = sum(p["bytes"] for p in baks + archived_logs + ranker_snaps)
    safe_tables = [t for t in tables if t["status"] == "safe"]
    warn_tables = [t for t in tables if t["status"] == "warn"]

    plan: dict = {
        "tables": tables,
        "baks": [
            {"path": str(p["path"]), "bytes": p["bytes"], "ts": p["ts"]}
            for p in baks
        ],
        "archived_logs": [
            {"path": str(p["path"]), "bytes": p["bytes"], "mtime": p["mtime"]}
            for p in archived_logs
        ],
        "ranker_snapshots": [
            {"path": str(p["path"]), "bytes": p["bytes"], "ts": p["ts"]}
            for p in ranker_snaps
        ],
        "total_bytes_reclaimable": bytes_files,
        "applied": False,
        "ragvec_bytes_freed": 0,
        "refused": None,
        "tables_dropped": [],
        "files_removed": 0,
        "errors": [],
    }

    # Preflight: si apply+yes, services vivos bloquean salvo --force
    if apply and yes:
        pids = _pgrep_obsidian_rag()
        if pids and not force:
            plan["refused"] = (
                f"pgrep matched {len(pids)} com.fer.obsidian-rag pid(s): "
                f"{' '.join(pids)}. Stop launchd services o pasa --force."
            )
            if as_json:
                click.echo(json.dumps(plan, ensure_ascii=False, indent=2, default=str))
                raise click.exceptions.Exit(1)
            console.print(f"[red]Refused:[/red] {plan['refused']}")
            raise click.exceptions.Exit(1)

    # Dry-run o --apply sin --yes: imprime el plan y sale
    if not apply or not yes:
        if as_json:
            click.echo(json.dumps(plan, ensure_ascii=False, indent=2, default=str))
            return
        mode = (
            "[yellow]dry-run[/yellow]" if not apply
            else "[yellow]plan (falta --yes)[/yellow]"
        )
        console.print(Rule(title=f"[bold cyan]rag free[/bold cyan] {mode}", style="cyan"))
        console.print()

        if tables:
            tbl = Table(title="Tablas legacy en ragvec.db", show_header=True)
            tbl.add_column("tabla", style="cyan")
            tbl.add_column("ragvec.db", justify="right")
            tbl.add_column("telemetry.db", justify="right")
            tbl.add_column("status")
            for t in tables:
                style = "green" if t["status"] == "safe" else "yellow"
                tbl.add_row(
                    t["table"],
                    f"{t['ragvec_count']:,}",
                    f"{t['telemetry_count']:,}",
                    f"[{style}]{t['status']}[/{style}]",
                )
            console.print(tbl)
            console.print(
                f"  [green]{len(safe_tables)} safe (drop + VACUUM)[/green] "
                f"/ [yellow]{len(warn_tables)} warn (preservadas)[/yellow]"
            )
            console.print()

        if baks:
            total = sum(p["bytes"] for p in baks)
            console.print(
                f"[bold].bak.<unix_ts> (migracion T10, >{min_age_days}d):[/bold] "
                f"{len(baks)} archivos, {total:,} bytes"
            )
        if archived_logs:
            total = sum(p["bytes"] for p in archived_logs)
            console.print(
                f"[bold]Logs .archived* (mtime >{min_age_days}d):[/bold] "
                f"{len(archived_logs)} archivos, {total:,} bytes"
            )
        if ranker_snaps:
            total = sum(p["bytes"] for p in ranker_snaps)
            console.print(
                f"[bold]Snapshots ranker.<ts>.json "
                f"(conservando {ranker_keep} nuevos):[/bold] "
                f"{len(ranker_snaps)} archivos, {total:,} bytes"
            )
        console.print()
        console.print(f"[bold]Archivos recuperables:[/bold] {bytes_files:,} bytes")
        if safe_tables:
            console.print(
                "[dim]Tablas DB: el espacio real se libera tras --apply + VACUUM.[/dim]"
            )
        console.print()
        if apply and not yes:
            console.print(
                "[yellow]Se requiere --yes junto con --apply para ejecutar.[/yellow]"
            )
        else:
            console.print("[dim]Proximo paso: rag free --apply --yes[/dim]")
        return

    # Ejecutar
    result = _rag_free_execute(
        plan_tables=tables,
        plan_baks=baks,
        plan_logs=archived_logs,
        plan_ranker=ranker_snaps,
    )
    plan["applied"] = True
    plan["tables_dropped"] = result["tables_dropped"]
    plan["files_removed"] = len(result["files_removed"])
    plan["ragvec_bytes_freed"] = result["bytes_reclaimed_db"]
    plan["total_bytes_reclaimable"] = (
        result["bytes_reclaimed_files"] + result["bytes_reclaimed_db"]
    )
    plan["errors"] = result["errors"]

    if as_json:
        click.echo(json.dumps(plan, ensure_ascii=False, indent=2, default=str))
        return

    console.print(Rule(title="[bold green]rag free — applied[/bold green]", style="green"))
    console.print()
    mb_db = result["bytes_reclaimed_db"] / (1024 * 1024)
    mb_files = result["bytes_reclaimed_files"] / (1024 * 1024)
    console.print(
        f"  [bold]Tablas dropeadas:[/bold] {len(result['tables_dropped'])} "
        f"(ragvec.db liberado: {mb_db:.1f} MB tras VACUUM)"
    )
    console.print(
        f"  [bold]Archivos borrados:[/bold] {len(result['files_removed'])} "
        f"({mb_files:.1f} MB)"
    )
    if result["errors"]:
        console.print(f"  [red]{len(result['errors'])} errores:[/red]")
        for e in result["errors"][:5]:
            console.print(f"    [dim]{e}[/dim]")
    console.print(
        f"  [bold]Total liberado:[/bold] "
        f"{(mb_db + mb_files):.1f} MB"
    )


# ── Phase 5: pendientes dashboard moved to `rag.pendientes` (2026-04-25) ──
# Mid-day check-in dashboard (Gmail awaiting + Apple Mail + WhatsApp +
# Reminders + vault loops + contradictions + low-conf queries + calendar)
# extracted to `rag/pendientes.py`. Includes:
#   - `_pendientes_collect` (concurrent fan-out via ThreadPoolExecutor).
#   - 4 `_pendientes_*` helpers (extract_loops_fast, recent_contradictions,
#     low_conf_queries, urgent).
#   - Click command `pendientes` + 2 renderers (plain + rich).
# Re-exported at the bottom of this file so `rag.pendientes`,
# `rag._pendientes_collect`, etc. keep resolving for callers.


# ──────────────────────────────────────────────────────────────────────
# NLI grounding (Improvement #1, Fase A — standalone module, no pipeline integration)
# ──────────────────────────────────────────────────────────────────────
# Claim-level validation: splits LLM response into atomic claims and
# classifies each vs retrieved chunks as entails|neutral|contradicts.
# Complement to verify_citations() (path existence) — this adds content
# grounding. Fase A = module only; Fase B integrates into query()/chat().
# Default OFF via RAG_NLI_GROUNDING=0 — no effect on existing pipeline.
# Ver docs/improvement-1-nli-integration-plan.md para el diseño completo.


@dataclass
class Claim:
    """Atomic claim extracted from an LLM response.

    Attributes:
        text: The claim text (1-300 chars after strip).
        start_char: Offset in original response (UI highlighting).
        end_char: End offset in original response.
        is_refusal: True for "No encontré..." patterns — skip NLI on these.
    """
    text: str
    start_char: int = 0
    end_char: int = 0
    is_refusal: bool = False


@dataclass
class ClaimGrounding:
    """Result of NLI grounding for a single claim."""
    text: str
    verdict: Literal["entails", "neutral", "contradicts"]
    evidence_chunk_id: str | None = None
    evidence_span: str | None = None
    score: float = 0.0
    start_char: int = 0
    end_char: int = 0


@dataclass
class GroundingResult:
    """Aggregated NLI grounding for a full response."""
    claims: list[ClaimGrounding] = field(default_factory=list)
    claims_total: int = 0
    claims_supported: int = 0
    claims_contradicted: int = 0
    claims_neutral: int = 0
    nli_ms: int = 0


# Refusal patterns — skip NLI on these, they're not factual claims.
# Match is case-insensitive over the whole claim text.
#
# Cubre las 4 variantes intencionales de refusal usadas en los prompts
# bajo `rag/prompts/intents/` (ver audit 2026-04-25 R2-6 #1 para la
# decisión de mantenerlas distintas en lugar de unificar):
#
# 1. ``"No tengo esa información en tus notas."`` — strict, web,
#    chat, system_rules. Default para queries semánticas que no
#    encontraron fuentes relevantes.
# 2. ``"No encontré esto en el vault."`` — lookup (count/list/recent/
#    agenda). Frase distinta para distinguir en telemetría
#    `count+refused` vs `semantic+refused`.
# 3. ``"No hay suficientes fuentes en el vault para sintetizar esto."``
#    — synthesis. Semánticamente distinto: tenemos UNA fuente pero
#    no llega para sintetizar (≥2 requerido).
# 4. ``"No hay suficientes fuentes en el vault para comparar esto."``
#    — comparison. Idem synthesis pero para comparison (≥2 lados).
#
# Si un prompt nuevo agrega una 5ta variante, agregá el pattern acá
# para que el cache poisoning detector y el NLI grounding lo skipeen.
_REFUSAL_PATTERNS = (
    r"^no encontr[eé]\b",
    r"^no hay\s+(?:ning[úu]n|informaci[óo]n|suficientes)\b",
    r"^no tengo (?:esa\s+)?informaci[óo]n\b",
    r"^i (?:don'?t|did not|didn'?t) find\b",
    r"^i could not find\b",
    r"^no information found\b",
)
_REFUSAL_RE = re.compile("|".join(_REFUSAL_PATTERNS), re.IGNORECASE)


def _is_refusal(text: str) -> bool:
    """True if the text matches a known refusal pattern."""
    return bool(_REFUSAL_RE.match(text.strip()))


# ── `rag feedback` subgroup ─────────────────────────────────────────────
# Generar, rescatar y ver señal de feedback para ranker-vivo + GC#2.C.
#
# Tres subcomandos self-contained (no tocan chat() ni web/):
#   - status    : progress hacia los 20 corrective_paths del gate
#   - backfill  : agregar corrective_path a turns existentes sin él
#   - harvest   : labelear queries recent low-confidence sin feedback
#
# Contract: nunca sobre-escribe un corrective_path explícito existente.
# Todos los updates invalidan el golden cache (same pattern que
# record_feedback) para que el próximo retrieve() vea la señal fresca.

_FEEDBACK_GATE_TARGET = 20  # sincroniza con RAG_FINETUNE_MIN_CORRECTIVES default


def _feedback_stats() -> dict:
    """Count feedback rows bucketed by rating + presence of corrective_path.

    Returns dict with keys: total, pos, neg, with_cp, pos_no_cp, neg_no_cp.
    All zeros on DB error (degradación graciosa).
    """
    try:
        with _ragvec_state_conn() as conn:
            row = conn.execute(
                "SELECT "
                " COUNT(*), "
                " SUM(CASE WHEN rating=1 THEN 1 ELSE 0 END), "
                " SUM(CASE WHEN rating=-1 THEN 1 ELSE 0 END), "
                " SUM(CASE WHEN json_extract(extra_json,'$.corrective_path') IS NOT NULL"
                "          AND json_extract(extra_json,'$.corrective_path') <> '' "
                "     THEN 1 ELSE 0 END), "
                " SUM(CASE WHEN rating=1 AND (json_extract(extra_json,'$.corrective_path') IS NULL"
                "          OR json_extract(extra_json,'$.corrective_path') = '') "
                "     THEN 1 ELSE 0 END), "
                " SUM(CASE WHEN rating=-1 AND (json_extract(extra_json,'$.corrective_path') IS NULL"
                "          OR json_extract(extra_json,'$.corrective_path') = '') "
                "     THEN 1 ELSE 0 END) "
                "FROM rag_feedback"
            ).fetchone()
            return {
                "total": int(row[0] or 0),
                "pos": int(row[1] or 0),
                "neg": int(row[2] or 0),
                "with_cp": int(row[3] or 0),
                "pos_no_cp": int(row[4] or 0),
                "neg_no_cp": int(row[5] or 0),
            }
    except Exception:
        return {"total": 0, "pos": 0, "neg": 0, "with_cp": 0,
                "pos_no_cp": 0, "neg_no_cp": 0}


def _set_feedback_corrective_path(feedback_id: int, corrective_path: str) -> bool:
    """Update rag_feedback.extra_json.corrective_path for a specific row.

    Uses json_set() so other extra_json fields stay intact. Invalidates the
    golden cache (same pattern as record_feedback) so retrieve() picks up
    the new positive signal on the next call.

    Returns True on success, False on any SQL error. Never raises.
    """
    try:
        with _ragvec_state_conn() as conn:
            conn.execute(
                "UPDATE rag_feedback "
                "SET extra_json = json_set(COALESCE(extra_json, '{}'), "
                "                          '$.corrective_path', ?) "
                "WHERE id = ?",
                (corrective_path, feedback_id),
            )
            try:
                conn.execute("DELETE FROM rag_feedback_golden")
                conn.execute(
                    "DELETE FROM rag_feedback_golden_meta "
                    "WHERE k='last_built_source_ts'"
                )
            except Exception:
                pass
        global _feedback_golden_memo, _feedback_golden_source_ts_sql
        _feedback_golden_memo = None
        _feedback_golden_source_ts_sql = None
        return True
    except Exception as exc:
        try:
            _log_sql_state_error("feedback_update_cp_failed", err=repr(exc))
        except Exception:
            pass
        return False


def _feedback_rows_without_cp(
    rating_filter: str, since_days: int, limit: int,
) -> list[dict]:
    """List recent rag_feedback rows that lack a corrective_path.

    Args:
      rating_filter: 'pos' | 'neg' | 'both'.
      since_days: window from today (default 30 = last month).
      limit: max rows returned.

    Returns list of dicts {id, ts, turn_id, rating, q, paths} ordered by ts DESC.
    """
    where = [
        "(json_extract(extra_json,'$.corrective_path') IS NULL "
        " OR json_extract(extra_json,'$.corrective_path') = '')",
        f"ts > datetime('now', '-{int(since_days)} days')",
    ]
    if rating_filter == "pos":
        where.append("rating = 1")
    elif rating_filter == "neg":
        where.append("rating = -1")
    sql = (
        "SELECT id, ts, turn_id, rating, q, paths_json "
        "FROM rag_feedback "
        "WHERE " + " AND ".join(where) + " "
        "ORDER BY ts DESC "
        "LIMIT ?"
    )
    try:
        with _ragvec_state_conn() as conn:
            rows = conn.execute(sql, (int(limit),)).fetchall()
            out: list[dict] = []
            for rid, ts, turn_id, rating, q, paths_json in rows:
                try:
                    paths = json.loads(paths_json) if paths_json else []
                except Exception:
                    paths = []
                out.append({
                    "id": int(rid),
                    "ts": ts or "",
                    "turn_id": turn_id or "",
                    "rating": int(rating),
                    "q": q or "",
                    "paths": [p for p in paths if isinstance(p, str) and p],
                })
            return out
    except Exception:
        return []


def _harvest_candidates(
    since_days: int, confidence_below: float, limit: int,
) -> list[dict]:
    """Recent queries with top_score below threshold and no explicit feedback.

    Same logic as the rag-feedback-harvester skill: queries the user never
    rated that the system itself flagged as low-confidence.
    """
    sql = (
        "SELECT q.id, q.ts, q.q, q.top_score, q.cmd, q.session, "
        "       q.paths_json, q.scores_json "
        "FROM rag_queries q "
        f"WHERE q.ts > datetime('now', '-{int(since_days)} days') "
        "  AND q.top_score IS NOT NULL "
        "  AND q.top_score < ? "
        "  AND NOT EXISTS ("
        "    SELECT 1 FROM rag_feedback f "
        "    WHERE f.q = q.q "
        "      AND ABS(julianday(f.ts) - julianday(q.ts)) < 1"
        "  ) "
        "  AND length(q.q) > 4 "
        "  AND q.q NOT IN ('test','probando','hola','ping') "
        "ORDER BY q.top_score ASC, q.ts DESC "
        "LIMIT ?"
    )
    try:
        with _ragvec_state_conn() as conn:
            rows = conn.execute(
                sql, (float(confidence_below), int(limit))
            ).fetchall()
            out: list[dict] = []
            for qid, ts, q, score, cmd, session, paths_json, scores_json in rows:
                try:
                    paths = json.loads(paths_json) if paths_json else []
                except Exception:
                    paths = []
                try:
                    scores = json.loads(scores_json) if scores_json else []
                except Exception:
                    scores = []
                out.append({
                    "id": int(qid),
                    "ts": ts or "",
                    "q": q or "",
                    "top_score": float(score) if score is not None else 0.0,
                    "cmd": cmd or "",
                    "session": session or "",
                    "paths": [p for p in paths if isinstance(p, str) and p],
                    "scores": scores,
                })
            return out
    except Exception:
        return []


def _feedback_insert_harvested(
    *, q: str, rating: int, paths: list[str],
    original_query_id: int | None = None,
    corrective_path: str | None = None,
    source: str = "harvester",
) -> bool:
    """Insert a new rag_feedback row from the harvest flow.

    Tagged with `source` (default 'harvester' = manual CLI / skill) +
    original_query_id in extra_json so the row can be traced back to
    the rag_queries entry that originated it. When corrective_path is
    provided, stores it inside extra_json as well.

    Quick Win C.7 (2026-04-29): `source` ahora es parametro — pre-fix
    estaba hardcodeado y los rows del `auto_harvest()` daemon (LLM-as-
    judge nocturno) caian bajo el mismo tag 'harvester', imposibles de
    distinguir en auditoria. Valores esperados:
      - 'harvester': manual CLI/skill (`rag feedback harvest`).
      - 'auto-harvester': LLM judge daemon (`rag feedback auto-harvest`).
      - 'active-learning-nudge': push WA con quick replies (C.6 follow-up).

    Generates a fresh turn_id (12 hex chars) — harvest rows aren't tied
    to an existing chat turn.
    """
    import secrets
    turn_id = secrets.token_hex(6)  # 12 hex chars
    event: dict = {
        "ts": datetime.now().isoformat(timespec="seconds"),
        "turn_id": turn_id,
        "rating": 1 if rating > 0 else -1,
        "q": q,
        "paths": [p for p in (paths or []) if p],
        "scope": "turn",
        # Unknown-to-_map_feedback_row keys land in extra_json flat.
        "source": source,
    }
    if original_query_id is not None:
        event["original_query_id"] = int(original_query_id)
    if corrective_path:
        event["corrective_path"] = corrective_path
        event["reason"] = "corrective"
    try:
        with _ragvec_state_conn() as conn:
            _sql_append_event(conn, "rag_feedback", _map_feedback_row(event))
            try:
                conn.execute("DELETE FROM rag_feedback_golden")
                conn.execute(
                    "DELETE FROM rag_feedback_golden_meta "
                    "WHERE k='last_built_source_ts'"
                )
            except Exception:
                pass
        global _feedback_golden_memo, _feedback_golden_source_ts_sql
        _feedback_golden_memo = None
        _feedback_golden_source_ts_sql = None
        return True
    except Exception as exc:
        try:
            _log_sql_state_error("harvester_insert_failed", err=repr(exc))
        except Exception:
            pass
        return False


@cli.group()
def feedback():
    """Ver, rescatar y generar señal de feedback para ranker-vivo + GC#2.C.

    Tres subcomandos:
      • `rag feedback status`    — progress hacia los 20 corrective_paths
        del gate de fine-tune (GC#2.C).
      • `rag feedback backfill`  — agregar corrective_path a turns que
        ya están en rag_feedback pero que no lo tienen (rescata data
        histórica que `rag chat + 👎` no capturó).
      • `rag feedback harvest`   — labelear queries recientes con
        top_score bajo que aún no tienen thumbs (equivalente CLI del
        skill `rag-feedback-harvester` de Claude Code, usable standalone).

    Todos los subcomandos invalidan el golden cache para que el próximo
    retrieve() vea la señal fresca. Sin --yes: siempre confirma antes
    de cada insert/update para evitar registros accidentales.
    """


@feedback.command("status")
def feedback_status():
    """Dashboard de señal de feedback y progreso hacia el gate de fine-tune.

    Muestra:
      • Total feedback (positivos / negativos)
      • Con corrective_path  (desbloquea GC#2.C cuando ≥20)
      • Sin corrective_path por rating (candidatos a `rag feedback backfill`)
      • Comando exacto para re-disparar el fine-tune si el gate está open.
    """
    s = _feedback_stats()
    target = _FEEDBACK_GATE_TARGET
    remaining = max(0, target - s["with_cp"])
    console.print()
    console.print("[bold]Feedback status[/bold]")
    console.print(f"  Total:         [cyan]{s['total']}[/cyan] "
                  f"(+1: {s['pos']}, −1: {s['neg']})")
    console.print(f"  Con corrective: [bold green]{s['with_cp']}[/bold green] "
                  f"/ {target} para gate  "
                  + (f"[yellow](faltan {remaining})[/yellow]"
                     if remaining > 0 else "[bold green](gate open!)[/bold green]"))
    console.print(f"  Sin corrective: {s['pos_no_cp']} positivos + "
                  f"{s['neg_no_cp']} negativos = "
                  f"[yellow]{s['pos_no_cp'] + s['neg_no_cp']}[/yellow] candidatos a backfill")
    console.print()
    if remaining > 0:
        console.print("[dim]Próximo paso: [bold]rag feedback backfill[/bold] "
                      "— rescatar corrective_path de los turns existentes.[/dim]")
        console.print("[dim]              [bold]rag feedback harvest[/bold] "
                      "— labelear queries low-confidence sin feedback.[/dim]")
    else:
        console.print("[bold green]Gate open — re-disparar fine-tune:[/bold green]")
        console.print("  [cyan]python scripts/finetune_reranker.py --epochs 2[/cyan]")
    console.print()


@feedback.command("backfill")
@click.option("--limit", default=15, show_default=True,
              help="Cuántos turns presentar como máximo.")
@click.option("--rating", type=click.Choice(["pos", "neg", "both"]),
              default="both", show_default=True,
              help="Filtrar por rating: pos (+1), neg (−1), o both (ambos).")
@click.option("--since", default=30, show_default=True,
              help="Ventana en días.")
def feedback_backfill(limit: int, rating: str, since: int):
    """Agregar corrective_path a turns en rag_feedback que no lo tienen.

    Rescata data histórica que `rag chat + 👎` no capturó (el prompt interactivo
    existe desde commit 23f2899, los 55 turns positivos previos nunca lo vieron).

    Por cada turn muestra query + top-5 paths. Aceptás:
      • número 1-5  → marcar ese path como corrective
      • texto libre → corrective_path custom (vault-relative)
      • s / enter   → skip
      • q           → quit temprano

    Updates idempotentes: si corrés el comando dos veces sobre el mismo turn,
    el segundo run sobreescribe el corrective_path del primero (no duplica rows).
    """
    stats_before = _feedback_stats()
    target = _FEEDBACK_GATE_TARGET
    remaining_before = max(0, target - stats_before["with_cp"])
    console.print()
    console.print("[bold]Backfill de corrective_path[/bold]")
    console.print(f"  Actual: [cyan]{stats_before['with_cp']}[/cyan] / {target}  "
                  f"(faltan [yellow]{remaining_before}[/yellow])")
    console.print(f"  Filtros: rating={rating}, since={since}d, limit={limit}")
    console.print()

    rows = _feedback_rows_without_cp(rating, since, limit)
    if not rows:
        console.print(f"[dim]Sin rows para backfillear (rating={rating}, "
                      f"últimos {since}d). Probá --since 60 o --rating both.[/dim]")
        return

    console.print(f"Rows a revisar: [bold]{len(rows)}[/bold]\n")
    applied = 0
    skipped = 0
    quit_early = False
    for i, row in enumerate(rows, 1):
        label = ("[green]+1[/green]" if row["rating"] > 0
                 else "[red]−1[/red]")
        console.print(f"[bold cyan]{i}/{len(rows)}[/bold cyan]  {label}  "
                      f"[dim]{row['ts']}[/dim]")
        console.print(f"  Query: [italic]{row['q'][:100]}[/italic]")
        if not row["paths"]:
            console.print("  [dim](sin paths en paths_json — skip automático)[/dim]")
            skipped += 1
            console.print()
            continue
        for j, p in enumerate(row["paths"][:5], 1):
            console.print(f"    {j}. {p}")
        ans = click.prompt(
            "  Corrective? [1-5 / path libre / s skip / q quit]",
            default="s", show_default=False,
        ).strip()
        if ans.lower() == "q":
            quit_early = True
            break
        if ans.lower() in ("s", "skip", ""):
            skipped += 1
            console.print()
            continue
        cp: str | None = None
        if ans.isdigit():
            idx = int(ans) - 1
            top5 = row["paths"][:5]
            if 0 <= idx < len(top5):
                cp = top5[idx]
            else:
                console.print("  [red]Índice fuera de rango, skip.[/red]\n")
                skipped += 1
                continue
        else:
            cp = ans
        if not cp:
            skipped += 1
            console.print()
            continue
        if _set_feedback_corrective_path(row["id"], cp):
            applied += 1
            console.print(f"  [green]✓[/green] corrective_path = {cp}")
        else:
            console.print("  [red]✗ error actualizando en SQL[/red]")
        console.print()

    stats_after = _feedback_stats()
    remaining_after = max(0, target - stats_after["with_cp"])
    console.print()
    console.print("[bold]Resumen[/bold]")
    console.print(f"  Applied: [green]{applied}[/green]  |  "
                  f"Skipped: {skipped}"
                  + ("  |  [yellow]quit early[/yellow]" if quit_early else ""))
    console.print(f"  corrective_paths: [cyan]{stats_before['with_cp']}[/cyan]"
                  f" → [green]{stats_after['with_cp']}[/green]")
    if remaining_after == 0 and remaining_before > 0:
        console.print()
        console.print("[bold green]🎯 Gate desbloqueado![/bold green] Re-disparar fine-tune:")
        console.print("  [cyan]python scripts/finetune_reranker.py --epochs 2[/cyan]")
    elif remaining_after > 0:
        console.print(f"  Faltan [yellow]{remaining_after}[/yellow] para "
                      f"desbloquear el gate ({target}).")
    console.print()


@feedback.command("harvest")
@click.option("--limit", default=15, show_default=True,
              help="Cuántos candidatos presentar como máximo.")
@click.option("--since", default=14, show_default=True,
              help="Días atrás a escanear (default ventana del ranker-vivo).")
@click.option("--confidence-below", "confidence_below", default=0.2,
              show_default=True,
              help="Sólo queries con top_score < este valor.")
def feedback_harvest(limit: int, since: int, confidence_below: float):
    """Labelear queries recientes low-confidence sin feedback explícito.

    Equivalente CLI del skill `rag-feedback-harvester` de Claude Code —
    usable standalone desde la terminal. Iterá sobre rag_queries de los
    últimos N días con top_score < threshold y sin rows en rag_feedback
    para la misma q (dedup por q + ts ±1 día).

    Por cada candidato mostrá query + top-5 resultados. Aceptás:
      • 1-5  → +1 sobre ese path (el ranker aprende "ése era el correcto")
      • -    → −1 sobre todos los paths devueltos (golden cache negativo)
      • c    → corrección: pregunta el path correcto, inserta DOS rows
               (−1 de los vistos + +1 del correcto) en transacción
      • s / enter → skip
      • q    → quit

    Tags source='harvester' + original_query_id en extra_json para trazabilidad.
    """
    cands = _harvest_candidates(since, confidence_below, limit)
    console.print()
    console.print("[bold]Harvest de queries low-confidence[/bold]")
    console.print(f"  Filtros: since={since}d, top_score<{confidence_below}, limit={limit}")
    console.print()
    if not cands:
        console.print(f"[dim]Sin candidatos (no hay queries low-confidence sin "
                      f"feedback en los últimos {since}d). Probá --since 30 o "
                      f"--confidence-below 0.3.[/dim]")
        return

    console.print(f"Candidatos: [bold]{len(cands)}[/bold]\n")
    pos = neg = corrective = skipped = 0
    quit_early = False
    for i, c in enumerate(cands, 1):
        console.print(f"[bold cyan]{i}/{len(cands)}[/bold cyan]  "
                      f"[dim]{c['ts']} · cmd={c['cmd']} · "
                      f"score={c['top_score']:.3f}[/dim]")
        console.print(f"  Query: [italic]{c['q'][:100]}[/italic]")
        if not c["paths"]:
            console.print("  [dim](sin paths — skip)[/dim]\n")
            skipped += 1
            continue
        for j, p in enumerate(c["paths"][:5], 1):
            score_str = ""
            if j - 1 < len(c["scores"]):
                try:
                    score_str = f"  [dim]({float(c['scores'][j - 1]):.3f})[/dim]"
                except Exception:
                    pass
            console.print(f"    {j}. {p}{score_str}")
        ans = click.prompt(
            "  ¿Qué tal? [1-5 +1, - neg, c correctivo, s skip, q quit]",
            default="s", show_default=False,
        ).strip().lower()
        if ans == "q":
            quit_early = True
            break
        if ans in ("s", "skip", ""):
            skipped += 1
            console.print()
            continue
        if ans == "-":
            ok = _feedback_insert_harvested(
                q=c["q"], rating=-1, paths=c["paths"],
                original_query_id=c["id"],
            )
            if ok:
                neg += 1
                console.print("  [red]✓ −1 guardado[/red] (todos los paths marcados)")
            else:
                console.print("  [red]✗ error SQL[/red]")
        elif ans == "c":
            # Correctivo: pedí el path correcto
            cp = click.prompt("    Path correcto (vault-relative)",
                              default="", show_default=False).strip()
            if not cp:
                console.print("  [dim]Path vacío, skip.[/dim]")
                skipped += 1
                console.print()
                continue
            # Dos inserts: −1 de los vistos + +1 del correcto con corrective
            ok1 = _feedback_insert_harvested(
                q=c["q"], rating=-1, paths=c["paths"],
                original_query_id=c["id"],
            )
            ok2 = _feedback_insert_harvested(
                q=c["q"], rating=1, paths=[cp],
                original_query_id=c["id"], corrective_path=cp,
            )
            if ok1 and ok2:
                corrective += 1
                console.print(f"  [green]✓ correctivo guardado[/green] "
                              f"(−1 paths vistos + +1 {cp})")
            else:
                console.print(f"  [red]✗ error SQL (ok1={ok1}, ok2={ok2})[/red]")
        elif ans.isdigit():
            idx = int(ans) - 1
            top5 = c["paths"][:5]
            if 0 <= idx < len(top5):
                chosen = top5[idx]
                ok = _feedback_insert_harvested(
                    q=c["q"], rating=1, paths=[chosen],
                    original_query_id=c["id"],
                )
                if ok:
                    pos += 1
                    console.print(f"  [green]✓ +1 guardado[/green] ({chosen})")
                else:
                    console.print("  [red]✗ error SQL[/red]")
            else:
                console.print("  [red]Índice fuera de rango, skip.[/red]")
                skipped += 1
        else:
            console.print(f"  [yellow]Opción '{ans}' no reconocida, skip.[/yellow]")
            skipped += 1
        console.print()

    console.print()
    console.print("[bold]Resumen harvest[/bold]")
    console.print(f"  +1: [green]{pos}[/green]  "
                  f"| −1: [red]{neg}[/red]  "
                  f"| correctivo: [yellow]{corrective}[/yellow]  "
                  f"| skip: {skipped}"
                  + ("  |  [yellow]quit early[/yellow]" if quit_early else ""))
    console.print("  [dim]Golden cache invalidado — próxima query rebuildea.[/dim]")
    stats = _feedback_stats()
    remaining = max(0, _FEEDBACK_GATE_TARGET - stats["with_cp"])
    if remaining == 0:
        console.print()
        console.print("[bold green]🎯 Gate de fine-tune desbloqueado![/bold green]")
        console.print("  [cyan]python scripts/finetune_reranker.py --epochs 2[/cyan]")
    elif corrective > 0:
        console.print(f"  Gate: {stats['with_cp']}/{_FEEDBACK_GATE_TARGET} "
                      f"(faltan {remaining}).")
    console.print()


# ── score calibration per-source (Feature #2 del 2026-04-23) ───────────
# Cross-encoder scores del bge-reranker-v2-m3 son incomparables entre
# sources (vault: 0.8-1.2, whatsapp: 0.02-0.10, calendar: 0.3-0.7).
# Esto forzó hacks como RAG_WA_FAST_PATH_THRESHOLD=0.05 + branch 1/2.
# La solución estructural: isotonic regression per-source que mapea
# raw → calibrated en [0, 1], haciendo el gate de fast-path + ranking
# cross-source uniforme.
#
# Isotonic regression:
# - Monotonic non-parametric: preserva el orden del cross-encoder
#   (mayor raw → mayor calibrated) pero permite ajustar la escala.
# - Entrenado con feedback: (raw_score, 1) para corrective_paths o
#   paths que ganaron thumbs-up; (raw_score, 0) para paths que no.
# - Persistido como 2 arrays float (JSON) en rag_score_calibration,
#   aplicado en retrieve() via piecewise-linear interpolation.
#
# Feature flag RAG_SCORE_CALIBRATION — default OFF inicialmente hasta
# que (a) haya data suficiente del auto-harvest (Feature #1) y (b) el
# `rag eval` confirme no-regresión. Activar con:
#   export RAG_SCORE_CALIBRATION=1
# Rollback: unset the env var — retrieve() vuelve a usar raw scores.

_SCORE_CALIBRATION_ENABLED = os.environ.get(
    "RAG_SCORE_CALIBRATION", ""
).strip().lower() in ("1", "true", "yes")

# Sources que entrenamos por separado. Todo lo que no esté acá cae al
# bucket "vault" (fallback conservador — si no reconocemos el source,
# usamos la calibración del vault ya que es la distribución más ancha).
_CALIBRATION_SOURCES = (
    "vault", "whatsapp", "calendar", "gmail",
    "drive", "reminders", "safari", "contacts", "calls",
)

# In-process cache del modelo por source: {source: (raw_knots, cal_knots)}
# Invalidate con `_reset_calibration_cache()` post-training.
_calibration_cache: dict[str, tuple[list[float], list[float]]] | None = None
_calibration_cache_lock = threading.Lock()


def _reset_calibration_cache() -> None:
    """Invalidate the in-process calibration cache.

    Called post `train_calibration()` so the next retrieve sees fresh knots.
    Idempotent; safe to call from any thread.
    """
    global _calibration_cache
    with _calibration_cache_lock:
        _calibration_cache = None


def _load_calibration() -> dict[str, tuple[list[float], list[float]]]:
    """Lazy-load the calibration models from rag_score_calibration.

    Returns a dict {source: (raw_knots, cal_knots)} where both arrays are
    sorted parallel floats defining the piecewise-linear map raw→cal.
    Empty dict when the table doesn't exist or no rows — calibrate_score()
    then falls back to the raw value.
    """
    global _calibration_cache
    with _calibration_cache_lock:
        if _calibration_cache is not None:
            return _calibration_cache
    out: dict[str, tuple[list[float], list[float]]] = {}
    try:
        with _ragvec_state_conn() as conn:
            rows = conn.execute(
                "SELECT source, raw_knots_json, cal_knots_json "
                "FROM rag_score_calibration"
            ).fetchall()
    except Exception:
        rows = []
    for source, raw_json, cal_json in rows:
        try:
            raw_k = [float(x) for x in json.loads(raw_json)]
            cal_k = [float(x) for x in json.loads(cal_json)]
        except Exception:
            continue
        if len(raw_k) < 2 or len(raw_k) != len(cal_k):
            continue
        out[str(source)] = (raw_k, cal_k)
    with _calibration_cache_lock:
        _calibration_cache = out
    return out


def calibrate_score(source: str | None, raw: float) -> float:
    """Map a raw cross-encoder score to calibrated probability in [0, 1].

    When the feature flag is OFF or no model exists for `source`, returns
    `raw` unchanged — safe to call unconditionally from retrieve().

    Uses piecewise-linear interpolation between trained knots, clamped
    at the boundaries. source=None or unknown → tries the `vault` bucket
    (most common) before falling back to raw. Preserves ordering within
    a source (isotonic = monotonic).

    Never raises. Returns a finite float.
    """
    try:
        raw_f = float(raw)
    except (TypeError, ValueError):
        return 0.0
    if not _SCORE_CALIBRATION_ENABLED:
        return raw_f
    models = _load_calibration()
    if not models:
        return raw_f
    key = (source or "").strip().lower() if isinstance(source, str) else ""
    knots = models.get(key) if key else None
    if knots is None:
        knots = models.get("vault")
    if knots is None:
        return raw_f
    raw_k, cal_k = knots
    # Clamp at boundaries.
    if raw_f <= raw_k[0]:
        return cal_k[0]
    if raw_f >= raw_k[-1]:
        return cal_k[-1]
    # Binary search for the bracket. Small arrays — linear scan is fine
    # and branch-predictable; keep it simple.
    for i in range(1, len(raw_k)):
        if raw_f <= raw_k[i]:
            lo, hi = raw_k[i - 1], raw_k[i]
            lo_cal, hi_cal = cal_k[i - 1], cal_k[i]
            if hi == lo:
                return (lo_cal + hi_cal) / 2.0
            t = (raw_f - lo) / (hi - lo)
            return lo_cal + t * (hi_cal - lo_cal)
    return cal_k[-1]


def _fit_isotonic_from_pairs(
    pairs: list[tuple[float, int]],
) -> tuple[list[float], list[float]] | None:
    """Fit isotonic regression on (raw_score, label ∈ {0,1}) pairs.

    Returns (raw_knots, cal_knots) as parallel sorted arrays defining
    the piecewise-linear map, or None when the input is too small /
    degenerate (ex. all-same labels).

    Uses scikit-learn's IsotonicRegression(out_of_bounds='clip'). The
    output is simplified: we keep only the breakpoints (consecutive
    equal cal_knots get collapsed) to produce a compact JSON payload.
    """
    if len(pairs) < 5:
        return None
    labels = {p[1] for p in pairs}
    if len(labels) < 2:
        return None
    try:
        import numpy as np
        from sklearn.isotonic import IsotonicRegression
    except Exception:
        return None
    x = np.array([p[0] for p in pairs], dtype=np.float64)
    y = np.array([p[1] for p in pairs], dtype=np.float64)
    # Clip raw scores to a sane range — extreme outliers (NaN, inf)
    # would break the fit.
    x = np.clip(x, -10.0, 20.0)
    model = IsotonicRegression(
        out_of_bounds="clip", y_min=0.0, y_max=1.0,
    )
    try:
        model.fit(x, y)
    except Exception:
        return None
    # Sample at ~50 quantiles of x to get a compact piecewise rep.
    try:
        x_sorted = np.sort(np.unique(x))
        if len(x_sorted) <= 50:
            probe = x_sorted
        else:
            probe = np.quantile(x_sorted, np.linspace(0, 1, 50))
            probe = np.unique(probe)
        cal = model.predict(probe)
    except Exception:
        return None
    raw_k = [float(v) for v in probe]
    cal_k = [float(v) for v in cal]
    # Collapse flat plateaus (keep first + last of each run) for compactness.
    if len(raw_k) > 2:
        keep_idx = [0]
        for i in range(1, len(raw_k) - 1):
            if abs(cal_k[i] - cal_k[i - 1]) > 1e-6 or abs(cal_k[i] - cal_k[i + 1]) > 1e-6:
                keep_idx.append(i)
        keep_idx.append(len(raw_k) - 1)
        raw_k = [raw_k[i] for i in keep_idx]
        cal_k = [cal_k[i] for i in keep_idx]
    return (raw_k, cal_k)


def _gather_calibration_pairs(
    conn, source: str, since_days: int = 90,
) -> list[tuple[float, int]]:
    """Extract (raw_score, label ∈ {0,1}) training pairs for a source.

    Positive labels come from rag_feedback rows with rating=1 joined
    back to the originating rag_queries.scores_json (via q + ts window).
    Negative labels come from the same rag_queries' OTHER paths (those
    NOT in rag_feedback positives for that query).

    The path→source mapping uses prefix heuristics on the vault-relative
    path. Paths with `<scheme>://` URIs map to their scheme (whatsapp://,
    gmail://, calendar://, reminders://, etc). `.md` paths under the
    WhatsApp folder get `source='whatsapp'`; everything else is `vault`.
    """
    pairs: list[tuple[float, int]] = []
    # Collect positives: rag_feedback rating=1 with matched path.
    try:
        pos_rows = conn.execute(
            "SELECT f.q, f.paths_json, "
            "       json_extract(f.extra_json, '$.corrective_path') AS cp, "
            "       q.paths_json AS qp, q.scores_json "
            " FROM rag_feedback f "
            " LEFT JOIN rag_queries q "
            "   ON q.q = f.q "
            "   AND ABS(julianday(q.ts) - julianday(f.ts)) < 1 "
            f" WHERE f.rating = 1 "
            f"   AND f.ts > datetime('now', '-{int(since_days)} days')"
        ).fetchall()
    except Exception:
        pos_rows = []

    # Quickly map (q, path) → raw_score from rag_queries on-the-fly.
    for q, fb_paths_json, cp, q_paths_json, q_scores_json in pos_rows:
        try:
            fb_paths = json.loads(fb_paths_json) if fb_paths_json else []
            q_paths = json.loads(q_paths_json) if q_paths_json else []
            q_scores = json.loads(q_scores_json) if q_scores_json else []
        except Exception:
            continue
        # Prefer corrective_path (known golden). Fall back to fb.paths[0]
        # when corrective_path is missing (older data) — rating=1 on a
        # single-path set still is reliable signal.
        golden_paths: list[str] = []
        if cp and isinstance(cp, str):
            golden_paths.append(cp)
        elif len(fb_paths) == 1:
            golden_paths.append(fb_paths[0])
        for gp in golden_paths:
            if gp in q_paths:
                idx = q_paths.index(gp)
                if idx < len(q_scores):
                    try:
                        raw = float(q_scores[idx])
                    except (TypeError, ValueError):
                        continue
                    if _classify_source_from_path(gp) == source:
                        pairs.append((raw, 1))
        # Negatives: every OTHER path in the q's candidate list that was
        # NOT marked as golden for that query, IF the path belongs to
        # this source. This is key — a top-ranked whatsapp path on a
        # vault-intended query is a good negative for the WA model.
        for i, p in enumerate(q_paths):
            if p in golden_paths:
                continue
            if i >= len(q_scores):
                continue
            if _classify_source_from_path(p) != source:
                continue
            try:
                raw = float(q_scores[i])
            except (TypeError, ValueError):
                continue
            pairs.append((raw, 0))
    return pairs


def _classify_source_from_path(path: str) -> str:
    """Map a path to its source bucket. Best-effort — conservative on unknowns."""
    if not path:
        return "vault"
    if "://" in path:
        scheme = path.split("://", 1)[0].strip().lower()
        # Normalize scheme aliases.
        if scheme in ("whatsapp", "whats_app", "wa"):
            return "whatsapp"
        # `gdrive://` es el scheme histórico del ingester de Drive
        # (gdrive://file/<id>); `_CALIBRATION_SOURCES` usa "drive".
        if scheme == "gdrive":
            return "drive"
        if scheme in _CALIBRATION_SOURCES:
            return scheme
        return "vault"
    if path.startswith("03-Resources/WhatsApp/"):
        return "whatsapp"
    return "vault"


# Quick Win #4 (2026-04-29): umbral minimo de pares de FEEDBACK REAL
# por debajo del cual fallback-eamos a synthetic. Igual al
# `min_pairs_per_source` del CLI (default 20). Conservador a proposito:
# 19 reales + 50 sinteticos es peor que 19 reales puros (el cosine
# bge-m3 introduce un sesgo que la calibracion isotonic absorbe). Solo
# disparamos fallback cuando el real signal es claramente insuficiente.
SYNTH_FALLBACK_THRESHOLD = 20


def _gather_synthetic_calibration_pairs(
    conn, source: str,
) -> list[tuple[float, int]]:
    """Pull (raw_score, label) pairs from synthetic queries + negatives.

    Quick Win #4 fallback cuando el feedback real para una source no
    alcanza `SYNTH_FALLBACK_THRESHOLD`. Las "fuentes" de raw score son
    los cosines del bge-m3 embedding (no el cross-encoder score que usa
    el feedback real), por lo que la calibracion resultante NO es
    directamente comparable — el row se persiste con
    `model_version='isotonic-v1-synth'` para que el lector (ej.
    `calibrate_score`) sepa que cosa absorbio.

    Positives: cada synthetic query tiene un `positive_path`. El cosine
    query->positive lo captura `mine_hard_negatives_for_synthetic` en
    la column `cosine_to_positive` de `rag_synthetic_negatives` (mismo
    valor para todas las rows del mismo synth_id). DISTINCT para no
    contar el mismo positive N veces.

    Negatives: cada row de `rag_synthetic_negatives` con `neg_path`
    matcheando la source contribuye un par (cosine_to_query, 0).

    Args:
        conn: connection a `telemetry.db`.
        source: source target (vault/whatsapp/gmail/...).

    Returns:
        Lista de pares (raw_score, label) — vacia si la tabla no existe
        o no hay datos para la source.
    """
    pairs: list[tuple[float, int]] = []

    # Positives: distinct synth_id con cosine_to_positive populated.
    try:
        pos_rows = conn.execute(
            "SELECT DISTINCT synthetic_query_id, cosine_to_positive, "
            "       positive_path "
            "FROM rag_synthetic_negatives "
            "WHERE cosine_to_positive IS NOT NULL"
        ).fetchall()
    except Exception:
        pos_rows = []
    for _synth_id, cos_pos, positive_path in pos_rows:
        if cos_pos is None:
            continue
        try:
            score = float(cos_pos)
        except (TypeError, ValueError):
            continue
        if _classify_source_from_path(positive_path) == source:
            pairs.append((score, 1))

    # Negatives: every hard negative row whose neg_path matches source.
    try:
        neg_rows = conn.execute(
            "SELECT cosine_to_query, neg_path FROM rag_synthetic_negatives"
        ).fetchall()
    except Exception:
        neg_rows = []
    for cos_q, neg_path in neg_rows:
        if cos_q is None:
            continue
        try:
            score = float(cos_q)
        except (TypeError, ValueError):
            continue
        if _classify_source_from_path(neg_path) == source:
            pairs.append((score, 0))

    return pairs


def train_calibration(
    *,
    since_days: int = 90,
    min_pairs_per_source: int = 20,
    dry_run: bool = False,
    use_synthetic_fallback: bool = True,
) -> dict:
    """Train isotonic regression per-source and persist to rag_score_calibration.

    Returns per-source stats:
      {sources: {src: {status, n_pairs, n_pos, n_neg, knots,
                       used_synthetic, n_synth_pairs}, ...},
       total_pairs, trained_sources}

    Never raises (wraps everything defensively). dry_run=True computes
    knots but skips the DB write.

    Quick Win #4 (2026-04-29): si `use_synthetic_fallback=True` (default)
    y una source tiene < SYNTH_FALLBACK_THRESHOLD pares de feedback real,
    suplementa con pares sinteticos derivados de
    `rag_synthetic_queries`/`rag_synthetic_negatives` (cosine bge-m3 como
    proxy de raw_score). El row de calibracion resultante se persiste
    con `model_version='isotonic-v1-synth'` para distinguirlo del
    `isotonic-v1` puro de feedback real.
    """
    from datetime import datetime
    result: dict = {
        "sources": {},
        "total_pairs": 0,
        "trained_sources": 0,
        "trained_at": datetime.now().isoformat(timespec="seconds"),
    }
    try:
        with _ragvec_state_conn() as conn:
            for src in _CALIBRATION_SOURCES:
                real_pairs = _gather_calibration_pairs(
                    conn, src, since_days=since_days,
                )
                pairs = list(real_pairs)
                synth_pairs: list[tuple[float, int]] = []
                used_synthetic = False
                # Quick Win #4: synthetic fallback. Solo si feedback real
                # cae por debajo del umbral — preferimos siempre real
                # signal cuando haya. El threshold es el mismo que el
                # `min_pairs_per_source` del CLI (default 20).
                if (
                    use_synthetic_fallback
                    and len(real_pairs) < SYNTH_FALLBACK_THRESHOLD
                ):
                    try:
                        synth_pairs = _gather_synthetic_calibration_pairs(
                            conn, src,
                        )
                    except Exception:
                        synth_pairs = []
                    if synth_pairs:
                        pairs.extend(synth_pairs)
                        used_synthetic = True
                n_pos = sum(1 for _, y in pairs if y == 1)
                n_neg = len(pairs) - n_pos
                n_real_pos = sum(1 for _, y in real_pairs if y == 1)
                n_real_neg = len(real_pairs) - n_real_pos
                entry = {
                    "status": "skipped",
                    "n_pairs": len(pairs),
                    "n_pos": n_pos,
                    "n_neg": n_neg,
                    # Subset de los counts: cuantos vinieron de synthetic
                    # vs feedback real. Util para diagnostics — el
                    # dashboard de calibration muestra el split.
                    "n_real_pos": n_real_pos,
                    "n_real_neg": n_real_neg,
                    "n_synth_pairs": len(synth_pairs),
                    "used_synthetic": used_synthetic,
                }
                result["total_pairs"] += len(pairs)
                if len(pairs) < min_pairs_per_source or n_pos == 0 or n_neg == 0:
                    entry["status"] = (
                        "insufficient" if len(pairs) < min_pairs_per_source
                        else "no-positive" if n_pos == 0
                        else "no-negative"
                    )
                    result["sources"][src] = entry
                    continue
                fit = _fit_isotonic_from_pairs(pairs)
                if fit is None:
                    entry["status"] = "fit-failed"
                    result["sources"][src] = entry
                    continue
                raw_k, cal_k = fit
                entry["status"] = "trained"
                entry["knots"] = len(raw_k)
                entry["raw_range"] = [raw_k[0], raw_k[-1]]
                entry["cal_range"] = [cal_k[0], cal_k[-1]]
                result["sources"][src] = entry
                result["trained_sources"] += 1
                if dry_run:
                    continue
                # Quick Win #4: model_version refleja si la calibracion
                # se baso en feedback real puro (`isotonic-v1`) o si
                # absorbio pares sinteticos como fallback
                # (`isotonic-v1-synth`). Lectores como `calibrate_score`
                # NO discriminan hoy, pero el flag esta disponible para
                # heuristicas futuras (ej. mostrar warning en el dashboard
                # si una source critica esta siendo calibrada con synth).
                model_version = (
                    "isotonic-v1-synth" if used_synthetic else "isotonic-v1"
                )
                try:
                    conn.execute(
                        "INSERT INTO rag_score_calibration "
                        "(source, raw_knots_json, cal_knots_json, "
                        " n_pos, n_neg, trained_at, model_version) "
                        "VALUES (?, ?, ?, ?, ?, ?, ?) "
                        "ON CONFLICT(source) DO UPDATE SET "
                        " raw_knots_json=excluded.raw_knots_json, "
                        " cal_knots_json=excluded.cal_knots_json, "
                        " n_pos=excluded.n_pos, "
                        " n_neg=excluded.n_neg, "
                        " trained_at=excluded.trained_at, "
                        " model_version=excluded.model_version",
                        (
                            src,
                            json.dumps(raw_k),
                            json.dumps(cal_k),
                            n_pos, n_neg,
                            result["trained_at"],
                            model_version,
                        ),
                    )
                except Exception as exc:
                    entry["status"] = f"persist-failed: {exc!r}"
    except Exception as exc:
        result["error"] = repr(exc)
    if not dry_run and result["trained_sources"] > 0:
        _reset_calibration_cache()
    return result


# ── `rag config` command (Feature #7 del 2026-04-23) ────────────────────
# Lista todas las env vars del sistema con sus valores actuales + defaults
# + descriptions (para las curadas). Útil para:
#  - Debug: "cuál es el valor actual de X?" sin tener que hacer
#    export a ciegas.
#  - Onboarding: ver todos los knobs que el sistema expone.
#  - Verificación: comparar entre máquinas / launchd plists / shells.
#
# Approach híbrido:
#  - Dict curado _CONFIG_VARS con 30 vars principales (descripciones,
#    tipos, rangos sugeridos).
#  - Scan del código para detectar todas las env vars RAG_*/OBSIDIAN_RAG_*
#    que NO estén en el curado, y mostrar sólo current value.
