# NLI model state + lazy loader (Fase B.1)
_NLI_MODEL_NAME = "MoritzLaurer/mDeBERTa-v3-base-xnli-multilingual-nli-2mil7"
_NLI_IDLE_TTL = float(os.environ.get("RAG_NLI_IDLE_TTL", "900"))
_NLI_NEVER_UNLOAD = os.environ.get("RAG_NLI_NEVER_UNLOAD", "").strip() not in ("", "0", "false", "no")

_nli_model = None
_nli_last_use: float = 0.0
_nli_lock = threading.Lock()


def _torch_mps_empty_cache() -> None:
    """Best-effort MPS cache drop. No-op if torch/MPS unavailable."""
    try:
        import torch
        if torch.backends.mps.is_available():
            torch.mps.empty_cache()
    except Exception:
        pass


def get_nli_model():
    """Lazy-load NLI cross-encoder for claim-level grounding (Improvement #1, Fase B).

    Model: MoritzLaurer/mDeBERTa-v3-base-xnli-multilingual-nli-2mil7 —
    multilingual NLI that classifies (claim, evidence_chunk) pairs as
    entails | neutral | contradicts. Used by ground_response() to add a
    content-validity layer on top of verify_citations() (path-existence only).

    Memory: ~600 MB unified memory (MPS, fp32). Device priority: mps > cuda > cpu.
    fp32 forced — fp16 on MPS collapses all scores to ~0.001 (same failure mode
    as the cross-encoder reranker, empirically verified 2026-04-13).

    Thread-safety: double-checked locking via _nli_lock (threading.Lock).
    The `_nli_model is not None` check inside the lock prevents two concurrent
    callers from each paying the ~2s cold-load cost (same pattern as get_reranker).
    Do NOT read or write _nli_model without holding _nli_lock — maybe_unload_nli_model()
    can set it to None from a background thread at any time.
    Returns None if load fails; caller (ground_response) marks all claims neutral.
    """
    global _nli_model, _nli_last_use
    with _nli_lock:
        _nli_last_use = time.time()
        if _nli_model is not None:
            return _nli_model
        try:
            import torch
            from sentence_transformers import CrossEncoder
            if torch.backends.mps.is_available():
                device = "mps"
            elif torch.cuda.is_available():
                device = "cuda"
            else:
                device = "cpu"
            _nli_model = CrossEncoder(_NLI_MODEL_NAME, max_length=512, device=device)
        except Exception as exc:
            _silent_log("nli_load_failed", exc)
            return None
    return _nli_model


def maybe_unload_nli_model(force: bool = False) -> bool:
    """Drop NLI model from MPS if idle > _NLI_IDLE_TTL. Same pattern as reranker."""
    global _nli_model, _nli_last_use
    with _nli_lock:
        if _nli_model is None:
            return False
        if not force and _NLI_NEVER_UNLOAD:
            return False
        if not force and time.time() - _nli_last_use < _NLI_IDLE_TTL:
            return False
        try:
            import gc
            del _nli_model
            _nli_model = None
            _torch_mps_empty_cache()
            gc.collect()
        except Exception as exc:
            _silent_log("nli_unload", exc)
    return True


def split_claims(text: str) -> list[Claim]:
    """Split an LLM response into atomic claims for NLI grounding.

    Strategy (regex-based, no spacy dependency required):
    1. Detect refusal upfront → single Claim with is_refusal=True
    2. Preserve markdown code fences (```...```) as single claims
    3. Preserve markdown bullet/ordered lists (consecutive - * + 1. lines) as one claim
    4. Preserve markdown tables (|...|...| rows) as one claim
    5. Split remaining prose on sentence boundaries (`[.!?]+\\s+`)
    6. Drop claims < 8 chars (punctuation-only fragments)

    Fase A = regex implementation. Fase B may swap for spacy-es if precision needed.

    Args:
        text: The LLM response text.

    Returns:
        List of Claim objects with char offsets preserved for UI highlighting.
        Empty list if text is empty/whitespace.
    """
    if not text or not text.strip():
        return []

    stripped = text.strip()

    # Early detection of refusal — single claim, no further splitting
    if _is_refusal(stripped):
        idx = text.find(stripped)
        return [Claim(
            text=stripped,
            start_char=idx if idx >= 0 else 0,
            end_char=(idx if idx >= 0 else 0) + len(stripped),
            is_refusal=True,
        )]

    # Strategy: extract code fences + tables + lists as atomic blocks,
    # then split prose between them on sentence boundaries.
    claims: list[Claim] = []

    code_fence_re = re.compile(r"```[\s\S]*?```", re.MULTILINE)
    table_re = re.compile(r"^(\|[^\n]*\|\s*\n){2,}", re.MULTILINE)
    list_re = re.compile(
        r"^(?:[-*+]\s+[^\n]+\n?){2,}|^(?:\d+\.\s+[^\n]+\n?){2,}",
        re.MULTILINE,
    )

    blocks: list[tuple[int, int, str]] = []
    for pattern in (code_fence_re, table_re, list_re):
        for m in pattern.finditer(text):
            blocks.append((m.start(), m.end(), m.group(0).strip()))

    # Sort blocks by start, skip overlaps (previous wins)
    blocks.sort(key=lambda b: b[0])
    merged: list[tuple[int, int, str]] = []
    for start, end, btext in blocks:
        if merged and start < merged[-1][1]:
            continue
        merged.append((start, end, btext))

    cursor = 0
    for start, end, btext in merged:
        if start > cursor:
            prose = text[cursor:start]
            claims.extend(_split_prose(prose, cursor))
        if btext and len(btext) >= 8:
            claims.append(Claim(
                text=btext,
                start_char=start,
                end_char=end,
                is_refusal=False,
            ))
        cursor = end

    if cursor < len(text):
        prose = text[cursor:]
        claims.extend(_split_prose(prose, cursor))

    # If no blocks at all, just split the whole text as prose
    if not merged:
        claims = _split_prose(text, 0)

    return claims


def _split_prose(prose: str, base_offset: int) -> list[Claim]:
    """Split prose on sentence boundaries. Helper for split_claims().

    Returns list of Claim objects with offsets relative to the original
    response (base_offset + local_offset).
    """
    if not prose or not prose.strip():
        return []

    claims: list[Claim] = []
    # Sentence boundary: punctuation followed by whitespace + capital letter.
    sentence_re = re.compile(r"(?<=[.!?])\s+(?=[A-ZÁÉÍÓÚÑ¿¡])")
    parts = sentence_re.split(prose)

    offset = 0
    for part in parts:
        if not part:
            continue
        stripped = part.strip()
        if len(stripped) < 8:
            offset += len(part) + 1
            continue
        local_idx = part.find(stripped)
        claim_start = base_offset + offset + (local_idx if local_idx >= 0 else 0)
        claims.append(Claim(
            text=stripped,
            start_char=claim_start,
            end_char=claim_start + len(stripped),
            is_refusal=False,
        ))
        offset += len(part) + 1

    return claims


@dataclass
class PostProcessResult:
    """Resultado agregado de `run_parallel_post_process()`.

    El helper ejecuta hasta 3 tareas de post-procesamiento concurrentemente
    (citation-repair, critique, NLI grounding) y retorna el estado mergeado.
    Diseñado para encapsular los 4 bloques inline previos (query + chat
    ×repair + critique) con un único call site por caller.
    """
    full: str                                  # texto final (post-merge)
    bad_citations: list[tuple[str, str]] = field(default_factory=list)
    citation_repaired: bool = False
    critique_fired: bool = False
    critique_changed: bool = False
    nli_summary: dict | None = None
    nli_ms: int = 0
    nli_result: "GroundingResult | None" = None
    timing_ms: dict = field(default_factory=dict)  # wall/repair/critique/nli


def _pp_task_repair(
    full_orig: str,
    bad: list[tuple[str, str]],
    metas: list[dict],
    context: str,
    question: str,
) -> dict:
    """Citation-repair task — para ejecutar en el ThreadPoolExecutor.

    Condición de disparo: `bad` no vacío, cantidad ≤ _CITATION_REPAIR_MAX_BAD,
    existe al menos un path válido. Misma gate que el bloque inline original.
    Return: {ran, ok, full, ms}. ok=True solo si el repair output pasa
    verify_citations sin bad.
    """
    t0 = time.perf_counter()
    valid_paths = [m.get("file", "") for m in metas if m.get("file")]
    if not bad or len(bad) > _CITATION_REPAIR_MAX_BAD or not valid_paths:
        return {"ran": False, "ok": False, "full": None, "ms": 0}
    repair_system = (
        "Solo puedes citar las siguientes rutas: "
        + ", ".join(valid_paths)
        + ". Responde la misma pregunta usando SOLO esas rutas. No inventes otras."
    )
    messages = [
        {"role": "system", "content": repair_system},
        {"role": "user", "content": (
            f"CONTEXTO:\n{context}\n\nPREGUNTA: {question}\n\nRESPUESTA:"
        )},
    ]
    try:
        resp = _chat_capped_client().chat(
            model=_postprocess_model(),
            messages=messages,
            options=_postprocess_options(),
            stream=False,
            keep_alive=chat_keep_alive(_postprocess_model()),
        )
        # 2026-04-29: filter PT→ES post-gen. La respuesta reparada se
        # le muestra al user en CLI y web — sin filter, leaks pt del
        # repair pueden llegar al usuario.
        from rag.iberian_leak_filter import replace_iberian_leaks
        repair_full = replace_iberian_leaks((resp.message.content or "").strip())
    except Exception as exc:
        _silent_log("postprocess_repair_failed", exc)
        return {"ran": True, "ok": False, "full": None, "ms": int((time.perf_counter() - t0) * 1000)}

    if not repair_full:
        return {"ran": True, "ok": False, "full": None, "ms": int((time.perf_counter() - t0) * 1000)}

    repair_bad = verify_citations(repair_full, metas)
    ok = not repair_bad
    return {
        "ran": True,
        "ok": ok,
        "full": repair_full if ok else None,
        "ms": int((time.perf_counter() - t0) * 1000),
    }


def _pp_task_critique(
    full_orig: str,
    metas: list[dict],
    context: str,
    question: str,
) -> dict:
    """Critique task — regenera la respuesta si el chat model no la aprueba.

    Corre siempre sobre `full_orig` (no sobre el repair output) porque en
    paralelo no podemos esperar al repair. Merge priority en el caller:
    repair gana sobre critique cuando ambos mutan (ver docstring de
    run_parallel_post_process).
    """
    t0 = time.perf_counter()
    critique_system = (
        "Evalúa si la respuesta responde la pregunta usando SOLO las fuentes provistas. "
        "Si es correcta, devuélvela tal cual. "
        "Si es incorrecta o incompleta, regenerá una respuesta mejor usando SOLO esas fuentes. "
        "No expliques tu evaluación — devolvé solo la respuesta final."
    )
    paths_str = "\n".join(m.get("file", "") for m in metas if m.get("file"))
    critique_user = (
        f"Pregunta: {question}\n\n"
        f"Respuesta original:\n{full_orig}\n\n"
        f"Fuentes disponibles:\n{paths_str}\n\n"
        f"Contexto de las fuentes:\n{context}"
    )
    try:
        resp = _chat_capped_client().chat(
            model=_postprocess_model(),
            messages=[
                {"role": "system", "content": critique_system},
                {"role": "user", "content": critique_user},
            ],
            options=_postprocess_options(),
            stream=False,
            keep_alive=chat_keep_alive(_postprocess_model()),
        )
        # 2026-04-29: filter PT→ES post-gen. La crítica regenera la
        # respuesta y el caller la pinta directo en CLI/web — sin
        # filter, leaks pt llegan al user.
        from rag.iberian_leak_filter import replace_iberian_leaks
        crit_full = replace_iberian_leaks((resp.message.content or "").strip())
    except Exception as exc:
        _silent_log("postprocess_critique_failed", exc)
        return {"ran": True, "changed": False, "full": None, "ms": int((time.perf_counter() - t0) * 1000)}

    if not crit_full:
        return {"ran": True, "changed": False, "full": None, "ms": int((time.perf_counter() - t0) * 1000)}

    # Normalise whitespace for comparison — avoid spurious "changed" when the
    # LLM just reflowed the paragraph.
    norm = lambda s: re.sub(r"\s+", " ", s.strip())
    changed = norm(crit_full) != norm(full_orig)
    return {
        "ran": True,
        "changed": changed,
        "full": crit_full if changed else None,
        "ms": int((time.perf_counter() - t0) * 1000),
    }


def _pp_task_nli(
    full_orig: str,
    docs: list[str],
    metas: list[dict],
) -> dict:
    """NLI grounding task — no muta el texto, solo clasifica claims.

    Return dict con summary (claims_total/supported/contradicted/neutral),
    ms, y el raw GroundingResult para render del panel en el caller.
    """
    t0 = time.perf_counter()
    try:
        claims = split_claims(full_orig)
    except Exception as exc:
        _silent_log("postprocess_nli_split_failed", exc)
        return {"ran": False, "summary": None, "raw": None, "ms": 0}

    if not claims:
        return {"ran": False, "summary": None, "raw": None, "ms": 0}

    try:
        result = ground_claims_nli(
            claims, docs, metas,
            threshold_contradicts=_nli_contradicts_threshold(),
            max_claims=_nli_max_claims(),
        )
    except Exception as exc:
        _silent_log("postprocess_nli_failed", exc)
        return {"ran": False, "summary": None, "raw": None, "ms": int((time.perf_counter() - t0) * 1000)}

    if result is None:
        return {"ran": False, "summary": None, "raw": None, "ms": 0}

    summary = {
        "claims_total": result.claims_total,
        "supported": result.claims_supported,
        "contradicted": result.claims_contradicted,
        "neutral": result.claims_neutral,
    }
    # Preserve the GroundingResult's internal ms (inference-only timing) so
    # callers that log `nli_ms` get the same value they did pre-refactor.
    # The task's own wall-clock includes split_claims + the launch overhead
    # which is not what "nli_ms" historically meant.
    return {
        "ran": True,
        "summary": summary,
        "raw": result,
        "ms": int(result.nli_ms or 0),
    }


def _pp_parallel_enabled() -> bool:
    """Env toggle para debugging: `RAG_PARALLEL_POSTPROCESS=0` fuerza
    secuencial. Default on — sin env var, usa threads cuando hay ≥2 tareas.
    """
    val = os.environ.get("RAG_PARALLEL_POSTPROCESS", "1").strip().lower()
    return val not in ("0", "false", "no", "off")


def run_parallel_post_process(
    full_orig: str,
    *,
    docs: list[str],
    metas: list[dict],
    context: str,
    question: str,
    fast_path: bool,
    critique: bool,
    intent: str | None,
) -> PostProcessResult:
    """Ejecuta citation-repair + critique + NLI en paralelo y mergea.

    Parallelization rules:
      - Fast-path bypass: cuando `fast_path=True` (lookup intents con score
        alto), skip repair (mismo gate que el código inline original).
      - Critique: solo si `critique=True`.
      - NLI: solo si `RAG_NLI_GROUNDING` ON y `intent` no en _nli_skip_intents.

    Merge priority cuando múltiples tareas quieren mutar `full`:
      1. **Repair wins over critique**. Rationale: critique corre sobre
         `full_orig` (que tenía citations inválidas); aunque regenere con
         citations válidas, preferimos el repair que tiene un gate explícito
         de verify_citations. Critique podría haber cambiado prosa y retenido
         citations inválidas.
      2. Solo repair OK → full = repaired.
      3. Solo critique changed → full = critiqued.
      4. Nada → full = full_orig.

    NLI nunca muta `full`; se agrega al result en paralelo.

    Threading safety:
      - Todas las tareas leen full_orig + metas/docs/context/question (read-only).
      - Cada tarea hace su propia llamada a ollama (HTTP client thread-safe).
      - NLI accede a mDeBERTa singleton con lock interno en get_nli_model.
      - No shared mutable state entre tasks.

    Args:
        full_orig: texto del LLM stream (post-generation).
        docs, metas: retrieved chunks del retrieve().
        context: contexto construido (build_progressive_context output).
        question: query original.
        fast_path: flag de adaptive routing (skip repair si True).
        critique: flag `--critique` (opt-in critique pass).
        intent: intent clasificado (gate para NLI).

    Returns: PostProcessResult con full mergeado + flags + timing.
    """
    from concurrent.futures import ThreadPoolExecutor

    wall_start = time.perf_counter()
    bad = verify_citations(full_orig, metas)

    # Figure out which tasks to run
    do_repair = (not fast_path) and bool(bad)
    do_critique = bool(critique)
    do_nli = _nli_grounding_enabled() and (intent not in _nli_skip_intents())

    result = PostProcessResult(full=full_orig, bad_citations=bad,
                                critique_fired=do_critique)

    if not (do_repair or do_critique or do_nli):
        result.timing_ms = {"wall": int((time.perf_counter() - wall_start) * 1000)}
        return result

    tasks: dict[str, tuple] = {}
    if do_repair:
        tasks["repair"] = (_pp_task_repair, (full_orig, bad, metas, context, question))
    if do_critique:
        tasks["critique"] = (_pp_task_critique, (full_orig, metas, context, question))
    if do_nli:
        tasks["nli"] = (_pp_task_nli, (full_orig, docs, metas))

    # Execute — parallel when ≥2 tasks AND the env toggle is on. Sequential
    # single-task path avoids thread overhead + preserves determinism for
    # existing tests that mock ollama.chat with an in-order call sequence.
    outcomes: dict[str, dict] = {}
    if len(tasks) >= 2 and _pp_parallel_enabled():
        with ThreadPoolExecutor(max_workers=len(tasks)) as ex:
            futs = {name: ex.submit(fn, *args) for name, (fn, args) in tasks.items()}
            for name, fut in futs.items():
                try:
                    outcomes[name] = fut.result(timeout=60)
                except Exception as exc:
                    _silent_log(f"postprocess_{name}_future_failed", exc)
                    outcomes[name] = {"ran": False, "ok": False, "changed": False,
                                       "full": None, "summary": None, "raw": None,
                                       "ms": 0}
    else:
        for name, (fn, args) in tasks.items():
            try:
                outcomes[name] = fn(*args)
            except Exception as exc:
                _silent_log(f"postprocess_{name}_seq_failed", exc)
                outcomes[name] = {"ran": False, "ok": False, "changed": False,
                                   "full": None, "summary": None, "raw": None,
                                   "ms": 0}

    # Merge — repair wins over critique
    repair_out = outcomes.get("repair", {})
    critique_out = outcomes.get("critique", {})
    nli_out = outcomes.get("nli", {})

    if repair_out.get("ok") and repair_out.get("full"):
        result.full = repair_out["full"]
        result.citation_repaired = True
    elif critique_out.get("changed") and critique_out.get("full"):
        result.full = critique_out["full"]
        result.critique_changed = True

    if nli_out.get("ran"):
        result.nli_summary = nli_out.get("summary")
        result.nli_ms = int(nli_out.get("ms") or 0)
        result.nli_result = nli_out.get("raw")

    result.timing_ms = {
        "wall": int((time.perf_counter() - wall_start) * 1000),
        "repair": int(repair_out.get("ms") or 0),
        "critique": int(critique_out.get("ms") or 0),
        "nli": int(nli_out.get("ms") or 0),
    }
    return result


def ground_claims_nli(
    claims: list[Claim],
    docs: list[str],
    metas: list[dict],
    *,
    threshold_contradicts: float = 0.7,
    cosine_threshold: float = 0.5,
    max_claims: int = 20,
) -> GroundingResult | None:
    """Stub for NLI grounding (Fase B will implement actual NLI inference).

    Fase A: returns a GroundingResult with all claims marked "neutral"
    (safe default). This lets callers integrate the API shape without
    depending on the NLI model being loaded.

    Fase B will:
        1. Load mDeBERTa-v3-base-xnli-multilingual-nli-2mil7 via CrossEncoder
        2. For each claim: embed + cosine prefilter top-3 chunks
        3. Run NLI on (claim, chunk) pairs → entails/neutral/contradicts
        4. Apply thresholds: score >= threshold_contradicts → entails
                           [threshold-0.2, threshold) → neutral
                           < threshold-0.2 → contradicts

    Args:
        claims: list of Claim objects from split_claims()
        docs: retrieved chunk display_text (parallel to metas)
        metas: retrieved chunk metadata dicts (file, note, chunk_id, etc.)
        threshold_contradicts: NLI score threshold for marking contradicts
        cosine_threshold: minimum cosine for prefilter (skip irrelevant chunks)
        max_claims: safety gate — skip if claims > max_claims (cost explosion)

    Returns:
        GroundingResult with per-claim verdicts + aggregate counts.
        None if inputs empty or max_claims exceeded.
    """
    if not claims or not docs:
        return None
    if len(claims) > max_claims:
        return None

    groundings: list[ClaimGrounding] = []
    nli_start = time.time()

    try:
        model = get_nli_model()
        for c in claims:
            if c.is_refusal:
                groundings.append(ClaimGrounding(
                    text=c.text, verdict="neutral", score=0.0,
                    start_char=c.start_char, end_char=c.end_char,
                ))
                continue
            if model is None:
                groundings.append(ClaimGrounding(
                    text=c.text, verdict="neutral", score=0.0,
                    start_char=c.start_char, end_char=c.end_char,
                ))
                continue
            try:
                import numpy as np
                pairs = [(c.text, doc) for doc in docs]
                scores = model.predict(pairs, convert_to_numpy=True)
                # Shape (N_docs, 3) con columnas [entailment, neutral, contradiction]
                best_entail_idx = int(np.argmax(scores[:, 0]))
                best_entail_score = float(scores[best_entail_idx, 0])
                best_contradict_idx = int(np.argmax(scores[:, 2]))
                best_contradict_score = float(scores[best_contradict_idx, 2])

                if best_entail_score > threshold_contradicts and best_entail_score > best_contradict_score:
                    verdict: "Literal['entails', 'neutral', 'contradicts']" = "entails"
                    evidence_idx = best_entail_idx
                elif best_contradict_score > threshold_contradicts:
                    verdict = "contradicts"
                    evidence_idx = best_contradict_idx
                else:
                    verdict = "neutral"
                    evidence_idx = best_entail_idx

                evidence_span = docs[evidence_idx][:200]
                evidence_chunk_id = metas[evidence_idx].get("chunk_id") or metas[evidence_idx].get("file")

                groundings.append(ClaimGrounding(
                    text=c.text,
                    verdict=verdict,
                    evidence_chunk_id=evidence_chunk_id,
                    evidence_span=evidence_span,
                    score=best_entail_score if verdict == "entails" else best_contradict_score,
                    start_char=c.start_char,
                    end_char=c.end_char,
                ))
            except Exception as exc:
                _silent_log("nli_inference_failed", exc)
                groundings.append(ClaimGrounding(
                    text=c.text, verdict="neutral", score=0.0,
                    start_char=c.start_char, end_char=c.end_char,
                ))
    except Exception as exc:
        _silent_log("nli_grounding_failed", exc)
        groundings = [ClaimGrounding(
            text=c.text, verdict="neutral", score=0.0,
            start_char=c.start_char, end_char=c.end_char,
        ) for c in claims]

    nli_ms = int((time.time() - nli_start) * 1000)

    return GroundingResult(
        claims=groundings,
        claims_total=len(groundings),
        claims_supported=sum(1 for g in groundings if g.verdict == "entails"),
        claims_contradicted=sum(1 for g in groundings if g.verdict == "contradicts"),
        claims_neutral=sum(1 for g in groundings if g.verdict == "neutral"),
        nli_ms=nli_ms,
    )


# ──────────────────────────────────────────────────────────────────────
# Entity extraction (Improvement #2, Fase B — extractor helpers)
# ──────────────────────────────────────────────────────────────────────
# GLiNER zero-shot NER multilingüe para popular rag_entities +
# rag_entity_mentions durante indexing. Default OFF via RAG_EXTRACT_ENTITIES=0.
_ENTITY_CONFIDENCE_MIN = float(os.environ.get("RAG_ENTITY_CONFIDENCE_MIN", "0.70"))
_ENTITY_LABELS = ("person", "organization", "location", "event")

# Noise filter (2026-04-22) — GLiNER sobre contenido conversacional meteroso:
# pronombres personales ("yo", "I", "vos", "nosotros") caen como `person` con
# conf >0.70; phone IDs largos de WhatsApp ("5493424303891") también. Pre-fix
# el top-3 de `person` era 2666 yo / 1279 Maria / 376 5493424303891 — la noise
# dominaba a Maria (legítima). Este set + regex aplica en `_extract_entities_single`
# antes del cluster, así nunca entran a `rag_entities`. Backfill pre-existing
# ya tiene la noise; re-correr `scripts/backfill_entities.py --reset` si el
# user quiere limpieza retroactiva.
_ENTITY_STOPWORDS_PERSON = frozenset({
    # ES pronombres + self-refs
    "yo", "mí", "me", "nos", "nosotros", "nosotras", "vos", "tu", "tú", "usted",
    "ustedes", "ellos", "ellas", "él", "ella", "te", "le", "les", "su", "sus",
    "mi", "mis", "nuestro", "nuestra", "nuestros", "nuestras",
    # EN pronombres + self-refs
    "i", "me", "myself", "you", "yourself", "he", "him", "she", "her", "it",
    "we", "us", "ourselves", "they", "them", "themselves", "my", "your", "his",
    "hers", "its", "our", "their",
    # Artículos / determinantes que GLiNER a veces marca
    "el", "la", "los", "las", "un", "una", "unos", "unas",
    "the", "a", "an",
})
# Phone-like IDs: WhatsApp chat IDs son 10-15 dígitos seguidos, sin espacios.
# `5493424303891` / `34084894028025` etc. Cadenas de 7+ dígitos sin letras son
# casi siempre identificadores, no nombres propios.
_ENTITY_PHONE_ID_RE = re.compile(r"^\d{7,}$")

_gliner_model = None
_gliner_lock = threading.Lock()
_gliner_load_failed = False
# Audit 2026-04-26 (BUG #19): TTL para sticky-fail.
_GLINER_STICKY_FAIL_TTL_S = float(os.environ.get("RAG_GLINER_RETRY_TTL_S", "1800"))
_gliner_load_failed_ts: float = 0.0

# Feature-dep warnings already emitted in this process. Gate for
# `_warn_feature_dep_once()`: we want the operator to see ONE stderr line
# per (feature, dep) the first time a default-ON soft-dep fails, but NOT
# spam every retry/call. `silent_errors.jsonl` keeps the audit trail;
# this is just the top-of-session heads-up. Module-level mutable set,
# since threading.Lock protection would be overkill for an
# idempotent-append-of-str operation.
_WARNED_FEATURE_DEPS: set[tuple[str, str]] = set()


def _warn_feature_dep_once(feature: str, dep: str, *, reason: str = "not_available") -> None:
    """Emit one stderr line the first time a default-ON feature's
    soft-dep fails to import / load in this process.

    `reason` distinguishes between install-missing ("not_available") and
    model-load failures ("load_failed") so operators can tell from the
    error.log whether they need to reinstall the extra or debug the HF
    cache / model download.

    Before this (2026-04-22 audit), `RAG_EXTRACT_ENTITIES=1` (default ON)
    + `gliner` missing produced 28+ `gliner_import_failed` per day in
    `silent_errors.jsonl` with zero operator-visible signal. Now the
    first miss prints a single line like::

        [feature: entities] dep `gliner` not available — install the
          `obsidian-rag[entities]` extra or disable the feature via env.

    or, when the package is installed but the model fails to load::

        [feature: entities] dep `gliner` model load failed — check
          ~/.cache/huggingface/hub/ or re-run `GLiNER.from_pretrained(...)`.

    Subsequent calls for the same (feature, dep) are no-ops. Process
    restart resets the set — this is by design, so operators see the
    warning every new session until they act on it.
    """
    key = (feature, dep)
    if key in _WARNED_FEATURE_DEPS:
        return
    _WARNED_FEATURE_DEPS.add(key)
    try:
        if reason == "load_failed":
            sys.stderr.write(
                f"[feature: {feature}] dep `{dep}` model load failed — check "
                f"~/.cache/huggingface/hub/ or reinstall: "
                f"`uv tool install --reinstall --editable '.[{feature}]'`\n"
            )
        else:
            sys.stderr.write(
                f"[feature: {feature}] dep `{dep}` not available — install the "
                f"`obsidian-rag[{feature}]` extra or disable the feature via env.\n"
            )
        sys.stderr.flush()
    except Exception:
        pass


def _entity_extraction_enabled() -> bool:
    """True cuando RAG_EXTRACT_ENTITIES no está seteada a "0"/"false"/"no".

    **Default ON tras 2026-04-21** — popula `rag_entities` +
    `rag_entity_mentions` durante indexing (vault + cross-source ingesters)
    para que `RAG_ENTITY_LOOKUP` (también default ON) no dependa solo del
    one-shot `scripts/backfill_entities.py`. Si `gliner` no está instalado,
    `_extract_entities_batch()` hace sticky-fail silencioso — sin costo ni
    log spam en entornos que no optaron por `[entities]`.

    Setear a "0"/"false"/"no" para desactivar la extracción durante indexing
    aun con `gliner` disponible (útil para acelerar `rag index --reset` si
    se prefiere correr el backfill después).
    """
    val = os.environ.get("RAG_EXTRACT_ENTITIES", "").strip().lower()
    return val not in ("0", "false", "no")


def _get_gliner_model():
    """Lazy-load GLiNER zero-shot NER model for entity extraction (Improvement #2).

    Model: urchade/gliner_multi-v2.1 — multilingual zero-shot entity extractor.
    Populates rag_entities + rag_entity_mentions during indexing when
    RAG_EXTRACT_ENTITIES=1. Labels: person, organization, location, event.
    Called only during indexing — NOT on the retrieve() hot path.

    Memory: ~300-500 MB (CPU only; GLiNER.from_pretrained has no device kwarg).

    Thread-safety: double-checked locking via _gliner_lock (threading.Lock).
    Do NOT read or write _gliner_model without holding _gliner_lock — the global
    can be None either because it hasn't loaded yet or because a prior attempt
    failed. Sticky-failure: _gliner_load_failed is set True on ImportError or load
    exception and is never reset in-process; subsequent calls return None immediately
    without re-attempting the import (avoids repeated heavy import overhead).
    Returns None if gliner package is missing or model load fails.
    """
    global _gliner_model, _gliner_load_failed, _gliner_load_failed_ts
    with _gliner_lock:
        # Audit 2026-04-26 (BUG #19): TTL al sticky flag — recuperación
        # automática post-instalar gliner / restablecer HF cache.
        if _gliner_load_failed:
            if (time.time() - _gliner_load_failed_ts) > _GLINER_STICKY_FAIL_TTL_S:
                _gliner_load_failed = False
            else:
                return None
        if _gliner_model is not None:
            return _gliner_model
        try:
            from gliner import GLiNER
        except ImportError:
            _gliner_load_failed = True
            _gliner_load_failed_ts = time.time()
            try:
                _silent_log("gliner_import_failed", Exception("gliner package not installed"))
            except Exception:
                pass
            _warn_feature_dep_once("entities", "gliner")
            return None
        try:
            _gliner_model = GLiNER.from_pretrained("urchade/gliner_multi-v2.1")
            return _gliner_model
        except Exception as exc:
            _gliner_load_failed = True
            _gliner_load_failed_ts = time.time()
            try:
                _silent_log("gliner_load_failed", exc)
            except Exception:
                pass
            _warn_feature_dep_once("entities", "gliner", reason="load_failed")
            return None


def _normalize_entity_name(name: str) -> str:
    """Lowercase + accent-strip + whitespace collapse."""
    if not name:
        return ""
    try:
        folded = _fold(name)
    except Exception:
        import unicodedata as _ud
        normalized = _ud.normalize("NFD", str(name).lower())
        folded = "".join(c for c in normalized if _ud.category(c) != "Mn")
    return " ".join(folded.split())


def _cluster_entities(candidates: list) -> dict:
    """Agrupa (text, type, confidence) por (normalized, type)."""
    clusters: dict = {}
    for text, etype, conf in candidates:
        if not text or not etype:
            continue
        norm = _normalize_entity_name(text)
        if not norm:
            continue
        key = (norm, etype)
        if key not in clusters:
            clusters[key] = {"forms": [], "scores": []}
        clusters[key]["forms"].append(text.strip())
        clusters[key]["scores"].append(float(conf))

    result: dict = {}
    for (norm, etype), data in clusters.items():
        forms = data["forms"]
        canonical = max(set(forms), key=lambda f: (forms.count(f), len(f)))
        aliases = sorted(set(forms) - {canonical})
        confidence = sum(data["scores"]) / len(data["scores"])
        result[(norm, etype)] = {
            "canonical": canonical,
            "aliases": aliases,
            "confidence": confidence,
            "count": len(forms),
        }
    return result


def _extract_entities_single(text: str) -> list:
    """Extract entities from one chunk via GLiNER."""
    if not text or not text.strip():
        return []
    model = _get_gliner_model()
    if model is None:
        return []
    try:
        raw = model.predict_entities(text, list(_ENTITY_LABELS))
    except Exception as exc:
        try:
            _silent_log("gliner_predict_failed", exc)
        except Exception:
            pass
        return []
    out = []
    for e in raw:
        score = float(e.get("score", 0.0))
        if score < _ENTITY_CONFIDENCE_MIN:
            continue
        etext = (e.get("text") or "").strip()
        elabel = (e.get("label") or "").lower().strip()
        if not etext or elabel not in _ENTITY_LABELS:
            continue
        # Noise filter (2026-04-22): pronombres ES/EN self-ref + articulos
        # + phone IDs que GLiNER clasifica como `person`. Ver
        # `_ENTITY_STOPWORDS_PERSON` y `_ENTITY_PHONE_ID_RE` arriba para
        # la motivación empírica (2666 yo / 1279 Maria → Maria legítima
        # quedaba enterrada).
        if elabel == "person":
            etext_lower = etext.lower()
            if etext_lower in _ENTITY_STOPWORDS_PERSON:
                continue
            if _ENTITY_PHONE_ID_RE.match(etext):
                continue
        # También descartamos entidades <3 chars (ambiguas en cualquier type):
        # "pc", "PO", "sr", "Ex", "la" — ruido consistente en el corpus.
        if len(etext) < 3:
            continue
        out.append((etext, elabel, score))
    return out


def _extract_entities_batch(texts: list) -> list:
    """Batch: list-of-clustered-dicts paralelo al input."""
    if not texts:
        return []
    return [_cluster_entities(_extract_entities_single(t)) for t in texts]


def _upsert_entities_for_chunk(
    conn,
    entities: dict,
    chunk_id: str,
    source: str,
    ts: float,
    snippet: str = "",
) -> int:
    """Upsert entities + mentions with batch SQL — single commit per chunk.

    Reduces SQL calls from N×3+N commits (old loop) to:
      1 SELECT (existing entity IDs for this chunk)
      1 executemany INSERT INTO rag_entities ... ON CONFLICT (entities not yet seen by this chunk)
      1 executemany INSERT OR IGNORE INTO rag_entity_mentions
      1 commit
    This eliminates per-entity SELECT+INSERT/UPDATE round-trips and the N inner
    commits that caused WAL contention during bulk indexing.

    Correctness invariant: mention_count in rag_entities is incremented only
    for genuinely new (entity_id, chunk_id) pairs — re-indexing the same chunk
    is idempotent.
    """
    if not entities or not chunk_id:
        return 0

    snippet_trunc = snippet[:200] if snippet else ""
    norm_etype_list = list(entities.keys())

    try:
        # ── Step 1: resolve existing entity IDs for these (normalized, entity_type) pairs.
        # Entities not yet in the DB will be absent from id_map.
        placeholders = ",".join("(?,?)" for _ in norm_etype_list)
        flat_params = [v for pair in norm_etype_list for v in pair]
        existing_rows = conn.execute(
            f"SELECT id, normalized, entity_type FROM rag_entities "
            f"WHERE (normalized, entity_type) IN (VALUES {placeholders})",
            flat_params,
        ).fetchall()
        id_map = {(r[1], r[2]): r[0] for r in existing_rows}

        # ── Step 2: find which of these entities already have a mention for
        # this chunk_id.  mention_count must NOT be incremented for those.
        existing_entity_ids = list(id_map.values())
        already_mentioned: set = set()
        if existing_entity_ids:
            id_ph = ",".join("?" for _ in existing_entity_ids)
            already_mentioned = {
                r[0]
                for r in conn.execute(
                    f"SELECT entity_id FROM rag_entity_mentions "
                    f"WHERE chunk_id=? AND entity_id IN ({id_ph})",
                    [chunk_id, *existing_entity_ids],
                ).fetchall()
            }

        # ── Step 3: batch upsert rag_entities.
        # For entities whose (entity_id, chunk_id) pair already exists we
        # only update last_seen_ts; for genuinely new mentions we also
        # increment mention_count and blend confidence.
        new_entity_rows = []      # not yet in rag_entities
        update_only_rows = []     # exist but this chunk already mentioned → ts only
        new_mention_rows = []     # exist but this chunk is new → count + conf update

        for (norm, etype), data in entities.items():
            aliases_json = json.dumps(data["aliases"]) if data.get("aliases") else None
            conf = data["confidence"]
            eid = id_map.get((norm, etype))
            if eid is None:
                # Brand-new entity — INSERT will handle it.
                new_entity_rows.append((
                    data["canonical"], norm, etype, aliases_json,
                    ts, ts, conf,
                ))
            elif eid in already_mentioned:
                # Entity exists AND chunk already seen — just bump last_seen_ts.
                update_only_rows.append((ts, eid))
            else:
                # Entity exists but this chunk is new — increment + blend.
                new_mention_rows.append((ts, conf, eid))

        if new_entity_rows:
            # ON CONFLICT covers the race where two parallel indexers insert
            # the same entity simultaneously.
            conn.executemany(
                """
                INSERT INTO rag_entities
                    (canonical_name, normalized, entity_type, aliases,
                     first_seen_ts, last_seen_ts, mention_count, confidence)
                VALUES (?, ?, ?, ?, ?, ?, 1, ?)
                ON CONFLICT(normalized, entity_type) DO UPDATE SET
                    last_seen_ts  = excluded.last_seen_ts,
                    mention_count = mention_count + 1,
                    confidence    = CASE
                        WHEN confidence IS NULL THEN excluded.confidence
                        ELSE (confidence * mention_count + excluded.confidence)
                             / (mention_count + 1)
                    END,
                    aliases       = COALESCE(excluded.aliases, aliases)
                """,
                new_entity_rows,
            )
            # Re-fetch IDs for the newly inserted entities.
            new_norms = [(norm, etype) for (norm, etype) in norm_etype_list
                         if (norm, etype) not in id_map]
            if new_norms:
                ph2 = ",".join("(?,?)" for _ in new_norms)
                fp2 = [v for pair in new_norms for v in pair]
                for r in conn.execute(
                    f"SELECT id, normalized, entity_type FROM rag_entities "
                    f"WHERE (normalized, entity_type) IN (VALUES {ph2})",
                    fp2,
                ).fetchall():
                    id_map[(r[1], r[2])] = r[0]

        if update_only_rows:
            conn.executemany(
                "UPDATE rag_entities SET last_seen_ts=? WHERE id=?",
                update_only_rows,
            )

        if new_mention_rows:
            conn.executemany(
                "UPDATE rag_entities SET last_seen_ts=?, "
                "mention_count=mention_count+1, "
                "confidence=CASE WHEN confidence IS NULL THEN ? "
                "ELSE (confidence*mention_count+?)/(mention_count+1) END "
                "WHERE id=?",
                # note: confidence param appears twice (CASE branches)
                [(ts, conf, conf, eid) for (ts, conf, eid) in new_mention_rows],
            )

        # ── Step 4: batch insert mentions (INSERT OR IGNORE = idempotent).
        mention_rows = []
        for (norm, etype), data in entities.items():
            entity_id = id_map.get((norm, etype))
            if entity_id is None:
                continue
            mention_rows.append((
                entity_id, chunk_id, source, ts,
                snippet_trunc, data["confidence"],
            ))
        if mention_rows:
            conn.executemany(
                "INSERT OR IGNORE INTO rag_entity_mentions "
                "(entity_id, chunk_id, source, ts, snippet, confidence) "
                "VALUES (?, ?, ?, ?, ?, ?)",
                mention_rows,
            )

        conn.commit()
        return len(entities)

    except Exception as exc:
        try:
            _silent_log("entity_upsert_failed", exc)
        except Exception:
            pass
        return 0


def _extract_and_index_entities_for_chunks(
    chunks,
    ids: list,
    metadatas: list,
    source: str,
) -> None:
    """High-level: batch extract + upsert. Silent-fail."""
    if not _entity_extraction_enabled() or not chunks or not ids:
        return

    def _get_display(c):
        if isinstance(c, tuple) and len(c) >= 2:
            return c[1]
        if isinstance(c, str):
            return c
        return ""

    texts = [_get_display(c) for c in chunks]
    try:
        all_entities = _extract_entities_batch(texts)
    except Exception as exc:
        try:
            _silent_log("entity_extraction_batch_failed", exc)
        except Exception:
            pass
        return
    try:
        with _ragvec_state_conn() as conn:
            for chunk_id, meta, entities, text in zip(ids, metadatas, all_entities, texts):
                if not entities:
                    continue
                ts = float(meta.get("created_ts") or meta.get("ts") or time.time())
                snippet = text[:200] if text else ""
                _upsert_entities_for_chunk(conn, entities, chunk_id, source, ts, snippet)
    except Exception as exc:
        try:
            _silent_log("entity_upsert_conn_failed", exc)
        except Exception:
            pass


# ── Phase 2: STT primitives + `rag transcribe` moved to `rag.whisper` ──────
# `_WHISPER_MODEL_DEFAULT`, `_whisper_model_cache`, `_load_whisper_model`,
# `_audio_transcript_cache_get`, `_audio_transcript_cache_put`,
# `transcribe_audio`, and the `rag transcribe <audio>` Click command moved
# to `rag/whisper.py` (Phase 2, 2026-04-25). Re-exported at the bottom of
# this file so `rag.transcribe_audio` etc. keep resolving for callers and
# tests that monkey-patch them.


@cli.command(name="send-mail")
@click.option("--to", required=True, help="Email destinatario (ej. juan@ejemplo.com)")
@click.option("--subject", default="", help="Asunto. Default: '(sin asunto)'.")
@click.option("--body", default="", help="Cuerpo del mail. Si se omite se lee de stdin.")
@click.option("--cc", default=None, help="Copia. Separar con coma si son varios.")
@click.option("--bcc", default=None, help="Copia oculta. Separar con coma si son varios.")
@click.option("--json", "as_json", is_flag=True,
              help="Output JSON estructurado en stdout (para subprocess parse).")
def send_mail_cli(to: str, subject: str, body: str, cc: str | None,
                  bcc: str | None, as_json: bool):
    """Enviar un mail vía Gmail API. Útil para bots (WhatsApp listener
    usa este comando cuando el user dice "mandale un mail a X diciendo Y").

    Reusa las creds del gmail-send MCP en `~/.gmail-mcp/credentials.json`
    (scope `gmail.modify` incluye send). Si --body no viene, lee de stdin.

    Exit codes:
      0 = enviado OK
      1 = error de envío (creds, API, network)
      2 = argumentos inválidos
    """
    if not body:
        import sys
        body = sys.stdin.read().strip()
    if not to.strip() or "@" not in to:
        msg = {"ok": False, "error": f"--to inválido: {to!r}"}
        click.echo(json.dumps(msg) if as_json else f"[red]{msg['error']}[/red]")
        raise SystemExit(2)

    result = _send_gmail(to=to, subject=subject, body=body, cc=cc, bcc=bcc)
    if as_json:
        click.echo(json.dumps(result, ensure_ascii=False))
    elif result.get("ok"):
        console.print(f"[green]✓ enviado[/green] · message_id: {result['message_id']}")
    else:
        console.print(f"[red]✗ {result.get('error', 'desconocido')}[/red]")

    raise SystemExit(0 if result.get("ok") else 1)


# Registrar caches core en el state global al import-time.  Debe ir
# al final del módulo — después de que todas las globales de cache
# estén definidas, sino el getter resuelve a NameError.
try:
    _register_core_caches()
except Exception as _e:
    # Defensivo: el registro de caches es observabilidad, nunca debe
    # romper el import.  Log silent + seguimos.
    try:
        _silent_log("register_core_caches_failed", _e)
    except Exception:
        pass


