# ── Phase 2: rag.whisper re-export shim (2026-04-25) ─────────────────────────
# STT primitives + whisper learning loop CLI extracted to `rag/whisper.py`.
# Importing the Click commands here triggers the decorators, registering the
# `transcribe` / `whisper` / `vocab` groups + subcommands on the global `cli`.
# The helper symbols are re-exported so `rag.transcribe_audio`,
# `rag._load_whisper_model`, etc. keep resolving for callers and for tests
# that `monkeypatch.setattr(rag, "_X", ...)`.
#
# Reload-safety: `importlib.reload(rag)` is used by some tests
# (test_adaptive_fast_path, test_adaptive_routing_flag, ...) to validate
# import-time env var hot-paths. On reload, `rag/__init__.py` re-executes and
# rebuilds the `cli` Group, but `from rag.whisper import ...` would normally
# return cached symbols from the previous module load — leaving the new `cli`
# without `transcribe`/`whisper` registered. We `pop` the cached submodule
# from sys.modules so the import below truly re-executes `rag/whisper.py`,
# re-running every `@cli.command` / `@cli.group` decorator on the NEW cli.
import sys as _sys_for_reload  # noqa: E402
_sys_for_reload.modules.pop("rag.whisper", None)
_sys_for_reload.modules.pop("rag.anticipatory", None)
_sys_for_reload.modules.pop("rag.proactive", None)
_sys_for_reload.modules.pop("rag.wa_tasks", None)
_sys_for_reload.modules.pop("rag.pendientes", None)
_sys_for_reload.modules.pop("rag.ocr", None)
del _sys_for_reload

